#!/usr/bin/env python3
"""
splicecraft.py
==============
SpliceCraft — terminal circular plasmid map viewer.

Features:
  - Fetch any GenBank record by accession (pUC19 = L09137)
  - Load local .gb / .gbk (GenBank) or .dna (popular commercial plasmid editor format) files
  - Circular map with per-strand feature rings and arrowheads
  - Rotate origin freely with ← → keys or mouse scroll
  - Click map to select feature; click sidebar row to highlight on map
  - Feature detail panel
  - Plasmid library panel (left, collection-style, persistent JSON)
  - DNA sequence viewer / editor (bottom, press e to edit, Ctrl+S to save)
  - CDS amino acid translation shown on feature selection

Run standalone:
    python3 splicecraft.py
    python3 splicecraft.py L09137          # fetch pUC19 on launch
    python3 splicecraft.py myplasmid.gb    # open local file
"""

import argparse
import functools
import json
import logging
import math
import os
import platform
import re
import shutil
import subprocess
import sys
import threading
import uuid as _uuid
import warnings as _warnings
from collections import Counter, OrderedDict as _OD
from copy import copy as _shallow_copy, deepcopy
from datetime import date as _date, datetime as _datetime
from io import StringIO
from logging.handlers import RotatingFileHandler
from pathlib import Path

__version__ = "0.9.13"

# Snapshot the runtime platform string ONCE at module import. On some
# OSes `platform.platform()` shells out via `subprocess.run` to learn
# kernel + glibc details — and tests that monkeypatch `subprocess.run`
# (e.g. to capture the upgrade command in `splicecraft update`) would
# otherwise re-trigger that subprocess call and crash on the mock.
# Anything that needs the runtime platform string in a hot path
# should read this constant rather than re-invoke `platform.platform()`.
try:
    _RUNTIME_PLATFORM: str = platform.platform()
except Exception:  # pragma: no cover — defensive against weird platforms
    _RUNTIME_PLATFORM = "?"

# ── Biopython warning filters ─────────────────────────────────────────
# Some real-world records (notably NCBI Entrez exports that picked up
# HTML-escaped `&nbsp;` sequences during scraping) carry annotations
# whose values exceed Biopython's 79-char-per-line GenBank threshold.
# Biopython then emits a `BiopythonWarning: Annotation X too long` per
# line on every serialise, which clutters the terminal at startup
# (autosave, library mirror, library-add) without giving the user any
# action to take — the source record is the problem, not SpliceCraft.
# Filter once at import so we don't re-filter on every call. The
# import is wrapped in try / except so an environment without Biopython
# (vanishingly unlikely given it's a hard dep, but defensive in case
# of a partial install) still loads the module.
try:
    from Bio import BiopythonWarning as _BiopythonWarning  # noqa: F401
    _warnings.filterwarnings(
        "ignore", message=r"Annotation .* too long",
        category=_BiopythonWarning,
    )
except ImportError:
    pass

# ── User data directory ────────────────────────────────────────────────────────
# All user-writable state (library, parts bin, primers, .bak files) lives in
# the platform-appropriate data dir:
#   Linux:   ~/.local/share/splicecraft/
#   macOS:   ~/Library/Application Support/splicecraft/
#   Windows: %APPDATA%\splicecraft\
# Override with $SPLICECRAFT_DATA_DIR (useful for tests and portable installs).

def _user_data_dir() -> Path:
    override = os.environ.get("SPLICECRAFT_DATA_DIR")
    if override:
        p = Path(override).expanduser()
    else:
        try:
            from platformdirs import user_data_dir
            p = Path(user_data_dir("splicecraft", appauthor=False, roaming=False))
        except ImportError:
            p = Path.home() / ".local" / "share" / "splicecraft"
    p.mkdir(parents=True, exist_ok=True)
    return p

_DATA_DIR = _user_data_dir()


def _migrate_legacy_data() -> None:
    """One-shot migration from Path(__file__).parent → _DATA_DIR.
    Idempotent: only copies files whose destination doesn't already exist.
    Preserves the source files (copy, not move) so a dev running from the
    repo checkout can still use them via $SPLICECRAFT_DATA_DIR.

    Each copy is atomic (tempfile + fsync + os.replace). The `.migrated`
    marker is also atomically written. Pre-0.8.9 used a bare
    `shutil.copy2` + `Path.write_text` pair; a crash mid-copy left a
    partial dest, and the `not dst.exists()` guard would *skip* the
    retry on next launch — silently locking in the corruption. Atomic
    discipline means a crash either leaves dst untouched OR fully
    written, with no halfway state."""
    import shutil, tempfile, os as _os
    legacy_root = Path(__file__).parent
    if legacy_root.resolve() == _DATA_DIR.resolve():
        return   # running from the data dir itself (no migration needed)
    names = [
        "plasmid_library.json", "parts_bin.json", "primers.json",
        "plasmid_library.json.bak", "parts_bin.json.bak", "primers.json.bak",
    ]

    def _atomic_copy(src: Path, dst: Path) -> None:
        dst.parent.mkdir(parents=True, exist_ok=True)
        fd, tmp_name = tempfile.mkstemp(
            prefix=f".{dst.name}.", suffix=".migrating",
            dir=str(dst.parent),
        )
        try:
            with open(src, "rb") as fsrc, _os.fdopen(fd, "wb") as fdst:
                shutil.copyfileobj(fsrc, fdst)
                fdst.flush()
                try:
                    _os.fsync(fdst.fileno())
                except OSError:
                    pass
            try:
                shutil.copystat(str(src), tmp_name)
            except OSError:
                pass
            _os.replace(tmp_name, str(dst))
        except Exception:
            try:
                _os.unlink(tmp_name)
            except OSError:
                pass
            raise

    def _atomic_marker_write(target: Path, text: str) -> None:
        target.parent.mkdir(parents=True, exist_ok=True)
        fd, tmp_name = tempfile.mkstemp(
            prefix=f".{target.name}.", suffix=".tmp",
            dir=str(target.parent),
        )
        try:
            with _os.fdopen(fd, "w", encoding="utf-8") as f:
                f.write(text)
                f.flush()
                try:
                    _os.fsync(f.fileno())
                except OSError:
                    pass
            _os.replace(tmp_name, str(target))
        except Exception:
            try:
                _os.unlink(tmp_name)
            except OSError:
                pass
            raise

    migrated = []
    failed: list[tuple[str, str]] = []
    for name in names:
        src = legacy_root / name
        dst = _DATA_DIR / name
        if src.exists() and not dst.exists():
            try:
                _atomic_copy(src, dst)
                migrated.append(name)
            except OSError as exc:
                # Pre-0.9.3 silently swallowed: a RO mount / disk-full /
                # permission-denied left the user thinking their library
                # had vanished (the new `_DATA_DIR` was missing entries
                # that lived in `legacy_root`). Surface to stderr — the
                # logger isn't wired up this early in import, but stderr
                # at launch is loud enough that pipx / pixi / dev shells
                # will all show it.
                failed.append((name, str(exc)))
    if failed:
        import sys
        sys.stderr.write(
            "SpliceCraft: legacy data migration could not copy "
            f"{len(failed)} file(s) from {legacy_root} → {_DATA_DIR}:\n"
        )
        for name, msg in failed:
            sys.stderr.write(f"  {name}: {msg}\n")
        sys.stderr.write(
            "Your existing data is intact at the source path; the new "
            "data dir is unwritable. Set $SPLICECRAFT_DATA_DIR to a "
            "writable location, or fix permissions on the destination.\n"
        )
    if migrated:
        try:
            _atomic_marker_write(_DATA_DIR / ".migrated", "\n".join(migrated))
        except OSError as exc:
            # Idempotent — `not dst.exists()` skips already-migrated files
            # so we'd retry next launch — but a missing marker means we
            # can't tell users-of-this-tree the migration ran. Visible
            # warning to stderr; subsequent runs are silent re-attempts.
            import sys
            sys.stderr.write(
                f"SpliceCraft: migration marker write failed at "
                f"{_DATA_DIR / '.migrated'}: {exc}\n"
            )

_migrate_legacy_data()


# ── Dependency check ───────────────────────────────────────────────────────────

_REQUIRED = {
    "textual":  "textual",
    "Bio":      "biopython",
}

def _check_deps():
    missing = []
    for module, package in _REQUIRED.items():
        try:
            __import__(module)
        except ImportError:
            missing.append(package)
    if missing:
        print("Missing dependencies — install with:")
        print(f"  pip install {' '.join(missing)}")
        sys.exit(1)

_check_deps()

# ── Logging ────────────────────────────────────────────────────────────────────
# Rotating file log with an 8-char session ID prefix on every line so multi-run
# logs are greppable. Default path is `_DATA_DIR/logs/splicecraft.log` so logs
# survive reboots on systemd-tmpfiles distros (which wipe /tmp on boot).
# Overridable via $SPLICECRAFT_LOG. UI never sees raw tracebacks — they go here.

def _default_log_path() -> str:
    override = os.environ.get("SPLICECRAFT_LOG")
    if override:
        return override
    try:
        log_dir = _DATA_DIR / "logs"
        log_dir.mkdir(parents=True, exist_ok=True)
        return str(log_dir / "splicecraft.log")
    except OSError:
        # Fall back to /tmp if the data dir is somehow unwritable (read-only
        # home, quota, etc.) — better than crashing at import time.
        return "/tmp/splicecraft.log"

_LOG_PATH   = _default_log_path()
_SESSION_ID = _uuid.uuid4().hex[:8]

class _SessionFilter(logging.Filter):
    def filter(self, record: logging.LogRecord) -> bool:
        record.session = _SESSION_ID
        return True

_log = logging.getLogger("splicecraft")
# DEBUG-level logs are off by default — bump via SPLICECRAFT_DEBUG=1
# so a user reproducing a bug can capture cache-invalidation / retry /
# pre-flight events that normally don't surface. Network retry events,
# cache-clear events, and other diagnostic-only signals key off this.
if os.environ.get("SPLICECRAFT_DEBUG", "").strip().lower() in (
    "1", "true", "yes"
):
    _log.setLevel(logging.DEBUG)
else:
    _log.setLevel(logging.INFO)
_log.propagate = False
if not _log.handlers:
    try:
        # Rotation: 5 MB per file × 4 backups = ~20 MB total, enough
        # depth to capture a multi-day session for diagnostic email
        # without runaway disk growth. Bumped from 2 MB × 2 (= 6 MB)
        # in 0.7.6 — see CLAUDE.md invariant on diagnostic bundling.
        _handler = RotatingFileHandler(
            _LOG_PATH, maxBytes=5 * 1024 * 1024, backupCount=4,
            encoding="utf-8",
        )
        _handler.setFormatter(logging.Formatter(
            fmt="%(asctime)s [%(session)s] %(levelname)-5s "
                "%(name)s.%(funcName)s:%(lineno)d %(message)s"
        ))
        _handler.addFilter(_SessionFilter())
        _log.addHandler(_handler)
        # Tighten permissions on the log file. POSIX-only — on
        # multi-user hosts the log can carry file paths and error
        # messages that shouldn't be world-readable.
        if sys.platform != "win32":
            try:
                os.chmod(_LOG_PATH, 0o600)
            except OSError:
                pass
    except OSError:
        # Last-resort no-op handler if the log dir is read-only.
        _log.addHandler(logging.NullHandler())


def _chmod_user_only(path: "Path | str") -> None:
    """Tighten file permissions to 0o600 (owner read/write only).
    Best-effort: a no-op on Windows (where POSIX mode bits don't
    apply meaningfully) and silent on permission failures (the file
    already exists and is in use; nothing to do).

    Used for the rotating log + diagnostic bundle ZIP, both of which
    can carry path/error info that shouldn't be world-readable on a
    multi-user host.
    """
    if sys.platform == "win32":
        return
    try:
        os.chmod(str(path), 0o600)
    except OSError:
        pass


def _repr_for_log(value, max_len: int = 100) -> str:
    """Compact, bounded `repr()` for log lines. Long sequences,
    nested dicts, and accidentally-huge values are truncated so a
    single chatty log line can't blow out the rotation window. The
    prefix preserves the type ("[123 items]") so a grepper can still
    find the relevant entry. Plasmid sequences are NOT logged (callers
    avoid passing them) but this guard keeps an accidental long-string
    log call from leaking content."""
    try:
        if isinstance(value, str):
            if len(value) > max_len:
                return f"{value[:max_len // 2]!r}…[{len(value)} chars]"
            return repr(value)
        if isinstance(value, (list, tuple, set)):
            n = len(value)
            if n > 10:
                return f"<{type(value).__name__} of {n} items>"
            return repr(value)[:max_len]
        if isinstance(value, dict):
            if len(value) > 10:
                return f"<dict with {len(value)} keys>"
            return repr(value)[:max_len]
        out = repr(value)
        if len(out) > max_len:
            return out[:max_len] + f"…[{len(out)} chars]"
        return out
    except Exception:
        return "<unrepr-able>"


# ── Hang-debug helper: SIGUSR1 → Python stack dump ──────────────────────────
# When the user reports "the app is hung", running `kill -USR1 <pid>`
# in another shell now dumps every thread's Python stack to a sibling
# log file (`splicecraft.stacks.log`). The output identifies which
# function is wedged and at what line, removing the guesswork that
# event-level logging alone can't resolve when the hang is inside a
# render or a deadlock between threads.
#
# Implementation note: stdlib's `faulthandler.register(signum, file)`
# captures a snapshot at signal time, including ALL threads. We open
# the stacks log in append mode and keep the FD alive for the
# session — `register` accepts a file object but holds it open via a
# borrowed reference, so the FD must outlive every signal that could
# arrive. POSIX-only (Windows lacks SIGUSR1).
try:
    import faulthandler as _faulthandler
    import signal as _signal
    _STACKS_LOG_PATH = str(Path(_LOG_PATH).with_name("splicecraft.stacks.log"))
    _STACKS_LOG_FD = open(_STACKS_LOG_PATH, "a", buffering=1, encoding="utf-8")
    if hasattr(_signal, "SIGUSR1"):
        _faulthandler.register(_signal.SIGUSR1, file=_STACKS_LOG_FD,
                                all_threads=True, chain=False)
except OSError:
    _log.exception("Failed to install SIGUSR1 stack-dump handler")
except (AttributeError, ValueError):
    # AttributeError: SIGUSR1 not present (Windows).
    # ValueError: signal already in use by something else.
    pass


def _log_startup_banner() -> None:
    def _ver(import_name: str) -> str:
        try:
            mod = __import__(import_name)
            return getattr(mod, "__version__", "unknown")
        except ImportError:
            return "NOT INSTALLED"
    _log.info("=" * 60)
    _log.info("SpliceCraft session %s starting", _SESSION_ID)
    _log.info("python    : %s", sys.version.split()[0])
    # Reuse the import-time cached platform string. Calling
    # `platform.platform()` here would re-shell-out via subprocess on
    # some OSes and conflict with tests that monkeypatch subprocess.run
    # (the whole reason `_RUNTIME_PLATFORM` exists per CLAUDE.md
    # invariant #36).
    _log.info("platform  : %s", _RUNTIME_PLATFORM)
    _log.info("textual   : %s", _ver("textual"))
    _log.info("biopython : %s", _ver("Bio"))
    _log.info("log path  : %s", _LOG_PATH)
    try:
        _log.info("stacks    : %s  (kill -USR1 <pid> on hang)",
                  _STACKS_LOG_PATH)
    except NameError:
        pass
    _log.info("=" * 60)


def _check_terminal_capabilities() -> "tuple[list[str], list[str]]":
    """Probe terminal + interpreter for the features SpliceCraft needs.

    Returns ``(blocking, warning)`` lists of human-readable strings.
    Empty `blocking` means SpliceCraft can launch; any string there
    means the user will hit a hard breakage and the launcher should
    refuse + print the message to stderr. `warning` lists soft
    degradations (no clipboard image grab, no primer3 Tm, etc.).

    Checks:
      * **stdout encoding** must be UTF-8 (or a superset). The braille
        plasmid map relies on U+2800-U+28FF; on a Latin-1 terminal
        the entire map renders as gibberish.
      * **stdout is a TTY** when not running in test mode. A pipe /
        redirect means Textual can't draw the UI.
      * **Pillow** is importable (needed for clipboard image paste on
        Windows / macOS; soft on Linux/WSL where the button is
        disabled anyway).
      * **primer3** is importable (Tm calculation; soft fallback to
        2+4 rule estimator).
      * **pyspellchecker** is importable (Experiments F7 spellcheck;
        the feature is gated to skip when missing).

    Designed to be cheap (no network, no subprocess) so it can fire
    on every launch without measurable delay. Output goes to the
    log unconditionally; stderr only on blocking failure.
    """
    blocking: list[str] = []
    warning:  list[str] = []
    # Encoding probe — the braille map needs UTF-8 (or a wider
    # codec). `stdout.encoding` is None when piped; treat that as
    # the caller's problem and skip the warning since they're
    # presumably scripting, not running interactively.
    enc = (getattr(sys.stdout, "encoding", "") or "").lower()
    if enc and enc not in ("utf-8", "utf8", "utf-16", "utf-32",
                              "cp65001"):
        blocking.append(
            f"Terminal encoding is {enc!r}; SpliceCraft requires UTF-8 "
            f"for the braille plasmid map. Set "
            f"PYTHONIOENCODING=utf-8 or use a UTF-8 locale "
            f"(e.g. LANG=C.UTF-8)."
        )
    # Optional Python deps — soft warnings only.
    for mod_name, purpose in (
        ("PIL",          "clipboard image paste (Experiments)"),
        ("primer3",      "primer Tm calculation"),
        ("spellchecker", "Experiments F7 spellcheck"),
    ):
        try:
            __import__(mod_name)
        except ImportError:
            warning.append(f"{mod_name!r} not importable — {purpose} "
                            f"will degrade.")
    return blocking, warning


def _log_terminal_capabilities() -> None:
    """Fire the capability probe + emit `startup.terminal_capabilities`
    event. Blocking failures print to stderr AND abort via
    `SystemExit(1)`; warnings only go to the log.

    Called from `main()` right after the startup banner so failures
    surface before the Textual harness initialises (which would
    swallow stderr).
    """
    blocking, warning = _check_terminal_capabilities()
    _log_event(
        "startup.terminal_capabilities",
        encoding=(getattr(sys.stdout, "encoding", "") or "").lower(),
        is_tty=bool(getattr(sys.stdout, "isatty", lambda: False)()),
        platform=sys.platform,
        blocking_count=len(blocking),
        warning_count=len(warning),
    )
    for msg in warning:
        _log.warning("terminal capability: %s", msg)
    if blocking:
        for msg in blocking:
            _log.error("terminal capability blocked: %s", msg)
            print(f"splicecraft: {msg}", file=sys.stderr)
        raise SystemExit(1)


def _log_event(event: str, *, _stacklevel: int = 2, **fields) -> None:
    """One-line AI-parseable structured event for diagnostic logs.

    Output line shape (JSON payload after the prefix):

        2026-05-15 12:34:56,789 [a3f2c1d8] INFO  splicecraft.action_save:53321 event save.ok {"rec":"pUC19","path":"/tmp/x.gb"}

    The event payload is JSON so any downstream parser (jq, Python
    json.loads, an LLM scanning the log on the user's behalf) can
    extract every field unambiguously without regex tricks against
    embedded whitespace or quotes. `stacklevel=2` makes the
    `funcName:lineno` prefix point at the originating caller, not at
    `_log_event` itself — so even an empty-field event names the
    method that emitted it.

    Sacred invariant: every string value over 200 chars is truncated
    before encoding, so a caller that accidentally passes raw
    sequence content can't leak bases into the log file. Non-scalar
    values pass through `_repr_for_log` which truncates and adds a
    size hint.

    Use this at click handlers, key actions, save/load/annotate
    boundaries — anywhere a user-visible state change happens. The
    output goes to the rotating log file at INFO level so a user
    pasting their log into a bug report tells the reader (or an
    AI assistant) exactly what was being done when the symptom hit.

    Event-name conventions (see also CLAUDE.md invariant #43):
      * `app.<area>.<verb>`  — user actions
            e.g. `app.save.trigger`, `app.library.add`,
            `app.feature.add`, `app.click_debug.toggle`.
      * `op.<area>.<verb>`   — heavy ops emitted by `@_timed`
            e.g. `op.fetch_genbank`, `op.gibson_simulate`,
            `op.pairwise_align`, `op.blast_search`, `op.hmmscan`,
            `op.annotation_transfer`.
      * `<noun>.<verb>`      — state changes
            e.g. `save.ok` / `save.failed`, `record.loaded`,
            `undo.trigger` / `undo.refused` / `undo.empty`,
            `redo.trigger` / `redo.refused` / `redo.empty`,
            `lock.acquired` / `lock.contended` / `lock.stale` /
            `lock.released`, `shutdown.drain.ok` /
            `shutdown.drain.timeout`, `agent.write.ok` /
            `agent.write.failed`, `agent.error`.

    Performance: short-circuits to a no-op when the logger isn't
    INFO-enabled, so every callsite pays one `isEnabledFor` check
    (~100 ns) in the happy path. The `logging` machinery is
    thread-safe, so this is safe to call from `@work` workers.
    """
    if not _log.isEnabledFor(logging.INFO):
        return
    if not fields:
        _log.info("event %s", event, stacklevel=_stacklevel)
        return
    safe: dict = {}
    for k, v in fields.items():
        if isinstance(v, str):
            safe[k] = v if len(v) <= 200 else (
                v[:100] + f"…[+{len(v) - 100}]"
            )
        elif isinstance(v, (int, float, bool)) or v is None:
            safe[k] = v
        elif isinstance(v, (list, tuple, dict)):
            # Lists / tuples / dicts of primitives JSON-encode as
            # arrays / objects (better for downstream parsers than
            # a stringified repr). Bail to bounded repr only when
            # the structure is too big to fit on one log line OR
            # carries un-JSON-encodable values.
            try:
                encoded = json.dumps(v, default=str,
                                      ensure_ascii=False)
                if len(encoded) <= 300:
                    safe[k] = list(v) if isinstance(v, tuple) else v
                else:
                    safe[k] = _repr_for_log(v, max_len=200)
            except (TypeError, ValueError):
                safe[k] = _repr_for_log(v, max_len=200)
        elif isinstance(v, (bytes, bytearray)):
            # Raw byte blobs (e.g. a .dna file body) are NEVER
            # rendered — only a size tag.
            safe[k] = f"<{type(v).__name__} len={len(v)}>"
        else:
            # Catch BioPython sequence-bearing classes by name
            # (avoids importing BioPython here, which would
            # already be in sys.modules anyway). `repr(Seq)` /
            # `repr(SeqRecord)` embed the first ~55 bases — the
            # sacred invariant says we must never log sequence
            # content, so render an opaque tag instead.
            cls_name = type(v).__name__
            if cls_name in ("SeqRecord", "Seq", "MutableSeq"):
                rid = getattr(v, "id", None)
                try:
                    sz = len(v)
                except (TypeError, ValueError):
                    sz = None
                parts = [f"<{cls_name}"]
                if rid:
                    parts.append(f"id={rid}")
                if sz is not None:
                    parts.append(f"len={sz}")
                safe[k] = " ".join(parts) + ">"
            else:
                # Path, datetime, arbitrary objects — bounded
                # repr. Final defence against an unexpected type
                # that happens to embed sequence in its repr.
                safe[k] = _repr_for_log(v, max_len=200)
    try:
        payload = json.dumps(safe, default=str,
                              separators=(",", ":"),
                              ensure_ascii=False)
    except (TypeError, ValueError):
        # Final-resort fallback for non-JSON-encodable values that
        # also slip past `_repr_for_log`. Should be unreachable.
        payload = repr(safe)[:500]
    _log.info("event %s %s", event, payload, stacklevel=_stacklevel)


def _action_log(event_name: str):
    """Decorator that emits an INFO event at action-method entry
    plus the active record id (when present) so the log line tells
    the reader what the user was looking at, not just what they
    pressed.

    Applied to ``action_*`` methods on `PlasmidApp` so the per-action
    boilerplate stays a one-line decorator instead of an explicit
    `_log_event` call at the head of every body. Any exception in
    the logging path is swallowed — logging must never break the
    underlying action.

    Use as::

        @_action_log("app.fetch")
        def action_fetch(self):
            ...
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(self, *args, **kwargs):
            # Level-gate FIRST so an INFO-suppressed run pays one
            # attribute lookup per action invocation (no getattr chain,
            # no dict build, no JSON encode). The same guard inside
            # `_log_event` covers the explicit-call path; this one
            # short-circuits the decorator wrapper too.
            if _log.isEnabledFor(logging.INFO):
                try:
                    ctx: dict = {}
                    rec = getattr(self, "_current_record", None)
                    if rec is not None:
                        rid = getattr(rec, "id", None) or getattr(
                            rec, "name", None
                        )
                        if rid:
                            ctx["rec"] = rid
                    # _stacklevel=3 so the logger's funcName:lineno
                    # points at the wrapped action method, not at this
                    # wrapper. Without it every action shows up in the
                    # log as "_action_log:531" — useless for tracing.
                    _log_event(event_name, _stacklevel=3, **ctx)
                except Exception:  # noqa: BLE001 — logging must never raise
                    pass
            return func(self, *args, **kwargs)
        return wrapper
    return decorator


import time as _time
from contextlib import contextmanager

# Threshold above which a wrapped block emits a `slow` event.
# 50 ms is roughly 3 frames at 60 fps — anything beyond that is
# "the user can perceive a stutter". Tune up for known-slow paths
# (NCBI fetch, pytest-driven cosmid renders) by passing an explicit
# `threshold_ms`.
_SLOW_THRESHOLD_MS = 50.0


def _timed(path: str, threshold_ms: float = 0.0):
    """Decorator counterpart to `_log_timing` — wraps a whole function
    body in the same start/elapsed harness. Use on top-level heavy
    operations (NCBI fetch, primer3, BLAST, Gibson simulate) where
    every call is potentially diagnostic-worthy.

    Default `threshold_ms=0` means every call emits an event — useful
    for known-heavy paths where you always want a timestamp + duration
    in the log. Bump to a non-zero value to silence fast cases on
    paths that mostly return quickly.

    Naming: pass a `path` like ``"op.fetch_genbank"`` or
    ``"op.gibson_simulate"`` so the AI-parser can group all slow
    events by operation type.

    Performance: same level-gate short-circuit as `_log_event` — when
    INFO is suppressed the wrapper still measures (`perf_counter` is
    sub-microsecond) but `_log_event` early-returns before any JSON
    encode. Net cost per call when INFO is off: ~300 ns.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            t0 = _time.perf_counter()
            try:
                return func(*args, **kwargs)
            finally:
                dt_ms = (_time.perf_counter() - t0) * 1000
                if dt_ms >= threshold_ms:
                    # _stacklevel=3 so the funcName:lineno prefix
                    # points at the wrapped function, not at this
                    # wrapper closure.
                    _log_event("op.timed", _stacklevel=3,
                                path=path,
                                elapsed_ms=round(dt_ms, 1))
        return wrapper
    return decorator


@contextmanager
def _log_timing(path: str, threshold_ms: float = _SLOW_THRESHOLD_MS):
    """Time the wrapped block and emit a `slow` event when it
    exceeds `threshold_ms`. Use as a `with` statement around hot
    paths; the no-event happy case has near-zero overhead (just
    two `perf_counter` calls). When a user pastes their log into
    a bug report after a "the app hangs" complaint, the slow
    events pinpoint which routine is the bottleneck.

    Example::

        with _log_timing("seq.refresh_view"):
            sp._refresh_view()

    Logs:

        slow path=seq.refresh_view elapsed_ms=183.2
    """
    t0 = _time.perf_counter()
    try:
        yield
    finally:
        dt_ms = (_time.perf_counter() - t0) * 1000
        if dt_ms >= threshold_ms:
            _log_event("slow", path=path, elapsed_ms=round(dt_ms, 1))


