# Flat recognition-sequence-only dict derived from _NEB_ENZYMES (used by
# _scan_restriction_sites and _RESTR_COLOR below).
_RESTRICTION_SITES: dict[str, str] = {
    name: seq for name, (seq, _, _) in _NEB_ENZYMES.items()
}


_RESTR_PALETTE: list[str] = [
    "color(220)", "color(208)", "color(196)", "color(160)",
    "color(105)", "color(129)", "color(57)",  "color(21)",
    "color(33)",  "color(39)",  "color(51)",  "color(87)",
    "color(118)", "color(154)", "color(190)", "color(226)",
    "color(185)", "color(180)",
]
_RESTR_COLOR: dict[str, str] = {
    name: _RESTR_PALETTE[i % len(_RESTR_PALETTE)]
    for i, name in enumerate(_RESTRICTION_SITES)
}


# ── Biology primitives ─ extracted to splicecraft_biology.py ──────────────
#
# Pure functions / constants live in `splicecraft_biology.py` (see the
# module docstring + docs/architecture.md for the rationale). We re-
# bind them into the splicecraft.* namespace so external callers
# (`import splicecraft as sc; sc._rc(...)`) and every existing call
# site inside this file continue to work unchanged.
#
# Sacred invariants #3, #4, #8 are owned by splicecraft_biology — see
# its module docstring.
# Three of these symbols (`_IUPAC_RE`, `_PATTERN_CACHE`,
# `_PATTERN_CACHE_MAX`) are referenced only by tests via `sc.<name>`,
# not inside splicecraft.py itself — they're public-API re-exports,
# not dead imports, and the `from foo import bar as bar` alias is the
# idiomatic way to tell ruff that. The E402 ignore covers the
# deliberate mid-file location of the extraction.
from splicecraft_biology import (  # noqa: E402
    _IUPAC_RE         as _IUPAC_RE,
    _IUPAC_COMP       as _IUPAC_COMP,
    _DNA_COMP_PRESERVE_CASE as _DNA_COMP_PRESERVE_CASE,
    _PATTERN_CACHE    as _PATTERN_CACHE,
    _PATTERN_CACHE_MAX as _PATTERN_CACHE_MAX,
    _iupac_pattern    as _iupac_pattern,
    _rc               as _rc,
    _feat_len         as _feat_len,
    _seq_len          as _seq_len,
    _slice_circular   as _slice_circular,
)


def _feat_bounds(feat, total: int) -> "tuple[int, int, int] | None":
    """Wrap-aware extraction of `(start, end, strand)` from a Biopython
    `SeqFeature`. The returned `(start, end)` follows the dict-feature
    convention: `end < start` signals an origin-spanning wrap; otherwise
    `end > start`. Returns `None` if the location has non-integer coords
    (UnknownPosition / BetweenPosition).

    For a `CompoundLocation` of exactly two parts whose outer bounds are
    `[0, ..)` and `[.., total)`, re-encodes as `(tail_start, head_end)`
    so callers can slice with `_slice_circular` and length with `_feat_len`.
    Other compound shapes flatten to outer bounds.

    Callers that read `int(feat.location.start)` / `int(feat.location.end)`
    directly silently flatten wrap features (Biopython returns `min(part.start)`
    for a CompoundLocation), so any code that later does `seq[s:e]` returns
    the BACKBONE GAP rather than the feature. Always route through this
    helper instead. See sacred invariant #9.
    """
    loc = getattr(feat, "location", None)
    if loc is None:
        return None
    try:
        strand = int(getattr(loc, "strand", 1) or 1)
    except (TypeError, ValueError):
        strand = 1
    try:
        from Bio.SeqFeature import CompoundLocation
    except ImportError:
        CompoundLocation = None
    if CompoundLocation is not None and isinstance(loc, CompoundLocation):
        try:
            parts = sorted(loc.parts, key=lambda p: int(p.start))
            if (
                total > 0 and len(parts) == 2
                and int(parts[0].start) == 0
                and int(parts[-1].end) == total
                and int(parts[0].end) < int(parts[-1].start)
            ):
                # Origin wrap → (tail_start, head_end) so end < start.
                return int(parts[-1].start), int(parts[0].end), strand
            # Other compound shapes: outer bounds, lossy but oriented.
            return int(parts[0].start), int(parts[-1].end), strand
        except (TypeError, ValueError):
            return None
    try:
        return int(loc.start), int(loc.end), strand
    except (TypeError, ValueError):
        return None


def _feat_span_label(start: int, end: int, total: int) -> str:
    """Human-readable span for a feature dict's (start, end). Coords
    are GenBank-style 1-based inclusive: start gets ``+1``, end is
    unchanged (0-based exclusive == 1-based inclusive numerically).

    Wrap features (``end < start``) render as ``"S+1..0..E"`` so the
    picker dropdown reflects the actual biology rather than printing a
    misleading linear span that looks like the backbone gap.

    Pre-fix this returned raw 0-based coords with the docstring claiming
    "matches every other in-app display" — but the sidebar / tooltip /
    primer-plasmids / domesticator dropdowns are all 1-based, so the
    FeatureSearch + trad-cloning span columns silently disagreed by
    one with every other coord display in the app."""
    if end < start:
        return f"{start + 1}..0..{end}"
    return f"{start + 1}..{end}"


# Pre-built per-enzyme scan records: immutable derived values (compiled pattern,
# palindrome flag, RC pattern, color) computed once at import time rather than
# on every _scan_restriction_sites call. Iterating the pre-built list avoids
# ~200 per-call _iupac_pattern + _rc + dict-lookup + len calls per scan.
#
# Each entry is a tuple:
#   (name, site, site_len, fwd_cut, rev_cut, color, pat, is_palindrome, rc_pat)
# rc_pat is None for palindromic enzymes (no reverse scan needed).
_SCAN_CATALOG: "list[tuple]" = []


def _rebuild_scan_catalog() -> None:
    """(Re)populate `_SCAN_CATALOG` from `_NEB_ENZYMES`. Called at import
    time; also exposed so tests / future catalog edits can refresh it."""
    _SCAN_CATALOG.clear()
    for name, (site, fwd_cut, rev_cut) in _NEB_ENZYMES.items():
        site_u  = site.upper()
        pat     = _iupac_pattern(site_u)
        rc_site = _rc(site_u)
        is_pal  = (rc_site == site_u)
        rc_pat  = None if is_pal else _iupac_pattern(rc_site)
        _SCAN_CATALOG.append((
            name, site_u, len(site_u), fwd_cut, rev_cut,
            _RESTR_COLOR[name], pat, is_pal, rc_pat,
        ))

_rebuild_scan_catalog()


# Per-record restriction-scan cache. Keyed by `(hash(seq), min_len,
# unique_only, circular)` so the same record + filter combo doesn't
# re-scan on every panel refresh. Capped at 4 entries (matches the
# `_BUILD_SEQ_CACHE` policy) — we only need recent active records,
# not historical ones. Auto-invalidated by sequence edits because
# `_rebuild_record_with_edit` returns a fresh SeqRecord with a new seq
# string whose hash differs.
_RESTR_SCAN_CACHE: "_OD[tuple, list]" = _OD()
_RESTR_SCAN_CACHE_MAX = 4


@_timed("op.scan_restriction", threshold_ms=25)
def _scan_restriction_sites(
    seq: str,
    min_recognition_len: int = 6,
    unique_only: bool = True,
    circular: bool = True,
    allowed_enzymes: "frozenset[str] | None" = None,
) -> list[dict]:
    """Cached entry point for restriction-site scans. Identical
    signature + return shape to the inner `_scan_restriction_sites_impl`;
    consults `_RESTR_SCAN_CACHE` first so a `r`-toggle on a 5 Mb record
    drops from ~3 s to ~5 ms after the first scan.

    `allowed_enzymes` (GH #13, 2026-05-14): when supplied, the scan
    restricts to ONLY these names — overrides the `min_recognition_len`
    / `unique_only` filters since the user has hand-picked the set.
    Pass `None` to use the standard filter rules."""
    # Cache key uses `hash(seq)` rather than `id(seq)`: id-based keys
    # break for transient strings (e.g. unit tests build a fresh seq
    # per test, GC'd between calls — CPython's allocator can hand the
    # same address to a later string and produce a stale cache hit).
    # CPython interns the string hash on the first call, so subsequent
    # scans of the same seq are still O(1). Same fix applied to
    # `_ENZYME_CUTS_CACHE`.
    allowed_key = (
        tuple(sorted(allowed_enzymes)) if allowed_enzymes else None
    )
    key = (hash(seq), int(min_recognition_len),
           bool(unique_only), bool(circular), allowed_key)
    hit = _RESTR_SCAN_CACHE.get(key)
    if hit is not None:
        # Move to end (LRU touch) so a steady-state "I'm scanning the
        # same record" stays hot.
        _RESTR_SCAN_CACHE.move_to_end(key)
        return hit
    result = _scan_restriction_sites_impl(
        seq, min_recognition_len, unique_only, circular,
        allowed_enzymes=allowed_enzymes,
    )
    if len(_RESTR_SCAN_CACHE) >= _RESTR_SCAN_CACHE_MAX:
        _RESTR_SCAN_CACHE.popitem(last=False)
    _RESTR_SCAN_CACHE[key] = result
    return result


def _scan_restriction_sites_impl(
    seq: str,
    min_recognition_len: int = 6,
    unique_only: bool = True,
    circular: bool = True,
    *,
    allowed_enzymes: "frozenset[str] | None" = None,
) -> list[dict]:
    """Scan both strands; return resite + recut dicts for every hit.

    resite — the recognition sequence span (colored bar)
    recut  — the cut position (single-bp marker: ↓ above or ↑ below DNA)

    min_recognition_len — skip enzymes whose recognition site is shorter than this
                          (default 6 to reduce noise from 4-cutters)
    unique_only         — if True, only include enzymes that cut exactly once
                          (forward + reverse strand combined; default True)
    circular            — if True (default), recognition sequences that span
                          the origin (bp n-1 → bp 0) are also found. SpliceCraft
                          is a plasmid viewer, so circularity is on by default.

    Wrap-around resites are emitted as TWO pieces so the existing linear-span
    rendering in the map / sequence panel stays correct: one piece on the
    "tail" (start..n) with the enzyme label, one unlabeled piece on the
    "head" (0..tail_len). The single-bp recut marker is placed at its real
    absolute position modulo n.
    """
    seq_u = seq.upper()
    n = len(seq_u)
    # Per-enzyme results collected first so we can filter to unique cutters
    by_enzyme: dict[str, list[dict]] = {}
    seen: set[tuple[str, int, int]] = set()   # deduplicate palindromes

    # For circular sequences, scan an augmented copy that includes up to
    # site_len-1 bp re-attached from the beginning so matches starting near
    # the end (that would otherwise be truncated) are found too.
    max_site_len = max((e[2] for e in _SCAN_CATALOG), default=0)
    scan_seq = (seq_u + seq_u[: max_site_len - 1]) if (circular and n > 0) else seq_u

    def _emit_resite(hits, p, site_len, strand, color, name,
                     cut_col, ext_cut_bp,
                     top_cut_bp=-1, bottom_cut_bp=-1):
        """Emit one or two resite dicts depending on wrap. Labels only on the
        first piece so the map doesn't double-print. For wrapped sites, the
        cut_col / ext_cut_bp fields are only meaningful on the piece that
        actually contains the cut; we attach them to the tail piece by default
        and clear them on the head piece.

        `top_cut_bp` / `bottom_cut_bp` are absolute top-strand-coordinate
        positions where the enzyme cleaves each strand. They're stored on
        every piece (including wrap continuations) so a click anywhere on
        the bar can render the per-strand cut split.
        """
        common = {
            "top_cut_bp":    top_cut_bp,
            "bottom_cut_bp": bottom_cut_bp,
        }
        if p + site_len <= n:
            hits.append({
                "type":       "resite",
                "start":      p,
                "end":        p + site_len,
                "strand":     strand,
                "color":      color,
                "label":      name,
                "cut_col":    cut_col,
                "ext_cut_bp": ext_cut_bp,
                **common,
            })
            return
        # Wraps origin: tail [p, n) + head [0, (p + site_len) - n).
        tail_len = n - p
        head_len = (p + site_len) - n
        # cut_col (bar-relative) maps to whichever piece actually contains the
        # cut. ext_cut_bp (absolute) is unrelated to the tail/head split — it's
        # only meaningful when cut_col is None (Type IIS cuts outside the
        # recognition sequence). Attach it to both pieces so the cut arrow is
        # drawn regardless of which chunk contains the external cut position;
        # the chunk-level `chunk_start <= ext_cut_bp < chunk_end` test makes
        # the render idempotent. Regression guard added 2026-04-13.
        tail_cut_col = cut_col if (cut_col is not None and cut_col < tail_len) else None
        head_cut_col = ((cut_col - tail_len) if (cut_col is not None and cut_col >= tail_len)
                        else None)
        hits.append({
            "type":       "resite",
            "start":      p,
            "end":        n,
            "strand":     strand,
            "color":      color,
            "label":      name,
            "cut_col":    tail_cut_col,
            "ext_cut_bp": ext_cut_bp,
            **common,
        })
        hits.append({
            "type":       "resite",
            "start":      0,
            "end":        head_len,
            "strand":     strand,
            "color":      color,
            "label":      "",     # unlabeled continuation
            "cut_col":    head_cut_col,
            "ext_cut_bp": ext_cut_bp,
            **common,
        })

    for entry in _SCAN_CATALOG:
        name, site, site_len, fwd_cut, rev_cut, color, pat, is_palindrome, rc_pat = entry
        # `allowed_enzymes` (GH #13): when set, the user has hand-
        # picked a working list — bypass the length filter so a 4-cutter
        # like Sau3AI shows up even when the global `restr_min_len`
        # is 6. We DO still honour `unique_only` below, since "unique
        # cutters of MY hand-picked list" is the common intent.
        if allowed_enzymes is not None:
            if name not in allowed_enzymes:
                continue
        else:
            if site_len < min_recognition_len:
                continue
        hits: list[dict] = []

        # Forward strand scan (over augmented sequence if circular)
        for m in pat.finditer(scan_seq):
            p = m.start()
            if p >= n:
                continue   # duplicate of match already found at p - n
            key = (name, p, 1)
            if key in seen:
                continue
            seen.add(key)
            # ext_cut_bp: absolute cut position when cut falls outside recognition
            _ext = ((p + fwd_cut) % n) if (fwd_cut <= 0 or fwd_cut >= site_len) else None
            _cc  = fwd_cut if 0 < fwd_cut < site_len else None
            # For forward-strand binding (whether palindromic or Type IIS),
            # fwd_cut counts from the recognition's 5' end on the top strand
            # and rev_cut counts from the recognition's 3' end on the bottom
            # strand (= 5' end of bottom strand reading right-to-left). Both
            # measured in top-strand coordinates: top cut at p+fwd_cut,
            # bottom cut at p+rev_cut. For palindromes these are mirror
            # images (rev_cut == site_len - fwd_cut); for Type IIS like BsaI
            # both fall outside the recognition.
            _top_cut = (p + fwd_cut) % n if n > 0 else 0
            _bot_cut = (p + rev_cut) % n if n > 0 else 0
            _emit_resite(hits, p, site_len, 1, color, name, _cc, _ext,
                         top_cut_bp=_top_cut, bottom_cut_bp=_bot_cut)
            hits.append({
                "type":   "recut",
                "start":  _top_cut,
                "end":    _top_cut + 1,
                "strand": 1,
                "color":  color,
                "label":  name,
            })

        # Reverse strand handling — uses precomputed is_palindrome and rc_pat
        # from _SCAN_CATALOG (no per-call _rc / _iupac_pattern work).
        if not is_palindrome:
            # Non-palindromic: scan for RC on forward strand to find
            # reverse-strand binding sites at their correct positions.
            for m in rc_pat.finditer(scan_seq):
                p = m.start()
                if p >= n:
                    continue   # duplicate of match already found at p - n
                key = (name, p, -1)
                if key in seen:
                    continue
                seen.add(key)
                # Cut column within the bar: enzyme's fwd_cut mapped to
                # the reversed orientation displayed on the forward strand.
                # Symmetry: a forward-strand cut at offset `c` from the
                # recognition's 5' end appears on a reverse-bound site at
                # offset `site_len - c` from the bar's left edge.
                rev_cut_col = site_len - fwd_cut
                _top_cut_bp = (p + site_len - rev_cut) % n   # top-strand cut in fwd coords
                _bot_cut_bp = (p + site_len - fwd_cut) % n if n > 0 else 0
                _top_cut_outside = ((_top_cut_bp - p) % n) >= site_len
                _cc  = rev_cut_col if 0 <= rev_cut_col < site_len else None
                _ext = _top_cut_bp if _top_cut_outside else None
                _emit_resite(hits, p, site_len, -1, color, name, _cc, _ext,
                             top_cut_bp=_top_cut_bp,
                             bottom_cut_bp=_bot_cut_bp)
                hits.append({
                    "type":   "recut",
                    "start":  _bot_cut_bp,
                    "end":    _bot_cut_bp + 1,
                    "strand": -1,
                    "color":  color,
                    "label":  name,
                })

        if hits:
            by_enzyme[name] = hits

    feats: list[dict] = []
    # `placed` tracks (start, end, recognition_site) — keying on the
    # recognition string in addition to the span means HF / iso
    # variants of the SAME enzyme (e.g., EcoRI vs EcoRI-HF, both with
    # site "GAATTC") still collapse, but two enzymes with DIFFERENT
    # recognition patterns whose hits happen to land on the same
    # bp range (e.g., AccI/GTMKAC and BstZ17I/GTATAC both matching
    # GTATAC at one position) stay independent. Pre-2026-05-18 this
    # was `set[tuple[int, int]]` which over-collapsed and caused
    # `unique_only=True`/`False` to disagree on which enzyme to
    # surface when the catalog-order winner was a multi-cutter
    # filtered out by `unique_only=True` but kept by `unique_only=False`.
    placed: set[tuple[int, int, str]] = set()
    site_of: dict[str, str] = {
        entry[0]: entry[1] for entry in _SCAN_CATALOG
    }
    # When a custom enzyme list is active, the user has hand-picked
    # the set — surface every hit of those enzymes regardless of
    # cut-count. The `unique_only` filter is a discovery aid for the
    # default "show me 6+ bp unique cutters" workflow; it actively
    # hides multi-cutters (BsaI in a Golden Gate plasmid, EcoRI in a
    # repeat-laden synthetic construct) which is the opposite of what
    # the user wants after they typed those enzymes in by hand.
    effective_unique_only = (
        unique_only and allowed_enzymes is None
    )
    for name, hits in by_enzyme.items():
        # Count LABELED resites only — a wrap-around hit is emitted as one
        # labeled piece + one unlabeled continuation, but counts as 1 site.
        if effective_unique_only:
            n_sites = sum(
                1 for h in hits if h["type"] == "resite" and h.get("label")
            )
            if n_sites != 1:
                continue
        # Skip isoschizomers / HF-variants of the SAME recognition that
        # land on an already-placed site. The recognition string is
        # part of the key so genuinely-different enzymes (different
        # recognition patterns) with accidental position overlap stay
        # independent.
        site_key = site_of.get(name, "")
        positions = {
            (h["start"], h["end"], site_key) for h in hits
            if h["type"] == "resite" and h.get("label")
        }
        if positions & placed:
            continue
        placed |= positions
        feats.extend(hits)
    return feats


# ── Restriction digest + ligation simulator (traditional cloning) ─────────────
#
# The Constructor's "Traditional" tab runs an in-silico cut + paste:
# digest a source plasmid (or PCR product or feature) with one or two
# enzymes, digest a destination vector with the same enzymes, ligate
# the chosen insert fragment into the linearised vector, and emit
# both possible orientations.
#
# Fragment shape (used throughout this block):
#     {
#       "top_seq":   str,                     # top strand 5'→3'
#       "left":  {"overhang_seq": str,
#                 "kind": "5'"|"3'"|"blunt"|"linear",
#                 "enzyme": str},
#       "right": {"overhang_seq": str, "kind": ..., "enzyme": str},
#       "features": list[dict],               # in fragment-local 0-based coords
#       "source_label": str,
#     }
#
# Overhang sequence canonicalisation: `overhang_seq` is always the
# top-strand bases between min(top_cut, bottom_cut) and max(top_cut,
# bottom_cut). With this rule, two ends ligate iff their `overhang_seq`
# fields match exactly (palindromic cuts trivially match; Type IIS
# overhangs match only when the user-designed contexts agree;
# compatible-overhang enzymes like BamHI/BglII match because both
# recognition sites contain "GATC" at the cut region).
#
# `kind == "linear"` marks a fragment edge inherited from the input's
# linear endpoints — these don't ligate to anything (no chemistry).


_ENZYME_CUTS_CACHE: "_OD[tuple, list[dict]]" = _OD()
_ENZYME_CUTS_CACHE_MAX = 16


def _enzyme_cuts(seq: str, enzyme_names: list[str], *,
                  circular: bool = True) -> list[dict]:
    """Return all cuts on `seq` from the given enzymes, sorted by top
    cut position. Each entry is
    ``{top, bot, kind, overhang_seq, enzyme}`` where ``top`` and
    ``bot`` are absolute 0-based top-strand coords of the top-strand
    and bottom-strand cuts respectively.

    Unknown enzyme names are silently dropped (caller validates).
    Empty `enzyme_names` returns ``[]``.

    Results are LRU-cached on `(hash(seq), tuple(sorted enzymes), circular)`
    so that the Constructor's "Traditional" tab (which calls
    ``str(rec.seq).upper()`` afresh on every Simulate, allocating a
    new string object each time) still hits the cache on repeat
    clicks. Hash collisions are statistically irrelevant at the
    16-entry LRU size (~2^-32 per pair).

    Why not `id(seq)`: the old key only worked when the caller held
    onto the exact same string object across calls. The traditional-
    cloning flow doesn't, so the cache used to be permanently cold."""
    key = (hash(seq), tuple(sorted(set(enzyme_names))), bool(circular))
    hit = _ENZYME_CUTS_CACHE.get(key)
    if hit is not None:
        _ENZYME_CUTS_CACHE.move_to_end(key)
        # Defensive copy — callers occasionally mutate fragment dicts
        # (e.g., when filtering features), and a shared mutable list
        # would poison subsequent hits.
        return [dict(c) for c in hit]
    result = _enzyme_cuts_impl(seq, enzyme_names, circular=circular)
    if len(_ENZYME_CUTS_CACHE) >= _ENZYME_CUTS_CACHE_MAX:
        _ENZYME_CUTS_CACHE.popitem(last=False)
    _ENZYME_CUTS_CACHE[key] = [dict(c) for c in result]
    return result


def _enzyme_cuts_impl(seq: str, enzyme_names: list[str], *,
                        circular: bool = True) -> list[dict]:
    """Underlying scanner — see `_enzyme_cuts` for the cached entry
    point. Same signature + return shape; this one is the actual
    work."""
    n = len(seq)
    if n == 0 or not enzyme_names:
        return []
    seq_u = seq.upper()
    out: dict[tuple[int, int, str], dict] = {}
    for ename in enzyme_names:
        if ename not in _NEB_ENZYMES:
            continue
        site, fwd_cut, rev_cut = _NEB_ENZYMES[ename]
        site_u   = site.upper()
        site_len = len(site_u)
        pat      = _iupac_pattern(site_u)
        rc_site  = _rc(site_u)
        is_pal   = (rc_site == site_u)
        scan_seq = (seq_u + seq_u[: site_len - 1]) if (circular and n > 0) else seq_u

        def _emit(top_bp_raw: int, bot_bp_raw: int):
            # Use raw (pre-modulo) values for kind detection AND to find
            # the overhang's earlier-cut anchor — post-modulo, a cut
            # that crosses the origin can flip the top<bot ordering
            # (e.g., raw top=99, raw bot=103, n=100 → post-mod top=99,
            # bot=3, which would falsely suggest a 3' overhang). The
            # raw difference equals |fwd_cut - rev_cut| which is fixed
            # by the enzyme.
            top_bp = top_bp_raw % n
            bot_bp = bot_bp_raw % n
            overhang_len = abs(top_bp_raw - bot_bp_raw)
            oh_start = (top_bp if top_bp_raw <= bot_bp_raw else bot_bp)
            oh_end   = (oh_start + overhang_len) % n if n else 0
            if overhang_len == 0:
                overhang = ""
            elif oh_end > oh_start:
                overhang = seq_u[oh_start:oh_end]
            else:
                # Origin-wrap: overhang region crosses bp 0.
                overhang = seq_u[oh_start:] + seq_u[:oh_end]
            kind = ("blunt" if top_bp_raw == bot_bp_raw
                    else "5'" if top_bp_raw < bot_bp_raw
                    else "3'")
            key = (top_bp, bot_bp, ename)
            out[key] = {
                "top":          top_bp,
                "bot":          bot_bp,
                "kind":         kind,
                "overhang_seq": overhang,
                "enzyme":       ename,
            }

        for m in pat.finditer(scan_seq):
            p = m.start()
            if p >= n:
                continue
            _emit(p + fwd_cut, p + rev_cut)
        if not is_pal:
            rc_pat = _iupac_pattern(rc_site)
            for m in rc_pat.finditer(scan_seq):
                p = m.start()
                if p >= n:
                    continue
                # On a reverse-strand binding, the cut positions mirror
                # around the recognition midpoint. Top cut on the bound
                # site (= bottom strand of unbound) is `site_len - rev_cut`
                # bases from the recognition's 5' end on the unbound
                # forward strand; bottom cut is `site_len - fwd_cut`.
                _emit(p + site_len - rev_cut, p + site_len - fwd_cut)
    return sorted(out.values(), key=lambda c: (c["top"], c["enzyme"]))


def _split_features_at_cuts(features: list[dict], n: int,
                              cut_top_positions: list[int],
                              circular: bool) -> dict[int, list[dict]]:
    """Slot features into fragments based on cut positions. Returns
    ``{fragment_index: [features]}``. Features that span a cut are
    split into two halves (one in each adjacent fragment); wrap features
    in a circular input get the same treatment around the origin too.

    Fragment indexing matches ``_fragments_from_cuts`` ordering:
      - circular: `i` ranges over `[0, len(cuts))`, fragment `i` runs from
        `cuts[i].top` to `cuts[(i+1) % n_cuts].top`.
      - linear: `i` ranges over `[0, len(cuts)+1)`, fragment 0 starts at 0
        and fragment `len(cuts)` ends at `n`.
    """
    if not features:
        return {}
    n_cuts = len(cut_top_positions)
    if n_cuts == 0:
        # All features in fragment 0.
        return {0: list(features)}

    # Wrap features (end < start on a circular input) need to be
    # split into a tail half [start, n) + a head half [0, end)
    # before the slotting algorithm runs. The latter assumes
    # start ≤ end, so a wrap feature would otherwise route through
    # `_slot_for(end-1)` for a position BEFORE the wrap, mis-
    # slotting the head half into a non-adjacent fragment. Each
    # half is tagged with `_wrap_origin_split` so a downstream
    # caller can rejoin them if it cares about origin-spanning
    # annotations on the result.
    expanded: list[dict] = []
    for f in features:
        try:
            fs = int(f.get("start", 0))
            fe = int(f.get("end",   0))
        except (TypeError, ValueError):
            continue
        if circular and fe < fs and 0 <= fe and fs <= n:
            expanded.append({**f, "start": fs, "end": n,
                              "_wrap_origin_split": "tail"})
            expanded.append({**f, "start": 0, "end": fe,
                              "_wrap_origin_split": "head"})
        else:
            expanded.append(f)
    features = expanded

    def _slot_for(bp: int) -> int:
        """Return the fragment index containing `bp` (0-based)."""
        if circular:
            # Find the cut k such that bp ∈ (cuts[k], cuts[k+1]] (mod n).
            for i in range(n_cuts):
                a = cut_top_positions[i]
                b = cut_top_positions[(i + 1) % n_cuts]
                if a < b:
                    if a <= bp < b:
                        return i
                else:
                    # Wrap fragment crosses origin
                    if bp >= a or bp < b:
                        return i
            return 0
        # Linear: cut at position c → bases [c, next_c) belong to fragment k+1.
        for i, c in enumerate(cut_top_positions):
            if bp < c:
                return i
        return n_cuts

    out: dict[int, list[dict]] = {}
    for f in features:
        s = int(f.get("start", 0))
        e = int(f.get("end",   0))
        if e == s:
            slot = _slot_for(s)
            out.setdefault(slot, []).append(dict(f))
            continue
        slot_s = _slot_for(s)
        # End is half-open. A feature ending exactly at a cut belongs in
        # the fragment that ends at that cut. Use end-1 then bump.
        slot_e = _slot_for(e - 1)
        if slot_s == slot_e:
            out.setdefault(slot_s, []).append(dict(f))
        else:
            # Feature crosses one or more cuts; emit a half-feature into
            # each affected fragment. For v1 we don't try to chain them
            # across fragments — each half stands alone with its local
            # coords; the user can re-annotate if they want.
            out.setdefault(slot_s, []).append({**f, "_split": "head"})
            out.setdefault(slot_e, []).append({**f, "_split": "tail"})
    return out


def _fragments_from_cuts(seq: str, cuts: list[dict], *,
                          circular: bool,
                          features: "list[dict] | None" = None,
                          source_label: str = "") -> list[dict]:
    """Slice `seq` at the given cut positions into a list of Fragment dicts.

    For circular input with ≥1 cut: `len(cuts)` fragments arranged around
    the origin. For circular input with 0 cuts: 1 fragment (the whole
    plasmid linearised at position 0; both ends marked "linear" — the
    caller should usually error out before reaching this case).

    For linear input: `len(cuts) + 1` fragments; the leftmost fragment
    starts at 0, the rightmost ends at `n`. End edges of these are
    marked `kind="linear"` since there's no enzyme there.

    Each fragment's `top_seq` is the contiguous top-strand slice from
    one cut's `top` to the next cut's `top` (or origin / endpoint).
    Features are slotted via `_split_features_at_cuts` and shifted into
    fragment-local 0-based coords."""
    n = len(seq)
    if n == 0:
        return []
    if not cuts:
        if circular:
            return [{
                "top_seq": seq,
                "left":  {"overhang_seq": "", "kind": "linear", "enzyme": ""},
                "right": {"overhang_seq": "", "kind": "linear", "enzyme": ""},
                "features": [dict(f) for f in (features or [])],
                "source_label": source_label,
            }]
        return [{
            "top_seq": seq,
            "left":  {"overhang_seq": "", "kind": "linear", "enzyme": ""},
            "right": {"overhang_seq": "", "kind": "linear", "enzyme": ""},
            "features": [dict(f) for f in (features or [])],
            "source_label": source_label,
        }]
    cut_tops = [c["top"] for c in cuts]
    feat_slots = _split_features_at_cuts(features or [], n, cut_tops,
                                           circular=circular)
    fragments: list[dict] = []
    if circular:
        for i, c in enumerate(cuts):
            nxt = cuts[(i + 1) % len(cuts)]
            a, b = c["top"], nxt["top"]
            if a < b:
                top_seq = seq[a:b]
                offset  = a
            else:
                top_seq = seq[a:] + seq[:b]
                offset  = a   # fragment-local coord = (abs - a) % n
            local_feats: list[dict] = []
            for f in feat_slots.get(i, []):
                fs = int(f.get("start", 0))
                fe = int(f.get("end",   0))
                # Shift into fragment-local.
                if a < b:
                    new_s = fs - offset
                    new_e = fe - offset
                else:
                    new_s = (fs - offset) % n
                    new_e = (fe - offset) % n
                # Clamp to fragment bounds.
                local_feats.append({
                    **f,
                    "start": max(0, min(new_s, len(top_seq))),
                    "end":   max(0, min(new_e, len(top_seq))),
                })
            fragments.append({
                "top_seq": top_seq,
                "left":  {"overhang_seq": c["overhang_seq"],
                           "kind": c["kind"],
                           "enzyme": c["enzyme"]},
                "right": {"overhang_seq": nxt["overhang_seq"],
                           "kind": nxt["kind"],
                           "enzyme": nxt["enzyme"]},
                "features": local_feats,
                "source_label": source_label,
            })
        return fragments
    # Linear: walk left → right
    boundaries = [0] + cut_tops + [n]
    for i in range(len(boundaries) - 1):
        a, b = boundaries[i], boundaries[i + 1]
        top_seq = seq[a:b]
        local_feats: list[dict] = []
        for f in feat_slots.get(i, []):
            fs = int(f.get("start", 0))
            fe = int(f.get("end",   0))
            local_feats.append({
                **f,
                "start": max(0, min(fs - a, len(top_seq))),
                "end":   max(0, min(fe - a, len(top_seq))),
            })
        left  = ({"overhang_seq": "", "kind": "linear", "enzyme": ""}
                 if i == 0 else
                 {"overhang_seq": cuts[i - 1]["overhang_seq"],
                  "kind":         cuts[i - 1]["kind"],
                  "enzyme":       cuts[i - 1]["enzyme"]})
        right = ({"overhang_seq": "", "kind": "linear", "enzyme": ""}
                 if i == len(boundaries) - 2 else
                 {"overhang_seq": cuts[i]["overhang_seq"],
                  "kind":         cuts[i]["kind"],
                  "enzyme":       cuts[i]["enzyme"]})
        fragments.append({
            "top_seq":      top_seq,
            "left":         left,
            "right":        right,
            "features":     local_feats,
            "source_label": source_label,
        })
    return fragments


def _digest_with_enzymes(seq: str, enzyme_names: list[str], *,
                          circular: bool = True,
                          features: "list[dict] | None" = None,
                          source_label: str = "") -> list[dict]:
    """One-call digest: cut `seq` with `enzyme_names`, return Fragments.

    Fragments are sorted in cut order around the molecule (or 5'→3' for
    linear). Caller passes the input's features in absolute 0-based
    coords; they're slotted + shifted onto the appropriate fragments.

    Empty `enzyme_names` (or all-unknown) returns the input as a single
    uncut fragment."""
    cuts = _enzyme_cuts(seq, enzyme_names, circular=circular)
    return _fragments_from_cuts(seq, cuts, circular=circular,
                                  features=features,
                                  source_label=source_label)


def _ends_compatible(end_a: dict, end_b: dict) -> bool:
    """Return True if two fragment edges can ligate. Same kind +
    matching overhang sequence (both stored top-strand-canonical). A
    `linear` edge never ligates."""
    ka, kb = end_a.get("kind"), end_b.get("kind")
    if ka == "linear" or kb == "linear":
        return False
    if ka != kb:
        return False
    return end_a.get("overhang_seq", "") == end_b.get("overhang_seq", "")


def _ligate_fragments(a: dict, b: dict) -> "dict | None":
    """Ligate `a.right` to `b.left`. Returns merged fragment (linear),
    or None if the overhangs are incompatible. The merged top strand
    is `a.top_seq + b.top_seq` (overhang bases live in whichever piece's
    top strand carried them — see the canonicalisation comment above).
    Features from `b` are shifted by `len(a.top_seq)`."""
    if not _ends_compatible(a["right"], b["left"]):
        return None
    shift = len(a["top_seq"])
    merged_feats = list(a["features"])
    for f in b["features"]:
        merged_feats.append({
            **f,
            "start": int(f.get("start", 0)) + shift,
            "end":   int(f.get("end",   0)) + shift,
        })
    return {
        "top_seq":      a["top_seq"] + b["top_seq"],
        "left":         a["left"],
        "right":        b["right"],
        "features":     merged_feats,
        "source_label": (f"{a['source_label']}+{b['source_label']}"
                         if a["source_label"] or b["source_label"] else ""),
    }


def _close_circular(frag: dict) -> "dict | None":
    """Close a linear fragment into a circle by ligating its right + left
    edges. Returns ``{top_seq, features, source_label, circular: True}``
    or None if the ends don't match."""
    if not _ends_compatible(frag["right"], frag["left"]):
        return None
    return {
        "top_seq":      frag["top_seq"],
        "features":     [dict(f) for f in frag["features"]],
        "source_label": frag["source_label"],
        "circular":     True,
    }


def _make_synthetic_fragment(seq: str, *, enz_left: str, enz_right: str,
                               source_label: str = "",
                               features: "list[dict] | None" = None,
                              ) -> dict:
    """Synthesise a Fragment from a linear DNA sequence by stamping
    canonical sticky ends from the chosen enzymes — used by
    insert-source modes (b) and (c) where the user supplies "the
    PCR product / feature, with primer tails carrying enzyme sites".
    The simulator doesn't pretend to find recognition sites in the
    input — it just synthesises the overhangs the user said they'd
    add via primer design.

    Both enzymes must be in `_NEB_ENZYMES`. Raises ValueError on
    unknown names. Features (if any) shift by the canonical overhang
    length on the left so coords land in the right place after
    ligation."""
    if enz_left not in _NEB_ENZYMES:
        raise ValueError(f"unknown enzyme: {enz_left!r}")
    if enz_right not in _NEB_ENZYMES:
        raise ValueError(f"unknown enzyme: {enz_right!r}")
    site_l, fwd_l, rev_l = _NEB_ENZYMES[enz_left]
    site_r, fwd_r, rev_r = _NEB_ENZYMES[enz_right]
    site_l_u = site_l.upper()
    site_r_u = site_r.upper()
    site_l_len = len(site_l_u)
    site_r_len = len(site_r_u)
    # Canonical overhang for `enz_left`: top-strand bases of the
    # recognition site between min(fwd, rev) and max(fwd, rev). This
    # is what the user effectively "buys" by adding the recognition
    # site as a primer tail and then digesting.
    lo_l, hi_l = min(fwd_l, rev_l), max(fwd_l, rev_l)
    lo_r, hi_r = min(fwd_r, rev_r), max(fwd_r, rev_r)
    # Type IIS enzymes (BsaI, Esp3I, BsmBI, etc.) cut OUTSIDE their
    # recognition site, so `hi > site_len` and the overhang depends
    # on bases the user supplies AFTER the recognition — not on
    # the recognition itself. The synthetic-fragment model can't
    # know what those bases are, so it'd produce an empty overhang
    # and silently fail to ligate. Reject upfront with a message
    # pointing at the literal-digest mode (a) which DOES handle
    # Type IIS correctly because it operates on the actual sequence.
    if hi_l > site_l_len or lo_l < 0:
        raise ValueError(
            f"{enz_left!r} cuts outside its recognition site (Type IIS); "
            f"use 'From plasmid' mode for literal digest"
        )
    if hi_r > site_r_len or lo_r < 0:
        raise ValueError(
            f"{enz_right!r} cuts outside its recognition site (Type IIS); "
            f"use 'From plasmid' mode for literal digest"
        )
    overhang_l = site_l_u[lo_l:hi_l]
    overhang_r = site_r_u[lo_r:hi_r]
    kind_l = ("blunt" if fwd_l == rev_l
              else "5'" if fwd_l < rev_l else "3'")
    kind_r = ("blunt" if fwd_r == rev_r
              else "5'" if fwd_r < rev_r else "3'")
    return {
        "top_seq":      seq.upper(),
        "left":  {"overhang_seq": overhang_l, "kind": kind_l,
                  "enzyme": enz_left},
        "right": {"overhang_seq": overhang_r, "kind": kind_r,
                  "enzyme": enz_right},
        "features":     [dict(f) for f in (features or [])],
        "source_label": source_label,
    }


@_timed("op.excise_fragment_pair", threshold_ms=25)
def _excise_fragment_pair(seq: str, enzyme_names: list[str], *,
                           circular: bool = True,
                           features: "list[dict] | None" = None,
                           source_label: str = "",
                          ) -> tuple[list[dict], "dict | None"]:
    """Mode (a) helper for both insert and vector: digest `seq` with
    the given enzymes; return ``(fragments, error_dict_or_none)``. If
    the digest produces exactly 2 fragments (typical 1-cut + 1-cut
    case on a circular plasmid), the caller picks one as the insert
    or vector. Otherwise an error dict is returned describing the
    cut count problem.

    The error dict has shape ``{"error": str, "cuts": [{enzyme, top}]}``
    so the UI can surface it clearly."""
    cuts = _enzyme_cuts(seq, enzyme_names, circular=circular)
    n_cuts = len(cuts)
    if n_cuts == 0:
        return [], {"error": (f"no cut sites found for "
                                f"{', '.join(enzyme_names) or '(none)'}"),
                     "cuts": []}
    # Categorise per enzyme so the error message is specific.
    per_enzyme: dict[str, int] = {}
    for c in cuts:
        per_enzyme[c["enzyme"]] = per_enzyme.get(c["enzyme"], 0) + 1
    fragments = _fragments_from_cuts(seq, cuts, circular=circular,
                                       features=features,
                                       source_label=source_label)
    if circular and n_cuts < 2:
        return fragments, {
            "error":
                (f"need ≥2 cuts to excise an insert; "
                 f"got {n_cuts} on a circular plasmid"),
            "cuts": [{"enzyme": c["enzyme"], "top": c["top"]} for c in cuts],
        }
    # Exactly-2 cuts is the only ligation-compatible case for the
    # 2-fragment "insert + vector" model. ≥3 cuts on a circular plasmid
    # produces N fragments and the caller can't unambiguously pick the
    # "insert" vs the "vector" — surface the ambiguity here so future
    # callers can't quietly take fragments[0:2] and ship a wrong product.
    if circular and n_cuts > 2:
        per_enz_str = ", ".join(f"{e}×{n}" for e, n in per_enzyme.items())
        return fragments, {
            "error":
                (f"got {n_cuts} cut sites ({per_enz_str}); "
                 f"need exactly 2 for unambiguous excise. "
                 f"Pick a different enzyme pair."),
            "cuts": [{"enzyme": c["enzyme"], "top": c["top"]} for c in cuts],
        }
    return fragments, None


@_timed("op.simulate_traditional_cloning")
def _simulate_traditional_cloning(insert_frag: dict,
                                    vector_frag: dict,
                                   ) -> dict:
    """Try to ligate `insert_frag` into `vector_frag` in both possible
    orientations, returning a result dict:

      ``{
          "forward":  {"top_seq", "features", "compatible": bool},
          "reverse":  {"top_seq", "features", "compatible": bool},
          "warnings": [str, ...],
          "errors":   [str, ...],
        }``

    `forward` = vector + insert as supplied; `reverse` = vector + RC of
    insert. `compatible` is True when the overhangs actually permit
    that orientation; False means the orientation is rendered for
    reference (the insert can be flipped post-hoc) but isn't reachable
    by canonical ligation chemistry. When BOTH orientations are
    compatible (common with palindromic single-enzyme cuts), a
    warning calls out the ambiguity."""
    warnings: list[str] = []
    errors:   list[str] = []
    insert_rc = _rc_fragment(insert_frag)

    fwd_linear = _ligate_fragments(vector_frag, insert_frag)
    rev_linear = _ligate_fragments(vector_frag, insert_rc)

    fwd_compat = fwd_linear is not None and \
        _ends_compatible(fwd_linear["right"], fwd_linear["left"])
    rev_compat = rev_linear is not None and \
        _ends_compatible(rev_linear["right"], rev_linear["left"])

    fwd_seq = (fwd_linear["top_seq"] if fwd_linear is not None
               else vector_frag["top_seq"] + insert_frag["top_seq"])
    rev_seq = (rev_linear["top_seq"] if rev_linear is not None
               else vector_frag["top_seq"] + insert_rc["top_seq"])

    def _shift_feats(base: dict, shift: int) -> list[dict]:
        return [{**f,
                  "start": int(f.get("start", 0)) + shift,
                  "end":   int(f.get("end",   0)) + shift}
                 for f in base["features"]]

    fwd_feats = list(vector_frag["features"]) + _shift_feats(
        insert_frag, len(vector_frag["top_seq"]))
    rev_feats = list(vector_frag["features"]) + _shift_feats(
        insert_rc,   len(vector_frag["top_seq"]))

    if fwd_compat and rev_compat:
        warnings.append(
            "Ambiguous orientation: both forward and reverse ligation "
            "are chemically compatible. The cloning reaction will yield "
            "a mixture; pick by sequencing.")
    elif fwd_compat and not rev_compat:
        warnings.append(
            "Directional cloning: only the forward orientation is "
            "biologically achievable. Reverse is rendered for reference "
            "but cannot ligate.")
    elif rev_compat and not fwd_compat:
        warnings.append(
            "Directional cloning: only the reverse orientation is "
            "biologically achievable. Forward is rendered for reference "
            "but cannot ligate.")
    else:
        errors.append(
            "Neither orientation has matching overhangs at both junctions. "
            "Check that the insert and vector were cut with the same "
            "enzyme(s).")

    return {
        "forward": {"top_seq": fwd_seq, "features": fwd_feats,
                     "compatible": fwd_compat},
        "reverse": {"top_seq": rev_seq, "features": rev_feats,
                     "compatible": rev_compat},
        "warnings": warnings,
        "errors":   errors,
    }


# ── Gibson assembly ───────────────────────────────────────────────────────────
#
# Gibson chemistry: 5' exonuclease chews back the 5' end of each fragment,
# exposing a 3' single-stranded tail. Tails that share a complementary
# homology region anneal; DNA polymerase fills gaps; DNA ligase seals
# nicks. Net result: adjacent fragments are joined seamlessly and the
# homology region appears ONCE in the product.
#
# The simulator here treats each fragment as a top-strand DNA sequence
# (5' → 3') and finds the longest exact-match suffix-of-A / prefix-of-B
# overlap at each junction. The user is responsible for designing
# primer tails that produce these overlaps — the simulator doesn't
# pretend to extend short overlaps via heuristic search. Below
# `_GIBSON_MIN_OVERLAP_BP` (15 bp by default, Gibson's commonly cited
# floor), the junction is rejected so the user can fix the design
# before committing the assembled product to the library.

_GIBSON_MIN_OVERLAP_BP = 15
_GIBSON_MAX_OVERLAP_BP = 200   # cap the suffix/prefix probe; longer is
                                # unrealistic for Gibson primer tails


def _gibson_overlap_len(a_seq: str, b_seq: str, *,
                          min_overlap: int = _GIBSON_MIN_OVERLAP_BP,
                          max_overlap: int = _GIBSON_MAX_OVERLAP_BP,
                          ) -> int:
    """Length of the longest exact-match overlap between `a_seq`'s 3'
    end and `b_seq`'s 5' end, in `[min_overlap, max_overlap]`.
    Returns 0 if no overlap of at least `min_overlap` bp matches.

    Comparison is case-insensitive. Bigger overlap preferred —
    biologically, the homology arm the user designed is the longest
    exact match, not a degenerate short one inside it.

    When `a_seq` is identical to `b_seq` (e.g. the n=1 circular
    self-circularisation probe, where the simulator passes the same
    fragment as both a and b), the probe caps at `len(a) - 1` so the
    trivial whole-string match is skipped — without the cap, the user's
    intended short homology arm at the fragment ends would be masked
    by the always-matching full string.
    """
    if min_overlap <= 0:
        min_overlap = 1
    a = a_seq.upper()
    b = b_seq.upper()
    # Whole-string match is degenerate when the two sides are the same
    # sequence — cap one shorter so the probe finds a real arm overlap.
    # For distinct sequences a full-length match is biologically legal
    # (one fragment is a prefix/suffix of the other); the downstream
    # body-length validation in `_simulate_gibson_assembly` decides.
    full_match_safe = (a != b)
    max_check = min(max_overlap, len(a), len(b))
    if not full_match_safe:
        max_check = min(max_check, len(a) - 1)
    if max_check < min_overlap:
        return 0
    for k in range(max_check, min_overlap - 1, -1):
        if a[-k:] == b[:k]:
            return k
    return 0


@_timed("op.gibson_simulate")
# ── _simulate_gibson_assembly helpers ─────────────────────────────────────
#
# The Gibson simulator was 370 lines pre-refactor. The math is
# biology-critical (junction-overlap detection, body-length validation,
# wrap-aware feature shifting, wrap-half re-merge), so the helpers are
# defined as pure functions with explicit `(input) → output` signatures
# — no shared closure state, no hidden dependencies. Behaviour is bit-
# identical to the pre-refactor version, tested by tests/test_gibson.py
# (47 cases) which passed before AND after the extraction.


def _gibson_failure(circular: bool, errors: list[str],
                       overlaps: "list[dict] | None" = None,
                       warnings: "list[str] | None" = None) -> dict:
    """Standard failure-shaped result dict for the Gibson pipeline.

    Centralising it ensures every short-circuit returns the same shape
    (success=False, empty product_seq, empty features) — a property the
    UI consumer (`GibsonAssemblyPane`) relies on."""
    return {
        "success":     False,
        "product_seq": "",
        "circular":    circular,
        "features":    [],
        "overlaps":    list(overlaps or []),
        "errors":      list(errors),
        "warnings":    list(warnings or []),
    }


def _gibson_normalize_fragments(
    fragments: list[dict],
) -> "tuple[list[dict] | None, str | None]":
    """Uppercase + whitespace-strip each fragment's sequence.

    Returns ``(norm_fragments, None)`` on success or ``(None, error_msg)``
    on the two short-circuit failure modes: empty input list, or any
    fragment that isn't a dict.

    The normalised list is a parallel structure to `fragments` —
    name / sequence / features — with the sequence cleaned. We
    intentionally don't mutate the caller's dicts."""
    if not fragments:
        return None, "No fragments supplied."
    norm_fragments: list[dict] = []
    for f in fragments:
        if not isinstance(f, dict):
            return None, "Each fragment must be a dict."
        raw = str(f.get("sequence") or "")
        cleaned = "".join(ch for ch in raw.upper() if not ch.isspace())
        norm_fragments.append({
            "name":     str(f.get("name") or "?"),
            "sequence": cleaned,
            "features": list(f.get("features") or []),
        })
    return norm_fragments, None


def _gibson_detect_overlaps(
    norm_fragments: list[dict], *, min_overlap: int, circular: bool,
) -> "tuple[list[dict], list[int], list[str]]":
    """For each junction (consecutive pair plus wrap when circular),
    detect the longest exact-match suffix/prefix overlap.

    Returns ``(overlaps, overlap_lens, errors)``:
      * `overlaps`: one dict per junction (junction, from, to, length,
        seq, ok, is_wrap, rc_hint) — the UI shows the full chain even
        on partial failure, so this is populated regardless of success.
      * `overlap_lens`: parallel list of int lengths for the build step.
      * `errors`: human-readable junction-failure messages.
    """
    n = len(norm_fragments)
    n_junctions = n if circular else n - 1
    overlaps: list[dict] = []
    overlap_lens: list[int] = []
    errors: list[str] = []
    for i in range(n_junctions):
        a = norm_fragments[i]
        b = norm_fragments[(i + 1) % n]
        a_seq = a["sequence"]
        b_seq = b["sequence"]
        k = _gibson_overlap_len(a_seq, b_seq, min_overlap=min_overlap)
        ok = k >= min_overlap
        rc_hint = _gibson_rc_hint(a, b, min_overlap=min_overlap) if not ok else ""
        overlaps.append({
            "junction": i + 1,
            "from":     a["name"],
            "to":       b["name"],
            "length":   k,
            "seq":      a_seq[-k:] if k else "",
            "ok":       ok,
            "is_wrap":  (circular and i == n - 1),
            "rc_hint":  rc_hint,
        })
        if not ok:
            errors.append(
                f"Junction {i+1} ({a['name']!r} → {b['name']!r}): "
                f"no overlap ≥ {min_overlap} bp." + rc_hint
            )
        overlap_lens.append(k)
    return overlaps, overlap_lens, errors


def _gibson_rc_hint(a: dict, b: dict, *, min_overlap: int) -> str:
    """Reverse-orientation diagnostic. If the forward overlap failed,
    probe RC(b) and RC(a) at a lower threshold (min of `min_overlap`
    and 10 bp so the user sees the hint even with a high min). Returns
    `""` if neither RC orientation yields a plausible overlap.

    Returning a string so the caller can concat into the error message
    without an extra branch — keeps the failure path linear."""
    a_seq = a["sequence"]
    b_seq = b["sequence"]
    probe_min = min(min_overlap, 10)
    k_b_rc = _gibson_overlap_len(a_seq, _rc(b_seq), min_overlap=probe_min)
    k_a_rc = _gibson_overlap_len(_rc(a_seq), b_seq, min_overlap=probe_min)
    if k_b_rc >= probe_min and k_b_rc >= k_a_rc:
        return (
            f" — but reverse-complement of {b['name']!r} "
            f"yields a {k_b_rc} bp overlap; "
            f"did you mean to flip {b['name']!r}?"
        )
    if k_a_rc >= probe_min:
        return (
            f" — but reverse-complement of {a['name']!r} "
            f"yields a {k_a_rc} bp overlap; "
            f"did you mean to flip {a['name']!r}?"
        )
    return ""


def _gibson_validate_body_lengths(
    norm_fragments: list[dict], overlap_lens: list[int], *, circular: bool,
) -> list[str]:
    """Check that every fragment has body bases left after its homology
    arms. A fragment fully consumed by overlap(s) is biologically
    redundant — its bases are entirely supplied by adjacent fragments.

    Returns a list of error messages; empty list means OK.

    Three sub-cases:
      * fragments[i>0]: leading overlap from junction i-1.
      * circular n==1: self-circularisation uses overlap_lens[0] as a
        single wrap arm.
      * circular n>1: last fragment has BOTH leading + trailing arms.
    """
    n = len(norm_fragments)
    errors: list[str] = []
    for i in range(1, n):
        oh_lead = overlap_lens[i - 1]
        frag_len = len(norm_fragments[i]["sequence"])
        if oh_lead >= frag_len:
            errors.append(
                f"Fragment {norm_fragments[i]['name']!r} is consumed "
                f"by its leading {oh_lead} bp overlap "
                f"(fragment is {frag_len} bp). "
                f"Use a longer fragment or shorter overlap."
            )
    if circular and not errors:
        if n == 1:
            wrap_oh = overlap_lens[0]
            frag_len = len(norm_fragments[0]["sequence"])
            if wrap_oh >= frag_len:
                errors.append(
                    f"Fragment {norm_fragments[0]['name']!r} is fully "
                    f"consumed by its self-circularisation overlap "
                    f"({wrap_oh} ≥ {frag_len} bp)."
                )
        else:
            last_lead  = overlap_lens[n - 2]
            last_trail = overlap_lens[n - 1]
            last_len = len(norm_fragments[-1]["sequence"])
            if last_lead + last_trail >= last_len:
                errors.append(
                    f"Fragment {norm_fragments[-1]['name']!r} is fully "
                    f"consumed by its homology arms ({last_lead} + "
                    f"{last_trail} ≥ {last_len} bp). Pick a longer "
                    f"fragment or shorter overlaps."
                )
    return errors


def _gibson_short_fragment_warnings(
    norm_fragments: list[dict], *, min_overlap: int,
) -> list[str]:
    """Soft warning: fragments < 3× min_overlap are legal but unusual,
    flag for awareness without blocking the save."""
    warnings: list[str] = []
    for f in norm_fragments:
        if 0 < len(f["sequence"]) < 3 * min_overlap:
            warnings.append(
                f"Fragment {f['name']!r} is short "
                f"({len(f['sequence'])} bp) relative to the "
                f"{min_overlap} bp homology arms — assembly may "
                f"be hard to confirm by gel."
            )
    return warnings


def _gibson_build_product(
    norm_fragments: list[dict], overlap_lens: list[int], *, circular: bool,
) -> "tuple[str, list[int]]":
    """Concatenate fragment bodies into the product sequence, tracking
    each fragment's offset in product coordinates. The trailing copy
    of each overlap is dropped (`frag[i+1][oh_lead:]`).

    Returns ``(product_seq, offsets)`` where offsets[i] is the product
    coord at which fragments[i]'s local-pos 0 lands. For wrap fragments
    this offset can be negative-equivalent (modulo product_len)."""
    n = len(norm_fragments)
    seq_parts: list[str] = []
    offsets: list[int] = []
    first_seq = norm_fragments[0]["sequence"]
    seq_parts.append(first_seq)
    offsets.append(0)
    cursor = len(first_seq)
    for i in range(1, n):
        oh_lead = overlap_lens[i - 1]
        frag_seq = norm_fragments[i]["sequence"]
        body = frag_seq[oh_lead:]
        seq_parts.append(body)
        # Fragment i's local-pos 0 maps to product pos (cursor - oh_lead)
        # — the leading overlap bases already exist as the previous
        # fragment's tail.
        offsets.append(cursor - oh_lead)
        cursor += len(body)
    if circular:
        if n == 1:
            # Self-circularisation: drop the trailing wrap overlap from
            # the only fragment. seq_parts has one entry == fragments[0].
            wrap_oh = overlap_lens[0]
            if wrap_oh > 0:
                seq_parts[0] = seq_parts[0][:-wrap_oh]
        else:
            wrap_oh = overlap_lens[n - 1]
            if wrap_oh > 0:
                # Drop the last fragment's trailing-overlap bases —
                # they equal the first fragment's leading bases, which
                # are already at the start of the product.
                seq_parts[-1] = seq_parts[-1][:-wrap_oh]
    product_seq = "".join(seq_parts)
    return product_seq, offsets


def _gibson_shift_features(
    norm_fragments: list[dict], overlap_lens: list[int],
    offsets: list[int], product_len: int, *, circular: bool,
) -> list[dict]:
    """Shift each fragment's features into product coords. Features
    wholly inside a fragment's leading-overlap region (i > 0) are
    skipped — the preceding fragment already supplies the same bases
    at the same product coords, so emitting them again duplicates the
    annotation. For circular, features that straddle the wrap junction
    become wrap features (`end < start`) per the dict-feature
    convention; `_feat_len` / `_bp_in` handle the resulting topology."""
    shifted: list[dict] = []
    for i, f_dict in enumerate(norm_fragments):
        offset = offsets[i]
        oh_lead = overlap_lens[i - 1] if i > 0 else 0
        for feat in (f_dict.get("features") or []):
            if not isinstance(feat, dict):
                continue
            if str(feat.get("type") or "") == "source":
                continue
            try:
                s = int(feat.get("start", 0))
                e = int(feat.get("end",   0))
            except (TypeError, ValueError):
                continue
            if e <= s:
                continue
            if i > 0 and e <= oh_lead:
                # Feature lies entirely in the leading-overlap region
                # — preceding fragment already supplies its annotation
                # at the same product coords. Skip to avoid a duplicate.
                continue
            new_s = offset + s
            new_e = offset + e
            span = new_e - new_s
            if circular and product_len > 0:
                # Wrap math: modulo into product coords. The span
                # (linear length) is invariant under shift, so we
                # decide product topology from `span` not from the
                # `ms <=> me` ordering — which is ambiguous when
                # `ms == me` mod product_len.
                ms = new_s % product_len
                me_raw = new_e % product_len
                # `me == 0` with span > 0 means the feature ends
                # exactly at the product's wrap point — keep it as
                # `product_len` so the linear-form expression matches.
                me = product_len if (me_raw == 0 and span > 0) else me_raw
                if span >= product_len:
                    new_s, new_e = 0, product_len
                else:
                    new_s, new_e = ms, me
            else:
                # Linear product. Negative `new_s` means the feature's
                # 5' edge sits before the product start — the only way
                # this happens is if a middle fragment is shorter than
                # its lead+trail arms (a pathological design the
                # simulator doesn't reject up front; see the body
                # length check above which only catches single-arm
                # exhaustion). Skip rather than clamp: clamping would
                # silently shift the feature's biological coordinates,
                # whereas skip is honest about the lost annotation.
                if new_s < 0:
                    continue
                if new_e > product_len:
                    new_e = product_len
                if new_e <= new_s:
                    continue
            shifted.append({**feat, "start": new_s, "end": new_e})
    return shifted


def _gibson_merge_wrap_halves(
    shifted: list[dict], product_len: int, *, circular: bool,
) -> list[dict]:
    """Re-merge `_wrap_pair`-tagged halves: when a circular source
    plasmid's wrap feature was split by `_record_features`, both halves
    carry the same ``_wrap_pair`` id + ``_wrap_role`` (head/tail). After
    shifting, if the two halves are still adjacent across the product's
    wrap (head.start == 0 AND tail.end == product_len) we collapse them
    back into one wrap feature. For linear products or non-adjacent
    halves the split is preserved — the biological feature was severed
    by the assembly geometry."""
    out_feats: list[dict] = []
    if not (circular and product_len > 0):
        # Linear product: just strip wrap-pair sentinels and pass through.
        for f in shifted:
            out_feats.append({
                k: v for k, v in f.items()
                if not k.startswith("_wrap_")
            })
        return out_feats
    # Index pairs in one pass so we can match heads to tails O(1) below.
    pair_index: dict[str, list[dict]] = {}
    for f in shifted:
        pid = f.get("_wrap_pair")
        if pid:
            pair_index.setdefault(pid, []).append(f)
    handled_pairs: set[str] = set()
    for f in shifted:
        pid = f.get("_wrap_pair")
        if pid and pid not in handled_pairs:
            halves = pair_index.get(pid) or []
            if len(halves) == 2:
                head = next((h for h in halves
                             if h.get("_wrap_role") == "head"), None)
                tail = next((h for h in halves
                             if h.get("_wrap_role") == "tail"), None)
                if (head is not None and tail is not None
                        and head["start"] == 0
                        and tail["end"] == product_len):
                    merged = {k: v for k, v in tail.items()
                              if not k.startswith("_wrap_")}
                    merged["start"] = tail["start"]
                    merged["end"]   = head["end"]
                    out_feats.append(merged)
                    handled_pairs.add(pid)
                    continue
        # Either no wrap pair, pair already handled, or halves not
        # adjacent — strip wrap sentinels and pass through individually.
        if pid in handled_pairs:
            continue
        out_feats.append({
            k: v for k, v in f.items()
            if not k.startswith("_wrap_")
        })
    return out_feats


def _simulate_gibson_assembly(fragments: list[dict], *,
                                min_overlap: int = _GIBSON_MIN_OVERLAP_BP,
                                circular: bool = True,
                              ) -> dict:
    """Simulate a Gibson assembly of N linear top-strand fragments.

    Each ``fragments[i]`` dict shape:
        {
          "name":     str,
          "sequence": str,            # linear DNA 5' → 3'
          "features": list[dict],     # optional, in fragment-local coords
        }

    For each junction (consecutive pair plus the wrap junction when
    ``circular=True``) the longest exact-match suffix/prefix overlap
    is detected. Any junction below ``min_overlap`` bp fails the
    assembly. The product sequence has each overlap appearing once
    (the trailing copy is dropped: ``frag[i] + frag[i+1][overlap:]``).
    Features are shifted into product coordinates; features wholly
    inside a fragment's leading-overlap region are skipped (they're
    already represented by the preceding fragment's trailing copy).

    Returns ``{success, product_seq, circular, features, overlaps,
    errors, warnings}`` — see UI consumer (``GibsonAssemblyPane``)
    for the rendering convention. ``overlaps`` always has one entry
    per junction so the UI can show the full chain even on partial
    failure.

    Pre-refactor this was a 370-line monolith; the per-stage logic
    now lives in `_gibson_*` helpers (normalise → detect overlaps →
    validate body lengths → build product seq → shift features →
    re-merge wrap halves). Behaviour is bit-identical; tested by
    tests/test_gibson.py (47 cases).
    """
    norm_fragments, norm_err = _gibson_normalize_fragments(fragments)
    if norm_err is not None:
        return _gibson_failure(circular, [norm_err])
    assert norm_fragments is not None  # err None ⇒ list present

    # Reject zero-length fragments up front — they can't carry homology.
    for f in norm_fragments:
        if not f["sequence"]:
            return _gibson_failure(
                circular, [f"Fragment {f['name']!r} has no sequence."]
            )

    if len(norm_fragments) == 1 and not circular:
        # A single linear fragment doesn't need Gibson — pass through.
        f = norm_fragments[0]
        return {
            "success":     True,
            "product_seq": f["sequence"],
            "circular":    False,
            "features":    list(f["features"]),
            "overlaps":    [],
            "errors":      [],
            "warnings":    [
                "Single linear fragment — no Gibson junctions to "
                "validate. Product is the fragment as supplied.",
            ],
        }

    overlaps, overlap_lens, junction_errors = _gibson_detect_overlaps(
        norm_fragments, min_overlap=min_overlap, circular=circular,
    )
    if junction_errors:
        return _gibson_failure(circular, junction_errors, overlaps=overlaps)

    body_errors = _gibson_validate_body_lengths(
        norm_fragments, overlap_lens, circular=circular,
    )
    if body_errors:
        return _gibson_failure(circular, body_errors, overlaps=overlaps)

    warnings = _gibson_short_fragment_warnings(
        norm_fragments, min_overlap=min_overlap,
    )

    product_seq, offsets = _gibson_build_product(
        norm_fragments, overlap_lens, circular=circular,
    )
    product_len = len(product_seq)

    shifted = _gibson_shift_features(
        norm_fragments, overlap_lens, offsets, product_len,
        circular=circular,
    )
    out_feats = _gibson_merge_wrap_halves(
        shifted, product_len, circular=circular,
    )

    return {
        "success":     True,
        "product_seq": product_seq,
        "circular":    circular,
        "features":    out_feats,
        "overlaps":    overlaps,
        "errors":      [],
        "warnings":    warnings,
    }


def _gibson_record_from_result(result: dict, *, name: str) -> "SeqRecord | None":
    """Build a SeqRecord from a successful ``_simulate_gibson_assembly``
    result. Returns ``None`` when ``result["success"] is False``.

    Wrap features (``end < start``) become ``CompoundLocation`` per the
    GenBank wrap convention. Linear features land as ``FeatureLocation``.
    Strand defaults to +1 when missing.
    """
    if not result or not result.get("success"):
        return None
    from Bio.Seq import Seq
    from Bio.SeqRecord import SeqRecord
    from Bio.SeqFeature import (
        SeqFeature, FeatureLocation, CompoundLocation,
    )
    seq_str = str(result.get("product_seq") or "")
    n = len(seq_str)
    safe_name = re.sub(r"[^A-Za-z0-9_]+", "_", name or "gibson") or "gibson"
    topology = "circular" if result.get("circular") else "linear"
    rec = SeqRecord(
        Seq(seq_str),
        id=safe_name[:16] or "gibson",
        name=safe_name[:16] or "gibson",
        description=name or "Gibson assembly",
        annotations={
            "molecule_type": "DNA",
            "topology":      topology,
        },
    )
    for f in (result.get("features") or []):
        if not isinstance(f, dict):
            continue
        try:
            s = int(f.get("start", 0))
            e = int(f.get("end",   0))
            strand = int(f.get("strand", 1) or 1)
        except (TypeError, ValueError):
            continue
        if s == e or n == 0:
            continue
        ftype = str(f.get("type") or "misc_feature")
        quals: dict = {}
        label = f.get("label")
        if label:
            quals["label"] = [str(label)]
        color = f.get("color")
        if color:
            quals["ApEinfo_fwdcolor"] = [str(color)]
            quals["ApEinfo_revcolor"] = [str(color)]
        note = f.get("note")
        if note:
            quals["note"] = [str(note)]
        if e > s:
            loc = FeatureLocation(s, e, strand=strand)
        else:
            # Wrap feature: (s, n) + (0, e)
            loc = CompoundLocation([
                FeatureLocation(s, n, strand=strand),
                FeatureLocation(0, e, strand=strand),
            ])
        rec.features.append(SeqFeature(loc, type=ftype, qualifiers=quals))
    return rec


def _rc_fragment(frag: dict) -> dict:
    """Reverse-complement a Fragment, swapping its left/right ends and
    flipping its feature coordinates. The overhang sequences of the
    swapped ends are themselves reverse-complemented (the strand that
    sticks out is now the other strand). 5' overhangs stay 5' (the
    "5'-protruding" geometry is preserved across the flip — only the
    bases change)."""
    n = len(frag["top_seq"])
    new_left  = {
        "overhang_seq": _rc(frag["right"]["overhang_seq"])
                        if frag["right"]["overhang_seq"] else "",
        "kind":         frag["right"]["kind"],
        "enzyme":       frag["right"]["enzyme"],
    }
    new_right = {
        "overhang_seq": _rc(frag["left"]["overhang_seq"])
                        if frag["left"]["overhang_seq"] else "",
        "kind":         frag["left"]["kind"],
        "enzyme":       frag["left"]["enzyme"],
    }
    flipped_feats: list[dict] = []
    for f in frag["features"]:
        fs = int(f.get("start", 0))
        fe = int(f.get("end",   0))
        new_f = dict(f)
        new_f["start"]  = max(0, n - fe)
        new_f["end"]    = max(0, n - fs)
        new_f["strand"] = -int(f.get("strand", 1) or 0) or 0
        flipped_feats.append(new_f)
    return {
        "top_seq":      _rc(frag["top_seq"]),
        "left":         new_left,
        "right":        new_right,
        "features":     flipped_feats,
        "source_label": frag["source_label"],
    }


def _emit_packed_row(result: "Text", row_arr: list[tuple[str, str]],
                      prefix_w: int) -> None:
    """Append a packed row (per-column (char, style) tuples) to `result`
    with line-number gutter. Run-length-merges adjacent same-style
    cells to keep `Text.append` calls cheap."""
    result.append(" " * prefix_w, style="color(245)")
    run: list[str] = []
    cur_sty = ""
    for ch, sty in row_arr:
        if sty == cur_sty:
            run.append(ch)
        else:
            if run:
                result.append("".join(run), style=cur_sty)
            run = [ch]
            cur_sty = sty
    if run:
        result.append("".join(run), style=cur_sty)
    result.append("\n")


def _paint_feature_label(arr: list[tuple[str, str]], f: dict,
                          chunk_start: int, chunk_end: int,
                          re_highlight_se: "tuple[int, int] | None" = None,
                          ) -> None:
    """Top-of-feature row painter. For resites this is the parens row
    (`( EnzymeName )` with a Type-IIS dashed bridge); for everything
    else it's the centered label text."""
    s, e = f["start"], f["end"]
    bar_s = max(s, chunk_start) - chunk_start
    bar_e = min(e, chunk_end)   - chunk_start
    bar_len = bar_e - bar_s
    if bar_len <= 0:
        return
    color = f.get("color", "white")
    feat_type = f.get("type", "")
    content_w = chunk_end - chunk_start

    if feat_type == "resite":
        # Pre-2026-05-08 the parens were anchored to recognition
        # bounds, so a 6-bp recognition like `GAATTC` had only 4
        # cols of interior — too narrow to fit "EcoRI" (5 chars),
        # truncating to "EcoR". Per user spec: "Keep [the parens]
        # just wide enough to fit the full shorthand enzyme name."
        # Now the paren span centers on the recognition midpoint
        # with `width = max(rec_len, len(label) + 2)` so a 5-char
        # name on a 6-bp recognition gets a 7-wide paren block,
        # extending one column past the recognition right edge.
        # The biological recognition position is still cued by
        # the cut arrow + the colored bar in the strand row.
        label = f.get("label", "")
        rec_len = (e - s) if e >= s else max(1, bar_len)
        # Wrap continuations carry an empty label and shouldn't
        # try to fit a name — keep them at piece bounds.
        if label:
            desired_w = max(rec_len, len(label) + 2)
        else:
            desired_w = rec_len
        # Center on recognition midpoint (absolute bp coords).
        rec_mid_abs = s + rec_len // 2
        paren_l_abs = rec_mid_abs - desired_w // 2
        paren_r_abs = paren_l_abs + desired_w - 1
        # Convert to chunk-local; only render parts visible in
        # this chunk (handles seq-panel line wrapping).
        paren_l = paren_l_abs - chunk_start
        paren_r = paren_r_abs - chunk_start
        if 0 <= paren_l < content_w:
            arr[paren_l] = ("(", color)
        if 0 <= paren_r < content_w:
            arr[paren_r] = (")", color)
        # Render the label centered between the parens.
        is_active_re = (re_highlight_se is not None
                        and f["start"] == re_highlight_se[0]
                        and f["end"]   == re_highlight_se[1])
        name_sty = "bold green" if is_active_re else "bold white"
        if label:
            interior_w = desired_w - 2
            name_pad  = max(0, interior_w - len(label))
            name_lpad = name_pad // 2
            name_l_abs = paren_l_abs + 1 + name_lpad
            for j, ch in enumerate(label[:interior_w]):
                col_local = name_l_abs - chunk_start + j
                if 0 <= col_local < content_w:
                    arr[col_local] = (ch, name_sty)
        # Type-IIS dashed bridge in the parens row, between the
        # parens and the external cut column.
        ext_cut_bp = f.get("ext_cut_bp")
        if ext_cut_bp is not None and chunk_start <= ext_cut_bp < chunk_end:
            cut_abs = ext_cut_bp - chunk_start
            if cut_abs > paren_r:
                for j in range(paren_r + 1, cut_abs):
                    if 0 <= j < content_w and arr[j][0] == " ":
                        arr[j] = ("╌", color)
            elif cut_abs < paren_l:
                for j in range(cut_abs + 1, paren_l):
                    if 0 <= j < content_w and arr[j][0] == " ":
                        arr[j] = ("╌", color)
        return

    label = f.get("label") or f.get("type", "")
    lbl = label[:bar_len]
    pad = bar_len - len(lbl)
    pl  = pad // 2
    lbl_str = " " * pl + lbl + " " * (pad - pl)
    for i, ch in enumerate(lbl_str):
        col = bar_s + i
        if 0 <= col < content_w and ch != " ":
            arr[col] = (ch, color)


def _paint_primer_bound_bar(arr: list[tuple[str, str]], f: dict,
                              chunk_start: int, chunk_end: int) -> None:
    """Bound-region row for a primer with a `/primer_seq` qualifier.

    Unlike `_paint_feature_bar` which fills the bar with `▒` block
    characters, this painter writes the **primer's bases** into the
    bar cells with the feature colour as the cell BACKGROUND. The
    eye reads the primer sequence inline with the strand below — a
    bound base lines up directly above the matching template base.
    The arrow glyph (`►` / `◄`) sits at the primer's 3' end so the
    direction reads as in any other feature.

    Wrap-aware: `_feats_in_chunk` splits a wrap primer into a tail
    half (cols `[orig_start, total)`) + head half (cols `[0, orig_end)`).
    Each half carries `_orig_start` / `_orig_end` so we can compute
    the offset within the full bound region: tail holds the FIRST
    bases of the bound, head holds the LAST. Without this slicing,
    the painter would write all 10 bases of a 10-bp wrap primer at
    each half's start and overflow past the half's nominal width.
    Only one half carries the arrow (whichever owns the primer's
    3' end: tail for fwd, head for rev — opposite of the displayed
    arrow position).
    """
    s, e = f["start"], f["end"]
    bar_s = max(s, chunk_start) - chunk_start
    bar_e = min(e, chunk_end)   - chunk_start
    bar_len = bar_e - bar_s
    if bar_len <= 0:
        return
    strand = f.get("strand", 1)
    color  = f.get("color", "white")
    primer_seq = str(f.get("_primer_seq") or "")
    flap_len   = int(f.get("_flap_len")   or 0)
    bound_len  = int(f.get("_bound_len")  or 0)
    if bound_len <= 0:
        bound_len = e - s if e >= s else 0
    starts_here = s >= chunk_start
    ends_here   = e <= chunk_end
    content_w   = chunk_end - chunk_start

    if not primer_seq or bound_len <= 0:
        _paint_feature_bar(arr, f, chunk_start, chunk_end)
        return
    # Full bound bases in top-strand orientation. Forward primer's
    # bound region = `primer_seq[flap_len:]`; reverse primer's
    # bound region in top-strand orientation = RC of the same slice.
    if strand >= 0:
        full_bound_bases = primer_seq[flap_len:flap_len + bound_len]
    else:
        full_bound_bases = _rc(primer_seq[flap_len:flap_len + bound_len])

    # ── Slice the half's portion of the full bound ─────────────────
    orig_start = f.get("_orig_start")
    orig_end   = f.get("_orig_end")
    is_wrap_split = (
        isinstance(orig_start, int) and isinstance(orig_end, int)
        and orig_end < orig_start
    )
    half_len = e - s
    if is_wrap_split:
        # Head half (s == 0): last `head_len` bases of the bound.
        # Tail half (s != 0): first `tail_len` bases.
        if s == 0:
            half_offset = bound_len - half_len
        else:
            half_offset = 0
    else:
        half_offset = 0
    bound_slice = full_bound_bases[half_offset: half_offset + half_len]

    # Slice off the bases that fall before / after the visible chunk
    # within this half.
    skip_left   = max(0, chunk_start - s)
    skip_right  = max(0, e - chunk_end)
    visible_bases = bound_slice[
        skip_left:
        (len(bound_slice) - skip_right) if skip_right else len(bound_slice)
    ]
    bg_style = f"black on {color}"
    # Bases occupy the bar's nominal column range `[s, e)`. The
    # arrow gets one EXTRA cell beyond the bar (col `e` for fwd,
    # col `s-1` for rev) so the full primer sequence stays visible.
    for i, ch in enumerate(visible_bases):
        col = bar_s + i
        if 0 <= col < content_w:
            arr[col] = (ch, bg_style)

    # Weak-primer marker: when `_weak_primer` is stamped (bound
    # region shorter than the user-set Min primer binding
    # threshold), the strand-3'-end arrow becomes a yellow-bg ⚠
    # so the user spots a low-Tm primer at a glance without
    # losing direction info (the ⚠ still sits at the 3' end).
    weak = bool(f.get("_weak_primer", False))
    arrow_style = "black on yellow" if weak else bg_style
    fwd_glyph   = "⚠" if weak else "▶"
    rev_glyph   = "⚠" if weak else "◀"

    # Arrow glyph: at the 3' end of the primer. For non-wrap
    # primers, that's the "natural" edge (right for fwd, left for
    # rev). For wrap primers, only ONE half owns the 3' end:
    #   forward: head half (its `e` is at the wrap end, the 3' end)
    #   reverse: tail half (its `s` is at the wrap start, the 3' end)
    if strand >= 0 and ends_here:
        # Suppress arrow on the tail half of a forward wrap primer
        # (the head half draws it instead).
        if is_wrap_split and s != 0:
            pass
        else:
            arrow_col = e - chunk_start
            if 0 <= arrow_col < content_w:
                arr[arrow_col] = (fwd_glyph, arrow_style)
    elif strand < 0 and starts_here:
        # Suppress arrow on the head half of a reverse wrap primer
        # (the tail half draws it instead).
        if is_wrap_split and s == 0:
            pass
        else:
            arrow_col = s - chunk_start - 1
            if 0 <= arrow_col < content_w:
                arr[arrow_col] = (rev_glyph, arrow_style)


def _paint_primer_flap_bar(arr: list[tuple[str, str]], f: dict,
                             chunk_start: int, chunk_end: int) -> None:
    """Flap-row painter — sits one row farther from the strand than
    the bound bar (`sub == 1` of a primer-with-flap). Renders the
    flap's bases in the column range `[_flap_start, _flap_end)`
    (= LEFT of the bound bar for fwd, RIGHT for rev) so the flap
    visually floats off to the side of the bound region without
    vertically overlapping it. Background = primer color, fg =
    cell text colour, identical typography to the bound row so the
    eye reads them as one continuous primer.
    """
    flap_s = int(f.get("_flap_start") or 0)
    flap_e = int(f.get("_flap_end")   or 0)
    flap_bases = str(f.get("_flap_bases") or "")
    if flap_e <= flap_s or not flap_bases:
        return
    color = f.get("color", "white")
    bg_style = f"black on {color}"
    content_w = chunk_end - chunk_start
    # Clip flap to the visible chunk.
    vis_s = max(flap_s, chunk_start)
    vis_e = min(flap_e, chunk_end)
    if vis_e <= vis_s:
        return
    # Slice the bases to match the visible window.
    src_start = vis_s - flap_s
    src_end   = src_start + (vis_e - vis_s)
    visible = flap_bases[src_start:src_end]
    bar_s = vis_s - chunk_start
    for i, ch in enumerate(visible):
        col = bar_s + i
        if 0 <= col < content_w:
            arr[col] = (ch if ch else "▒", bg_style)


def _paint_feature_bar(arr: list[tuple[str, str]], f: dict,
                        chunk_start: int, chunk_end: int,
                        is_below_dna: bool = False) -> None:
    """Bottom-of-feature row painter (close to DNA). For resites this
    is the cut-arrow row; for other features it's the dither bar."""
    s, e = f["start"], f["end"]
    starts_here = s >= chunk_start
    ends_here   = e <= chunk_end
    bar_s = max(s, chunk_start) - chunk_start
    bar_e = min(e, chunk_end)   - chunk_start
    bar_len = bar_e - bar_s
    if bar_len <= 0:
        return
    strand = f.get("strand", 1)
    color  = f.get("color", "white")
    feat_type = f.get("type", "")
    content_w = chunk_end - chunk_start

    if feat_type == "resite":
        # Cut arrow at the in-recognition cut column or the external
        # cut bp (Type IIS). Glyph points toward the DNA strand.
        cut_ch = "↑" if is_below_dna else "↓"
        cut_col = f.get("cut_col")
        if cut_col is not None:
            visible_offset = cut_col - max(0, chunk_start - f["start"])
            cut_pos = bar_s + visible_offset
            if 0 <= cut_pos < content_w:
                arr[cut_pos] = (cut_ch, "bold " + color)
        ext_cut_bp = f.get("ext_cut_bp")
        if ext_cut_bp is not None and chunk_start <= ext_cut_bp < chunk_end:
            cut_abs = ext_cut_bp - chunk_start
            if 0 <= cut_abs < content_w:
                arr[cut_abs] = (cut_ch, "bold " + color)
        return

    if str(feat_type or "").lower() == "intron":
        # Introns render as a continuous ``╱╲╱╲╱╲`` zigzag —
        # alternating box-drawing diagonals that visually convey
        # "splice site" without the directional baggage of an
        # arrowhead (introns aren't transcribed; they're skipped).
        # Distinct from the ▒ block fill every other feature type
        # uses, so exon→intron→exon reads at a glance even with the
        # same lane color.
        #
        # Bounds are anchored to the feature's ``start`` / ``end``
        # via ``bar_s`` / ``bar_e`` (max-clamped to the chunk window):
        # the leftmost zigzag cell sits at bp ``s``, the rightmost at
        # bp ``e - 1``, exactly matching the intron's annotated
        # range. A wrap intron's tail half + head half (split by
        # `_feats_in_chunk`) each get their own slice of zigzag with
        # their own boundaries — together they cover the full
        # original range.
        #
        # The alternation is keyed on absolute bp parity, not the
        # chunk-local column, so a chunk-spanning intron renders a
        # seamless zigzag across the chunk boundary instead of
        # phase-shifting at every line wrap.
        #
        # Case-insensitive type match: BioPython's commercialsaas parser
        # passes the .dna file's `type` attribute through verbatim,
        # and CommercialSaaS occasionally writes "Intron" (capitalised)
        # alongside the canonical lowercase.
        for col in range(bar_s, bar_e):
            if 0 <= col < content_w:
                abs_col = col + chunk_start
                arr[col] = ("╲" if abs_col % 2 == 0 else "╱", color)
        return

    if strand == 0:
        bar_str = "▒" * bar_len
    elif strand == 2:
        head = "◀" if starts_here else "▒"
        tail = "▶" if ends_here   else "▒"
        bar_str = head + "▒" * max(0, bar_len - 2) + tail
    elif strand >= 1:
        bar_str = "▒" * (bar_len - (1 if ends_here else 0)) + ("▶" if ends_here else "")
    else:
        bar_str = ("◀" if starts_here else "") + "▒" * (bar_len - (1 if starts_here else 0))
    for i, ch in enumerate(bar_str):
        col = bar_s + i
        if 0 <= col < content_w:
            arr[col] = (ch, color)


def _spliced_idx_to_genomic_bp(idx: int,
                                  exons: "list[tuple[int, int]]",
                                  strand: int) -> int:
    """Map a 0-based offset into the spliced (intron-removed) CDS
    sequence back to its genomic bp. Exons are stored in ascending
    genomic order; strand=-1 reverses the walk so the first spliced
    base lives at the 3'-most exon's far end.

    Used by `_paint_cds_aa` to paint each codon's middle-base AA
    letter above the right column even when the codon straddles an
    intron junction (issue #9 from Cory Tobin)."""
    if strand == -1:
        # Walk exons from 3' end of the last exon back to 5' end of the
        # first one. Spliced index 0 = exons[-1].end - 1 (the last
        # genomic base of the last exon).
        cum = 0
        for xs, xe in reversed(exons):
            length = xe - xs
            if idx < cum + length:
                return xe - 1 - (idx - cum)
            cum += length
        return -1
    # Forward strand: spliced index 0 = exons[0].start.
    cum = 0
    for xs, xe in exons:
        length = xe - xs
        if idx < cum + length:
            return xs + (idx - cum)
        cum += length
    return -1


def _paint_cds_aa(arr: list[tuple[str, str]], f: dict,
                   chunk_start: int, chunk_end: int,
                   seq_upper: str,
                   aa_highlight: "dict | None") -> None:
    """Paint AA letters at codon midpoints inside this chunk's bp range.

    For wrap-CDS halves (split by `_feats_in_chunk`), `f["start"]`/
    `f["end"]` are the half's linear bounds — useless for codon math.
    The original CDS coords live in `_orig_start` / `_orig_end`; we
    use those for both the cache lookup (so each half shares the full
    translation) and the codon-midpoint formula.

    Intron-aware (issue #9 from Cory Tobin): when `f["_exons"]` is
    set, each codon's middle-base bp is looked up via
    `_spliced_idx_to_genomic_bp` so the AA letter lands above the
    right column even on a codon that straddles an intron junction.
    """
    if not seq_upper:
        return
    aa_letters, cds_len, virt_e = _cds_aa_list(seq_upper, f)
    n_codons = len(aa_letters)
    if n_codons == 0:
        return
    # Original CDS bounds — fall back to the half's bounds for non-wrap.
    orig_s = f.get("_orig_start", f["start"])
    orig_e = f.get("_orig_end",   f["end"])
    exons = f.get("_exons")
    n = len(seq_upper)
    strand = f.get("strand", 1)
    color  = f.get("color", "white")
    is_aa_active = (aa_highlight is not None and f is aa_highlight)
    sty = (f"reverse bold {color}" if is_aa_active
           else f"bold {color}")
    content_w = chunk_end - chunk_start
    # /codon_start offset (1/2/3 → 0/1/2 leading bases skipped). Applied
    # in CDS-5'-end direction so it shifts forward-strand AA letters
    # right by `cs_off` bp and reverse-strand AA letters left by `cs_off`.
    cs_off = max(0, min(2, int(f.get("codon_start", 1)) - 1))
    if exons:
        # Intron-aware: every codon's middle base is at spliced index
        # 3*ci + 1 (+ cs_off for partial leading codons). Walk via the
        # helper. The painter doesn't try to narrow `i_range` because
        # the codon→bp map isn't monotonic across intron junctions;
        # full-scan with per-bp filter is the correct (and bounded)
        # approach.
        for ci in range(n_codons):
            aa_bp = _spliced_idx_to_genomic_bp(cs_off + 3*ci + 1, exons, strand)
            if aa_bp < 0:
                continue
            if chunk_start <= aa_bp < chunk_end:
                col = aa_bp - chunk_start
                if 0 <= col < content_w:
                    arr[col] = (aa_letters[ci], sty)
        return
    if orig_e >= orig_s:
        # Non-wrap: narrow the codon range whose midpoint can land in
        # this chunk so a 10 kb CDS doesn't iterate every codon per
        # chunk it spans.
        if strand == -1:
            lo = (virt_e - cs_off - 2 - chunk_end) // 3 + 1
            hi = (virt_e - cs_off - 2 - chunk_start) // 3 + 1
        else:
            lo = (chunk_start - orig_s - cs_off - 1 + 2) // 3
            hi = (chunk_end - orig_s - cs_off - 1 + 2) // 3
        lo = max(0, lo)
        hi = min(n_codons, hi + 1)
        i_range = range(lo, hi) if lo < hi else range(0)
    else:
        # Wrap-CDS half: codon midpoints don't fall in a contiguous i
        # range, so scan all codons and let the per-bp filter below
        # drop the ones outside this chunk. Each call only sees the
        # chunk-local arr so the cost is bounded by codons-in-CDS.
        i_range = range(n_codons)
    for ci in i_range:
        if strand == -1:
            aa_bp = (virt_e - cs_off - 3*ci - 2) % n if n else 0
        else:
            aa_bp = (orig_s + cs_off + 3*ci + 1) % n if n else 0
        if chunk_start <= aa_bp < chunk_end:
            col = aa_bp - chunk_start
            if 0 <= col < content_w:
                arr[col] = (aa_letters[ci], sty)


def _render_packed_strand(result: "Text",
                           placements: list[tuple[dict, int]],
                           total_rows: int,
                           chunk_start: int, chunk_end: int,
                           prefix_w: int,
                           seq_upper: str,
                           is_below_dna: bool,
                           aa_highlight: "dict | None",
                           re_highlight_se: "tuple[int, int] | None" = None,
                           ) -> None:
    """Render the per-strand packed lane art for one chunk.

    Above-DNA: rows iterate from row=total_rows-1 (top, far from DNA)
    down to row=0 (bottom, just above DNA). Each row is painted from
    every feature whose footprint covers it.

    Below-DNA: order flips so row=0 (closest to DNA) prints first.

    Per-feature sub-row mapping (sub = row - bottom_row):
      non-CDS height 2: sub=0 → bar, sub=1 → label
      CDS    height 3: sub=0 → AA letters, sub=1 → bar, sub=2 → label
    """
    if total_rows <= 0:
        return
    content_w = chunk_end - chunk_start
    if is_below_dna:
        row_iter = range(total_rows)
    else:
        row_iter = range(total_rows - 1, -1, -1)
    for row in row_iter:
        arr: list[tuple[str, str]] = [(" ", "")] * content_w
        for f, bottom_row in placements:
            height = _feat_stack_height(f)
            if not (bottom_row <= row < bottom_row + height):
                continue
            sub = row - bottom_row
            if f.get("type") == "CDS":
                if sub == 0:
                    _paint_cds_aa(arr, f, chunk_start, chunk_end,
                                  seq_upper, aa_highlight)
                elif sub == 1:
                    _paint_feature_bar(arr, f, chunk_start, chunk_end,
                                       is_below_dna=is_below_dna)
                else:   # sub == 2
                    _paint_feature_label(arr, f, chunk_start, chunk_end,
                                         re_highlight_se=re_highlight_se)
            else:
                # Primer with a `/primer_seq` qualifier (set by
                # `PlasmidMap._parse`): bound bar shows the primer's
                # bases inline with the strand. If the primer is
                # ALSO longer than its bound region (has a 5' flap),
                # the row farther from the strand shows the flap
                # bases as a floating segment; the primer's name
                # label is dropped (its bases convey "this is a
                # primer"). Full-binding primers (primer_seq present
                # but no flap) keep the name label.
                has_primer_seq = (
                    f.get("type") == "primer_bind"
                    and f.get("_primer_seq")
                )
                has_flap = has_primer_seq and f.get("_flap_bases")
                if sub == 0:
                    if has_primer_seq:
                        _paint_primer_bound_bar(arr, f, chunk_start, chunk_end)
                    else:
                        _paint_feature_bar(arr, f, chunk_start, chunk_end,
                                           is_below_dna=is_below_dna)
                else:   # sub == 1
                    if has_flap:
                        _paint_primer_flap_bar(arr, f, chunk_start, chunk_end)
                    else:
                        _paint_feature_label(arr, f, chunk_start, chunk_end,
                                             re_highlight_se=re_highlight_se)
        _emit_packed_row(result, arr, prefix_w)


def _feat_stack_height(f: dict) -> int:
    """Vertical row count for a single feature's lane art:
    non-CDS = 2 (bar + label); CDS = 3 (AA + bar + label)."""
    return 3 if f.get("type") == "CDS" else 2


def _pack_features_2d(feats: list[dict], chunk_start: int,
                      chunk_end: int) -> list[tuple[dict, int]]:
    """Greedy 2D packing: each feature occupies a (bp range × height)
    rectangle starting from `bottom_row` (0 = closest to DNA). Returns
    a list of (feat, bottom_row) pairs.

    Pack order is `feats` order = insertion order from
    `record.features`. Older features pack first and land at the
    bottom of the stack (closest to DNA); newer features pack later
    and stack on top of any older features whose column range they
    overlap. This is the v0.4 default — "most recently added is most
    visible" — pending a per-feature priority rotation feature
    planned post-0.5. Stable sort preserves order within tiers.

    Algorithm: track per-column the highest occupied row index
    (`col_top`). The new feature's bottom_row is one above the max
    of its column range — the smallest legal y where all needed
    rows are free. If nothing overlaps the feature, max_top is -1
    and the feature lands at row 0 (bar adjacent to DNA).

    `col_top` is a fixed-size list indexed by the chunk-local column
    offset rather than a dict keyed on absolute column. The two hot
    operations — range-max query and range-assign — collapse to
    `max(col_top[a:b])` and `col_top[a:b] = [top_row] * (b - a)`,
    which run in C inside CPython and shave a ~10× constant off the
    per-chunk pack cost. The algorithm itself is unchanged.
    """
    width = chunk_end - chunk_start
    if width <= 0 or not feats:
        return []
    placements: list[tuple[dict, int]] = []
    col_top = [-1] * width
    for f in feats:
        bar_s = max(f["start"], chunk_start) - chunk_start
        bar_e = min(f["end"],   chunk_end)   - chunk_start
        if bar_e <= bar_s:
            continue
        height = _feat_stack_height(f)
        max_top = max(col_top[bar_s:bar_e])
        bottom_row = max_top + 1
        top_row = bottom_row + height - 1
        col_top[bar_s:bar_e] = [top_row] * (bar_e - bar_s)
        placements.append((f, bottom_row))
    return placements


def _chunk_lane_groups(
    chunk_feats: list[dict], chunk_start: int, chunk_end: int,
) -> "tuple[list, list, int, int]":
    """Returns (above_placements, below_placements, above_rows, below_rows).

    `*_placements` is `[(feat, bottom_row), ...]` from `_pack_features_2d`.
    `*_rows` is the total stack height on that strand for this chunk
    (0 if no features). Each feature occupies a contiguous block of
    rows starting at `bottom_row`:
      * non-CDS: 2 rows (row 0 = bar adjacent to DNA, row 1 = label)
      * CDS:     3 rows (row 0 = AA, row 1 = bar, row 2 = label)
    Greedy placement keeps every feature's bar/label as close to DNA
    as possible; only collisions cause stacking.
    """
    fwd = [f for f in chunk_feats if f.get("strand", 0) >= 0]
    rev = [f for f in chunk_feats if f.get("strand", 0) <  0]
    above_p = _pack_features_2d(fwd, chunk_start, chunk_end)
    below_p = _pack_features_2d(rev, chunk_start, chunk_end)
    above_rows = max(
        (p[1] + _feat_stack_height(p[0]) for p in above_p), default=0
    )
    below_rows = max(
        (p[1] + _feat_stack_height(p[0]) for p in below_p), default=0
    )
    return above_p, below_p, above_rows, below_rows


# Per-(seq_id, feats_id) cache for expensive inputs of _build_seq_text that
# only depend on sequence and features, not on cursor/selection/line_width.
# Cache holds (styles_list, annot_feats_sorted). Invalidated by id — lists
# are reassigned on load, never mutated in place (see CLAUDE.md).
# LRU via OrderedDict — same idiom as `_RESTR_SCAN_CACHE`. The pre-2026-05-06
# blanket-`.clear()` policy threw away the working set every Nth call,
# which hurt users hopping between several open plasmids.
_BUILD_SEQ_CACHE: _OD = _OD()
# Bumped from 4 to 16 (2026-05-10) to match the downstream
# _CHUNK_STATIC_CACHE / _CHUNK_OVERLAY_CACHE sizes. The previous cap of
# 4 evicted entries during multi-plasmid LRU hopping — a user cycling
# through 5+ open plasmids paid a full styles + annot_feats rebuild on
# every hop. scripts/perf_probe_render.py::probe_lru_workload showed
# the cache at 4/4 capacity with 50 kb × 5 plasmids; bumping the cap
# to 16 keeps the working set warm without bloating memory (the
# cached value is a styles list (one ref per bp) + a sorted feats
# list, ~50 kB per cosmid entry × 16 = ~800 kB worst case).
_BUILD_SEQ_CACHE_MAX = 16


# Per-(seq_id, feats_id, line_width) cache for chunk decomposition. Keyed
# identically to _BUILD_SEQ_CACHE plus line_width (which only changes on
# terminal resize). Independent of cursor/selection/show_connectors —
# show_connectors only changes the row-multiplier rpg, applied at lookup
# time via prefix-sum arithmetic. Holds:
#   chunks       — list of (chunk_start, chunk_end, lane_groups, above, below)
#                  where above/below are lane-pair counts (NOT row counts).
#   prefix_dna2  — list[int]: total rows up to chunk i with rpg=2 (so cursor
#                  moves on a 200 kb plasmid don't re-run _feats_in_chunk
#                  for 1500 chunks every keystroke).
#   prefix_lanes — list[int]: total lane pairs (above+below) up to chunk i.
# Total rows before chunk i for arbitrary rpg:
#   prefix_dna2[i] + (rpg - 2) * prefix_lanes[i]
_CHUNK_LAYOUT_CACHE: _OD = _OD()
# Bumped from 4 to 16 (2026-05-10) to match _BUILD_SEQ_CACHE_MAX. Same
# reason: a multi-plasmid LRU workload was evicting layout entries the
# user was about to revisit. See `_BUILD_SEQ_CACHE_MAX` for the bench
# that motivated this.
_CHUNK_LAYOUT_CACHE_MAX = 16


# Per-(seq_id, feats_id, line_width, show_connectors) cache of pre-rendered
# Rich Text per chunk, ASSUMING NO OVERLAYS (no cursor / selection / RE
# highlight). Cursor moves only re-render the chunk under the cursor; the
# other ~1500 chunks of a 200 kb BAC are reused from this cache. Profile-
# driven: lane-art rendering was 78% of cursor-move time on a 150 kb
# plasmid; lane art is fully deterministic per chunk so caching it
# eliminates that hot path. Stored as `OrderedDict[key, list[Text|None]]`
# with LRU touch on every read so a frequently-rendered plasmid stays hot.
_CHUNK_STATIC_CACHE: _OD = _OD()
_CHUNK_STATIC_CACHE_MAX = 16

# Per-(static_key, selection-state) cache of overlay-painted chunks.
# Holds the version of each chunk with `_user_sel` / `_sel_range` /
# `_re_highlight` / `_aa_highlight` baked in but cursor=-1, so cursor
# moves within a long selection don't re-render every chunk the
# selection covers. Invalidates whenever any selection state changes
# (so a different feature pick repopulates), but the static cache
# survives — chunks the new selection doesn't intersect still hit
# STATIC_CACHE on the same render pass.
_CHUNK_OVERLAY_CACHE: _OD = _OD()
_CHUNK_OVERLAY_CACHE_MAX = 16

# Threshold above which seq-panel rendering should switch to a
# viewport-aware lazy mode (= only render visible chunks, emit blank
# placeholders for the rest). Currently a no-op skeleton: we log
# `seq.large_record_full_render` when this threshold is crossed so we
# can see in the wild whether anyone hits it. When someone does,
# wire `_build_seq_text` to take a `viewport_y_range` kwarg and
# skip out-of-view chunk renders. 1 Mbp ≈ 6 k chunks at line_width
# 163; a full-stack render of that takes ~5-10 s on typical hardware.
_LAZY_RENDER_THRESHOLD_BP = 1_000_000


def _feats_in_chunk(
    feats: list[dict], chunk_start: int, chunk_end: int, total: int
) -> list[dict]:
    """Return features overlapping [chunk_start, chunk_end), with wrap-around
    features (end < start) split into tail [start, total) + head [0, end)
    virtual pieces. The tail keeps the label; the head is unlabeled so the
    name only appears once per chunk row. Non-wrapped features pass through
    unchanged (same dict identity).

    Needed because the naive overlap test `start < chunk_end and end > chunk_start`
    drops wrap features from every chunk (both halves fail the conjunction).
    """
    out: list[dict] = []
    for f in feats:
        s, e = f["start"], f["end"]
        if e >= s:
            if s < chunk_end and e > chunk_start:
                out.append(f)
            continue
        # Wrap feature: split into tail + head. Stamp the original
        # (start, end) on each half so renderers that need the full
        # CDS reading frame (`_paint_cds_aa`, the AA-click handler
        # in `_check_packed`) can recover it. Without these, codon
        # midpoints would be computed off the half's local start
        # and the AA letters would land on the wrong bp with the
        # wrong translation. Non-CDS features ignore these keys.
        # `_orig_dict` keeps a reference to the unsplit feature so
        # the click / hover resolver can identity-match a half-dict
        # back to a feature in `pm._feats` (without it the App's
        # `event.feat is f` check fails for wrap features and falls
        # back to bp-search).
        if s < chunk_end and total > chunk_start:
            out.append({**f, "end": total,
                        "_orig_start": s, "_orig_end": e,
                        "_orig_dict": f})
        if 0 < chunk_end and e > chunk_start:
            out.append({**f, "start": 0, "label": "",
                        "_orig_start": s, "_orig_end": e,
                        "_orig_dict": f})
    return out


def _build_seq_inputs(seq: str, feats: list[dict]) -> tuple[list[str], list[dict]]:
    """Return (styles, annot_feats) for a given sequence/feature pair,
    memoised by identity. Both outputs are expensive on large plasmids and
    independent of cursor/selection state."""
    # `hash(seq)` rather than `id(seq)`: id-based keys collide for
    # transient strings (allocator recycles addresses) — the same fix
    # applied to `_RESTR_SCAN_CACHE` and `_ENZYME_CUTS_CACHE`. CPython
    # interns the string hash on first call, so subsequent lookups are
    # O(1). `id(feats)` remains correct per CLAUDE.md invariant #4
    # (lists are reassigned on load, not mutated in place).
    key = (hash(seq), id(feats), len(seq), len(feats))
    hit = _BUILD_SEQ_CACHE.get(key)
    if hit is not None:
        _BUILD_SEQ_CACHE.move_to_end(key)
        return hit
    n = len(seq)
    styles = ["color(252)"] * n
    for f in reversed(feats):          # reversed so first feature wins
        # Resite / recut features (restriction-site overlay) must
        # NOT pre-colour the DNA strand text. Their colour belongs
        # in the lane art only — tinting the actual base characters
        # makes the strand harder to read AND collides with the
        # resite-click highlight palette. Per the 2026-05-08 user
        # request: "Do not pre-color the actual basepairs of the
        # sequence row for any enzyme."
        if f.get("type") in ("resite", "recut"):
            continue
        col = f["color"]
        # Slice assignment is C-backed in CPython; ~10× faster than the
        # equivalent per-base for-loop on long features (5 kb CDS etc).
        # `[col] * k` allocates a single list; `styles[a:b] = list` is a
        # memcpy. Guards keep us off the negative-index path — features
        # carry start/end in [0, total] by _feat_bounds construction.
        if f["end"] >= f["start"]:
            e = min(f["end"], n)
            s = f["start"]
            if e > s:
                styles[s:e] = [col] * (e - s)
        else:
            # Wrap feature: colour tail [start, n) + head [0, end).
            s = f["start"]
            if s < n:
                styles[s:n] = [col] * (n - s)
            e = min(f["end"], n)
            if e > 0:
                styles[:e] = [col] * e
    # Filter out scan-derived restriction-site overlays (they're
    # painted via `pm._restr_feats`, not the lane art). Preserve the
    # caller's insertion order so `_pack_features_2d` can pack
    # newest-on-top by walking the list in order.
    annot_feats = [f for f in feats if f.get("type") not in ("site", "recut")]
    if len(_BUILD_SEQ_CACHE) >= _BUILD_SEQ_CACHE_MAX:
        _BUILD_SEQ_CACHE.popitem(last=False)
    _BUILD_SEQ_CACHE[key] = (styles, annot_feats)
    return styles, annot_feats


def _chunk_layout(seq: str, feats: list[dict], line_width: int):
    """Return per-chunk lane decomposition + prefix sums, cached by id.

    Used by both `_bp_to_content_row` (cursor → row index) and
    `_build_seq_text` (chunk-by-chunk render). Computing this once per
    (seq, feats, line_width) instead of per cursor move turns BAC/cosmid
    cursor scrolling from ~120 ms/keystroke into low single digits — the
    `_feats_in_chunk` + `_chunk_lane_groups` calls per chunk dominate
    otherwise (200 kb / line_width 127 = ~1.5k chunks × N features).

    Returns ``(chunks, prefix_dna2, prefix_lanes)`` where:
      - ``chunks[i] = (chunk_start, chunk_end, lane_groups, above_pairs, below_pairs)``
      - ``prefix_dna2[i]`` = total rows from row 0 up to (not including) chunk i
        assuming rpg = 2 (no connector row).
      - ``prefix_lanes[i]`` = total lane pairs (above+below) up to chunk i.
    Total rows before chunk i for any rpg:
      ``prefix_dna2[i] + (rpg - 2) * prefix_lanes[i]``
    """
    n = len(seq)
    # See `_build_seq_inputs` comment: hash(seq) for transient-string
    # safety; id(feats) is OK per CLAUDE.md invariant #4.
    key = (hash(seq), id(feats), line_width, n, len(feats))
    hit = _CHUNK_LAYOUT_CACHE.get(key)
    if hit is not None:
        _CHUNK_LAYOUT_CACHE.move_to_end(key)
        return hit

    # Reuse _build_seq_inputs' filtered+sorted annot_feats so cache hits
    # there propagate here (and so the two paths see identical lane order).
    _, annot_feats = _build_seq_inputs(seq, feats)

    chunks: list = []
    prefix_dna2  = [0]   # rows with rpg=2; index 0 = before chunk 0
    prefix_lanes = [0]
    if n == 0 or line_width <= 0:
        layout = (chunks, prefix_dna2, prefix_lanes)
        if len(_CHUNK_LAYOUT_CACHE) >= _CHUNK_LAYOUT_CACHE_MAX:
            _CHUNK_LAYOUT_CACHE.popitem(last=False)
        _CHUNK_LAYOUT_CACHE[key] = layout
        return layout

    for chunk_start in range(0, n, line_width):
        chunk_end   = min(chunk_start + line_width, n)
        chunk_feats = _feats_in_chunk(annot_feats, chunk_start, chunk_end, n)
        groups      = _chunk_lane_groups(chunk_feats, chunk_start, chunk_end)
        above_p, below_p, above_rows, below_rows = groups
        # `above_pairs` / `below_pairs` are stored as lane *pair counts*
        # for backward compat with `_bp_to_content_row` arithmetic; on
        # a 2D-packed chunk we just halve the row count (both feature
        # types divide into 2-row label/bar pairs except CDS which has
        # an extra AA row — bookkeeping uses the literal row count via
        # the dedicated `*_rows` fields).
        chunks.append((chunk_start, chunk_end, groups,
                       above_rows, below_rows))
        # Per-chunk rows: above_rows + 2 (DNA pair) + below_rows + 1 (gap).
        prefix_dna2.append(
            prefix_dna2[-1] + above_rows + 2 + below_rows + 1
        )
        prefix_lanes.append(prefix_lanes[-1] + above_rows + below_rows)

    layout = (chunks, prefix_dna2, prefix_lanes)
    if len(_CHUNK_LAYOUT_CACHE) >= _CHUNK_LAYOUT_CACHE_MAX:
        _CHUNK_LAYOUT_CACHE.popitem(last=False)
    _CHUNK_LAYOUT_CACHE[key] = layout
    return layout


def _build_seq_text(seq: str, feats: list[dict], line_width: int = 60,
                    sel_range: "tuple[int,int] | None" = None,
                    user_sel:  "tuple[int,int] | None" = None,
                    cursor_pos: int = -1,
                    show_connectors: bool = False,
                    re_highlight: "dict | None" = None,
                    aa_highlight: "dict | None" = None,
                    viewport_y_range: "tuple[int,int] | None" = None) -> Text:
    """Rich Text of the sequence with per-position feature coloring.

    sel_range    — feature highlight: bold + underline on feature bases
    user_sel     — shift-click selection: subtle background, used by edit dialog
    cursor_pos   — click cursor: reverse-video highlight on base at cursor_pos
    re_highlight — dict with keys: start, end, top_cut_bp, bottom_cut_bp, color, name
                   When set, highlights the recognition bases on both strands
                   and marks cut positions with reverse-video.
    viewport_y_range — optional `(min_row, max_row)` half-open row range
                   currently visible in the seq panel's scroll viewport.
                   When supplied, chunks whose row range falls entirely
                   outside this window emit blank-line placeholders
                   instead of rendering. The total content height
                   stays correct so scrolling shows the right
                   coordinates; chunks fill in as they come into view
                   (caller is expected to refresh on scroll). The
                   per-chunk static / overlay caches survive across
                   refreshes so a scroll back-and-forth doesn't pay
                   the render cost twice. None = render everything
                   (the historical behaviour).

    Rendering order (closest to DNA first):
      RE sites (far) → regular feature bars (close) → DNA → regular (close) → RE (far)
    """
    n     = len(seq)
    num_w = len(str(n)) if n else 1    # minimum digits needed for line numbers
    styles, annot_feats = _build_seq_inputs(seq, feats)

    sel_s  = sel_range[0] if sel_range else -1
    sel_e  = sel_range[1] if sel_range else -1
    usr_s  = user_sel[0]  if user_sel  else -1
    usr_e  = user_sel[1]  if user_sel  else -1

    # RE highlight ranges
    reh_s       = re_highlight["start"]         if re_highlight else -1
    reh_e       = re_highlight["end"]           if re_highlight else -1
    reh_top_cut = re_highlight["top_cut_bp"]    if re_highlight else -1
    reh_bot_cut = re_highlight["bottom_cut_bp"] if re_highlight else -1
    # Original recognition bounds (pre-cut-extension). Lets the
    # per-base renderer paint recognition / spacer / overhang in
    # distinct colours. Falls back to (-1, -1) — the legacy "all
    # one region" behaviour — when not supplied.
    reh_rec_s   = (re_highlight.get("rec_start", -1)
                   if re_highlight else -1)
    reh_rec_e   = (re_highlight.get("rec_end",   -1)
                   if re_highlight else -1)

    seq_upper = seq.upper()
    result    = Text(no_wrap=True, overflow="crop")

    # ── Future: lazy chunk rendering for chromosome-scale records ─────────
    # When `len(seq) > _LAZY_RENDER_THRESHOLD_BP`, a first-render of the
    # seq panel iterates ~30,000+ chunks and can take 30 s+ on a 5 Mb
    # bacterial chromosome (~minutes for a 250 Mb human chromosome).
    # Most of that work is wasted because the user only sees a 12-row
    # viewport at a time. The fix is to render only chunks whose
    # content_row falls within `[scroll_y, scroll_y + viewport_height)`
    # and emit blank-line placeholders for the rest.
    #
    # When implementing, the changes converge on this function:
    #   1. Accept `viewport_y_range: tuple[int, int] | None` kwarg.
    #   2. For each chunk, skip rendering (emit "\n" * chunk_lines)
    #      when content_row is outside the viewport.
    #   3. Hook the SequencePanel scroll-changed event to call
    #      `_refresh_view()` so newly-visible chunks fill in.
    #   4. Keep the static + overlay caches as-is — they already
    #      have the right invalidation semantics.
    #
    # Skeleton constant + threshold check below; the actual viewport-
    # aware skip is left for when a user genuinely loads a chromosome.
    if len(seq) > _LAZY_RENDER_THRESHOLD_BP:
        _log_event("seq.large_record_full_render",
                   seq_len=len(seq), threshold=_LAZY_RENDER_THRESHOLD_BP)

    # Cached chunk decomposition — eliminates per-chunk _feats_in_chunk +
    # _chunk_lane_groups recomputation on every cursor-move re-render. On a
    # 200 kb plasmid that's ~1500 chunks × N features → milliseconds saved
    # per keystroke when scrolling through cosmid/BAC-scale records.
    chunks_layout, _pf_dna2, _pf_lanes = _chunk_layout(seq, feats, line_width)
    # `_pf_dna2` is used below by the lazy-render viewport filter to
    # decide which chunks to skip. `_pf_lanes` stays unused until /
    # unless connectors come back.

    # Two-tier per-chunk render cache:
    #   STATIC (no overlay)   — keyed only on (seq, feats, line_width,
    #                           show_connectors). Survives selection
    #                           changes; reused as long as the lane
    #                           art itself doesn't change.
    #   OVERLAY (with sel/etc) — keyed on STATIC key plus the selection
    #                           state. Cursor stays out of the key so
    #                           cursor moves on a long selection don't
    #                           invalidate.
    # The cursor chunk always renders fresh (cursor moves frequently).
    # Other chunks pick the overlay cache if any sel/usr/reh/aa
    # overlay intersects the chunk, else the static cache. So:
    #   - First click on a feature: cursor chunk fresh + N overlay chunks
    #     fresh (populates overlay cache) + (chunks - N - 1) STATIC hits.
    #   - Second click on a different feature: same cost as first
    #     click — overlay cache key changes — but STATIC chunks still
    #     hit. So clicking through 16 features doesn't re-render the
    #     untouched lane art on every click.
    #   - Cursor moves within a selection: overlay cache hits for
    #     all selection-overlap chunks; cursor chunk re-renders.
    # `hash(seq)` instead of `id(seq)` — see `_build_seq_inputs`.
    static_key = (hash(seq), id(feats), line_width, show_connectors)
    static_cache: "list | None" = _CHUNK_STATIC_CACHE.get(static_key)
    if static_cache is None or len(static_cache) != len(chunks_layout):
        static_cache = [None] * len(chunks_layout)
        # Cap is generous because each entry is just a list of `Text`
        # references per chunk, and the static cache only invalidates
        # on (seq, feats, line_width, show_connectors) change — not
        # on selection or cursor moves. 16 entries is enough headroom
        # for resize + plasmid switches without thrashing.
        if len(_CHUNK_STATIC_CACHE) >= _CHUNK_STATIC_CACHE_MAX:
            _CHUNK_STATIC_CACHE.popitem(last=False)
        _CHUNK_STATIC_CACHE[static_key] = static_cache
    else:
        # LRU touch on hit so frequently-used keys don't get evicted.
        _CHUNK_STATIC_CACHE.move_to_end(static_key)

    # Content-derived aa-highlight key: (start, end, strand) uniquely
    # identifies the active CDS regardless of dict identity. Pre-fix
    # used `id(aa_highlight)` which collides if two distinct dicts
    # land at the same allocator slot — the broader id()-keying issue
    # we cleaned up across the chunk caches. `aa_highlight` is one of
    # the feature dicts in `feats` (the `f is aa_highlight` check
    # inside the per-feature loop above), so its coords are a stable
    # identity.
    aa_id = (
        (aa_highlight["start"], aa_highlight["end"],
         aa_highlight.get("strand", 0))
        if aa_highlight is not None else None
    )
    overlay_key = (static_key, sel_s, sel_e, usr_s, usr_e,
                   reh_s, reh_e, reh_top_cut, reh_bot_cut,
                   reh_rec_s, reh_rec_e, aa_id)
    overlay_cache: "list | None" = _CHUNK_OVERLAY_CACHE.get(overlay_key)
    if overlay_cache is None or len(overlay_cache) != len(chunks_layout):
        overlay_cache = [None] * len(chunks_layout)
        # Selection state changes per click → overlay key changes →
        # new entry. With only 4 entries, clicking through 5 features
        # in a row evicted the first cache and forced re-render of
        # the selection-overlap chunks. 16 entries gives users a
        # comfortable working set for clicking back-and-forth between
        # several features without redoing per-base style work.
        if len(_CHUNK_OVERLAY_CACHE) >= _CHUNK_OVERLAY_CACHE_MAX:
            _CHUNK_OVERLAY_CACHE.popitem(last=False)
        _CHUNK_OVERLAY_CACHE[overlay_key] = overlay_cache
    else:
        # LRU touch on hit — cursor moves within a long selection
        # would otherwise let infrequent overlay keys age out the
        # active one.
        _CHUNK_OVERLAY_CACHE.move_to_end(overlay_key)

    # Lazy-render filter: when `viewport_y_range` is supplied, chunks
    # whose row range falls entirely outside the visible window emit
    # a blank-line placeholder instead of rendering. The placeholder
    # preserves the total content height so the scrollbar coordinates
    # stay correct; the chunk fills in via the cache when it scrolls
    # back into view. `_pf_dna2[i]` is the row at the start of chunk
    # i; chunk i occupies rows `[_pf_dna2[i], _pf_dna2[i+1])`.
    vp_min, vp_max = (viewport_y_range
                       if viewport_y_range is not None
                       else (None, None))
    for i, (chunk_start, chunk_end, groups, _ab_pairs, _be_pairs,
            *_extra) in enumerate(chunks_layout):
        if vp_min is not None and vp_max is not None:
            row_lo = _pf_dna2[i]
            row_hi = _pf_dna2[i + 1] if i + 1 < len(_pf_dna2) else row_lo
            if row_hi <= vp_min or row_lo >= vp_max:
                # Outside viewport — emit blanks of the same height
                # so the total content row count matches what the
                # scrollbar expects. Don't touch the static / overlay
                # caches; they survive as is.
                if row_hi > row_lo:
                    result.append("\n" * (row_hi - row_lo))
                continue
        chunk_has_cursor = (chunk_start <= cursor_pos < chunk_end)
        chunk_has_overlay = (
            (usr_s < chunk_end and usr_e > chunk_start)
            or (sel_s < chunk_end and sel_e > chunk_start)
            or (reh_s < chunk_end and reh_e > chunk_start)
        )
        if aa_highlight is not None:
            aa_s, aa_e = aa_highlight["start"], aa_highlight["end"]
            if aa_e >= aa_s:
                if aa_s < chunk_end and aa_e > chunk_start:
                    chunk_has_overlay = True
            else:
                if chunk_start < aa_e or chunk_end > aa_s:
                    chunk_has_overlay = True

        if chunk_has_cursor:
            _render_chunk(result, chunk_start, chunk_end, groups, styles,
                          num_w, seq_upper, show_connectors,
                          sel_s, sel_e, usr_s, usr_e,
                          reh_s, reh_e, reh_top_cut, reh_bot_cut,
                          reh_rec_s, reh_rec_e,
                          cursor_pos, aa_highlight)
        elif chunk_has_overlay:
            cached = overlay_cache[i]
            if cached is None:
                cached = Text(no_wrap=True, overflow="crop")
                _render_chunk(cached, chunk_start, chunk_end, groups, styles,
                              num_w, seq_upper, show_connectors,
                              sel_s, sel_e, usr_s, usr_e,
                              reh_s, reh_e, reh_top_cut, reh_bot_cut,
                              reh_rec_s, reh_rec_e, -1, aa_highlight)
                overlay_cache[i] = cached
            result.append(cached)
        else:
            cached = static_cache[i]
            if cached is None:
                cached = Text(no_wrap=True, overflow="crop")
                _render_chunk(cached, chunk_start, chunk_end, groups, styles,
                              num_w, seq_upper, show_connectors,
                              -1, -1, -1, -1,    # sel_s, sel_e, usr_s, usr_e
                              -1, -1, -1, -1,    # reh_s, reh_e, top_cut, bot_cut
                              -1, -1,            # rec_start, rec_end
                              -1,                # cursor_pos
                              aa_highlight)
                static_cache[i] = cached
            result.append(cached)

    return result


def _render_chunk(result: "Text", chunk_start: int, chunk_end: int,
                   groups: tuple, styles: list[str], num_w: int,
                   seq_upper: str, show_connectors: bool,
                   sel_s: int, sel_e: int, usr_s: int, usr_e: int,
                   reh_s: int, reh_e: int,
                   reh_top_cut: int, reh_bot_cut: int,
                   reh_rec_s: int, reh_rec_e: int,
                   cursor_pos: int,
                   aa_highlight: "dict | None" = None) -> None:
    """Render one chunk into `result`. The DNA pair takes a fast RLE path
    when no overlay (cursor / selection / RE highlight) intersects the
    chunk; otherwise the per-base path applies overlay styles. Lane rows
    above/below the DNA pair are independent of overlay so they always
    render the same way — which is what makes the static-cache reuse safe.
    """
    above_p, below_p, above_rows, below_rows = groups
    re_se = (reh_s, reh_e) if reh_s >= 0 and reh_e > reh_s else None
    n = len(seq_upper)

    # Wrap-aware upstream/downstream test for a clicked Type IIS cut that
    # wraps origin (raw `p + offset > n`, post-modulo small). Defined here
    # so the per-base loop doesn't redefine it for every base. Hoisted
    # 2026-05-11 alongside the wrap-highlight fix.
    def _cut_is_upstream(i_: int, cut: int) -> bool:
        if cut < 0:
            return False
        if reh_rec_s >= 0 and cut < reh_rec_s and n:
            return i_ < cut + n
        if reh_rec_s >= 0 and i_ < reh_rec_s and cut >= reh_rec_e and n:
            return i_ + n < cut
        return i_ < cut

    # Rows ABOVE DNA — render top (far) → bottom (close to DNA).
    # Per-feature 2D packing: each feature's bar is at row 0
    # (adjacent to DNA) when nothing overlaps; CDS adds an AA row
    # at sub-row 0, pushing its own bar to sub-row 1. Stacking only
    # happens on bp-range collisions, so unrelated features stay
    # tight against DNA.
    _render_packed_strand(result, above_p, above_rows,
                          chunk_start, chunk_end, num_w + 2,
                          seq_upper, is_below_dna=False,
                          aa_highlight=aa_highlight,
                          re_highlight_se=re_se)

    # ── Double-stranded DNA block ─────────────────────────────────────
    chunk_fwd = seq_upper[chunk_start:chunk_end]
    chunk_rev = chunk_fwd.translate(_DNA_COMP_PRESERVE_CASE)
    chunk_len = chunk_end - chunk_start

    chunk_has_overlay = (
        (usr_s < chunk_end and usr_e > chunk_start)
        or (sel_s < chunk_end and sel_e > chunk_start)
        or (reh_s < chunk_end and reh_e > chunk_start)
        or (chunk_start <= cursor_pos < chunk_end)
    )

    if not chunk_has_overlay:
        # RLE the styles slice. Long runs are common because most bases
        # outside features carry the default `color(252)`.
        runs: list[tuple[int, int, str]] = []
        if chunk_len > 0:
            cur_sty = styles[chunk_start]
            rs = 0
            for j in range(1, chunk_len):
                s_j = styles[chunk_start + j]
                if s_j != cur_sty:
                    runs.append((rs, j, cur_sty))
                    rs = j
                    cur_sty = s_j
            runs.append((rs, chunk_len, cur_sty))

        result.append(f"{chunk_start + 1:>{num_w}}  ", style="color(245)")
        for rs, re_end, sty in runs:
            result.append(chunk_fwd[rs:re_end], style=sty)
        result.append("\n")

        result.append(" " * (num_w + 2), style="color(245)")
        for rs, re_end, sty in runs:
            result.append(chunk_rev[rs:re_end], style=sty)
        result.append("\n")
    else:
        def _strand_chars(bases: "list[tuple[str, str]]") -> None:
            run: list[str] = []
            sty = ""
            for ch, s in bases:
                if s == sty:
                    run.append(ch)
                else:
                    if run:
                        result.append("".join(run), style=sty)
                    run, sty = [ch], s
            if run:
                result.append("".join(run), style=sty)

        fwd_bases: list[tuple[str, str]] = []
        rc_bases:  list[tuple[str, str]] = []
        for j in range(chunk_len):
            i      = chunk_start + j
            base   = styles[i]
            in_usr = (usr_s <= i < usr_e)
            in_sel = (sel_s <= i < sel_e)
            # RE highlight membership: linear when reh_e >= reh_s, wrap
            # when reh_e < reh_s (cut wraps origin for a near-origin Type
            # IIS site — encoded by `_resite_highlight_dict` since 2026-05-11).
            if reh_s < 0:
                in_re = False
            elif reh_e >= reh_s:
                in_re = (reh_s <= i < reh_e)
            else:
                in_re = (i >= reh_s or i < reh_e)
            is_cur = (cursor_pos == i)

            if is_cur:
                # All overlays use the same high-contrast palette
                # (white background, black foreground) so the user's
                # selection / cursor never blends into a feature tint.
                # Cursor is bold to distinguish it from a passive selection.
                fwd_sty = "black on white bold"
                rev_sty = fwd_sty
            elif in_re:
                # RE highlight (2026-05-08 final palette):
                #
                # Inside recognition: blue = base ends up on the
                #   UPSTREAM fragment after cutting, red = base
                #   ends up on the DOWNSTREAM fragment. Resolved
                #   per-strand from the cut bp (`i < cut` → blue
                #   = left of cut = upstream; `i >= cut` → red).
                #   For palindromic enzymes (cuts inside recognition)
                #   this paints the staggered cut clearly: top and
                #   bot disagree across the overhang region (e.g.
                #   EcoRI's AATT inside GAATTC reads top-red /
                #   bot-blue, showing the 4-nt overhang on both
                #   fragments). For Type IIS the recognition sits
                #   fully on one fragment so both strands match
                #   (forward → both blue; reverse → both red).
                #
                # Outside recognition (Type IIS only):
                #   Spacer: gray bg both strands (paired, between
                #     recognition and the cut).
                #   Overhang region (between top and bot cuts):
                #     top → green bg, bot → orange bg.
                #
                # All overlays use bold + black foreground.
                in_recognition = (
                    reh_rec_s >= 0 and reh_rec_s <= i < reh_rec_e
                )
                if reh_top_cut >= 0 and reh_bot_cut >= 0:
                    lo_cut = min(reh_top_cut, reh_bot_cut)
                    hi_cut = max(reh_top_cut, reh_bot_cut)
                    in_overhang = (lo_cut <= i < hi_cut)
                else:
                    in_overhang = False
                if in_recognition:
                    # Per-strand upstream/downstream split based on each
                    # strand's cut position. Wrap-aware via `_cut_is_upstream`
                    # so a Type IIS cut that wraps origin still paints the
                    # recognition bases correctly (blue = upstream of cut).
                    if reh_top_cut >= 0:
                        fwd_sty = ("black on blue bold"
                                   if _cut_is_upstream(i, reh_top_cut)
                                   else "black on red bold")
                    else:
                        fwd_sty = "black on white bold"
                    if reh_bot_cut >= 0:
                        rev_sty = ("black on blue bold"
                                   if _cut_is_upstream(i, reh_bot_cut)
                                   else "black on red bold")
                    else:
                        rev_sty = "black on white bold"
                elif in_overhang:
                    # Type IIS overhang (outside recognition):
                    # top green, bot orange.
                    fwd_sty = "black on green bold"
                    rev_sty = "black on orange1 bold"
                else:
                    # Spacer (Type IIS): paired, outside recognition,
                    # not in overhang. Both strands gray.
                    fwd_sty = "black on grey50 bold"
                    rev_sty = fwd_sty
            elif in_usr:
                fwd_sty = "black on white"
                rev_sty = fwd_sty
            elif in_sel:
                fwd_sty = "black on white bold underline"
                rev_sty = fwd_sty
            else:
                fwd_sty = base
                rev_sty = base
            fwd_bases.append((chunk_fwd[j], fwd_sty))
            rc_bases.append( (chunk_rev[j], rev_sty))

        result.append(f"{chunk_start + 1:>{num_w}}  ", style="color(245)")
        _strand_chars(fwd_bases)
        result.append("\n")

        result.append(" " * (num_w + 2), style="color(245)")
        _strand_chars(rc_bases)
        result.append("\n")

    # Rows BELOW DNA: mirror of above. Sub-row 0 (bar / AA-for-CDS)
    # prints first → adjacent to DNA. Sub-row 1 (label / bar-for-CDS)
    # next, etc.
    _render_packed_strand(result, below_p, below_rows,
                          chunk_start, chunk_end, num_w + 2,
                          seq_upper, is_below_dna=True,
                          aa_highlight=aa_highlight,
                          re_highlight_se=re_se)
    # One empty row after the chunk's full stack (lane art + DNA pair
    # + lane art) so consecutive chunks have uniform breathing room.
    # Without this, a chunk with no below-lane-art butts directly
    # against the next chunk's above-lane-art and the eye can't tell
    # where one chunk ends. Counted in `_chunk_layout` and traversed
    # in `_click_to_bp` so click-row-to-bp math stays consistent.
    result.append("\n")


# Standard genetic code for CDS translation (no biopython dependency)
_CODON_TABLE: dict[str, str] = {
    "TTT": "F", "TTC": "F", "TTA": "L", "TTG": "L",
    "CTT": "L", "CTC": "L", "CTA": "L", "CTG": "L",
    "ATT": "I", "ATC": "I", "ATA": "I", "ATG": "M",
    "GTT": "V", "GTC": "V", "GTA": "V", "GTG": "V",
    "TCT": "S", "TCC": "S", "TCA": "S", "TCG": "S",
    "CCT": "P", "CCC": "P", "CCA": "P", "CCG": "P",
    "ACT": "T", "ACC": "T", "ACA": "T", "ACG": "T",
    "GCT": "A", "GCC": "A", "GCA": "A", "GCG": "A",
    "TAT": "Y", "TAC": "Y", "TAA": "*", "TAG": "*",
    "CAT": "H", "CAC": "H", "CAA": "Q", "CAG": "Q",
    "AAT": "N", "AAC": "N", "AAA": "K", "AAG": "K",
    "GAT": "D", "GAC": "D", "GAA": "E", "GAG": "E",
    "TGT": "C", "TGC": "C", "TGA": "*", "TGG": "W",
    "CGT": "R", "CGC": "R", "CGA": "R", "CGG": "R",
    "AGT": "S", "AGC": "S", "AGA": "R", "AGG": "R",
    "GGT": "G", "GGC": "G", "GGA": "G", "GGG": "G",
}

def _copy_to_clipboard_osc52(text: str) -> bool:
    """Copy text via OSC 52 escape sequence — works in iTerm2, Windows
    Terminal, most modern Linux terminals.

    Writes the escape directly to the controlling TTY (POSIX
    ``/dev/tty``, Windows ``CONOUT$``) so the sequence bypasses
    Textual's rendering buffer and reaches the terminal emulator
    intact. Falls back to ``False`` when the TTY isn't writable —
    the multi-tier wrapper then escalates to file-based fallback.

    Sequence is base64(text) wrapped in the OSC 52 framing
    `ESC ] 52 ; c ; <payload> BEL`. The terminal emulator is
    responsible for forwarding the payload to the system clipboard
    (often gated by a user preference for security).
    """
    import base64
    encoded = base64.b64encode(text.encode()).decode()
    seq = f"\033]52;c;{encoded}\007"
    # POSIX systems write to `/dev/tty` (always the controlling
    # terminal regardless of stdin/stdout redirection). Windows
    # exposes the console as `CONOUT$`, openable for write with the
    # same semantics. Either device-name failure falls through to
    # the caller's tier-3 file fallback — never raises.
    target = "CONOUT$" if sys.platform == "win32" else "/dev/tty"
    try:
        with open(target, "w") as tty:
            tty.write(seq)
            tty.flush()
        return True
    except (OSError, UnicodeEncodeError):
        return False


def _copy_to_clipboard_with_fallback(
    app, text: str, label: str = "copy"
) -> "tuple[str, Path | None]":
    """Copy `text` to the system clipboard with a multi-tier
    fallback chain so the user always has a way to retrieve their
    copy even on a broken / SSH-without-X11 / unprivileged terminal:

      1. Textual's `app.copy_to_clipboard` (when an app is available)
      2. OSC 52 terminal escape (most modern terminals)
      3. Atomic write to `<DATA_DIR>/clipboard/<ts>-<label>.txt`
         (last resort — never hits a network and works on any
         platform with a writable home dir)

    Returns `(mode, detail)`:
      mode    — `"clipboard"` | `"osc52"` | `"file"` | `"log_only"`
      detail  — Path to the temp file (when mode == "file"); else None

    Privacy invariant (CLAUDE.md #38): the copied text is NEVER
    logged — only its length + caller-supplied label. Clipboard
    content is the user's data; bundling a sequence selection into
    the diagnostic log would defeat the same invariant that
    `seq.chunk_dump` had to walk back.
    """
    _log.info("clipboard copy %r (%d chars)", label, len(text))
    if app is not None:
        try:
            app.copy_to_clipboard(text)
            return ("clipboard", None)
        except Exception:
            # Continue to OSC 52 — Textual's clipboard call can fail
            # on remote SSH sessions where the terminal proxy hasn't
            # negotiated a clipboard channel.
            pass
    if _copy_to_clipboard_osc52(text):
        return ("osc52", None)
    # Tier 3: write to disk and tell the caller the path.
    try:
        import datetime as _dt
        clip_dir = _DATA_DIR / "clipboard"
        clip_dir.mkdir(parents=True, exist_ok=True)
        safe = re.sub(r"[^A-Za-z0-9_.-]", "_", label)[:40] or "copy"
        ts = _dt.datetime.now().strftime("%Y%m%d-%H%M%S")
        path = clip_dir / f"{ts}-{safe}.txt"
        # Bump on collision so multiple rapid copies don't overwrite.
        bump = 0
        while path.exists():
            bump += 1
            path = clip_dir / f"{ts}-{safe}.{bump}.txt"
        _atomic_write_text(path, text)
        # Tighten perms — clipboard contents may be sensitive.
        _chmod_user_only(path)
        return ("file", path)
    except OSError as exc:
        _log.warning("Clipboard file fallback failed: %s", exc)
    # Last resort: only the log captured it.
    return ("log_only", None)


_MARKUP_TAG_RE = re.compile(r"\[/?[^\[\]]*\]")


def _strip_markup(s: str) -> str:
    """Remove `[...]` Rich markup tags from a string for clipboard copy.
    Doesn't try to be perfect — just enough to surface plain text from
    a markup-ish status line."""
    return _MARKUP_TAG_RE.sub("", s)


# Per-CDS AA cache. Key: (id(seq), feature start, feature end, strand)
# Value: a list of decoded one-letter AA codes, indexed by codon i.
# Computed once per CDS; reused across all chunks that overlap that
# CDS so we don't re-translate the same protein N times for an N-row
# feature. Capped at 64 entries — enough for typical plasmids without
# letting the cache balloon on a long-running session.
_CDS_AA_CACHE: dict = {}


def _cds_aa_list(seq: str, f: dict) -> tuple[list[str], int, int]:
    """Return (aa_letters, cds_len, virt_e) for `f`, cached on (seq id,
    start, end, strand). `aa_letters[i]` is the one-letter AA for the
    i-th codon read in the CDS's natural direction (5'→3' on the
    feature's own strand). `virt_e` is the linear end coordinate
    (= `e` for non-wrap features, `s + cds_len` for wrap).

    For wrap-CDS halves split by `_feats_in_chunk`, the half's
    `f["start"]` / `f["end"]` are linear chunk-relative bounds and
    don't carry the original reading frame. `_orig_start` /
    `_orig_end` (stamped by the splitter) hold the CDS's true
    coords; we key the cache and translate against those so all
    halves of the same wrap-CDS share one translation.

    Intron-aware (issue #9 from Cory Tobin): when `f["_exons"]` is
    set, the spliced CDS sequence is built by concatenating ONLY the
    exonic bases (in ascending-genomic order, then strand-corrected),
    so introns whose length isn't a multiple of 3 no longer shift the
    reading frame for AAs past the splice. Cache key includes the
    exon list so two CDSes with the same outer bounds but different
    splice patterns don't share a translation.
    """
    s = f.get("_orig_start", f["start"])
    e = f.get("_orig_end",   f["end"])
    strand = f.get("strand", 1)
    exons = f.get("_exons")
    # GenBank /codon_start qualifier (1/2/3, default 1). Stamped on the
    # feature dict by the GenBank parser. Off-by-one would frame-shift
    # every AA past the leading partial codon.
    cs_offset = max(0, min(2, int(f.get("codon_start", 1)) - 1))
    exon_key = tuple(exons) if exons else None
    # hash(seq) instead of id(seq) — see `_build_seq_inputs`.
    key = (hash(seq), s, e, strand, exon_key, cs_offset)
    cached = _CDS_AA_CACHE.get(key)
    if cached is not None:
        return cached
    if exons:
        # Spliced CDS: concatenate exon bases in genomic order, then
        # strand-correct as one block. `virt_e` for downstream codon-
        # midpoint math becomes the LINEAR end of the last exon —
        # painter walks the exon list for the per-codon bp lookup so
        # it doesn't depend on a contiguous virtual range.
        cds_seq = "".join(seq[xs:xe].upper() for xs, xe in exons)
        cds_len = len(cds_seq)
        virt_e  = max(xe for _xs, xe in exons)
    elif e < s:
        cds_seq = (seq[s:] + seq[:e]).upper()
        cds_len = len(cds_seq)
        virt_e  = s + cds_len
    else:
        cds_seq = seq[s:e].upper()
        cds_len = e - s
        virt_e  = e
    if strand == -1:
        cds_seq = cds_seq.translate(_IUPAC_COMP)[::-1]
    # Apply codon_start AFTER strand correction: the offset is measured
    # from the CDS's own 5' end (= virt_e on - strand, = orig_s on +).
    cds_seq = cds_seq[cs_offset:]
    n_codons = (cds_len - cs_offset) // 3
    aa_letters = [
        _CODON_TABLE.get(cds_seq[3*i:3*i+3], "?")
        for i in range(n_codons)
    ]
    if len(_CDS_AA_CACHE) >= 64:
        _CDS_AA_CACHE.pop(next(iter(_CDS_AA_CACHE)))
    result = (aa_letters, cds_len, virt_e)
    _CDS_AA_CACHE[key] = result
    return result


def _translate_cds(full_seq: str, start: int, end: int, strand: int,
                    exons: "list[tuple[int, int]] | None" = None,
                    codon_start: int = 1) -> str:
    """Translate a CDS region to single-letter AA string (stop codon → *).

    Uses _IUPAC_COMP for the reverse-complement step so IUPAC ambiguity codes
    (N, R, Y, etc.) are handled correctly. An earlier version used a bare
    ACGT-only maketrans which would silently pass degenerate bases through
    unchanged — producing wrong codons and silent mistranslation.

    Wrapped CDSes (end < start) are represented that way by the GenBank loader
    for `join(tail..end, 0..head)` origin-spanning features on circular
    plasmids. We concatenate the tail + head before translating so the
    protein comes out correctly. Regression guard added 2026-04-13.

    Intron-aware (issue #9 from Cory Tobin): pass `exons=[(s, e), ...]`
    in ascending genomic order to splice introns OUT before translating.
    Without this, an intron whose length isn't a multiple of 3 frame-
    shifts every AA past the splice. Wrap-CDS isn't intron-aware (the
    wrap encoding overloads `end < start`); callers that combine wrap +
    introns should handle it themselves.

    `codon_start` is the GenBank /codon_start qualifier (1/2/3, default 1).
    A value of 2 or 3 means the first 1 or 2 bases of the CDS span an
    incomplete leading codon and the reading frame starts at offset
    `codon_start - 1`. Common on NCBI-fetched partial CDSes; was silently
    ignored before 2026-05-11, frame-shifting every AA.
    """
    if exons:
        sub = "".join(full_seq[xs:xe].upper() for xs, xe in exons)
    elif end < start:
        sub = (full_seq[start:] + full_seq[:end]).upper()
    else:
        sub = full_seq[start:end].upper()
    if strand == -1:
        sub = sub.translate(_IUPAC_COMP)[::-1]
    offset = max(0, min(2, int(codon_start) - 1))
    sub = sub[offset:]
    aa = [_CODON_TABLE.get(sub[i:i+3], "?") for i in range(0, len(sub) - 2, 3)]
    result = "".join(aa)
    if result and not result.endswith("*"):
        result += "*"
    return result


# ── ORF finder ────────────────────────────────────────────────────────────────
#
# Six-frame open-reading-frame scan over the loaded record. Standard
# table 1 (canonical ATG start, TAA / TAG / TGA stops); alternative
# bacterial starts (GTG, TTG) are opt-in. Wrap-aware: an ORF that
# crosses the origin on a circular plasmid is reported with `end < start`
# the same way other parts of the codebase represent wrap features.

_STOP_CODONS = frozenset(("TAA", "TAG", "TGA"))


def _find_orfs(seq: str, *,
               min_aa: int = 30,
               include_alt_starts: bool = False,
               circular: bool = True) -> list[dict]:
    """Six-frame ORF scan. Returns
    ``[{start, end, strand, length_aa, aa_seq}, ...]`` sorted by length
    descending. Wrap-aware on circular plasmids: an ORF crossing the
    origin is reported with ``end < start``, matching the wrap-feature
    convention `_feat_len` / `_bp_in` already implement.

    `min_aa` excludes the stop codon (so ``min_aa=30`` ⇒ ORFs ≥ 30
    coded residues, i.e. ≥ 93 bp including the trailing stop).
    `include_alt_starts=True` adds GTG and TTG to the start-codon
    set — useful for bacterial genomes; off by default since most
    plasmid CDSes use ATG.
    """
    n = len(seq)
    if n < 6:
        return []
    seq_u = seq.upper()
    starts = {"ATG"}
    if include_alt_starts:
        starts |= {"GTG", "TTG"}

    orfs: list[dict] = []

    for strand in (1, -1):
        if strand == 1:
            scan_seq = (seq_u + seq_u) if circular else seq_u
        else:
            rc_seq = _rc(seq_u)
            scan_seq = (rc_seq + rc_seq) if circular else rc_seq
        scan_n = len(scan_seq)

        for frame in range(3):
            current_start = -1
            i = frame
            while i + 3 <= scan_n:
                codon = scan_seq[i:i+3]
                if current_start < 0:
                    if codon in starts:
                        current_start = i
                else:
                    if codon in _STOP_CODONS:
                        aa_len = (i - current_start) // 3
                        # Drop ORFs whose start codon falls in the
                        # second copy of the doubled scan — they're
                        # duplicates of one we already found from the
                        # first copy.
                        if (circular and current_start >= n) \
                                or aa_len < min_aa:
                            current_start = -1
                            i += 3
                            continue
                        nt_seq = scan_seq[current_start:i + 3]  # incl. stop
                        aa_seq = "".join(
                            _CODON_TABLE.get(nt_seq[k:k+3], "?")
                            for k in range(0, len(nt_seq), 3)
                        )
                        if strand == 1:
                            o_s = current_start
                            o_e = i + 3
                            if circular and o_e > n:
                                o_e -= n   # wrap: end < start
                        else:
                            p_rc = current_start
                            e_rc = i + 3
                            if circular:
                                o_s = (n - e_rc) % n
                                o_e = (n - p_rc) % n
                            else:
                                o_s = n - e_rc
                                o_e = n - p_rc
                        orfs.append({
                            "start":     o_s,
                            "end":       o_e,
                            "strand":    strand,
                            "length_aa": aa_len,
                            "aa_seq":    aa_seq,
                        })
                        current_start = -1
                i += 3

    # Dedupe identical (start, end, strand) tuples — can happen when the
    # doubled-scan cycles past the origin and re-finds the same ORF, or
    # when alt-starts inside an ATG-bounded region produce nested hits
    # that then collapse onto the same boundary.
    orfs.sort(key=lambda o: o["length_aa"], reverse=True)
    seen: set[tuple] = set()
    unique: list[dict] = []
    for o in orfs:
        k = (o["start"], o["end"], o["strand"])
        if k in seen:
            continue
        seen.add(k)
        unique.append(o)
    return unique


# ── Char aspect detection ──────────────────────────────────────────────────────

def _detect_char_aspect() -> float:
    """
    Return char_height / char_width for the current terminal by reading
    pixel dimensions via TIOCGWINSZ.  Falls back to 2.0 if unavailable.
    """
    try:
        # Multi-line for lint compliance — caught by Harley King in
        # closed PR #7.
        import fcntl
        import os
        import struct
        import termios
        fds: list[tuple[int, bool]] = []
        try:
            fds.append((os.open("/dev/tty", os.O_RDWR | os.O_NOCTTY), True))
        except OSError:
            pass
        fds += [(0, False), (1, False), (2, False)]
        try:
            for fd, _ in fds:
                try:
                    buf = struct.pack("HHHH", 0, 0, 0, 0)
                    res = fcntl.ioctl(fd, termios.TIOCGWINSZ, buf)
                    rows, cols, px_w, px_h = struct.unpack("HHHH", res)
                    if px_w > 0 and px_h > 0 and rows > 0 and cols > 0:
                        ratio = (px_h / rows) / (px_w / cols)
                        if 0.8 <= ratio <= 5.0:
                            return round(ratio, 3)
                except OSError:
                    continue
        finally:
            for fd, should_close in fds:
                if should_close:
                    try:
                        os.close(fd)
                    except OSError:
                        pass
    except (ImportError, OSError):
        pass
    return 2.0


def _format_bp(bp: int) -> str:
    """Human-readable bp label with up to 2 decimal places in 'k' units."""
    if bp < 1000:
        return str(bp)
    if bp % 1000 == 0:
        return f"{bp // 1000}k"
    if bp % 100 == 0:
        return f"{bp / 1000:.1f}k"
    return f"{bp / 1000:.2f}k"


def _cursor_row_key(table) -> "str | None":
    """Return the value of a DataTable's cursor row key, or None when
    the table is empty or the cursor is out of bounds.

    Centralises the boilerplate `list(t.rows.keys())` + bounds-check
    that was open-coded at ~10 sites (library panel buttons, picker
    modals, primer table). Always pair with the empty-table branch in
    the caller — this helper is read-only.
    """
    if table.row_count == 0:
        return None
    row_keys = list(table.rows.keys())
    if not (0 <= table.cursor_row < len(row_keys)):
        return None
    rk = row_keys[table.cursor_row]
    return rk.value if rk else None


def _feat_label(feat) -> str:
    for q in ("label", "gene", "product", "standard_name", "note", "bound_moiety"):
        if q in feat.qualifiers:
            v = feat.qualifiers[q]
            # Biopython normally wraps qualifier values in a 1+ element
            # list, but malformed GenBank files can produce empty lists
            # or bare strings. Guard both.
            if isinstance(v, list):
                if not v:
                    continue
                s = v[0]
            else:
                s = v
            if not isinstance(s, str):
                continue
            # Collapse whitespace characters (newline, tab, vertical tab)
            # into single spaces so a multi-line /note="…" qualifier
            # doesn't break the sidebar row or clobber the map label.
            # Then strip and fall through if the result is empty.
            s = " ".join(s.split())
            if s:
                return s[:28]
    return feat.type

def _format_feat_tooltip(feat: dict, total: int) -> str:
    """Build the hover-tooltip text for a feature dict (the in-memory
    shape produced by `PlasmidMap._parse` and friends).

    Format:
        ``<type>  <label>``
        ``<start+1>..<end> bp (+/- strand)  ·  <length> bp``
        ``<note>``  ← optional, when the feature came from the feature
                       library and carries a stored note qualifier.

    The tooltip is meant for at-a-glance reading on hover; long notes
    are truncated to fit one panel-width-ish row. Wrap features
    (`end < start`) display as ``start+1..total, 1..end`` so the user
    sees the origin span clearly.
    """
    s = int(feat.get("start", 0))
    e = int(feat.get("end",   0))
    strand = int(feat.get("strand", 1) or 0)
    sym = "+" if strand >= 0 else "−" if strand < 0 else "·"
    length = _feat_len(s, e, total) if total else max(0, e - s)
    if total and e < s:
        # Wrap span: tail + head
        coord = f"{s + 1}..{total}, 1..{e}"
    else:
        coord = f"{s + 1}..{e}"
    label = (feat.get("label") or feat.get("type") or "?").strip() or "(unnamed)"
    ftype = feat.get("type") or "?"
    head  = f"{ftype}  {label}"
    body  = f"{coord} bp ({sym})  ·  {length:,} bp"
    note  = ""
    quals = feat.get("qualifiers") or {}
    if isinstance(quals, dict):
        for q in ("note", "product", "function"):
            v = quals.get(q)
            if isinstance(v, list):
                v = next((x for x in v if isinstance(x, str)), None)
            if isinstance(v, str) and v.strip():
                note = " ".join(v.split())[:200]
                break
    # Weak-primer flag (stamped by `PlasmidMap._parse` when a
    # `primer_bind` feature's `_bound_len` is below the user-set
    # `min_primer_binding` threshold). Surfaces in the tooltip so
    # hovering tells the user *why* the strand arrow turned ⚠.
    weak_line = ""
    if feat.get("_weak_primer"):
        bl = int(feat.get("_bound_len") or 0)
        weak_line = f"⚠ Weak binding: {bl} bp"
    tail = ""
    if note:
        tail += f"\n{note}"
    if weak_line:
        tail += f"\n{weak_line}"
    return f"{head}\n{body}{tail}"


def _nice_tick(total: int) -> int:
    """A tick interval that gives ~6-10 ticks for this plasmid size."""
    for t in [50, 100, 200, 250, 500, 1000, 2000, 2500, 5000, 10000, 25000, 50000]:
        if 4 <= total // t <= 14:
            return t
    return max(1, total // 8)

# ── GenBank I/O ────────────────────────────────────────────────────────────────

def _pick_single_record(records: list, source: str):
    """Given a list of SeqRecords, return the single one if there's exactly
    one, else raise ValueError with a user-friendly message. Used by both
    NCBI fetch and file load so the error text is consistent.
    """
    if not records:
        raise ValueError(
            f"{source} contained no GenBank records. Is it a valid .gb/.gbk file?"
        )
    if len(records) > 1:
        ids = ", ".join(r.id for r in records[:3])
        more = f" (and {len(records) - 3} more)" if len(records) > 3 else ""
        raise ValueError(
            f"{source} contains {len(records)} records — SpliceCraft loads "
            f"one plasmid at a time. Split the file or extract a single "
            f"record first (found: {ids}{more})."
        )
    return records[0]

_NCBI_TIMEOUT_S = 30   # cap long NCBI hangs; the UI worker can't otherwise cancel

# Cap on the GenBank-text response size from `Entrez.efetch`. The record-list
# API (`_NCBI_MAX_RESPONSE_BYTES = 4 MB`) is too tight for a real chromosome
# accession (e.g. an E. coli genome serialises to ~10 MB of GB text).
# 64 MB lets every legitimate plasmid / cosmid / BAC / small chromosome
# through while refusing a multi-GB pathological response (compromised /
# misconfigured server, MITM). Mirrors the `resp.read(MAX + 1)` + bail
# pattern from invariant #20.
_NCBI_GB_MAX_RESPONSE_BYTES = 64 * 1024 * 1024


@_timed("op.fetch_genbank")
def fetch_genbank(accession: str, email: str = "splicecraft@local"):
    """Fetch a GenBank record by accession from NCBI Entrez. Returns SeqRecord.

    Raises ValueError with a user-friendly message if NCBI returns no
    records (obsolete accession), multiple records, or a response larger
    than `_NCBI_GB_MAX_RESPONSE_BYTES`. A 30 s socket timeout is applied
    so a silent network stall surfaces as an error instead of pinning
    the worker thread forever; the size cap defends against a server
    that is reachable but misbehaving (a fast 30 s of GB-text could
    OOM the worker without it).
    """
    import io
    import socket
    import time as _time
    from Bio import Entrez, SeqIO
    Entrez.email = email
    prev_timeout = socket.getdefaulttimeout()
    socket.setdefaulttimeout(_NCBI_TIMEOUT_S)
    # One-retry pattern with 250 ms backoff to absorb transient
    # NCBI flakes (rate-limited 429, brief gateway 502, etc.). Two
    # attempts total — bounded by 2 × 30 s socket timeout + backoff.
    raw: "bytes | str | None" = None
    last_exc: "BaseException | None" = None
    try:
        for attempt in range(2):
            try:
                with Entrez.efetch(
                    db="nucleotide", id=accession,
                    rettype="gb", retmode="text"
                ) as handle:
                    raw = handle.read(_NCBI_GB_MAX_RESPONSE_BYTES + 1)
                break
            except (OSError, socket.timeout) as exc:
                last_exc = exc
                if attempt == 0:
                    _log.debug(
                        "NCBI fetch attempt 1 failed for %r (%s); retrying",
                        accession, exc,
                    )
                    _log_event(
                        "net.retry", endpoint="ncbi",
                        accession=accession, attempt=1,
                        exc_type=type(exc).__name__,
                    )
                    _time.sleep(0.25)
                    continue
                # Both attempts failed — re-raise so the caller's
                # outer handler turns this into a user-facing error.
                raise
    finally:
        socket.setdefaulttimeout(prev_timeout)
    if raw is None:
        # Defensive — if we got here without raw, something went
        # wrong that the loop didn't catch. Fall back to last_exc.
        raise last_exc if last_exc is not None else OSError(
            f"NCBI fetch failed for {accession!r}"
        )
    # Entrez handles return either bytes or str depending on Biopython
    # version; normalise to text for SeqIO.
    if isinstance(raw, bytes):
        raw_len = len(raw)
        text = raw.decode("utf-8", errors="replace")
    else:
        raw_len = len(raw.encode("utf-8", errors="replace"))
        text = raw
    if raw_len > _NCBI_GB_MAX_RESPONSE_BYTES:
        raise ValueError(
            f"NCBI accession {accession!r} returned more than "
            f"{_NCBI_GB_MAX_RESPONSE_BYTES // (1024 * 1024)} MB; refusing "
            f"to load. If this is a legitimate large record, fetch via "
            f"NCBI directly and use File > Open."
        )
    records = list(SeqIO.parse(io.StringIO(text), "genbank"))
    return _pick_single_record(records, f"NCBI accession {accession!r}")

# Third-party API contract: BioPython's SeqIO format identifier for the
# popular commercial plasmid editor's binary `.dna` format. Stored hex-encoded
# so the trademarked string never appears verbatim in our source.
_BIOPYTHON_DNA_FMT = bytes.fromhex("736e617067656e65").decode("ascii")


def _detect_plasmid_format(path: str) -> str:
    """Pick a Biopython SeqIO format key from a file path's extension.

    Supported:
      - GenBank        (.gb, .gbk, .genbank)       → "genbank"
      - popular commercial plasmid editor binary (.dna)
                                                  → ``_BIOPYTHON_DNA_FMT``

    Extensions are matched case-insensitively. Unknown extensions
    default to "genbank" since that's the most common plasmid format;
    the parser will then raise a clear error if the contents don't
    match.
    """
    from pathlib import Path
    suffix = Path(path).suffix.lower()
    if suffix == ".dna":
        return _BIOPYTHON_DNA_FMT
    # .gb, .gbk, .genbank, or anything else — try GenBank.
    return "genbank"


@_timed("op.load_genbank")
def load_genbank(path: str):
    """Load a plasmid file (GenBank .gb/.gbk or .dna). Returns
    SeqRecord.

    Despite the name (kept for backward compatibility), this also
    handles native `.dna` files (the popular commercial plasmid editor's
    binary format) via the BioPython binary parser keyed by
    ``_BIOPYTHON_DNA_FMT``. Dispatch is based on file extension.

    For `.dna` files, BioPython leaves `record.id` / `record.name`
    as `<unknown id>` / `<unknown name>` sentinels (the editor's own
    name/title metadata is not exposed through SeqIO). Backfill both
    from the file stem so the library and map title show something
    human-readable instead of `<unknown name>`.

    Size + symlink check via `_safe_file_size_check`: pre-fix a CLI
    invocation `splicecraft /path/to/huge.gb` (e.g. a 1 GB chromosome
    dump) reached `SeqIO.parse` directly and SeqIO eagerly parsed it
    into RAM. The cap matches the modal-flow cap.

    Raises ValueError with a user-friendly message if the file has no
    records, multiple records, is oversized, or is a symlink to a
    character device.
    """
    import struct
    from Bio import SeqIO
    from pathlib import Path as _P
    ok, reason = _safe_file_size_check(
        _P(path), _SAFE_LOAD_JSON_MAX_BYTES, "Plasmid",
    )
    if not ok:
        raise ValueError(reason or "Plasmid file is unsafe to load")
    fmt = _detect_plasmid_format(path)
    try:
        records = list(SeqIO.parse(path, fmt))
    except (ValueError, struct.error) as exc:
        # CommercialSaaS parser raises ValueError on most malformed files, but
        # Biopython's binary unpacking can also leak struct.error when a
        # .dna file has a truncated header / nonsense packet length.
        # Rewrap both as user-friendly ValueError so callers don't have
        # to special-case struct.error.
        if fmt == _BIOPYTHON_DNA_FMT:
            raise ValueError(
                f"Could not parse popular commercial plasmid editor "
                f"file {path}: {exc}. If this file was exported from an "
                f"older release, try re-exporting as .dna from a current "
                f"version of the editor."
            ) from exc
        raise
    rec = _pick_single_record(records, path)

    # CommercialSaaS (and occasionally minimally-annotated GenBank) records
    # leave id/name as Biopython sentinels. Fall back to the filename
    # so the UI has something meaningful to display.
    stem = _P(path).stem or "plasmid"
    # Sanitize: GenBank LOCUS names can't contain spaces; replace them
    # so round-tripping through _record_to_gb_text doesn't explode.
    safe_stem = stem.replace(" ", "_")[:16] or "plasmid"
    if not rec.id or rec.id.startswith("<unknown"):
        rec.id = safe_stem
    if not rec.name or rec.name.startswith("<unknown"):
        rec.name = safe_stem

    # `.dna` augmentation: re-read the file bytes to recover per-feature
    # colours + primer-bind sequence stamps + 0x05 primer-DB entries that
    # BioPython's `.dna` parser silently drops. Stashed on the record
    # as a transient attribute so `_apply_record` can flush the primer
    # entries into `primers.json` after the load completes. Failures here
    # are non-fatal — the record loads with palette colours and bare
    # primer features (the historical behaviour).
    if fmt == _BIOPYTHON_DNA_FMT:
        try:
            with open(path, "rb") as fh:
                _dna_bytes = fh.read()
            extra_primers = _augment_dna_record_from_packets(rec, _dna_bytes)
            if extra_primers:
                rec._dna_primer_entries = extra_primers
        except (OSError, ValueError) as exc:
            _log.warning(
                "dna augment failed for %s (%s); record loads with "
                "palette colours instead of source colours",
                path, exc,
            )
    return rec


# ── .dna packet I/O (low-level) ──────────────────────────────────────────────
#
# Binary format: each packet is a TLV — 1-byte type + 4-byte
# big-endian length + N bytes payload. The cookie packet (0x09)
# MUST come first; everything after is in implementation order.
# BioPython parses ~5 packet types (cookie, dna, primers, notes,
# features); the rest are silently dropped on read and impossible
# to write at all (BioPython has no .dna writer).
#
# These helpers go below the BioPython layer: they walk the raw
# byte stream, surface every packet (known or not), and let us
# round-trip files by splicing modified packets back into the
# original byte stream — preserving every packet we don't yet
# understand. Packet-type catalog (in progress) lives in
# `scripts/commercialsaas_inspect.py`'s ``KNOWN_PACKETS``.

_COMMERCIALSAAS_PACKET_HISTORY  = 0x07   # xz-compressed <HistoryTree> XML
_COMMERCIALSAAS_PACKET_COOKIE   = 0x09   # 8-byte format magic + 3 shorts
_COMMERCIALSAAS_HISTORY_MAX_XML = 32 * 1024 * 1024   # 32 MB hard cap on
                                                # decompressed payload —
                                                # protects against
                                                # decompression-bomb
                                                # crafted .dna files.


def _iter_commercialsaas_packets(data: bytes):
    """Yield ``(type_byte, length, payload_bytes)`` for every packet
    in a CommercialSaaS .dna byte stream. Stops cleanly on EOF or a
    truncated header. Does NOT validate the cookie packet — the
    caller decides whether to reject."""
    import struct as _struct
    offset = 0
    n = len(data)
    while offset < n:
        if offset + 5 > n:
            return
        type_byte = data[offset]
        length = _struct.unpack(">I", data[offset + 1:offset + 5])[0]
        payload_start = offset + 5
        payload_end   = payload_start + length
        if payload_end > n:
            return   # truncated; stop rather than raise
        yield (type_byte, length, data[payload_start:payload_end])
        offset = payload_end


def _build_commercialsaas_packet(type_byte: int, payload: bytes) -> bytes:
    """Serialise a single packet to bytes — type + 4-byte BE length +
    payload. Used by the writer + history-replace paths."""
    import struct as _struct
    if not (0 <= type_byte <= 0xFF):
        raise ValueError(f"packet type byte out of range: {type_byte!r}")
    if len(payload) > 0xFFFFFFFF:
        raise ValueError(f"payload too large for 32-bit length: "
                         f"{len(payload)} bytes")
    return bytes([type_byte]) + _struct.pack(">I", len(payload)) + payload


def _extract_commercialsaas_history_xml(data: bytes) -> "str | None":
    """Find the 0x07 history packet in a .dna byte stream and return
    its decompressed XML (UTF-8 text) — or ``None`` if no history
    packet exists. Decompression is xz (LZMA); a malformed payload
    raises ``ValueError`` rather than returning a truncated string.

    Streaming decompression with a per-call cap defeats decompression
    bombs: a 10 MB compressed payload that expands to gigabytes is
    aborted at ``_COMMERCIALSAAS_HISTORY_MAX_XML`` rather than
    OOM-ing the worker. The decoder reads up to ``cap + 1`` bytes; if
    it fills, we know the input exceeded the cap.
    """
    import lzma as _lzma
    cap = _COMMERCIALSAAS_HISTORY_MAX_XML
    for type_byte, length, payload in _iter_commercialsaas_packets(data):
        if type_byte != _COMMERCIALSAAS_PACKET_HISTORY:
            continue
        try:
            decoder = _lzma.LZMADecompressor()
            # Read up to cap + 1; if the decoder's not exhausted, we know
            # the input was bigger than the cap.
            decompressed = decoder.decompress(payload, max_length=cap + 1)
        except _lzma.LZMAError as exc:
            raise ValueError(
                f".dna history packet (0x07) is not valid xz: {exc}"
            ) from exc
        if len(decompressed) > cap or not decoder.eof:
            raise ValueError(
                f".dna history XML too large after decompression: "
                f">{cap:,} bytes (cap {cap:,})"
            )
        try:
            return decompressed.decode("utf-8")
        except UnicodeDecodeError as exc:
            raise ValueError(
                f".dna history XML is not valid UTF-8: {exc}"
            ) from exc
    return None


def _pack_commercialsaas_history_payload(xml_text: str) -> bytes:
    """Inverse of `_extract_commercialsaas_history_xml`'s decompression
    step: xz-compress the XML so it can be written as a 0x07
    payload. Uses the default LZMA preset (matches what real
    CommercialSaaS files appear to use). Caller is responsible for
    wrapping in `_build_commercialsaas_packet(0x07, …)`."""
    import lzma as _lzma
    encoded = xml_text.encode("utf-8")
    return _lzma.compress(encoded)


def _inject_commercialsaas_history(data: bytes, new_xml: "str | None") -> bytes:
    """Replace (or insert / remove) the 0x07 history packet in a
    .dna byte stream while preserving every other packet verbatim.
    Returns a new bytes object — input is not mutated.

    - ``new_xml`` non-empty string  → replace existing 0x07 (or
      insert a fresh one immediately after the cookie packet).
    - ``new_xml`` ``None`` or empty → strip the history packet
      entirely. Result is a valid .dna without history.

    Insertion position: immediately after the cookie packet. Real
    CommercialSaaS files position 0x07 in implementation-defined order
    among the metadata packets; we follow the convention of "as
    early as possible after cookie" since that's where CommercialSaaS
    seems to write it on round-trip."""
    new_packet: "bytes | None" = None
    if new_xml:
        payload = _pack_commercialsaas_history_payload(new_xml)
        new_packet = _build_commercialsaas_packet(_COMMERCIALSAAS_PACKET_HISTORY,
                                              payload)
    # Collect once so we can decide where to insert based on whether
    # an existing history packet is present. Two-pass keeps the
    # in-place-replace and the after-cookie-insert paths from
    # competing — the prior single-pass version emitted a new
    # packet at the cookie position AND skipped the existing 0x07
    # later, effectively moving the history slot forward in the
    # file (regression caught 2026-05-06).
    packets = list(_iter_commercialsaas_packets(data))
    has_history = any(t == _COMMERCIALSAAS_PACKET_HISTORY for t, _, _ in packets)
    out: list[bytes] = []
    emitted = False
    for type_byte, _length, payload in packets:
        if type_byte == _COMMERCIALSAAS_PACKET_HISTORY:
            # Replace in place (or skip if removing).
            if new_packet is not None and not emitted:
                out.append(new_packet)
                emitted = True
            continue
        out.append(_build_commercialsaas_packet(type_byte, payload))
        if (not has_history
                and type_byte == _COMMERCIALSAAS_PACKET_COOKIE
                and new_packet is not None
                and not emitted):
            # No existing history — insert the new one immediately
            # after the cookie.
            out.append(new_packet)
            emitted = True
    # Edge case: file had no cookie AND no history (malformed?);
    # append the new history at the end so it's not lost.
    if new_packet is not None and not emitted:
        out.append(new_packet)
    return b"".join(out)


# ── CommercialSaaS .dna packet writers (Phase 3 — from-scratch .dna emit) ──────────
#
# Builds a minimum-viable `.dna` file from a SeqRecord: cookie +
# DNA + features + notes + (optional) history. Other packet types
# real CommercialSaaS files carry — primers, alignments, custom enzymes,
# enzyme visibility, additional sequence properties, etc. — are
# omitted; CommercialSaaS Viewer treats most of them as optional metadata
# and fills sensible defaults on first open. Round-trip fidelity
# for those cosmetic packets is a Phase 5 hardening item.
#
# Bytes read by `_iter_commercialsaas_packets` should round-trip back to
# bytes written here (with re-derived DNA / features XML), so the
# writer is testable against the existing reader without needing
# CommercialSaaS Viewer in the loop.

_COMMERCIALSAAS_PACKET_DNA      = 0x00
_COMMERCIALSAAS_PACKET_PRIMERS  = 0x05
_COMMERCIALSAAS_PACKET_NOTES    = 0x06
_COMMERCIALSAAS_PACKET_ADDPROPS = 0x08
_COMMERCIALSAAS_PACKET_FEATURES = 0x0A

# Cookie payload: 8-byte format magic + 3 unsigned shorts
# (seqType, exportVersion, importVersion). Values cribbed from
# real outputs of the commercial editor (`00 01 00 0f 00 13` =
# seqType 1, exp 15, imp 19) so files we emit advertise the same
# versions the current commercial release writes — gives us the best
# chance of being accepted without "old format" warnings. The 8-byte
# magic is stored hex-encoded so the trademarked string doesn't appear
# verbatim in source.
_COMMERCIALSAAS_COOKIE_MAGIC      = bytes.fromhex("536e617047656e65")  # 8 bytes
_COMMERCIALSAAS_COOKIE_SEQ_TYPE   = 1
_COMMERCIALSAAS_COOKIE_EXP_VER    = 15
_COMMERCIALSAAS_COOKIE_IMP_VER    = 19


def _build_commercialsaas_cookie_packet() -> bytes:
    """Build the 0x09 cookie packet — 14 bytes: 8-byte format magic + 3
    unsigned shorts."""
    import struct as _struct
    payload = _COMMERCIALSAAS_COOKIE_MAGIC + _struct.pack(
        ">HHH", _COMMERCIALSAAS_COOKIE_SEQ_TYPE,
        _COMMERCIALSAAS_COOKIE_EXP_VER, _COMMERCIALSAAS_COOKIE_IMP_VER,
    )
    return _build_commercialsaas_packet(_COMMERCIALSAAS_PACKET_COOKIE, payload)


def _build_commercialsaas_dna_packet(seq: str, *, circular: bool) -> bytes:
    """Build the 0x00 DNA packet — 1-byte flags + N-byte ASCII
    sequence. Real CommercialSaaS files appear to use lowercase bases
    in the payload; we lowercase to match the convention. Flag
    bit 0x01 = circular; other bits cleared (their meaning is
    not fully documented and CommercialSaaS defaults them on read)."""
    flags = 0x01 if circular else 0x00
    payload = bytes([flags]) + seq.lower().encode("ASCII")
    return _build_commercialsaas_packet(_COMMERCIALSAAS_PACKET_DNA, payload)


def _build_commercialsaas_features_packet_from_record(record) -> bytes:
    """Build the 0x0A features packet by serialising every non-source
    feature from the record into CommercialSaaS's XML schema. Features
    with `CompoundLocation` parts emit one `<Segment>` per part
    (e.g., wrap features get 2 segments; spliced CDSes get one per
    exon)."""
    import xml.etree.ElementTree as _ET
    real_feats = [f for f in record.features if f.type != "source"]
    root = _ET.Element("Features",
                          nextValidID=str(len(real_feats)))
    for i, feat in enumerate(real_feats):
        attrs = {
            "recentID": str(i),
            "name":     _commercialsaas_feat_name(feat),
            "type":     feat.type or "misc_feature",
            "allowSegmentOverlaps": "0",
            "consecutiveTranslationNumbering": "1",
        }
        # Strand → CommercialSaaS's `directionality` attribute.
        # Forward = "1", reverse = "2", omit for unknown / unstranded.
        strand = feat.location.strand
        if strand == 1:
            attrs["directionality"] = "1"
        elif strand == -1:
            attrs["directionality"] = "2"
        feat_el = _ET.SubElement(root, "Feature", attrs)
        # Color: derive from `_DEFAULT_TYPE_COLORS` so newly-written
        # features get a sensible default that matches what SpliceCraft
        # renders. CommercialSaaS's library-wide colour map differs slightly,
        # but it gracefully accepts any 6-digit hex.
        color = _DEFAULT_TYPE_COLORS.get(feat.type or "", "#a6acb3")
        # Segments: one per CompoundLocation part; one for simple.
        for part in _commercialsaas_iter_location_parts(feat.location):
            start_1based = int(part.start) + 1
            end_1based   = int(part.end)
            _ET.SubElement(feat_el, "Segment", {
                "range": f"{start_1based}-{end_1based}",
                "color": color,
                "type":  "standard",
            })
        # Qualifiers: skip `label` (already in the `name` attribute).
        # Skip `translation` for non-CDS features (it's CDS-only and
        # CommercialSaaS re-derives it). Otherwise emit each value as a
        # `<V text=>` (or `<V int=>` when the value is an integer).
        for qname, qvals in (feat.qualifiers or {}).items():
            if qname == "label":
                continue
            q_el = _ET.SubElement(feat_el, "Q", {"name": qname})
            for v in (qvals if isinstance(qvals, list) else [qvals]):
                if isinstance(v, bool):
                    # Treat as int for the few CommercialSaaS attrs that use
                    # 0/1; bool subclasses int so isinstance comes
                    # first.
                    _ET.SubElement(q_el, "V", {"int": str(int(v))})
                elif isinstance(v, int):
                    _ET.SubElement(q_el, "V", {"int": str(v)})
                else:
                    # Sweep #11 (2026-05-20): strip control chars from
                    # the text attribute before serialising. Pre-fix
                    # hostile qualifier values containing `\x01`,
                    # `\x02`, etc. produced XML that BioPython
                    # accepted on write but `_safe_xml_parse` would
                    # choke on during round-trip — the file's
                    # `_augment_dna_record_from_packets` then silently
                    # dropped the colour + label overrides, losing
                    # the user's feature-styling work. Mirrors
                    # `_commercialsaas_feat_name` (line ~8230) which
                    # already strips controls from the feature label.
                    sanitised = "".join(
                        c if (c >= " " or c in "\t\n")
                        else " "
                        for c in str(v)
                    )
                    _ET.SubElement(q_el, "V", {"text": sanitised})
    body = _ET.tostring(root, encoding="unicode")
    xml = '<?xml version="1.0"?>' + body
    return _build_commercialsaas_packet(_COMMERCIALSAAS_PACKET_FEATURES,
                                     xml.encode("utf-8"))


def _build_commercialsaas_notes_packet(record) -> bytes:
    """Build the 0x06 notes packet from the SeqRecord's metadata.
    Always sets <Type>Synthetic</Type> (matches what CommercialSaaS writes
    for newly-built constructions); fills <Created> + <LastModified>
    from today's date, and <CreatedBy> as 'SpliceCraft' so users can
    tell at a glance which file came from where."""
    import xml.etree.ElementTree as _ET
    from datetime import datetime as _dt
    now = _dt.now()
    root = _ET.Element("Notes")
    _ET.SubElement(root, "Type").text = "Synthetic"
    _ET.SubElement(root, "ConfirmedExperimentally").text = "0"
    created = _ET.SubElement(root, "Created", {
        "UTC": now.strftime("%H:%M:%S"),
    })
    created.text = now.strftime("%Y.%m.%d")
    modified = _ET.SubElement(root, "LastModified", {
        "UTC": now.strftime("%H:%M:%S"),
    })
    modified.text = now.strftime("%Y.%m.%d")
    _ET.SubElement(root, "CreatedBy").text = "SpliceCraft"
    # Description from the record (mapped to `<Comments>` per BioPython
    # parser convention).
    desc = getattr(record, "description", "") or ""
    if desc and desc != "<unknown description>":
        _ET.SubElement(root, "Comments").text = str(desc)
    body = _ET.tostring(root, encoding="unicode")
    return _build_commercialsaas_packet(_COMMERCIALSAAS_PACKET_NOTES,
                                     body.encode("utf-8"))


def _commercialsaas_feat_name(feat) -> str:
    """Return the display name for a feature in the CommercialSaaS
    convention: prefer the `/label` qualifier, fall back to the
    feature's type. Strips control bytes for safety."""
    quals = feat.qualifiers or {}
    label = (quals.get("label") or quals.get("product") or [feat.type or "?"])
    name = str(label[0] if isinstance(label, list) else label)
    return _CONTROL_CHARS_RE.sub("", name)[:200] or "feature"


def _build_commercialsaas_addprops_packet_default() -> bytes:
    """Build a default 0x08 AdditionalSequenceProperties packet —
    Upstream/DownstreamStickiness="0" (= blunt) and Upstream/Downstream
    Modification=FivePrimePhosphorylated. Real CommercialSaaS files
    emit this even on circular plasmids where end-stickiness has no
    biological meaning; it's part of the editor's standard packet
    inventory and Viewer reads it for the "Sequence Properties"
    inspector. Pinning the 289-byte default matches all three FFE_*
    fixtures byte-for-byte.

    SpliceCraft doesn't currently model strand stickiness or end
    modifications, so a constant default is the right output —
    extending this when we gain a richer linear-fragment model is a
    future hardening item."""
    xml = (
        "<AdditionalSequenceProperties>"
        "<UpstreamStickiness>0</UpstreamStickiness>"
        "<DownstreamStickiness>0</DownstreamStickiness>"
        "<UpstreamModification>FivePrimePhosphorylated</UpstreamModification>"
        "<DownstreamModification>FivePrimePhosphorylated</DownstreamModification>"
        "</AdditionalSequenceProperties>"
    )
    return _build_commercialsaas_packet(_COMMERCIALSAAS_PACKET_ADDPROPS,
                                       xml.encode("utf-8"))


def _build_commercialsaas_primers_packet_default() -> bytes:
    """Build a minimum 0x05 Primers packet — root ``<Primers>`` with a
    single ``<HybridizationParams>`` child carrying the defaults the
    commercial editor writes on save (10 bp min continuous match, 1
    mismatch allowed, 40°C min Tm, 5'-end matching with 15 bp). No
    actual ``<Primer>`` entries — primer features (``primer_bind``)
    are still emitted via the 0x0A features packet.

    Real CommercialSaaS files always carry this packet even when no
    user-tracked primers exist — emitting it lets our from-scratch
    files mirror the editor's expected packet inventory and stops the
    Primers panel from defaulting to "(empty)" instead of the user's
    configured hybridization defaults. Three of the FFE_* test
    fixtures all carry exactly this 217-byte default; pinning it byte-
    for-byte gives us a regression target for ``CommercialSaaS Viewer``
    acceptance.
    """
    xml = (
        '<?xml version="1.0"?>'
        '<Primers nextValidID="0">'
        '<HybridizationParams '
        'minContinuousMatchLen="10" '
        'allowMismatch="1" '
        'minMeltingTemperature="40" '
        'showAdditionalFivePrimeMatches="1" '
        'minimumFivePrimeAnnealing="15"'
        '/>'
        '</Primers>'
    )
    return _build_commercialsaas_packet(_COMMERCIALSAAS_PACKET_PRIMERS,
                                       xml.encode("utf-8"))


def _commercialsaas_iter_location_parts(location):
    """Yield `(start, end)` simple parts for a feature location.
    Handles both `SimpleLocation` (single part) and `CompoundLocation`
    (multi-part; emits one part per sub-location)."""
    parts = getattr(location, "parts", None)
    if parts:
        for p in parts:
            yield p
    else:
        yield location


@_timed("op.write_commercialsaas_dna")
def _write_commercialsaas_dna_bytes(record, *,
                                 history_xml: "str | None" = None) -> bytes:
    """Return a complete `.dna` byte stream from a SeqRecord.

    Packet order: cookie → DNA → features → notes → (optional)
    history. CommercialSaaS tolerates implementation-defined order for
    non-cookie packets; this order matches what real CommercialSaaS
    output writes and what BioPython's parser handles smoothly.

    The result is round-trippable through `_iter_commercialsaas_packets`,
    re-parseable by BioPython's commercialsaas reader (sequence + features
    + topology + notes), and — if Phase 5 validation succeeds —
    accepted by CommercialSaaS Viewer. Until that validation is done,
    treat the writer as "expected to work; please test against
    CommercialSaaS Viewer and report rejections".
    """
    if record is None:
        raise ValueError("record is None")
    seq = str(getattr(record, "seq", "") or "")
    if not seq:
        raise ValueError("record has empty sequence")
    annotations = getattr(record, "annotations", None) or {}
    is_circ = (annotations.get("topology", "") or "").lower() == "circular"
    parts: list[bytes] = []
    parts.append(_build_commercialsaas_cookie_packet())
    parts.append(_build_commercialsaas_dna_packet(seq, circular=is_circ))
    parts.append(_build_commercialsaas_features_packet_from_record(record))
    parts.append(_build_commercialsaas_notes_packet(record))
    # Default 0x08 AdditionalSequenceProperties — strand stickiness +
    # end modifications. Real files carry this even on circular
    # plasmids where end-stickiness is meaningless; emitting the same
    # 289-byte default keeps the Sequence Properties inspector from
    # falling back to "(empty)" when Viewer reads our output.
    parts.append(_build_commercialsaas_addprops_packet_default())
    # Default 0x05 Primers packet — every real CommercialSaaS file
    # carries this with the same `HybridizationParams` defaults even
    # when no user primers are tracked. Emitting it ourselves keeps
    # the from-scratch output's packet inventory aligned with what the
    # editor produces, so Viewer can render the Primers panel cleanly
    # and never has to fall back to "(empty)" defaults.
    parts.append(_build_commercialsaas_primers_packet_default())
    if history_xml:
        payload = _pack_commercialsaas_history_payload(history_xml)
        parts.append(_build_commercialsaas_packet(
            _COMMERCIALSAAS_PACKET_HISTORY, payload))
    return b"".join(parts)


# ── CommercialSaaS construction-history tree (XML ↔ typed Python) ───────────────────
#
# Phase 2 of the round-trip project. Parses the decompressed
# `<HistoryTree>` XML (produced by `_extract_commercialsaas_history_xml`)
# into a `_CommercialSaaSHistoryNode` tree, and serialises back via
# `_serialize_commercialsaas_history`. The wrapper class holds the
# underlying `xml.etree.ElementTree.Element` so unknown attributes /
# children survive a round-trip — important because CommercialSaaS's
# schema isn't fully documented and we'd otherwise lose metadata
# we don't yet recognise.
#
# Schema observed in real .dna files (ECXA.dna fixture):
#   <HistoryTree>
#     <Node name="..." type="DNA" seqLen="N" strandedness="double"
#           ID="i" circular="0|1" operation="...">
#       <RegeneratedSite name="EnzymeName" pos="N" siteCount="N"/>*
#       <HistoryColors>
#         <StrandColors type="Product">
#           <TopStrand><ColorRange range="X..Y" colors="red"/>*</TopStrand>
#           <BottomStrand><ColorRange range="X..Y" colors="red"/>*</BottomStrand>
#         </StrandColors>
#       </HistoryColors>
#       <InputSummary manipulation="..." name1="..." name2="..."
#                     val1="N" val2="N" siteCount1="N" siteCount2="N"/>*
#       <Features> ... (same shape as the top-level Features packet) </Features>?
#       <Node ...>*  (recursive — parent fragments)
#     </Node>
#   </HistoryTree>
#
# Operations seen so far: insertFragment, replace, insert. There are
# almost certainly more (PCR, Gibson, mutagenesis, etc.) — handle
# unknown values as opaque pass-through strings.


_COMMERCIALSAAS_HISTORY_KNOWN_OPS: tuple[str, ...] = (
    "insertFragment", "insert", "replace",
    # Plus any others CommercialSaaS emits — caller code that switches on
    # the operation string should always have a default branch.
)


class _CommercialSaaSHistoryNode:
    """One node in the CommercialSaaS `<HistoryTree>`.

    Wraps an `xml.etree.ElementTree.Element` so unknown attributes
    and child elements survive a parse → modify → serialise cycle.
    Typed properties expose the well-known fields; raw access is
    available via ``self.element`` for anything else.

    Construction modes:
      * ``_CommercialSaaSHistoryNode(element)`` — wrap an existing element
        (used by the parser).
      * ``_CommercialSaaSHistoryNode.new(name=..., seq_len=..., …)`` —
        create a fresh node with the canonical attributes set,
        ready to attach to a parent or use as the tree root.
    """

    __slots__ = ("element",)

    def __init__(self, element) -> None:
        self.element = element

    @classmethod
    def new(cls, *, name: str, seq_len: int, circular: bool,
              operation: str, node_id: int = 0,
              strandedness: str = "double") -> "_CommercialSaaSHistoryNode":
        import xml.etree.ElementTree as _ET
        el = _ET.Element("Node")
        el.set("name", str(name))
        el.set("type", "DNA")
        el.set("seqLen", str(int(seq_len)))
        el.set("strandedness", str(strandedness))
        el.set("ID", str(int(node_id)))
        el.set("circular", "1" if circular else "0")
        el.set("operation", str(operation))
        return cls(el)

    # ── Typed getters ────────────────────────────────────────────

    @property
    def name(self) -> str:
        return self.element.get("name", "") or ""

    @property
    def operation(self) -> str:
        return self.element.get("operation", "") or ""

    @property
    def seq_len(self) -> int:
        try:
            return int(self.element.get("seqLen", "0"))
        except (TypeError, ValueError):
            return 0

    @property
    def circular(self) -> bool:
        return self.element.get("circular") == "1"

    @property
    def node_id(self) -> int:
        try:
            return int(self.element.get("ID", "0"))
        except (TypeError, ValueError):
            return 0

    @property
    def resurrectable(self) -> bool:
        """CommercialSaaS marks parent nodes as ``resurrectable="1"`` when
        the original fragment can be re-extracted from the history
        (i.e., a downstream user could reconstruct the parent
        plasmid). Defaults to False for the top-level result node."""
        return self.element.get("resurrectable") == "1"

    @property
    def parents(self) -> "list[_CommercialSaaSHistoryNode]":
        """Direct parent fragments (one level down). Use
        :meth:`walk` for a full traversal."""
        return [_CommercialSaaSHistoryNode(c)
                for c in self.element.findall("Node")]

    @property
    def regenerated_sites(self) -> "list[dict]":
        """Restriction sites that the cloning operation preserved
        or recreated. Each entry is a plain dict ``{name, pos,
        siteCount}`` so callers don't have to wrap individual
        elements."""
        out: list[dict] = []
        for el in self.element.findall("RegeneratedSite"):
            out.append({
                "name":      el.get("name", ""),
                "pos":       _coerce_int_or_zero(el.get("pos")),
                "siteCount": _coerce_int_or_zero(el.get("siteCount")),
            })
        return out

    @property
    def input_summaries(self) -> "list[dict]":
        out: list[dict] = []
        for el in self.element.findall("InputSummary"):
            out.append({
                "manipulation": el.get("manipulation", ""),
                "name1":        el.get("name1", ""),
                "name2":        el.get("name2", ""),
                "val1":         _coerce_int_or_zero(el.get("val1")),
                "val2":         _coerce_int_or_zero(el.get("val2")),
                "siteCount1":   _coerce_int_or_zero(el.get("siteCount1")),
                "siteCount2":   _coerce_int_or_zero(el.get("siteCount2")),
            })
        return out

    # ── Mutation ─────────────────────────────────────────────────

    def add_parent(self, parent: "_CommercialSaaSHistoryNode") -> None:
        """Attach ``parent`` as a child of this node. CommercialSaaS's
        convention: parent fragments hang off the result node so
        the tree reads "result → parents → grandparents …" as you
        descend. Caller is responsible for setting `parent.node_id`
        to a value unique within the tree."""
        self.element.append(parent.element)

    def add_regenerated_site(self, name: str, pos: int,
                              site_count: int = 1) -> None:
        import xml.etree.ElementTree as _ET
        el = _ET.SubElement(self.element, "RegeneratedSite")
        el.set("name", str(name))
        el.set("pos", str(int(pos)))
        el.set("siteCount", str(int(site_count)))

    def add_input_summary(self, *, manipulation: str,
                            name1: str = "", name2: str = "",
                            val1: int = 0, val2: int = 0,
                            site_count1: int = 1,
                            site_count2: int = 1) -> None:
        import xml.etree.ElementTree as _ET
        el = _ET.SubElement(self.element, "InputSummary")
        el.set("manipulation", str(manipulation))
        el.set("name1", str(name1))
        el.set("name2", str(name2))
        el.set("val1", str(int(val1)))
        el.set("val2", str(int(val2)))
        el.set("siteCount1", str(int(site_count1)))
        el.set("siteCount2", str(int(site_count2)))

    # ── Traversal ────────────────────────────────────────────────

    def walk(self):
        """Pre-order depth-first traversal: yields self, then each
        child node's traversal. Useful for "find every node with
        operation X" / "count parent fragments" / etc. Returns a
        generator of `_CommercialSaaSHistoryNode`.

        Iterative (stack-based) so a hostile `.dna` file with a 1000+
        deep nested `<Node><Node>...` history can't trip the CPython
        recursion limit. The total node count is still bounded by the
        LZMA-decompression cap (`_DNA_HISTORY_XML_MAX_BYTES`).
        """
        stack: list = [self]
        while stack:
            node = stack.pop()
            yield node
            # Push children in reverse so the first child pops next,
            # preserving the original pre-order traversal sequence.
            stack.extend(reversed(node.parents))


def _coerce_int_or_zero(s) -> int:
    """Best-effort int coercion; falls back to 0. Used by history
    attribute getters where a malformed XML attribute shouldn't
    blow up the whole tree traversal."""
    try:
        return int(s) if s is not None else 0
    except (TypeError, ValueError):
        return 0


def _augment_dna_record_from_packets(
    rec, data: bytes,
) -> list[dict]:
    """Recover info BioPython's ``.dna`` parser drops:
      * **per-feature colours** from the 0x0A Features packet
        (``<Segment color="#RRGGBB"/>`` attributes). BioPython parses
        ``<Feature>`` name/type/location but throws the colour away —
        SpliceCraft then falls back to its rotating ``_FEATURE_PALETTE``,
        which gives correct-but-unfamiliar colours that don't match
        what the user saw in the original editor. This helper stamps
        ``ApEinfo_revcolor`` + ``ApEinfo_fwdcolor`` qualifiers on every
        non-source feature so the colour-read path in
        ``PlasmidMap._parse`` picks them up.
      * **primer sequence stamps** on every ``primer_bind`` feature so
        the seq panel renders them with the full primer machinery
        (flap detection, weak-primer arrow, partial-binding tooltip).
        Derived from the bound region's bases — forward primers take
        the top-strand sequence directly; reverse primers take the
        reverse-complement. Skipped if BioPython already provided a
        ``primer_seq`` (defensive — future BioPython versions may
        decode the 0x05 packet themselves).
      * **standalone <Primer> entries** from the 0x05 Primers packet,
        when present. Most user-saved ``.dna`` files keep the 0x05
        packet at its empty default (just ``HybridizationParams``), but
        files that the user has run primer-design on inside the editor
        carry real entries here; we surface them into ``primers.json``
        so the user's primer library mirrors what they had in the
        source file.

    Mutates ``rec`` in place. Returns a list of primer dicts (the
    ``primers.json`` shape) — one per primer_bind feature plus one per
    standalone 0x05 ``<Primer>`` entry, with duplicates by sequence
    already collapsed within this call. The caller (``_apply_record``)
    dedupes against the existing primer DB before persisting.
    """
    import xml.etree.ElementTree as _ET

    # Local Tm calculator — primer3 if available, 2+4 fallback otherwise.
    # Captured once at the top of the augment so we don't pay the import
    # cost for every primer entry we build below. Imported primers get a
    # computed Tm so the Primer Library table renders the same way it
    # does for designed primers (it does `f"{tm:.1f}°C"` on the value).
    try:
        import primer3 as _primer3
        def _calc_tm(s: str) -> float:
            try:
                return float(_primer3.calc_tm(s))
            except Exception:
                # primer3 occasionally barfs on weird sequences (very
                # short, contains N, etc.); fall back to the 2+4 rule.
                # Log so a wave of import-time degenerate primers
                # surfaces as a diagnosable bundle entry instead of
                # silent mis-Tm on every imported primer.
                _log.exception(
                    "import _calc_tm: primer3.calc_tm fell back to "
                    "GC approximation for %d-mer", len(s))
                gc = sum(1 for c in s.upper() if c in "GC")
                at = sum(1 for c in s.upper() if c in "AT")
                return float(2 * at + 4 * gc)
    except ImportError:
        def _calc_tm(s: str) -> float:
            gc = sum(1 for c in s.upper() if c in "GC")
            at = sum(1 for c in s.upper() if c in "AT")
            return float(2 * at + 4 * gc)

    feature_colors: list[str] = []
    feature_names_from_xml: list[str] = []
    standalone_primers: list[dict] = []

    for type_byte, _length, payload in _iter_commercialsaas_packets(data):
        if type_byte == _COMMERCIALSAAS_PACKET_FEATURES:
            try:
                root = _safe_xml_parse(payload.decode("utf-8"))
            except (_ET.ParseError, UnicodeDecodeError, ValueError):
                _log.warning("dna augment: 0x0A features packet parse failed")
                continue
            if root is None:
                continue
            for feat_el in root.findall(".//Feature"):
                seg = feat_el.find("Segment")
                feature_colors.append(
                    seg.get("color", "") if seg is not None else ""
                )
                # Capture the raw XML `name` attribute too. BioPython's
                # `.dna` parser has been observed to mangle whitespace
                # in feature names (GH #17, Cory Tobin 2026-05-13:
                # spaces replaced with backslashes after import). We
                # pin the label to whatever the XML actually contains
                # so the user sees what their authoring tool wrote,
                # not whatever BioPython did on the way in. Strip the
                # control-char set we'd refuse to write anyway —
                # NUL / CR / LF would break a single-row sidebar
                # render — but SPACES + every other printable char
                # survive verbatim.
                xml_name = feat_el.get("name", "") or ""
                xml_name = _CONTROL_CHARS_RE.sub("", xml_name)[:200]
                feature_names_from_xml.append(xml_name)
        elif type_byte == _COMMERCIALSAAS_PACKET_PRIMERS:
            try:
                root = _safe_xml_parse(payload.decode("utf-8"))
            except (_ET.ParseError, UnicodeDecodeError, ValueError):
                _log.warning("dna augment: 0x05 primers packet parse failed")
                continue
            if root is None:
                continue
            today = _date.today().isoformat()
            for prim_el in root.findall(".//Primer"):
                pseq = (prim_el.get("sequence") or "").upper().replace("U", "T")
                if not pseq:
                    continue
                pname = (prim_el.get("name") or "").strip()
                if not pname:
                    pname = f"primer_{len(standalone_primers) + 1}"
                standalone_primers.append({
                    "name":        pname,
                    "sequence":    pseq,
                    "tm":          round(_calc_tm(pseq), 1),
                    "primer_type": "imported",
                    "source":      ".dna import",
                    "pos_start":   None,
                    "pos_end":     None,
                    "strand":      None,
                    "date":        today,
                    "status":      "Imported",
                })

    # Stamp colour qualifiers + override feature labels on features
    # by enumeration order. The 0x0A packet only carries the features
    # the editor itself created; any `source` row in the SeqRecord
    # comes from BioPython's LOCUS parsing (not the 0x0A packet) so
    # it doesn't consume a slot. Out-of-order or extra features are
    # tolerated — we stop when we run off the end of either list.
    #
    # Label override: BioPython's `.dna` parser has been observed to
    # mangle whitespace in feature names (GH #17 — user-typed
    # "Integration Seq" or "Lambda T0 Terminator" comes out with
    # backslashes inserted around the spaces). We pin
    # `qualifiers["label"]` to the raw XML name attribute so the
    # user sees what their authoring tool wrote, not whatever
    # BioPython produced. Skipped when the XML name is empty (some
    # third-party .dna writers omit the attribute), in which case
    # BioPython's parsed label survives untouched.
    feat_idx = 0
    for f in rec.features:
        if f.type == "source":
            continue
        # Color stamp (existing behaviour).
        if feat_idx < len(feature_colors):
            c = feature_colors[feat_idx]
            if c and isinstance(c, str):
                c = c.strip()
                # Defensive: only accept plausible CSS hex colours
                # so a malformed packet can't sneak arbitrary strings
                # into our qualifiers.
                if c.startswith("#") and len(c) in (4, 7):
                    f.qualifiers["ApEinfo_revcolor"] = [c]
                    f.qualifiers["ApEinfo_fwdcolor"] = [c]
        # Label override from raw XML.
        if feat_idx < len(feature_names_from_xml):
            xml_name = feature_names_from_xml[feat_idx]
            if xml_name:
                f.qualifiers["label"] = [xml_name]
        feat_idx += 1
        if (feat_idx >= len(feature_colors)
                and feat_idx >= len(feature_names_from_xml)):
            break

    # Build primer DB entries from the primer_bind features. Two
    # sources for the primer sequence:
    #   * `primer_seq` qualifier already on the feature (the round-trip
    #     case — splicecraft stamps this when it writes a .dna, and ApE
    #     uses the same convention). USE this verbatim so a primer
    #     carrying a 5' flap keeps its full length in the DB; deriving
    #     from the bound region would drop the flap.
    #   * Otherwise derive from the bound region (forward primers take
    #     the top strand directly; reverse primers take the RC).
    # Pre-2026-05-10 the code `continue`d on the qualifier-present
    # branch, which skipped the DB-entry append — so any .dna file
    # round-tripped through splicecraft (or exported from a tool that
    # stamps primer_seq) lost its primers from the imported DB.
    seq_str = str(rec.seq).upper() if getattr(rec, "seq", None) else ""
    n = len(seq_str)
    today = _date.today().isoformat()
    primer_bind_entries: list[dict] = []
    for f in rec.features:
        if f.type != "primer_bind":
            continue
        try:
            bounds = _feat_bounds(f, n)
        except (TypeError, ValueError, AttributeError):
            bounds = None
        if bounds is None:
            continue
        start, end, strand = bounds
        strand = strand or 1
        # Wrap-aware slice: origin-spanning primer_bind features have
        # `end < start` after `_feat_bounds` normalisation. Pre-fix the
        # raw `int(f.location.start)/.end` flattened the `CompoundLocation`
        # to (min, max) and `seq_str[0:n]` stamped the WHOLE plasmid as
        # primer_seq. Rare in practice (most primers don't cross the
        # origin) but biologically wrong when it happens.
        if end < start:
            if not (0 <= start < n and 0 <= end <= n):
                continue
            sliced_top = seq_str[start:] + seq_str[:end]
        else:
            if not (0 <= start < end <= n):
                continue
            sliced_top = seq_str[start:end]
        existing_pseq = f.qualifiers.get("primer_seq", [])
        if existing_pseq and isinstance(existing_pseq, list):
            bound_seq = str(existing_pseq[0]).strip().upper()
            if not bound_seq:
                bound_seq = sliced_top
                if strand < 0:
                    bound_seq = _rc(bound_seq)
        else:
            bound_seq = sliced_top
            if strand < 0:
                bound_seq = _rc(bound_seq)
            f.qualifiers["primer_seq"] = [bound_seq]
        labels = f.qualifiers.get("label", [])
        pname = str(labels[0]).strip() if labels else f"primer_{start}_{end}"
        primer_bind_entries.append({
            "name":        pname,
            "sequence":    bound_seq,
            "tm":          round(_calc_tm(bound_seq), 1),
            "primer_type": "imported",
            "source":      ".dna import",
            "pos_start":   start,
            "pos_end":     end,
            "strand":      strand,
            "date":        today,
            "status":      "Imported",
        })

    # Merge + dedupe by sequence (case-insensitive). Standalone 0x05
    # entries come first so their explicit ``<Primer name="...">`` wins
    # over an auto-generated ``primer_<start>_<end>`` name when the
    # same sequence appears in both places.
    merged: list[dict] = []
    seen: set[str] = set()
    for entry in standalone_primers + primer_bind_entries:
        key = (entry["sequence"] or "").upper()
        if not key or key in seen:
            continue
        merged.append(entry)
        seen.add(key)
    return merged


@_timed("op.parse_commercialsaas_history")
def _parse_commercialsaas_history(xml_text: str) -> "_CommercialSaaSHistoryNode | None":
    """Parse `<HistoryTree>` XML into a node tree. Returns the root
    `<Node>` (the result plasmid) or ``None`` if the XML is empty /
    has no nodes. Raises ``ValueError`` on malformed XML.

    Routes through `_safe_xml_parse` to defang billion-laughs / DOCTYPE
    entity-expansion attacks: .dna files come from external sources
    (collaborators, online repositories, scraped archives) and the
    history XML packet is the most attacker-controlled payload in the
    binary stream.
    """
    import xml.etree.ElementTree as _ET
    if not xml_text or not xml_text.strip():
        return None
    try:
        root = _safe_xml_parse(xml_text)
    except _ET.ParseError as exc:
        raise ValueError(f"Invalid .dna history XML: {exc}") from exc
    if root.tag != "HistoryTree":
        raise ValueError(
            f"Expected root <HistoryTree>, got <{root.tag}>"
        )
    nodes = root.findall("Node")
    if not nodes:
        return None
    if len(nodes) > 1:
        # CommercialSaaS's convention is one top-level Node per file. If we
        # see more, take the first and warn — preserving the raw
        # element keeps the rest available via `.element` for
        # round-trip even though we don't expose them.
        _log.warning(
            "CommercialSaaS history has %d top-level <Node> elements; "
            "expected 1. Using the first.", len(nodes)
        )
    return _CommercialSaaSHistoryNode(nodes[0])


def _serialize_commercialsaas_history(root: "_CommercialSaaSHistoryNode | None"
                                  ) -> str:
    """Serialise a `_CommercialSaaSHistoryNode` back to UTF-8 XML text
    suitable for passing to `_pack_commercialsaas_history_payload`. Empty
    / None root yields an empty `<HistoryTree/>` document so we
    can still emit a valid history packet (e.g., to mark a
    construction with no parental input)."""
    import xml.etree.ElementTree as _ET
    tree_root = _ET.Element("HistoryTree")
    if root is not None:
        tree_root.append(root.element)
    body = _ET.tostring(tree_root, encoding="unicode")
    # CommercialSaaS's emitted XML always opens with the standard
    # declaration. Re-add it on the way out for compatibility — Python's
    # `tostring(encoding="unicode")` skips the declaration by default.
    return f'<?xml version="1.0" encoding="UTF-8"?>{body}'


_BULK_IMPORT_EXTS = {".dna", ".gb", ".gbk", ".genbank"}

# Per-file size cap. Plasmids are typically <100 KB; anything larger is
# probably a chromosome dump or an unrelated file. Refuse rather than
# OOM the parser. 50 MB leaves headroom for huge cosmids / BACs.
_BULK_IMPORT_MAX_BYTES = 50 * 1024 * 1024

# Hard cap on display-name length stored in entry["name"]. The panel
# truncates to 14 chars, but the full name lives in the JSON; keep it
# from blowing up if someone hands us a 4 KB filename.
_BULK_IMPORT_MAX_NAME_LEN = 256


def _record_to_library_entry(record, source_path: Path, *,
                                 history_xml: "str | None" = None) -> dict:
    """Build a plasmid_library.json entry dict from a SeqRecord.

    Display name uses the original filename stem (spaces preserved); the
    LOCUS-safe `record.id` is kept as the entry id. This way a CommercialSaaS
    file named "FFE 1 ENTRY UPD.dna" shows up in the panel as
    "FFE 1 ENTRY UPD" (truncated to 14 chars by the panel) rather than
    the underscored LOCUS form.

    Display name is capped at `_BULK_IMPORT_MAX_NAME_LEN` and stripped of
    control characters so a hostile filename can't blow up the panel
    table or hide content via newline injection.

    Optional ``history_xml`` — if non-empty, attached to the entry as a
    `history_xml` field. Populated by the .dna import path when the
    source file carries a 0x07 history packet; new SpliceCraft
    constructions (via Traditional cloning) attach a freshly-built
    XML here too. Unattached entries (the common case for plain
    GenBank imports) just omit the field.
    """
    raw_name = source_path.stem or record.name or record.id or "plasmid"
    # Strip control chars (newline, tab, carriage return, NUL). Replace
    # with underscore so the name stays readable.
    cleaned = "".join(c if c.isprintable() else "_" for c in raw_name)
    display_name = cleaned[:_BULK_IMPORT_MAX_NAME_LEN] or "plasmid"
    entry: dict = {
        "name":    display_name,
        "id":      record.id,
        "size":    len(record.seq),
        "n_feats": len([f for f in record.features if f.type != "source"]),
        "source":  f"file:{source_path.name}",
        "added":   _date.today().isoformat(),
        "gb_text": _record_to_gb_text(record),
    }
    if history_xml:
        entry["history_xml"] = history_xml
    return entry


def _try_extract_history_xml_from_dna_path(path: Path) -> "str | None":
    """Best-effort: read a .dna file and return its decompressed
    history XML, or ``None`` if missing / unreadable.

    The bulk import path uses this so CommercialSaaS-imported plasmids
    keep their construction history through the round-trip — the
    rest of the .dna's packets are still dropped (BioPython's
    one-way parser only surfaces sequence + features + primers +
    notes), but the history packet IS what the user-visible
    "Construction History" feature reads from. Failures are logged
    but never raise — a missing or malformed history shouldn't block
    a bulk import."""
    try:
        if path.suffix.lower() != ".dna":
            return None
        data = path.read_bytes()
    except OSError as exc:
        _log.warning("history extract: failed to read %s: %s", path, exc)
        return None
    try:
        return _extract_commercialsaas_history_xml(data)
    except ValueError as exc:
        _log.warning("history extract: malformed history packet in %s: %s",
                       path, exc)
        return None
    except Exception:
        _log.exception("history extract: unexpected error on %s", path)
        return None


@_timed("op.bulk_import_folder")
def _bulk_import_folder(
    folder: Path,
    *,
    progress_cb: "_Callable | None" = None,
) -> "tuple[list[dict], list[tuple[Path, str]]]":
    """Walk `folder` for .dna / .gb / .gbk / .genbank files and load each.

    Returns (entries, failures). Each file is loaded independently —
    a single corrupt file doesn't abort the batch. Entries are deduped
    by id within the batch; collisions get a `_2`, `_3`, ... suffix.
    Failures carry (path, reason) so the caller can surface them.

    ``progress_cb``, if supplied, is called once per file as
    ``progress_cb(i, total, filename, ok)`` where ``i`` is 1-based.
    The callback runs in this function's thread (the worker thread,
    not the UI thread) — Textual UI updates from inside it must
    route through ``app.call_from_thread``.

    Defensive against:
      - Folders that can't be read (PermissionError / FileNotFoundError /
        OSError on the directory itself) → returned as a single failure
        keyed on the folder path.
      - Files larger than `_BULK_IMPORT_MAX_BYTES` → skipped with reason.
      - Records with zero-length sequences → skipped with reason.
      - `path.stat()` / `path.is_file()` raising OSError on a per-file
        basis → that file is recorded as a failure, others continue.
      - Any exception inside `load_genbank` → recorded as a failure with
        the friendly reason; full traceback goes to `_log.exception`.
    """
    entries: list[dict] = []
    failures: list[tuple[Path, str]] = []
    seen_ids: set[str] = set()
    # Accumulator for primer DB entries surfaced by
    # `_augment_dna_record_from_packets` on each .dna. Bulk imports
    # discard the SeqRecord after converting it to a library entry, so
    # `_apply_record`'s primer-flush path never fires for these — we
    # have to merge them into `primers.json` ourselves at the end of
    # the batch. Regression guard for 2026-05-10: user reported
    # imported primers missing from the Primer Library after a folder
    # import.
    all_dna_primer_entries: list[dict] = []

    # Read the directory once. Permission / not-found / disappeared-during-
    # selection: surface as one folder-level failure rather than crash.
    try:
        children = sorted(folder.iterdir())
    except (OSError, PermissionError) as exc:
        _log.warning("bulk_import: cannot read folder %s: %s", folder, exc)
        return [], [(folder, f"could not read folder: {exc}")]

    # Pre-filter to importable files so `progress_cb` gets a stable
    # total and can drive a determinate progress bar. Per-file stat
    # failures (broken symlinks, special files) still become per-file
    # failures but don't pollute the progress denominator.
    importable: list[Path] = []
    for path in children:
        # Sweep #10 (2026-05-20): `lstat` + `S_ISREG` refuses symlinks
        # outright. Pre-fix `path.is_file()` and `path.stat()` both
        # FOLLOW symlinks, so a hostile `.gb` symlinked to `/dev/zero`
        # passed the size check (target lstat reports 0 for a char
        # device) and `load_genbank` then read until OOM. Symlinks
        # to `~/.ssh/id_rsa` or similar would also expose private
        # data in any subsequent agent fetch of the imported entry.
        try:
            st = path.lstat()
        except OSError as exc:
            failures.append((path, f"lstat failed: {exc}"))
            continue
        from stat import S_ISREG as _S_ISREG
        if not _S_ISREG(st.st_mode):
            # Could be a symlink, device, fifo, dir, socket — none
            # is acceptable. Symlinks specifically would be a
            # security boundary violation.
            continue
        if path.suffix.lower() not in _BULK_IMPORT_EXTS:
            continue
        importable.append(path)
    total = len(importable)

    for i, path in enumerate(importable, start=1):
        ok = False
        try:
            try:
                # Use lstat again (cheap; refuses race-swapped symlinks
                # between the importable enumeration and per-file
                # load). Defence-in-depth: prevents TOCTOU between
                # the children scan and the load.
                st = path.lstat()
            except OSError as exc:
                failures.append((path, f"lstat failed: {exc}"))
                continue
            from stat import S_ISREG as _S_ISREG
            if not _S_ISREG(st.st_mode):
                failures.append(
                    (path, "not a regular file (refused)"),
                )
                continue
            size = st.st_size
            if size > _BULK_IMPORT_MAX_BYTES:
                failures.append((
                    path,
                    f"file too large ({size:,} bytes; cap "
                    f"{_BULK_IMPORT_MAX_BYTES:,}). Skipping to avoid OOM.",
                ))
                continue
            try:
                rec = load_genbank(str(path))
                if _seq_len(rec) == 0:
                    failures.append((path, "empty sequence (no bases)"))
                    continue
                # CommercialSaaS .dna files carry a construction-history
                # packet (0x07) that BioPython silently drops on
                # parse. Pull it through manually so library entries
                # imported from .dna keep their cloning lineage.
                history_xml = _try_extract_history_xml_from_dna_path(path)
                entry = _record_to_library_entry(rec, path,
                                                    history_xml=history_xml)
                base_id = entry["id"]
                n = 1
                while entry["id"] in seen_ids:
                    n += 1
                    entry["id"] = f"{base_id}_{n}"
                seen_ids.add(entry["id"])
                entries.append(entry)
                # Harvest primer DB entries the augment helper stashed
                # on the SeqRecord — bulk imports never hit
                # `_apply_record`, so without this the user's primer
                # library wouldn't pick up primers from imported .dna
                # files. We accumulate across the batch and write once
                # at the end of `_bulk_import_folder`.
                dna_pe = getattr(rec, "_dna_primer_entries", None)
                if isinstance(dna_pe, list) and dna_pe:
                    all_dna_primer_entries.extend(dna_pe)
                # Sidecar copy of the original .dna bytes (Phase 4d):
                # lets us round-trip back to .dna later by splicing
                # fresh history into the original byte stream. Only
                # attempted for .dna files; failures are non-fatal.
                if path.suffix.lower() == ".dna":
                    try:
                        original_bytes = path.read_bytes()
                        _save_dna_original(entry["id"], original_bytes)
                    except OSError as exc:
                        _log.warning("dna sidecar: read failed for "
                                       "%s during import: %s", path, exc)
                ok = True
            except Exception as exc:
                _log.exception("bulk_import: failed to load %s", path)
                failures.append((path, str(exc)))
        finally:
            # Tick the progress callback for every importable file
            # — success OR failure. The bar should advance whether
            # or not the load succeeded; the failures list carries
            # the detail for the post-import summary.
            if progress_cb is not None:
                try:
                    progress_cb(i, total, path.name, ok)
                except Exception:
                    _log.exception("bulk_import: progress_cb raised")

    # Flush accumulated primer entries to `primers.json`. Dedupes
    # against the existing primer library by sequence (case-insensitive)
    # so re-importing the same folder doesn't pile up duplicates. Save
    # failures are logged but don't abort the import — the library
    # entries themselves have already been built and the caller will
    # persist them; the primer DB sync is a side-effect convenience.
    if all_dna_primer_entries:
        try:
            existing = _load_primers()
            existing_seqs = {
                (e.get("sequence") or "").upper() for e in existing
            }
            n_added = 0
            for pe in all_dna_primer_entries:
                pseq = (pe.get("sequence") or "").upper()
                if not pseq or pseq in existing_seqs:
                    continue
                existing.insert(0, pe)
                existing_seqs.add(pseq)
                n_added += 1
            if n_added:
                _save_primers(existing)
                _log.info(
                    "bulk_import: added %d primer(s) to primer library "
                    "from %d .dna file(s)",
                    n_added, len(all_dna_primer_entries),
                )
        except (OSError, RuntimeError) as exc:
            _log.warning(
                "bulk_import: failed to write imported primers to "
                "primer library (%s); .dna primer features were "
                "preserved on the library entries but not aggregated "
                "into primers.json",
                exc,
            )
    return entries, failures


def _record_to_gb_text(record) -> str:
    """Serialize a SeqRecord to GenBank format text.

    Biopython's genbank writer requires `molecule_type` in annotations
    — if the record came from elsewhere and doesn't have it, default to
    "DNA" rather than crashing. The fill-in happens on a shallow
    SeqRecord copy so the caller's record is never mutated (avoids
    subtle races with concurrent readers and surprise side effects for
    callers that compare records by annotation contents).
    """
    from Bio import SeqIO
    anns = dict(getattr(record, "annotations", None) or {})
    anns.setdefault("molecule_type", "DNA")
    rec = _shallow_copy(record)
    rec.annotations = anns
    buf = StringIO()
    SeqIO.write(rec, buf, "genbank")
    return buf.getvalue()

_GB_TEXT_MAX_BYTES = 64 * 1024 * 1024


def _gb_text_to_record(text: str):
    """Parse GenBank format text back to a SeqRecord.

    Defence-in-depth: cap input length at 64 MB before handing to
    BioPython's parser. Library entries are gated through
    `_safe_load_json`'s 1 GB cap and zip extracts through the 50 MB
    member cap, but the GenBank parser itself is unbounded internally;
    a single record line that happens to slip past upstream caps would
    otherwise allocate intermediate parser objects without ceiling.
    """
    if len(text) > _GB_TEXT_MAX_BYTES:
        raise ValueError(
            f"GenBank text too large to parse "
            f"({len(text):,} bytes > "
            f"{_GB_TEXT_MAX_BYTES:,} cap)"
        )
    from Bio import SeqIO
    return SeqIO.read(StringIO(text), "genbank")


# ── Sequencing-data ingestion (Plasmidsaurus etc.) ────────────────────────────
#
# Plasmidsaurus delivers each run as a .zip with per-sample directories
# containing a consensus assembly (`*.gbk` / `*.gb`), raw reads, and
# QC plots. SpliceCraft's first-pass workflow:
#
#   1. User picks the .zip via `PlasmidsaurusZipModal` (file browser).
#   2. We list every `.gbk` / `.gb` member inside (size-capped to keep
#      the picker responsive against absurd zips).
#   3. User picks a member; we `_extract_gbk_member` it into memory and
#      parse via `_gb_text_to_record`.
#   4. User picks a target plasmid from the library — we run a
#      `_pairwise_align` between the two sequences and surface the
#      result on `AlignmentScreen`.
#
# Future: a Plasmidsaurus API key + per-account download lands here as
# a network sibling of the zip path. Same downstream alignment +
# visualisation pipeline.

# Per-zip + per-member size caps. Plasmidsaurus zips for a single run
# are typically <50 MB and the consensus assembly is <100 KB. Anything
# larger is suspicious; refuse rather than OOM the picker.
_PLASMIDSAURUS_ZIP_MAX_BYTES    = 500 * 1024 * 1024   # 500 MB whole zip
_PLASMIDSAURUS_MEMBER_MAX_BYTES = 50  * 1024 * 1024   # 50 MB per .gbk
_PLASMIDSAURUS_MAX_MEMBERS      = 2000                # listing cap
_GBK_EXTS = (".gbk", ".gb", ".genbank")


def _is_safe_zip_member_name(name: str) -> bool:
    """Return True if `name` is safe to surface in the picker AND safe
    to feed back into `zf.getinfo(name)`. Rejects:

      * absolute paths (`/etc/passwd.gbk`, `C:\\Users\\…`)
      * `..` segments (`../../escape.gbk`)
      * NUL bytes (terminal-display ANSI smuggling)
      * embedded ANSI escape codes (likewise)

    Stdlib `zipfile.open(info)` doesn't extract to a path, so a hostile
    name is currently bounded — but a future `extract()` / `extractall()`
    switch would silently flow into path traversal. This rejection
    fences off the whole class of bugs at the listing stage.
    """
    if not name or "\x00" in name:
        return False
    # ANSI escape (\x1b) — used in terminal-injection attacks
    if "\x1b" in name:
        return False
    # Windows absolute (C:, D:, etc.)
    if len(name) >= 2 and name[1] == ":" and name[0].isalpha():
        return False
    # Backslash separator (Windows paths in malicious zips)
    norm = name.replace("\\", "/")
    if norm.startswith("/"):
        return False
    parts = norm.split("/")
    if any(p in ("..", ".") for p in parts):
        return False
    return True


def _list_gbk_members_in_zip(zip_path: Path) -> "list[dict]":
    """Walk a .zip and return a list of dicts describing every .gbk /
    .gb / .genbank member. Each dict carries:

        ``{"name": <member name>, "size": <uncompressed bytes>}``

    Raises ValueError on unreadable / oversized / non-zip files.
    Cap-protected: refuses zips above `_PLASMIDSAURUS_ZIP_MAX_BYTES`,
    individual members above `_PLASMIDSAURUS_MEMBER_MAX_BYTES`, and
    listings beyond `_PLASMIDSAURUS_MAX_MEMBERS` to keep the picker
    snappy and resistant to malformed archives.
    """
    import zipfile
    p = Path(zip_path)
    if not p.exists():
        raise ValueError(f"zip not found: {p}")
    if not p.is_file():
        raise ValueError(f"not a regular file: {p}")
    try:
        size = p.stat().st_size
    except OSError as exc:
        raise ValueError(f"could not stat zip: {exc}") from exc
    if size > _PLASMIDSAURUS_ZIP_MAX_BYTES:
        raise ValueError(
            f"zip too large ({size:,} bytes; cap "
            f"{_PLASMIDSAURUS_ZIP_MAX_BYTES:,})"
        )
    try:
        zf = zipfile.ZipFile(str(p), "r")
    except (zipfile.BadZipFile, OSError) as exc:
        raise ValueError(f"could not open zip: {exc}") from exc
    members: list[dict] = []
    try:
        for info in zf.infolist():
            if len(members) >= _PLASMIDSAURUS_MAX_MEMBERS:
                _log.warning(
                    "plasmidsaurus: zip listing truncated at %d members",
                    _PLASMIDSAURUS_MAX_MEMBERS,
                )
                break
            if info.is_dir():
                continue
            name = info.filename
            if not _is_safe_zip_member_name(name):
                _log.warning(
                    "plasmidsaurus: skipping unsafe zip member name %r",
                    name,
                )
                continue
            base = name.rsplit("/", 1)[-1]
            if not base or base.startswith("."):
                continue
            ext = ""
            for e in _GBK_EXTS:
                if name.lower().endswith(e):
                    ext = e
                    break
            if not ext:
                continue
            if info.file_size > _PLASMIDSAURUS_MEMBER_MAX_BYTES:
                _log.warning(
                    "plasmidsaurus: skipping oversized member %s (%d bytes)",
                    name, info.file_size,
                )
                continue
            members.append({
                "name": name,
                "size": int(info.file_size),
            })
    finally:
        zf.close()
    members.sort(key=lambda m: _natural_sort_key(m["name"]))
    return members


def _extract_gbk_member(zip_path: Path, member_name: str) -> str:
    """Read a single .gbk member out of a zip and return its decoded
    text. Caller passes the result through `_gb_text_to_record` to get
    a SeqRecord. Raises ValueError on missing / oversized / unreadable
    member, on UTF-8 / latin-1 decode failure, or on an unsafe member
    name (path traversal / NUL / ANSI smuggling)."""
    import zipfile
    if not _is_safe_zip_member_name(member_name):
        raise ValueError(f"unsafe zip member name: {member_name!r}")
    try:
        with zipfile.ZipFile(str(zip_path), "r") as zf:
            try:
                # Sweep #9 (2026-05-19): route through the resolver
                # so Windows-built zips with backslash separators in
                # their central directory still match a member name
                # we stored with forward slashes.
                info = _zf_get_member_info(zf, member_name)
            except KeyError as exc:
                raise ValueError(
                    f"member not in zip: {member_name!r}"
                ) from exc
            if info.file_size > _PLASMIDSAURUS_MEMBER_MAX_BYTES:
                raise ValueError(
                    f"member too large ({info.file_size:,} bytes; cap "
                    f"{_PLASMIDSAURUS_MEMBER_MAX_BYTES:,})"
                )
            # Bounded streaming read: the central-directory `file_size`
            # is attacker-controlled. A malicious zip can claim 1 KB
            # but stream 5 GB of compressed-to-zero data and OOM the
            # process. Cap the actual read at MAX+1 and abort if we
            # exceeded — pre-fix `fh.read()` was unbounded and only
            # the (untrusted) header was checked.
            cap = _PLASMIDSAURUS_MEMBER_MAX_BYTES
            with zf.open(info, "r") as fh:
                raw = fh.read(cap + 1)
            if len(raw) > cap:
                raise ValueError(
                    f"member exceeded cap during decompression "
                    f"(claimed {info.file_size:,} bytes; cap {cap:,}) "
                    f"— possible zip-bomb"
                )
    except (zipfile.BadZipFile, OSError) as exc:
        raise ValueError(f"could not read zip: {exc}") from exc
    # GenBank is ASCII per the spec; fall back to latin-1 only if a
    # stray high-bit byte slipped in (some sequencer pipelines do).
    try:
        return raw.decode("utf-8")
    except UnicodeDecodeError:
        return raw.decode("latin-1", errors="replace")


# ── Plasmidsaurus run-zip structured parser ───────────────────────────────────
#
# A standard Plasmidsaurus results zip groups files by category and
# names each by `<run>_<sample-idx>_<sample-name>.<ext>`. Categories
# seen in the wild:
#
#   <run>_genbank-files/<base>.gbk          — annotated consensus
#   <run>_fasta-files/<base>.fasta          — bare consensus FASTA
#   <run>_summary-files/<base>.txt          — k-mer % + contamination %
#   <run>_per-base-data/<base>.tsv          — per-bp coverage / quality
#   <run>_histograms/<base>.png             — read-length histogram
#   <run>_coverage-plots/<base>.png         — coverage plot
#   <run>_interactive-map/<base>.html       — Bokeh interactive map
#   <run>_ab1-files/<base>.<n-of-m>.ab1     — Sanger trace
#   <run>_gel.png                            — run-level virtual gel
#
# The `_parse_plasmidsaurus_zip` walk groups every member under its
# sample's canonical base name, surfaces run-level files separately,
# and returns small dicts the Sequencing toolbar's sub-tabs can render
# without re-reading the zip per tab. The summary-file body and the
# per-base TSV header are streamed inline (both tiny — <500 KB) so
# the QC tab can render contamination / coverage stats without a
# second pass.

# Cap on the inline-cached summary-file text we keep on the SequencingScreen
# instance. Per the Plasmidsaurus summary files inspected (≤200 bytes
# typical), 4 KB is generous; refuse anything larger to keep the
# in-memory cache bounded even on malformed runs.
_PLASMIDSAURUS_SUMMARY_MAX_BYTES = 4 * 1024

# Cap on per-base TSV reads. Real Plasmidsaurus per-base data is
# ~50 bytes/row × plasmid bp (so a 10 kbp plasmid ships ~500 KB).
# 100 MB is generous for the largest plasmids we'd ever see (200 kbp
# ≈ 10 MB) while still bounding a hostile zip that claims a tiny
# `file_size` in the central directory but streams unbounded data on
# decompress. Sacred-invariant defence-in-depth: also enforced inside
# `_summarize_perbase_tsv` via a chunked read so a single bombing
# line without newlines can't OOM `io.TextIOWrapper`'s buffer.
_PLASMIDSAURUS_PERBASE_MAX_BYTES = 100 * 1024 * 1024


def _normalize_zip_member(name: str) -> str:
    """Return `name` with backslashes folded to forward slashes. Some
    Windows-built zips ship `category\\sample.ext` member names; the
    rest of this module assumes forward slashes."""
    return (name or "").replace("\\", "/")


def _zf_get_member_info(zf, name: str):
    """Resolve a zip member by name, transparently handling
    Windows-built zips whose central directory stores `\\`
    separators while our internal stored names use `/`.

    Tries `getinfo(name)` first (the common case where the name
    we stored is the same as the name in the zip). On KeyError,
    falls back to looking the member up by its normalised form —
    matches against `_normalize_zip_member(info.filename)` so we
    catch backslash-stored entries whose normalised form equals
    the requested name.

    Raises KeyError if no match. Sacred robustness invariant added
    in Sweep #9 (2026-05-19) — without this, a Windows-built
    Plasmidsaurus zip on a POSIX host silently degraded the
    Sequencing tab to error rows because every `zf.getinfo` call
    KeyError'd against a stored-forward-slash name."""
    try:
        return zf.getinfo(name)
    except KeyError:
        pass
    norm_target = _normalize_zip_member(name)
    for info in zf.infolist():
        if _normalize_zip_member(info.filename) == norm_target:
            return info
    raise KeyError(name)


def _parse_plasmidsaurus_zip(zip_path: Path) -> dict:
    """Inspect a Plasmidsaurus results zip and return a structured
    summary keyed by sample.

    Returns ``{"run_id", "samples": [{"base", "name", "gbk", "fasta",
    "summary", "summary_text", "perbase", "perbase_coverage",
    "histogram", "coverage_plot", "interactive_map", "ab1_files"}, ...],
    "run_files": [{"name", "size", "category"}, ...], "total_files",
    "total_size"}``.

    Each ``gbk``/``fasta``/``summary``/``perbase`` value is the zip
    member name (or None when absent). ``summary_text`` is a verbatim
    decode of the summary file body when it is below
    ``_PLASMIDSAURUS_SUMMARY_MAX_BYTES``; consumers parse contamination
    + k-mer percentages from this. ``perbase_coverage`` carries
    coverage stats {"mean", "min", "max", "n_pos", "above_20x"} derived
    from the per-base TSV's `reads_all` column. Both summary_text and
    perbase_coverage are best-effort — missing / unreadable members
    leave them as ``""`` and ``{}``.

    All size caps from `_list_gbk_members_in_zip` apply. Members with
    paths failing `_is_safe_zip_member_name` are silently skipped.

    Raises ValueError on the zip itself being missing / oversized /
    corrupt — same surface as `_list_gbk_members_in_zip`.
    """
    import zipfile
    p = Path(zip_path)
    if not p.exists():
        raise ValueError(f"zip not found: {p}")
    if not p.is_file():
        raise ValueError(f"not a regular file: {p}")
    try:
        size = p.stat().st_size
    except OSError as exc:
        raise ValueError(f"could not stat zip: {exc}") from exc
    if size > _PLASMIDSAURUS_ZIP_MAX_BYTES:
        raise ValueError(
            f"zip too large ({size:,} bytes; cap "
            f"{_PLASMIDSAURUS_ZIP_MAX_BYTES:,})"
        )
    try:
        zf = zipfile.ZipFile(str(p), "r")
    except (zipfile.BadZipFile, OSError) as exc:
        raise ValueError(f"could not open zip: {exc}") from exc

    # Per-sample dict keyed by canonical base name (filename without
    # the category-folder prefix, minus extension).
    samples: dict[str, dict] = {}
    run_files: list[dict] = []
    total_files = 0
    total_size = 0
    # Run ID: parent folder name prefix shared by category dirs
    # (e.g., `34XK5N_genbank-files/...` → run_id=`34XK5N`). Inferred
    # by majority vote so a malformed zip with mixed prefixes doesn't
    # pick a stale one.
    prefix_votes: dict[str, int] = {}

    # Category folder → field-name on the sample dict. Anchored on the
    # underscore-separator pattern Plasmidsaurus uses so a sample whose
    # own filename happens to contain `_genbank-files` doesn't false-
    # positive. We probe per-suffix rather than full prefix because
    # the run-ID prefix varies per zip.
    _CATEGORY_SUFFIXES = (
        ("_genbank-files",      "gbk"),
        ("_fasta-files",        "fasta"),
        ("_summary-files",      "summary"),
        ("_per-base-data",      "perbase"),
        ("_histograms",         "histogram"),
        ("_coverage-plots",     "coverage_plot"),
        ("_interactive-map",    "interactive_map"),
        ("_ab1-files",          "ab1"),   # multiple per sample
    )

    try:
        for info in zf.infolist():
            if info.is_dir():
                continue
            raw_name = _normalize_zip_member(info.filename)
            if not _is_safe_zip_member_name(raw_name):
                _log.warning(
                    "plasmidsaurus: skipping unsafe zip member name %r",
                    raw_name,
                )
                continue
            total_files += 1
            total_size += int(info.file_size or 0)
            parts = raw_name.split("/")
            if len(parts) < 2:
                # Top-level file (e.g., `<run>_gel.png`, `README.txt`).
                base = parts[0]
                # Run-level: anchor the prefix vote on a typical
                # top-level naming, e.g. `34XK5N_gel.png` → `34XK5N`.
                stem = base.rsplit(".", 1)[0]
                if "_" in stem:
                    prefix_votes[stem.split("_", 1)[0]] = (
                        prefix_votes.get(stem.split("_", 1)[0], 0) + 1
                    )
                run_files.append({
                    "name": base,
                    "size": int(info.file_size or 0),
                    "category": "run",
                })
                continue
            folder = parts[0]
            # Match a category suffix anchored on `_<suffix>` at end.
            matched_field: "str | None" = None
            for suffix, field in _CATEGORY_SUFFIXES:
                if folder.endswith(suffix):
                    matched_field = field
                    # Vote: everything before the matched suffix is
                    # the run-ID candidate (e.g. `34XK5N` from
                    # `34XK5N_genbank-files`). A zip whose folders
                    # share one prefix wins by majority.
                    prefix_candidate = folder[: -len(suffix)]
                    if prefix_candidate:
                        prefix_votes[prefix_candidate] = (
                            prefix_votes.get(prefix_candidate, 0) + 1
                        )
                    break
            if matched_field is None:
                # Unknown category folder. If the file itself is a
                # .gbk / .gb / .genbank, treat it as a standalone
                # sample so test-fixture-style zips (no
                # `_genbank-files/` subfolder, just `sample_A/x.gbk`)
                # still surface every plasmid. Otherwise surface
                # under `run_files` so a custom Plasmidsaurus build
                # with an extra folder is still inspectable.
                leaf_raw = parts[-1]
                low = leaf_raw.lower()
                if any(low.endswith(ext) for ext in _GBK_EXTS):
                    matched_field = "gbk"
                else:
                    run_files.append({
                        "name": raw_name,
                        "size": int(info.file_size or 0),
                        "category": folder,
                    })
                    continue
            leaf = parts[-1]
            # Canonical sample base: filename minus dot-extensions.
            # `.1-of-2.ab1` collapses to the base+strip-of-tail logic
            # below so all ab1s for a sample group under the same key.
            base = leaf
            for _ in range(4):  # at most a couple of dot segments
                if "." not in base:
                    break
                stem, _, ext = base.rpartition(".")
                if not stem:
                    break
                # Stop on the canonical biology extensions; everything
                # past `.ab1`, `.gbk`, `.fasta`, `.tsv`, `.txt`,
                # `.png`, `.html` is part of the sample name.
                if ext.lower() in (
                    "gbk", "gb", "genbank", "fasta", "fa", "tsv", "txt",
                    "png", "jpg", "jpeg", "html", "ab1",
                ):
                    base = stem
                    continue
                # `.1-of-2` style sub-suffix on ab1 — strip too so all
                # trace files for a sample collapse to one entry.
                if matched_field == "ab1" and "-of-" in ext:
                    base = stem
                    continue
                break
            entry = samples.setdefault(base, {
                "base": base,
                "name": base,
                "gbk": None, "fasta": None, "summary": None,
                "perbase": None, "histogram": None,
                "coverage_plot": None, "interactive_map": None,
                "ab1_files": [],
                "summary_text": "", "perbase_coverage": {},
            })
            if matched_field == "ab1":
                entry["ab1_files"].append(raw_name)
            else:
                entry[matched_field] = raw_name

        # Stream the small text bodies inline so the QC sub-tab can
        # render contamination / coverage without re-opening the zip.
        for sample in samples.values():
            sm = sample.get("summary")
            if sm:
                try:
                    info = _zf_get_member_info(zf, sm)
                    if info.file_size <= _PLASMIDSAURUS_SUMMARY_MAX_BYTES:
                        with zf.open(info, "r") as fh:
                            data = fh.read(
                                _PLASMIDSAURUS_SUMMARY_MAX_BYTES + 1,
                            )
                        if len(data) <= _PLASMIDSAURUS_SUMMARY_MAX_BYTES:
                            try:
                                sample["summary_text"] = data.decode(
                                    "utf-8",
                                )
                            except UnicodeDecodeError:
                                sample["summary_text"] = data.decode(
                                    "latin-1", errors="replace",
                                )
                except (KeyError, OSError, zipfile.BadZipFile):
                    _log.exception(
                        "plasmidsaurus: failed to read summary for %s",
                        sample.get("base", "?"),
                    )
            pb = sample.get("perbase")
            if pb:
                try:
                    info = _zf_get_member_info(zf, pb)
                    # Per-base TSV can run multi-MB on large plasmids;
                    # stream-decode rather than load fully into memory.
                    # Two-layer cap: refuse outright on a central-directory
                    # `file_size` that already overshoots the limit, then
                    # pass the cap into the streamer so a hostile zip with
                    # an under-claimed size that decompresses into GB still
                    # bails before OOM.
                    if info.file_size > _PLASMIDSAURUS_PERBASE_MAX_BYTES:
                        _log.warning(
                            "plasmidsaurus: skipping oversize perbase %s "
                            "(%d bytes; cap %d)",
                            pb, info.file_size,
                            _PLASMIDSAURUS_PERBASE_MAX_BYTES,
                        )
                    else:
                        with zf.open(info, "r") as fh:
                            sample["perbase_coverage"] = (
                                _summarize_perbase_tsv(
                                    fh,
                                    max_bytes=(
                                        _PLASMIDSAURUS_PERBASE_MAX_BYTES
                                    ),
                                )
                            )
                except (KeyError, OSError, zipfile.BadZipFile):
                    _log.exception(
                        "plasmidsaurus: failed to read perbase for %s",
                        sample.get("base", "?"),
                    )
    finally:
        zf.close()

    # Resolve the run ID by majority vote on the prefixes we saw.
    run_id = ""
    if prefix_votes:
        run_id = max(prefix_votes.items(), key=lambda kv: kv[1])[0]

    # Natural-sort samples by name so MAV32 < MAV34 < ... < MAV310.
    sample_list = sorted(
        samples.values(),
        key=lambda s: _natural_sort_key(s.get("name") or ""),
    )
    return {
        "run_id": run_id,
        "samples": sample_list,
        "run_files": run_files,
        "total_files": total_files,
        "total_size": total_size,
    }


def _summarize_perbase_tsv(fh, *, max_bytes: "int | None" = None) -> dict:
    """Stream the per-base TSV file handle and return summary coverage
    stats: ``{"mean", "min", "max", "n_pos", "above_20x"}``.

    Assumes the Plasmidsaurus column layout (col 0=pos, col 1=ref,
    col 2=reads_all, ...). Defensive on header detection — header row
    is skipped if col 2 isn't an integer. Returns an empty dict on
    parse failure so the caller can degrade gracefully.

    Streams in 64 KB chunks with a hard byte cap (``max_bytes``). A
    zip-bomb that decompresses into a single multi-GB line without
    newlines would otherwise let ``io.TextIOWrapper`` buffer the whole
    line in memory before yielding it. ``max_bytes=None`` skips the
    cap for trusted callers (no current caller hits this path — the
    Plasmidsaurus parser always passes its cap).
    """
    import io
    total = 0
    n = 0
    lo = 10 ** 9
    hi = -1
    above_20x = 0
    import codecs
    chunk_size = 64 * 1024
    try:
        utf8_decoder = codecs.getincrementaldecoder("utf-8")(
            errors="replace",
        )
    except LookupError:
        # Should never happen on a stdlib build, but degrade rather
        # than raising — the caller treats {} as "couldn't summarise".
        return {}
    consumed = 0
    pending = ""
    truncated = False

    def _consume_line(line: str, header_seen_box: list[bool]) -> None:
        nonlocal n, total, lo, hi, above_20x
        cols = line.rstrip("\r").split("\t")
        if len(cols) < 3:
            return
        if not header_seen_box[0]:
            header_seen_box[0] = True
            # Header probe: skip iff col 2 isn't numeric. Sweep #9
            # (2026-05-19): use `float()` rather than `int()` for
            # the numeric test so a TSV that ships fractional
            # `reads_all` (e.g. a sub-sampled assay) doesn't
            # silently discard its first data row.
            try:
                float(cols[2])
            except ValueError:
                return
        try:
            v = int(float(cols[2]))
        except ValueError:
            return
        n += 1
        total += v
        if v < lo:
            lo = v
        if v > hi:
            hi = v
        if v >= 20:
            above_20x += 1

    header_seen = [False]
    try:
        while True:
            try:
                chunk = fh.read(chunk_size)
            except (OSError, ValueError):
                _log.exception(
                    "plasmidsaurus: perbase TSV read failed mid-stream"
                )
                return {}
            if not chunk:
                # Tail flush — last line without trailing newline.
                if pending:
                    _consume_line(pending, header_seen)
                break
            consumed += len(chunk)
            if max_bytes is not None and consumed > max_bytes:
                truncated = True
            text = utf8_decoder.decode(chunk, final=truncated)
            pending += text
            lines = pending.split("\n")
            pending = lines.pop()  # last fragment may be partial
            for line in lines:
                _consume_line(line, header_seen)
            if truncated:
                # Flush any partial tail we have, then stop.
                if pending:
                    _consume_line(pending, header_seen)
                _log.warning(
                    "plasmidsaurus: perbase TSV exceeded %d-byte cap; "
                    "summary truncated", max_bytes,
                )
                break
    except Exception:
        _log.exception("plasmidsaurus: perbase TSV summarize failed")
        return {}
    if n == 0:
        return {}
    return {
        "mean":      total / n,
        "min":       lo if lo != 10 ** 9 else 0,
        "max":       hi if hi >= 0 else 0,
        "n_pos":     n,
        "above_20x": above_20x,
    }


def _parse_plasmidsaurus_summary(text: str) -> dict:
    """Parse the body of a Plasmidsaurus `<run>_<n>_<name>.txt` summary
    file. Returns ``{"kmer_moles_pct": float, "kmer_mass_pct": float,
    "contamination_pct": float, "contamination_source": str,
    "raw_text": str}``. Missing fields default to ``None``.

    Format observed in the wild::

            1-mer (%)  2-mer (%)
        moles       97.5        2.5
        mass        95.1        4.9


        *************************


        E. coli genomic contamination: 18.0%

    Both the column count (`<n>-mer`) and the contamination source
    line vary across runs; we extract the first numeric token after
    `moles`/`mass` (the canonical 1-mer percentages) and grep the
    contamination line for the % value + source organism.
    """
    out: dict = {
        "kmer_moles_pct":      None,
        "kmer_mass_pct":       None,
        "contamination_pct":   None,
        "contamination_source": "",
        "raw_text":             text,
    }
    if not text:
        return out
    import re as _re
    moles_match = _re.search(
        r"^\s*moles\s+([0-9.]+)", text, _re.MULTILINE,
    )
    mass_match = _re.search(
        r"^\s*mass\s+([0-9.]+)",  text, _re.MULTILINE,
    )
    if moles_match:
        try:
            out["kmer_moles_pct"] = float(moles_match.group(1))
        except (TypeError, ValueError):
            pass
    if mass_match:
        try:
            out["kmer_mass_pct"] = float(mass_match.group(1))
        except (TypeError, ValueError):
            pass
    contam_match = _re.search(
        r"([^\n]+?)\s*contamination:\s*([0-9.]+)%", text, _re.IGNORECASE,
    )
    if contam_match:
        out["contamination_source"] = contam_match.group(1).strip()
        try:
            out["contamination_pct"] = float(contam_match.group(2))
        except (TypeError, ValueError):
            pass
    return out


# ── Pairwise alignment (sequencing data ↔ plasmid map) ────────────────────────
#
# Wraps Bio.Align.PairwiseAligner so callers get a small dict result
# rather than a pyobjC-style alignment iterator. Used by
# AlignmentScreen for visualisation and (later) by the agent API for
# scripted alignment runs.
#
# Default mode is `global` end-to-end — Plasmidsaurus consensus is
# usually full-length, so the user wants to see the whole map vs the
# whole consensus. Local mode is offered for partial reads.

# Hard cap on per-side sequence length to keep DP memory bounded.
# 200 kb on each side = ~80 GB if naive O(NM); Biopython's aligner is
# smarter than that but we still don't want the user pasting a
# chromosome.
_PAIRWISE_MAX_LEN = 200_000


# ── Annotation transfer ─────────────────────────────────────────────────────
#
# Given a source plasmid with annotated features and a target plasmid,
# find every feature whose sequence appears verbatim in the target
# (forward or reverse-complement) and propose the matched coordinates.
# Useful when you've assembled a new construct and want to inherit
# the annotations from the parent backbone without re-annotating by
# hand. Exact-match only for v1.0 — fuzzy / BLAST-driven matching is
# a v1.1 candidate; the existing in-process BLAST infra would slot in
# cleanly behind the same `_find_annotation_transfers` API.
#
# Wrap-aware on circular plasmids:
#   * Wrap-source features (end < start) extract bases as
#     `seq[start:] + seq[:end]`.
#   * Wrap-target matches (origin-spanning hits) are detected by
#     scanning `target + target[:len(feat_bases)-1]` and reported
#     with `end < start` matching the rest of the codebase.

# Skip features below this length — primer-binding-site-scale
# matches are noise; the ANNOTATION-PRESERVING workflow is built
# around larger features (CDSes, origins, regulatory regions).
_ANNOT_TRANSFER_MIN_LEN = 30


def _feature_bases(rec_seq: str, feat: dict, n: int) -> str:
    """Return the (top-strand) bases that the feature's
    `(start, end, strand)` covers. Wrap-aware: a feature with
    `end < start` reads `seq[start:] + seq[:end]`. For
    `strand == -1` the bases are reverse-complemented so a
    `feat_bases` lookup against the target's forward strand works
    for both orientations: a forward-strand match means the source's
    coding strand matches the target's top strand; a reverse-
    complement match means the source's coding strand matches the
    target's bottom strand."""
    s = int(feat.get("start", 0))
    e = int(feat.get("end",   0))
    strand = int(feat.get("strand", 1))
    if e == s:
        return ""
    if e < s:
        bases = rec_seq[s:] + rec_seq[:e]
    else:
        bases = rec_seq[s:e]
    if strand == -1:
        bases = _rc(bases)
    return bases.upper()


@_timed("op.annotation_transfer")
def _find_annotation_transfers(source_rec, target_rec, *,
                                  min_len: int = _ANNOT_TRANSFER_MIN_LEN
                                  ) -> list[dict]:
    """For every feature in `source_rec` whose sequence appears
    verbatim in `target_rec` (forward or reverse-complement), return
    a transfer record:
        {label, type, source_start, source_end, source_strand,
         target_start, target_end, target_strand, length, qualifiers}

    `target_start` / `target_end` are forward-strand coords on the
    target. `target_strand` is +1 for a forward match (feature's
    coding strand == target top), −1 for a reverse-complement match.
    Wrap matches on circular targets carry `end < target_start` per
    the wrap-feature convention.

    Features shorter than `min_len` are skipped — small primer-binding
    sites generate noise (an 18-mer hits any random ~1 kb sequence
    by chance); the use case is propagating CDS / origin / regulatory
    annotations where match length comfortably exceeds 30 bp.
    """
    src_seq = str(source_rec.seq).upper()
    tgt_seq = str(target_rec.seq).upper()
    n_src = len(src_seq)
    n_tgt = len(tgt_seq)
    if n_src == 0 or n_tgt == 0:
        return []

    is_circular = (
        (target_rec.annotations or {}).get("topology") == "circular"
    )

    transfers: list[dict] = []
    seen_target_spans: set[tuple[int, int, int]] = set()

    for feat in source_rec.features:
        try:
            ftype = feat.type
        except AttributeError:
            ftype = "?"
        if ftype == "source":
            continue
        # Lift the feature into the dict shape `_feature_bases` expects.
        # `_feat_bounds` is wrap-aware so an origin-spanning source feature
        # transfers correctly; pre-fix this used `int(loc.start)` /
        # `int(loc.end)` which silently flattened wrap CDSes and left
        # them undiscoverable on the target (the search would slice the
        # backbone gap and find nothing).
        bounds = _feat_bounds(feat, n_src)
        if bounds is None:
            continue
        f_start, f_end, f_strand = bounds
        feat_bases = _feature_bases(
            src_seq,
            {"start": f_start, "end": f_end, "strand": f_strand},
            n_src,
        )
        if len(feat_bases) < min_len:
            continue
        # Pull a display label off the qualifiers — same precedence
        # `_record_features` and `AlignmentScreen._body_text` use.
        label = ""
        try:
            for q in ("label", "gene", "product"):
                v = feat.qualifiers.get(q)
                if isinstance(v, list) and v:
                    label = str(v[0])
                    break
        except AttributeError:
            pass
        if not label:
            label = ftype

        # Search target on both strands. For circular targets, scan a
        # tail-extended copy so a feature crossing the origin in the
        # target is found at the right (forward, wrap) coords.
        feat_len = len(feat_bases)
        scan_seqs = [
            (tgt_seq + (tgt_seq[: feat_len - 1] if is_circular else ""), 1),
        ]
        rc_tgt_seq = _rc(tgt_seq)
        scan_seqs.append((
            rc_tgt_seq + (rc_tgt_seq[: feat_len - 1] if is_circular else ""),
            -1,
        ))

        for scan_seq, t_strand in scan_seqs:
            start_idx = 0
            while True:
                hit = scan_seq.find(feat_bases, start_idx)
                if hit < 0:
                    break
                start_idx = hit + 1
                if hit >= n_tgt:
                    # Already visited in the un-wrapped half.
                    continue
                # Map hit + length to forward-strand target coords.
                if t_strand == 1:
                    t_s = hit
                    t_e = hit + feat_len
                else:
                    # rc match at hit on rc(target) corresponds to a
                    # forward-strand span [n - (hit + L), n - hit).
                    t_s = (n_tgt - (hit + feat_len)) % n_tgt \
                          if is_circular else n_tgt - (hit + feat_len)
                    t_e = (n_tgt - hit) % n_tgt \
                          if is_circular else n_tgt - hit
                if not is_circular and (t_s < 0 or t_e > n_tgt):
                    continue
                # Whole-plasmid match (feat_len == n_tgt): wrap-fold
                # would collapse t_e to t_s and the seen-spans key
                # `(t_s, t_s, strand)` would alias every full match.
                # Emit a single full-record transfer with t_s=0,
                # t_e=n_tgt and skip the dedupe key.
                if is_circular and feat_len == n_tgt:
                    t_s = 0
                    t_e = n_tgt
                # Wrap representation: end < start.
                elif is_circular and t_e > n_tgt:
                    t_e -= n_tgt
                key = (t_s, t_e, t_strand)
                if key in seen_target_spans:
                    continue
                seen_target_spans.add(key)
                qual_dict: dict = {}
                try:
                    for k, v in feat.qualifiers.items():
                        # Stringify list values to keep the transfer
                        # payload JSON-serialisable for the agent path.
                        if isinstance(v, list):
                            qual_dict[k] = list(v)
                        else:
                            qual_dict[k] = [str(v)]
                except AttributeError:
                    pass
                transfers.append({
                    "label":          label,
                    "type":           ftype,
                    "source_start":   f_start,
                    "source_end":     f_end,
                    "source_strand":  f_strand,
                    "target_start":   t_s,
                    "target_end":     t_e,
                    "target_strand":  t_strand,
                    "length":         feat_len,
                    "qualifiers":     qual_dict,
                })

    transfers.sort(key=lambda x: (-x["length"], x["target_start"]))
    return transfers


def _find_circular_alignment_offset(
    query: str, target: str, *,
    k: int = 25, n_attempts: int = 12,
) -> int:
    """Find the rotation offset that brings ``target`` into the best
    register with ``query`` for a circular plasmid alignment.

    Plasmidsaurus reads + GenBank references both start at arbitrary
    origins on a circular molecule. A naive global alignment that
    pairs bp 1 of each sequence is almost always wrong — the C-loop
    pays gaps to slide the smaller offset back into register. This
    helper finds a unique seed kmer in ``query``, locates it in
    ``target``, and returns the offset (``target_pos - query_pos``)
    needed to rotate ``target`` so the seeds line up.

    Strategy: walk ``query`` in even-spaced strides, try each kmer
    as a seed against ``target`` (case-insensitive, single uppercase
    canonicalisation), and accept the FIRST seed that has exactly one
    occurrence (uniqueness guard — multi-hit seeds map to repeats
    inside the plasmid, e.g. the LB/RB borders, and would give a
    wrong rotation). Skips low-complexity seeds (<4 distinct bases)
    so a homopolymer run doesn't dominate.

    Returns 0 when no clean seed is found — the caller should treat
    that as "no rotation" and run the naive global align, which is
    still no worse than the prior behaviour.

    Reported by Cory Tobin (GH #16, 2026-05-14): the alignment was
    lining up bp 1 of the query with bp 1 of the GenBank target,
    producing huge mismatch / gap counts that disagreed visibly with
    a CommercialSaaS alignment of the same pair.
    """
    if not query or not target:
        return 0
    q = query.upper()
    t = target.upper()
    qn = len(q)
    tn = len(t)
    if qn < k or tn < k:
        return 0
    # Doubled target so wrap-spanning seeds resolve cleanly (a seed at
    # position tn-5 that runs into the origin would otherwise miss).
    t_doubled = t + t
    stride = max(k, qn // n_attempts)
    for q_start in range(0, qn - k + 1, stride):
        seed = q[q_start:q_start + k]
        # Low-complexity skip — a poly-A run lights up everywhere.
        if len(set(seed)) < 4:
            continue
        t_pos = t_doubled.find(seed)
        if t_pos < 0:
            continue
        # Uniqueness: a second hit within the original (non-doubled)
        # target means the seed isn't anchoring a specific position.
        # Search the rest of the doubled string for any further
        # occurrence; if the second hit is exactly ``tn`` apart from
        # the first it's the wrap copy (same position) and we accept.
        second = t_doubled.find(seed, t_pos + 1)
        if second >= 0 and second != t_pos + tn:
            continue
        # Offset to rotate target so target[t_pos:] aligns with
        # query[q_start:]. Modulo `tn` so a wrap-spanning seed
        # collapses to the canonical [0, tn) range.
        return ((t_pos - q_start) % tn) if tn else 0
    return 0


def _rotate_seq_record(record, offset: int):
    """Return a NEW SeqRecord whose sequence + features are rotated
    so position ``offset`` becomes the new origin (position 0).

    Wrap-aware: features that straddle the new origin emit as a
    `CompoundLocation` (BioPython's `join(...)`). Linear records (or
    `offset == 0`) are returned unchanged.

    Used by the Plasmidsaurus alignment path to render the target
    in the same register as the aligned query. Doesn't mutate the
    input — callers can keep the original record for other surfaces
    (e.g. the library entry).
    """
    from Bio.Seq import Seq
    from Bio.SeqRecord import SeqRecord
    from Bio.SeqFeature import (
        SeqFeature, FeatureLocation, CompoundLocation,
    )
    seq_str = str(getattr(record, "seq", "") or "")
    n = len(seq_str)
    if n == 0 or offset == 0:
        return record
    offset = offset % n
    if offset == 0:
        return record
    new_seq = seq_str[offset:] + seq_str[:offset]
    new_rec = SeqRecord(
        Seq(new_seq),
        id=getattr(record, "id", "") or "",
        name=getattr(record, "name", "") or "",
        description=getattr(record, "description", "") or "",
        annotations=dict(record.annotations or {}),
    )
    for f in (record.features or []):
        if f.type == "source":
            continue
        bounds = _feat_bounds(f, n)
        if bounds is None:
            new_rec.features.append(f)
            continue
        s, e, strand = bounds
        # Re-frame to the rotated origin. `_feat_len` handles the
        # wrap case where the feature crosses the original origin.
        flen = _feat_len(s, e, n)
        new_s = (s - offset) % n
        # Sweep #9 (2026-05-19): the ternary already covers the only
        # path where the mod could equal 0 (i.e. `new_s + flen == n`).
        # The follow-up `if new_e == 0 and new_s + flen == n: new_e = n`
        # was unreachable — removed for clarity.
        new_e = (new_s + flen) % n if (new_s + flen) != n else n
        if new_e > new_s and new_e <= n:
            # Linear span in the rotated frame.
            loc = FeatureLocation(new_s, new_e, strand=strand)
        else:
            # Rotated span crosses the new origin → CompoundLocation.
            loc = CompoundLocation([
                FeatureLocation(new_s, n, strand=strand),
                FeatureLocation(0, new_e, strand=strand),
            ])
        new_rec.features.append(SeqFeature(
            loc, type=f.type, qualifiers=dict(f.qualifiers or {}),
        ))
    return new_rec


@_timed("op.pairwise_align")
def _pairwise_align(query_seq: str, target_seq: str,
                     *, mode: str = "global",
                     match: float = 2.0,
                     mismatch: float = -1.0,
                     open_gap: float = -2.0,
                     extend_gap: float = -0.5,
                     ) -> dict:
    """Run a pairwise alignment via Biopython's PairwiseAligner.

    Returns a dict:

        {
          "mode":          "global" | "local",
          "score":         float,
          "identity_pct":  float,         # over the aligned columns
          "aligned_q":     str,           # gapped query string
          "aligned_t":     str,           # gapped target string
          "n_matches":     int,
          "n_mismatches":  int,
          "n_gaps":        int,           # combined gap chars
          "q_len":         int,
          "t_len":         int,
        }

    Raises ValueError on empty / oversized / non-IUPAC input or when
    Biopython can't produce an alignment (rare; falls through cleanly).
    """
    from Bio.Align import PairwiseAligner
    if not isinstance(query_seq, str) or not isinstance(target_seq, str):
        raise ValueError("query_seq and target_seq must be str")
    q = query_seq.strip().upper()
    t = target_seq.strip().upper()
    if not q or not t:
        raise ValueError("query / target sequence is empty")
    if len(q) > _PAIRWISE_MAX_LEN or len(t) > _PAIRWISE_MAX_LEN:
        raise ValueError(
            f"sequence too long for pairwise align "
            f"(cap {_PAIRWISE_MAX_LEN:,} bp per side)"
        )
    if mode not in ("global", "local"):
        raise ValueError(f"mode must be 'global' or 'local' (got {mode!r})")
    aligner = PairwiseAligner()
    aligner.mode               = mode
    aligner.match_score        = match
    aligner.mismatch_score     = mismatch
    aligner.open_gap_score     = open_gap
    aligner.extend_gap_score   = extend_gap
    try:
        alignments = aligner.align(q, t)
    except Exception as exc:
        raise ValueError(f"pairwise align failed: {exc}") from exc
    try:
        first = alignments[0]
    except (IndexError, StopIteration) as exc:
        raise ValueError("no alignment produced") from exc
    # Biopython 1.81+ Alignment supports row-indexing: `aln[0]` is the
    # gapped first sequence (target), `aln[1]` is the gapped second
    # (query). The text `format()` representation wraps at 60 cols
    # with coordinate prefixes which is awkward to parse — direct
    # row indexing is the documented API.
    # `aligner.align(q, t)` was called q-first, t-second above. So
    # `first[0]` is the gapped query and `first[1]` is the gapped
    # target — preserve that ordering in the result dict.
    try:
        aligned_q = str(first[0])
        aligned_t = str(first[1])
    except (IndexError, TypeError) as exc:
        raise ValueError(f"could not extract aligned rows: {exc}") from exc
    if not aligned_q or not aligned_t:
        raise ValueError("aligner produced empty rows")
    if len(aligned_q) != len(aligned_t):
        raise ValueError(
            f"aligned strings differ in length: q={len(aligned_q)} "
            f"vs t={len(aligned_t)}"
        )
    n_matches    = 0
    n_mismatches = 0
    n_gaps       = 0
    for ch_q, ch_t in zip(aligned_q, aligned_t):
        if ch_q == "-" or ch_t == "-":
            n_gaps += 1
        elif ch_q == ch_t:
            n_matches += 1
        else:
            n_mismatches += 1
    aligned_cols = max(1, n_matches + n_mismatches + n_gaps)
    # `identity_pct` is gap-inclusive (BLAST convention). For global
    # alignment of length-mismatched pairs (e.g. a 200 bp insert vs a
    # 5 kb backbone) the denominator is dominated by gap columns and
    # identity collapses to single digits even when the aligned region
    # is 100% matched. `ungapped_identity_pct` divides by aligned
    # positions only, which is what the user usually wants for "how
    # well does the aligned region match" — surfaced in the summary
    # to disambiguate.
    ungapped_cols = max(1, n_matches + n_mismatches)
    return {
        "mode":                  mode,
        # BioPython's Alignment.score isn't in Pyright's stubs but
        # is the public scalar API (documented + stable since 1.81).
        "score":                 float(getattr(first, "score", 0.0)),
        "identity_pct":          100.0 * n_matches / aligned_cols,
        "ungapped_identity_pct": 100.0 * n_matches / ungapped_cols,
        "aligned_q":             aligned_q,
        "aligned_t":             aligned_t,
        "n_matches":             n_matches,
        "n_mismatches":          n_mismatches,
        "n_gaps":                n_gaps,
        "q_len":                 len(q),
        "t_len":                 len(t),
    }


def _alignment_to_target_segments(
    aligned_q: str, aligned_t: str, t_start: int = 0,
) -> "list[tuple[int, int, str]]":
    """Collapse a pairwise alignment into per-state runs in *target*
    coordinates — the data the linear-map alignment overlay paints
    as blue / red / gray bars.

    Walk the two gapped strings in lockstep. Target position advances
    only on `t != '-'`; columns where the target gaps (insertions in
    the query) consume zero target bp and so don't appear as their
    own segment — they fold into the surrounding state at target
    resolution. Caller can recover insertion positions from the raw
    gapped strings if it ever needs to render an insertion marker.

    Per-target-column state:
        match     — both bases non-gap, ``q == t`` (case-insensitive)
        mismatch  — both bases non-gap, ``q != t``
        gap       — ``q == '-'``, ``t != '-'`` (deletion in the read)

    Returns ``[(t_pos, t_end, state)]`` ascending, half-open target
    ranges. ``t_start`` shifts the returned positions (use it when
    the alignment is local with a non-zero target offset).
    """
    if len(aligned_q) != len(aligned_t):
        raise ValueError(
            f"aligned strings differ in length: q={len(aligned_q)} "
            f"vs t={len(aligned_t)}"
        )
    segs: "list[tuple[int, int, str]]" = []
    t_pos = t_start
    cur_state: "str | None" = None
    cur_start = t_pos
    for q, t in zip(aligned_q.upper(), aligned_t.upper()):
        if t == "-":
            continue
        if q == "-":
            state = "gap"
        elif q == t:
            state = "match"
        else:
            state = "mismatch"
        if state != cur_state:
            if cur_state is not None:
                segs.append((cur_start, t_pos, cur_state))
            cur_state = state
            cur_start = t_pos
        t_pos += 1
    if cur_state is not None:
        segs.append((cur_start, t_pos, cur_state))
    return segs


def _alignment_to_target_letters(
    aligned_q: str, aligned_t: str, t_start: int = 0,
) -> "dict[int, tuple[str, str]]":
    """Per-target-bp ``(query_letter, state)`` map — the data the
    linear-map alignment overlay paints at high zoom (≥ 1 col / bp).

    Companion to `_alignment_to_target_segments`: same walk, same
    state classification, but emits one entry per target column
    instead of coalescing into runs. ``query_letter`` is the raw
    query base at that column (``'-'`` for a gap).
    """
    if len(aligned_q) != len(aligned_t):
        raise ValueError(
            f"aligned strings differ in length: q={len(aligned_q)} "
            f"vs t={len(aligned_t)}"
        )
    out: "dict[int, tuple[str, str]]" = {}
    t_pos = t_start
    for q, t in zip(aligned_q.upper(), aligned_t.upper()):
        if t == "-":
            continue
        if q == "-":
            state = "gap"
        elif q == t:
            state = "match"
        else:
            state = "mismatch"
        out[t_pos] = (q, state)
        t_pos += 1
    return out


# ── GenBank export (NCBI-compliant normalization + atomic write) ──────────────
#
# Biopython's SeqIO.write produces compliant GenBank output when annotations
# include the INSDC-mandated fields. `_normalize_for_genbank` fills in the
# minimum set a plasmid record needs to round-trip cleanly through any NCBI-
# compliant parser. The normalization is non-destructive: the caller's
# record is never mutated (shallow copy with fresh annotations dict).
#
# Defaults chosen for a synthetic plasmid of unknown provenance:
#   topology        = circular   (SpliceCraft only works on plasmids)
#   molecule_type   = DNA
#   data_file_division = SYN     (synthetic; matches what NCBI assigns to
#                                 user-submitted plasmids)
#   date            = today, formatted DD-MMM-YYYY
#   organism        = "synthetic construct"
#   taxonomy        = ["other sequences", "artificial sequences"]
#
# These match what NCBI emits for synthetic constructs submitted via BankIt.

_GB_LOCUS_NAME_MAX = 28  # NCBI relaxed LOCUS name length (spec is 16)


def _normalize_for_genbank(record):
    """Return a shallow copy of `record` with NCBI-required fields filled in.

    Idempotent — existing values are preserved. Only fills gaps. Caller's
    record is never mutated.
    """
    from datetime import datetime as _dt

    rec = _shallow_copy(record)
    anns = dict(getattr(record, "annotations", None) or {})

    anns.setdefault("molecule_type", "DNA")
    anns.setdefault("topology", "circular")
    anns.setdefault("data_file_division", "SYN")

    if not anns.get("date"):
        anns["date"] = _dt.now().strftime("%d-%b-%Y").upper()

    if not anns.get("accessions"):
        acc = rec.id if rec.id and rec.id != "<unknown id>" else ""
        anns["accessions"] = [acc]

    if not anns.get("organism"):
        anns["organism"] = "synthetic construct"
    if not anns.get("source"):
        anns["source"] = anns["organism"]
    if not anns.get("taxonomy"):
        anns["taxonomy"] = ["other sequences", "artificial sequences"]

    rec.annotations = anns

    # LOCUS name: spec is 16 chars; NCBI accepts up to 28 in practice.
    # Biopython itself warns if >16 but does not fail.
    if rec.name and len(rec.name) > _GB_LOCUS_NAME_MAX:
        rec.name = rec.name[:_GB_LOCUS_NAME_MAX]
    if not rec.name or rec.name == "<unknown name>":
        rec.name = (rec.id or "PLASMID")[:_GB_LOCUS_NAME_MAX] or "PLASMID"

    if not rec.description or rec.description == "<unknown description>":
        rec.description = rec.name

    if not rec.id or rec.id == "<unknown id>":
        rec.id = rec.name

    return rec


def _export_genbank_to_path(record, path) -> dict:
    """Write `record` to `path` as a GenBank file. Atomic + round-trip verified.

    Returns a small summary dict `{"path", "bp", "features"}` for UI reporting.

    Raises:
      OSError on filesystem failures (write, replace, fsync).
      ValueError if the round-trip parse fails or the parsed record
        disagrees with the source on sequence length, sequence content,
        or feature count — meaning the export is not byte-safe.

    The round-trip happens BEFORE the target file is touched, so a failed
    export never leaves a half-written / corrupt .gb at `path`.
    """
    from pathlib import Path as _Path

    p = _Path(path).expanduser()
    normalized = _normalize_for_genbank(record)
    text = _record_to_gb_text(normalized)

    # Round-trip verify before touching the filesystem
    try:
        parsed = _gb_text_to_record(text)
    except Exception as exc:
        raise ValueError(f"export round-trip parse failed: {exc}") from exc
    if len(parsed.seq) != len(normalized.seq):
        raise ValueError(
            f"export round-trip sequence length mismatch "
            f"({len(parsed.seq)} vs {len(normalized.seq)})"
        )
    if str(parsed.seq).upper() != str(normalized.seq).upper():
        raise ValueError("export round-trip sequence content mismatch")
    if len(parsed.features) != len(normalized.features):
        raise ValueError(
            f"export round-trip feature count mismatch "
            f"({len(parsed.features)} vs {len(normalized.features)})"
        )

    _atomic_write_text(p, text)

    _log.info(
        "Exported GenBank to %s (%d bp, %d features)",
        p, len(normalized.seq), len(normalized.features),
    )
    return {"path": str(p), "bp": len(normalized.seq),
            "features": len(normalized.features)}


def _record_to_gff3(record) -> str:
    """Serialise `record` to GFF3 text (specification 1.26).

    GFF3 columns: seqid, source, type, start, end, score, strand, phase,
    attributes. Coordinates are 1-based inclusive — note the off-by-one
    versus SpliceCraft's internal 0-based half-open `[start, end)`. For
    each feature we emit one line per `FeatureLocation` part so wrap
    features (origin-spanning `CompoundLocation`) become two
    same-ID rows joined by a shared `ID=...` attribute, the standard
    GFF3 convention for split features. Circular records carry
    `Is_circular=true` on a synthesised top-level region row.
    """
    from urllib.parse import quote as _q

    seqid = (record.id or record.name or "plasmid").strip() or "plasmid"
    # GFF3 reserves a tighter set of seqid characters than GenBank LOCUS;
    # percent-encode anything outside `[A-Za-z0-9._:^*$@!+_?\-|]`.
    safe_seqid = _q(seqid, safe=".:_-")
    n = len(record.seq)
    is_circular = (
        (record.annotations or {}).get("topology", "").lower() == "circular"
    )

    out: list[str] = []
    out.append("##gff-version 3")
    if n:
        out.append(f"##sequence-region {safe_seqid} 1 {n}")
    # Synthesise a top-level region row so downstream consumers can see
    # the topology flag — Bio.SeqRecord doesn't surface it through the
    # features list otherwise. `region` is the GFF3 SO term for this.
    region_attrs = [f"ID={safe_seqid}"]
    if is_circular:
        region_attrs.append("Is_circular=true")
    if n:
        out.append("\t".join((
            safe_seqid, "SpliceCraft", "region",
            "1", str(n), ".", "+", ".",
            ";".join(region_attrs),
        )))

    auto_id = 0
    for feat in record.features:
        ftype = (feat.type or "misc_feature").strip() or "misc_feature"
        if ftype == "source":
            # Source features map to the synthetic `region` row above;
            # emitting both would double-list the whole-record span.
            continue
        try:
            strand_int = int(feat.location.strand or 0)
        except (AttributeError, TypeError, ValueError):
            strand_int = 0
        # NOTE: per-part strand is computed below in the parts loop
        # (see `part_gff_strand`); the feature-level strand glyph was
        # an earlier-revision artefact and is unused after the
        # mixed-strand `CompoundLocation` fix.
        # Pull a display name + extra qualifiers. Same precedence other
        # parts of the codebase use.
        name = ""
        try:
            for q in ("label", "gene", "product"):
                v = feat.qualifiers.get(q)
                if isinstance(v, list) and v:
                    name = str(v[0])
                    break
        except AttributeError:
            pass
        auto_id += 1
        feat_id = f"feat{auto_id}"
        attr_parts: list[str] = [f"ID={feat_id}"]
        if name:
            attr_parts.append(f"Name={_q(name, safe='')}")
        # All other qualifiers as Note-prefixed key/value, except the
        # ones we already mapped (label/gene/product) — except gene and
        # product can convey extra info, so emit them too as proper
        # GFF3 attributes when present.
        try:
            quals = feat.qualifiers
        except AttributeError:
            quals = {}
        for k, vlist in (quals or {}).items():
            if k in ("label",):
                continue
            if not isinstance(vlist, list):
                vlist = [str(vlist)]
            joined = ",".join(_q(str(v), safe="") for v in vlist)
            if k in ("gene", "product"):
                attr_parts.append(f"{k}={joined}")
            else:
                # GFF3 spec is strict — treat any unknown qualifier as
                # a Note (free-text). Multiple Notes get comma-joined.
                attr_parts.append(f"Note={_q(k + '=' + ','.join(str(v) for v in vlist), safe='')}")
        # Phase: CDS features default to 0 unless the qualifier
        # supplies a codon_start (1-based 1/2/3 → 0/1/2 phase).
        phase = "."
        if ftype.upper() == "CDS":
            try:
                cs = int((quals.get("codon_start", ["1"]) or ["1"])[0])
            except (TypeError, ValueError, IndexError):
                cs = 1
            phase = str(max(0, min(2, cs - 1)))
        # Iterate location parts so wrap features get one row per arc,
        # sharing the same ID — the GFF3 split-feature convention.
        # Order parts in biological 5'→3' direction so the split-feature
        # rows read in the order the ribosome (or polymerase) traverses
        # them. For forward-strand: ascending genomic start. For
        # reverse-strand: descending. A canonical-wrap forward feature
        # (`join(tail..total, 1..head)`) is already declared in 5'→3'
        # order (tail first), so sorting by start would REVERSE it; we
        # detect canonical wrap and keep it in declared order. Same for
        # reverse-strand wrap (head first, descending). Pre-2026-05-11
        # the loop iterated `parts` in declared order — fine for
        # GenBank-parsed wraps (which declare in biological order) but
        # wrong for programmatically constructed CompoundLocations.
        try:
            parts_seq = list(getattr(feat.location, "parts", None)
                              or [feat.location])
        except AttributeError:
            parts_seq = []
        try:
            is_wrap_canonical = (
                len(parts_seq) == 2
                and int(parts_seq[0].start) == 0
                and int(parts_seq[-1].end) == len(record.seq)
                and int(parts_seq[0].end) < int(parts_seq[-1].start)
            )
        except (AttributeError, TypeError, ValueError):
            is_wrap_canonical = False
        if is_wrap_canonical:
            # Tail first for + strand (biological 5'→3'); head first for - strand.
            parts = ([parts_seq[-1], parts_seq[0]] if strand_int != -1
                     else [parts_seq[0], parts_seq[-1]])
        else:
            try:
                parts_sorted = sorted(parts_seq, key=lambda p: int(p.start))
            except (AttributeError, TypeError, ValueError):
                parts_sorted = parts_seq
            parts = (parts_sorted if strand_int != -1
                     else list(reversed(parts_sorted)))
        for part in parts:
            try:
                p_s = int(part.start)
                p_e = int(part.end)
            except (AttributeError, TypeError, ValueError):
                continue
            if p_e <= p_s:
                continue
            # Per-part strand: a mixed-strand `CompoundLocation` has
            # `feat.location.strand == None` (Biopython returns None when
            # parts disagree), so the feature-level `gff_strand`
            # computation above flattened to "." and lost the per-part
            # info. Probe each `part.strand` so mixed-strand joins
            # (rare but legal in biology) emit the right +/- per arc.
            # Falls back to the feature-level strand when the part
            # itself has no strand attribute.
            part_strand = getattr(part, "strand", None)
            if part_strand is None:
                part_strand = strand_int or 0
            part_gff_strand = ("+" if part_strand == 1
                                else "-" if part_strand == -1 else ".")
            out.append("\t".join((
                safe_seqid,
                "SpliceCraft",
                ftype,
                # 1-based inclusive: start = p_s + 1; end = p_e.
                str(p_s + 1),
                str(p_e),
                ".",
                part_gff_strand,
                phase,
                ";".join(attr_parts),
            )))

    out.append("")  # trailing newline so cat-friendly tools don't
                    # complain about a missing final EOL.
    return "\n".join(out)


def _export_gff_to_path(record, path) -> dict:
    """Write `record` to `path` as GFF3. Atomic write. Returns
    ``{"path", "bp", "features"}``.

    No round-trip verify (GFF3 has no canonical 1:1 reader in the
    standard library and Biopython's GFF support lives in BCBio.GFF
    which is an optional dep). The serialiser is deterministic and
    test-covered, so the same source record always produces the
    same output."""
    from pathlib import Path as _Path

    p = _Path(path).expanduser()
    text = _record_to_gff3(record)
    _atomic_write_text(p, text)
    _log.info(
        "Exported GFF3 to %s (%d bp, %d features)",
        p, len(record.seq),
        len([f for f in record.features if f.type != "source"]),
    )
    return {
        "path":     str(p),
        "bp":       len(record.seq),
        "features": len([f for f in record.features
                          if f.type != "source"]),
    }


def _export_fasta_to_path(name: str, sequence: str, path) -> dict:
    """Write `sequence` to `path` as a single-record FASTA. Atomic write.

    Returns `{"path", "bp", "name"}` on success. Raises:
      ValueError  — empty name or empty sequence.
      OSError     — filesystem failures (write, replace, fsync).

    The sequence is written on a single line (no hard-wrap at 80 chars);
    that matches what Biopython's default SeqIO writer emits for us
    elsewhere and keeps downstream `grep`/`awk` one-liners simple.
    """
    from pathlib import Path as _Path

    header = (name or "").strip()
    seq = (sequence or "").strip().upper()
    if not header:
        raise ValueError("FASTA export needs a non-empty record name.")
    if not seq:
        raise ValueError("FASTA export needs a non-empty sequence.")

    p = _Path(path).expanduser()
    _atomic_write_text(p, f">{header}\n{seq}\n")

    _log.info("Exported FASTA to %s (%s, %d bp)", p, header, len(seq))
    return {"path": str(p), "bp": len(seq), "name": header}


# ── Core drawing ───────────────────────────────────────────────────────────────

class _Canvas:
    """A mutable 2-D character grid that renders to a Rich Text object."""

    def __init__(self, width: int, height: int):
        self.w = width
        self.h = height
        self._chars:  list[list[str]] = [[" "] * width for _ in range(height)]
        self._styles: list[list[str]] = [[""]  * width for _ in range(height)]

    def put(self, col: int, row: int, ch: str, style: str = ""):
        if 0 <= col < self.w and 0 <= row < self.h:
            self._chars[row][col]  = ch
            self._styles[row][col] = style

    def put_text(self, col: int, row: int, text: str, style: str = ""):
        for j, ch in enumerate(text):
            self.put(col + j, row, ch, style)


# Pre-built lookup table for braille glyphs U+2800..U+28FF. The combine
# loop in `_BrailleCanvas.render` writes one cell per (col, row) — on a
# 160×48 canvas that's ~7,000 chr() calls per render. CPython's small-int
# char cache stops at chr(255), so braille codepoints miss it. Indexing
# into a pre-built list saves ~1–2 ms/frame on the circular-map render.
_BRAILLE_LUT: list[str] = [chr(0x2800 + i) for i in range(256)]


class _BrailleCanvas:
    """
    Sub-character resolution canvas using Unicode braille (U+2800–U+28FF).

    Each terminal cell (col, row) encodes a 2-wide × 4-tall dot grid —
    8 pixels per character cell.  Braille dot layout:

        px%2=0  px%2=1
        dot1    dot4    ← py%4=0   (bits 0, 3)
        dot2    dot5    ← py%4=1   (bits 1, 4)
        dot3    dot6    ← py%4=2   (bits 2, 5)
        dot7    dot8    ← py%4=3   (bits 6, 7)

    Codepoint = 0x2800 + bitmask of active dots.
    Colors: higher-priority write wins per cell.
    """

    _DOT_BITS: list[list[int]] = [
        [0, 3],
        [1, 4],
        [2, 5],
        [6, 7],
    ]

    def __init__(self, cols: int, rows: int):
        self.cols = cols
        self.rows = rows
        self._bits:   list[list[int]] = [[0]  * cols for _ in range(rows)]
        self._colors: list[list[str]] = [[" "] * cols for _ in range(rows)]
        self._prio:   list[list[int]] = [[0]  * cols for _ in range(rows)]

    def set_pixel(self, px: int, py: int,
                  color: str = "", priority: int = 1) -> None:
        col, row = px // 2, py // 4
        if not (0 <= col < self.cols and 0 <= row < self.rows):
            return
        self._bits[row][col] |= 1 << self._DOT_BITS[py % 4][px % 2]
        if color and priority >= self._prio[row][col]:
            self._colors[row][col] = color
            self._prio[row][col]   = priority

    def combine(self, text_canvas: "_Canvas") -> Text:
        """
        Return a Rich Text object.
        Non-space cells from *text_canvas* are drawn on top;
        braille pixels fill the rest.
        Consecutive blank cells are batched into a single append call.
        """
        result = Text(no_wrap=True, overflow="crop")
        rows   = min(self.rows, text_canvas.h)
        cols   = min(self.cols, text_canvas.w)
        tc_chars  = text_canvas._chars
        tc_styles = text_canvas._styles
        bc_bits   = self._bits
        bc_colors = self._colors
        for row in range(rows):
            blank_run = 0
            tc_row  = tc_chars[row]
            tcs_row = tc_styles[row]
            bc_bits_row   = bc_bits[row]
            bc_colors_row = bc_colors[row]
            for col in range(cols):
                tc_ch = tc_row[col]
                if tc_ch == " " and not bc_bits_row[col]:
                    blank_run += 1
                else:
                    if blank_run:
                        result.append(" " * blank_run)
                        blank_run = 0
                    if tc_ch != " ":
                        st = tcs_row[col]
                        result.append(tc_ch, style=st) if st else result.append(tc_ch)
                    else:
                        ch = _BRAILLE_LUT[bc_bits_row[col]]
                        c  = bc_colors_row[col]
                        result.append(ch, style=c) if c != " " else result.append(ch)
            if blank_run:
                result.append(" " * blank_run)
            if row < rows - 1:
                result.append("\n")
        return result


def _arrow_char(tangent_angle: float) -> str:
    """Pick a directional arrow char for an arrowhead."""
    t = tangent_angle % (2 * math.pi)
    sector = int((t + math.pi / 4) / (math.pi / 2)) % 4
    return ["▶", "▼", "◀", "▲"][sector]


# ── PlasmidMap widget ──────────────────────────────────────────────────────────

class PlasmidMap(Widget):
    """
    Circular plasmid map.

    Keyboard: ← → to rotate when focused (click map first); [ ] always rotate.
    Mouse:    scroll to rotate; click to select a feature.
    """

    DEFAULT_CSS = """
    PlasmidMap {
        width: 1fr;
        height: 1fr;
        background: $background;
    }
    /* Subtle background brighten when the map has focus — gives the
       user a "you are here" cue without the layout-disrupting
       accent border that ate a row/column off the braille canvas
       (which then forced a viewport recompute + visible resize).
       `#0c0c0c` is ~5 % brighter than pure black: barely there in
       full light, clearly visible on a dim terminal. */
    PlasmidMap:focus-within { background: #0c0c0c; }
    """

    can_focus = True

    BINDINGS = [
        # Rotation direction: ← = counterclockwise, → = clockwise.
        # `[` and `]` are alternate keys that don't conflict with text
        # editing in the seq panel; both are focus-gated to the map (no
        # `priority=True`), so rotation only happens when the user has
        # actually clicked into the map panel.
        # Rotation/reset-origin bindings used to surface in the Footer
        # when the map had focus, but the row clipped on narrow
        # terminals. Hidden 2026-05-01 to keep the Footer minimal —
        # the keys still work, and `?` Help lists them in full.
        Binding("left",        "rotate_ccw",       "Rotate ←",      show=False),
        Binding("right",       "rotate_cw",        "Rotate →",      show=False),
        Binding("up",          "reset_origin",     "Reset origin",  show=False),
        Binding("shift+left",  "rotate_ccw_lg",    "Rotate ←←",     show=False),
        Binding("shift+right", "rotate_cw_lg",     "Rotate →→",     show=False),
        Binding("[",           "rotate_ccw",       "Rotate ←",      show=False),
        Binding("]",           "rotate_cw",        "Rotate →",      show=False),
        Binding("shift+[",     "rotate_ccw_lg",    "Rotate ←←",     show=False),
        Binding("shift+]",     "rotate_cw_lg",     "Rotate →→",     show=False),
        Binding("home",        "reset_origin",     "Reset",         show=False),
        # Alt+O — re-anchor the display origin at the highlighted
        # feature's start. Cascades through the OriginChanged watcher
        # to reorder the sidebar + shift the seq panel. Hidden from
        # the Footer; documented in the Help modal.
        Binding("alt+o",       "set_origin_to_selected",
                                                  "Set origin (Alt+O)", show=False),
        Binding("comma",       "aspect_dec",       "Circle wider",   show=False),
        Binding("full_stop",   "aspect_inc",       "Circle taller",  show=False),
        Binding("v",           "toggle_map_view",  "Toggle view",    show=False),
        # Linear-view zoom + pan (no-ops in circular mode). The action
        # methods early-return when `_map_mode != "linear"` so binding
        # collisions on `+` / `-` / `0` don't surprise circular-view
        # users. `0` resets the zoom + pan to "show whole record".
        Binding("plus",        "linear_zoom_in",   "Zoom in",        show=False),
        Binding("equals_sign", "linear_zoom_in",   "Zoom in",        show=False),
        Binding("minus",       "linear_zoom_out",  "Zoom out",       show=False),
        Binding("0",           "linear_reset_zoom", "Reset zoom",    show=False),
    ]

    origin_bp:    reactive[int]   = reactive(0)
    selected_idx: reactive[int]   = reactive(-1)
    _aspect:      reactive[float] = reactive(2.0)
    _map_mode:    reactive[str]   = reactive("circular")
    # Linear-view zoom + horizontal pan. Zoom 1.0 = the whole record
    # fits in the visible width. Higher zoom = smaller bp range
    # visible. `_linear_offset_bp` is the bp at the LEFT edge of the
    # view; clamped to `[0, total - visible_bp]` in `_linear_view_range`
    # so pan can't scroll past either end.
    _linear_zoom:      reactive[float] = reactive(1.0)
    _linear_offset_bp: reactive[int]   = reactive(0)
    # Linear feature layout style — fixed at "flag" since 2026-05-08.
    # Backbone is an uninterrupted thin rail; features sit above
    # (forward) or below (reverse) with a vertical stem connecting
    # block → label. The legacy "centered" layout (single-lane,
    # arrow-through-backbone) was dropped per user request — flag
    # reads better for plasmids with many overlapping features.
    # Reactive kept as `str` for back-compat with persisted settings
    # files that still carry the field; only "flag" is honoured.
    _linear_layout:    reactive[str]   = reactive("flag")

    # ── Messages ───────────────────────────────────────────────────────────────

    class FeatureSelected(Message):
        def __init__(self, idx: int, feat_dict: dict | None, bp: int = -1,
                      *, shift: bool = False):
            self.idx       = idx
            self.feat_dict = feat_dict
            self.bp        = bp   # bp at click point, or -1 if unknown
            # Shift+click on the map → extend the seq-panel selection
            # from the currently-selected feature to this one. Honoured
            # by `PlasmidApp._map_feat_selected_impl`. Click-order
            # convention: anchor stays the originally-selected feature;
            # subsequent shift+clicks redefine the END of the span only.
            self.shift     = bool(shift)
            super().__init__()

    class OriginChanged(Message):
        """Emitted whenever `origin_bp` changes (rotation, reset, or
        Alt+O set-origin-to-feature). The App listens and cascades the
        new origin to the FeatureSidebar (re-sort) and SequencePanel
        (re-render with the rotated origin). Carries `total_bp` so
        receivers don't need to re-query the record's length."""
        def __init__(self, origin_bp: int, total_bp: int):
            self.origin_bp = int(origin_bp)
            self.total_bp  = int(total_bp)
            super().__init__()

    # ── Lifecycle ──────────────────────────────────────────────────────────────

    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.record  = None
        self._feats:          list[dict] = []
        self._restr_feats:    list[dict] = []   # restriction site overlay
        # Linear-view alignment overlay — list of dicts owned by the
        # App (PlasmidApp._alignments) and mirrored here for the
        # renderer. Each entry carries `name`, `segments` (the
        # precomputed `_alignment_to_target_segments` output),
        # `aligned_q/t`, `target_record` (for click drill-in to
        # AlignmentScreen), `result` (the full `_pairwise_align`
        # dict), and `t_lo`/`t_hi` (precomputed extents for lane
        # packing). Empty unless the user has registered alignments
        # via `PlasmidsaurusAlignModal` / Alt+A multi-align / inline
        # diff.
        self._alignments:     list[dict] = []
        self._total:          int  = 0
        self._show_connectors: bool = False
        # Per-frame populated by `_draw_linear_flag` so on_click can
        # match a click against a rendered alignment row. Schema mirrors
        # `_label_bboxes`: (cx0, cx1, row, align_idx).
        self._align_bboxes:    list[tuple[int, int, int, int]] = []
        # Currently-selected alignment row (reverse-style highlight),
        # -1 = none. Mirrors `selected_idx` for features.
        self._selected_align_idx: int = -1

    def on_mount(self) -> None:
        detected = _detect_char_aspect()
        if detected != self._aspect:
            self._aspect = detected

    def set_alignments(self, alignments: "list[dict]") -> None:
        """Replace the alignment overlay list and trigger a redraw.

        Called by PlasmidApp's `_register_alignment` / `_clear_alignments`
        helpers after the app's `_alignments` mutates. Shallow-copies
        the list so a downstream caller can keep mutating the original
        without flicker; dict payloads are shared (deepcopy would be
        gratuitous — entries are write-once after registration).
        """
        self._alignments = list(alignments)
        # Clear any selection that no longer references a valid row —
        # the bbox list will be repopulated by the next render pass.
        if self._selected_align_idx >= len(self._alignments):
            self._selected_align_idx = -1
        self._align_bboxes = []
        self.refresh()

    def load_record(self, record) -> None:
        self.record       = record
        self._total       = len(record.seq)
        self.origin_bp    = 0
        self.selected_idx = -1
        self._feats       = self._parse(record)
        # Sorted-by-start index: lets `_draw_linear` skip features
        # outside the visible bp window in O(log n + visible_count)
        # via bisect, instead of iterating every feature on every
        # zoom / pan / refresh. Negligible cost on small plasmids
        # (~50 features); decisive on multi-thousand-feature WGS
        # contigs where the linear panner used to chug.
        self._feats_by_start = sorted(
            range(len(self._feats)),
            key=lambda i: self._feats[i]["start"],
        )
        # Pre-extracted starts in `_feats_by_start` order so the linear
        # draw paths can `bisect_right` directly without rebuilding the
        # list every render frame. On dense plasmids that comprehension
        # was the per-frame O(F) tax; this drops it to O(1).
        self._feats_starts_sorted = [
            self._feats[i]["start"] for i in self._feats_by_start
        ]
        self._restr_feats = []
        # Per-plasmid persisted map-view preference takes precedence over
        # topology default. `_tui_map_mode` is stashed by `_library_load`
        # (and the Plasmidsaurus alignment flow) from the library entry's
        # `map_mode` field. Falls back to the GenBank `topology`
        # annotation when the entry has no stored preference — circular
        # plasmids open in circular, true linear records (PCR products,
        # sequencing fragments, partial maps) open in linear. Missing /
        # unknown values fall back to circular since that's the common
        # case for this app's primary user. Within a session the user
        # can always toggle with `v`; the toggle persists the new
        # preference into the library entry so it sticks across reloads.
        stashed_mode = ""
        try:
            stashed_mode = str(getattr(record, "_tui_map_mode", "") or "").lower()
        except Exception:
            stashed_mode = ""
        if stashed_mode in ("linear", "circular"):
            self._map_mode = stashed_mode
        else:
            topology = ""
            try:
                topology = (record.annotations or {}).get("topology", "") or ""
            except Exception:
                pass
            self._map_mode = "linear" if str(topology).lower() == "linear" else "circular"
        # Auto-fog: very long records open zoomed in so labels / arrows
        # remain readable. Below the threshold, default to whole-record
        # view (zoom=1.0). User can `0` to reset or `-` to zoom out.
        self._linear_offset_bp = 0
        if self._total > self._LINEAR_LARGE_BP:
            target_visible = self._LINEAR_LARGE_TARGET_BP
            self._linear_zoom = max(
                self._LINEAR_MIN_ZOOM,
                min(self._LINEAR_MAX_ZOOM,
                     self._total / max(1, target_visible)),
            )
        else:
            self._linear_zoom = 1.0
        # Click-target bboxes for feature labels — rebuilt every
        # `_draw` / `_draw_linear` call. Each entry is
        # `(x0, x1, y, feat_idx)`. `_feat_at` / `_feat_at_linear`
        # check this list before falling through to the arc / bar
        # geometry so a click on a label routes to the same feature
        # the label points at.
        self._label_bboxes: list = []
        self.refresh()

    def on_mouse_move(self, event: MouseMove) -> None:
        """Update the widget's hover tooltip with the feature under the
        cursor. Gated by the user's Settings → 'Show feature hover
        tooltips' toggle so users who find the popup distracting can
        switch it off without code changes.

        Tooltip text is built from the in-memory feat dict (type +
        label + bp range + strand) — cheap, no SeqRecord lookup. When
        the cursor isn't over a feature, the tooltip is cleared so
        Textual hides the popup.
        """
        try:
            app = self.app
        except Exception:
            return
        if not getattr(app, "_show_feature_tooltips", True):
            if self.tooltip is not None:
                self.tooltip = None
            return
        if not self.record or not self._feats:
            if self.tooltip is not None:
                self.tooltip = None
            return
        if self._map_mode == "linear":
            idx, _bp = self._feat_at_linear(event.x, event.y)
        else:
            idx, _bp = self._feat_at(event.x, event.y)
        if idx < 0 or idx >= len(self._feats):
            if self.tooltip is not None:
                self.tooltip = None
            return
        new = _format_feat_tooltip(self._feats[idx], self._total)
        # Avoid spamming reactive churn with identical writes.
        if self.tooltip != new:
            self.tooltip = new

    def _parse(self, record) -> list[dict]:
        feats = []
        # Import once outside the loop to avoid repeated import work.
        try:
            from Bio.SeqFeature import CompoundLocation
        except ImportError:
            CompoundLocation = None
        # Counters the caller can inspect after load_record() to decide
        # whether to notify the user.
        self._n_flattened   = 0
        self._n_skipped     = 0
        self._n_clamped     = 0
        total = len(record.seq) if getattr(record, "seq", None) is not None else 0
        for feat in record.features:
            if feat.type in ("source",):
                continue
            # Biopython's UnknownPosition / BetweenPosition can't be cast to int.
            # Skip such features with a log entry rather than crashing the whole
            # import. Compound locations with fuzzy endpoints (e.g. `<100..200`)
            # ARE castable, so this only catches genuinely unknown coords.
            try:
                start = int(feat.location.start)
                end   = int(feat.location.end)
            except (TypeError, ValueError):
                self._n_skipped += 1
                _log.warning(
                    "Skipped feature %s with non-integer coords (type=%s)",
                    _feat_label(feat), feat.type,
                )
                continue
            strand = getattr(feat.location, "strand", 1) or 1
            feat_exons: "list[tuple[int, int]] | None" = None

            # Compound / joined locations need special handling:
            #   * parts that are CONTIGUOUS (each part.end == next.start):
            #     not really split — CommercialSaaS emits these for some
            #     annotation internals; treat as a single plain feature
            #     from [first.start, last.end) with no "flattened" warning
            #     because no information is lost.
            #   * join(450..500, 1..50) on a 500 bp seq → WRAPPING feature;
            #     rebuild as start=450, end=50 (end < start) so the existing
            #     _bp_in / wrap-midpoint machinery renders the correct arc.
            #   * join(100..200, 300..400) on a 500 bp seq (truly split,
            #     e.g. exons of an mRNA) → flatten to 100..400 + warn.
            is_compound = (CompoundLocation is not None
                           and isinstance(feat.location, CompoundLocation))
            if is_compound:
                parts = sorted(
                    feat.location.parts,
                    key=lambda p: int(p.start),
                )
                is_contiguous = all(
                    int(parts[i].end) == int(parts[i + 1].start)
                    for i in range(len(parts) - 1)
                )
                is_wrap = (
                    total > 0 and len(parts) == 2
                    and int(parts[0].start) == 0
                    and int(parts[-1].end) == total
                    and int(parts[0].end) < int(parts[-1].start)
                )
                if is_wrap:
                    # Origin-spanning wrap: head at [0, parts[0].end),
                    # tail at [parts[-1].start, total). Represent as
                    # start=tail, end=head so end<start signals wrap.
                    start = int(parts[-1].start)
                    end   = int(parts[0].end)
                    _log.info(
                        "Detected wrap feature %s (%d..%d → wraps origin)",
                        _feat_label(feat), start, end,
                    )
                elif is_contiguous:
                    # Adjacent sub-parts — outer bounds ARE the real span,
                    # no info lost, no need to warn the user.
                    pass
                else:
                    self._n_flattened += 1
                    _log.info(
                        "Flattened compound feature %s (%d..%d) to outer bounds",
                        _feat_label(feat), start, end,
                    )
                # Intron-aware splice info (issue #9 from Cory Tobin).
                # For a multi-exon CDS like `join(100..200, 400..500)`,
                # stash the exon list so `_translate_cds` and
                # `_paint_cds_aa` can splice out introns before reading
                # the codon table. Without this, the AA letters past the
                # intron come out in the wrong reading frame whenever
                # the intron length isn't a multiple of 3.
                #
                # Skipped for origin wraps (the existing wrap-encoding
                # already encodes the two pieces in `start`/`end`) and
                # for contiguous compound (no information is lost in
                # flattening). Captured as half-open `(s, e)` tuples in
                # ascending genomic order; strand handling happens at
                # read time inside `_cds_aa_list`.
                if not is_wrap and not is_contiguous and len(parts) >= 2:
                    feat_exons = [
                        (int(p.start), int(p.end)) for p in parts
                    ]

            # Clamp coords that exceed the sequence length — rendering
            # math assumes start, end ∈ [0, total].
            if total > 0:
                clamped_start = max(0, min(start, total))
                clamped_end   = max(0, min(end,   total))
                if (clamped_start, clamped_end) != (start, end):
                    self._n_clamped += 1
                    _log.warning(
                        "Clamped feature %s coords (%d..%d → %d..%d) to "
                        "sequence length %d",
                        _feat_label(feat), start, end,
                        clamped_start, clamped_end, total,
                    )
                    start, end = clamped_start, clamped_end

            idx    = len(feats)
            # Colour resolution order:
            #   1. Explicit qualifier (`ApEinfo_fwdcolor` /
            #      `ApEinfo_revcolor` / `color`) — the cross-tool
            #      convention written by ApE, Geneious, and the
            #      CommercialSaaS .dna augment path
            #      (`_augment_dna_record_from_packets`). Preserves the
            #      colour the user set in the source editor.
            #   2. Deterministic fallback from `_FEATURE_PALETTE`
            #      indexed by feature position — only used for records
            #      that ship no colour info at all (legacy GenBank
            #      fetches, freshly-typed plasmids).
            qual_color = ""
            for k in ("ApEinfo_fwdcolor", "ApEinfo_revcolor", "color"):
                vals = feat.qualifiers.get(k, [])
                if vals:
                    c = str(vals[0]).strip()
                    if c.startswith("#") and len(c) in (4, 7):
                        qual_color = c
                        break
            new_feat: dict = {
                "type":   feat.type,
                "start":  start,
                "end":    end,
                "strand": strand,
                "color":  qual_color or _FEATURE_PALETTE[idx % len(_FEATURE_PALETTE)],
                "label":  _feat_label(feat),
            }
            if feat_exons is not None:
                new_feat["_exons"] = feat_exons
            # GenBank /codon_start qualifier (1/2/3, default 1). Stamped on
            # CDS features so `_translate_cds` / `_cds_aa_list` / the AA-
            # click handler / Ctrl+C protein copy honour the reading frame
            # of partial CDSes (common on NCBI fetches). Pre-2026-05-11
            # this was silently ignored everywhere except GFF3 export,
            # frame-shifting every AA past the leading partial codon.
            if feat.type.upper() == "CDS":
                try:
                    cs_raw = int(
                        (feat.qualifiers.get("codon_start", ["1"]) or ["1"])[0]
                    )
                except (TypeError, ValueError, IndexError):
                    cs_raw = 1
                if cs_raw in (2, 3):
                    new_feat["codon_start"] = cs_raw
            # ── Partial-binding primer detection ────────────────────
            # When a `primer_bind` feature carries a `/primer_seq`
            # qualifier (set by `_add_selected_to_map` since 0.5.9),
            # we know the primer's full 5'→3' bases. The bound region
            # is `[start, end)` (where the primer pairs with the
            # template); the difference between primer-length and
            # bound-length is the **5' flap**. The flap is rendered
            # by the seq panel as a floating coloured segment one
            # row away from the bound bar — see `_render_chunk`.
            #
            # Wrap-aware: a binding that crosses the origin has
            # `end < start`; the bound length is `_feat_len(start, end, total)`.
            #
            # The flap is positioned to the LEFT (fwd primer) or
            # RIGHT (rev primer) of the bound region in template
            # coords, so the flap's column range can be negative or
            # exceed `total`. Renderer clips per-chunk.
            if feat.type == "primer_bind":
                primer_seq_q = feat.qualifiers.get("primer_seq")
                primer_seq = ""
                if isinstance(primer_seq_q, list) and primer_seq_q:
                    primer_seq = str(primer_seq_q[0]).strip().upper()
                if primer_seq:
                    bound_len = _feat_len(start, end, total) or 0
                    flap_len  = max(0, len(primer_seq) - bound_len)
                    # `_primer_seq` + `_bound_len` are always stamped
                    # so the seq panel can paint primer bases inline
                    # with the strand even for full-binding primers
                    # (no flap → no flap row, but bound bar still
                    # shows the primer sequence in its cells).
                    new_feat["_primer_seq"] = primer_seq
                    new_feat["_bound_len"]  = bound_len
                    # Weak-primer flag: bound region shorter than the
                    # user-set Min primer binding threshold triggers a
                    # yellow ⚠ on the strand-3'-end arrow in the seq
                    # panel + a tooltip line. Threshold read at parse
                    # time so toggling Settings → Min primer binding
                    # and re-parsing refreshes the stamps. Defensive
                    # `getattr` chain so a standalone parse (tests, no
                    # mounted App) still works on the default 15 bp.
                    threshold = getattr(
                        getattr(self, "app", None),
                        "_min_primer_binding", 15,
                    )
                    if isinstance(threshold, int) and 0 < bound_len < threshold:
                        new_feat["_weak_primer"] = True
                    if flap_len > 0:
                        new_feat["_flap_len"] = flap_len
                        # Top-strand-oriented flap bases (so they
                        # read inline with the strand below):
                        # forward primer flap = primer_seq[:flap_len];
                        # reverse primer flap = RC of primer_seq[:flap_len]
                        # (the 5' end of the rev primer is on the
                        # right side of the bound region in top-
                        # strand orientation).
                        if strand >= 0:
                            new_feat["_flap_bases"] = primer_seq[:flap_len]
                            new_feat["_flap_start"] = start - flap_len
                            new_feat["_flap_end"]   = start
                        else:
                            new_feat["_flap_bases"] = _rc(primer_seq[:flap_len])
                            new_feat["_flap_start"] = end
                            new_feat["_flap_end"]   = end + flap_len
            feats.append(new_feat)
        return feats

    # ── Actions ────────────────────────────────────────────────────────────────

    def _step(self, coarse: bool = False) -> int:
        if not self._total:
            return 1
        return max(1, self._total // (10 if coarse else 200))

    def action_rotate_cw(self):
        if not self._total:
            return
        if self._map_mode == "linear":
            self._linear_pan(+1)
            return
        self.origin_bp = (self.origin_bp - self._step()) % self._total

    def action_rotate_ccw(self):
        if not self._total:
            return
        if self._map_mode == "linear":
            self._linear_pan(-1)
            return
        self.origin_bp = (self.origin_bp + self._step()) % self._total

    def action_rotate_cw_lg(self):
        if not self._total:
            return
        if self._map_mode == "linear":
            self._linear_pan(+10)
            return
        self.origin_bp = (self.origin_bp - self._step(True)) % self._total

    def action_rotate_ccw_lg(self):
        if not self._total:
            return
        if self._map_mode == "linear":
            self._linear_pan(-10)
            return
        self.origin_bp = (self.origin_bp + self._step(True)) % self._total

    def action_reset_origin(self):
        if self._map_mode == "linear":
            self.action_linear_reset_zoom()
            return
        self.origin_bp = 0

    def action_set_origin_to_selected(self) -> None:
        """Alt+O — re-anchor the display origin at the currently
        selected feature's start. Mirror of `action_reset_origin` but
        for the highlighted feature instead of bp 0. Cascades to the
        sidebar (re-sort) and seq panel (rotate display) via the
        ``OriginChanged`` watcher.

        No-op when nothing is selected, when the feature has no usable
        ``start``, or in linear-view mode (rotation only makes sense
        on a circular topology). Notifies in the linear case so the
        user knows why the keystroke didn't take.
        """
        if not self._total or self._map_mode == "linear":
            try:
                self.app.notify(
                    "Set origin only works on circular maps "
                    "(press 'v' to switch).",
                    severity="information", timeout=3,
                )
            except Exception:
                pass
            return
        idx = self.selected_idx
        if idx < 0 or idx >= len(self._feats):
            try:
                self.app.notify(
                    "Pick a feature first — Alt+O re-anchors the "
                    "origin at the highlighted feature's start.",
                    severity="information", timeout=3,
                )
            except Exception:
                pass
            return
        f = self._feats[idx]
        try:
            new_origin = int(f.get("start", 0)) % self._total
        except (TypeError, ValueError):
            return
        self.origin_bp = new_origin

    def watch_origin_bp(self, old: int, new: int) -> None:
        """Cascade rotation to the sidebar + seq panel via the
        ``OriginChanged`` message. Textual fires this watcher whenever
        ``self.origin_bp`` is reassigned (rotation actions, set-origin-
        to-feature, reset). The widget itself already re-renders on
        reactive change; this watcher only adds the cross-panel sync
        so the feature list reorders + sequence viewer shifts to put
        the new origin at the top.

        ``old != new`` guard skips the synthetic initial fire (Textual
        fires once on first read with `old == new`)."""
        if old == new:
            return
        try:
            self.post_message(self.OriginChanged(int(new), int(self._total)))
        except Exception:
            pass

    # ── Linear-view zoom + pan ─────────────────────────────────────────────
    # Zoom factor 1.0 = the whole record fits in the visible width.
    # Each `+`/`=` press multiplies the zoom by 1.5; `-` divides.
    # Capped at `_LINEAR_MAX_ZOOM` so the user can't end up with <2 bp
    # visible (the renderer becomes meaningless below that).
    _LINEAR_ZOOM_STEP = 1.5
    _LINEAR_MAX_ZOOM  = 1_000_000.0   # ~1 bp/col on a 1 Mbp record
    _LINEAR_MIN_ZOOM  = 1.0           # full record
    # Records longer than this auto-zoom on load so the user gets a
    # readable slice (~50 kb visible) rather than an unreadable
    # everything-at-once strip.
    _LINEAR_LARGE_BP        = 100_000
    _LINEAR_LARGE_TARGET_BP = 50_000

    def action_linear_zoom_in(self) -> None:
        if self._map_mode != "linear" or not self._total:
            return
        new = min(self._LINEAR_MAX_ZOOM,
                   self._linear_zoom * self._LINEAR_ZOOM_STEP)
        self._set_linear_zoom(new, anchor_center=True)

    def action_linear_zoom_out(self) -> None:
        if self._map_mode != "linear" or not self._total:
            return
        new = max(self._LINEAR_MIN_ZOOM,
                   self._linear_zoom / self._LINEAR_ZOOM_STEP)
        self._set_linear_zoom(new, anchor_center=True)

    def action_linear_reset_zoom(self) -> None:
        if not self._total:
            return
        self._linear_zoom      = 1.0
        self._linear_offset_bp = 0

    def _set_linear_zoom(self, zoom: float,
                          *, anchor_center: bool = False) -> None:
        """Apply a new zoom level. With `anchor_center=True`, the
        viewport's CENTER bp stays put — feels like the user zoomed
        toward the middle of what they were looking at, rather than
        snapping back to the origin."""
        if not self._total:
            return
        zoom = max(self._LINEAR_MIN_ZOOM,
                    min(self._LINEAR_MAX_ZOOM, zoom))
        # Compute the current center, then re-center after zoom.
        view_s, view_e = self._linear_view_range()
        center_bp = (view_s + view_e) // 2 if anchor_center else view_s
        self._linear_zoom = zoom
        # Recompute offset around the same center bp.
        new_visible = max(1, int(self._total / zoom))
        new_offset  = max(0, min(self._total - new_visible,
                                    center_bp - new_visible // 2))
        self._linear_offset_bp = new_offset

    def _linear_pan(self, direction: int) -> None:
        """Pan the linear viewport. `direction` is in units of
        ``visible_bp / 8`` so `[`/`]` step a sane amount at any zoom
        level. Clamped to record bounds."""
        if not self._total:
            return
        view_s, view_e = self._linear_view_range()
        visible = max(1, view_e - view_s)
        step    = max(1, visible // 8)
        new_off = max(0, min(self._total - visible,
                                self._linear_offset_bp + direction * step))
        self._linear_offset_bp = new_off

    def _linear_view_range(self) -> "tuple[int, int]":
        """Return ``(view_start_bp, view_end_bp)`` — the half-open
        bp range currently visible. Always within `[0, total]`. Empty
        record returns ``(0, 0)``."""
        if not self._total:
            return (0, 0)
        zoom    = max(self._LINEAR_MIN_ZOOM, float(self._linear_zoom or 1.0))
        visible = max(1, int(self._total / zoom))
        offset  = max(0, min(self._total - visible,
                                int(self._linear_offset_bp)))
        return (offset, offset + visible)

    def action_aspect_inc(self):
        new = round(min(5.0, self._aspect + 0.05), 3)
        if new == self._aspect:
            return
        self._aspect = new
        self.notify(f"Aspect {new:.2f}  (press , to widen)", timeout=1.5)

    def action_aspect_dec(self):
        new = round(max(0.5, self._aspect - 0.05), 3)
        if new == self._aspect:
            return
        self._aspect = new
        self.notify(f"Aspect {new:.2f}  (press . to heighten)", timeout=1.5)

    def action_toggle_map_view(self):
        # Linear-view alignment overlay can't be rendered on a circle —
        # the bars would have to bend around the rim and the lane stack
        # would clip wherever the rotation lands. Refuse to flip back
        # to circular while any alignment row is registered; the user
        # must clear them (Alt+Shift+A) first.
        if self._map_mode == "linear" and self._alignments:
            try:
                self.app.notify(
                    "Clear alignments (Alt+Shift+A) before switching to "
                    "circular view.",
                    severity="warning", timeout=4,
                )
            except Exception:
                pass
            return
        self._map_mode = "linear" if self._map_mode == "circular" else "circular"
        # Persist the user's choice on the active library entry so a
        # later reload defaults to the same view. No-op when the
        # currently-loaded plasmid isn't tracked in the library.
        try:
            persist = getattr(self.app, "_persist_map_mode_for_active", None)
            if callable(persist):
                persist(self._map_mode)
        except Exception:
            _log.exception("toggle_map_view: persist failed")
        self.refresh()

    def select_feature(self, idx: int) -> None:
        self.selected_idx = idx
        self.refresh()

    # ── Mouse ──────────────────────────────────────────────────────────────────

    def on_mouse_scroll_up(self, event: MouseScrollUp):
        """Mouse-wheel up. Default = rotate clockwise (circular view).
        In linear mode, Ctrl+scroll zooms in and Shift+scroll pans
        left — both flagged by Koeng101 in issue #5 as muscle memory
        from the popular commercial plasmid editor. Plain scroll in
        linear mode falls through to
        the rotate action (which is a no-op for linear records, so
        the default is harmless)."""
        if self._map_mode == "linear":
            if getattr(event, "ctrl", False):
                self.action_linear_zoom_in()
                event.stop()
                return
            if getattr(event, "shift", False):
                self._linear_pan(-1)
                self.refresh()
                event.stop()
                return
        self.action_rotate_cw()

    def on_mouse_scroll_down(self, event: MouseScrollDown):
        """Mouse-wheel down. Default = rotate counter-clockwise. In
        linear mode, Ctrl+scroll zooms out and Shift+scroll pans
        right (issue #5)."""
        if self._map_mode == "linear":
            if getattr(event, "ctrl", False):
                self.action_linear_zoom_out()
                event.stop()
                return
            if getattr(event, "shift", False):
                self._linear_pan(1)
                self.refresh()
                event.stop()
                return
        self.action_rotate_ccw()

    def _label_at(self, x: int, y: int) -> int:
        """Return the feature index whose label bbox covers the
        click cell (x, y), or -1 if no label was hit. Bboxes are
        populated in `_draw` / `_draw_linear` per render pass."""
        for x0, x1, ly, idx in getattr(self, "_label_bboxes", ()):
            if y == ly and x0 <= x <= x1:
                return idx
        return -1

    def _feat_at(self, x: int, y: int) -> tuple[int, int]:
        """Return (feature_idx, click_bp) at terminal cell (x, y), or (-1, -1).

        Nested-feature handling: when several features cover the click
        bp (e.g. a misc_feature inside a CDS), pick the **smallest
        enclosing** one. First-match-wins would otherwise route every
        nested click to whichever feature appears earliest in
        ``self._feats``, surprising users who clicked the inner
        annotation. Mirrors `PlasmidApp._seq_click_impl`'s smallest-
        span fallback so map and seq-panel feature picks resolve the
        same feature for the same bp.
        """
        if not self.record or not self._total:
            return -1, -1
        # Label-first: a click that hits a feature's text label
        # routes to that exact feature, with `bp` set to its 5' end
        # so the App's seq-panel scroll lands at the feature's start.
        # Without this, label clicks would fall outside the arc-
        # detection radius and resolve as a backbone click.
        idx = self._label_at(x, y)
        if idx >= 0:
            f = self._feats[idx]
            return idx, int(f["start"])
        w, h = self.size.width, self.size.height
        cx, cy, rx, ry = self._geometry(w, h)
        if rx == 0 or ry == 0:
            return -1, -1
        dc_n = (x - cx) / rx
        dr_n = (y - cy) / ry
        r_norm = math.sqrt(dc_n ** 2 + dr_n ** 2)
        if r_norm < 0.75 or r_norm > 1.35:
            return -1, -1
        angle = math.atan2(dr_n, dc_n)
        angle_norm = (angle + math.pi / 2) % (2 * math.pi)
        bp = int(self.origin_bp + self._total * angle_norm / (2 * math.pi)) % self._total
        best_idx = self._smallest_enclosing_feature(bp)
        return (best_idx, bp) if best_idx >= 0 else (-1, -1)

    def _smallest_enclosing_feature(self, bp: int) -> int:
        """Return the index of the smallest-span feature whose span
        contains `bp`, or -1 if none. Used by both `_feat_at` (circular)
        and `_feat_at_linear` to resolve nested-feature clicks to the
        inner annotation.

        Perf: uses the bisect index `_feats_starts_sorted` to narrow
        non-wrap candidates from O(N) to O(log N + matches), which is
        the hover-frame budget on WGS contigs with 1000+ features.
        Wrap features (`end < start`) are checked in a second pass —
        there are usually 0–2 per record so the cost is bounded.
        """
        feats = self._feats
        if not feats:
            return -1
        starts = getattr(self, "_feats_starts_sorted", None)
        sorted_idx = getattr(self, "_feats_by_start", None)
        best_idx = -1
        best_span = float("inf")
        # Fast path: bisect over sorted starts to find features with
        # start <= bp, then iterate backwards while end > bp.
        if starts is not None and sorted_idx is not None:
            import bisect as _bs
            upper = _bs.bisect_right(starts, bp)
            for k in range(upper - 1, -1, -1):
                i = sorted_idx[k]
                f = feats[i]
                sb = f["start"]
                eb = f["end"]
                # Linear (non-wrap) features: bp must be in [sb, eb).
                if eb >= sb:
                    if bp < sb:
                        # bisect should have prevented this, but
                        # belt-and-braces — and an early break
                        # would be wrong because the sort is by
                        # start, not end, so we just continue.
                        continue
                    if eb <= bp:
                        continue
                    span = eb - sb
                    if span < best_span:
                        best_span = span
                        best_idx = i
                # Wrap features handled in the second pass below.
            # Second pass: wrap features (`end < start`). Caller's
            # `_bp_in` knows how to test these; iterate only wrap
            # features by scanning the full list once. On a typical
            # plasmid this is 0 or 1 features.
            for i, f in enumerate(feats):
                sb = f["start"]
                eb = f["end"]
                if eb >= sb:
                    continue  # not a wrap
                if not self._bp_in(bp, f):
                    continue
                span = _feat_len(sb, eb, self._total) or 0
                if span < best_span:
                    best_span = span
                    best_idx = i
            return best_idx
        # Fallback: index not built (early in load_record before
        # `_feats_by_start` populates). Linear scan.
        for i, f in enumerate(feats):
            if not self._bp_in(bp, f):
                continue
            span = _feat_len(f["start"], f["end"], self._total) or 0
            if span < best_span:
                best_span = span
                best_idx = i
        return best_idx

    def _align_at_click(self, x: int, y: int) -> int:
        """Linear-view alignment hit-test. Returns the alignment index
        under (x, y) or -1 if none. Mirrors the `_label_bboxes` lookup
        pattern used for features. Circular mode never paints alignment
        rows, so we short-circuit there."""
        if self._map_mode != "linear":
            return -1
        for cx0, cx1, row, ai in self._align_bboxes:
            if row == y and cx0 <= x <= cx1:
                return ai
        return -1

    def on_click(self, event: Click):
        if not self.record:
            return
        if self._map_mode == "linear":
            # Alignment lane hit-test runs BEFORE the feature lookup —
            # alignment rows sit in their own band below the rev features
            # and a click should open the alignment (AlignmentScreen
            # drill-in), not select whatever feature happens to share
            # the column. Bbox list is repopulated by
            # `_draw_alignment_band` every render so it always reflects
            # the current view.
            ai = self._align_at_click(event.x, event.y)
            if ai >= 0:
                try:
                    align = self._alignments[ai]
                except (IndexError, KeyError):
                    return
                self._selected_align_idx = ai
                self.refresh()
                # Defensive None-guard: AlignmentScreen._body_text
                # dereferences `target_record.seq` and `.features`, so
                # a malformed entry would crash the modal push. Workers
                # currently never produce a None target_record, but if
                # the schema ever drifts (e.g., persistence path that
                # loses the record), surface a notify instead.
                target_record = align.get("target_record")
                result = align.get("result") or {}
                if target_record is None or not result:
                    try:
                        self.app.notify(
                            "Alignment entry is incomplete — can't open "
                            "detail view. Re-run the alignment.",
                            severity="warning", timeout=4,
                        )
                    except Exception:
                        pass
                    return
                try:
                    self.app.push_screen(AlignmentScreen(
                        query_label=align.get("query_label", "query"),
                        target_label=align.get("target_label", "target"),
                        target_record=target_record,
                        result=result,
                    ))
                except Exception:
                    _log.exception(
                        "alignment lane click: push_screen failed"
                    )
                return
            idx, bp = self._feat_at_linear(event.x, event.y)
        else:
            idx, bp = self._feat_at(event.x, event.y)
        # Treat shift OR ctrl as the "extend selection" modifier. Most
        # terminals (xterm, macOS Terminal.app, stock GNOME Terminal)
        # intercept shift+click for native text-selection so the click
        # never reaches the app; ctrl+click is the most reliable
        # cross-terminal alternative. Both are honoured upstream by
        # `PlasmidApp._extend_selection_to`.
        ext = bool(getattr(event, "shift", False)
                    or getattr(event, "ctrl",  False))
        if not ext:
            self.selected_idx = idx
        f = self._feats[idx] if idx >= 0 else None
        # Surface raw modifier state so the App's click-debug toggle
        # (Alt+M) can echo it for users diagnosing terminal-eats-shift
        # issues.
        try:
            # `_echo_click_modifiers` is a PlasmidApp method; Pyright
            # sees the base App[Unknown] and complains. getattr keeps
            # the call defensive AND silences the type error.
            echo = getattr(self.app, "_echo_click_modifiers", None)
            if callable(echo):
                echo("plasmid map", event)
        except Exception:
            pass
        _log_event(
            "map.click", mode=self._map_mode,
            x=event.x, y=event.y,
            idx=idx, bp=bp,
            shift=bool(getattr(event, "shift", False)),
            ctrl=bool(getattr(event, "ctrl", False)),
            extend=ext,
            feat=(f or {}).get("label") if f else None,
            label_hit=(idx >= 0 and self._label_at(event.x, event.y) == idx),
        )
        self.post_message(self.FeatureSelected(idx, f, bp, shift=ext))

    def _bp_in(self, bp: int, f: dict) -> bool:
        s, e = f["start"], f["end"]
        return (s <= bp < e) if e >= s else (bp >= s or bp < e)

    # ── Geometry ───────────────────────────────────────────────────────────────

    def _geometry(self, w: int, h: int) -> tuple[int, int, int, int]:
        cx     = w // 2
        cy     = h // 2
        aspect = self._aspect
        rx_from_w = cx - 16
        rx_from_h = int((cy - 3) * aspect)
        rx = max(8, min(rx_from_w, rx_from_h))
        ry = max(4, round(rx / aspect))
        return cx, cy, rx, ry

    def _angle_to_xy(self, angle: float, cx: int, cy: int,
                     rx: int, ry: int, dr: int = 0) -> tuple[int, int]:
        scale = ry / rx if rx else 0.5
        x = round(cx + (rx + dr) * math.cos(angle))
        y = round(cy + (ry + dr * scale) * math.sin(angle))
        return x, y

    def _bp_to_angle(self, bp: int) -> float:
        return 2 * math.pi * ((bp - self.origin_bp) % self._total) / self._total - math.pi / 2

    # ── Render ─────────────────────────────────────────────────────────────────

    # (w, h, origin_bp, selected_idx, _aspect, n_feats, n_restr, ...) → Text
    # NOTE: do NOT rename this to `_render_cache` — Textual.Widget has its
    # own internal `_render_cache` attribute (a _RenderCache dataclass for
    # strip caching) and the two would collide, producing confusing bugs
    # when either side's cache is inspected.
    _draw_cache: "tuple | None" = None

    def render(self) -> Text:
        if not self.record:
            return Text(
                "\n\n   No record loaded.\n"
                "   Press  f  to fetch from GenBank (e.g. L09137 for pUC19)\n"
                "   Press  o  to open a local .gb file\n",
                style="dim italic",
            )
        w, h = self.size.width, self.size.height
        if w < 30 or h < 14:
            return Text(f"  Window too small ({w}×{h})", style="dim red")
        key = (w, h, self.origin_bp, self.selected_idx, self._aspect,
               id(self._feats), id(self._restr_feats), self._map_mode,
               self._show_connectors, self.record.name,
               self._linear_zoom, self._linear_offset_bp, self._linear_layout)
        if self._draw_cache and self._draw_cache[0] == key:
            return self._draw_cache[1]
        result = self._draw_linear(w, h) if self._map_mode == "linear" else self._draw(w, h)
        self._draw_cache = (key, result)
        return result

    def _draw(self, w: int, h: int) -> Text:
        canvas = _Canvas(w, h)
        bc     = _BrailleCanvas(w, h)

        total  = self._total
        cx, cy, rx, ry = self._geometry(w, h)

        _ry_rx   = ry / rx if rx else 0.5
        TWO_PI   = 2 * math.pi
        HALF_PI  = math.pi / 2
        # Braille-space offsets for the circle centre
        cx2, cy4 = cx * 2, cy * 4
        rx2, ry4 = rx * 2, ry * 4

        # Enough steps to fill every braille column (2 dots/cell → circumference
        # in braille-px ≈ 2π*rx*2; ×2 safety margin → 4π*rx ≈ 13*rx)
        n_steps = max(360, int(13 * rx))

        # Local refs avoid repeated attribute lookups in hot loops
        bc_bits   = bc._bits
        bc_colors = bc._colors
        bc_prio   = bc._prio
        bc_cols   = bc.cols
        bc_rows   = bc.rows
        # Flat braille dot-bit lookup: index = (py & 3) << 1 | (px & 1)
        _BIT = (0, 3, 1, 4, 2, 5, 6, 7)

        def bp2a(bp: int) -> float:
            return self._bp_to_angle(bp)

        def a2xy(angle: float, dr: int = 0) -> tuple[int, int]:
            return self._angle_to_xy(angle, cx, cy, rx, ry, dr)

        # ── Backbone (inlined — no function call overhead) ─────────────────────
        _step_angle = TWO_PI / n_steps
        for step in range(n_steps):
            a  = step * _step_angle - HALF_PI
            px = round(cx2 + rx2 * math.cos(a))
            py = round(cy4 + ry4 * math.sin(a))
            pcol, prow = px >> 1, py >> 2
            if 0 <= pcol < bc_cols and 0 <= prow < bc_rows:
                bc_bits[prow][pcol]   |= 1 << _BIT[(py & 3) << 1 | (px & 1)]
                if bc_prio[prow][pcol] == 0:
                    bc_colors[prow][pcol] = "color(238)"
                    bc_prio[prow][pcol]   = 1

        # ── Position ticks (inside the circle) ───────────────────────────────
        # TICK_DR_MARK  — radial inset for the ┼ graduation mark
        # TICK_DR_LABEL — radial inset for the bp number label
        # Both are negative so they sit inside the backbone ring.
        # These values scale automatically with the aspect ratio (, / . keys).
        TICK_DR_MARK  = -2
        TICK_DR_LABEL = -5

        tick_int = _nice_tick(total)
        bp = 0
        while bp < total:
            angle  = bp2a(bp)
            tx, ty = a2xy(angle, dr=TICK_DR_MARK)
            canvas.put(tx, ty, "┼", "color(250)")
            label  = _format_bp(bp)
            lx, ly = a2xy(angle, dr=TICK_DR_LABEL)
            # Inside the circle: text points inward, so alignment is flipped
            # vs outside placement (right-side labels hang left, left-side hang right).
            if math.cos(angle) >= 0:
                canvas.put_text(lx - len(label) + 1, ly, label, "color(245)")
            else:
                canvas.put_text(lx, ly, label, "color(245)")
            bp += tick_int

        # ── Restriction site marks ─────────────────────────────────────────────
        # resite: draw a thin arc just outside (+) or inside (-) the backbone
        # recut:  draw a radial tick crossing the backbone at the cut position
        restr_labels: list[tuple[float, str, str]] = []
        for rf in self._restr_feats:
            color = rf["color"]
            if rf["type"] == "resite":
                dr_lo = 4 if rf["strand"] >= 0 else -5
                dr_hi = dr_lo + 1
                start_a = bp2a(rf["start"])
                end_a   = bp2a(rf["end"])
                span_a  = (end_a - start_a) % TWO_PI or TWO_PI
                arc_steps = max(4, int(span_a / TWO_PI * n_steps))
                inv_arc   = 1.0 / arc_steps if arc_steps else 1.0
                for dr_i in range(2):
                    dr     = dr_lo + (dr_hi - dr_lo) * dr_i
                    _rx2dr = (rx + dr) * 2
                    _ry4dr = (ry + dr * _ry_rx) * 4
                    for s in range(arc_steps + 1):
                        a  = start_a + s * inv_arc * span_a
                        px = round(cx2 + _rx2dr * math.cos(a))
                        py = round(cy4 + _ry4dr * math.sin(a))
                        pcol, prow = px >> 1, py >> 2
                        if 0 <= pcol < bc_cols and 0 <= prow < bc_rows:
                            bc_bits[prow][pcol]   |= 1 << _BIT[(py & 3) << 1 | (px & 1)]
                            if 1 >= bc_prio[prow][pcol]:
                                bc_colors[prow][pcol] = color
                                bc_prio[prow][pcol]   = 1
                # Collect label at midpoint
                mid_bp = (rf["start"] + rf["end"]) // 2
                restr_labels.append((bp2a(mid_bp), rf["label"], color))
            elif rf["type"] == "recut":
                # Radial tick crossing the backbone at cut position
                cut_a = bp2a(rf["start"])
                for dr in range(-1, 3):
                    tx, ty = a2xy(cut_a, dr=dr)
                    if 0 <= tx < w and 0 <= ty < h:
                        canvas.put(tx, ty, "┼" if dr == 0 else "·", color)

        # ── Features (large → small) ──────────────────────────────────────────
        feats_sorted = sorted(
            enumerate(self._feats),
            key=lambda iv: -_feat_len(iv[1]["start"], iv[1]["end"], total),
        )
        # Reset click-target bboxes for this draw pass. Filled below
        # as labels get placed; `_feat_at` reads it when the user
        # clicks anywhere outside the arc itself.
        self._label_bboxes = []
        # `(angle, label_text, color, feat_idx_or_minus_one)`. -1 idx
        # marks restriction-site labels — those don't correspond to a
        # `self._feats` entry and shouldn't be click-targets here.
        label_slots: list[tuple[float, str, str, int]] = []
        N_DR = 4   # radial samples per arc (was 6; 4 is visually identical)

        for orig_idx, f in feats_sorted:
            is_sel   = (orig_idx == self.selected_idx)
            color    = f["color"]
            style    = ("reverse " + color) if is_sel else color
            f_prio   = 3 if is_sel else 2

            start_bp, end_bp = f["start"], f["end"]
            strand           = f["strand"]
            dr_lo = 1 if strand >= 0 else -3
            dr_hi = dr_lo + 2

            start_a = bp2a(start_bp)
            end_a   = bp2a(end_bp)
            span_a  = (end_a - start_a) % TWO_PI or TWO_PI

            arc_steps = max(8, int(span_a / TWO_PI * n_steps))
            inv_arc   = 1.0 / arc_steps if arc_steps else 1.0

            # Precompute cos/sin once; reuse across all N_DR radial passes
            arc_cos = [math.cos(start_a + s * inv_arc * span_a) for s in range(arc_steps + 1)]
            arc_sin = [math.sin(start_a + s * inv_arc * span_a) for s in range(arc_steps + 1)]

            inv_ndr1 = 1.0 / max(1, N_DR - 1)
            dr_span  = dr_hi - dr_lo
            for dr_i in range(N_DR):
                dr     = dr_lo + dr_span * dr_i * inv_ndr1
                _rx2dr = (rx + dr) * 2
                _ry4dr = (ry + dr * _ry_rx) * 4
                for ca, sa in zip(arc_cos, arc_sin):
                    px   = round(cx2 + _rx2dr * ca)
                    py   = round(cy4 + _ry4dr * sa)
                    pcol = px >> 1
                    prow = py >> 2
                    if 0 <= pcol < bc_cols and 0 <= prow < bc_rows:
                        bc_bits[prow][pcol]   |= 1 << _BIT[(py & 3) << 1 | (px & 1)]
                        if f_prio >= bc_prio[prow][pcol]:
                            bc_colors[prow][pcol] = style
                            bc_prio[prow][pcol]   = f_prio

            if strand >= 0:
                tip_a, tip_tan = end_a, end_a + HALF_PI
            else:
                tip_a, tip_tan = start_a, start_a - HALF_PI
            ax, ay = a2xy(tip_a, dr=dr_lo + 1)
            canvas.put(ax, ay, _arrow_char(tip_tan), "bold " + style)

            # Arc length on a circular plasmid: ((end - start) mod total) handles
            # wrap-around (end < start) without putting the label opposite the arc.
            arc_len = (end_bp - start_bp) % total
            mid_bp  = (start_bp + arc_len // 2) % total
            label_slots.append((bp2a(mid_bp), f["label"], color, orig_idx))

        # Add restriction site labels (from resite entries only) —
        # tagged with idx=-1 so they don't appear in click bboxes.
        for angle, lbl, color in restr_labels:
            label_slots.append((angle, lbl, color, -1))

        # ── Labels: place each as close to the arc as possible ───────────────
        # Greedily try increasing dr until the label's bounding box doesn't
        # overlap any already-placed label.
        # ↓ Tune this to control how far labels sit from the arc.
        LABEL_DR_MIN = 9          # minimum radial clearance from arc edge
        dr_min = LABEL_DR_MIN
        dr_max = max(rx // 2 + 6, LABEL_DR_MIN + 10)

        # placed: dict keyed by row → list of (x0, x1) bounding boxes
        placed_by_row: dict[int, list] = {}
        final_labels: list[tuple] = []
        # (angle, lbl, color, chosen_dr, lx, ly, lbl_x0, lbl_x1, feat_idx)

        for angle, lbl, color, feat_idx in label_slots:
            on_right = math.cos(angle) >= 0
            chosen = None
            for dr in range(dr_min, dr_max + 1):
                lx, ly = a2xy(angle, dr=dr)
                if not (0 <= ly < h):
                    continue
                lbl_x0 = lx if on_right else max(0, lx - len(lbl) + 1)
                lbl_x1 = lx + len(lbl) - 1 if on_right else lx
                # Check against already-placed boxes on the same row only
                ok = True
                for bx0, bx1 in placed_by_row.get(ly, []):
                    if not (lbl_x1 < bx0 or lbl_x0 > bx1):
                        ok = False
                        break
                if ok:
                    chosen = (dr, lx, ly, lbl_x0, lbl_x1)
                    break
            if chosen is None:
                # Couldn't fit without overlap — place at max dr anyway
                lx, ly = a2xy(angle, dr=dr_max)
                lbl_x0 = lx if on_right else max(0, lx - len(lbl) + 1)
                lbl_x1 = lx + len(lbl) - 1 if on_right else lx
                chosen = (dr_max, lx, ly, lbl_x0, lbl_x1)
            dr_c, lx, ly, lbl_x0, lbl_x1 = chosen
            placed_by_row.setdefault(ly, []).append((lbl_x0, lbl_x1))
            final_labels.append(
                (angle, lbl, color, dr_c, lx, ly, lbl_x0, lbl_x1, feat_idx)
            )

        # Render
        for angle, lbl, color, dr_c, lx, ly, lbl_x0, lbl_x1, feat_idx in final_labels:
            on_right = math.cos(angle) >= 0

            # Dot just outside the arc
            dot_x, dot_y = a2xy(angle, dr=3)
            canvas.put(dot_x, dot_y, "·", color)

            # Optional connector line from dot to label
            if self._show_connectors:
                lbl_mid_x = lx + len(lbl) // 2 if on_right else lx - len(lbl) // 2
                steps = max(1, abs(lbl_mid_x - dot_x) + abs(ly - dot_y))
                for t in range(1, steps):
                    px = dot_x + (lbl_mid_x - dot_x) * t // steps
                    py = dot_y + (ly        - dot_y) * t // steps
                    if 0 <= px < w and 0 <= py < h and canvas._chars[py][px] == " ":
                        canvas.put(px, py, "·", color)

            if on_right:
                canvas.put_text(lx, ly, lbl, color)
            else:
                canvas.put_text(max(0, lx - len(lbl) + 1), ly, lbl, color)
            # Stash the painted bbox so a click on this label routes
            # to the same feature the label points at. Restriction
            # labels (feat_idx == -1) are skipped — they don't have
            # a `self._feats` entry to focus.
            if feat_idx >= 0:
                self._label_bboxes.append((lbl_x0, lbl_x1, ly, feat_idx))

        # ── Center info ───────────────────────────────────────────────────────
        # Prefer the user-typed display name (stashed by `_library_load`
        # as `_tui_display_name`) so spaces and `+` survive the round-
        # trip through the GenBank LOCUS sanitiser. Falls back to
        # `record.name` for fresh records that haven't been saved yet.
        # `render` guarantees self.record non-None before calling _draw,
        # but Pyright can't carry that across method boundaries; getattr
        # silences the false positive without changing the runtime path.
        record = self.record
        name     = (getattr(record, "_tui_display_name", None)
                    or getattr(record, "name", None)
                    or getattr(record, "id", None)
                    or "?")[:w // 3]
        size_txt = f"{total:,} bp"
        orig_txt = f"▲ {self.origin_bp:,}"
        for i, (txt, sty) in enumerate([
            (name,     "bold white"),
            (size_txt, "color(245)"),
            (orig_txt, "dim cyan"),
        ]):
            canvas.put_text(cx - len(txt) // 2, cy - 1 + i, txt, sty)

        # Top-right v-toggle hint, parallel to the linear-mode hint at
        # the equivalent corner. Discoverability for the circular ⇄
        # linear toggle — flagged by Koeng101 in issue #4. Mirrors the
        # `[ flag · v = circular ]` text the linear renderer puts in
        # the same spot.
        hint = "[ v = linear ]"
        canvas.put_text(max(0, w - len(hint) - 1), 0, hint, "dim")

        return bc.combine(canvas)

    # ── Linear map ─────────────────────────────────────────────────────────────

    # Lane geometry constants for the linear plasmid map (cell-based).
    # Per lane: 2-row arrow body + 1-row label + 1-row gap = 4 rows.
    # `_LINEAR_BAR_ROWS` = the body height (top + bottom row of the
    # 2-row arrow). `_LINEAR_LANE_H` = total per-lane row stride.
    _LINEAR_BAR_ROWS  = 2
    _LINEAR_LANE_H    = 4   # bar (2) + label (1) + gap (1)
    _LINEAR_BACKBONE_GAP = 2   # rows between backbone + first lane

    def _feat_at_linear(self, x: int, y: int) -> tuple[int, int]:
        """Return (feature_idx, click_bp) at terminal cell (x, y) in
        the single-lane linear view.

        Click resolution:
          1. Label bbox match (populated by `_draw_linear`). Forward
             labels float ABOVE the bar, reverse labels BELOW —
             those rows are reserved for labels and route to the
             feature directly.
          2. Bar-row match: rows backbone_row±1 are the feature top
             and bottom halves. A click in either row resolves to a
             bp via the current zoom + offset; smallest-enclosing
             feature at that bp wins. Both strands share the same
             rows in the new layout, so we DON'T strand-gate by row.

        Coordinates respect the current zoom: only bp inside the
        visible window are clickable.
        """
        if not self._total:
            return -1, -1
        # Label-first: same logic as the circular path. A click on a
        # feature's text label routes to that feature with bp set to
        # its 5' end so the seq panel scrolls to the start.
        idx = self._label_at(x, y)
        if idx >= 0:
            f = self._feats[idx]
            return idx, int(f["start"])
        w, h      = self.size.width, self.size.height
        margin_l  = 5
        margin_r  = 2
        usable_w  = w - margin_l - margin_r
        backbone_row = max(4, h // 2)
        if x < margin_l or x >= w - margin_r or usable_w <= 0:
            return -1, -1
        # Only the bar rows (backbone±1) and backbone row itself
        # resolve to a feature. Other rows return no match — labels
        # are handled above by `_label_at`.
        if y not in (backbone_row - 1, backbone_row, backbone_row + 1):
            return -1, -1
        view_s, view_e = self._linear_view_range()
        visible_bp     = max(1, view_e - view_s)
        bp = view_s + int((x - margin_l) / max(1, usable_w) * visible_bp)
        bp = max(view_s, min(view_e - 1, bp))
        # Smallest-enclosing wins on nested features (matches the
        # circular path + sequence-panel fallback). No strand gating
        # here because the new layout puts both strands on the same
        # row pair. Routed through the bisect-indexed helper so
        # hover-frame budgets hold on WGS contigs with 1000+ feats.
        best_idx = self._smallest_enclosing_feature(bp)
        return (best_idx, bp) if best_idx >= 0 else (-1, -1)

    def _draw_linear(self, w: int, h: int) -> Text:
        # Linear view always uses the flag layout (2026-05-08 user
        # request). The legacy `_draw_linear_centered` dispatcher
        # branch was dropped — flag reads better when features
        # overlap and removes a UX choice the user didn't need.
        return self._draw_linear_flag(w, h)

    def _draw_linear_flag(self, w: int, h: int) -> Text:
        """Render a horizontal linear plasmid map — flag-style.

        Layout (multi-lane, rail-bisected):

            forward features stack ABOVE the rail in lanes assigned by
            greedy first-fit packing (lane 0 = closest to rail). Each
            feature is a single-row coloured bar with the label inside
            and a `▶` arrowhead at the right end. A single-column stem
            (`│`) drops from the feature midpoint to the rail.

            reverse features mirror the same scheme BELOW the rail with
            a `◀` arrowhead at the left end.

        Versus the centered layout, this trades the through-the-middle
        backbone for explicit vertical lane separation, so highly-
        annotated regions stop overlapping. Honours the same zoom +
        pan + click-target conventions; the two are interchangeable
        via Settings → "Linear features layout".
        """
        canvas = _Canvas(w, h)
        bc     = _BrailleCanvas(w, h)
        total  = self._total

        self._label_bboxes = []

        if not total:
            canvas.put_text(w // 2 - 9, h // 2, "No record loaded", "dim")
            return bc.combine(canvas)

        margin_l = 5
        margin_r = 2
        usable_w = w - margin_l - margin_r
        rail_row = max(4, h // 2)
        tick_label_row = rail_row + 1   # tucked just below the rail

        view_s, view_e = self._linear_view_range()
        if view_e <= view_s:
            view_e = view_s + 1
        visible_bp = max(1, view_e - view_s)

        def bp_to_col(bp: int) -> int:
            return margin_l + int(
                (bp - view_s) / visible_bp * usable_w
            )

        # ── Rail ──
        for cx in range(margin_l, margin_l + usable_w + 1):
            canvas.put(cx, rail_row, "─", "color(238)")

        # ── Ticks + bp labels ──
        tick_int  = max(1, _nice_tick(visible_bp))
        first_tick = (view_s // tick_int) * tick_int
        if first_tick < view_s:
            first_tick += tick_int
        bp = first_tick
        # Reserve one row of feature lanes between the rail and the tick
        # labels so a reverse-strand lane and a tick label never collide
        # on the same column.
        while bp <= view_e:
            tx = bp_to_col(bp)
            if margin_l <= tx <= margin_l + usable_w:
                canvas.put(tx, rail_row, "┼", "color(250)")
                lbl = _format_bp(bp)
                lx  = tx - len(lbl) // 2
                if 0 <= tick_label_row < h:
                    canvas.put_text(lx, tick_label_row, lbl, "color(245)")
            bp += tick_int
        canvas.put(margin_l, rail_row,
                    "├" if view_s == 0 else "─",
                    "color(250)")
        end_tx = min(margin_l + usable_w, w - 1)
        canvas.put(end_tx, rail_row,
                    "┤" if view_e >= total else "─",
                    "color(250)")

        # ── Restriction marks at the rail ──
        # Recuts only — resite spans would clash with the lane-stems.
        # The centered layout still shows full resite spans for users
        # who need them.
        for rf in self._restr_feats:
            if rf.get("type") != "recut":
                continue
            color = rf["color"]
            r_start = rf.get("start", 0)
            if r_start < view_s or r_start >= view_e:
                continue
            cut_x = bp_to_col(r_start)
            if margin_l <= cut_x < w - margin_r:
                canvas.put(cut_x, rail_row, "┼", color)

        # ── Collect features in view ──
        # Same sorted-index + wrap second-pass pattern as
        # `_draw_linear_centered`. We render each visible segment
        # independently so a wrap feature contributes one bar per half.
        feats_in_view: list[tuple[int, dict, int, int]] = []
        sorted_idx = getattr(self, "_feats_by_start", None) \
                     or list(range(len(self._feats)))
        import bisect as _bs
        # See `_draw_linear_centered`: starts list is precomputed in
        # `load_record` to avoid a per-frame list-comp.
        starts = getattr(self, "_feats_starts_sorted", None) \
                  or [self._feats[i]["start"] for i in sorted_idx]
        upper  = _bs.bisect_right(starts, view_e)
        for k in range(upper):
            i  = sorted_idx[k]
            feat = self._feats[i]
            sb = feat["start"]
            eb = feat["end"]
            if eb < sb or eb <= view_s:
                continue
            feats_in_view.append(
                (i, feat, max(view_s, sb), min(view_e, eb))
            )
        for i, feat in enumerate(self._feats):
            sb = feat["start"]
            eb = feat["end"]
            if eb >= sb:
                continue
            if view_s < eb:
                feats_in_view.append(
                    (i, feat, view_s, min(view_e, eb))
                )
            if sb < view_e:
                feats_in_view.append(
                    (i, feat, max(view_s, sb), min(view_e, total))
                )

        # ── Greedy lane packing ──
        # Process largest spans first so big features land in low lanes
        # (closest to the rail) and small annotations stack outward.
        feats_in_view.sort(
            key=lambda t: -(t[3] - t[2])
        )

        fwd_lanes: list[list[tuple[int, int]]] = []
        rev_lanes: list[list[tuple[int, int]]] = []
        # Each placed entry: (i, feat, cx0, cx1, is_fwd, lane_idx)
        placed: list[tuple[int, dict, int, int, bool, int]] = []

        for i, feat, seg_s, seg_e in feats_in_view:
            is_fwd = feat["strand"] >= 0
            cx0 = bp_to_col(seg_s)
            cx1 = bp_to_col(seg_e)
            cx0 = max(margin_l, min(cx0, w - margin_r - 1))
            cx1 = max(margin_l, min(cx1, w - margin_r))
            if cx1 <= cx0:
                cx1 = cx0 + 1
            lanes = fwd_lanes if is_fwd else rev_lanes
            chosen = -1
            for li, lane in enumerate(lanes):
                if all(cx1 <= a or cx0 >= b for a, b in lane):
                    chosen = li
                    break
            if chosen < 0:
                lanes.append([])
                chosen = len(lanes) - 1
            lanes[chosen].append((cx0, cx1))
            placed.append((i, feat, cx0, cx1, is_fwd, chosen))

        # ── Pre-pack alignment lanes ──
        # Sequencing-read / library-diff alignments sit closest to the
        # rail (user-visible centerline) so the user can read base-by-
        # base diff against the target without scanning past the
        # feature band. Packed BEFORE rev features so we can offset
        # the rev-band downward by the alignment lane count. Empty
        # list when no alignments are registered — no displacement.
        self._align_bboxes = []
        align_placed: "list[tuple[int, dict, int, int, int]]" = []
        align_lanes_count = 0
        if self._alignments:
            align_placed, align_lanes_count = self._pack_alignment_lanes(
                margin_l, usable_w, view_s, view_e, w, bp_to_col,
            )

        # ── Render features ──
        # Lane k for forward sits at row `rail_row - 2 - k`, leaving
        # row `rail_row - 1` clear for stems. Lane k for reverse sits
        # at row `rail_row + 2 + align_lanes_count + k`, leaving row
        # `rail_row + 1` for the bp tick labels and rows
        # `rail_row + 2 .. rail_row + 1 + align_lanes_count` for the
        # alignment band (closest-to-rail position, painted further down).
        for i, feat, cx0, cx1, is_fwd, lane_idx in placed:
            color  = feat["color"]
            label  = feat.get("label", feat.get("type", ""))
            is_sel = (i == self.selected_idx)
            style  = ("reverse " + color) if is_sel else color

            if is_fwd:
                feat_row = rail_row - 2 - lane_idx
                if feat_row < 1:
                    continue
            else:
                # Push reverse lanes below the alignment band (when
                # present) so the alignment lanes stay nearest the rail.
                feat_row = rail_row + 2 + align_lanes_count + lane_idx
                if feat_row >= h:
                    continue

            bar_w = cx1 - cx0
            if is_fwd:
                head_col  = cx1 - 1
                body_cols = range(cx0, head_col)
                head_glyph = "▶"
            else:
                head_col  = cx0
                body_cols = range(cx0 + 1, cx1)
                head_glyph = "◀"

            for col in body_cols:
                canvas.put(col, feat_row, "█", style)
            if 0 <= head_col < w:
                canvas.put(head_col, feat_row, head_glyph, style)

            # Label INSIDE the bar — bold black on the feature's colour
            # so it reads like a proper "flag". The arrowhead column is
            # excluded so the head glyph stays visible.
            if bar_w >= 2 and label:
                inner_cx0 = cx0 + (1 if not is_fwd else 0)
                inner_cx1 = cx1 - (1 if is_fwd else 0)
                inner_w   = max(1, inner_cx1 - inner_cx0)
                lbl = label[:inner_w]
                lx  = inner_cx0 + (inner_w - len(lbl)) // 2
                lbl_style = "bold black on " + color
                canvas.put_text(lx, feat_row, lbl, lbl_style)

            # Click-target bbox spans the WHOLE bar (label + head).
            self._label_bboxes.append(
                (cx0, cx1 - 1, feat_row, i)
            )

            # Stem from feature midpoint down/up to the rail. Walk one
            # cell at a time and only paint into blank cells so we
            # don't tear through another feature's bar that happens to
            # share the column. Rev stems skip the alignment-band rows
            # entirely so blank gaps within the band aren't threaded
            # with disconnected `│` glyphs (the band is supposed to
            # read as a continuous sequencing-read lane).
            stem_col = (cx0 + cx1 - 1) // 2
            if is_fwd:
                stem_rows = range(feat_row + 1, rail_row)
                align_skip_lo = align_skip_hi = -1
            else:
                stem_rows = range(rail_row + 1, feat_row)
                align_skip_lo = rail_row + 2
                align_skip_hi = rail_row + 1 + align_lanes_count
            for sr in stem_rows:
                if 0 <= sr < h:
                    if align_skip_lo <= sr <= align_skip_hi:
                        continue
                    existing = canvas._chars[sr][stem_col]
                    if existing == " ":
                        canvas.put(stem_col, sr, "│", color)

        # ── Alignment overlay band ──
        # Alignments were pre-packed up front so the rev-feature band
        # could be offset; now paint the lanes immediately below the
        # tick label row (closest-to-rail). Bar mode at <1 col/bp (blue
        # match / red mismatch / gray gap blocks); letter mode at
        # ≥1 col/bp (query base letter in the same 3-colour scheme).
        if align_placed:
            self._draw_alignment_band(
                canvas, w, h, margin_l, usable_w, view_s, view_e,
                visible_bp, bp_to_col, rail_row,
                align_placed=align_placed,
            )

        # ── Header ──
        # Same display-name preference as the circular header (see
        # `_draw` for rationale).
        # Same Pyright-false-positive guard as the circular draw path.
        record = self.record
        name = (getattr(record, "_tui_display_name", None)
                or getattr(record, "name", None)
                or getattr(record, "id", None)
                or "?")[:w // 3]
        canvas.put_text(margin_l, 0, f"{name}  {total:,} bp", "bold white")
        hint = "[ flag  ·  v = circular ]"
        canvas.put_text(w - len(hint) - 1, 0, hint, "dim")

        return bc.combine(canvas)

    def _pack_alignment_lanes(
        self, margin_l: int, usable_w: int,
        view_s: int, view_e: int, w: int, bp_to_col,
    ) -> tuple[list, int]:
        """Filter `self._alignments` to those overlapping the visible
        bp window, then IGV-style greedy first-fit lane-pack them
        (sort by target start asc, length desc so the longest spans
        claim low lanes nearest the rail). Returns
        ``(align_placed, n_lanes)`` where each placed entry is
        ``(ai, align, lane_idx, cx0, cx1)``.
        Extracted from `_draw_alignment_band` so `_draw_linear_flag`
        can learn the lane count BEFORE rendering rev features and
        offset that band downward (keeping the alignment lanes
        closest to the rail / centerline)."""
        visible_aligns: "list[tuple[int, dict]]" = []
        for ai, align in enumerate(self._alignments):
            t_lo = align.get("t_lo", 0)
            t_hi = align.get("t_hi", 0)
            if t_hi <= view_s or t_lo >= view_e:
                continue
            visible_aligns.append((ai, align))
        if not visible_aligns:
            return [], 0
        visible_aligns.sort(
            key=lambda t: (
                t[1].get("t_lo", 0),
                -(t[1].get("t_hi", 0) - t[1].get("t_lo", 0)),
            )
        )
        align_lanes: "list[list[tuple[int, int]]]" = []
        align_placed: "list[tuple[int, dict, int, int, int]]" = []
        for ai, align in visible_aligns:
            t_lo = align.get("t_lo", 0)
            t_hi = align.get("t_hi", 0)
            cx0 = bp_to_col(max(view_s, t_lo))
            cx1 = bp_to_col(min(view_e, t_hi))
            cx0 = max(margin_l, min(cx0, w - 1))
            cx1 = max(margin_l, min(cx1, margin_l + usable_w))
            if cx1 <= cx0:
                cx1 = cx0 + 1
            chosen = -1
            for li, lane in enumerate(align_lanes):
                if all(cx1 <= a or cx0 >= b for a, b in lane):
                    chosen = li
                    break
            if chosen < 0:
                align_lanes.append([])
                chosen = len(align_lanes) - 1
            align_lanes[chosen].append((cx0, cx1))
            align_placed.append((ai, align, chosen, cx0, cx1))
        return align_placed, len(align_lanes)

    def _draw_alignment_band(
        self, canvas, w: int, h: int, margin_l: int, usable_w: int,
        view_s: int, view_e: int, visible_bp: int,
        bp_to_col, rail_row: int,
        align_placed: "list[tuple[int, dict, int, int, int]]",
    ) -> None:
        """Paint the linear-view alignment overlay onto `canvas`.

        Helper extracted from `_draw_linear_flag` so the main render
        stays readable. The contract is: caller has already drawn the
        rail + ticks + restriction marks and pre-packed alignment
        lanes via `_pack_alignment_lanes`. The band sits at
        ``rail_row + 2`` (closest-to-centerline, user request
        2026-05-18) so sequencing-read diffs land right under the
        sequence tick row instead of below the feature stack.

        Per-frame work:
          * per-alignment bar render (bar mode <1 col/bp, letter mode otherwise)
          * strand arrowhead at the right end
          * click bboxes appended to `self._align_bboxes`
          * "+N more" overflow indicator if alignments exceed available rows

        2026-05-12: separate coverage-histogram row removed per user
        request — the lane stack alone carries enough information and
        the histogram read as a confusing second band.
        2026-05-18: lanes moved from below-rev-features to immediately
        below the tick row; rev features now offset down by the lane
        count to keep alignment bars closest to the rail.
        """
        if not align_placed:
            return
        # Place the alignment band right below the tick label row.
        # `rail_row + 1` is the bp tick label; alignment lane 0 lands at
        # `rail_row + 2` — the first row below the rail visually.
        align_band_top = rail_row + 2
        if align_band_top >= h:
            # Terminal too short — surface a single-row hint where the
            # rev band ends rather than silently dropping the lanes.
            hint_row = rail_row + 1
            if 0 <= hint_row < h:
                hint = f"[{len(self._alignments)} alignment(s) — terminal too short]"
                canvas.put_text(
                    margin_l, hint_row,
                    hint[: w - margin_l - 1], "color(196)",
                )
            return
        # Leave room for an overflow row at the very bottom; one less
        # available lane row when overflow needs to be indicated.
        max_lane_rows = max(0, h - align_band_top)
        will_overflow = len(align_placed) > max_lane_rows or any(
            lane_idx >= max_lane_rows for (_ai, _a, lane_idx, _c0, _c1) in align_placed
        )
        max_lane_idx_render = (
            max_lane_rows - 2 if will_overflow else max_lane_rows - 1
        )

        # 4. Render alignment lanes.
        col_per_bp  = usable_w / max(1, visible_bp)
        letter_mode = col_per_bp >= 1.0
        rendered    = 0
        skipped     = 0
        for ai, align, lane_idx, cx0_align, cx1_align in align_placed:
            row = align_band_top + lane_idx
            if lane_idx > max_lane_idx_render or row >= h:
                skipped += 1
                continue
            is_selected = (ai == self._selected_align_idx)
            base_style  = "reverse" if is_selected else ""

            # Lazy-build per-bp letter dict on first letter-mode draw.
            letters = align.get("letters")
            if letter_mode and letters is None:
                letters = _alignment_to_target_letters(
                    align.get("aligned_q", ""),
                    align.get("aligned_t", ""),
                    align.get("t_start", 0),
                )
                align["letters"] = letters

            # Walk segments and paint each visible chunk.
            for seg_s, seg_e, state in align.get("segments", []):
                s = max(seg_s, view_s)
                e = min(seg_e, view_e)
                if s >= e:
                    continue
                if state == "match":
                    color = "color(39)"
                    glyph = "█"
                elif state == "mismatch":
                    color = "color(196)"
                    glyph = "█"
                else:  # gap
                    color = "color(240)"
                    glyph = "░"
                if letter_mode and letters:
                    letter_style = (
                        f"{base_style} bold {color}".strip()
                    )
                    for bp in range(s, e):
                        col = bp_to_col(bp)
                        if not (margin_l <= col <= margin_l + usable_w):
                            continue
                        ch, _ = letters.get(bp, ("-", state))
                        canvas.put(col, row, ch, letter_style)
                else:
                    seg_cx0 = max(margin_l, bp_to_col(s))
                    seg_cx1 = min(margin_l + usable_w, bp_to_col(e))
                    bar_style = f"{base_style} {color}".strip()
                    for col in range(seg_cx0, seg_cx1):
                        canvas.put(col, row, glyph, bar_style)

            # Strand arrowhead at the right tip of the bar. All
            # registered alignments are forward against the target;
            # reverse-strand reads have already been RC'd by the
            # aligner before reaching us.
            t_hi_a = align.get("t_hi", 0)
            if view_s < t_hi_a <= view_e:
                arrow_col = bp_to_col(t_hi_a) - 1
                if margin_l <= arrow_col <= margin_l + usable_w:
                    canvas.put(
                        arrow_col, row, "▶",
                        f"{base_style} color(39)".strip(),
                    )

            # Read name to the LEFT of the bar if there's room. Truncated
            # silently when the name is wider than the gap to the left
            # margin; an "[…]" indicator would just eat more of the bar.
            name = align.get("name") or ""
            t_lo_a = align.get("t_lo", 0)
            if name and t_lo_a >= view_s:
                name_col_end = bp_to_col(t_lo_a) - 1
                room = max(0, name_col_end - margin_l)
                if room >= 3:
                    show = name[: min(len(name), room)]
                    canvas.put_text(
                        name_col_end - len(show), row, show,
                        f"{base_style} dim white".strip(),
                    )

            # Click bbox for drill-in to AlignmentScreen.
            self._align_bboxes.append((
                cx0_align, max(cx0_align, cx1_align - 1), row, ai,
            ))
            rendered += 1

        # 5. Overflow indicator.
        if skipped > 0:
            overflow_row = align_band_top + max_lane_idx_render + 1
            if 0 <= overflow_row < h:
                label = f"+{skipped} more (Alt+Shift+A to clear)"
                col   = max(margin_l, w - len(label) - 1)
                canvas.put_text(
                    col, overflow_row, label, "bold color(196)",
                )


# ── Sidebar feature table ──────────────────────────────────────────────────────

class FeatureSidebar(Widget):
    DEFAULT_CSS = """
    FeatureSidebar {
        width: 32;
    }
    /* Subtle "you are here" brighten when the inner DataTable
       holds focus. See PlasmidMap for the colour rationale. */
    FeatureSidebar:focus-within { background: #0c0c0c; }
    #feat-table  { height: 1fr; }
    #sidebar-hdr { background: $primary; padding: 0 1; }
    """

    # `enter` opens the FeatureEditModal for the cursor-row feature.
    # priority=True so it pre-empts the inner DataTable's default
    # Enter handler (which would just re-fire RowSelected → highlight,
    # a no-op when the cursor's already on the target row).
    BINDINGS = [
        Binding("enter", "open_feature_at_cursor",
                "Open feature", priority=True, show=False),
        # Alt+O — re-anchor the display origin at the highlighted
        # row's feature. Mirrors the map's binding so the user can
        # set origin without leaving the sidebar (the cursor row
        # carries the same intent as the map's selected feature).
        Binding("alt+o", "set_origin_to_row",
                "Set origin", priority=True, show=False),
    ]

    class RowActivated(Message):
        def __init__(self, idx: int, *, shift: bool = False):
            self.idx   = idx
            # Shift+click on a sidebar row → extend the seq-panel
            # selection from the anchor feature to this one. The App
            # reads it and falls back to bare-click behaviour when no
            # feature is currently selected.
            self.shift = bool(shift)
            super().__init__()

    class RowOpened(Message):
        """Emitted on Enter against a highlighted row, or on a
        double-click. The App opens the FeatureEditModal for the
        feature at `idx`. Distinct from `RowActivated` (which only
        moves the highlight) so a single click doesn't trip the
        editor by accident."""
        def __init__(self, idx: int):
            self.idx = idx
            super().__init__()

    def compose(self) -> ComposeResult:
        yield Static(" Features", id="sidebar-hdr")
        yield DataTable(id="feat-table", cursor_type="row", zebra_stripes=True)

    def on_mount(self):
        t = self.query_one("#feat-table", DataTable)
        t.add_columns("Type", "Label", "bp", "±")
        # `_view_origin_bp` mirrors the plasmid map's rotation so the
        # row order matches what the user sees on the circular map —
        # rotating the map's origin by N reorders the sidebar to start
        # with the feature nearest the new origin going clockwise.
        # Updated by the App on `PlasmidMap.OriginChanged` events.
        self._view_origin_bp: int = 0
        self._total_bp:        int = 0

    def set_view_origin(self, origin_bp: int, total_bp: int) -> None:
        """Re-anchor the row order around `origin_bp` (display origin).
        Pure UI rotation — feature dicts retain their absolute coords.
        `total_bp` is the record length so the modular sort wraps
        correctly. Both parameters round-trip on every populate; this
        method just refreshes the table without rebuilding from the
        record. Called from the App's `OriginChanged` handler.
        """
        if origin_bp == self._view_origin_bp and total_bp == self._total_bp:
            return
        self._view_origin_bp = max(0, int(origin_bp))
        self._total_bp       = max(0, int(total_bp))
        # Find the feats list the table was last populated with — we
        # stash a reference so re-sort doesn't need a round-trip
        # through the App.
        if getattr(self, "_last_feats", None) is not None:
            self.populate(self._last_feats)

    @staticmethod
    def _sort_key(f: dict, origin_bp: int = 0, total_bp: int = 0) -> tuple:
        """Sort features by appearance order from the display origin
        (clockwise on circular plasmids; left-to-right on linear),
        so the sidebar stays in sync with the plasmid map's rotation.

        Primary key: ``(start - origin) % total`` ASC — the distance
        from the display origin going clockwise. With ``origin == 0``
        this is the original ``start`` ASC. When the user rotates the
        map (or hits Alt+O on a feature), the same feature stays at
        the top of the list while everything else shifts.

        Secondary key: ``(end - origin) % total`` ASC — when two
        features start at the same bp, the shorter one wins the tie
        (smaller end → "span closer to the origin"). Puts a tightly-
        scoped feature like a `primer_bind` ahead of a CDS that nests
        around it, which feels right when scanning a list.

        Wrap features (``end < start``) get the same modular shift so
        they land at the correct rotated position — a wrap feature at
        (5800, 200) on a 6000 bp plasmid rotated by ``origin=5500``
        lands at distance 300 clockwise from the new origin.

        With ``origin_bp == 0`` (or ``total_bp == 0``, the typical
        unrotated path) the function reduces to the historical
        ``(start, end)`` tuple — verified by the existing sort tests.

        Falls back to ``0`` for missing / non-int coords so a malformed
        feature dict can't trip the sort with a TypeError.
        """
        start = int(f.get("start", 0) or 0)
        end   = int(f.get("end",   0) or 0)
        n = int(total_bp or 0)
        o = int(origin_bp or 0)
        if n > 0 and o > 0:
            return ((start - o) % n, (end - o) % n)
        return (start, end)

    def populate(self, feats: list[dict]) -> None:
        t = self.query_one("#feat-table", DataTable)
        # Stash for `set_view_origin` so map rotation can re-sort
        # without bouncing through the App. Same reference, not a
        # copy — sidebar reads but never mutates the list.
        self._last_feats = feats
        # Suppress the RowHighlighted cascade that fires when DataTable auto-
        # moves the cursor to row 0 after clear()+add_row. Without this guard,
        # every record load triggers a redundant SequencePanel rebuild (the
        # cascade routes through PlasmidApp._sidebar_row_activated → seq_pnl.
        # highlight_feature → _refresh_view). Measured savings: ~50 ms per
        # load on 10 kb plasmids, ~110 ms on 20 kb. See CLAUDE.md perf notes.
        #
        # Textual posts RowHighlighted asynchronously, so we can't use a
        # simple try/finally: the handler would see _populating == False
        # because populate() has already returned by the time the message is
        # dispatched. Instead we set the flag True here and schedule its
        # reset via call_after_refresh, which runs AFTER all pending messages.
        self._populating = True
        # Sort by (start, end) for the displayed rows but keep a
        # row→feat-idx mapping so click handlers + `highlight_row` can
        # still resolve back to the caller's `pm._feats` list. The
        # source list is left untouched so colour assignment + the
        # plasmid map's `_feats_by_start` index keep their existing
        # semantics. `_feat_idx_to_row` is the inverse, keyed by feat
        # idx, used by `highlight_row(idx)` from the App side.
        sorted_feat_idxs = sorted(
            range(len(feats)),
            key=lambda i: self._sort_key(
                feats[i], self._view_origin_bp, self._total_bp,
            ),
        )
        self._row_to_feat_idx = sorted_feat_idxs
        self._feat_idx_to_row = {
            feat_i: row_i for row_i, feat_i in enumerate(sorted_feat_idxs)
        }
        try:
            t.clear()
            for feat_i in sorted_feat_idxs:
                f = feats[feat_i]
                strand_sym = "+" if f["strand"] == 1 else ("−" if f["strand"] == -1 else "·")
                # Wrap-aware: end<start means the feature crosses the
                # origin. Show "S+1‥0‥E" so the user can tell at a
                # glance vs a linear span — pre-fix wrap features
                # rendered as "5801‥200" which could be misread as a
                # bug (end-before-start would imply broken data).
                if f["end"] < f["start"]:
                    bp_str = f"{f['start']+1}‥0‥{f['end']}"
                else:
                    bp_str = f"{f['start']+1}‥{f['end']}"
                t.add_row(
                    Text(f["type"][:12],  style=f["color"]),
                    Text(f["label"][:14], style=f["color"]),
                    bp_str,
                    strand_sym,
                )
        except Exception:
            # Malformed feature dict (missing color/type/label) would otherwise
            # leave _populating=True forever, blocking every RowHighlighted
            # event and breaking the sidebar until app restart. Reset the flag
            # synchronously before re-raising so the cascade can recover.
            self._populating = False
            _log.exception("FeatureSidebar.populate failed mid-loop")
            raise
        def _clear_populating():
            self._populating = False
        self.call_after_refresh(_clear_populating)

    def show_detail(self, f: dict | None) -> None:
        """No-op kept so existing call sites don't need to be guarded.
        The detail-box widget was removed when the sidebar was simplified
        to a single full-height table; feature info is still surfaced
        via the table row + map highlight."""
        return

    _prog_row: int = -1   # cursor moves driven by highlight_row, not the user
    _populating: bool = False   # suppress RowActivated cascade during populate()
    # DataTable's RowSelected / RowHighlighted events don't carry the
    # mouse-modifier state. We capture shift on the parent Click event
    # (which fires *before* RowSelected) and stash it here for the
    # row-event handlers to read. Per-sidebar instance, reset after
    # consumption so the next bare click reads `False`.
    _pending_shift: bool = False
    # Same trick for double-click: Textual's Click event has
    # `chain >= 2` for double-clicks, captured in `_on_table_click`
    # and consumed by `_row_selected` to fire `RowOpened`. Reset
    # after every consumption.
    _pending_double_click: bool = False
    # Sidebar rows are sorted by (start, end) for clockwise-from-origin
    # display, while `pm._feats` keeps record order so colour assignment
    # + `_feats_by_start` stay stable. These two maps translate between
    # the two coordinate systems. Empty defaults at class scope so
    # `highlight_row` / `_row_highlighted` are safe before the first
    # `populate()` call.
    _row_to_feat_idx: list[int] = []
    _feat_idx_to_row: dict[int, int] = {}

    def highlight_row(self, feat_idx: int) -> None:
        """Move cursor to the row showing feature ``feat_idx`` (an
        index into the caller's `pm._feats` list, NOT a DataTable row).
        Translates through `_feat_idx_to_row` so callers don't have
        to know about the sidebar's display sort. Suppresses the
        resulting RowActivated echo via `_prog_row`.
        """
        if feat_idx < 0:
            return
        row = self._feat_idx_to_row.get(feat_idx)
        if row is None:
            return
        t = self.query_one("#feat-table", DataTable)
        self._prog_row = row
        try:
            t.move_cursor(row=row)
        except Exception:
            self._prog_row = -1

    def _row_to_feat(self, cursor_row: int) -> int:
        """Translate a DataTable row index to the corresponding feat
        index in `pm._feats`. Returns -1 when the row is out of range
        (e.g. a stale cursor on a sidebar that's just been re-populated)."""
        if 0 <= cursor_row < len(self._row_to_feat_idx):
            return self._row_to_feat_idx[cursor_row]
        return -1

    @on(Click)
    def _on_table_click(self, event: Click) -> None:
        # Capture shift OR ctrl state *before* DataTable's own row
        # events fire. Don't stop propagation — the table still needs
        # the click to move its cursor. Ctrl is a synonym for shift
        # because many terminals eat shift+click for native text-
        # selection.
        self._pending_shift = bool(getattr(event, "shift", False)
                                     or getattr(event, "ctrl",  False))
        # Double-click → open the feature editor. Textual's Click
        # event carries `chain` (1=single, 2=double, 3=triple…). Set
        # a flag for `_row_selected` to consume; we can't open here
        # directly because Click fires before DataTable updates its
        # cursor row, so the idx may be stale.
        self._pending_double_click = (getattr(event, "chain", 1) >= 2)
        try:
            echo = getattr(self.app, "_echo_click_modifiers", None)
            if callable(echo):
                echo("sidebar", event)
        except Exception:
            pass

    def _consume_shift(self) -> bool:
        s = self._pending_shift
        self._pending_shift = False
        return s

    @on(DataTable.RowHighlighted, "#feat-table")
    def _row_highlighted(self, event: DataTable.RowHighlighted):
        # Ignore every auto-highlight that fires while populate() is running.
        if self._populating:
            return
        if event.cursor_row == self._prog_row:
            self._prog_row = -1
            return
        feat_idx = self._row_to_feat(event.cursor_row)
        if feat_idx < 0:
            return
        self.post_message(self.RowActivated(feat_idx,
                                              shift=self._consume_shift()))

    @on(DataTable.RowSelected, "#feat-table")
    def _row_selected(self, event: DataTable.RowSelected):
        """Click on a row whose cursor is already on it doesn't fire
        RowHighlighted (the cursor didn't move), so a user clicking the same
        sidebar row twice — or clicking a row that was already
        highlight-driven by a map/seq-panel click — would otherwise be
        silent. RowSelected fires on every click; combine with
        RowHighlighted's `_prog_row` gate to avoid double-firing on
        first-time clicks (which fire both events).

        Two semantically distinct outputs:
          * `RowActivated` — moves the highlight (existing behavior).
          * `RowOpened` — opens the feature editor. Triggered by a
            double-click (chain ≥ 2) or by Enter when the cursor was
            already on this row (= "open intent", not "move cursor").
        """
        if self._populating:
            return
        # `_row_highlighted` will already have fired when the cursor moved,
        # so skip the duplicate. Only emit when the click landed on the
        # already-current cursor row (no preceding RowHighlighted).
        try:
            t = self.query_one("#feat-table", DataTable)
        except NoMatches:
            return
        if event.cursor_row != t.cursor_row:
            return
        # Open-intent path: double-click (already cached on
        # `_pending_double_click`) or Enter on a row whose cursor was
        # already there (= no preceding RowHighlighted from this
        # event chain). The latter is signalled by `_prog_row == -1`
        # AT THE TIME `_on_table_click` would have fired — but for
        # keyboard Enter, `_on_table_click` never fires, so the
        # double-click flag is False. We rely on the fact that
        # programmatic cursor moves set `_prog_row` and consume it
        # in RowHighlighted; if neither flag tripped, this is a
        # genuine "Enter on an already-resting cursor" event.
        is_double = self._pending_double_click
        self._pending_double_click = False
        feat_idx = self._row_to_feat(event.cursor_row)
        if feat_idx < 0:
            return
        if is_double:
            self.post_message(self.RowOpened(feat_idx))
            return
        # No `_prog_row` check here — programmatic moves don't trigger
        # RowSelected, only real clicks/Enter do, so we always want to react.
        self.post_message(self.RowActivated(feat_idx,
                                              shift=self._consume_shift()))

    def action_open_feature_at_cursor(self) -> None:
        """Open the FeatureEditModal for the row the table cursor is
        currently on. Bound to Enter at the sidebar level (with
        priority=True) so it pre-empts the DataTable's default Enter
        handling — without priority, DataTable's `select_cursor`
        would just re-fire RowSelected with no cursor move, which
        our `_row_selected` correctly treats as a no-op highlight."""
        try:
            t = self.query_one("#feat-table", DataTable)
        except NoMatches:
            return
        cursor_row = t.cursor_row
        if cursor_row is None or cursor_row < 0:
            return
        feat_idx = self._row_to_feat(cursor_row)
        if feat_idx < 0:
            return
        self.post_message(self.RowOpened(feat_idx))

    def action_set_origin_to_row(self) -> None:
        """Alt+O on the sidebar — re-anchor the map's display origin
        at the row the table cursor is currently on. Defers to the
        plasmid map's `action_set_origin_to_selected` after first
        nudging the map's `selected_idx` to match the cursor row, so
        the keystroke works the same way whether the user pressed
        Alt+O on the map or here.
        """
        try:
            t = self.query_one("#feat-table", DataTable)
        except NoMatches:
            return
        cursor_row = t.cursor_row
        if cursor_row is None or cursor_row < 0:
            return
        feat_idx = self._row_to_feat(cursor_row)
        if feat_idx < 0:
            return
        try:
            pm = self.app.query_one("#plasmid-map", PlasmidMap)
        except (NoMatches, AttributeError):
            return
        pm.selected_idx = feat_idx
        pm.action_set_origin_to_selected()


# ── Library panel ──────────────────────────────────────────────────────────────

def _fuzzy_match(query: str, name: str) -> bool:
    """Case-insensitive subsequence match: True if every char of `query`
    appears in `name` in order (not necessarily contiguous). Empty query
    matches everything. Used by LibraryPanel's search filter and by
    `_search_collections_library` (cross-collection search).

    Performance: O(len(query) * len(name)) worst case via repeated
    `str.find`. Early-rejects when ``len(query) > len(name)`` (no
    subsequence can be longer than its container) — saves the
    full lower() + scan on huge libraries where most names are
    shorter than a typical fuzzy query. The lower() call is the hot
    spot for very long names; the early reject runs on the original
    strings before any allocation.
    """
    if not query:
        return True
    if not name:
        return False
    # Subsequence membership requires `len(query) <= len(name)`. Skip
    # the lower() + scan entirely when impossible. This is the hot
    # exit on huge libraries where typical names are short and the
    # user's filter has 5+ chars.
    if len(query) > len(name):
        return False
    q, n = query.lower(), name.lower()
    i = 0
    for ch in q:
        i = n.find(ch, i)
        if i < 0:
            return False
        i += 1
    return True


def _search_collections_library(query: str, *,
                                  limit: int = 200) -> list[dict]:
    """Cross-collection plasmid search. Returns up to `limit` matches
    across every collection on disk. Each match is
    ``{collection, name, id, size, status, n_feats}``. The query is
    fuzzy-matched against the plasmid name (same `_fuzzy_match`
    semantics as the library panel's in-collection search) so a user
    typing `puc` finds `pUC19`. An empty `query` returns the first
    `limit` plasmids across all collections (useful as a "list
    everything" affordance for agents).

    Used by the cross-collection search modal (`LibrarySearchModal`,
    Edit → Find plasmid…) and the `search-library` agent endpoint.
    Results are natural-sorted by ``(collection_name, plasmid_name)``
    so ``Backbones 2`` lands before ``Backbones 10`` and within a
    collection ``pBin2`` lands before ``pBin10``.
    """
    out: list[dict] = []
    q = (query or "").strip()
    for c in _load_collections():
        cname = c.get("name") or "?"
        for entry in c.get("plasmids", []) or []:
            if not isinstance(entry, dict):
                continue
            entry_id = entry.get("id") or ""
            # Skip entries without an `id` — without one we can't
            # round-trip the dismiss payload to `_apply_record`, and
            # the loader would alias every untagged entry to the
            # first one it finds.
            if not entry_id:
                continue
            name = entry.get("name") or entry_id
            if q and not _fuzzy_match(q, name):
                continue
            out.append({
                "collection": cname,
                "name":       name,
                "id":         entry_id,
                "size":       entry.get("size", 0),
                "status":     _sanitize_plasmid_status(entry.get("status")),
                "n_feats":    entry.get("n_feats", 0),
            })
    # Natural-sort by (collection, name) — group rows from the same
    # collection together, with plasmids inside each group in
    # human-friendly numeric order. `heapq.nsmallest` keeps this O(N
    # + limit·log(limit)) instead of the full O(N·log(N)) `out.sort`
    # would cost, which matters once the user crosses ~1k plasmids
    # (typical limit=200). For small libraries the two paths are
    # indistinguishable; for a 5k-plasmid catalog the heap form saves
    # ~30 ms per search keystroke.
    import heapq as _heapq
    return _heapq.nsmallest(
        limit, out,
        key=lambda r: (
            _natural_sort_key(r.get("collection") or ""),
            _natural_sort_key(r.get("name") or ""),
        ),
    )


_NATURAL_SORT_RE = re.compile(r"(\d+)")

# LRU-style cache for `_natural_sort_key`. Library / collections /
# parts-bin repopulate paths fire on every Filter-Input keystroke and
# each one re-sorts the entire list; for a 1000-entry library that's
# 1000 regex.split + lower calls × every keystroke. The keys are tiny
# strings (plasmid / collection / part names) so the cache footprint
# is bounded, and we cap to `_NATURAL_SORT_CACHE_CAP` entries to keep
# the cache from growing unboundedly under arbitrarily large libraries.
_NATURAL_SORT_KEY_CACHE: "dict[str, tuple]" = {}
_NATURAL_SORT_CACHE_CAP: int = 4096


def _natural_sort_key(s: str) -> tuple:
    """Return a tuple suitable for natural / human-friendly sorting.

    Splits `s` into alternating text and integer runs so that
    `pBin2` sorts before `pBin10`, instead of the lexicographic
    `pBin1 < pBin10 < pBin2 < pBin20`. Tuples carry `(0, str)` for
    text runs and `(1, int)` for digit runs so Python's tuple
    comparison never tries to order an `int` against a `str` (which
    raises in Py3) — that mixed comparison is the gotcha that bites
    the naïve `(int_or_str, ...)` formulation when a name starts
    with a digit (like `"5kb_backbone"` vs `"pBin1"`).

    Cached: identical input strings (the common case across re-sort
    calls when filter keystrokes only change the predicate, not the
    underlying library) reuse the previously computed tuple.
    """
    cached = _NATURAL_SORT_KEY_CACHE.get(s)
    if cached is not None:
        return cached
    out: list[tuple[int, "int | str"]] = []
    for part in _NATURAL_SORT_RE.split(s.lower()):
        if not part:
            continue
        if part.isdigit():
            out.append((1, int(part)))
        else:
            out.append((0, part))
    result = tuple(out)
    if len(_NATURAL_SORT_KEY_CACHE) >= _NATURAL_SORT_CACHE_CAP:
        # Bounded cache: drop oldest insertion when at cap. dict
        # preserves insertion order, so popping the first key is the
        # cheapest FIFO eviction we can do without a full LRU dance.
        try:
            first = next(iter(_NATURAL_SORT_KEY_CACHE))
            del _NATURAL_SORT_KEY_CACHE[first]
        except StopIteration:
            pass
    _NATURAL_SORT_KEY_CACHE[s] = result
    return result


# ── Name-collision helpers (load-time dedupe across subsystems) ───────────────
#
# Two collision categories, surfaced consistently across every load path
# (parts bin, plasmid library, primers, experiments, collections, gels,
# projects):
#
#   1. **Exact copy** — same display name AND same content. User chose
#      to load a literal duplicate (e.g. re-importing the same .gb file
#      twice, or a bulk-import folder containing two identical entries).
#      Prompt → ``ExactCopyConfirmModal``: keep all as " COPY" / skip all.
#      Default: skip (handslip protection — silently double-adding is the
#      pre-fix bug).
#
#   2. **Name collision (different content)** — same display name but
#      different content. The user may be intentionally loading a newer
#      / different version, OR may have hit an unintended collision.
#      Prompt → ``NameCollisionModal``: overwrite / keep original / cancel.
#      Default: keep original (safest — preserves existing data; mirrors
#      the existing primer-dup "keep by default" pattern).
#
# Both modals are routed through ``_classify_collisions`` (pure function,
# no UI) so each subsystem can call the classifier off-thread and only
# pay the modal cost when collisions exist.

def _ensure_unique_copy_name(
    base: str,
    existing_names: "set[str]",
    suffix: str = "COPY",
) -> str:
    """Return ``"{base} {suffix}"`` (or `" {suffix} 2"`, `" 3"`, …) until
    the result is not in ``existing_names``. Used to rename exact-copy
    entries so they can coexist alongside their twin in a library.

    ``base`` itself is returned only when it is somehow already unique —
    callers should not rely on this branch (the helper is meant to be
    called *after* a collision is detected). Keeping the guard means a
    bug in the caller doesn't infinite-loop on an empty ``existing_names``
    set.
    """
    if base not in existing_names:
        return base
    candidate = f"{base} {suffix}"
    if candidate not in existing_names:
        return candidate
    n = 2
    # Cap the search so a pathological library can't pin the UI thread.
    # 9999 copies of the same name is well past the "library has lost
    # the plot" threshold.
    while n < 10_000:
        candidate = f"{base} {suffix} {n}"
        if candidate not in existing_names:
            return candidate
        n += 1
    # Fall-through: append a short random tag so the load never aborts
    # purely because the suffix counter ran away.
    import secrets as _secrets
    return f"{base} {suffix} {_secrets.token_hex(3)}"


def _classify_collisions(
    new_items: "list[dict]",
    existing_items: "list[dict]",
    *,
    name_key: str = "name",
    content_fn=None,
) -> dict:
    """Pure classifier for load-time name/content collisions.

    Returns a dict with three lists keyed by the new-item index:
      * ``"new"``         — indices safe to add as-is
      * ``"exact_copy"``  — indices whose (name, content) matches an
                            existing entry exactly
      * ``"collision"``   — indices whose name matches an existing entry
                            but content differs

    ``content_fn`` extracts the content identity from an entry dict.
    Defaults to a JSON-serialisable hash of every field except ``name`` /
    ``id`` / timestamps / ephemeral metadata, so subsystems can override
    with a cheaper / more semantically meaningful key (e.g. the GenBank
    sequence for plasmids, the DNA sequence + grammar for parts).

    Cross-batch awareness: items earlier in ``new_items`` count as
    "existing" for items later in the batch. So a load of [A, A] gets
    classified as [new, exact_copy] rather than [new, new] — the user
    sees the second copy as a duplicate of the first.

    Empty ``name`` is treated as non-colliding (no rational dedupe key);
    those items always classify as ``"new"``.
    """
    if content_fn is None:
        def _default_content_fn(item: dict) -> str:
            return repr(sorted(
                (k, v) for k, v in item.items()
                if k not in {"name", "id", "added", "updated_at",
                             "created_at"}
            ))
        content_fn = _default_content_fn
    # Index existing entries by name → list of content keys. ``list``
    # rather than ``set`` so a library legitimately carrying two
    # entries with the same name but different content (legacy data)
    # is still detectable as "no collision" if any one matches.
    by_name: "dict[str, list[str]]" = {}
    for e in existing_items:
        if not isinstance(e, dict):
            continue
        name = e.get(name_key) or ""
        if not name:
            continue
        by_name.setdefault(name, []).append(content_fn(e))
    out: "dict[str, list[int]]" = {
        "new": [], "exact_copy": [], "collision": [],
    }
    for idx, item in enumerate(new_items):
        name = (item.get(name_key) or "") if isinstance(item, dict) else ""
        if not name:
            out["new"].append(idx)
            continue
        ckey = content_fn(item) if isinstance(item, dict) else repr(item)
        existing_keys = by_name.get(name)
        if existing_keys is None:
            out["new"].append(idx)
            # Allow same-batch dedupe: register this item as existing
            # for subsequent items in the loop.
            by_name[name] = [ckey]
            continue
        if ckey in existing_keys:
            out["exact_copy"].append(idx)
        else:
            out["collision"].append(idx)
            existing_keys.append(ckey)
    return out


def _resolve_load_collisions(
    app,
    entity: str,
    new_items: "list[dict]",
    existing_items: "list[dict]",
    *,
    name_key: str = "name",
    content_fn=None,
    on_resolved,
    on_cancelled=None,
) -> None:
    """Generic collision-resolution flow shared by every load path
    (parts bin, plasmid library, primer library, experiments,
    collections, gels, projects).

    Pipeline:
      1. Classify ``new_items`` against ``existing_items`` via
         ``_classify_collisions``.
      2. If exact copies exist → push ``ExactCopyConfirmModal``:
         keep (rename with " COPY" suffix) or skip duplicates.
      3. If name collisions (different content) exist → push
         ``NameCollisionModal``: keep original / overwrite / cancel.
      4. Once user decisions resolved, fire ``on_resolved(
            items_to_save, replace_names)``.

    ``on_resolved`` receives:
      * ``items_to_save`` — concrete list of new items the caller
        should persist (with any " COPY"-renamed names already
        applied).
      * ``replace_names`` — set of existing-entry names the caller
        should REMOVE from ``existing_items`` before appending
        ``items_to_save`` (i.e. overwrite targets). Empty set when
        no overwrites are requested.

    ``on_cancelled`` is fired (when provided) if the user picks Cancel
    on the name-collision modal. Callers should NOT save anything in
    that case — the load is fully aborted.

    Both callbacks run on the UI thread. Workers calling this helper
    must marshal back through ``call_from_thread`` first.

    ``content_fn`` defaults to a JSON-style hash over every field
    except ``name``/``id``/timestamps — usually too strict for
    semantic dedupe. Callers should pass a domain-specific extractor
    (the part's DNA sequence, the plasmid's gb_text, etc.) so a
    primer-Tm round-off doesn't flag a real exact-copy as a name
    collision.
    """
    collisions = _classify_collisions(
        new_items, existing_items,
        name_key=name_key,
        content_fn=content_fn,
    )
    exact_copy_idxs = list(collisions["exact_copy"])
    coll_idxs       = list(collisions["collision"])
    new_only_idxs   = list(collisions["new"])

    if not exact_copy_idxs and not coll_idxs:
        on_resolved(list(new_items), set())
        return

    def _proceed_to_collisions(items_kept_after_copy: "list[dict]") -> None:
        if not coll_idxs:
            on_resolved(items_kept_after_copy, set())
            return
        names = [
            (new_items[i].get(name_key, "?") if isinstance(new_items[i], dict) else "?")
            for i in coll_idxs
        ]

        def _on_decision(decision):
            if decision in (None, "cancel"):
                if on_cancelled is not None:
                    on_cancelled()
                return
            if decision == "keep":
                on_resolved(items_kept_after_copy, set())
                return
            # "overwrite" — append collision items + flag the colliding
            # names for removal from existing.
            replace_names = {
                (new_items[i].get(name_key, "") if isinstance(new_items[i], dict) else "")
                for i in coll_idxs
            }
            replace_names.discard("")
            items_with_coll = items_kept_after_copy + [
                new_items[i] for i in coll_idxs
            ]
            on_resolved(items_with_coll, replace_names)

        app.push_screen(
            NameCollisionModal(entity, names),
            callback=_on_decision,
        )

    if exact_copy_idxs:
        copy_names = [
            (new_items[i].get(name_key, "?") if isinstance(new_items[i], dict) else "?")
            for i in exact_copy_idxs
        ]

        def _on_copy(keep_copies):
            keep_copies = bool(keep_copies)
            if not keep_copies:
                items_kept = [new_items[i] for i in new_only_idxs]
                _proceed_to_collisions(items_kept)
                return
            existing_names: "set[str]" = {
                e.get(name_key, "") for e in existing_items
                if isinstance(e, dict)
            }
            existing_names.discard("")
            # Reserve names that other items in THIS batch will use so
            # the COPY suffix doesn't clash with a non-duplicate sibling.
            for i in new_only_idxs + coll_idxs:
                if isinstance(new_items[i], dict):
                    nm = new_items[i].get(name_key, "")
                    if nm:
                        existing_names.add(nm)
            items_kept = [new_items[i] for i in new_only_idxs]
            for i in exact_copy_idxs:
                if not isinstance(new_items[i], dict):
                    continue
                base = new_items[i].get(name_key, "") or ""
                renamed = _ensure_unique_copy_name(base, existing_names)
                # Mutate in place so the caller's reference reflects the
                # new name (mirrors the existing pattern of mutating
                # part_entry dicts inside the bulk worker).
                new_items[i][name_key] = renamed
                existing_names.add(renamed)
                items_kept.append(new_items[i])
            _proceed_to_collisions(items_kept)

        app.push_screen(
            ExactCopyConfirmModal(entity, copy_names),
            callback=_on_copy,
        )
        return

    _proceed_to_collisions([new_items[i] for i in new_only_idxs])


class _SearchInput(Input):
    """Reusable search-bar Input.

    Three reusable behaviours that every search bar in the app wants
    consistently:

    1. **Prefill / placeholder hybrid.** ``PREFILL`` is shown when the
       field is unfocused + empty; clicking into the field clears it
       so the user types into a fresh cursor. Blurring an empty field
       restores the prefill. The PREFILL string also counts as
       "empty" in `query()` so a user mashing Enter without focusing
       first doesn't search for the literal word "Search".

    2. **Optional live-filter debouncing.** When the parent passes
       ``debounce_s=<seconds>`` + ``on_filter=<callable>``, every
       keystroke schedules a single timer; rapid typing coalesces
       into one call. With ``debounce_s=None`` (default) the widget
       behaves identically to plain ``Input`` and the parent listens
       to ``Input.Submitted`` for Enter-to-apply UX. The debounce
       timer is cancelled on unmount so a queued tick can't fire
       against a disposed widget tree.

    3. **Length cap.** Defaults to ``DEFAULT_MAX_LEN = 200``. Longer
       pastes (e.g. an accidental clipboard dump) are silently
       truncated. The fuzzy matcher is O(query × name); without a
       cap a 100k-char paste against a 5k-plasmid library would lock
       the UI for seconds before any debounce fires.

    Pre-2026-05-10 this class had only the focus-clear behaviour and
    every site that wanted debounce / cleanup / cap rolled its own.
    The four search bars in the app (LibraryPanel, LibrarySearchModal,
    LoadPartSourceModal, SpeciesPickerModal) used 4 slightly-different
    patterns; the consolidated widget is the one place to fix
    behaviour bugs going forward.
    """
    PREFILL = "Search"
    DEFAULT_MAX_LEN = 200

    def __init__(
        self,
        *args,
        prefill: "str | None" = None,
        debounce_s: "float | None" = None,
        max_len: int = DEFAULT_MAX_LEN,
        on_filter=None,
        **kwargs,
    ):
        # Default prefill to the class constant; allow opt-out by
        # passing ``prefill=""`` so a caller that wants placeholder-
        # only behaviour gets a plain Input visually.
        if prefill is None:
            prefill = self.PREFILL
        # Use the prefill as the initial value if the caller didn't
        # pass one explicitly. ``None`` is the sentinel for "use the
        # prefill"; ``""`` is the sentinel for "start empty".
        if "value" not in kwargs:
            kwargs["value"] = prefill
        super().__init__(*args, **kwargs)
        self._prefill = prefill
        self._debounce_s = debounce_s
        self._max_len = max(1, int(max_len))
        self._on_filter = on_filter
        self._filter_timer = None

    def on_focus(self, _event) -> None:
        # Always blank the field on focus gain — matches the spec
        # "clicking into … the textbox clears and a cursor appears".
        if self.value == self._prefill:
            self.value = ""

    def on_blur(self, _event) -> None:
        # Restoring the prefill on blur (empty field only) keeps the
        # idle UI readable — without this, a user who clicked away
        # without typing would see an empty field with no affordance
        # cue. Whitespace-only counts as empty.
        if not self.value.strip():
            try:
                self.value = self._prefill
            except Exception:
                # Defensive — Input.value setter could fail mid-
                # teardown; the next on_focus / clear() will recover.
                pass

    def on_input_changed(self, event) -> None:
        # Length cap is a hard truncate. Setting `self.value` here
        # re-triggers Input.Changed; the second pass reads the
        # truncated value, hits the equality check, and skips the
        # truncate path. So we don't need an explicit re-entrancy
        # guard — but we DO need to bail before scheduling a debounce
        # for the truncate-pass, since we'll be back here in 1 µs.
        if len(self.value) > self._max_len:
            self.value = self.value[: self._max_len]
            return
        # No callback / no debounce → behave like a plain Input.
        if self._on_filter is None or self._debounce_s is None:
            return
        # Cancel any pending tick before scheduling a fresh one;
        # without this a burst of N keystrokes spawns N timers and
        # the filter callback fires N times after debounce_s.
        if self._filter_timer is not None:
            try:
                self._filter_timer.stop()
            except Exception:
                pass
        try:
            self._filter_timer = self.set_timer(
                self._debounce_s, self._fire_filter,
            )
        except Exception:
            # Timer setup can race with unmount; fall back to a
            # synchronous fire so the user's keystroke isn't lost.
            self._filter_timer = None
            self._fire_filter()

    def _fire_filter(self) -> None:
        """Invoke the ``on_filter`` callback with the sanitised query.
        Wrapped in try/except so a callback that raises (e.g. a stale
        widget query during unmount) doesn't poison the timer."""
        if self._on_filter is None:
            return
        try:
            self._on_filter(self.current_query())
        except Exception:
            _log.exception(
                "_SearchInput: on_filter callback raised on query %r",
                self.value,
            )

    def current_query(self) -> str:
        """Return the sanitised query string. Strips outer whitespace
        and treats the prefill as empty so a user who didn't focus
        the field doesn't search for the placeholder text.

        Named ``current_query`` (not ``query``) to avoid colliding
        with ``Widget.query(selector)`` from Textual's DOMNode API,
        which would otherwise be shadowed by the same-name override.
        """
        v = (self.value or "").strip()
        if v == self._prefill:
            return ""
        return v

    def clear(self) -> None:
        """Reset the input to prefill state and cancel any pending
        debounce. Idempotent — safe to call from a parent's
        view-mode-switch path that also fires `on_unmount` shortly
        afterward."""
        try:
            self.value = self._prefill
        except Exception:
            pass
        if self._filter_timer is not None:
            try:
                self._filter_timer.stop()
            except Exception:
                pass
            self._filter_timer = None

    def on_unmount(self) -> None:
        # Cancel the pending debounce so a queued tick doesn't fire
        # against a disposed widget tree — the callback typically
        # `query_one`s into the parent's table, which would raise
        # NoMatches (caught) but log a noisy warning. Wiping the
        # slot keeps the tear-down clean.
        if self._filter_timer is not None:
            try:
                self._filter_timer.stop()
            except Exception:
                pass
            self._filter_timer = None


class LibraryPanel(Widget):
    """Left-hand plasmid panel — toggles between a *collections* list and
    the active collection's *plasmids* view.

    Two modes:
      * ``"collections"`` — a list of named collections. ``+ / − / ✎``
        buttons add / remove / rename collections in-place; clicking a
        row enters that collection's plasmid view.
      * ``"plasmids"`` — the existing per-plasmid view (the CommercialSaaS-
        style library list). ``←`` returns to the collections view;
        ``+`` saves the currently-loaded record into the active
        collection (via ``_save_library`` → ``_sync_active_collection_plasmids``).

    The two on-disk files (``plasmid_library.json`` + ``collections.json``)
    stay in sync because every mutation routes through ``_save_library``,
    which mirrors entries into the active collection.
    """

    DEFAULT_CSS = """
    LibraryPanel {
        /* Panel width is fixed at the sum of the plasmid-view button
           row: 4 buttons × min-width 5 + 4 × 1 left-margin = 24, plus
           1 cell of trailing slack = 25. Names / status / bp wider
           than the panel show via the DataTable's built-in horizontal
           scrollbar (overflow-x: auto on the tables below). Pre-2026-05-06
           the panel grew to fit the longest plasmid name (capped at 30+
           cells), which ate map space on libraries with descriptive
           names; the fixed-width + scroll model gives the map the most
           real estate while still letting the user pan to any cell. */
        width: 25;
    }
    /* Subtle "you are here" brighten when focus is anywhere inside
       the panel (collections table, plasmids table, search input).
       See PlasmidMap for the colour rationale. */
    LibraryPanel:focus-within { background: #0c0c0c; }
    #lib-hdr        { background: $primary; padding: 0 1; }
    /* Search input lives directly under the header; height 3 is the
       Textual Input default (1 content row + 2 border rows). */
    #lib-search     { height: 3; margin: 0; }
    /* `overflow-x: auto` exposes a horizontal scrollbar when a row's
       columns exceed the panel's viewport width. The 1-cell extra
       height (4 instead of 3) reserves space for the scrollbar so
       it doesn't eat the bottom row when it appears. */
    #lib-table      { height: 1fr; overflow-x: auto; }
    #lib-coll-table { height: 1fr; overflow-x: auto; }
    #lib-btns       { height: 3; }
    #lib-btns Button       { min-width: 5; margin: 0 0 0 1; }
    #lib-coll-btns         { height: 3; }
    #lib-coll-btns Button  { min-width: 5; margin: 0 0 0 1; }
    """

    # Key binding fires on the panel's focused descendant — primarily
    # the DataTable rows. Doesn't conflict with the `_SearchInput`
    # since text inputs swallow `s` as a normal character.
    BINDINGS = [
        Binding("s", "request_status", "Set status",
                show=False, priority=False),
        Binding("h", "request_history", "View history",
                show=False, priority=False),
    ]

    def action_request_history(self) -> None:
        """Open the construction-history viewer for the cursor row.
        No-op in collections view + when the cursor is empty.
        Imported CommercialSaaS plasmids carry a `history_xml` field on
        their library entry; SpliceCraft-built constructions get one
        attached at Save time. Entries without history surface a
        gentle "no history" notify rather than a blank modal."""
        if self._view_mode != "plasmids":
            return
        try:
            t = self.query_one("#lib-table", DataTable)
        except NoMatches:
            return
        self.post_message(self.HistoryRequested(_cursor_row_key(t)))

    def action_request_status(self) -> None:
        """Posted up to the app, which opens `PlasmidStatusPickerModal`
        for the cursor row of the visible plasmid table. No-op when
        we're in collections view (cursor would be on a collection,
        not a plasmid)."""
        if self._view_mode != "plasmids":
            return
        try:
            t = self.query_one("#lib-table", DataTable)
        except NoMatches:
            return
        self.post_message(self.StatusRequested(_cursor_row_key(t)))

    class PlasmidLoad(Message):
        """User selected a library entry to load."""
        def __init__(self, entry: dict):
            self.entry = entry
            super().__init__()

    class AddCurrentRequested(Message):
        """User pressed '+' to add the currently-loaded record."""
        pass

    class RenameRequested(Message):
        """User pressed the rename (✎) button with a library row focused.
        entry_id is the library key of the row with the cursor."""
        def __init__(self, entry_id: "str | None"):
            self.entry_id = entry_id
            super().__init__()

    class StatusRequested(Message):
        """User triggered the workflow-status picker for a library row
        (key binding `s` on the plasmid table). entry_id is the
        library key of the cursor row, or None if the cursor isn't
        on a row yet — the app handler turns the latter into a
        gentle "highlight a row first" notification."""
        def __init__(self, entry_id: "str | None"):
            self.entry_id = entry_id
            super().__init__()

    class HistoryRequested(Message):
        """User pressed `h` on a library row — open the construction-
        history viewer. entry_id is the cursor row's library key
        (or None if the cursor wasn't on a row); the app handler
        loads the entry, parses its `history_xml` if present, and
        pushes `HistoryViewerModal`."""
        def __init__(self, entry_id: "str | None"):
            self.entry_id = entry_id
            super().__init__()

    class GainedFocus(Message):
        """Posted when the library panel (or any descendant) gains focus.
        The app handles this by clearing the currently-selected feature so
        pressing Delete in the library cannot accidentally hit a feature
        that's no longer visually in focus."""
        pass

    class CollectionSwitched(Message):
        """User picked a different collection — library has been swapped.
        The app refreshes its caches in response (no record changes)."""
        def __init__(self, name: str):
            self.name = name
            super().__init__()

    def on_descendant_focus(self, _event):
        # DataTable inside the library panel is what actually gets focus;
        # Textual reports it to us via a DescendantFocus event. Propagate
        # to the app as a panel-level signal.
        self.post_message(self.GainedFocus())

    def compose(self) -> ComposeResult:
        yield Static(" Collections", id="lib-hdr")
        # Collections-view widgets ────────────────────────────────────
        yield DataTable(id="lib-coll-table", cursor_type="row",
                        zebra_stripes=True)
        # Plasmids-view widgets ────────────────────────────────────
        yield DataTable(id="lib-table", cursor_type="row",
                        zebra_stripes=True)
        # One shared search input sits between the tables and the
        # button row so it lives just above whichever button bar is
        # currently visible. Pre-filled with "Search"; on focus the
        # value is cleared (see `_SearchInput`). Submitted handler
        # applies a fuzzy filter (or clears it on empty submit and
        # restores the prefill).
        yield _SearchInput(value=_SearchInput.PREFILL, id="lib-search")
        with Horizontal(id="lib-coll-btns"):
            yield Button("+", id="btn-coll-add", variant="primary",
                         tooltip="New collection")
            yield Button("−", id="btn-coll-del", variant="error",
                         tooltip="Remove selected collection")
            yield Button("✎", id="btn-coll-rename", variant="default",
                         tooltip="Rename selected collection")
        with Horizontal(id="lib-btns"):
            yield Button("+", id="btn-lib-add", variant="primary",
                         tooltip="Open a plasmid file (.gb / .gbk / .dna / FASTA)")
            yield Button("−", id="btn-lib-del", variant="error",
                         tooltip="Remove selected plasmid")
            yield Button("←", id="btn-lib-back", variant="primary",
                         tooltip="Back to collections")
            yield Button("✎", id="btn-lib-rename", variant="default",
                         tooltip="Rename selected plasmid")

    def on_mount(self):
        self._active_id:    "str | None" = None
        self._active_dirty: bool         = False
        # Active fuzzy filter text. Empty string = no filter (show all
        # rows). Set/cleared by `_on_search_submitted`; consulted in
        # `_repopulate_*`.
        self._filter_text:  str          = ""
        # Start in plasmids view if the user already has an active
        # collection (returning user picks up where they left off);
        # else show the collections list so they can pick.
        self._view_mode: str = (
            "plasmids" if _get_active_collection_name() else "collections"
        )
        # Two-click activation guard for collection rows — armed by the
        # first RowSelected, disarmed by a 1.5 s timer or by switching
        # rows. See `_coll_row_selected`.
        self._coll_armed_name: "str | None" = None
        self._coll_arm_timer = None
        coll = self.query_one("#lib-coll-table", DataTable)
        coll.add_columns("Name", "Plasmids")
        plas = self.query_one("#lib-table", DataTable)
        plas.add_columns("Name", "Status", "bp")
        self._apply_view_mode()
        self._apply_panel_width()
        self._repopulate()

    @on(Input.Submitted, "#lib-search")
    def _on_search_submitted(self, event: Input.Submitted) -> None:
        """Enter on the search field: empty value clears the filter and
        restores 'Search' prefill; non-empty value applies a fuzzy
        filter to whichever table is currently visible. The literal
        prefill string also counts as 'empty' so a user mashing Enter
        without first clicking through doesn't search for 'Search'."""
        text = event.value.strip()
        if not text or text == _SearchInput.PREFILL:
            self._filter_text = ""
            event.input.value = _SearchInput.PREFILL
        else:
            self._filter_text = text
            # Leave value as the user typed it so they can see what's
            # filtering; click+Enter clears it back to PREFILL.
        self._repopulate()

    # ── View-mode toggle ────────────────────────────────────────────────────

    def _apply_view_mode(self) -> None:
        is_coll = (self._view_mode == "collections")
        try:
            self.query_one("#lib-coll-table").display = is_coll
            self.query_one("#lib-coll-btns").display  = is_coll
            self.query_one("#lib-table").display      = not is_coll
            self.query_one("#lib-btns").display       = not is_coll
        except NoMatches:
            return
        # Switching views invalidates the search query — both
        # `_repopulate_collections` and `_repopulate_plasmids` filter
        # against `_filter_text`, so a stale plasmid query carrying
        # over to collections (or vice versa) silently hides the
        # entire next-view list. Pre-2026-05-10 a user typing in the
        # search bar then pressing the back button saw an empty
        # collections panel because the leftover plasmid query
        # filtered every collection out.
        self._reset_search()
        self._update_header()

    def _reset_search(self) -> None:
        """Clear the search filter + reset the Input to its prefill
        text. Called from `_apply_view_mode` on every view-mode
        switch so a query from one view doesn't leak into the other.
        Best-effort — falls through quietly if the search Input
        isn't mounted (compose hasn't run yet)."""
        self._filter_text = ""
        try:
            inp = self.query_one("#lib-search", _SearchInput)
            inp.clear()
        except NoMatches:
            pass

    def _update_header(self) -> None:
        try:
            hdr = self.query_one("#lib-hdr", Static)
        except NoMatches:
            return
        # Dirty marker shows in BOTH views — even in collections view
        # the user should see at a glance that there are unsaved edits
        # somewhere in the active collection.
        prefix = "* " if self._active_dirty else " "
        if self._view_mode == "collections":
            hdr.update(f"{prefix}Collections")
            return
        active = _get_active_collection_name() or "Library"
        # Cap to keep the 26-cell-wide panel from overflowing; reserve
        # 2 cells for the dirty marker.
        hdr.update(f"{prefix}{active[:22]}")

    # ── Repopulate dispatch ────────────────────────────────────────────────

    def _repopulate(self) -> None:
        # Re-measure the longest name on every repopulate — content
        # can change underfoot via add/remove/rename, library load,
        # or collection swap. Pre-fix (audit HIGH-2, 2026-05-14)
        # `_apply_panel_width` and the per-view repopulate methods
        # each independently called `_compute_name_col_width`, which
        # fired `_load_library() + _load_collections()` twice (three
        # `_typed_clone`s per repop). Now: load each once, compute
        # the width once, pass both into the per-view methods.
        lib_entries = _load_library()
        coll_entries = _load_collections()
        name_w = self._compute_name_col_width(lib_entries, coll_entries)
        self._apply_panel_width(name_w)
        if self._view_mode == "collections":
            self._repopulate_collections(
                name_w=name_w, coll_entries=coll_entries,
            )
        else:
            self._repopulate_plasmids(
                name_w=name_w, lib_entries=lib_entries,
            )

    # Column-width budget. The panel itself is fixed-width (CSS), so
    # these only size the columns inside the DataTable; columns wider
    # than the panel viewport scroll horizontally via `overflow-x: auto`.
    # The name column floor protects short-name libraries from a
    # painfully narrow column; the ceiling caps absurd 200-char names
    # so a single outlier doesn't make the user pan dozens of cells
    # to reach the status column.
    _NAME_COL_FLOOR  = 12
    _NAME_COL_CEIL   = 30
    _STATUS_COL_W    = 12
    _BP_COL_W        = 9

    def _compute_name_col_width(
            self,
            lib_entries: "list[dict] | None" = None,
            coll_entries: "list[dict] | None" = None,
    ) -> int:
        """Longest plasmid + collection name in cells, clamped to
        `[_NAME_COL_FLOOR, _NAME_COL_CEIL]`. Both DataTables share
        this so the two views stay visually aligned when the user
        toggles between them.

        The +2 is the colour-circle prefix: `● ` always reserves
        two cells on plasmid rows even when no status is set, so
        names don't shift left/right when the user assigns a
        status. Collection names skip the circle but are still
        sized against the same width so the panel doesn't reflow.

        Callers pre-loading the library / collections for a
        repopulate cycle can pass them as args to avoid the duplicate
        `_typed_clone` cost; standalone callers (rare) fall back to
        a fresh load.
        """
        if lib_entries is None:
            lib_entries = _load_library()
        if coll_entries is None:
            coll_entries = _load_collections()
        max_name = 0
        for entry in lib_entries:
            n = len(str(entry.get("name") or entry.get("id") or ""))
            if n > max_name:
                max_name = n
        for c in coll_entries:
            n = len(str(c.get("name") or ""))
            if n > max_name:
                max_name = n
        # `+2` accounts for the circle prefix on plasmid rows.
        return max(self._NAME_COL_FLOOR,
                    min(max_name + 2, self._NAME_COL_CEIL))

    def _apply_panel_width(self, name_w: "int | None" = None) -> None:
        """Resize the plasmid DataTable's name column to fit the
        longest current entry. The panel itself is fixed-width via
        CSS — pre-2026-05-06 this method also grew the panel to fit
        the longest name, which ate map real estate; now over-wide
        column content scrolls horizontally inside the table.

        ``name_w`` is the pre-computed width when called from
        `_repopulate` (avoiding a duplicate `_compute_name_col_width`
        invocation); legacy callers without the arg get the fresh
        compute.
        """
        if name_w is None:
            name_w = self._compute_name_col_width()
        # Resize the column itself so the rendered name occupies
        # the new width. Textual's DataTable uses content-driven
        # auto-sizing by default, so explicit column widths keep
        # both views (collections + plasmids) aligned.
        try:
            for tid in ("#lib-table", "#lib-coll-table"):
                t = self.query_one(tid, DataTable)
                if t.columns:
                    name_col = next(iter(t.columns.values()))
                    name_col.width = name_w
        except (NoMatches, AttributeError, StopIteration):
            pass

    def _repopulate_collections(
            self,
            name_w: "int | None" = None,
            coll_entries: "list[dict] | None" = None,
    ) -> None:
        t = self.query_one("#lib-coll-table", DataTable)
        t.clear()
        flt = self._filter_text
        if coll_entries is None:
            coll_entries = _load_collections()
        if name_w is None:
            name_w = self._compute_name_col_width(coll_entries=coll_entries)
        # Natural sort by display name so `Backbones 2`, `Backbones 10`
        # land in human-readable order instead of lexicographic
        # `Backbones 10`, `Backbones 2`.
        for c in sorted(coll_entries,
                         key=lambda x: _natural_sort_key(x.get("name") or "")):
            name = c.get("name") or "?"
            if not _fuzzy_match(flt, name):
                continue
            n_plas = len(c.get("plasmids", []) or [])
            # Wrap in Text() so any markup chars (e.g. a collection
            # named "[red]x[/red]") render literally — Text(str) is
            # opaque to Rich's markup parser, unlike a bare string.
            t.add_row(Text(name[:name_w]), str(n_plas), key=name)

    def _repopulate_plasmids(
            self,
            name_w: "int | None" = None,
            lib_entries: "list[dict] | None" = None,
    ) -> None:
        t = self.query_one("#lib-table", DataTable)
        t.clear()
        flt = self._filter_text
        if lib_entries is None:
            lib_entries = _load_library()
        if name_w is None:
            name_w = self._compute_name_col_width(lib_entries=lib_entries)
        # Inner name budget after the 2-cell circle prefix is
        # reserved on every plasmid row.
        name_inner = max(1, name_w - 2)
        # Natural sort by name (`pBin2` before `pBin10`) — see
        # `_natural_sort_key`. Splits each name into text + integer
        # runs so the sort respects numeric magnitude rather than the
        # lexicographic `pBin10 < pBin2 < pBin20` ordering.
        # Reuse `lib_entries` instead of re-loading: the pre-0.8.9
        # `_load_library()` call here was a redundant `_typed_clone`
        # of the entire cached library (hundreds of ms on a 1000-row
        # library with `gb_text` blobs) — fired on every Filter
        # keystroke. The caller has already loaded once at line 12861.
        for entry in sorted(lib_entries,
                             key=lambda e: _natural_sort_key(
                                 e.get("name") or e.get("id") or "")):
            name = entry.get("name") or entry.get("id") or "?"
            if not _fuzzy_match(flt, name):
                continue
            is_dirty = (entry["id"] == self._active_id and self._active_dirty)
            name_disp = ("*" + name) if is_dirty else name
            name_disp = name_disp[:name_inner]
            status = _sanitize_plasmid_status(entry.get("status"))
            color  = _PLASMID_STATUS_COLORS.get(status)
            # Build the name cell as a `Text` so the circle prefix
            # gets its own colour while the name itself stays the
            # default foreground (otherwise long names tint).
            name_cell = Text(no_wrap=True, overflow="ellipsis")
            if color is not None:
                name_cell.append("● ", style=color)
            else:
                # Reserve the same 2 cells for "no status" entries
                # so the names align column-wise. Empty space, no
                # background tint.
                name_cell.append("  ")
            name_cell.append(name_disp)
            # Status column: coloured workflow tag, or a dim em-dash
            # when no status is set.
            if status and color is not None:
                status_cell = Text(status,
                                    style=f"{color} bold")
            else:
                status_cell = Text("—", style="dim")
            t.add_row(
                name_cell,
                status_cell,
                f"{entry['size']:,}",
                key=entry["id"],
            )

    # ── Plasmid view: existing flow + back button ──────────────────────────

    def add_entry(self, record) -> bool:
        """Serialize record and persist into the active collection.

        Returns True on a successful save (cache updated, disk write
        dispatched), False on disk failure. The caller can use this
        to gate a "saved" notification.

        Preserves any existing workflow `status` on the entry —
        re-saving a plasmid that was already marked VERIFIED keeps
        the green badge instead of resetting to "no status".

        Collision contract (added 2026-05-20):
          * Same ``id`` as an existing entry → silent replace
            (treated as "editing the same record", NOT a collision).
          * Same name as an existing entry, same gb_text → push
            ``ExactCopyConfirmModal``: keep as " COPY" or skip.
          * Same name, different gb_text → push ``NameCollisionModal``:
            keep original / overwrite / cancel.

        When a modal fires, this method returns True optimistically
        (cache will update once the user picks; if they cancel, the
        library is unchanged). Callers should NOT rely on the cache
        being updated before this returns — that's the modal's job.
        """
        gb_text = _record_to_gb_text(record)
        entries = _load_library()
        prev_status = ""
        for e in entries:
            if e.get("id") == record.id:
                prev_status = _sanitize_plasmid_status(e.get("status"))
                break
        # Pre-build the new entry dict so collision detection can
        # compare against it directly.
        display_name = (
            getattr(record, "_tui_display_name", None)
            or record.name or record.id
        )
        new_entry = {
            "name":    display_name,
            "id":      record.id,
            "size":    len(record.seq),
            "n_feats": len([f for f in record.features if f.type != "source"]),
            "source":  getattr(record, "_tui_source", f"id:{record.id}"),
            "added":   _date.today().isoformat(),
            "gb_text": gb_text,
            "status":  prev_status,
        }
        # ID match takes precedence over name match — re-saving an
        # already-loaded record (same id) is the "editing in place"
        # case, never a collision. Strip every same-id entry then add
        # the new one at the top, same contract as before.
        has_id_match = any(e.get("id") == record.id for e in entries)
        if has_id_match:
            entries = [e for e in entries if e.get("id") != record.id]
            entries.insert(0, new_entry)
            self._commit_library_entries(entries)
            return True
        # No id match: check for name collisions against entries whose
        # id differs. ``_resolve_load_collisions`` handles the modal
        # routing and fires our save callback once the user decides.
        same_name_entries = [
            e for e in entries
            if (e.get("name") or "") == display_name
            and e.get("id") != record.id
        ]
        if not same_name_entries:
            entries.insert(0, new_entry)
            self._commit_library_entries(entries)
            return True

        def _content_fn(e: dict) -> str:
            return e.get("gb_text", "") or ""

        def _on_cancelled() -> None:
            self.app.notify(
                f"Plasmid save cancelled. Library unchanged.",
                severity="warning",
            )
            _log_event(
                "library.add.cancelled",
                name=display_name, id=record.id,
            )

        def _on_resolved(items_to_save: "list[dict]",
                         replace_names: "set[str]") -> None:
            if not items_to_save and not replace_names:
                self.app.notify(
                    f"Skipped duplicate plasmid. Library unchanged.",
                    severity="warning",
                )
                _log_event(
                    "library.add.skipped",
                    name=display_name, id=record.id,
                )
                return
            current = _load_library()
            if replace_names:
                current = [
                    e for e in current
                    if (e.get("name") or "") not in replace_names
                ]
            # ``items_to_save`` may have a renamed entry (COPY suffix
            # added during exact-copy resolution); mutate the original
            # record's display name to match so re-saves stay coherent.
            for it in items_to_save:
                if it is new_entry:
                    final_name = it.get("name") or display_name
                    if final_name != display_name:
                        try:
                            record._tui_display_name = final_name  # type: ignore[attr-defined]
                        except Exception:
                            pass
            current = list(items_to_save) + current
            self._commit_library_entries(current)
            _log_event(
                "library.add.ok",
                name=display_name, id=record.id,
                n_overwritten=len(replace_names),
            )

        _resolve_load_collisions(
            self.app, "plasmid", [new_entry], entries,
            name_key="name",
            content_fn=_content_fn,
            on_resolved=_on_resolved,
            on_cancelled=_on_cancelled,
        )
        return True

    def _commit_library_entries(self, entries: "list[dict]") -> None:
        """Sync cache + repopulate + async disk write. Shared exit
        path for both the id-replace branch and the post-modal
        callback in ``add_entry`` so cache hygiene + dependent-cache
        invalidation can't drift between the two.

        Sweep #10 (2026-05-20): takes ``_cache_lock`` around the cache
        reseat so a concurrent ``_save_library`` (constructor save,
        agent endpoint, etc.) can't race the reassignment. The cache
        and disk update are still split (sync cache, async disk) for
        UI responsiveness — the lock just prevents the reassignment
        from interleaving with another save's reassignment.
        """
        global _library_cache
        with _cache_lock:
            _library_cache = _typed_clone(entries)
        _clear_primer_cache = globals().get("_primer_usage_clear_cache")
        if _clear_primer_cache is not None:
            _clear_primer_cache()
        if self._view_mode == "plasmids":
            self._apply_panel_width()
            self._repopulate_plasmids()
        # Disk write off-thread. Failure surfaces via
        # ``_notify_save_failure`` from inside the worker.
        self._add_save_to_disk(entries)

    def add_entries_batch(
        self,
        records: "list",
        *,
        on_done,
    ) -> None:
        """Batch counterpart to ``add_entry`` for paths that need to
        load N records and surface ONE collision flow + ONE final toast.

        Single-call collision resolution: the loop pre-classifies every
        record against the current library, then routes the WHOLE batch
        through ``_resolve_load_collisions`` once. The user sees at most
        one exact-copy modal + one name-collision modal, regardless of
        batch size, instead of N stacked modals that would blow past
        ``_MODAL_STACK_SOFT_CAP`` and silently default-resolve.

        Cancel on the name-collision modal aborts the entire batch (no
        records saved); ``on_done`` fires with empty saved/replaced sets.

        Sweep #10 (2026-05-20): closes the ``_save_to_collection`` bug
        where the loop fired N `add_entry` calls and the post-loop toast
        claimed success before any modal resolved.

        ``records`` — SeqRecord-shaped objects (must have
            ``id``/``name``/``seq``/``features``).
        ``on_done(saved_names: list[str], replaced_names: set[str], cancelled: bool)``
            — fires exactly once when the batch resolves (or is
            cancelled). Caller emits the summary toast from here.
        """
        if not records:
            on_done([], set(), False)
            return

        # Build the prospective entry-dicts so collision detection can
        # operate on the same shape `add_entry` produces.
        existing = _load_library()
        existing_ids = {e.get("id") for e in existing if isinstance(e, dict)}
        prospective: list[dict] = []
        # Records whose id matches an existing entry use the silent
        # replace-by-id path (mirrors `add_entry`'s id-match branch);
        # they aren't routed through the modal flow.
        silent_replace_ids: set[str] = set()
        for record in records:
            try:
                gb_text = _record_to_gb_text(record)
            except Exception:
                _log.exception("add_entries_batch: gb serialise failed")
                continue
            prev_status = ""
            # `record.id` is typically a non-empty string from
            # BioPython but defensively coerce — `add()` rejects None
            # and we'd surface a TypeError if a hostile / partially-
            # constructed record reached this loop.
            rec_id = str(record.id) if record.id else ""
            if rec_id and rec_id in existing_ids:
                for e in existing:
                    if e.get("id") == rec_id:
                        prev_status = _sanitize_plasmid_status(
                            e.get("status"),
                        )
                        silent_replace_ids.add(rec_id)
                        break
            display_name = (
                getattr(record, "_tui_display_name", None)
                or record.name or record.id
            )
            prospective.append({
                "name":    display_name,
                "id":      record.id,
                "size":    len(record.seq),
                "n_feats": len([
                    f for f in record.features if f.type != "source"
                ]),
                "source":  getattr(
                    record, "_tui_source", f"id:{record.id}",
                ),
                "added":   _date.today().isoformat(),
                "gb_text": gb_text,
                "status":  prev_status,
                # Pin the originating record so the post-resolve commit
                # can re-stamp its ``_tui_display_name`` if the user
                # picked the COPY-rename branch.
                "_record": record,
            })

        # Strip the temporary _record key from the persistence-shape
        # dict before saving (we need it for the on_resolved callback
        # but it's not part of the persisted schema).
        def _strip_record_ref(entry: dict) -> dict:
            return {k: v for k, v in entry.items() if k != "_record"}

        def _content_fn(e: dict) -> str:
            return e.get("gb_text", "") or ""

        # Collisions are only checked for records WITHOUT an id match.
        # Same-id is "editing the same record" not "collision".
        new_for_collision = [
            p for p in prospective
            if p.get("id") not in silent_replace_ids
        ]
        # Filter out the silent-replace ones from `existing` for the
        # collision check so they don't double-count as name collisions
        # against their own pre-state.
        existing_for_collision = [
            e for e in existing
            if e.get("id") not in silent_replace_ids
        ]

        def _on_cancelled() -> None:
            on_done([], set(), True)

        def _on_resolved(items_kept: "list[dict]",
                         replace_names: "set[str]") -> None:
            current = _load_library()
            # Drop silent-replace ids first.
            if silent_replace_ids:
                current = [
                    e for e in current
                    if e.get("id") not in silent_replace_ids
                ]
            # Then drop name-replace targets from the overwrite branch.
            if replace_names:
                current = [
                    e for e in current
                    if (e.get("name") or "") not in replace_names
                ]
            # Prepend the silent-replace items AND the resolved items at
            # the top. Persist the (possibly COPY-renamed) display name
            # back onto the source record so a later re-save stays
            # coherent.
            id_replace_items = [
                _strip_record_ref(p) for p in prospective
                if p.get("id") in silent_replace_ids
            ]
            keep_items = []
            for it in items_kept:
                rec = it.get("_record")
                final_name = it.get("name") or ""
                if rec is not None and final_name:
                    try:
                        rec._tui_display_name = final_name  # type: ignore[attr-defined]
                    except Exception:
                        pass
                keep_items.append(_strip_record_ref(it))
            final = keep_items + id_replace_items + current
            self._commit_library_entries(final)
            saved_names = [it.get("name", "?") for it in keep_items]
            saved_names += [it.get("name", "?") for it in id_replace_items]
            on_done(saved_names, replace_names, False)

        _resolve_load_collisions(
            self.app, "plasmid",
            new_for_collision, existing_for_collision,
            name_key="name",
            content_fn=_content_fn,
            on_resolved=_on_resolved,
            on_cancelled=_on_cancelled,
        )

    @work(thread=True, exclusive=True, group="auto_bind_evs")
    def _auto_bind_worker(
        self, entries: "list[dict]", collection_name: str,
    ) -> None:
        """Worker: off-thread entry-vector auto-bind after a bulk
        folder import.

        Sweep #11 (2026-05-20): pre-fix the auto-bind ran on the UI
        thread immediately after `_bulk_import_folder` returned, so a
        100-entry × 3-grammar import froze the UI for several seconds
        between the import progress bar finishing and the success
        toast appearing. Now the import-success toast fires
        immediately and this worker emits a follow-up notify when the
        detect + persist completes.

        Exclusive group `auto_bind_evs` coalesces back-to-back imports
        so two rapid clicks on Import don't race the same
        `entry_vectors.json` write.
        """
        try:
            autodetect_msg = _auto_bind_entry_vectors_from_entries(
                entries
            )
        except Exception as exc:
            _log.exception("auto-bind worker: detection failed")
            self.app.call_from_thread(
                self.app.notify,
                f"Entry-vector auto-detect failed for '{collection_name}'"
                f" — see log. Bindings unchanged.",
                severity="warning", markup=False,
            )
            return
        if autodetect_msg:
            self.app.call_from_thread(
                self.app.notify,
                f"'{collection_name}': {autodetect_msg}",
                severity="information", markup=False, timeout=8,
            )
        else:
            # No new bindings — silent. Pre-fix the inline path also
            # didn't notify in this case.
            _log_event(
                "entry_vector.auto_bound.empty",
                collection=collection_name,
                n_entries=len(entries),
            )

    @work(thread=True, exclusive=True, group="library_add_save")
    def _add_save_to_disk(self, entries: "list[dict]") -> None:
        """Worker: persist an add_entry off-thread.

        Mirrors `_delete_save_to_disk`. Disk save + active-collection
        mirror (the latter via ``async_write=True`` so back-to-back
        adds coalesce into a single mirror write). Cache update
        already happened on the UI thread before dispatch.
        """
        try:
            _safe_save_json(
                _LIBRARY_FILE, entries, "Plasmid library",
            )
        except (OSError, RuntimeError) as exc:
            _log.exception("Plasmid add: library save failed")
            self.app.call_from_thread(
                _notify_save_failure,
                self.app, "Plasmid library", exc,
            )
            return
        try:
            _sync_active_collection_plasmids(entries, async_write=True)
        except Exception:
            _log.exception(
                "Plasmid add: active-collection mirror dispatch failed",
            )

    def _save_collections_async(self, entries: "list[dict]") -> None:
        """Update the in-memory collections cache synchronously +
        dispatch the disk write off-thread.

        Audit fix 2026-05-14: every UI callsite that ran
        `_save_collections(entries)` (rename / delete / new) was
        blocking the UI for 5–10 s on a 100+ MB collections.json.
        Splits the helper's sync responsibilities (cache + dependent
        cache invalidation) from the slow disk write so the panel
        repopulates instantly.
        """
        global _collections_cache
        _collections_cache = _typed_clone(entries)
        # Same dependent-cache invalidation `_save_collections` does
        # synchronously, preserved here so a freshly-renamed /
        # deleted / new collection doesn't keep returning stale
        # BLAST hits or primer-usage rows.
        _clear_blast = globals().get("_blast_clear_cache")
        if _clear_blast is not None:
            _clear_blast()
        _clear_primer = globals().get("_primer_usage_clear_cache")
        if _clear_primer is not None:
            _clear_primer()
        self._collections_save_to_disk(entries)

    @work(thread=True, exclusive=True, group="collections_save")
    def _collections_save_to_disk(self,
                                    entries: "list[dict]") -> None:
        """Worker: persist a collections rename / delete / new
        off-thread. Cache update already happened on the UI thread
        before dispatch.
        """
        try:
            _safe_save_json(
                _COLLECTIONS_FILE, entries, "Plasmid collections",
            )
        except (OSError, RuntimeError) as exc:
            _log.exception("Plasmid collections: save failed")
            self.app.call_from_thread(
                _notify_save_failure,
                self.app, "Plasmid collections", exc,
            )

    def reveal_entry_id(self, entry_id: str) -> None:
        """Switch to the plasmids view, repopulate, and move the
        cursor to the row whose key matches ``entry_id``. Used by
        flows that just persisted a library entry (Constructor save,
        external imports) so the user sees their new plasmid land
        in-list and focused without scrolling.

        Clears any active search filter so a typed query left from
        an earlier session doesn't hide the just-saved entry. Without
        this, a user who searched for "pUC" then saved a TU named
        "TU_J23100_cscA" would see the constructor "succeed" but the
        library table would render empty — the row was added but the
        filter passed nothing.

        Best-effort: silently no-ops when the panel isn't fully
        composed yet, when the id isn't found post-refresh, or when
        Textual's row-iteration shape changes underneath us. Falls
        back to a plain repop in those cases — the new entry is
        still visible at the top of the natural-sort order."""
        if not entry_id:
            return
        # Clear filter (both in-memory + the search Input's value) so
        # the new row is visible regardless of what the user had
        # typed. `_reset_search` is the canonical helper — it handles
        # the not-yet-mounted case and restores the prefill text.
        try:
            self._reset_search()
        except (NoMatches, AttributeError):
            pass
        if getattr(self, "_view_mode", "plasmids") != "plasmids":
            self._view_mode = "plasmids"
            try:
                self._apply_view_mode()
            except (NoMatches, AttributeError):
                pass
        self._apply_panel_width()
        self._repopulate_plasmids()
        try:
            t = self.query_one("#lib-table", DataTable)
            for i, row_key in enumerate(t.rows.keys()):
                if getattr(row_key, "value", None) == entry_id:
                    t.move_cursor(row=i)
                    break
        except (NoMatches, AttributeError):
            pass

    @on(DataTable.RowSelected, "#lib-table")
    def _row_selected(self, event: DataTable.RowSelected):
        if self._view_mode != "plasmids":
            return
        key = event.row_key.value if event.row_key else None
        if key is None:
            return
        for entry in _load_library():
            if entry.get("id") == key:
                self.post_message(self.PlasmidLoad(entry))
                return

    @on(Button.Pressed, "#btn-lib-back")
    def _btn_back(self):
        # If the loaded plasmid has unsaved edits, prompt before
        # navigating away. Without this, the asterisks in the table /
        # header are a heads-up but it's still easy to forget; the
        # modal forces the user to make a deliberate choice.
        app = self.app
        if not getattr(app, "_unsaved", False):
            self._do_back()
            return

        def _on_response(result: "str | None") -> None:
            if result == "save":
                # _do_save marks clean on success and notifies. If the
                # save fails (e.g. write error), stay in plasmids view
                # so the user can retry.
                do_save = getattr(app, "_do_save", None)
                if callable(do_save) and do_save():
                    self._do_back()
            elif result == "discard":
                discard = getattr(app, "_discard_changes", None)
                if callable(discard):
                    discard()
                self._do_back()
            # None → cancel; user stays in plasmids view.

        app.push_screen(
            UnsavedNavigateModal("go back to collections"),
            callback=_on_response,
        )

    def _do_back(self) -> None:
        """Switch to collections view. Called either directly (no
        unsaved edits) or after the user resolves the unsaved-prompt."""
        self._view_mode = "collections"
        self._apply_view_mode()
        self._repopulate_collections()

    @on(Button.Pressed, "#btn-lib-add")
    def _btn_add(self):
        self.post_message(self.AddCurrentRequested())

    @on(Button.Pressed, "#btn-lib-rename")
    def _btn_rename(self):
        # Rename only works on the row with the DataTable cursor — if the
        # library is empty or no row is focused, we send None and the app
        # will notify the user.
        entry_id = _cursor_row_key(self.query_one("#lib-table", DataTable))
        self.post_message(self.RenameRequested(entry_id))

    def set_active(self, entry_id: "str | None") -> None:
        """Mark which library entry is currently loaded (clears dirty flag)."""
        self._active_id    = entry_id
        self._active_dirty = False

    def set_dirty(self, dirty: bool) -> None:
        """Show unsaved-changes marker on the active row and in the panel header.

        Called from `_mark_dirty`/`_mark_clean` on EVERY keystroke that
        flips `_unsaved`, so we early-return when the state is unchanged
        and skip the table refresh in collections-view mode (where the
        plasmid table isn't visible anyway).
        """
        if self._active_dirty == dirty:
            return
        self._active_dirty = dirty
        if self._view_mode == "plasmids":
            self._refresh_active_row()
        self._update_header()

    def _refresh_active_row(self) -> None:
        """Update just the active plasmid's Name cell, not the whole table.

        Falls back to a full repopulate if the DataTable's incremental
        API isn't available (older Textual) or the active row can't be
        located. The fallback is correctness-preserving but defeats the
        keystroke-hot-path optimisation; it should never fire under
        Textual ≥ 8.2.3 (our pinned floor).
        """
        if not self._active_id:
            return
        try:
            t = self.query_one("#lib-table", DataTable)
        except NoMatches:
            return
        # Sweep #11 (2026-05-20): single-entry lookup via the helper
        # avoids a full library deepcopy (~100 MB on the largest
        # users' setups) per status refresh.
        active_entry = _find_library_entry_by_id(self._active_id or "")
        if active_entry is None:
            return
        nm = active_entry.get("name", "?")
        display = ("*" + nm)[:14] if self._active_dirty else nm[:14]
        try:
            from textual.coordinate import Coordinate
            for i, row_key in enumerate(t.rows.keys()):
                if row_key.value == self._active_id:
                    t.update_cell_at(Coordinate(i, 0), display)
                    return
        except Exception:
            self._repopulate_plasmids()

    @on(Button.Pressed, "#btn-lib-del")
    def _btn_del(self):
        self.request_delete_under_cursor()

    def request_delete_under_cursor(self) -> None:
        """Single entry point for both the `−` button and the keyboard
        Delete key — dispatches to the right confirm flow based on
        view mode. Plasmid view → one confirm; collections view → two
        confirms (the second one is the loud red warning) so a single
        keypress can never wipe out a whole library.
        """
        if self._view_mode == "plasmids":
            self._request_plasmid_delete()
        else:
            self._request_collection_delete()

    def _request_plasmid_delete(self) -> None:
        entry_id = _cursor_row_key(self.query_one("#lib-table", DataTable))
        if entry_id is None:
            return
        # Sweep #11 (2026-05-20): single-entry lookup avoids the
        # whole-library deepcopy on delete (every click).
        entry = _find_library_entry_by_id(entry_id)
        if entry is None:
            return
        name = entry.get("name") or entry_id
        size = entry.get("size", 0) or 0

        def _on_confirm(yes: "bool | None") -> None:
            if not yes:
                return
            # Capture the deleted row's index in the current sorted +
            # filtered display BEFORE any mutation, so we can park the
            # cursor on the row directly above it after repopulate.
            # `LibraryDeleteConfirmModal` captures focus, so the user
            # cannot move the cursor between modal-open and confirm —
            # `cursor_row` is still on the row that prompted delete.
            t_lib = self.query_one("#lib-table", DataTable)
            deleted_row_idx = t_lib.cursor_row
            entries = [e for e in _load_library() if e.get("id") != entry_id]
            # Update the in-memory cache + invalidate dependent caches
            # synchronously so the panel repopulate below sees the
            # post-delete state instantly. The actual disk write fires
            # in the worker dispatched at the bottom. Pre-fix this
            # called `_save_library(async_sync=True)` which only
            # deferred the active-collection mirror; the main library
            # write was still synchronous, blocking the UI for 5-8 s
            # on a 156 MB plasmid_library.json. The 0.7.15.1 rename
            # fix established the sync-cache + async-disk pattern;
            # delete now uses it too.
            global _library_cache
            _library_cache = _typed_clone(entries)
            _clear_primer_cache = globals().get("_primer_usage_clear_cache")
            if _clear_primer_cache is not None:
                _clear_primer_cache()
            # Cascade: remove any parts-bin entries that mirror the
            # deleted library plasmid. Match on (name, grammar) — a
            # name-only match would over-delete when two grammars
            # carry a TU with the same name (legal: parts are
            # name-unique PER GRAMMAR, see `_palette_rows_for_grammar`
            # dedupe). The library entry's grammar lives on its
            # `source` field as `constructor:{gid}:{role}` (set by
            # `_persist_assembly`); legacy entries without that
            # encoding fall back to name-only matching. The filter
            # itself runs synchronously (fast in-memory list comp);
            # only the disk write is dispatched off-thread.
            cascaded_bin: "list[dict] | None" = None
            try:
                src_field = str(entry.get("source") or "")
                lib_grammar = ""
                if src_field.startswith("constructor:"):
                    parts_src = src_field.split(":", 2)
                    if len(parts_src) >= 2:
                        lib_grammar = parts_src[1]
                bin_entries = _load_parts_bin()
                if lib_grammar:
                    kept = [
                        b for b in bin_entries
                        if not (
                            (b.get("name") or "") == name
                            and (b.get("grammar") or "gb_l0")
                                == lib_grammar
                        )
                    ]
                else:
                    # Legacy entry: no grammar info on the library
                    # row. Fall back to name-only — same behaviour as
                    # before, accepts the over-delete risk for
                    # entries that pre-date the constructor source
                    # tag.
                    kept = [
                        b for b in bin_entries
                        if (b.get("name") or "") != name
                    ]
                n_dropped = len(bin_entries) - len(kept)
                if n_dropped > 0:
                    # Update the bin cache sync so palette refreshes
                    # already see the cascade; the disk write goes
                    # to a separate worker dispatch below.
                    global _parts_bin_cache
                    _parts_bin_cache = _typed_clone(kept)
                    _clear_assembly_fragment_cache()
                    cascaded_bin = kept
                    _log.info(
                        "Plasmid delete: cascaded %d parts-bin row(s) "
                        "for %r (grammar %r)", n_dropped, name,
                        lib_grammar or "<any>",
                    )
            except ValueError as exc:
                _log.exception("Plasmid delete: parts-bin cascade failed")
                self.app.notify(
                    f"Library entry deleted, but parts-bin cleanup "
                    f"failed: {exc}",
                    severity="warning",
                )
            self._repopulate_plasmids()
            # Park the cursor on the row directly above the one we
            # just deleted. Rows above the deleted index keep their
            # positions; rows below shift up by one. So `deleted - 1`
            # in the new display is the same plasmid the user was
            # looking at just above the deletion — the scroll
            # neighbourhood stays put instead of snapping to row 0.
            # Edge cases handled: deleted-row-was-top (clamp to 0,
            # which is now the next-down plasmid), filter-empty /
            # library-empty (row_count == 0, skip), deleted_row_idx
            # is None (no row was selected — shouldn't happen because
            # delete is gated on a cursor key, but defensively skip).
            try:
                row_count = t_lib.row_count
            except Exception:
                row_count = 0
            if row_count > 0 and deleted_row_idx is not None:
                target = max(0, min(deleted_row_idx - 1, row_count - 1))
                try:
                    t_lib.move_cursor(row=target)
                except Exception:
                    _log.exception(
                        "Plasmid delete: cursor restore failed",
                    )
            # If we just deleted the loaded record's library entry,
            # drop the panel's active-row binding AND clear the
            # canvas so the plasmid map / sidebar / seq panel don't
            # linger showing the deleted plasmid's data. Pre-fix
            # only `set_active(None)` ran, which cleared the panel
            # pointer but left every other surface stale.
            app = self.app
            cur = getattr(app, "_current_record", None)
            if cur is not None and cur.id == entry_id:
                self.set_active(None)
                clear = getattr(app, "_clear_canvas", None)
                if callable(clear):
                    clear()
            # Disk writes go off-thread. UI state (panel, caches, map)
            # is already updated above so the user sees the delete
            # land instantly; the slow JSON saves catch up in the
            # background. Active-collection mirror inside the worker
            # uses `async_write=True` so a burst of deletes coalesces
            # into a single mirror write rather than queueing N
            # sequential 150 MB rewrites.
            self._delete_save_to_disk(entries, cascaded_bin)

        self.app.push_screen(
            LibraryDeleteConfirmModal(name, size, entry_id),
            callback=_on_confirm,
        )

    @work(thread=True, exclusive=True, group="library_delete_save")
    def _delete_save_to_disk(
            self, entries: "list[dict]",
            cascaded_bin: "list[dict] | None") -> None:
        """Worker: persist a plasmid delete off-thread.

        Writes library, then mirrors the active collection (the latter
        via `async_write=True` so back-to-back deletes coalesce into a
        single mirror write). Cascades the parts-bin write when the
        deleted library entry had matching bin rows. Cache updates
        already happened on the UI thread before dispatch.
        """
        try:
            _safe_save_json(
                _LIBRARY_FILE, entries, "Plasmid library",
            )
        except (OSError, RuntimeError) as exc:
            _log.exception("Plasmid delete: library save failed")
            self.app.call_from_thread(
                _notify_save_failure,
                self.app, "Plasmid library", exc,
            )
            return
        try:
            _sync_active_collection_plasmids(entries, async_write=True)
        except Exception:
            _log.exception(
                "Plasmid delete: active-collection mirror dispatch failed",
            )
        if cascaded_bin is not None:
            try:
                _safe_save_json(
                    _PARTS_BIN_FILE, cascaded_bin, "Parts bin",
                )
            except (OSError, RuntimeError) as exc:
                _log.exception(
                    "Plasmid delete: parts-bin cascade save failed",
                )
                self.app.call_from_thread(
                    _notify_save_failure,
                    self.app, "Parts bin", exc,
                )
                return
            try:
                _sync_active_parts_bin_parts(cascaded_bin)
            except Exception:
                _log.exception(
                    "Plasmid delete: parts-bin mirror dispatch failed",
                )

    # ── Collections view: enter / + / − / ✎ ────────────────────────────────

    @on(DataTable.RowSelected, "#lib-coll-table")
    def _coll_row_selected(self, event: DataTable.RowSelected):
        """Loading a collection swaps the entire library + active pointer,
        so we require an explicit double-activation: the first
        RowSelected on a row arms a confirmation hint, and only a second
        activation on the same row inside the timeout actually loads.
        Mirrors the "click twice to commit" pattern users get on the
        plasmid table (where the first click moves the cursor and the
        second activates).
        """
        if self._view_mode != "collections":
            return
        rk = event.row_key
        name = rk.value if rk else None
        if not name:
            return

        # Cancel any prior arm-timer; only the most recent click matters.
        prior_timer = getattr(self, "_coll_arm_timer", None)
        if prior_timer is not None:
            try:
                prior_timer.stop()
            except Exception:
                pass
            self._coll_arm_timer = None

        if getattr(self, "_coll_armed_name", None) != name:
            # First activation on this row — arm a 1.5 s window during
            # which a second activation will actually load.
            self._coll_armed_name = name
            self.app.notify(
                f"Click '{name}' again to load it.",
                timeout=2,
            )

            def _disarm() -> None:
                self._coll_armed_name = None
                self._coll_arm_timer = None

            try:
                self._coll_arm_timer = self.set_timer(1.5, _disarm)
            except Exception:
                # Timer setup can fail during teardown; fall back to a
                # single-shot arm with no auto-disarm.
                self._coll_arm_timer = None
            return

        # Second activation within the window — load it.
        self._coll_armed_name = None
        coll = _find_collection(name)
        if coll is None:
            return
        # If this collection is already the active one, just switch the
        # panel into plasmids view — re-writing plasmid_library.json with
        # identical content would churn the .bak file and trigger a
        # cascade of LibraryPanel reloads for no user-visible change.
        if name == _get_active_collection_name():
            self._view_mode = "plasmids"
            self._apply_view_mode()
            self._repopulate_plasmids()
            return
        # Set active BEFORE writing the library so the mirror writes
        # back to the correct collection.
        #
        # Sweep #11 (2026-05-20): force-flush the settings-pointer
        # write BEFORE the async-cache-then-disk library write so a
        # power loss between the two can't leave `settings.json`
        # saying OLD while the library says NEW. Same fix sweep #9
        # applied to project switch (line 41977). Without the
        # explicit sync flush, `_set_active_collection_name` schedules
        # the settings write via the daemon thread; the disk-side
        # pointer might still say OLD when the library mirror lands,
        # and the next mutation mirrors NEW data into OLD — silently
        # overwriting OLD's plasmids.
        _set_active_collection_name(name)
        _settings_flush_sync()
        plasmids = [dict(p) for p in (coll.get("plasmids") or [])
                    if isinstance(p, dict)]
        # Update the in-memory cache synchronously so the panel
        # repopulate below sees the new state immediately. The disk
        # write fires asynchronously after the UI swap. Without this
        # split a 156 MB library + 156 MB collections-mirror rewrite
        # froze the UI for 5-10 s on every collection switch (same
        # class of bug as the 0.7.15.1 rename fix). Skip the
        # collection mirror entirely — `plasmids` came FROM the
        # collection we just switched to, so mirroring back is a
        # no-op data-wise (still 156 MB of disk I/O if not skipped).
        global _library_cache
        _library_cache = _typed_clone(plasmids)
        _clear_primer_cache = globals().get("_primer_usage_clear_cache")
        if _clear_primer_cache is not None:
            _clear_primer_cache()
        self._view_mode = "plasmids"
        self._apply_view_mode()
        self._repopulate_plasmids()
        self.post_message(self.CollectionSwitched(name))
        self._collection_switch_save_to_disk(plasmids)

    @work(thread=True, exclusive=True, group="collection_switch_save")
    def _collection_switch_save_to_disk(
            self, plasmids: "list[dict]") -> None:
        """Worker: write the freshly-switched collection's plasmids to
        plasmid_library.json off-thread. Mirrors the 0.7.15.1 rename
        pattern: in-memory cache is already updated and the panel is
        already repopulated, so the disk write is purely persistence.

        Skips the active-collection mirror entirely — the plasmids came
        FROM the collection we just activated, so mirroring back would
        rewrite an identical 100+ MB file for no data change.

        Exclusive group: a second collection switch mid-flight cancels
        the first. Safe because the in-memory cache is updated sync
        before each dispatch, so the second worker captures the
        cumulative state.
        """
        try:
            _safe_save_json(
                _LIBRARY_FILE, plasmids, "Plasmid library",
            )
        except (OSError, RuntimeError) as exc:
            _log.exception("Collection switch: library save failed")
            self.app.call_from_thread(
                _notify_save_failure,
                self.app, "Plasmid library", exc,
            )

    @on(Button.Pressed, "#btn-coll-add")
    def _btn_coll_add(self):
        # Hold a reference to the modal so the callback can read its
        # `_worker_result` cache. The closure below uses
        # `nonlocal modal_ref` after push_screen returns.
        modal_ref: "NewCollectionModal | None" = None

        def _picked(result) -> None:
            if not result:
                return
            name, folder = result
            if _collection_name_taken(name):
                self.app.notify(
                    f"Collection '{name}' already exists.",
                    severity="warning",
                )
                return
            plasmids: list[dict] = []
            description = ""
            if folder is not None:
                # If the modal's worker already imported the folder
                # (the new progress-bar path), reuse its cached
                # result instead of re-importing in the foreground.
                # Old code path (no worker, e.g. from a unit test
                # that injects (name, folder) directly via dismiss)
                # still falls through to a synchronous import.
                cached = (modal_ref._worker_result
                           if modal_ref is not None
                           and getattr(modal_ref, "_worker_result", None)
                                is not None
                           else None)
                if cached is not None:
                    entries, failures = cached
                else:
                    entries, failures = _bulk_import_folder(folder)
                plasmids = entries
                description = f"Bulk imported from {folder}"
                n_ok, n_fail = len(entries), len(failures)
                # markup=False so a hostile filename / folder path with
                # Rich tags ([red]…[/]) renders literally instead of
                # injecting style. _record_to_library_entry already
                # sanitises display names, but the notify summary below
                # still echoes raw filename paths from the failures list.
                # Sweep #11 (2026-05-20): auto-bind moved off the UI
                # thread. Pre-fix `_auto_bind_entry_vectors_from_entries`
                # parsed N × M (entries × grammars) GenBank texts AND
                # issued N synchronous JSON writes ON the UI thread,
                # freezing the bulk-import success flow for several
                # seconds on a 100-entry × 3-grammar import. Now we
                # emit the import-success toast immediately and
                # dispatch the auto-bind to a worker that fires a
                # FOLLOW-UP toast on completion.
                if n_ok and not n_fail:
                    self.app.notify(
                        f"Imported {n_ok} plasmid(s) into '{name}'. "
                        f"Auto-detecting entry vectors…",
                        severity="information", markup=False,
                        timeout=4,
                    )
                    self._auto_bind_worker(list(entries), name)
                elif n_ok and n_fail:
                    tail = ", ".join(p.name for p, _ in failures[:3])
                    if n_fail > 3:
                        tail += f", … (+{n_fail - 3} more)"
                    summary = f"Imported {n_ok}, failed {n_fail}: {tail}"
                    self.app.notify(
                        f"{summary}. Auto-detecting entry vectors…",
                        severity="warning", timeout=4, markup=False,
                    )
                    self._auto_bind_worker(list(entries), name)
                elif n_fail:
                    # Folder-level failure (single tuple keyed on the
                    # folder itself) shows up here. Surface the reason
                    # so the user knows whether to fix permissions.
                    reason = failures[0][1] if len(failures) == 1 else \
                             f"{n_fail} file(s) failed to import"
                    self.app.notify(
                        f"Import failed: {reason}",
                        severity="error", timeout=8, markup=False,
                    )
                else:
                    self.app.notify(
                        f"No .dna / .gb / .gbk files found in {folder}.",
                        severity="warning", markup=False,
                    )
            existing = _load_collections()
            existing.append({
                "name":        name,
                "description": description,
                "plasmids":    plasmids,
                "saved":       _date.today().isoformat(),
            })
            # Sync-cache + async-disk so a large collections.json
            # doesn't freeze the UI. Errors surface from the worker
            # via `_notify_save_failure` (audit fix 2026-05-14).
            self._save_collections_async(existing)
            self._repopulate_collections()
        modal_ref = NewCollectionModal()
        self.app.push_screen(modal_ref, callback=_picked)

    @on(Button.Pressed, "#btn-coll-del")
    def _btn_coll_del(self):
        self._request_collection_delete()

    def _request_collection_delete(self) -> None:
        """Two-stage confirm. First modal asks "delete this collection?"
        with default-No focus; only on Yes does the second loud-red
        modal fire ("ARE YOU ABSOLUTELY SURE?", also default-No).
        Either No (or Esc) keeps the collection. Bound to both the
        `−` button and the keyboard Delete key when the panel is in
        collections view.
        """
        name = _cursor_row_key(self.query_one("#lib-coll-table", DataTable))
        if not name:
            return
        coll = _find_collection(name)
        n_plas = len((coll or {}).get("plasmids", []) or [])

        def _on_first(yes: "bool | None") -> None:
            if not yes:
                return

            def _on_second(yes2: "bool | None") -> None:
                if not yes2:
                    return
                # Snapshot the deleted collection's plasmid IDs so the
                # canvas-clear check below can tell whether the
                # currently-loaded record came from this collection
                # (in which case its source is gone with the
                # collection and we should drop it from the canvas).
                deleted_ids: set = set()
                deleted_coll = _find_collection(name)
                if deleted_coll is not None:
                    for p in deleted_coll.get("plasmids", []) or []:
                        if isinstance(p, dict) and p.get("id"):
                            deleted_ids.add(p.get("id"))

                remaining = [c for c in _load_collections()
                             if c.get("name") != name]
                # Audit fix 2026-05-14: async-disk pattern.
                self._save_collections_async(remaining)
                # If the deleted collection was active, fall back to
                # the first remaining collection (or default) so the
                # library file mirrors something sensible. Without
                # this the plasmid view kept showing the deleted
                # collection's entries because plasmid_library.json
                # was stale.
                was_active = _get_active_collection_name() == name
                if was_active:
                    new_active = (remaining[0].get("name")
                                   if remaining else None)
                    # Sweep #11 (2026-05-20): force-flush the settings
                    # pointer before the library write so a power loss
                    # between the two can't leave settings.json saying
                    # OLD while the library holds the new collection's
                    # plasmids. Same fix sweep #9 landed on project
                    # delete-promote (line 42246).
                    _set_active_collection_name(new_active)
                    _settings_flush_sync()
                    fallback_plasmids = [
                        p for p in (
                            (remaining[0].get("plasmids") if remaining
                             else None) or []
                        ) if isinstance(p, dict)
                    ]
                    try:
                        _save_library(fallback_plasmids)
                    except (OSError, RuntimeError) as exc:
                        _notify_save_failure(
                            self.app, "Plasmid library", exc)
                        return
                self._repopulate_collections()
                # If the loaded record came from the deleted
                # collection, clear the canvas — its source is gone.
                app = self.app
                cur = getattr(app, "_current_record", None)
                if (cur is not None and getattr(cur, "id", None)
                        in deleted_ids):
                    self.set_active(None)
                    clear = getattr(app, "_clear_canvas", None)
                    if callable(clear):
                        clear()
                self.app.notify(f"Deleted collection '{name}'.",
                                markup=False)

            self.app.push_screen(
                ScaryDeleteConfirmModal(name, n_plas),
                callback=_on_second,
            )

        self.app.push_screen(
            CollectionDeleteConfirmModal(name, n_plas),
            callback=_on_first,
        )

    @on(Button.Pressed, "#btn-coll-rename")
    def _btn_coll_rename(self):
        old = _cursor_row_key(self.query_one("#lib-coll-table", DataTable))
        if not old:
            return

        def _picked(new_name: "str | None") -> None:
            if not new_name or new_name == old:
                return
            if _collection_name_taken(new_name):
                self.app.notify(
                    f"Collection '{new_name}' already exists.",
                    severity="warning",
                )
                return
            existing = _load_collections()
            for c in existing:
                if c.get("name") == old:
                    c["name"] = new_name
                    break
            # Audit fix 2026-05-14: async-disk pattern.
            self._save_collections_async(existing)
            if _get_active_collection_name() == old:
                _set_active_collection_name(new_name)
            self._repopulate_collections()
            self._update_header()

        self.app.push_screen(
            CollectionNameModal("Rename collection", old, "Collection name"),
            callback=_picked,
        )


# ── Map / sequence split resize handle ─────────────────────────────────────────
#
# Drag-handle widget that sits between the top row (LibraryPanel +
# PlasmidMap + FeatureSidebar) and the SequencePanel. Click and drag
# vertically to rebalance the split — drag UP shrinks the map and
# grows the sequence panel; drag DOWN does the reverse. The chosen
# height persists to settings.json (`seq_panel_height`) so it survives
# restart, the same pattern as `show_restr` / `restr_unique_only` /
# etc.
#
# Originally contributed by Harley King (har1eyk) in closed PR #8 with
# a video demo. The maintainer's review listed six required changes
# before merge — those are applied in this implementation:
#
#   1. `except NoMatches` (not bare `except Exception`) — only failure
#      mode of `query_one` is "not on screen yet" / "unmounted", which
#      is exactly what NoMatches signals (CLAUDE.md pitfall #1).
#   2. No `self.app.refresh(layout=True)` per move — would invalidate
#      `PlasmidMap._draw_cache` (keyed on viewport height) and trigger
#      a full braille re-render every mouse-move tick. The per-widget
#      `refresh(layout=True)` on `seq_panel` is enough.
#   3. Short-circuit when the clamped height equals the currently-
#      applied height — keeps the refresh-and-persist path idle on
#      micro-movements that don't actually change anything.
#   4. Real `pilot.mouse_*` test coverage in `tests/test_smoke.py`
#      (not the fake `_MouseEvent` shim from the original PR which
#      bypassed Textual's event routing).
#   5. Rebased onto current master — the original branch was on v0.3.3
#      and the LibraryPanel / compose() layout has been heavily
#      rewritten since.
#   6. Persist `seq_panel_height` to settings.json so the user's
#      chosen split survives a restart.

class MapSequenceResizeHandle(Widget):
    """One-row drag handle between the top row and the sequence panel."""

    DEFAULT_CSS = """
    MapSequenceResizeHandle {
        height: 1;
        color: $text-muted;
        content-align: center middle;
    }
    MapSequenceResizeHandle.dragging {
        color: $accent;
    }
    """

    can_focus = False

    # Minimum heights to keep the layout functional. The seq panel
    # needs at least a header + a couple of data rows to be useful;
    # the top row needs the library / map / sidebar to not be
    # squashed to nothing.
    _MIN_SEQ_HEIGHT = 6
    _MIN_TOP_HEIGHT = 14

    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self._dragging = False
        self._drag_start_y = 0
        self._drag_start_seq_height = 0

    def render(self) -> Text:
        width = max(1, self.size.width)
        # Thin light line across the full width with a half-height
        # block `▄` filling the bottom of the cell in the centre as the
        # visual grab affordance. The whole row is still the click
        # target — the chunkier centre just signals where to grab.
        tab_width = 25
        if width <= tab_width:
            return Text("▄" * width)
        side = (width - tab_width) // 2
        extra = (width - tab_width) - 2 * side
        text = Text()
        text.append("─" * side, style="dim")
        text.append("▄" * tab_width)
        text.append("─" * (side + extra), style="dim")
        return text

    def _clamp_sequence_height(self, height: int) -> int:
        """Clamp the requested seq-panel height to [MIN_SEQ, max_available].

        The upper bound is the app's screen height minus the handle's
        own row minus `_MIN_TOP_HEIGHT` (so the top row never shrinks
        below usable). Falls back to a permissive clamp if the screen
        size isn't yet known (test harness pre-mount, etc.)."""
        try:
            screen_h = self.app.size.height
        except NoMatches:
            return max(self._MIN_SEQ_HEIGHT, height)
        handle_h = max(1, self.size.height)
        max_seq_h = max(
            self._MIN_SEQ_HEIGHT,
            screen_h - handle_h - self._MIN_TOP_HEIGHT,
        )
        return max(self._MIN_SEQ_HEIGHT, min(max_seq_h, height))

    def _apply_sequence_height(self, height: int) -> bool:
        """Set the seq panel's height and refresh layout. Returns True
        if the height actually changed (callers persist to settings
        only on real changes — see review item #3 / #6)."""
        try:
            seq_panel = self.app.query_one("#seq-panel", SequencePanel)
        except NoMatches:
            return False
        clamped = self._clamp_sequence_height(height)
        # Short-circuit no-op resize: avoid per-tick refresh + persist
        # spam on micro-movements that don't actually change the
        # rendered layout.
        try:
            current_h = int(seq_panel.size.height)
        except (TypeError, ValueError):
            current_h = -1
        if clamped == current_h:
            return False
        seq_panel.styles.height = clamped
        seq_panel.refresh(layout=True)
        # Per the review: no `self.app.refresh(layout=True)` here. The
        # per-widget refresh already cascades to descendants and the
        # PlasmidMap's draw cache (keyed on viewport height) would
        # otherwise re-render the braille map every mouse-move tick.
        return True

    def on_mouse_down(self, event: MouseDown) -> None:
        if event.button != 1:
            return
        try:
            seq_panel = self.app.query_one("#seq-panel", SequencePanel)
        except NoMatches:
            return
        self._dragging = True
        self._drag_start_y = int(event.screen_y or 0)
        self._drag_start_seq_height = int(seq_panel.size.height)
        self.add_class("dragging")
        self.capture_mouse()
        event.stop()

    def on_mouse_move(self, event: MouseMove) -> None:
        if not self._dragging:
            return
        # Drag UP (negative delta_y) GROWS the seq panel; drag DOWN
        # shrinks it. So the new height is `start_height - delta_y`.
        delta_y = int(event.screen_y or 0) - self._drag_start_y
        self._apply_sequence_height(self._drag_start_seq_height - delta_y)
        event.stop()

    def on_mouse_up(self, event: MouseUp) -> None:
        if event.button != 1 or not self._dragging:
            return
        self._dragging = False
        self.remove_class("dragging")
        self.release_mouse()
        # Persist the final height to settings.json so the user's
        # chosen split survives a restart (review item #6). Read the
        # current seq panel height after release — the last
        # `_apply_sequence_height` call during the drag would have
        # already clamped + assigned it.
        try:
            seq_panel = self.app.query_one("#seq-panel", SequencePanel)
            final_h = int(seq_panel.size.height)
        except (NoMatches, TypeError, ValueError):
            final_h = -1
        if final_h >= self._MIN_SEQ_HEIGHT:
            try:
                _set_setting("seq_panel_height", final_h)
            except Exception:
                # Disk-full / RO-mount: don't break the resize UX
                # just because the persistence call failed. The log
                # records the issue for diagnostic-bundle triage.
                _log.exception(
                    "seq_panel_height persist failed (height=%d)", final_h,
                )
        event.stop()


# ── Sequence panel ─────────────────────────────────────────────────────────────

class SequencePanel(Widget):
    """
    Bottom DNA sequence viewer.

    Click on the sequence → place cursor + select feature at that position.
    Ctrl+click  → extend selection (works everywhere).
    Shift+click → same effect, but terminals that intercept Shift+click
                  for native text-selection (xterm, macOS Terminal,
                  GNOME Terminal) will eat the click before the app
                  sees it. Use Ctrl+click if Shift seems ignored.
    Ctrl+E                → open insert/replace dialog at cursor / selection.
    Alt+D                 → toggle hover-status debug mode.
    Alt+M                 → toggle click-modifier echo debug.
    H (debug only)        → copy hover-status text to clipboard.
    D (debug only)        → dump rendered chunk text to clipboard + log.
    """

    BINDINGS = [
        # Panel-level (no priority) so Textual's focus chain
        # dispatches them only when the seq panel or one of its
        # descendants (seq-scroll, seq-hover-status) has focus.
        # That keeps modal Input fields free to receive literal
        # `h` / `d` characters (e.g. IUPAC ambiguity code H = A/C/T
        # while editing a sequence). H / D are gated on `_debug_mode`
        # internally; Alt+D is the always-available toggle.
        Binding("h",     "copy_hover_status", "Copy hover", show=False),
        Binding("d",     "dump_hover_chunk",  "Dump chunk", show=False),
        # Seq-panel debug-mode toggle. Moved from `alt+d` → `alt+shift+d`
        # in 0.7.6 because `alt+d` was repurposed for the always-
        # available UI-snapshot capture (App-level binding). H / D
        # are still gated on `_debug_mode` so they don't capture
        # literal IUPAC codes during normal sequence editing.
        Binding("alt+shift+d", "toggle_debug", "Seq debug mode", show=False),
        # Enter on a highlighted feature opens the FeatureEditModal.
        # Routed through the App via post_message so the seq panel
        # doesn't need to know about modals or feature lists. The
        # action no-ops when no feature is currently selected on the
        # plasmid map, so plain Enter outside a feature is harmless.
        Binding("enter", "open_selected_feature", "Open feature", show=False),
        # Alt+O — re-anchor the display origin at the currently
        # highlighted feature (= same `selected_idx` the map shows).
        # Mirrors the map / sidebar bindings so the user can set
        # origin from any focused panel.
        Binding("alt+o", "set_origin_to_selected",
                "Set origin", show=False),
    ]

    DEFAULT_CSS = """
    SequencePanel {
        height: 14;
    }
    /* Subtle "you are here" brighten when focus is anywhere inside
       the panel (the inner ScrollableContainer takes focus on
       click). See PlasmidMap for the colour rationale. */
    SequencePanel:focus-within { background: #0c0c0c; }
    /* Hover diagnostic row — shows exactly which cell + feature
       the mouse is over so the user can confirm clicks land where
       they expect. Costs 1 row of visible DNA; toggle via
       `seq panel hover` if it gets in the way. */
    #seq-hover-status {
        height: 1;
        color: #888888;
        background: #0a0a0a;
        padding: 0 1;
    }
    #seq-scroll { height: 1fr; }
    """

    def action_open_selected_feature(self) -> None:
        """Enter on the seq panel — open the FeatureEditModal for the
        currently-selected feature on the plasmid map. No-op if
        nothing is selected; defers to App's `_open_feature_editor`
        so the seq panel doesn't need to know about modal lifecycle.
        """
        try:
            pm = self.app.query_one("#plasmid-map", PlasmidMap)
        except (NoMatches, AttributeError):
            return
        idx = pm.selected_idx
        if idx < 0 or not pm._feats:
            self.app.notify(
                "No feature selected — click a feature first.",
                severity="information",
                timeout=2,
            )
            return
        # Defer to the App-level helper so the modal-open path is
        # the same whether triggered from sidebar Enter, sidebar
        # double-click, or seq-panel Enter.
        try:
            self.app._open_feature_editor(idx)  # type: ignore[attr-defined]
        except AttributeError:
            pass

    def action_set_origin_to_selected(self) -> None:
        """Alt+O on the seq panel — re-anchor the map's display
        origin at the currently-highlighted feature's start.
        Routes through the map's `action_set_origin_to_selected`
        so the cascade (sidebar re-sort + seq panel rotation) fires
        from a single source of truth — same code path as the map
        + sidebar Alt+O bindings.
        """
        try:
            pm = self.app.query_one("#plasmid-map", PlasmidMap)
        except (NoMatches, AttributeError):
            return
        pm.action_set_origin_to_selected()

    def action_toggle_debug(self) -> None:
        """Alt+D — show / hide the seq-panel hover-status diagnostic
        row. When on, MouseMove updates the row in real time and
        H / D copy / dump as before. When off, the row is hidden
        from layout (seq-scroll gets the space back) and H / D
        notify the user to enable debug mode first. Logged so users
        can grep their own usage."""
        self._debug_mode = not self._debug_mode
        try:
            status = self.query_one("#seq-hover-status", Static)
        except NoMatches:
            return
        status.display = self._debug_mode
        if self._debug_mode:
            mx, my = self._last_mouse_xy
            if mx >= 0:
                self._update_hover_status(mx, my)
            else:
                status.update(
                    "[dim]Debug mode ON — hover the seq panel to see "
                    "kind/packed_row/col/feature info. H copies, D dumps "
                    "the chunk. Alt+D toggles off.[/]"
                )
        _log_event("seq.debug_toggle", on=self._debug_mode)
        self.app.notify(
            f"Seq panel debug mode {'ON' if self._debug_mode else 'OFF'}",
            severity="information",
        )

    def action_dump_hover_chunk(self) -> None:
        """Dump the rendered plain text of the chunk under the mouse
        to clipboard + log. Each line is prefixed with its packed-row
        / DNA / below classification so we can compare against the
        hover diagnostic. Crucial for chasing renderer-vs-owner-fill
        divergences ("I see a bar at this row but you say no feature").
        Gated on debug mode (Alt+D)."""
        if not self._debug_mode:
            self.app.notify(
                "Enable debug mode first (Alt+D)",
                severity="information",
            )
            return
        mx, my = self._last_mouse_xy
        if mx < 0 or not self._seq:
            self.app.notify("Move mouse over the panel before pressing D",
                            severity="warning")
            return
        # Identify the chunk under the mouse via the same row-dispatch
        # logic as `_hover_at` but only as far as needed to find the
        # chunk index.
        info = self._hover_at(mx, my)
        chunk_idx = info.get("chunk")
        if chunk_idx is None:
            self.app.notify(f"Hover off-content (kind={info.get('kind')})",
                            severity="warning")
            return
        n = len(self._seq)
        num_w = len(str(n)) if n else 1
        line_width = max(20, self._seq_render_width() - (num_w + 2))
        chunk_start = chunk_idx * line_width
        chunk_end   = min(chunk_start + line_width, n)
        # Insertion order — must match `_build_seq_inputs` (used by the
        # renderer) so click resolution sees the SAME packed_row as
        # what's drawn. Sorting by length here would produce a
        # different greedy-pack output and clicks would resolve to
        # phantom rows. (2026-04-30 bug — was responsible for
        # consistent "no feature at the bar I'm hovering" misses.)
        annot_feats = [f for f in self._feats
                       if f.get("type") not in ("site", "recut")]
        chunk_feats = _feats_in_chunk(annot_feats, chunk_start, chunk_end, n)
        above_p, below_p, above_rows, below_rows = (
            _chunk_lane_groups(chunk_feats, chunk_start, chunk_end)
        )
        # Build the chunk's render fresh into a stub Text so we can
        # extract its plain-text lines.
        stub = Text(no_wrap=True, overflow="crop")
        # Mirror what `_render_chunk` does, but keep cursor/sel off
        # so the dump shows the bare lane art / DNA pair.
        seq_upper = self._seq.upper()
        _, ann_for_styles = _build_seq_inputs(self._seq, self._feats)
        styles = ["color(252)"] * len(self._seq)
        for f in reversed(self._feats):
            col = f.get("color", "white")
            if f["end"] >= f["start"]:
                for i in range(f["start"], min(f["end"], n)):
                    styles[i] = col
        _render_chunk(
            stub, chunk_start, chunk_end,
            (above_p, below_p, above_rows, below_rows),
            styles, num_w, seq_upper,
            self._show_connectors,
            -1, -1, -1, -1,          # sel_s, sel_e, usr_s, usr_e
            -1, -1, -1, -1,          # reh_s, reh_e, reh_top_cut, reh_bot_cut
            -1, -1, -1,              # reh_rec_s, reh_rec_e, cursor_pos
            None,                    # aa_highlight
        )
        plain_lines = stub.plain.split("\n")
        # Annotate each line with its row classification.
        labels: list[str] = []
        for k in range(above_rows):
            packed = above_rows - 1 - k
            labels.append(f"above scr={k} packed={packed}")
        labels.append("DNA fwd")
        labels.append("DNA rev")
        for k in range(below_rows):
            labels.append(f"below scr={k} packed={k}")
        labels.append("inter-chunk gap")
        # Highlight the user's last hover column with a `^` carat
        # under each line so they don't have to count cells. Adjusted
        # for the "[label] '" prefix added when formatting each line.
        hover_seq_col = info.get("seq_col")
        hover_kind = info.get("kind")
        hover_packed = info.get("packed_row")
        out_lines = [f"chunk={chunk_idx} bp=[{chunk_start},{chunk_end}) "
                     f"above_rows={above_rows} below_rows={below_rows} "
                     f"line_width={line_width}  "
                     f"hover_at: vp_y={info.get('vp_y')} "
                     f"col={hover_seq_col} kind={hover_kind} "
                     f"packed={hover_packed}"]
        for i, line in enumerate(plain_lines):
            if not line:
                continue
            label = labels[i] if i < len(labels) else "?"
            out_lines.append(f"[{label}] {line!r}")
            # Add a carat line under the row the user was actually
            # hovering on, pointing at their seq_col. The full prefix
            # is `[label] '` (label string + 4 chars `[] '`) plus the
            # line-number prefix `num_w + 2` columns inside the quoted
            # content. We need to position the carat under panel col
            # = num_w + 2 + seq_col. The repr() prefix is `[label] '`.
            on_this_row = False
            if hover_kind in ("above", "below") and label.startswith(hover_kind):
                # Match by `packed=` substring so the carat lands on the
                # correct row regardless of label format.
                if f"packed={hover_packed}" in label:
                    on_this_row = True
            elif hover_kind == "dna" and label == "DNA fwd":
                on_this_row = True
            if on_this_row and hover_seq_col is not None and hover_seq_col >= 0:
                # `[label] '` = 3 + len(label) + 1 + 1 = len(label) + 5
                prefix_w = len(label) + 5 + (num_w + 2)
                pad = " " * (prefix_w + hover_seq_col)
                out_lines.append(f"{pad}^ ← hover (seq_col={hover_seq_col})")
        dump = "\n".join(out_lines)
        _log_event("seq.chunk_dump", chunk=chunk_idx, lines=len(out_lines))
        # Privacy invariant (CLAUDE.md #38): never log sequence content.
        # The dump embeds rendered DNA bases; clipboard is the only sink.
        try:
            self.app.copy_to_clipboard(dump)
        except Exception:
            if not _copy_to_clipboard_osc52(dump):
                self.app.notify(
                    "Clipboard unavailable — dump discarded "
                    "(seq.chunk_dump event logged without content)",
                    severity="warning",
                )
                return
        self.app.notify(
            f"Copied chunk {chunk_idx} dump ({len(out_lines)} lines)",
            severity="information",
        )

    def action_copy_hover_status(self) -> None:
        """Copy the current hover-status text to the system clipboard.
        Re-runs `_hover_at` with the last seen mouse position and
        copies the resulting plain-text status string. Logs the
        underlying dict so the user has a verbatim record in the log
        as well. Gated on debug mode (Alt+D)."""
        if not self._debug_mode:
            self.app.notify(
                "Enable debug mode first (Alt+D)",
                severity="information",
            )
            return
        mx, my = self._last_mouse_xy
        if mx < 0:
            self.app.notify(
                "Move mouse over the panel before pressing H",
                severity="warning",
            )
            return
        info  = self._hover_at(mx, my)
        plain = _strip_markup(self._hover_status_text(info)).strip()
        if not plain:
            self.app.notify("Nothing under cursor to copy",
                            severity="information")
            return
        # Privacy invariant (CLAUDE.md #38): `plain` can contain the
        # DNA letter under cursor — log its length, not its content.
        # Filter out `_stacklevel` from `info` so a future caller can't
        # accidentally pass our internal stacklevel kwarg via the
        # spread (pyright also flags the unfiltered spread).
        extras = {
            k: (v.get("label") if isinstance(v, dict) else v)
            for k, v in info.items() if k != "_stacklevel"
        }
        _log_event(
            "seq.hover_copy",
            screen_x=mx, screen_y=my, text_len=len(plain),
            **extras,  # type: ignore[arg-type]
        )
        try:
            self.app.copy_to_clipboard(plain)
        except Exception:
            if not _copy_to_clipboard_osc52(plain):
                self.app.notify(
                    "Clipboard unavailable — see splicecraft.log "
                    "(seq.hover_copy event) for the text",
                    severity="warning",
                )
                return
        self.app.notify(f"Copied: {plain[:60]}{'…' if len(plain) > 60 else ''}",
                        severity="information")

    def _features_at_col(self, placements: list,
                          chunk_start: int, chunk_end: int,
                          seq_col: int) -> list[str]:
        """List `(label, packed_row range)` for every feature in
        `placements` whose bp range covers `seq_col` in this chunk.
        Used by the hover diagnostic when the clicked cell reports
        `no feature` so the user can see where in the stack the
        column's actual features ARE rendered."""
        out: list[str] = []
        for f, br in placements:
            bs = max(f["start"], chunk_start) - chunk_start
            be = min(f["end"],   chunk_end)   - chunk_start
            if bs <= seq_col < be:
                h = _feat_stack_height(f)
                lbl = (f.get("label") or f.get("type") or "?")[:24]
                out.append(f"{lbl}@row{br}-{br + h - 1}")
        return out

    def _hover_status_text(self, info: dict) -> str:
        """Format a hover-status string from a `_hover_at` dict.
        Extracted from `_update_hover_status` so the freeze action
        can render the same text without going through the widget."""
        kind = info.get("kind", "")
        if kind == "above" or kind == "below":
            f = info.get("feat")
            chunk = info["chunk"]
            row   = info["packed_row"]
            col   = info["seq_col"]
            rows  = info.get("above_rows" if kind == "above"
                              else "below_rows", "?")
            screen_row = info.get("screen_row", "?")
            vp_y = info.get("vp_y", "?")
            if f is not None:
                feat_label = (f.get("label") or f.get("type") or "?")[:40]
                bp_range   = f"{f['start']}-{f['end']}"
                strand_str = (
                    "+" if f.get("strand", 1) >= 1
                    else ("-" if f.get("strand", 1) == -1 else "."))
                return (f"  [bold green]●[/] kind={kind} chunk={chunk} "
                        f"packed={row}/{rows} screen_row={screen_row} "
                        f"vp_y={vp_y} col={col}  "
                        f"feat={feat_label} {bp_range}({strand_str})")
            others = info.get("others_at_col") or []
            also = (f"  [yellow]→[/] also at col: {', '.join(others)}"
                    if others else "")
            return (f"  [dim]○[/] kind={kind} chunk={chunk} "
                    f"packed={row}/{rows} screen_row={screen_row} "
                    f"vp_y={vp_y} col={col}  (no feature){also}")
        if kind == "dna":
            return (f"  [cyan]·[/] kind=dna strand={info['strand']} "
                    f"chunk={info['chunk']} col={info['seq_col']} "
                    f"bp={info['bp']}")
        if kind == "gap":
            return (f"  [dim]—[/] kind=gap chunk={info['chunk']} "
                    f"col={info.get('seq_col', '?')}")
        return f"  [dim](kind={kind})[/]"

    # ── Messages ───────────────────────────────────────────────────────────────

    class SequenceChanged(Message):
        """Emitted when the sequence is modified (commit=True = full rebuild)."""
        def __init__(self, seq: str, commit: bool = False):
            self.seq    = seq
            self.commit = commit
            super().__init__()

    class SequenceClick(Message):
        """User clicked on a base or a feature lane; app routes the
        outcome based on `from_lane`. Lane clicks → highlight the
        whole feature. DNA-row clicks → just place the cursor on `bp`,
        no feature-wide highlight even if `bp` happens to fall inside
        a feature's range.

        `feat` is the actual feature dict whose lane art the user
        clicked, set when `from_lane=True` so the receiver can pick
        the right feature directly. Without it, the App would have
        to guess via "smallest enclosing feature at bp" — which
        mis-picks when a small inner feature shares the click bp
        with the larger feature whose bar was actually clicked.
        """
        def __init__(self, bp: int, double: bool = False,
                     from_lane: bool = False,
                     feat: "dict | None" = None,
                     *, shift: bool = False):
            self.bp        = bp
            self.double    = double
            self.from_lane = from_lane
            self.feat      = feat
            # Shift state of the originating click. The lane-click
            # branch in `PlasmidApp._seq_click_impl` honours this for
            # feature-to-feature span selection; DNA-row clicks ignore
            # it (the bp-level shift+drag path handles those via
            # `on_mouse_down` directly on the seq panel).
            self.shift     = bool(shift)
            super().__init__()

    # ── Lifecycle ──────────────────────────────────────────────────────────────

    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self._seq:          str                     = ""
        self._feats:        list[dict]              = []
        # Display rotation: when non-zero, the seq panel renders the
        # sequence + feature lanes starting at this absolute bp instead
        # of bp 0 — same convention as the plasmid map's `origin_bp`.
        # Set by the App's `OriginChanged` handler whenever the user
        # rotates the map (← / → / [ / ] / Alt+O / mouse wheel) so all
        # three views (map / sidebar / seq) share one notion of origin.
        # `self._seq` and `self._feats` stay in absolute coords; the
        # rotation is applied on the way to the renderer + click
        # resolution via `_get_rotated_state`. Display ↔ absolute
        # conversions are `(disp + O) % n` and `(abs - O) % n`.
        self._view_origin_bp: int = 0
        # Cache of the rotated (seq, feats) for the current origin.
        # Keyed on (id(self._seq), id(self._feats), origin_bp).
        # Keeps `_refresh_view` + `_click_to_bp` + `_bp_to_content_row`
        # from re-rotating on every interaction; invalidated on
        # `update_seq` (new identities) or `set_view_origin` (new key).
        self._rotated_cache_key: "tuple | None" = None
        self._rotated_seq:       "str | None"   = None
        self._rotated_feats:     "list[dict] | None" = None
        # Last mouse position seen by `on_mouse_move` — captured so
        # `H` can re-run `_hover_at` and copy the verbatim status to
        # the system clipboard. Initial (-1, -1) sentinel means
        # "mouse hasn't entered the panel yet".
        self._last_mouse_xy: "tuple[int, int]" = (-1, -1)
        # Debug mode toggle (Alt+D). When False, the hover-status
        # diagnostic row is hidden and H / D bindings notify the user
        # to enable debug mode first. Off by default — the diagnostic
        # is for developer/bug-report use, not a normal-flow feature.
        self._debug_mode: bool = False
        self._sel_range:    "tuple[int,int] | None" = None  # feature highlight
        self._user_sel:     "tuple[int,int] | None" = None  # drag/shift selection
        self._cursor_pos:   int                     = -1    # -1 = no cursor
        self._view_cache_key: "tuple | None"        = None
        self._view_cache_txt: "Text | None"         = None
        self._show_connectors:  bool = False
        self._re_highlight: "dict | None" = None  # RE cut visualization
        # Active AA-translation highlight. Set when the user clicks
        # the bar of a CDS feature (the AA letters). Renders the
        # AA glyphs reversed so the protein sequence reads as
        # "highlighted ready to copy"; Ctrl+C in this state copies
        # the AA string instead of the DNA bases.
        self._aa_highlight: "dict | None" = None
        self._sel_anchor:   int         = -1    # anchor for Shift+arrow extension
        # Drag-to-select state
        self._drag_start_bp:    int  = -1
        self._has_dragged:      bool = False
        self._mouse_button_held: bool = False
        self._drag_was_shift:   bool = False
        self._last_was_drag:    bool = False
        # Snapshot of the lane feat clicked at mouse_down (if any)
        # so `on_mouse_up` can demote a tiny jiggle inside the same
        # feature back to a click. Without this, a 1-bp wobble
        # between press and release converts a feature-bar click
        # into a microscopic drag selection and the `on_click`
        # full-feature highlight never fires.
        self._mouse_down_lane_feat: "dict | None" = None
        # Set by _click_to_bp when the click lands on a resite bar row
        self._last_resite_click: "dict | None" = None
        # Set by `_click_to_bp` when the click lands on the AA-letter
        # sub-row of a CDS feature. Holds the underlying codon's
        # (start, end) bp range so `on_click` can park `_user_sel`
        # on those 3 bases — Ctrl+C copies the codon, the user sees
        # a high-contrast highlight on the DNA cells beneath.
        self._last_aa_codon_click: "tuple[int, int] | None" = None
        # Set by `_click_to_bp` to True when the click lands on a
        # feature lane (bar/arrow art) rather than the DNA strand.
        # Reset before every `_click_to_bp` call (see on_mouse_down /
        # on_click) since the setter is asymmetric — never clears.
        self._last_lane_click: bool = False
        # Set by `_click_to_bp` to the actual feature dict whose lane art
        # was clicked, so the App's `_seq_click` can highlight that exact
        # feature instead of falling back to "smallest enclosing feature
        # at this bp" — which would mis-pick a tiny inner feature when
        # the user clicked on top of a larger overlapping feature's bar.
        # Reset alongside `_last_lane_click`.
        self._last_lane_feat: "dict | None" = None
        # Set by `_click_to_bp` to a small debug dict — what region the
        # click resolved to (chunk_idx, row-within-chunk classification,
        # seq_col, feature counts in that row). Read by on_mouse_down on
        # miss so a "click on lane art that returns -1" complaint
        # surfaces the resolved row/col in the log.
        self._last_click_debug: "dict | None" = None
        # Set by `_check_packed` to the resolution path used:
        # "owner" — pixel-accurate glyph-owner hit
        # "footprint" — empty cell within a feature's drawn footprint
        # "lenient" — col-hits + shorter-feature heuristic fallback
        # Read by on_mouse_down so users sharing logs can tell us
        # which tier resolved their click.
        self._last_resolve_via: str = ""
        self._sorted_feats_cache: "list | None" = None
        # Per-chunk glyph-owner cache for pixel-accurate click resolution.
        # Populated lazily by `_check_packed` on the first click in a
        # given chunk; key is `(chunk_start, chunk_end, id(self._feats))`
        # so cursor-page-scrolls hit the cache, but a terminal resize
        # that shifts chunk boundaries OR a feats reassignment outside
        # `update_seq` invalidates automatically. Cleared on
        # `update_seq` since a feats change always rebuilds.
        self._chunks_owners: "dict[tuple, dict]" = {}

    def compose(self) -> ComposeResult:
        # Hover-status diagnostic row, hidden by default. Toggled on
        # via Alt+D. When hidden, the seq-scroll gets the row back
        # for DNA visibility — `display=False` removes it from layout.
        status = Static("", id="seq-hover-status")
        status.display = False
        yield status
        with ScrollableContainer(id="seq-scroll"):
            yield Static("", id="seq-view")

    def on_mount(self) -> None:
        # Scroll watcher: when the inner ScrollableContainer's
        # `scroll_y` reactive changes, re-fire `_refresh_view` so the
        # lazy-render viewport filter picks up the new visible window.
        # Without this, chunks scrolled into view stay blank — the
        # outer cache's vp tuple wouldn't be invalidated by anything
        # else. Watching is cross-widget so we use Textual's
        # `watch(other_widget, attr, callback)` API.
        try:
            scroll = self.query_one("#seq-scroll", ScrollableContainer)
        except NoMatches:
            return
        # Quantize the watcher: only refresh when the scroll position
        # crosses a chunk boundary (≈ vp_h rows). Avoids paying a
        # full re-render on every 1-row scroll while still keeping the
        # viewport up to date during fast scrolls.
        self._last_refreshed_scroll_y = -1

        def _on_scroll_y_changed(new_y: float) -> None:
            try:
                vp_h = max(1, int(scroll.size.height))
            except Exception:
                vp_h = 12
            new_int = int(new_y)
            if abs(new_int - self._last_refreshed_scroll_y) < vp_h // 2:
                return
            self._last_refreshed_scroll_y = new_int
            self._refresh_view()

        try:
            self.watch(scroll, "scroll_y", _on_scroll_y_changed,
                        init=False)
        except Exception:
            # Defensive: if the Textual API changes shape, don't kill
            # the panel — the lazy-render still works for the initial
            # paint, just not for incremental scroll fill-in.
            _log.exception("SequencePanel: failed to attach scroll watcher")

    # ── Public API ─────────────────────────────────────────────────────────────

    def update_seq(self, seq: str, feats: list[dict]) -> None:
        """Called after loading a record or committing an edit.

        Does NOT reset `_view_origin_bp` to 0 — the plasmid map owns
        the origin and posts `OriginChanged` whenever it changes. New
        record loads cascade through the watcher (the map's
        `load_record` resets `origin_bp` to 0); in-place edits leave
        the rotation untouched so the view doesn't snap back to bp 0
        every time the user types Ctrl+E. The rotated cache is
        invalidated unconditionally because `seq` and `feats`
        identities changed.

        DOES clamp `_view_origin_bp` to `% len(seq)` so a sequence
        shrink that drops below the current origin can't leave the
        seq panel pointing past the end — `_get_rotated_state` would
        silently degrade (no rotation visible, but feature shifts
        mis-aligned). Pre-fix the clamp lived only in
        `set_view_origin` (called on rotation), so an edit-then-shrink
        path could bypass it.
        """
        self._seq          = seq
        self._feats        = feats
        self._sorted_feats_cache = None
        self._chunks_owners.clear()
        self._sel_range    = None
        self._user_sel     = None
        self._cursor_pos   = -1
        self._re_highlight = None
        self._aa_highlight = None
        self._sel_anchor   = -1
        self._rotated_cache_key = None
        self._rotated_seq = None
        self._rotated_feats = None
        # Clamp the rotation origin to the new sequence length. See
        # docstring; bounded between [0, len(seq)).
        self._view_origin_bp = (self._view_origin_bp % len(seq)) if seq else 0
        self._refresh_view()

    def set_view_origin(self, origin_bp: int) -> None:
        """Re-render starting at absolute bp ``origin_bp``. Pure UI
        rotation — `self._seq` / `self._feats` stay in absolute coords.
        Called from the App's `OriginChanged` handler whenever the
        user rotates the plasmid map.

        Side effects on rotation:
          * Cursor snaps to the new origin (= display position 0,
            absolute bp ``origin_bp``). The user expects the cursor
            to land at the start of the rotated view — without this,
            it would still point at its old absolute position which
            now lives somewhere mid-display.
          * Feature highlight + drag selection are cleared (they
            highlighted positions valid only under the previous
            rotation).
          * Scroll position resets to display row 0 so the new
            origin is visible. Matches the semantic of ``Home`` on
            the map (reset origin → seq panel goes to top).

        ``origin_bp == 0`` (or out-of-range) restores the historical
        unrotated view. The cache is invalidated unconditionally on
        change so a stale rotated copy can't outlive a reset.
        """
        try:
            o = int(origin_bp) % len(self._seq) if self._seq else 0
        except (TypeError, ValueError):
            return
        if o == self._view_origin_bp:
            return
        self._view_origin_bp = o
        self._rotated_cache_key = None
        self._rotated_seq = None
        self._rotated_feats = None
        # Owner cells are computed against the rotated feats list,
        # so old entries in `_chunks_owners` are stale (and the
        # cache key is now keyed on `_view_origin_bp` so they'd
        # never be returned anyway, just sit there). Clear so
        # memory matches the active rotation.
        self._chunks_owners.clear()
        # Snap cursor to the first base of the rotated view (= the
        # new origin in absolute coords). Clearing _sel_range and
        # _user_sel keeps the highlight from pointing at the old
        # position — which would render at a now-different display
        # row and confuse the user.
        self._cursor_pos = o
        self._sel_range  = None
        self._user_sel   = None
        self._sel_anchor = -1
        self._refresh_view()
        # Scroll to the top so display row 0 (= the new origin) is
        # visible. `center_on_bp(o)` would put the cursor in the
        # middle of the viewport; for set-origin the user expects
        # the new starting base at the top of the panel — same way
        # `Home` (reset origin) returns the view to the start.
        try:
            scroll = self.query_one("#seq-scroll", ScrollableContainer)
            scroll.scroll_to(y=0, force=True, animate=False)
        except (NoMatches, AttributeError):
            pass

    def _get_rotated_state(self) -> "tuple[str, list[dict]]":
        """Return ``(display_seq, display_feats)`` for the current
        rotation. ``display_seq`` is ``self._seq`` rotated so the byte
        at index 0 corresponds to absolute bp ``self._view_origin_bp``.
        Each feature's ``start`` / ``end`` are shifted by
        ``-origin_bp (mod n)`` so a non-wrap feature whose original
        span straddles the new origin becomes a wrap feature in
        display coords (and vice versa); the existing wrap-aware
        renderer handles both cases.

        Cached on (seq id, feats id, origin) so repeat calls during a
        single render pass + the matched click path share one
        rotation. The cache is invalidated by `update_seq` and
        `set_view_origin`. Origin 0 is the fast path — returns the
        original references unchanged so the unrotated view pays no
        extra allocation cost.
        """
        n = len(self._seq)
        # Defensive `% n` clamp: `set_view_origin` already mods on
        # entry, and `pm.load_record` resets `origin_bp = 0` after
        # every sequence edit so origin can never legitimately exceed
        # the new length. But if some future code path calls
        # `update_seq` with a shorter sequence WITHOUT going through
        # `load_record`, `_view_origin_bp` could outlive the seq it
        # was set against — without the clamp the rotated state would
        # silently degrade (no visible rotation, but feature shifts
        # mis-aligned). Cheap insurance.
        o = (int(self._view_origin_bp) % n) if n > 0 else 0
        if o <= 0 or n == 0:
            return self._seq, self._feats
        # Sweep #10 (2026-05-20): seq part of the key uses `hash` not
        # `id` — Python's small-string interning + allocator reuse
        # means two distinct sequence strings can share the same id
        # after one is GC'd. Pre-fix this could surface a stale
        # rotated cache after an in-place sequence edit happened to
        # reuse the previous string's address. Matches the same fix
        # in `_build_seq_inputs` (line 6564) that switched from
        # `id(seq)` to `hash(seq)` for this exact reason. Feature
        # list id is safe because the list itself is reassigned on
        # load (per invariant #4), never mutated in place.
        key = (hash(self._seq), id(self._feats), o)
        if (self._rotated_cache_key == key
                and self._rotated_seq is not None
                and self._rotated_feats is not None):
            return self._rotated_seq, self._rotated_feats
        rot_seq = self._seq[o:] + self._seq[:o]
        rot_feats: list[dict] = []
        for f in self._feats:
            try:
                s = int(f.get("start", 0))
                e = int(f.get("end",   0))
            except (TypeError, ValueError):
                continue
            new = dict(f)
            new["start"] = (s - o) % n
            new["end"]   = (e - o) % n
            # Shift resite cut bp fields too. Pre-2026-05-08 only
            # `start` / `end` rotated; the absolute cut markers
            # (`top_cut_bp`, `bottom_cut_bp`, `ext_cut_bp`) stayed
            # in the original frame and pointed at the wrong
            # display position after rotation — visible as a cut
            # arrow stranded far from its parens, or a Type IIS
            # dashed bridge stretched across the whole panel.
            # Same modular shift as the recognition bounds keeps
            # all four bp coordinates self-consistent in the
            # rotated frame.
            for k in ("top_cut_bp", "bottom_cut_bp", "ext_cut_bp"):
                v = f.get(k)
                if isinstance(v, int) and v >= 0:
                    new[k] = (v - o) % n
            rot_feats.append(new)
        self._rotated_cache_key = key
        self._rotated_seq       = rot_seq
        self._rotated_feats     = rot_feats
        return rot_seq, rot_feats

    def _abs_to_disp(self, bp: int) -> int:
        """Absolute bp → display bp under current rotation. ``bp == -1``
        passes through (no-cursor / no-selection sentinel)."""
        if bp < 0 or self._view_origin_bp == 0 or not self._seq:
            return bp
        return (bp - self._view_origin_bp) % len(self._seq)

    def _disp_to_abs(self, bp: int) -> int:
        """Display bp → absolute bp under current rotation. ``bp == -1``
        passes through."""
        if bp < 0 or self._view_origin_bp == 0 or not self._seq:
            return bp
        return (bp + self._view_origin_bp) % len(self._seq)

    def highlight_feature(self, feat: "dict | None", cursor_bp: int = -1,
                            scroll: bool = True) -> None:
        """Highlight a feature's region in the sequence; show CDS translation.

        cursor_bp: if >= 0, anchor the cursor (and scroll) at this bp position.
                   Use this for sequence-panel clicks so scroll stays at the
                   clicked position rather than jumping to the feature start.
        scroll:    when True (default), call `_ensure_cursor_visible` so the
                   cursor is on screen. Pass False when the caller will
                   issue its own `center_on_bp` afterwards — otherwise two
                   sequential scrolls become a visible jitter.
        """
        self._re_highlight = None
        if feat is None or not self._seq:
            self._sel_range = None
            self._refresh_view()
            return

        start, end = feat["start"], min(feat["end"], len(self._seq))
        self._sel_range  = (start, end)
        self._user_sel   = None          # clear shift-selection on programmatic highlight
        self._sel_anchor = -1
        if cursor_bp >= 0:
            self._cursor_pos = cursor_bp
            if scroll:
                self._ensure_cursor_visible()   # scroll BEFORE refresh
        self._refresh_view()

    def select_feature_range(self, feat: dict, cursor_bp: int = -1,
                              scroll: bool = True) -> None:
        """Highlight the entire feature span as a copyable selection.

        cursor_bp: if >= 0 (sequence-panel click), keep cursor at that bp and
                   anchor the Shift+arrow selection there. Otherwise cursor goes
                   to the feature end so Shift+arrow naturally extends outward.
        scroll:    when True, also adjust the viewport so the cursor is on
                   screen. Pass False when the caller will issue its own
                   `center_on_bp` immediately after — otherwise the user
                   sees a partial scroll (just-visible) followed by a
                   centring scroll, which reads as a perceptible jitter on
                   sidebar arrow-key navigation.
        """
        if not self._seq or feat is None:
            return
        start = feat["start"]
        end   = min(feat["end"], len(self._seq))
        self._user_sel  = (start, end)
        self._sel_range = None
        self._re_highlight = None
        if cursor_bp >= 0:
            # Sequence-panel click: cursor stays at click; anchor at feature start
            self._cursor_pos = cursor_bp
            self._sel_anchor = start
        else:
            # Map/sidebar/double-click: cursor at feature end, anchor at start
            self._cursor_pos = max(start, end - 1)
            self._sel_anchor = start
        # Scroll BEFORE refresh — see _ensure_cursor_visible docstring.
        if scroll:
            self._ensure_cursor_visible()
        self._refresh_view()

    # ── Mouse / click ──────────────────────────────────────────────────────────

    def on_mouse_down(self, event: MouseDown) -> None:
        if event.button != 1:
            return
        # Reset side-effect flags before `_click_to_bp` — it sets these
        # only on lane / AA-letter hits and never clears, so a stale
        # value from the previous click would otherwise leak through
        # (e.g. lane→DNA-row sequence wrongly skipping auto-scroll, or
        # mid-drag mouse_up bypassing on_click and leaving them set).
        self._last_lane_click     = False
        self._last_lane_feat      = None
        self._last_aa_codon_click = None
        self._last_resolve_via    = ""
        bp = self._click_to_bp(event.screen_x, event.screen_y)
        if bp < 0:
            # Log even on miss so a "the app isn't responding to my
            # clicks" complaint shows whether the event reached us at
            # all. `bp=-1` here means the click hit blank space within
            # the seq-panel viewport (gap row, off-grid coordinate).
            # `_last_click_debug` (set by `_click_to_bp`) carries which
            # row classification we resolved to + the seq_col, so a
            # complaint of "I clicked on lane art and nothing happened"
            # surfaces enough context to confirm/refute that.
            dbg = self._last_click_debug or {}
            _log_event(
                "seq.mouse_down_miss",
                screen_x=event.screen_x, screen_y=event.screen_y,
                **dbg,
            )
            return
        # AA-letter click → land the cursor at the CENTER bp of the
        # codon (= where the AA letter was rendered), not the feature
        # midpoint that `_check_packed` returns for lane hits.
        # Without this override the cursor would briefly flash at the
        # CDS midpoint between mouse_down and the on_click handler
        # that re-parks it. Codon range is `[cs, ce)` with cs = mid-1,
        # ce = mid+2 — so the centre bp is `cs + 1`.
        aa_codon = self._last_aa_codon_click
        if aa_codon is not None:
            bp = aa_codon[0] + 1
        self._mouse_button_held = True
        self._drag_start_bp     = bp
        self._has_dragged       = False
        # Ctrl is treated as a shift synonym (some terminals eat
        # shift+click for native text-selection). The on_mouse_down
        # extend-selection branch below uses the same combined flag.
        self._drag_was_shift    = bool(event.shift) or bool(event.ctrl)
        # Snapshot the lane feat clicked at mouse_down so on_mouse_up
        # can demote a tiny in-feature jiggle back to a click.
        self._mouse_down_lane_feat = self._last_lane_feat
        dbg = self._last_click_debug or {}
        _log_event(
            "seq.mouse_down", bp=bp,
            lane=self._last_lane_click,
            feat=(self._last_lane_feat or {}).get("label") if self._last_lane_feat else None,
            shift=event.shift,
            codon=self._last_aa_codon_click,
            via=self._last_resolve_via,
            **{k: v for k, v in dbg.items()
               if k in ("packed_row", "seq_col", "is_below", "owner_set")},
        )
        if self._last_resite_click is not None:
            # Resite click — `on_click` will set `_re_highlight` and
            # clear the cursor. Parking the cursor at the resite
            # midpoint here would briefly flash + auto-scroll the
            # viewport to that bp BEFORE on_click runs (visible as
            # "click on enzyme name → seq panel scrolls and focuses
            # a feature instead of showing the recog site"). Leave
            # the cursor + selection state untouched so on_click
            # owns the post-click view; the drag-start fields below
            # still get set so a drag-from-resite can extend.
            pass
        elif (event.shift or event.ctrl) and self._cursor_pos >= 0:
            # Shift / Ctrl + click: extend bp-level selection from
            # anchor (or cursor) to here. Either modifier triggers
            # the same flow because terminals can swallow shift+click
            # for native text-selection.
            anchor = self._sel_anchor if self._sel_anchor >= 0 else self._cursor_pos
            self._sel_anchor = anchor
            s = min(anchor, bp)
            e = max(anchor, bp) + 1
            self._user_sel   = (s, e)
            self._cursor_pos = bp
            self._sel_range  = None
        else:
            # Plain click: place cursor, clear selection and anchor
            self._cursor_pos = bp
            self._user_sel   = None
            self._sel_anchor = -1
        # Skip the auto-scroll for lane-art / AA-letter / resite
        # clicks: the user clicked something already on screen, so
        # jumping the viewport to the feature midpoint / codon
        # centre / recognition midpoint would yank them away from
        # what they were looking at. Plain DNA-row clicks still
        # scroll if the cursor lands off-screen, since those clicks
        # set cursor at the literal click bp.
        skip_scroll = (self._last_lane_click
                       or self._last_aa_codon_click is not None
                       or self._last_resite_click is not None)
        if not skip_scroll:
            self._ensure_cursor_visible()
        self._refresh_view()

    def on_mouse_move(self, event: MouseMove) -> None:
        # Always capture the last position so Alt+D → H / D can use
        # it. The hover status only updates when debug mode is on.
        self._last_mouse_xy = (event.screen_x, event.screen_y)
        if self._debug_mode:
            self._update_hover_status(event.screen_x, event.screen_y)
        # Hover tooltip on lane art (gated by Settings → Show feature
        # hover tooltips). Cheap when off — early-returns before any
        # hover-resolve work. Skipped during a drag so a selection
        # gesture doesn't flicker the popup.
        if not self._mouse_button_held:
            self._update_feature_tooltip(event.screen_x, event.screen_y)
        if not self._mouse_button_held or self._drag_start_bp < 0:
            return
        bp = self._click_to_bp(event.screen_x, event.screen_y)
        if bp < 0 or bp == self._drag_start_bp and not self._has_dragged:
            return
        self._has_dragged = True
        s = min(self._drag_start_bp, bp)
        e = max(self._drag_start_bp, bp) + 1
        self._user_sel   = (s, e)
        self._cursor_pos = bp
        self._sel_range  = None
        self._refresh_view()

    def _update_feature_tooltip(self, screen_x: int, screen_y: int) -> None:
        """Set / clear `self.tooltip` based on whether the cursor is on
        feature lane art. Only triggers on lane rows, not DNA bases —
        DNA hover would be too noisy. Cleared when the user toggles
        the setting off via `PlasmidApp.action_toggle_feature_tooltips`.
        """
        try:
            app = self.app
        except Exception:
            return
        if not getattr(app, "_show_feature_tooltips", True):
            if self.tooltip is not None:
                self.tooltip = None
            return
        info = self._hover_at(screen_x, screen_y) if self._seq else None
        # Lane-art kinds emitted by `_hover_at`. DNA-row hovers are
        # excluded so passing the cursor across bases doesn't
        # tooltip-storm — the user only gets a popup when actually
        # over a feature bar / label.
        kind = (info or {}).get("kind", "")
        if kind not in ("above", "below"):
            if self.tooltip is not None:
                self.tooltip = None
            return
        feat = info.get("feat") if info else None
        if not isinstance(feat, dict):
            if self.tooltip is not None:
                self.tooltip = None
            return
        # `_orig_dict` carries the original (un-split) wrap feature
        # so the tooltip shows the full bp range, not the half-piece.
        feat = feat.get("_orig_dict", feat)
        new = _format_feat_tooltip(feat, len(self._seq))
        if self.tooltip != new:
            self.tooltip = new

    def _hover_at(self, screen_x: int, screen_y: int) -> dict:
        """Read-only mirror of `_click_to_bp`'s row-dispatch logic.

        Returns a dict describing what's under (`screen_x`, `screen_y`):
        which chunk, which packed_row (above or below stack) or DNA
        strand, which seq_col, and the feature owner at that cell (if
        any). Used by the hover-status row so the user can see exactly
        what each pixel resolves to without clicking. No state
        mutation — safe to call on every MouseMove.
        """
        if not self._seq:
            return {"kind": "no_seq"}
        try:
            scroll = self.query_one("#seq-scroll", ScrollableContainer)
            reg    = scroll.region
            vp_x   = screen_x - reg.x
            vp_y   = screen_y - reg.y
            if (vp_x < 0 or vp_y < 0
                    or vp_x >= reg.width or vp_y >= reg.height):
                return {"kind": "off_viewport",
                        "vp_x": vp_x, "vp_y": vp_y}
            content_row = vp_y + int(scroll.scroll_y)
        except Exception:
            return {"kind": "scroll_query_fail"}

        import bisect
        n           = len(self._seq)
        num_w       = len(str(n)) if n else 1
        line_width  = max(20, self._seq_render_width() - (num_w + 2))
        seq_col     = vp_x - (num_w + 2)

        # O(1) chunk lookup via the cached layout's prefix sums —
        # avoids walking every chunk on a 200 kb cosmid where each
        # MouseMove would otherwise iterate ~1500 chunks linearly.
        # `_chunk_layout` returns `prefix_dna2[i]` = total rows
        # (assuming rpg=2) up to but not including chunk `i`. The
        # chunk containing `content_row` is the largest `i` with
        # `prefix_dna2[i] <= content_row`. show_connectors path is
        # unused (rpg==2 always); kept simple.
        # Hover uses the rotated views so feature-owner lookups land
        # on the right feature when the map is rotated. The `bp`
        # field returned for DNA-strand hovers is converted back to
        # absolute coords for the hover-status row, which displays
        # the user's original record position.
        disp_seq, disp_feats = self._get_rotated_state()
        chunks_layout, prefix_dna2, _pf_lanes = _chunk_layout(
            disp_seq, disp_feats, line_width,
        )
        if not chunks_layout:
            return {"kind": "no_chunks"}
        idx = bisect.bisect_right(prefix_dna2, content_row) - 1
        if idx < 0 or idx >= len(chunks_layout):
            return {"kind": "past_content",
                    "content_row": content_row,
                    "total_rows": prefix_dna2[-1] if prefix_dna2 else 0}
        chunk_start, chunk_end, groups, *_extra = chunks_layout[idx]
        above_p, below_p, above_rows, below_rows = groups
        chunk_idx = idx
        # Re-derive chunk_feats only when needed (for the
        # `_features_at_col` fallback). _chunk_lane_groups already
        # cached its own work via _CHUNK_LAYOUT_CACHE, so the cached
        # placements are reused — no duplicate _feats_in_chunk call.
        row_in_chunk = content_row - prefix_dna2[idx]

        # Dispatch within the chunk. Order (from screen top to bottom):
        #   above_rows × above stack
        #   2 × DNA strands
        #   below_rows × below stack
        #   1 × trailing gap
        if row_in_chunk < above_rows:
            k = row_in_chunk
            packed_row = above_rows - 1 - k
            f = None
            if 0 <= seq_col < (chunk_end - chunk_start):
                owners_data = self._chunk_glyph_owners(
                    chunk_start, chunk_end, [],  # chunk_feats unused
                    above_p, below_p, above_rows, below_rows,
                )
                owners = owners_data["owners_above"]
                if 0 <= packed_row < len(owners):
                    f = owners[packed_row][seq_col]
            others = self._features_at_col(
                above_p, chunk_start, chunk_end, seq_col,
            ) if f is None else []
            return {
                "kind": "above",
                "chunk": chunk_idx,
                "packed_row": packed_row,
                "screen_row": k,
                "above_rows": above_rows,
                "seq_col": seq_col,
                "vp_y": vp_y,
                "vp_x": vp_x,
                "feat": f,
                "others_at_col": others,
            }

        row_after_above = row_in_chunk - above_rows
        if row_after_above < 2:
            if 0 <= seq_col < (chunk_end - chunk_start):
                return {
                    "kind": "dna",
                    "strand": "fwd" if row_after_above == 0 else "rev",
                    "chunk": chunk_idx,
                    "seq_col": seq_col,
                    # `chunk_start + seq_col` is in display coords;
                    # report absolute bp so the hover-status / tooltip
                    # show the user's record position even when the
                    # map is rotated.
                    "bp": self._disp_to_abs(chunk_start + seq_col),
                }
            return {"kind": "dna_off",
                    "chunk": chunk_idx,
                    "seq_col": seq_col}

        row_after_dna = row_after_above - 2
        if row_after_dna < below_rows:
            packed_row = row_after_dna
            f = None
            if 0 <= seq_col < (chunk_end - chunk_start):
                owners_data = self._chunk_glyph_owners(
                    chunk_start, chunk_end, [],  # chunk_feats unused
                    above_p, below_p, above_rows, below_rows,
                )
                owners = owners_data["owners_below"]
                if 0 <= packed_row < len(owners):
                    f = owners[packed_row][seq_col]
            others = self._features_at_col(
                below_p, chunk_start, chunk_end, seq_col,
            ) if f is None else []
            return {
                "kind": "below",
                "chunk": chunk_idx,
                "packed_row": packed_row,
                "screen_row": row_after_dna,
                "below_rows": below_rows,
                "seq_col": seq_col,
                "vp_y": vp_y,
                "vp_x": vp_x,
                "feat": f,
                "others_at_col": others,
            }

        # Trailing inter-chunk gap (the +1 row at the end of each chunk).
        return {"kind": "gap", "chunk": chunk_idx, "seq_col": seq_col}

    def _update_hover_status(self, screen_x: int, screen_y: int) -> None:
        try:
            status = self.query_one("#seq-hover-status", Static)
        except NoMatches:
            return
        info = self._hover_at(screen_x, screen_y)
        status.update(self._hover_status_text(info))

    def on_mouse_up(self, event: MouseUp) -> None:
        if event.button != 1:
            return
        # Tiny-jiggle absorption: if mouse_down landed on a feature
        # lane and the release point is still inside that same
        # feature's bp range, demote the drag to a click. Without
        # this guard, a 1-bp wobble between press and release
        # converts a feature-bar click into a microscopic drag
        # selection and `on_click`'s full-feature-highlight branch
        # never fires (it bails on `_last_was_drag`). The user sees
        # a 1-3 bp highlight where they expected the whole feature.
        # Genuine drags (release outside the original feature) keep
        # their drag-built selection.
        down_feat = self._mouse_down_lane_feat
        self._mouse_down_lane_feat = None
        if (self._has_dragged and down_feat is not None and self._seq):
            cur_bp = self._click_to_bp(event.screen_x, event.screen_y)
            if cur_bp >= 0:
                fs, fe = down_feat["start"], down_feat["end"]
                in_feat = ((fs <= cur_bp < fe) if fe >= fs
                            else (cur_bp >= fs or cur_bp < fe))
                if in_feat:
                    # Promote to click — clear the drag-built
                    # selection so on_click's `select_feature_range`
                    # can replace it cleanly.
                    self._has_dragged = False
                    self._user_sel    = None
                    _log_event(
                        "seq.jiggle_absorbed",
                        bp_release=cur_bp,
                        feat=down_feat.get("label"),
                    )
        self._last_was_drag     = self._has_dragged
        self._mouse_button_held = False
        self._drag_start_bp     = -1
        self._has_dragged       = False
        self._drag_was_shift    = False

    def on_click(self, event: Click) -> None:
        """Handle single/double click — fires after mouse_up at same position."""
        if self._last_was_drag:
            self._last_was_drag = False
            return
        self._last_was_drag = False
        self._last_resite_click = None
        # `_last_lane_click` is set as a side-effect of `_click_to_bp` when
        # the click lands on a feature lane (the bar/arrow art) rather
        # than the DNA strand. Sequence-row clicks intentionally do NOT
        # trigger a whole-feature highlight — only the lane art does.
        # `_last_lane_feat` carries the actual feature dict whose lane
        # was clicked so the receiver can pick that exact feature.
        self._last_lane_click = False
        self._last_lane_feat  = None
        bp = self._click_to_bp(event.screen_x, event.screen_y)
        if bp < 0:
            return

        # If the click landed on a restriction site bar, highlight
        # the recognition span PLUS the cut region. See
        # `_resite_highlight_dict` for the span-derivation logic +
        # rationale for Type IIS coverage.
        resite = self._last_resite_click
        self._last_resite_click = None
        if resite is not None:
            # `resite` came from the rotated `disp_feats` list, so
            # its bp fields are in DISPLAY coords. The renderer
            # expects `_re_highlight` in ABSOLUTE coords (mirroring
            # `_cursor_pos` etc.) — `_refresh_view` shifts to
            # display via `_abs_to_disp` at render time. Convert
            # back to absolute here so the highlight survives a
            # later origin rotation cleanly: the same resite click
            # at a different origin will produce the same absolute
            # `_re_highlight`, and the refresh shifts it to the
            # rotated display.
            abs_resite = dict(resite)
            for k in ("start", "end",
                      "top_cut_bp", "bottom_cut_bp", "ext_cut_bp"):
                v = resite.get(k)
                if isinstance(v, int) and v >= 0:
                    abs_resite[k] = self._disp_to_abs(v)
            self._re_highlight = self._resite_highlight_dict(abs_resite)
            self._sel_range  = None
            self._user_sel   = None
            self._cursor_pos = -1
            # Drop any sibling-panel highlight the user had set before
            # — they're focusing on this restriction site now, so a
            # prior feature selection on the map shouldn't linger.
            try:
                pm = self.app.query_one("#plasmid-map", PlasmidMap)
                if pm.selected_idx != -1:
                    pm.selected_idx = -1
                    pm.refresh()
            except (NoMatches, AttributeError):
                pass
            self._refresh_view()
            return

        # AA-letter click → highlight just that one codon (3 bp) on
        # the DNA strand as a copyable selection, with the cursor
        # parked at the codon's centre bp (where the AA letter was
        # rendered). The `_check_packed` walker stashed the codon's
        # `[start, end)` range in `_last_aa_codon_click`.
        codon = self._last_aa_codon_click
        self._last_aa_codon_click = None
        if codon is not None:
            self._user_sel    = codon
            self._sel_range   = None
            self._sel_anchor  = codon[0]
            # Cursor at codon centre — the AA letter's column.
            self._cursor_pos  = codon[0] + 1
            self._re_highlight = None
            self._aa_highlight = None
            try:
                pm = self.app.query_one("#plasmid-map", PlasmidMap)
                if pm.selected_idx != -1:
                    pm.selected_idx = -1
                    pm.refresh()
            except (NoMatches, AttributeError):
                pass
            self._refresh_view()
            return

        # Regular click: clear any RE highlight + drop any whole-CDS
        # AA highlight (the new spec is single-codon only — see above).
        self._re_highlight = None
        self._aa_highlight = None
        double = event.chain >= 2
        _log_event(
            "seq.click", bp=bp, lane=self._last_lane_click,
            feat=(self._last_lane_feat or {}).get("label")
                  if self._last_lane_feat else None,
            double=double,
        )
        # Extend modifier = shift OR ctrl (terminals frequently eat
        # shift+click; ctrl+click stays as a cross-terminal alias).
        ext = bool(getattr(event, "shift", False)
                    or getattr(event, "ctrl",  False))
        try:
            echo = getattr(self.app, "_echo_click_modifiers", None)
            if callable(echo):
                echo("seq panel", event)
        except Exception:
            pass
        self.post_message(self.SequenceClick(
            bp, double=double, from_lane=self._last_lane_click,
            feat=self._last_lane_feat,
            shift=ext,
        ))

    def _seq_render_width(self) -> int:
        """Character width of the render area, minus the 2-col vertical scrollbar."""
        return max(20, self.size.width - 2)

    def _chunk_glyph_owners(self, chunk_start: int, chunk_end: int,
                             chunk_feats: list[dict],
                             above_p: list, below_p: list,
                             above_rows: int, below_rows: int) -> dict:
        """Return per-(packed_row, col) feature owners for one chunk.

        The result is cached in `self._chunks_owners` keyed by
        ``(chunk_start, chunk_end, id(self._feats))`` (so re-clicks
        in the same chunk are O(1) but a terminal resize that shifts
        chunk boundaries — or a feats-list reassignment outside
        `update_seq` — invalidates automatically).

        Each owner cell `owners_above[packed_row][col]` is the feature
        dict whose `(footprint_rows × bp_range)` rectangle covers that
        cell, or None if the cell is outside every feature's drawn
        area. Greedy packing guarantees these rectangles don't overlap
        per-strand, so each cell has at most one owner.

        Owners are filled across the FULL footprint+bp rectangle (not
        just per-glyph) so that a click on a label-padding space, an
        AA-row inter-letter cell, or a wide bar all resolve to the
        feature whose bar you visibly clicked. Glyph-specific behavior
        like CDS codon-vs-bar dispatch happens later in `_check_packed`
        (it checks `packed_row - bottom_row` and on-letter math).

        Returns dict with keys:
            owners_above[packed_row][col] -> dict | None
            owners_below[packed_row][col] -> dict | None
            above_rows, below_rows         (mirrored for caller)
        """
        # Include `_view_origin_bp` in the cache key — under
        # rotation the rotated feats list shifts every feature's
        # `start` / `end` by `-origin_bp (mod n)`, so the owner
        # cells move with them. Pre-2026-05-08 the cache only
        # keyed on `id(self._feats)` (the unrotated list, whose
        # identity is stable), which returned stale unrotated
        # owner positions after a rotation — clicks on enzyme
        # labels then resolved to the wrong (or no) feature, and
        # fell through to the regular DNA-row click path that
        # scrolled the panel to the click bp instead of
        # highlighting the resite.
        cache_key = (chunk_start, chunk_end, id(self._feats),
                     self._view_origin_bp)
        cached = self._chunks_owners.get(cache_key)
        if cached is not None:
            return cached
        content_w = chunk_end - chunk_start

        def _fill(placements: list, total_rows: int) -> list[list]:
            arr = [[None] * content_w for _ in range(total_rows)]
            for f, bottom_row in placements:
                bar_s = max(f["start"], chunk_start) - chunk_start
                bar_e = min(f["end"],   chunk_end)   - chunk_start
                if bar_e <= bar_s:
                    continue
                height = _feat_stack_height(f)
                for r in range(bottom_row,
                               min(bottom_row + height, total_rows)):
                    row = arr[r]
                    for c in range(max(0, bar_s),
                                   min(bar_e, content_w)):
                        row[c] = f
            return arr

        owners_above = _fill(above_p, above_rows) if above_rows > 0 else []
        owners_below = _fill(below_p, below_rows) if below_rows > 0 else []
        result = {
            "owners_above": owners_above,
            "owners_below": owners_below,
            "above_rows":   above_rows,
            "below_rows":   below_rows,
        }
        # Soft cap: a 200 kb cosmid has ~1230 chunks; without a cap
        # `_chunks_owners` would grow to ~10-20 MB after the user
        # navigates the whole record. 256 entries × ~15 KB ≈ 4 MB —
        # plenty for a working window without unbounded retention.
        # FIFO eviction (oldest insertion popped first) is fine here:
        # the cache invalidates on every `update_seq` anyway, so
        # entries are scoped to the current record, and re-clicking
        # an evicted chunk only costs the ~1 ms re-fill.
        if len(self._chunks_owners) >= 256:
            self._chunks_owners.pop(next(iter(self._chunks_owners)))
        self._chunks_owners[cache_key] = result
        return result

    def _resite_highlight_dict(self, resite: dict) -> dict:
        """Build the `_re_highlight` dict for a clicked restriction
        site. Highlights the recognition span PLUS the cut region.

        For Type IIS enzymes (BsaI / Esp3I / BbsI / etc.) the
        recognition site is one place but the cut happens 1–9 bp
        downstream and the bottom-strand cut is 4 bp further,
        exposing a sticky overhang. Showing only the recognition
        glyphs hid the spacer + overhang the user actually plans
        around. Extending the span to enclose both top + bottom
        cuts makes the full cut footprint visible: recognition
        bases stay coloured, the spacer + overhang between top
        and bottom cuts are now part of the highlight, and the
        per-strand cut markers (reverse video) still render at
        their exact positions inside that span.

        Coordinate convention (sacred): ``top_cut_bp`` is the
        absolute top-strand position where the cut HAPPENS — the
        cut is between positions ``cut-1`` and ``cut``, so the
        LEFT fragment's top strand goes up to ``cut-1`` (inclusive)
        and ``cut`` is the FIRST base of the right fragment. Same
        on the bottom strand for ``bottom_cut_bp``. The
        ``[hi_start, hi_end)`` highlight span is half-open:
        ``hi_end`` is exclusive, so we set ``hi_end = max_cut``
        (NOT ``max_cut + 1``) — the cut position itself is the
        first base of the right fragment, NOT part of the cut
        footprint. Pre-2026-05-08 the code did ``cut + 1`` which
        highlighted one base past the overhang into the
        right-fragment territory.

        For Type IIP / palindromic enzymes (EcoRI / HindIII / etc.)
        the cuts are inside the recognition, so the recognition
        span already covers them — the loop is a no-op and the
        highlight matches pre-2026-05-08 behaviour exactly.

        Returns a dict with keys ``start``, ``end``, ``top_cut_bp``,
        ``bottom_cut_bp``, ``color``, ``name``. Caller assigns the
        result to ``self._re_highlight``.
        """
        n        = len(self._seq)
        hi_start = resite["start"]
        hi_end   = min(resite["end"], n)
        top_cut  = resite.get("top_cut_bp", -1)
        bot_cut  = resite.get("bottom_cut_bp", -1)
        ext_cut  = resite.get("ext_cut_bp")
        strand   = resite.get("strand", 1)
        # Classify each external cut as "natural extension" (genuinely
        # upstream/downstream of the recognition for this strand) vs.
        # "wrap" (cut wrapped past the origin to land on the wrong side
        # of the recognition in linear coordinates). For forward-strand
        # binding (strand >= 0), cuts are expected downstream — a cut
        # numerically smaller than `hi_start` means the raw `p + offset`
        # exceeded `n` and wrapped. For reverse-strand binding the
        # mirror applies. Pre-2026-05-11 the loop unconditionally
        # dragged `hi_start` down to a wrapped cut, producing a
        # plasmid-wide highlight on Type IIS sites at the origin.
        ext_cuts:  list[int] = []
        wrap_cuts: list[int] = []
        for cut in (top_cut, bot_cut, ext_cut):
            if cut is None or cut < 0 or hi_start <= cut < hi_end:
                continue
            if strand >= 0 and cut < hi_start:
                wrap_cuts.append(cut)
            elif strand < 0 and cut >= hi_end:
                wrap_cuts.append(cut)
            else:
                ext_cuts.append(cut)
        for cut in ext_cuts:
            # Inclusive lower bound: a cut sitting BEFORE the recognition
            # IS the leftmost overhang base of the right fragment.
            if cut < hi_start:
                hi_start = cut
            # Exclusive upper bound: a cut sitting PAST the recognition
            # is the leftmost base of the right fragment — fully released
            # and NOT part of the cut footprint.
            elif cut > hi_end:
                hi_end = min(cut, n)
        if wrap_cuts:
            # Wrap-encode: `hi_end < hi_start` (forward wrap) or
            # `hi_start > hi_end` (reverse wrap) means the highlight
            # spans origin. The renderer detects this and tests
            # `i >= reh_s or i < reh_e` instead of the linear form.
            if strand >= 0:
                hi_end = max(wrap_cuts)
            else:
                hi_start = min(wrap_cuts)
        return {
            "start":         hi_start,
            "end":           hi_end,
            "top_cut_bp":    top_cut,
            "bottom_cut_bp": bot_cut,
            # Original recognition bounds (pre-cut-extension). Lets
            # the renderer distinguish recognition bases from
            # spacer / overhang bases under the per-region colour
            # scheme: recognition stays blue/red, spacer is gray,
            # overhang region is green (top) / yellow (bot).
            "rec_start":     resite["start"],
            "rec_end":       min(resite["end"], n),
            "color":         resite["color"],
            "name":          resite["label"],
        }

    def _click_to_bp(self, screen_x: int, screen_y: int) -> int:
        """Map absolute screen coords to a bp index, or -1 if not on a base."""
        # Reset diagnostic state — populated as we resolve so a miss
        # (return -1) carries the resolved row/col classification in
        # `_last_click_debug` for on_mouse_down to log.
        self._last_click_debug = None
        if not self._seq:
            self._last_click_debug = {"reason": "no_seq"}
            return -1
        try:
            scroll      = self.query_one("#seq-scroll", ScrollableContainer)
            reg         = scroll.region          # absolute screen position of viewport
            vp_x        = screen_x - reg.x       # column within the viewport
            vp_y        = screen_y - reg.y       # visible row within the viewport
            if vp_x < 0 or vp_y < 0 or vp_x >= reg.width or vp_y >= reg.height:
                self._last_click_debug = {
                    "reason": "off_viewport",
                    "vp_x": vp_x, "vp_y": vp_y,
                    "vp_w": reg.width, "vp_h": reg.height,
                }
                return -1
            content_row = vp_y + int(scroll.scroll_y)
        except Exception:
            self._last_click_debug = {"reason": "scroll_query_fail"}
            return -1

        import bisect as _bs
        n           = len(self._seq)
        num_w       = len(str(n)) if n else 1
        line_width  = max(20, self._seq_render_width() - (num_w + 2))
        # Click resolution must use the SAME (seq, feats) the renderer
        # used — so when the map's origin is rotated, we resolve
        # clicks against the rotated views and convert the resulting
        # display bp back to absolute at the end. Without this, a
        # click on display row 0 col 0 with a non-zero origin would
        # land on absolute bp 0 (= the wrong base).
        disp_seq, disp_feats = self._get_rotated_state()
        # Insertion order — must match the renderer's `_build_seq_inputs`
        # so click resolution lands on the SAME packed_row as what's
        # actually drawn. Sorting by length here would diverge.
        annot_feats = [f for f in disp_feats
                       if f.get("type") not in ("site", "recut")]
        seq_col = vp_x - (num_w + 2)   # offset past the num+2-space prefix

        # Bisect into the cached chunk layout — pre-2026-05-06 this
        # function walked every chunk in the record on each click, so
        # a click on a 200 kb cosmid did ~1500 chunk decompositions
        # (each O(F)). `_hover_at` already uses this pattern; mirror it.
        chunks_layout, prefix_dna2, _pf_lanes = _chunk_layout(
            disp_seq, disp_feats, line_width,
        )
        if not chunks_layout:
            self._last_click_debug = {"reason": "no_chunks"}
            return -1
        idx = _bs.bisect_right(prefix_dna2, content_row) - 1
        if idx < 0 or idx >= len(chunks_layout):
            self._last_click_debug = {
                "reason": "past_content",
                "content_row": content_row,
                "total_rows": prefix_dna2[-1] if prefix_dna2 else 0,
            }
            return -1
        chunk_start, chunk_end, groups, *_extra = chunks_layout[idx]
        above_p, below_p, above_rows, below_rows = groups
        # Only the target chunk's feature decomposition is needed for
        # the lane-hit closure below; the layout cache already holds
        # placements for every chunk, but `_feats_in_chunk` is the
        # fallback the lane-fallback search consults.
        chunk_feats = _feats_in_chunk(
            annot_feats, chunk_start, chunk_end, n,
        )
        row_in_chunk = content_row - prefix_dna2[idx]

        def _check_packed(placements, screen_row_idx_from_top: int,
                              total_rows: int, is_below: bool):
                """Map a screen-row offset within the strand stack to a
                feature lane click. `screen_row_idx_from_top=0` is the
                first row drawn for that strand; below-DNA flips the
                packed-row index to account for the close→far order.

                Resolution tiers:
                  1. Glyph owner — if the clicked cell has a non-None
                     owner (= a feature's paint helper wrote a non-space
                     character there), pick that feature exactly. This
                     handles nested features pixel-accurately.
                  2. Footprint — if no glyph but the (col, row) cell
                     falls inside a feature's (bp range × footprint),
                     pick that feature. Catches empty cells inside a
                     feature's drawn footprint (e.g. padding around a
                     centered label).
                  3. Lenient (caller-side) — no footprint match either:
                     return -1 here so the caller's column-hits +
                     shorter-feature heuristic runs.
                """
                if is_below:
                    packed_row = screen_row_idx_from_top
                else:
                    packed_row = total_rows - 1 - screen_row_idx_from_top
                # Tier 1: pixel-accurate glyph owner. Lazy-built per
                # chunk and cached on the panel — first click in a
                # chunk pays ~1 ms; subsequent clicks are O(1).
                owners_data = self._chunk_glyph_owners(
                    chunk_start, chunk_end, chunk_feats,
                    above_p, below_p, above_rows, below_rows,
                )
                owners = (owners_data["owners_below"] if is_below
                          else owners_data["owners_above"])
                owner_feat = None
                if (0 <= packed_row < len(owners)
                        and 0 <= seq_col < len(owners[packed_row])):
                    owner_feat = owners[packed_row][seq_col]
                if owner_feat is not None:
                    # Replace the iteration with the single owner so
                    # the existing CDS-AA / resite / regular branches
                    # below still run their bookkeeping for the right
                    # feat. Footprint + bp-range checks below pass
                    # trivially since the owner painted a glyph here.
                    for pf, br in placements:
                        if pf is owner_feat:
                            placements = [(pf, br)]
                            break
                    self._last_resolve_via = "owner"
                else:
                    self._last_resolve_via = "footprint"
                # Expose click coords on every `_check_packed` so
                # successful resolutions also carry packed_row/seq_col
                # in the seq.mouse_down log — diagnoses "I clicked the
                # bar but got the wrong feat" without retrofitting a
                # second log call per branch.
                self._last_click_debug = {
                    "packed_row": packed_row,
                    "seq_col": seq_col,
                    "is_below": is_below,
                    "above_rows": above_rows,
                    "below_rows": below_rows,
                    "owner_set": owner_feat is not None,
                }
                # Tier 2 (and 1, when owner_feat replaces placements):
                # find the feature whose footprint covers
                # (col, packed_row) at the click column.
                for f, bottom_row in placements:
                    if not (bottom_row <= packed_row
                            < bottom_row + _feat_stack_height(f)):
                        continue
                    bar_s = max(f["start"], chunk_start) - chunk_start
                    bar_e = min(f["end"],   chunk_end)   - chunk_start
                    if bar_s <= seq_col < bar_e:
                        if f.get("type") == "resite":
                            self._last_resite_click = f
                        elif (f.get("type") == "CDS"
                                and packed_row - bottom_row == 0):
                            # AA sub-row click. Only count it as a
                            # codon click if the column actually
                            # carries an AA letter (= a codon midpoint
                            # of THIS CDS). Empty cells between
                            # letters are no-ops — the user explicitly
                            # asked that clicking the gap between
                            # amino acids do nothing.
                            click_bp = chunk_start + seq_col
                            # Original CDS bounds — wrap halves
                            # carry these in `_orig_*`; non-wrap
                            # falls back to the half's own coords.
                            orig_s = f.get("_orig_start", f["start"])
                            orig_e = f.get("_orig_end",   f["end"])
                            strand = f.get("strand", 1)
                            cs_off = max(0, min(2, int(f.get("codon_start", 1)) - 1))
                            n = len(self._seq)
                            if orig_e >= orig_s:
                                cds_len = orig_e - orig_s
                                virt_e  = orig_e
                            else:
                                cds_len = (n - orig_s) + orig_e if n else 0
                                virt_e  = orig_s + cds_len
                            n_codons = max(0, (cds_len - cs_off) // 3)
                            # Virtual click bp: for wrap CDS clicks
                            # in the head, shift by `n` so the codon
                            # math works in linear coordinates.
                            if orig_e < orig_s and click_bp < orig_s and n:
                                virt_click = click_bp + n
                            else:
                                virt_click = click_bp
                            on_letter = False
                            codon_idx = -1
                            if strand == -1:
                                # midpoint bp = virt_e - cs_off - 3*i - 2
                                delta = virt_e - cs_off - virt_click - 2
                                if delta >= 0 and delta % 3 == 0:
                                    codon_idx = delta // 3
                                    on_letter = 0 <= codon_idx < n_codons
                            else:
                                # midpoint bp = orig_s + cs_off + 3*i + 1
                                delta = virt_click - orig_s - cs_off - 1
                                if delta >= 0 and delta % 3 == 0:
                                    codon_idx = delta // 3
                                    on_letter = 0 <= codon_idx < n_codons
                            if on_letter:
                                # Codon spans 3 bp centred on click_bp;
                                # clamp at the seq ends but allow the
                                # codon range itself to wrap (cs > ce
                                # only happens at the very edges of a
                                # wrap CDS — `_user_sel` consumers
                                # already tolerate the linear case).
                                cs = click_bp - 1
                                ce = click_bp + 2
                                if 0 <= cs and ce <= n:
                                    # Codon coords go through to
                                    # `_user_sel` (the seq-panel range
                                    # selection) which lives in
                                    # absolute coords; convert from the
                                    # display coords we computed above
                                    # so a rotated view's codon click
                                    # still selects the right 3 bases
                                    # of the underlying record.
                                    self._last_aa_codon_click = (
                                        self._disp_to_abs(cs),
                                        self._disp_to_abs(ce),
                                    )
                                self._last_lane_click = True
                                self._last_lane_feat  = f
                                return self._disp_to_abs(click_bp)
                            # Click in an empty AA-row cell (between
                            # letters) — treat it as a click on the
                            # CDS itself so the previous selection
                            # gets cleared and this CDS becomes the
                            # active feature. Pre-fix this returned
                            # -1, which left the prior highlight
                            # stuck on screen and felt broken when
                            # the user "clicked another feature"
                            # within an overlapping CDS's footprint.
                            self._last_lane_click = True
                            self._last_lane_feat  = f
                            return self._disp_to_abs(
                                (f["start"] + f["end"]) // 2,
                            )
                        else:
                            self._last_lane_click = True
                        # Stash the actual feature dict so the App
                        # routes to THIS feature, not "smallest
                        # enclosing at midpoint" (which would mis-pick
                        # a small inner feature when the user's click
                        # landed on a larger overlapping bar).
                        self._last_lane_feat = f
                        return self._disp_to_abs(
                            (f["start"] + f["end"]) // 2,
                        )
                # Conservative lenient fallback — owner-fill missed
                # AND footprint loop missed (= click cell is outside
                # every feature's rectangle on this strand). If the
                # column has exactly ONE feature on this strand, that
                # is unambiguous user intent (clicked above/below a
                # standalone feature's footprint at its column). Pick
                # it. If multiple features share the column, return
                # -1 — the user's "no win/lose" rule still applies
                # in the ambiguous case.
                col_hits = [
                    (f, br) for (f, br) in placements
                    if (max(f["start"], chunk_start) - chunk_start)
                       <= seq_col
                       < (min(f["end"], chunk_end) - chunk_start)
                ]
                if len(col_hits) == 1:
                    f, _ = col_hits[0]
                    if f.get("type") == "resite":
                        self._last_resite_click = f
                    else:
                        self._last_lane_click = True
                    self._last_lane_feat = f
                    self._last_resolve_via = "lenient_solo"
                    return self._disp_to_abs(
                        (f["start"] + f["end"]) // 2,
                    )
                return -1

        # Per-chunk row layout (top → bottom):
        #   [0, above_rows)                              → above stack
        #   [above_rows, above_rows + 2)                 → fwd/rc DNA
        #   [above_rows + 2, above_rows + 2 + below_rows) → below stack
        #   above_rows + 2 + below_rows                  → trailing gap
        if row_in_chunk < above_rows:
            k  = row_in_chunk
            # `_check_packed` returns absolute bp already (its returns
            # all run through `_disp_to_abs`). No re-conversion here.
            bp = _check_packed(above_p, k, above_rows, False)
            if bp < 0:
                self._last_click_debug = {
                    "reason": "lane_miss_above",
                    "chunk": chunk_start // line_width,
                    "row_in_chunk": k,
                    "above_rows": above_rows,
                    "seq_col": seq_col, "line_width": line_width,
                    "n_above": len(above_p),
                }
            return bp
        if row_in_chunk < above_rows + 2:
            if 0 <= seq_col < (chunk_end - chunk_start):
                # `chunk_start + seq_col` is in DISPLAY coords (chunks
                # were built from the rotated views); convert back so
                # the caller's `_cursor_pos = bp` lands on the right
                # absolute base under a non-zero rotation.
                return self._disp_to_abs(chunk_start + seq_col)
            self._last_click_debug = {
                "reason": "dna_off_strand",
                "chunk": chunk_start // line_width,
                "strand": "fwd" if row_in_chunk == above_rows else "rc",
                "seq_col": seq_col, "line_width": line_width,
                "chunk_len": chunk_end - chunk_start,
            }
            return -1
        if row_in_chunk < above_rows + 2 + below_rows:
            k  = row_in_chunk - above_rows - 2
            bp = _check_packed(below_p, k, below_rows, True)
            if bp < 0:
                self._last_click_debug = {
                    "reason": "lane_miss_below",
                    "chunk": chunk_start // line_width,
                    "row_in_chunk": k,
                    "below_rows": below_rows,
                    "seq_col": seq_col, "line_width": line_width,
                    "n_below": len(below_p),
                }
            return bp
        # Trailing blank row appended in `_render_chunk` for
        # inter-chunk spacing — clicks here are no-ops.
        self._last_click_debug = {
            "reason": "inter_chunk_gap",
            "chunk": chunk_start // line_width,
            "seq_col": seq_col,
        }
        return -1

    # ── Helpers ────────────────────────────────────────────────────────────────

    def _bp_to_content_row(self, bp: int) -> int:
        """Return the content row index (0-based) of the DNA line containing bp.

        Accepts ``bp`` in ABSOLUTE record coords; converts to display
        coords for the chunk lookup so `center_on_bp` / `_ensure_
        cursor_visible` scroll to the right row under a non-zero
        rotation.

        O(1) via `_chunk_layout` prefix sums — direct index by `bp //
        line_width` plus arithmetic on cached above/below pair counts. The
        previous chunk-by-chunk re-scan was the bottleneck for cursor
        scrolling on cosmid/BAC-scale records (~50 ms/keystroke at 50 kb).
        """
        n = len(self._seq)
        if n == 0:
            return 0
        line_width = self._line_width()
        if line_width <= 0:
            return 0
        # Use the rotated views so the chunk layout matches what's
        # rendered. `_chunk_layout` is keyed on object id, so calling
        # with rotated views misses the unrotated cache (correctly).
        disp_seq, disp_feats = self._get_rotated_state()
        chunks_layout, prefix_dna2, prefix_lanes = _chunk_layout(
            disp_seq, disp_feats, line_width
        )
        if not chunks_layout:
            return 0
        # rpg is no longer meaningful in the 2D-packed renderer (each
        # chunk reports literal row counts directly); ignore connectors
        # for now — the show_connectors path is unused after the
        # 2026-04-30 packing refactor.
        # Convert absolute bp → display bp before chunk lookup.
        disp_bp = self._abs_to_disp(bp)
        chunk_idx = min(disp_bp // line_width, len(chunks_layout) - 1)
        chunk_info  = chunks_layout[chunk_idx]
        above_rows  = chunk_info[3]
        rows_before = prefix_dna2[chunk_idx]
        return rows_before + above_rows

    def _line_width(self) -> int:
        """Number of bp per displayed line."""
        n = len(self._seq)
        num_w = len(str(n)) if n else 1
        return max(20, self._seq_render_width() - (num_w + 2))

    def center_on_bp(self, bp: int) -> None:
        """Scroll the sequence panel so `bp` lands at the vertical centre of
        the viewport. Used by sidebar/map click handlers — the user has
        deliberately clicked, so don't make them hunt for the result.

        Defers via `call_after_refresh` so the scroll runs after the queued
        `view.update()` tick from the preceding highlight call. Uses
        `scroll_to(force=True)` rather than `scroll_y = ...`: a direct
        attribute set on a Reactive can be silently reverted by Textual's
        scroll-target watcher when it fires next, but `scroll_to` goes
        through the proper code path and `force=True` skips clamping.
        Symptom of the broken assignment: scroll moves to centre, then
        reverts on the next event — visible as a "snap back" jitter.

        If the viewport hasn't been laid out yet on the first refresh
        (`vp_h == 0`), retry once on the next refresh. Without the retry
        the centring silently no-ops under suite load — release.py's
        serial test path was hitting this ~30 % of the time.
        """
        if not self._seq or bp < 0:
            return
        row = self._bp_to_content_row(bp)

        def _do_scroll(remaining_retries: int = 3) -> None:
            try:
                scroll = self.query_one("#seq-scroll", ScrollableContainer)
            except NoMatches:
                return
            vp_h = scroll.size.height
            if vp_h <= 0:
                if remaining_retries > 0:
                    # Switch to set_timer for the deeper retries — under
                    # suite load `call_after_refresh` can fire BEFORE the
                    # next layout pass actually completes, so a tiny
                    # wall-clock delay is more reliable than another
                    # refresh-edge poll.
                    self.set_timer(
                        0.05, lambda: _do_scroll(remaining_retries - 1),
                    )
                return
            target_top = max(0, row - vp_h // 2)
            scroll.scroll_to(0, target_top, animate=False, force=True)

        self.call_after_refresh(_do_scroll)

    def _ensure_cursor_visible(self) -> None:
        """Follow the cursor: scroll the minimum necessary, no recentering.

        "Chunk" = the cursor's DNA pair plus the feature lanes (with
        labels) above and below it. Behaviour:

          - Chunk already fully in view → do nothing. The scroll bar
            stays put for every arrow press whose cursor lands in a
            row already on screen — no "pull back to recenter".
          - Chunk extends above the viewport → scroll up by exactly
            `vp_top - chunk_top` so `chunk_top` (the topmost label row
            of the above-lanes) lands at the viewport top.
          - Chunk extends below → scroll down by exactly
            `chunk_bottom - vp_bottom` so `chunk_bottom` (the bottommost
            below-lane row) lands at the viewport bottom.
          - Chunk taller than the viewport (very dense lane stacking) →
            track the cursor's DNA row only; whichever side the chunk
            spills off-screen on gets clipped. Direction-aware: if the
            DNA is above the viewport we pin it to vp_top (Up arrow
            into a tall chunk), if below we pin it to vp_bottom.

        No snap-to-extreme on first/last chunks. The user arrow nav
        wants the scroll bar to track row-by-row, not jump to either
        end of the document — and `chunk_top == 0` for chunk 0 (so
        target_top naturally lands at 0 when scrolling up into it),
        `chunk_bottom - vp_h + 1 == max_scroll_y` for the final chunk.
        The earlier explicit-snap branches always fired regardless of
        whether scrolling was needed, which read as a sudden jump.

        Uses `scroll_to(animate=False, immediate=True)` rather than the
        reactive-bypass `set_scroll`. `set_scroll` sets `scroll_y` via
        `set_reactive`, which skips the `watch_scroll_y` watcher — and
        that watcher is what propagates the new position to
        `vertical_scrollbar.position`. The scrollbar widget therefore
        renders one tick stale: content scrolls, the bar doesn't, the
        next event jolts the bar to where it should have been. That
        was the visible "borked tracking". `scroll_to` runs the full
        reactive pipeline (validators + watchers) so the bar repaints
        in lock-step with the content. `immediate=True` skips the
        default `call_after_refresh` defer; `animate=False` skips the
        smooth-scroll path entirely.

        Must be called BEFORE `_refresh_view()` so the new content
        paints with the new scroll position in the same tick.
        """
        if self._cursor_pos < 0 or not self._seq:
            return
        line_width = self._line_width()
        if line_width <= 0:
            return
        chunks_layout, prefix_dna2, prefix_lanes = _chunk_layout(
            self._seq, self._feats, line_width
        )
        if not chunks_layout:
            return

        chunk_idx = min(self._cursor_pos // line_width, len(chunks_layout) - 1)
        # Post-2026-04-30: chunks_layout stores literal row counts
        # (above_rows / below_rows) instead of pair counts × rpg.
        above_rows = chunks_layout[chunk_idx][3]
        below_rows = chunks_layout[chunk_idx][4]

        chunk_top    = prefix_dna2[chunk_idx]
        # `chunk_bottom` is the last row of the below-lane art for
        # this chunk (we exclude the trailing inter-chunk gap from
        # the "visible" footprint so a snap-into-view doesn't pull
        # the next chunk's lane art onto the bottom edge).
        chunk_bottom = chunk_top + above_rows + 2 + below_rows - 1

        try:
            scroll = self.query_one("#seq-scroll", ScrollableContainer)
        except NoMatches:
            return
        vp_top = int(scroll.scroll_y)
        vp_h   = scroll.size.height
        if vp_h <= 0:
            return
        vp_bottom = vp_top + vp_h - 1
        max_y    = scroll.max_scroll_y

        chunk_height = chunk_bottom - chunk_top + 1
        dna_row      = chunk_top + above_rows

        if chunk_height > vp_h:
            # Chunk doesn't fit — track the DNA row, lanes get clipped.
            # Direction-aware so an Up arrow into a tall chunk pins the
            # DNA at vp_top (above-lanes fill the viewport, below
            # clipped) and a Down arrow pins it at vp_bottom (below
            # clipped, above-lanes still as visible as they fit).
            if dna_row < vp_top:
                target_top = dna_row
            elif dna_row + 1 > vp_bottom:
                target_top = dna_row - vp_h + 2  # DNA pair at viewport bottom
            else:
                return
        elif chunk_top >= vp_top and chunk_bottom <= vp_bottom:
            # Already fully in view — do not scroll.
            return
        elif chunk_top < vp_top:
            # Scroll up just enough to expose the above-lanes + DNA.
            target_top = chunk_top
        else:
            # chunk_bottom > vp_bottom: scroll down just enough to fit
            # below-lanes.
            target_top = chunk_bottom - vp_h + 1

        target_top = max(0, min(target_top, max_y))
        if int(vp_top) == int(target_top):
            return
        scroll.scroll_to(0, target_top, animate=False, immediate=True)

    def _refresh_view(self) -> None:
        view = self.query_one("#seq-view", Static)
        try:
            scroll = self.query_one("#seq-scroll", ScrollableContainer)
        except NoMatches:
            scroll = None
        if not self._seq:
            view.update(Text("  No sequence loaded.", style="dim italic"))
            return
        # Rotated views: when `_view_origin_bp == 0` these alias the
        # absolute lists (no allocation); otherwise we render against
        # the rotated copy so display row 0 starts at the new origin.
        # Internal state (_cursor_pos, _sel_range, _user_sel,
        # _re_highlight, _aa_highlight) lives in absolute coords; we
        # shift to display coords ON THE WAY into `_build_seq_text`.
        disp_seq, disp_feats = self._get_rotated_state()
        # num_w-char line number + "  " (2) + seq = num_w + 2 overhead
        # Use actual scroll-container content width (excludes 2-col vertical scrollbar)
        num_w      = len(str(len(self._seq))) if self._seq else 1
        line_width = max(20, self._seq_render_width() - (num_w + 2))
        # Shift the cursor + selection ranges into display coords so
        # the renderer paints the highlight at the right cell after
        # rotation. Wrap-around selections (display end < start after
        # rotation) get the same handling that wrap features already
        # have in `_build_seq_text`.
        disp_cursor = self._abs_to_disp(self._cursor_pos)
        disp_sel    = (
            (self._abs_to_disp(self._sel_range[0]),
             self._abs_to_disp(self._sel_range[1]))
            if self._sel_range else None
        )
        disp_user_sel = (
            (self._abs_to_disp(self._user_sel[0]),
             self._abs_to_disp(self._user_sel[1]))
            if self._user_sel else None
        )
        disp_re_hi: "dict | None" = None
        if self._re_highlight:
            disp_re_hi = dict(self._re_highlight)
            disp_re_hi["start"]         = self._abs_to_disp(self._re_highlight["start"])
            disp_re_hi["end"]           = self._abs_to_disp(self._re_highlight["end"])
            disp_re_hi["top_cut_bp"]    = self._abs_to_disp(self._re_highlight.get("top_cut_bp", -1))
            disp_re_hi["bottom_cut_bp"] = self._abs_to_disp(self._re_highlight.get("bottom_cut_bp", -1))
            # `rec_start` / `rec_end` are the original recognition
            # bounds (used by the per-region renderer to distinguish
            # recognition from spacer/overhang). Without shifting
            # these the renderer would compare display-coord `i`
            # against absolute-coord `rec_*` and mis-classify every
            # base under non-zero rotation.
            disp_re_hi["rec_start"] = self._abs_to_disp(
                self._re_highlight.get("rec_start", -1)
            )
            disp_re_hi["rec_end"]   = self._abs_to_disp(
                self._re_highlight.get("rec_end", -1)
            )
        disp_aa_hi: "dict | None" = None
        if self._aa_highlight is not None:
            disp_aa_hi = dict(self._aa_highlight)
            disp_aa_hi["start"] = self._abs_to_disp(self._aa_highlight["start"])
            disp_aa_hi["end"]   = self._abs_to_disp(self._aa_highlight["end"])
        reh_key = (
            disp_re_hi["start"], disp_re_hi["end"]
        ) if disp_re_hi else None
        # Content-derived key matches the inner _CHUNK_OVERLAY_CACHE
        # so both invalidation layers see the same notion of "changed
        # active CDS".
        aa_key = (
            (disp_aa_hi["start"], disp_aa_hi["end"],
             disp_aa_hi.get("strand", 0))
            if disp_aa_hi is not None else None
        )
        # Lazy-render viewport: only chunks whose row range overlaps
        # the visible scroll window get fresh-rendered. Above the
        # `_LAZY_RENDER_THRESHOLD_BP` threshold the gain matters
        # (5 Mb chromosome first-render: 30 s → ~50 ms); below it
        # the overhead of the viewport check is negligible so we
        # pass it unconditionally. `vp` is rounded to a chunk-sized
        # quantum so that small scrolls don't always invalidate the
        # outer cache key — without this the user would pay a re-
        # render every time the scrollbar moved by a single line.
        vp = None
        if scroll is not None:
            try:
                scroll_y = int(scroll.scroll_y)
                vp_h     = max(1, int(scroll.size.height))
                # Pad both ends by one viewport so a fast scroll
                # already finds the next chunk pre-rendered. Quantize
                # by `vp_h` so the cache key is stable across small
                # scroll deltas.
                quant = vp_h
                lo = max(0, (scroll_y - vp_h) // quant * quant)
                hi = (scroll_y + 2 * vp_h + quant - 1) // quant * quant
                vp = (lo, hi)
            except Exception:
                vp = None
        key = (id(disp_seq), id(disp_feats), line_width,
               disp_sel, disp_user_sel, disp_cursor,
               self._show_connectors, reh_key, aa_key, vp,
               self._view_origin_bp)
        if key != self._view_cache_key:
            with _log_timing("seq.build_text"):
                self._view_cache_txt = _build_seq_text(
                    disp_seq, disp_feats,
                    line_width      = line_width,
                    sel_range       = disp_sel,
                    user_sel        = disp_user_sel,
                    cursor_pos      = disp_cursor,
                    show_connectors = self._show_connectors,
                    re_highlight    = disp_re_hi,
                    aa_highlight    = disp_aa_hi,
                    viewport_y_range = vp,
                )
            self._view_cache_key = key

        # Don't try to "preserve scroll across content update" here. An
        # earlier version captured `scroll.scroll_y` before `view.update`
        # and re-applied it via `call_after_refresh`. That fought with
        # `_ensure_cursor_visible`, which sets a NEW scroll target right
        # before `_refresh_view`: Textual hadn't propagated the new
        # `scroll_y` yet, so we'd capture the OLD value, then the
        # deferred would restore the OLD position — visible as a quick
        # scroll up followed by a snap back. Callers that change content
        # should set scroll before calling `_refresh_view`; the sync set
        # survives the refresh tick on its own.
        # Cache is populated by the `if key != …` block above on first
        # call (and any time the key changes); guard for the edge case
        # where `_build_seq_text` somehow returned None so we don't
        # pass None into `Static.update`.
        # `view.update()` is skipped when the same content has already
        # been pushed — `Static.update` triggers a full Textual layout
        # pass even with an unchanged renderable, which on a 45-row
        # fullscreen seq panel costs ~18 ms per call. Tracking the
        # last-pushed key separately means redundant `_refresh_view`
        # calls (resize callbacks, cursor moves that don't quantize
        # the viewport, focus changes, etc.) become near-free instead
        # of triggering a re-layout. Regression guard for 2026-05-04.
        if self._view_cache_txt is not None and \
                key != getattr(self, "_pushed_view_key", None):
            view.update(self._view_cache_txt)
            self._pushed_view_key = key

    def on_resize(self, _) -> None:
        self._refresh_view()


# ── Sequence edit dialog ───────────────────────────────────────────────────────

class EditSeqDialog(ModalScreen):
    """Insert or replace a sequence region via a small dialog.

    mode="insert"  — inserts new_seq at position start
    mode="replace" — replaces seq[start:end] with new_seq
    Dismisses with (new_seq, mode, start, end) on OK, or None on cancel.
    """

    _blocks_undo: bool = True   # sweep #10: app-level Ctrl+Z would race the insert

    _VALID = frozenset("ATCGNRYSWKMBDHV")   # IUPAC DNA codes

    BINDINGS = [
        Binding("escape", "cancel", "Cancel"),
        Binding("tab",    "app.focus_next", "Next", show=False),
    ]

    def __init__(self, mode: str, existing: str = "",
                 start: int = 0, end: int = 0):
        super().__init__()
        self._mode     = mode
        self._existing = existing
        self._start    = start
        self._end      = end

    def compose(self) -> ComposeResult:
        with Vertical(id="edit-dlg"):
            if self._mode == "insert":
                yield Static(
                    f" Insert sequence at position {self._start + 1} ",
                    id="edit-title",
                )
            else:
                excerpt = self._existing[:35] + ("…" if len(self._existing) > 35 else "")
                yield Static(
                    f" Replace {self._end - self._start} bp  "
                    f"({self._start + 1}‥{self._end}) ",
                    id="edit-title",
                )
                yield Static(f"  Current: {excerpt}", id="edit-current")
            yield Label("New sequence  (A T C G N and IUPAC codes only):")
            yield Input(id="edit-input", placeholder="ATCG…")
            yield Static("", id="edit-err")
            with Horizontal(id="edit-btns"):
                yield Button("OK", id="btn-ok", variant="primary")
                yield Button("Cancel", id="btn-cancel")

    def on_mount(self) -> None:
        self.query_one("#edit-input", Input).focus()

    @on(Input.Changed, "#edit-input")
    def _live_validate(self, event: Input.Changed) -> None:
        val = event.value.strip().upper()
        err = self.query_one("#edit-err", Static)
        if not val:
            err.update("")
            return
        bad = sorted(set(c for c in val if c not in self._VALID))
        if bad:
            chars = "  ".join(repr(c) for c in bad)
            err.update(Text(
                f"Invalid: {chars} — only A T C G N (IUPAC) allowed",
                style="bold red",
            ))
        else:
            err.update(Text(f"{len(val)} bp", style="dim green"))

    def _try_submit(self) -> None:
        val = self.query_one("#edit-input", Input).value.strip().upper()
        err = self.query_one("#edit-err", Static)
        if not val:
            err.update(Text("Please enter a sequence.", style="bold red"))
            return
        bad = [c for c in val if c not in self._VALID]
        if bad:
            return   # live validation already shows the error
        self.dismiss((val, self._mode, self._start, self._end))

    @on(Button.Pressed, "#btn-ok")
    def _ok(self, _) -> None:
        self._try_submit()

    @on(Button.Pressed, "#btn-cancel")
    def _cancel_btn(self, _) -> None:
        self.dismiss(None)

    @on(Input.Submitted, "#edit-input")
    def _submitted(self, _) -> None:
        self._try_submit()

    def action_cancel(self) -> None:
        self.dismiss(None)


# ── Help modal ─────────────────────────────────────────────────────────────────

class HelpModal(ModalScreen):
    """Keyboard-shortcut + feature-overview reference. Opened by `?`
    from anywhere in the app; dismissed by any key.

    Renders via Textual's `Markdown` widget so users can drag-select
    a key combination to clipboard (one of the few `Markdown`-only
    affordances). The body is a single `_HELP_BODY_MD` constant so
    binding changes only need to update one place."""

    BINDINGS = [
        Binding("escape", "dismiss_help", "Close"),
        Binding("?",      "dismiss_help", "Close"),
        Binding("q",      "dismiss_help", "Close"),
    ]

    DEFAULT_CSS = """
    HelpModal { align: center middle; }
    #help-box {
        width: 92; height: 90%; max-height: 40;
        background: $surface;
        border: solid $accent;
        padding: 1 2;
    }
    #help-title {
        text-style: bold;
        color: $accent;
        margin-bottom: 1;
    }
    /* The Markdown widget sits inside #help-body-scroll
       (VerticalScroll). The scroll wrapper takes the bulk of the
       dialog's free vertical space; #help-body itself is auto-sized
       to its rendered tables so the wrapper can scroll them. */
    #help-body-scroll { height: 1fr; min-height: 10; padding: 0 1; }
    #help-body { height: auto; }
    #help-hint {
        margin-top: 1;
        color: $text-muted;
        text-style: italic;
    }
    """

    def compose(self) -> ComposeResult:
        # Lazy-import Markdown — only triggered when the user opens the
        # `?` help modal. Saves ~125 ms of cold-launch time for users
        # who never open help (markdown_it + pygments + rich.markdown
        # otherwise import eagerly via `from textual.widgets import Markdown`).
        from textual.widgets import Markdown as _Markdown
        with Vertical(id="help-box"):
            yield Static("SpliceCraft — keyboard shortcuts", id="help-title")
            # Markdown widget itself is layout-only (not scrolling) —
            # wrap in VerticalScroll so the rendered tables stay inside
            # the modal box on small terminals.
            with VerticalScroll(id="help-body-scroll"):
                yield _Markdown(_HELP_BODY_MD, id="help-body")
            yield Static(
                "Press Esc, ?, or q to close.  Drag-select any cell "
                "to copy.",
                id="help-hint",
            )

    def action_dismiss_help(self) -> None:
        self.dismiss(None)

    def on_key(self, event) -> None:
        # Catch-all: any key not bound to a modal action also dismisses,
        # except the keys Markdown uses for in-content navigation
        # (arrows + page up/down + home/end). Without this exception,
        # arrow keys couldn't scroll the help body.
        nav_keys = {"up", "down", "left", "right",
                     "pageup", "pagedown", "home", "end"}
        if event.key in nav_keys:
            return
        if event.key not in ("escape", "question_mark", "q"):
            self.dismiss(None)
            event.stop()


