# ── What's New modal ──────────────────────────────────────────────────────────

# Cache: parsing the CHANGELOG is cheap, but the Markdown render of
# the body is the slow part and the modal opens on every version
# bump + on demand from File → What's New… Cache by (path, mtime)
# so an in-session edit to CHANGELOG.md isn't masked by a stale
# render.
_WHATS_NEW_CACHE: "tuple[str, float, str] | None" = None  # (path, mtime, body_md)

# Cap the modal to the most recent N releases. The full CHANGELOG
# is ~24 versions / 60 KB; rendering all of it through Textual's
# Markdown widget is noticeably slow on cold open and most users
# only care about what changed since they last upgraded. The
# remainder lives on GitHub; the body links there explicitly.
_WHATS_NEW_MAX_VERSIONS = 3
_WHATS_NEW_GITHUB_URL = (
    "https://github.com/Binomica-Labs/SpliceCraft/blob/master/CHANGELOG.md"
)

# Pre-compiled at module load — the parser runs over every line of
# CHANGELOG.md (hundreds of lines) and recompiling per call adds
# measurable overhead on a cold open.
_CHANGELOG_HEADING_RE = re.compile(r"^##\s*\[([^\]]+)\]")


def _parse_changelog_sections(changelog_md: str) -> list[tuple[str, str]]:
    """Split the CHANGELOG markdown into ``[(version, section_md), ...]``
    in source order. The "version" string is whatever appears between
    `[` and `]` on a `## [X.Y.Z]` heading; everything between that
    heading and the next `## [` (or end-of-file) is the section body.

    `[Unreleased]` blocks (if any) parse just like versioned ones —
    the caller can filter them out if it wants strict releases only.
    """
    sections: list[tuple[str, str]] = []
    cur_ver: "str | None" = None
    cur_buf: list[str] = []
    for ln in changelog_md.splitlines():
        m = _CHANGELOG_HEADING_RE.match(ln)
        if m:
            if cur_ver is not None:
                sections.append((cur_ver, "\n".join(cur_buf).rstrip()))
            cur_ver = m.group(1).strip()
            cur_buf = [ln]
        elif cur_ver is not None:
            cur_buf.append(ln)
    if cur_ver is not None:
        sections.append((cur_ver, "\n".join(cur_buf).rstrip()))
    return sections


def _version_sort_key(version_str: str) -> tuple:
    """Sort key for canonical SemVer / `X.Y.Z.W` strings — split on
    dots, parse each component as int (non-numeric tokens like
    `Unreleased` sort to the front so they appear above any released
    version). Returns a tuple suitable for `sorted(..., reverse=True)`
    so newer versions land first."""
    parts = version_str.strip().split(".")
    out: list = []
    for p in parts:
        try:
            out.append((1, int(p)))
        except ValueError:
            # Non-numeric component (e.g. `1.0rc1`, `Unreleased`):
            # rank them BEFORE numeric components when reversed,
            # i.e. they show at the top of the descending sort.
            out.append((2, p))
    return tuple(out) if out else ((0, ""),)


def _build_whats_new_body(changelog_md: str,
                            current_version: str,
                            max_versions: int = _WHATS_NEW_MAX_VERSIONS,
                            ) -> str:
    """Compose the Markdown body of the What's New modal.

    Pulls every `## [X.Y.Z]` section out of `changelog_md`, sorts
    the version blocks newest-first, and returns the most recent
    `max_versions` of them as one Markdown string. The body
    finishes with a footer pointing at the full changelog on
    GitHub for older releases.

    Adds a small thank-you header at the top reserving space for
    future contributor credits — referenced in each version's
    section as `**Contributors:** name1, name2` or wherever the
    maintainer chooses. Cite-by-name is intentional; the modal is
    where contributors get visible recognition without users
    having to dig through git log.
    """
    sections = _parse_changelog_sections(changelog_md)
    # Drop `[Unreleased]` (and any other non-numeric heading) — the
    # modal is for end users on a tagged build and should only
    # surface released versions. The parser keeps these blocks so
    # dev tooling can still see them; the filter lives here.
    sections = [
        (v, body) for (v, body) in sections
        if v and v[0:1].isdigit()
    ]
    sections.sort(key=lambda s: _version_sort_key(s[0]), reverse=True)
    if not sections:
        return ("# What's New in SpliceCraft\n\n"
                f"You're on **{current_version}**. No changelog "
                "entries parsed — see `CHANGELOG.md` in the repo.")
    cap = max(1, int(max_versions))
    shown = sections[:cap]
    truncated = len(sections) > len(shown)
    parts: list[str] = []
    parts.append("# What's New in SpliceCraft")
    parts.append(
        f"You're running **{current_version}**.  "
        f"Showing the {len(shown)} most recent release"
        f"{'s' if len(shown) != 1 else ''}, newest first. "
        "To see this dialog again any time, open "
        "`File → What's New…`."
    )
    parts.append("---")
    parts.append(
        "_A standing thank-you to everyone who flagged a bug, "
        "filed a feature request, or contributed code. "
        "Per-release contributor credits appear inline in the "
        "matching version block._"
    )
    for _ver, body in shown:
        parts.append(body)
    parts.append("---")
    if truncated:
        parts.append(
            "For older releases and the full version history, please "
            f"visit the GitHub changelog: <{_WHATS_NEW_GITHUB_URL}>"
        )
    else:
        parts.append(
            "Full changelog (mirrored on GitHub): "
            f"<{_WHATS_NEW_GITHUB_URL}>"
        )
    return "\n\n".join(parts)


def _load_whats_new_body(current_version: str) -> str:
    """Locate `CHANGELOG.md` next to the running module, parse it,
    and return the modal body. Cached on (path, mtime) so a quick
    reopen doesn't re-read the file but a mid-session edit (rare
    but possible during development) doesn't get masked. Falls
    back to a placeholder if the changelog is missing (e.g. a
    stripped wheel install on some platforms)."""
    global _WHATS_NEW_CACHE
    # Lookup order, first hit wins:
    #   1. Alongside the running module — works for the wheel install
    #      (CHANGELOG.md is bundled into the wheel as of 0.7.x; older
    #      wheels miss this file and fall through).
    #   2. One level up from the module — covers `pip install -e .` style
    #      development installs where splicecraft.py sits inside the repo
    #      and CHANGELOG.md is at the repo root.
    #   3. Current working directory — covers `python3 splicecraft.py`
    #      invocations from inside the source tree.
    here = Path(__file__).resolve().parent
    candidates = [
        here / "CHANGELOG.md",
        here.parent / "CHANGELOG.md",
        Path.cwd() / "CHANGELOG.md",
    ]
    cl_path: "Path | None" = next(
        (p for p in candidates if p.is_file()), None
    )
    if cl_path is None:
        return (f"# What's New in SpliceCraft\n\n"
                f"You're on **{current_version}**.\n\n"
                f"_(CHANGELOG.md not found in this install — see the "
                f"GitHub changelog for release notes:_ "
                f"<{_WHATS_NEW_GITHUB_URL}>)")
    cache_key = str(cl_path)
    try:
        mtime = cl_path.stat().st_mtime
    except OSError:
        mtime = 0.0
    if (_WHATS_NEW_CACHE is not None
            and _WHATS_NEW_CACHE[0] == cache_key
            and _WHATS_NEW_CACHE[1] == mtime):
        return _WHATS_NEW_CACHE[2]
    try:
        text = cl_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        _log.warning("Could not read CHANGELOG: %s", cl_path)
        return (f"# What's New in SpliceCraft\n\n"
                f"You're on **{current_version}** "
                "(could not read CHANGELOG.md).")
    body = _build_whats_new_body(text, current_version)
    _WHATS_NEW_CACHE = (cache_key, mtime, body)
    return body


class HistoryViewerModal(ModalScreen):
    """Construction-history viewer for a library plasmid.

    Renders the parsed `<HistoryTree>` from
    `_parse_commercialsaas_history` into a Textual Tree widget — each
    history step is one tree node, expandable to show its parent
    fragments. Used by the LibraryPanel's `h` key binding; the App
    handler builds the tree object and pushes this modal.

    The display is read-only — modifying history is the
    responsibility of the construction action that produced it
    (Traditional cloning Save, future: Mutagenesis, Gibson, etc.).
    Closing returns to the library panel; the tree is rebuilt
    fresh each open so library edits in another window are
    reflected on the next view.
    """

    BINDINGS = [
        Binding("escape", "dismiss_history", "Close"),
        Binding("q",      "dismiss_history", "Close"),
    ]

    DEFAULT_CSS = """
    HistoryViewerModal { align: center middle; }
    #hist-box {
        /* Was `height: 36;` (rigid) — switched to flex height with a
           cap so the dialog shrinks to content on a sparse history
           and still leaves Tree room to scroll on a deep one
           (2026-05-20 UX audit). */
        width: 110; height: 90%; max-height: 36; min-height: 18;
        background: $surface; border: solid $accent;
        padding: 1 2;
    }
    #hist-title {
        background: $accent-darken-2; padding: 0 1; margin-bottom: 1;
    }
    #hist-tree { height: 1fr; }
    #hist-detail {
        height: 8; border: solid $primary-darken-2;
        padding: 0 1; margin-top: 1; overflow-y: auto;
    }
    #hist-detail Static { padding: 0 1; }
    #hist-btns { height: 3; align: right middle; margin-top: 1; }
    #hist-btns Button { min-width: 10; }
    """

    def __init__(self, title: str,
                  root_node: "_CommercialSaaSHistoryNode") -> None:
        super().__init__()
        self._title = title
        self._root_node = root_node
        # Map Textual tree-node-id → CommercialSaaS history node, populated
        # in `on_mount`. Lets the Selected handler look up the
        # backing history node without re-parsing the XML.
        self._node_by_id: "dict[int, _CommercialSaaSHistoryNode]" = {}

    def compose(self) -> ComposeResult:
        with Vertical(id="hist-box"):
            yield Static(f" Construction history — {self._title} ",
                          id="hist-title")
            yield Tree("History", id="hist-tree")
            with Vertical(id="hist-detail"):
                yield Static(
                    "[dim]Pick a node to see its details.[/]",
                    id="hist-detail-text", markup=True,
                )
            with Horizontal(id="hist-btns"):
                yield Button("Close", id="btn-hist-close")

    def on_mount(self) -> None:
        tree = self.query_one("#hist-tree", Tree)
        tree.show_root = False
        tree.guide_depth = 4
        # Walk the CommercialSaaS history tree and populate the Textual
        # tree. The root CommercialSaaS node = the result plasmid (the
        # current library entry).
        def _add(parent_tree_node, hist_node: "_CommercialSaaSHistoryNode"):
            label = self._tree_label_for(hist_node)
            child = parent_tree_node.add(label, expand=True)
            self._node_by_id[child.id] = hist_node
            for parent in hist_node.parents:
                _add(child, parent)
        _add(tree.root, self._root_node)
        # Auto-select the root so the detail pane has something
        # interesting on open.
        try:
            top = tree.root.children[0]
            tree.select_node(top)
        except (IndexError, Exception):
            pass

    @staticmethod
    def _tree_label_for(node: "_CommercialSaaSHistoryNode") -> str:
        """One-line tree label — thin wrapper around the module-level
        `_history_tree_label` helper so the legacy modal and the
        fullscreen `HistoryScreen` render identical rows. Kept as a
        staticmethod for backwards compatibility with code that calls
        `HistoryViewerModal._tree_label_for(node)`."""
        return _history_tree_label(node)

    @on(Button.Pressed, "#btn-hist-close")
    def _on_close(self, _: Button.Pressed) -> None:
        self.dismiss(None)

    def action_dismiss_history(self) -> None:
        """Close the history viewer modal. Named distinctly from the
        Textual base `Screen.action_dismiss` (which is async + takes a
        result kwarg) so the override doesn't trip
        `reportIncompatibleMethodOverride` — the binding above routes
        to this method by name."""
        self.dismiss(None)

    @on(Tree.NodeSelected, "#hist-tree")
    def _on_node_selected(self, event) -> None:
        """When the user picks a node, render its full details (all
        attributes + regenerated sites + input summaries) into the
        bottom detail panel. Falls back gracefully if the lookup
        fails — defence-in-depth against the dict going stale."""
        hist = self._node_by_id.get(event.node.id)
        if hist is None:
            return
        try:
            detail = self.query_one("#hist-detail-text", Static)
        except NoMatches:
            return
        lines: list[str] = []
        lines.append(f"[b]{hist.name}[/]")
        lines.append(
            f"  {hist.seq_len:,} bp  ·  "
            f"{'circular' if hist.circular else 'linear'}  ·  "
            f"strandedness: "
            f"{hist.element.get('strandedness', '?')}  ·  "
            f"ID: {hist.node_id}"
        )
        lines.append(f"  operation: [cyan]{hist.operation}[/]")
        if hist.resurrectable:
            lines.append("  [green]✓ resurrectable[/] (parent fragment "
                          "can be re-extracted from history)")
        sites = hist.regenerated_sites
        if sites:
            joined = ", ".join(
                f"{s['name']}@{s['pos']}" for s in sites
            )
            lines.append(f"  regenerated sites: {joined}")
        for sm in hist.input_summaries:
            lines.append(
                f"  input: {sm['manipulation']}  "
                f"({sm['name1']}↔{sm['name2']})"
            )
        if hist.parents:
            lines.append(f"  parents: {len(hist.parents)} "
                          f"({', '.join(p.name for p in hist.parents)})")
        else:
            lines.append("  [dim](leaf — no recorded parents)[/]")
        detail.update("\n".join(lines))


_HISTORY_TITLE_NAME_MAX: int = 60
_HISTORY_LABEL_NAME_MAX: int = 40
_HISTORY_DETAIL_LIST_MAX: int = 12


def _history_tree_label(node: "_CommercialSaaSHistoryNode") -> str:
    """One-line tree label for the History viewer:
    ``name · N bp · circular · operation``.

    Names + operations are escaped against Rich markup injection (the
    fields come from XML attributes which can legally contain `[`)
    and truncated against extremely long values that would push the
    tree column off-screen. Empty strings render as ``(unnamed)`` /
    ``(no operation)`` so the row never collapses to whitespace."""
    from rich.markup import escape as _esc
    raw_name = node.name or "(unnamed)"
    name = _esc(raw_name)
    if len(raw_name) > _HISTORY_LABEL_NAME_MAX:
        name = _esc(raw_name[: _HISTORY_LABEL_NAME_MAX - 1] + "…")
    topo = "circular" if node.circular else "linear"
    op = _esc(node.operation) if node.operation else "(no operation)"
    return f"{name}  ·  {node.seq_len:,} bp  ·  {topo}  ·  {op}"


def _history_node_count(root: "_CommercialSaaSHistoryNode") -> int:
    """Number of nodes in the history tree, counting the root.
    Iterative so a hostile / pathologically deep XML can't trip the
    CPython recursion limit (mirrors `_CommercialSaaSHistoryNode.walk`)."""
    n = 0
    stack: list = [root]
    while stack:
        node = stack.pop()
        n += 1
        stack.extend(node.parents)
    return n


class HistoryScreen(Screen):
    """Full-screen construction-history viewer for the loaded plasmid.

    Same data shape as `HistoryViewerModal` — a `_CommercialSaaSHistoryNode`
    tree rendered into a Textual `Tree` widget plus a detail pane for
    the selected node — but takes the entire terminal. Opened from the
    `History` top-bar menu, the `F6` key, or `Ctrl+H`.

    Read-only. Closing returns to the main app; the tree is rebuilt
    fresh each open so the rendered lineage matches the current
    library state.

    Hardening notes (2026-05-11):
      * Tree assembly is iterative (`_build_tree`) — a 1000-deep
        history can't blow the recursion limit.
      * All user-controlled XML fields (`name`, `operation`,
        `manipulation`, enzyme names, parent labels) route through
        `rich.markup.escape` before reaching the detail pane / tree
        labels, so a `name="x[red]boom[/red]"` can't poison styling.
      * Long values (plasmid names, operation strings, enzyme lists,
        parent-name joins) are truncated with an ellipsis so the
        viewport stays usable on hostile / deeply-nested trees.
      * Empty XML attributes render as ``(unnamed)`` / ``(no
        operation)`` placeholders rather than collapsing to
        whitespace.
    """

    BINDINGS = [
        Binding("escape", "close",          "Close"),
        Binding("q",      "close",          "Close"),
        Binding("e",      "expand_all",     "Expand all", show=True),
        Binding("c",      "collapse_all",   "Collapse",   show=True),
    ]

    DEFAULT_CSS = """
    HistoryScreen { layout: vertical; background: $surface; }
    #hist-scr-title {
        background: $accent-darken-2; padding: 0 2; height: 1;
        text-style: bold;
    }
    #hist-scr-subtitle {
        background: $primary-darken-3; padding: 0 2; height: 1;
        color: $text-muted;
    }
    #hist-scr-main { layout: horizontal; height: 1fr; }
    #hist-scr-tree-col {
        width: 2fr; padding: 1 2;
        border-right: solid $primary-darken-2;
    }
    #hist-scr-detail-col { width: 1fr; padding: 1 2; }
    #hist-scr-tree-label, #hist-scr-detail-label {
        text-style: bold; color: $accent; margin-bottom: 1;
    }
    #hist-scr-tree { height: 1fr; }
    #hist-scr-detail {
        height: 1fr; border: solid $primary-darken-2;
        padding: 0 1; overflow-y: auto;
    }
    #hist-scr-detail Static { padding: 0 1; }
    #hist-scr-btns { height: 3; align: right middle; padding: 0 2; }
    #hist-scr-btns Button { min-width: 12; margin: 0 0 0 1; }
    """

    def __init__(self, title: str,
                  root_node: "_CommercialSaaSHistoryNode") -> None:
        super().__init__()
        # Truncate the title up front so the colored title bar can't
        # wrap or push the subtitle off-screen on narrow terminals.
        if len(title) > _HISTORY_TITLE_NAME_MAX:
            title = title[: _HISTORY_TITLE_NAME_MAX - 1] + "…"
        self._title = title
        self._root_node = root_node
        self._node_by_id: "dict[int, _CommercialSaaSHistoryNode]" = {}

    def compose(self) -> ComposeResult:
        from rich.markup import escape as _esc
        yield Static(f" Construction history — {_esc(self._title)} ",
                      id="hist-scr-title")
        n_nodes = _history_node_count(self._root_node)
        yield Static(
            f"  {n_nodes} node{'s' if n_nodes != 1 else ''}  ·  "
            "Esc / Q to close  ·  E expand all  ·  C collapse",
            id="hist-scr-subtitle",
        )
        with Horizontal(id="hist-scr-main"):
            with Vertical(id="hist-scr-tree-col"):
                yield Static("Lineage", id="hist-scr-tree-label")
                yield Tree("History", id="hist-scr-tree")
            with Vertical(id="hist-scr-detail-col"):
                yield Static("Step details", id="hist-scr-detail-label")
                with Vertical(id="hist-scr-detail"):
                    yield Static(
                        "[dim]Pick a node to see its details.[/]",
                        id="hist-scr-detail-text", markup=True,
                    )
        with Horizontal(id="hist-scr-btns"):
            yield Button("Close  [Esc]", id="btn-hist-scr-close")
        yield Footer()

    def on_mount(self) -> None:
        tree = self.query_one("#hist-scr-tree", Tree)
        tree.show_root = False
        tree.guide_depth = 4
        self._build_tree(tree)
        try:
            top = tree.root.children[0]
            tree.select_node(top)
        except (IndexError, Exception):
            pass

    def _build_tree(self, tree: Tree) -> None:
        """Populate the Textual `Tree` with our history nodes.

        Iterative DFS so a 1000+ deep history (hostile XML or a long
        chain of L0 → L1 → L2 → … builds) can't trip the CPython
        recursion limit. Mirrors `_CommercialSaaSHistoryNode.walk`'s
        iteration shape and `_history_node_count` so the three
        traversal helpers stay consistent.
        """
        stack: list[tuple] = [(tree.root, self._root_node)]
        while stack:
            parent_tree_node, hist_node = stack.pop()
            label = _history_tree_label(hist_node)
            child = parent_tree_node.add(label, expand=True)
            self._node_by_id[child.id] = hist_node
            # Push children reversed so the first parent pops next —
            # preserves the original pre-order traversal.
            stack.extend(
                (child, p) for p in reversed(hist_node.parents)
            )

    @on(Button.Pressed, "#btn-hist-scr-close")
    def _on_close(self, _: Button.Pressed) -> None:
        self.dismiss(None)

    def action_close(self) -> None:
        self.dismiss(None)

    def action_expand_all(self) -> None:
        """Force every tree node open. Useful when a deeply-nested
        lineage was collapsed by C and the user wants the full view
        back."""
        try:
            tree = self.query_one("#hist-scr-tree", Tree)
        except NoMatches:
            return
        try:
            tree.root.expand_all()
        except Exception:
            # Older Textual: fall back to manual walk.
            _stack = [tree.root]
            while _stack:
                n = _stack.pop()
                try:
                    n.expand()
                except Exception:
                    pass
                _stack.extend(n.children)

    def action_collapse_all(self) -> None:
        """Collapse every node but the root's direct children. The
        root itself is hidden so collapsing all the way would make
        the panel look empty — leave the first generation visible."""
        try:
            tree = self.query_one("#hist-scr-tree", Tree)
        except NoMatches:
            return
        for top in list(tree.root.children):
            _stack = list(top.children)
            while _stack:
                n = _stack.pop()
                try:
                    n.collapse()
                except Exception:
                    pass
                _stack.extend(n.children)

    @on(Tree.NodeSelected, "#hist-scr-tree")
    def _on_node_selected(self, event) -> None:
        """Render the picked node's full details into the right pane.
        Every dynamic field is escaped through `rich.markup.escape`
        so a name like ``[red]boom[/red]`` can't bend styling, and
        long joins are truncated so a node with hundreds of
        regenerated sites or parents doesn't blow up the column.

        Defence-in-depth — a stale dict lookup or missing widget
        returns silently rather than tracing back at the user."""
        from rich.markup import escape as _esc
        hist = self._node_by_id.get(event.node.id)
        if hist is None:
            return
        try:
            detail = self.query_one("#hist-scr-detail-text", Static)
        except NoMatches:
            return
        name_disp = _esc(hist.name) if hist.name else "[dim](unnamed)[/]"
        op_raw = hist.operation
        op_disp = (
            f"[cyan]{_esc(op_raw)}[/]" if op_raw
            else "[dim](not recorded)[/]"
        )
        strandedness = hist.element.get("strandedness") or "?"
        lines: list[str] = []
        lines.append(f"[b]{name_disp}[/]")
        lines.append("")
        lines.append("[b]Properties[/]")
        lines.append(f"  Length:        {hist.seq_len:,} bp")
        lines.append("  Topology:      "
                       f"{'circular' if hist.circular else 'linear'}")
        lines.append(f"  Strandedness:  {_esc(strandedness)}")
        lines.append(f"  Node ID:       {hist.node_id}")
        lines.append("")
        lines.append("[b]Operation[/]")
        lines.append(f"  {op_disp}")
        if hist.resurrectable:
            lines.append("  [green]✓ resurrectable[/] "
                          "[dim](parent can be re-extracted)[/]")
        sites = hist.regenerated_sites
        if sites:
            lines.append("")
            lines.append("[b]Regenerated sites[/]")
            shown = sites[: _HISTORY_DETAIL_LIST_MAX]
            joined = ", ".join(
                f"{_esc(str(s['name']) or '(unnamed)')}@{s['pos']}"
                for s in shown
            )
            if len(sites) > _HISTORY_DETAIL_LIST_MAX:
                joined += f", … (+{len(sites) - _HISTORY_DETAIL_LIST_MAX} more)"
            lines.append(f"  {joined}")
        sums = hist.input_summaries
        if sums:
            lines.append("")
            lines.append("[b]Inputs[/]")
            for sm in sums[: _HISTORY_DETAIL_LIST_MAX]:
                manip = _esc(str(sm.get('manipulation') or "(unknown)"))
                n1 = _esc(str(sm.get('name1') or "?"))
                n2 = _esc(str(sm.get('name2') or "?"))
                lines.append(f"  {manip}  ({n1} ↔ {n2})")
            if len(sums) > _HISTORY_DETAIL_LIST_MAX:
                lines.append(
                    f"  [dim]… (+{len(sums) - _HISTORY_DETAIL_LIST_MAX} more)[/]"
                )
        parents = hist.parents
        lines.append("")
        if parents:
            lines.append(f"[b]Parents ({len(parents)})[/]")
            shown = parents[: _HISTORY_DETAIL_LIST_MAX]
            joined = ", ".join(
                _esc(p.name or "(unnamed)") for p in shown
            )
            if len(parents) > _HISTORY_DETAIL_LIST_MAX:
                joined += (
                    f", … (+{len(parents) - _HISTORY_DETAIL_LIST_MAX} more)"
                )
            lines.append(f"  {joined}")
        else:
            lines.append("[dim](leaf — no recorded parents)[/]")
        detail.update("\n".join(lines))


class WhatsNewModal(ModalScreen):
    """Per-release "What's New" dialog.

    Auto-pushed once per version on app launch (once the splash is
    dismissed) and available any time from `File → What's New…`.
    The auto-trigger uses the persisted `last_seen_version` setting:
    if it differs from the running `__version__`, the modal shows
    and the setting bumps to the current version on dismiss. So
    a user who's already seen the dialog for `0.5.10.0` won't see
    it again until they upgrade to a newer version.

    Body is rendered from `CHANGELOG.md` via `_load_whats_new_body`,
    sorted newest-version-first. Scrollable; closes on Escape, the
    `Dismiss` button, or any key not bound to internal scroll
    (mirrors the HelpModal pattern).
    """

    BINDINGS = [
        Binding("escape", "dismiss_whatsnew", "Close"),
        Binding("q",      "dismiss_whatsnew", "Close"),
    ]

    DEFAULT_CSS = """
    WhatsNewModal { align: center middle; }
    /* Quiet, green-accented styling. Default Textual themes paint
       Markdown headings + the modal title with `$accent`, which
       in `dark-ansi` maps to ANSI yellow/orange — visually
       jarring against the rest of the app. We override every
       accented element with `$success` (green) so the modal reads
       as a calm "good news" colour instead. */
    #whatsnew-box {
        width: 92; height: 90%; max-height: 40;
        background: $surface;
        border: round $success;
        padding: 1 2;
    }
    #whatsnew-title {
        height: 1;
        text-style: bold;
        color: $success;
        margin-bottom: 1;
    }
    #whatsnew-body-scroll {
        height: 1fr; min-height: 10; padding: 0 1;
        background: $surface;
    }
    #whatsnew-body {
        height: auto;
        background: $surface;
    }
    /* Recolour every Markdown heading level — `## [version]` is
       the loudest highlight in a real CHANGELOG, and `### Added`
       / `### Fixed` show up in nearly every section. All four
       (H1 for the dialog header, H2/H3 for version + category,
       H4 as a tail) get the same green so the body reads as a
       single quiet palette. */
    #whatsnew-body MarkdownH1 {
        color: $success;
        text-style: bold;
        background: $surface;
    }
    #whatsnew-body MarkdownH2 {
        color: $success;
        text-style: bold;
        background: $surface;
    }
    #whatsnew-body MarkdownH3 {
        color: $success;
        text-style: bold;
        background: $surface;
    }
    #whatsnew-body MarkdownH4 {
        color: $success;
        text-style: bold;
        background: $surface;
    }
    /* Inline code spans (single backticks) — `File → What's New…`,
       `0.5.11.0`, `CHANGELOG.md`, etc. The default Markdown theme
       paints these with `$accent` (orange in `dark-ansi`). The
       Textual `MarkdownBlock` widget exposes the inline code
       style as a COMPONENT_CLASS named `code_inline` (note the
       underscore), so the selector is `MarkdownBlock > .code_inline`
       — matching the pattern Textual uses internally. We remap
       to a green-tinted background + green text so backtick spans
       blend into the rest of the modal palette. */
    #whatsnew-body MarkdownBlock > .code_inline {
        color: $success;
        background: $success 15%;
    }
    #whatsnew-hint {
        margin-top: 1;
        color: $text-muted;
        text-style: italic;
    }
    #whatsnew-btns { height: 3; margin-top: 1; align: right middle; }
    #whatsnew-btns Button { margin-right: 1; }
    """

    def __init__(self, current_version: "str | None" = None) -> None:
        super().__init__()
        self._version = str(current_version or __version__)

    def compose(self) -> ComposeResult:
        # Lazy-import Markdown — same rationale as HelpModal.compose.
        from textual.widgets import Markdown as _Markdown
        body_md = _load_whats_new_body(self._version)
        with Vertical(id="whatsnew-box"):
            # Title is text-only (no filled bar); the dot separator
            # keeps the version next to the heading without a
            # second row.
            yield Static(
                f"What's New  ·  v{self._version}",
                id="whatsnew-title",
            )
            with VerticalScroll(id="whatsnew-body-scroll"):
                yield _Markdown(body_md, id="whatsnew-body")
            yield Static(
                "Press Esc or q to close.", id="whatsnew-hint",
            )
            with Horizontal(id="whatsnew-btns"):
                yield Button("Dismiss", id="btn-whatsnew-dismiss",
                              variant="default")

    @on(Button.Pressed, "#btn-whatsnew-dismiss")
    def _on_dismiss_btn(self, _: Button.Pressed) -> None:
        self.dismiss(None)

    def action_dismiss_whatsnew(self) -> None:
        self.dismiss(None)


# ── Update check (PyPI) ───────────────────────────────────────────────────────

# Endpoint returns a JSON document with the latest released version
# at `info.version`. Hitting this is bandwidth-cheap (~7 KB
# response) and PyPI's CDN is fast worldwide. We never hit the
# package archive itself — just the metadata blob.
_PYPI_JSON_URL = "https://pypi.org/pypi/splicecraft/json"


def _resolve_pypi_url() -> str:
    """Return the URL that the PyPI update-check should hit. Honours
    `$SPLICECRAFT_PYPI_URL` so ops / corporate environments behind a
    PyPI mirror or an air-gapped index can redirect the check without
    a code patch.

    Validation: the override MUST be `http://` or `https://` to
    prevent `file://` / `ftp://` schemes that could exfiltrate
    information or read the local filesystem (Python's urllib will
    happily follow `file://`). Falls back to the default on any
    invalid / suspicious value, with a debug log so misconfiguration
    is diagnosable."""
    override = os.environ.get("SPLICECRAFT_PYPI_URL", "").strip()
    if not override:
        return _PYPI_JSON_URL
    lower = override.lower()
    if not (lower.startswith("https://") or lower.startswith("http://")):
        _log.warning(
            "$SPLICECRAFT_PYPI_URL=%r ignored: must be http(s)://",
            override,
        )
        return _PYPI_JSON_URL
    # Bound length too — a 10 MB env var would be silly but
    # someone could try.
    if len(override) > 2048:
        _log.warning(
            "$SPLICECRAFT_PYPI_URL ignored: too long (%d chars)",
            len(override),
        )
        return _PYPI_JSON_URL
    return override

# How long to trust a cached "latest version" answer before
# re-asking PyPI. 24 h keeps the chatter low while still surfacing
# new releases promptly for daily users.
_UPDATE_CHECK_INTERVAL_S = 24 * 60 * 60

# Hard timeout on the urllib fetch. Anything slower than this and
# we'd rather skip the check than block the worker thread for the
# session's lifetime. PyPI's CDN typically answers in <500 ms.
_UPDATE_CHECK_TIMEOUT_S = 3.0

# Hard ceiling on the PyPI response size — defence against an
# upstream returning a giant blob (compromised or misconfigured).
# The real splicecraft JSON document is ~10 KB; 256 KB is wildly
# generous while still bounding worker memory + parse time.
_PYPI_MAX_RESPONSE_BYTES = 256 * 1024


def _parse_pypi_version(v: str) -> "tuple[int, ...] | None":
    """Strict parser for canonical SpliceCraft version strings
    (`X.Y.Z` or `X.Y.Z.W`). Returns a tuple of ints for valid
    inputs or None for anything that doesn't fully parse —
    pre-releases, hashes, blank strings, etc. Returning None lets
    the comparator treat "weird PyPI metadata" as "don't notify"
    rather than silently producing a wrong answer."""
    if not isinstance(v, str):
        return None
    s = v.strip()
    if not s:
        return None
    parts = s.split(".")
    out: list[int] = []
    for p in parts:
        try:
            out.append(int(p))
        except ValueError:
            return None
    return tuple(out)


def _is_newer_pypi_version(remote: str, local: str) -> bool:
    """True iff `remote` parses as a strictly newer canonical
    version than `local`. Returns False for any parse failure or
    for equal versions — defensive: if we can't be sure, don't
    nag the user."""
    r = _parse_pypi_version(remote)
    l = _parse_pypi_version(local)
    if r is None or l is None:
        return False
    return r > l


def _fetch_latest_pypi_version(timeout: float = _UPDATE_CHECK_TIMEOUT_S
                                ) -> "str | None":
    """Hit PyPI's JSON metadata endpoint and return the published
    `info.version` string. Returns None for any network error,
    parse failure, or missing field — the caller treats None as
    "couldn't tell, skip notification".

    Pure stdlib (urllib + json), no third-party dependency. The
    UA string is set politely so PyPI's logs distinguish us from
    anonymous scrapers — they explicitly ask packaging clients to
    self-identify.

    Defensive: response is capped at `_PYPI_MAX_RESPONSE_BYTES`
    (much larger than any legitimate JSON payload for one package
    but small enough to bound memory + parse time on a malicious
    or misconfigured upstream); the parsed version string is
    capped at 64 chars (PEP 440 versions are far shorter).
    """
    import time as _time
    import urllib.request
    import urllib.error
    url = _resolve_pypi_url()
    req = urllib.request.Request(
        url,
        headers={
            "User-Agent": f"splicecraft/{__version__} (update-check)",
            "Accept": "application/json",
        },
    )
    # Single retry with 250 ms backoff to absorb transient flakiness
    # (DNS race on a flaky train Wi-Fi, brief 502 from a CDN edge,
    # etc.). Two attempts total — keeps the worst-case latency
    # bounded by 2 × timeout + backoff so the foreground UI doesn't
    # appear hung. Logged at DEBUG so the diagnostic bundle reflects
    # whether retries fire often.
    raw: "bytes | None" = None
    last_exc: "BaseException | None" = None
    for attempt in range(2):
        try:
            with urllib.request.urlopen(req, timeout=timeout) as resp:
                raw = resp.read(_PYPI_MAX_RESPONSE_BYTES + 1)
            break
        except (urllib.error.URLError, OSError, TimeoutError) as exc:
            last_exc = exc
            if attempt == 0:
                _log.debug("PyPI fetch attempt 1 failed (%s); retrying", exc)
                _log_event(
                    "net.retry", endpoint="pypi",
                    attempt=1, exc_type=type(exc).__name__,
                )
                _time.sleep(0.25)
                continue
            # Both attempts failed — fall through to the error path.
            raw = None
    try:
        if raw is None:
            raise last_exc if last_exc is not None else OSError("unknown PyPI fetch failure")
        if len(raw) > _PYPI_MAX_RESPONSE_BYTES:
            _log.debug("PyPI update check: response exceeded %d-byte cap",
                        _PYPI_MAX_RESPONSE_BYTES)
            return None
    except (urllib.error.URLError, OSError, TimeoutError) as exc:
        _log.debug("PyPI update check failed (network): %s", exc)
        return None
    try:
        data = json.loads(raw)
    except (json.JSONDecodeError, ValueError) as exc:
        _log.debug("PyPI update check failed (parse): %s", exc)
        return None
    info = data.get("info") if isinstance(data, dict) else None
    if not isinstance(info, dict):
        return None
    latest = info.get("version")
    if not isinstance(latest, str):
        return None
    latest = latest.strip()[:64]
    return latest or None


# ── Self-update subcommand (`splicecraft update`) ─────────────────────────────
#
# Detects how SpliceCraft was installed (pipx / pip --user / pip in venv /
# system pip / editable / source clone / unknown) and runs the matching
# upgrade command — so end users can `splicecraft update` instead of
# remembering whichever pip/pipx incantation they originally used.
#
# Hardening notes:
#   * subprocess invoked list-form (no shell, no env injection).
#   * Editable + source-clone installs refuse to run pip; they suggest
#     `git pull` instead — clobbering a developer's working tree with a
#     PyPI build would be hostile.
#   * System-wide pip installs print the sudo command but do NOT auto-run
#     sudo (interactive password prompts from inside an app are dangerous
#     and the surrounding TTY state is unpredictable).
#   * PyPI fetch reuses `_fetch_latest_pypi_version` (already timeout-
#     bounded + size-capped per the network-reads rule in CLAUDE.md).
#   * Confirmation prompt defaults to "no"; `--yes`/`-y` skips.
#   * `--check` is read-only — never invokes pip/pipx.
#   * Exit codes follow shell convention: 0 success, 1 runtime failure,
#     2 bad usage, 130 user-cancelled at the confirmation prompt.

# Names of upgrade methods returned by `_detect_install_method`. These
# strings appear in user-facing output and in the test suite, so they
# are deliberately stable.
_INSTALL_METHODS = (
    "pipx",          # pipx-managed venv (`pipx install splicecraft`)
    "uv-tool",       # `uv tool install splicecraft` (Astral uv)
    "uv-venv",       # `uv pip install splicecraft` inside a uv-created venv
    "pixi-global",   # `pixi global install splicecraft` (prefix.dev pixi)
    "pixi-project",  # splicecraft is in a pixi project env (`.pixi/envs/...`)
    "pip-user",      # `pip install --user splicecraft`
    "pip-venv",      # `pip install splicecraft` inside a virtualenv
    "pip-system",    # system-wide pip (e.g. /usr/lib/python*/site-packages)
    "editable",      # `pip install -e .` from a checkout
    "source",        # `python splicecraft.py` from a git clone, no install
    "unknown",       # everything else — we'll suggest a generic command
)


def _find_dist_info_dir(pkg_name: str = "splicecraft") -> "Path | None":
    """Return the *.dist-info directory for `pkg_name`, or None if the
    package isn't installed (e.g. running from a source clone) or the
    metadata location can't be determined.

    Pure-stdlib via `importlib.metadata`. We need the dist-info dir
    (rather than just the Distribution) so we can read its
    `direct_url.json` (PEP 610) to detect editable installs.
    """
    try:
        import importlib.metadata as ilm
    except ImportError:  # pragma: no cover — stdlib on 3.10+
        return None
    try:
        dist = ilm.distribution(pkg_name)
    except ilm.PackageNotFoundError:
        return None
    # `Distribution._path` is technically private but is the documented
    # location attribute on CPython's PathDistribution. Falling back to
    # walking RECORD covers the (rare) zipapp / non-PathDistribution
    # case without crashing.
    loc = getattr(dist, "_path", None)
    if loc is not None:
        try:
            p = Path(str(loc))
            if p.is_dir():
                return p
        except (OSError, ValueError):
            pass
    try:
        files = dist.files or []
    except (OSError, AttributeError):
        files = []
    for f in files:
        try:
            if f.name == "RECORD":
                return Path(str(f.locate())).parent
        except (OSError, ValueError):
            continue
    return None


def _detect_install_method() -> dict:
    """Inspect the running process to infer how SpliceCraft was
    installed. Returns a dict with these keys:

        method     — one of `_INSTALL_METHODS`
        module     — absolute path to the splicecraft.py being executed
                     (str; "" if `__file__` is unavailable)
        python     — sys.executable
        venv       — venv root (pipx / pip-venv) or None
        git_clone  — repo root if running from a git clone, else None
        details    — short human-readable explanation for `--check`
                     output and error messages

    Order of checks matters:
      1. editable (PEP 610 direct_url.json) — overrides path heuristics
      2. pipx (path component) — overrides generic venv detection
      3. source clone (`__file__` next to .git/ + pyproject.toml)
      4. pip-venv (sys.prefix differs from base_prefix)
      5. pip-user (`~/.local/` or `%APPDATA%`)
      6. pip-system (anything else with site-packages on the path)
      7. unknown
    """
    info: dict = {
        "method": "unknown",
        "module": "",
        "python": sys.executable,
        "venv": None,
        "git_clone": None,
        "details": "",
    }
    try:
        mod_path = Path(__file__).resolve()
    except (OSError, ValueError, NameError):
        info["details"] = "Cannot determine module location (__file__ unavailable)"
        return info
    info["module"] = str(mod_path)

    in_venv = sys.prefix != getattr(sys, "base_prefix", sys.prefix)
    if in_venv:
        info["venv"] = sys.prefix

    # Editable install? PEP 610: `direct_url.json` with
    # `dir_info.editable: true` lives in the dist-info dir.
    dist_info = _find_dist_info_dir("splicecraft")
    if dist_info is not None:
        durl = dist_info / "direct_url.json"
        if durl.is_file():
            try:
                d = json.loads(durl.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError, UnicodeDecodeError):
                d = None
            if isinstance(d, dict):
                dir_info = d.get("dir_info")
                if isinstance(dir_info, dict) and dir_info.get("editable") is True:
                    info["method"] = "editable"
                    src = d.get("url", "") or ""
                    info["details"] = (
                        f"Editable install (dist-info at {dist_info})"
                        if not src else
                        f"Editable install of {src}"
                    )
                    return info

    # Normalise path separators so the substring tests work the same
    # way on Linux, Mac, and Windows.
    mod_str = str(mod_path).replace("\\", "/")
    mod_lower = mod_str.lower()

    # uv tool — Astral's pipx-equivalent. Tools live in
    #   Linux/Mac:  ~/.local/share/uv/tools/splicecraft/
    #   Windows:    %APPDATA%/uv/tools/splicecraft/
    # Substring `/uv/tools/splicecraft/` is unique to this layout.
    if "/uv/tools/splicecraft/" in mod_lower:
        info["method"] = "uv-tool"
        for ancestor in mod_path.parents:
            if ancestor.name.lower() == "splicecraft" and \
                    ancestor.parent.name.lower() == "tools":
                info["venv"] = str(ancestor)
                break
        info["details"] = (
            f"uv-managed tool install (venv: {info['venv']})"
            if info["venv"] else
            "uv-managed tool install"
        )
        return info

    # pixi global — prefix.dev's pipx-equivalent. Envs at
    #   Linux/Mac:  ~/.pixi/envs/splicecraft/   ← hidden `.pixi`
    #   Windows:    %LOCALAPPDATA%/pixi/envs/splicecraft/   ← no dot
    # The leading-dot form on Linux/Mac means a substring match for
    # `/pixi/envs/splicecraft/` would NOT fire (the `/` precedes a
    # `.`, not a `p`), so we check both shapes. This must run BEFORE
    # the broader pixi-project check below — pixi-global is a subset
    # of that pattern, and the specific match must win.
    if (
        "/.pixi/envs/splicecraft/" in mod_lower
        or "/pixi/envs/splicecraft/" in mod_lower
    ):
        info["method"] = "pixi-global"
        for ancestor in mod_path.parents:
            if ancestor.name.lower() == "splicecraft" and \
                    ancestor.parent.name.lower() == "envs":
                info["venv"] = str(ancestor)
                break
        info["details"] = (
            f"pixi-managed global install (env: {info['venv']})"
            if info["venv"] else
            "pixi-managed global install"
        )
        return info

    # pixi project — splicecraft pulled in as a dependency of a pixi
    # project. Envs live at `<project>/.pixi/envs/<env_name>/` on
    # every platform (project-level config follows Unix dot-prefix
    # convention). We refuse to auto-upgrade these (the project
    # manifest, not PyPI, is the source of truth).
    if "/.pixi/envs/" in mod_lower or "/pixi/envs/" in mod_lower:
        info["method"] = "pixi-project"
        # Walk up to find the project root (the dir containing .pixi/).
        for ancestor in mod_path.parents:
            if ancestor.name.lower() in (".pixi", "pixi"):
                info["git_clone"] = str(ancestor.parent)
                break
        info["details"] = (
            f"pixi-managed project env (project: {info['git_clone']})"
            if info["git_clone"] else
            "pixi-managed project env"
        )
        return info

    # pipx — most reliable signal is the canonical path component.
    # Linux / Mac:  ~/.local/share/pipx/venvs/splicecraft/lib/...
    # Windows:      %USERPROFILE%/pipx/venvs/splicecraft/Lib/...
    # Some distros put pipx data at /opt/pipx; covered by the same
    # `/pipx/venvs/splicecraft/` substring.
    if "/pipx/venvs/splicecraft/" in mod_lower or "/pipx/shared/" in mod_lower:
        info["method"] = "pipx"
        # Walk up to find the venv root (parent of the splicecraft venv).
        for ancestor in mod_path.parents:
            if ancestor.name.lower() == "splicecraft" and \
                    ancestor.parent.name.lower() == "venvs":
                info["venv"] = str(ancestor)
                break
        info["details"] = (
            f"pipx-managed install (venv: {info['venv']})"
            if info["venv"] else
            "pipx-managed install"
        )
        return info

    # Source clone — running splicecraft.py directly from a git checkout
    # (no install). Detected by `__file__` sitting next to .git/ and
    # pyproject.toml. Editable installs were already handled above.
    parent = mod_path.parent
    try:
        is_git_clone = (parent / ".git").is_dir() and (parent / "pyproject.toml").is_file()
    except OSError:
        is_git_clone = False
    if is_git_clone:
        info["method"] = "source"
        info["git_clone"] = str(parent)
        info["details"] = f"Running from git clone at {parent}"
        return info

    # Generic venv — pip install inside a non-pipx, non-pixi-global,
    # non-uv-tool virtualenv. uv-created venvs are distinguished by a
    # `uv = <version>` line in `pyvenv.cfg` (uv writes this when it
    # creates the venv). Fall back to pip-venv if the cfg is missing,
    # unreadable, or doesn't carry the uv signature.
    if in_venv:
        is_uv_venv = False
        try:
            cfg = Path(sys.prefix) / "pyvenv.cfg"
            if cfg.is_file():
                # `pyvenv.cfg` is a tiny key=value file (~6 lines);
                # 16 KB is wildly more than any real one. Cap the read
                # so a bogus replacement on disk can't blow up RAM.
                text = cfg.read_text(encoding="utf-8", errors="replace")[:16384]
                for line in text.splitlines():
                    key = line.split("=", 1)[0].strip().lower()
                    if key == "uv":
                        is_uv_venv = True
                        break
        except (OSError, UnicodeDecodeError):
            pass
        if is_uv_venv:
            info["method"] = "uv-venv"
            info["details"] = f"uv-managed venv at {sys.prefix}"
        else:
            info["method"] = "pip-venv"
            info["details"] = f"pip install in virtualenv at {sys.prefix}"
        return info

    # User-site install — `~/.local/lib/.../site-packages/` on Linux,
    # `~/Library/Python/.../site-packages/` on Mac, `%APPDATA%/Python/`
    # on Windows.
    if (
        "/.local/lib/" in mod_lower
        or "/library/python/" in mod_lower
        or "/appdata/roaming/python/" in mod_lower
    ):
        info["method"] = "pip-user"
        info["details"] = "user-site pip install"
        return info

    # System site-packages — any other location with /site-packages/
    # in the path.
    if "/site-packages/" in mod_lower:
        info["method"] = "pip-system"
        info["details"] = f"system-wide install at {mod_path.parent}"
        return info

    # Couldn't classify — caller will recommend a generic command and
    # ask for confirmation before running anything.
    info["details"] = f"Unable to classify install at {mod_path}"
    return info


def _build_upgrade_command(method: str, *, force: bool, pre: bool = False,
                            pin_version: "str | None" = None) -> "list[str] | None":
    """Translate a detected install method into the argv list for the
    upgrade command. Returns None for methods that we refuse to upgrade
    automatically (`editable`, `source`, `pixi-project` — for the last,
    the project manifest is the source of truth).

    For `pip-system` we DO return a command list — but the caller is
    expected to print it for the user to run with sudo rather than
    invoking it directly.

    When ``pin_version`` is supplied (a validated version string like
    ``"0.8.10"``), the returned command installs that exact version
    instead of the PyPI latest. This is the downgrade-recovery path:
    if a release ships broken code, the user can roll the install
    itself back to the prior working version. Pinning implies
    ``--force`` semantics everywhere because every front-end refuses to
    "upgrade" to an older version — we have to ask for an explicit
    reinstall. ``pre`` is silently ignored when pinning because the
    user has already chosen the exact version they want.
    """
    if method in ("editable", "source", "pixi-project"):
        return None
    pkg_spec = f"splicecraft=={pin_version}" if pin_version else "splicecraft"
    pinned = pin_version is not None
    if method == "pipx":
        if force or pinned:
            # `pipx upgrade` is a no-op when versions match; `install
            # --force` re-runs the install end-to-end. Also the only
            # way to install a specific version (incl. older).
            return ["pipx", "install", "--force", pkg_spec]
        return ["pipx", "upgrade", "splicecraft"]
    if method == "uv-tool":
        if force or pinned:
            # `uv tool upgrade` is also a no-op when versions match;
            # `install --force` is the canonical re-run for uv tools.
            return ["uv", "tool", "install", "--force", pkg_spec]
        return ["uv", "tool", "upgrade", "splicecraft"]
    if method == "uv-venv":
        # uv-managed venv: prefer the uv front-end over plain pip so
        # the user's lockfile / cache stay consistent with how the
        # venv was built. When pinning, drop --upgrade (uv refuses to
        # "upgrade" to an older version) and add --reinstall so the
        # pinned spec wins over whatever is already installed.
        if pinned:
            cmd = ["uv", "pip", "install", "--reinstall", pkg_spec]
        else:
            cmd = ["uv", "pip", "install", "--upgrade", "splicecraft"]
            if force:
                cmd.append("--force-reinstall")
            if pre:
                cmd.insert(3, "--prerelease=allow")
        return cmd
    if method == "pixi-global":
        if force or pinned:
            # pixi global has no `--force` on update; the canonical
            # force-reinstall is `install --force`.
            return ["pixi", "global", "install", "--force", pkg_spec]
        return ["pixi", "global", "update", "splicecraft"]
    if method == "pip-user":
        if pinned:
            # Drop --upgrade (pip refuses to downgrade with --upgrade)
            # and use --force-reinstall so the pinned spec replaces the
            # installed package regardless of direction.
            return [sys.executable, "-m", "pip", "install", "--user",
                    "--force-reinstall", pkg_spec]
        cmd = [sys.executable, "-m", "pip", "install", "--user",
               "--upgrade", "splicecraft"]
        if force:
            cmd.append("--force-reinstall")
        if pre:
            cmd.insert(4, "--pre")
        return cmd
    # pip-venv, pip-system, unknown — same baseline command. Caller
    # decides whether to run it or just print it.
    if pinned:
        return [sys.executable, "-m", "pip", "install",
                "--force-reinstall", pkg_spec]
    cmd = [sys.executable, "-m", "pip", "install", "--upgrade", "splicecraft"]
    if force:
        cmd.append("--force-reinstall")
    if pre:
        cmd.insert(3, "--pre")
    return cmd


# PEP 440-lite: digits dot-separated, with optional pre-release / dev
# suffix. Matches the shapes SpliceCraft itself publishes and the
# common patterns on PyPI. Anchored so the entire string is the
# version — we never accept "0.8.10 ; os_name=='posix'" or any other
# environment-marker / extras / URL syntax through the pin flag. If a
# future SpliceCraft starts publishing post-release tags, extend this
# regex (and the corresponding test).
_PINNED_VERSION_RE = re.compile(
    r"^\d+(?:\.\d+){0,3}(?:(?:a|b|rc|\.dev|\.post)\d+)?$"
)


def _validate_pin_version(raw: str) -> "str | None":
    """Return the normalised version string if ``raw`` looks like a
    PyPI version SpliceCraft would publish, else ``None``. The caller
    is expected to surface a user-facing error on ``None``. Defence-in-
    depth before constructing the install command: an unvalidated
    string would land verbatim in the subprocess argv as
    ``splicecraft==<raw>``."""
    if not isinstance(raw, str):
        return None
    stripped = raw.strip()
    if not stripped:
        return None
    # Be permissive about a leading 'v' (`v0.8.10` from a git tag) but
    # strip it before validating — pip et al. expect bare digits.
    if stripped.lower().startswith("v"):
        stripped = stripped[1:]
    if len(stripped) > 64:
        return None
    if not _PINNED_VERSION_RE.match(stripped):
        return None
    return stripped


# ── Pre-update user-data snapshot (SACRED INVARIANT) ──────────────────────────
#
# Every running upgrade path (pipx / uv-tool / uv-venv / pixi-global / pip-*)
# MUST take a complete, atomic snapshot of the user's library, collections,
# parts bin, primers, feature library, custom grammars, codon tables,
# settings, crash-recovery autosaves, and `.dna` sidecars BEFORE the install
# subprocess starts. If the snapshot can't be made, the upgrade aborts —
# it is never acceptable to risk overwriting user data without a known-good
# copy first. This is enforced by `test_update_snapshot_taken_before_subprocess`
# in tests/test_smoke.py and must remain enforced by any future change.
#
# Snapshots live OUTSIDE `_DATA_DIR` (sibling at `<data_dir>/../<name>-update-
# backups/`) so a hypothetical bug in a new version that recursively wipes
# `_DATA_DIR` doesn't take the recovery copy with it. The location is
# overridable via $SPLICECRAFT_UPDATE_BACKUP_DIR.

# Canonical user-data files. Order matters for the manifest so a future
# audit can replay the snapshot in deterministic sequence; do not reorder.
_USER_DATA_FILE_ATTRS: tuple = (
    "_LIBRARY_FILE",          # plasmid_library.json — the user's plasmids
    "_COLLECTIONS_FILE",      # collections.json — collection definitions
    "_PARTS_BIN_FILE",        # parts_bin.json — active bin's parts (mirror)
    "_PARTS_BIN_COLLECTIONS_FILE",   # parts_bin_collections.json — all bins
    "_PRIMERS_FILE",          # primers.json — primer designs
    "_FEATURES_FILE",         # features.json — feature library
    "_FEATURE_COLORS_FILE",   # feature_colors.json — feature colours
    "_GRAMMARS_FILE",         # cloning_grammars.json — custom grammars
    "_ENTRY_VECTORS_FILE",    # entry_vectors.json — entry vectors
    "_CODON_TABLES_FILE",     # codon_tables.json — codon usage tables
    "_SETTINGS_FILE",         # settings.json — persisted user toggles
    "_EXPERIMENTS_FILE",      # experiments.json — lab-notebook entries
    "_EXPERIMENT_PROJECTS_FILE",  # experiment_projects.json — all projects
    "_GELS_FILE",             # gels.json — saved agarose-gel snapshots
)

# User-data sub-directories — autosaved unsaved-edits + .dna sidecars.
# Both are user-generated content the user might be relying on for recovery.
_USER_DATA_DIR_ATTRS: tuple = (
    "_CRASH_RECOVERY_DIR",   # autosaved .gb files for unsaved records
    "_DNA_ORIGINALS_DIR",    # .dna sidecars (CommercialSaaS round-trip)
    "_EXPERIMENTS_DIR",      # lab-notebook image attachments (per-entry)
    "_PLUGINS_DIR",          # reserved for future plugin storage (empty for now)
)

# Reserved field name for forward-compat plugin metadata on entries.
# Any entry in any user-data file may carry an `_plugin_data` dict
# whose keys are plugin names and whose values are arbitrary plugin
# state (must be JSON-serialisable). Round-trip preservation is
# enforced by `test_plugin_data_field_round_trip` in
# tests/test_smoke.py — the existing deepcopy-on-read + write-as-is
# loader pipeline already preserves unknown fields, but reserving
# the name explicitly here means we won't accidentally introduce a
# native field with the same name in a future schema.
_RESERVED_ENTRY_FIELDS: tuple = (
    "_plugin_data",
)

# Operational files: NOT user data. These are listed explicitly so that
# the `test_every_data_file_constant_is_classified` audit catches any
# new `_*_FILE` constant that a future contributor adds without
# deciding which list it belongs in. If you add a new `_*_FILE` and
# the audit fails, either:
#   * append it to `_USER_DATA_FILE_ATTRS` (it carries data the user
#     would lose if it were destroyed), OR
#   * append it here (it's regenerated/transient — agent tokens,
#     migration markers, ephemeral state).
_OPERATIONAL_FILE_ATTRS: tuple = (
    "_AGENT_TOKEN_FILE",      # ephemeral; regenerated each --agent-api launch
    "_DATA_VERSION_FILE",     # last-touched-version stamp; tiny, regenerated
)

# How many pre-update snapshots to keep before pruning oldest. 5 covers
# the realistic "I updated last week and now things look weird" window
# while bounding worst-case disk usage to ~5× the user's library size.
_PRE_UPDATE_SNAPSHOT_RETENTION = 5

# Filenames inside each snapshot directory.
_PRE_UPDATE_MANIFEST_NAME = "manifest.json"
_PRE_UPDATE_STAGING_PREFIX = ".tmp-"
# Manifests are pure JSON metadata (file list + checksums + small
# headers). Real manifests run ~2-16 KB; a few-MB cap leaves slack for
# unforeseen growth while refusing a planted multi-GB manifest that
# would OOM the launch-time listing or the restore handler. The
# directory is user-writable (sibling of _DATA_DIR by default), so a
# defensive cap matters even though normal flows never approach it.
_PRE_UPDATE_MANIFEST_MAX_BYTES = 4 * 1024 * 1024

# Snapshot manifest schema version. Bump this when the on-disk shape
# changes incompatibly (e.g., a new required field). Restore code
# refuses any manifest whose `schema_version` exceeds this — better
# to surface a clear error than to risk a silent partial restore. A
# manifest with a *lower* version still loads (additive fields are
# read with `.get(...)` defaults).
_PRE_UPDATE_SCHEMA_VERSION = 1

# Anchored regex for snapshot directory names. Retention pruning uses
# this so a maliciously symlinked or misconfigured `backup_dir` (e.g.
# pointing at `/`, `~`, or a system path with bin/etc/home subdirs)
# still cannot rmtree directories we did not create. The pattern
# matches every name `_create_pre_update_snapshot` ever produces —
# `<8-digit date>-<6-digit time>-<8-hex random>__from-<token>` plus
# an optional `.<int>` collision-bump suffix.
_PRE_UPDATE_NAME_RE = re.compile(
    r"^\d{8}-\d{6}-[0-9a-f]{8}__from-[A-Za-z0-9._-]+(?:\.\d+)?$"
)

# Front-end binary → homepage URL, surfaced in the "tool not on PATH"
# error message. Module-level (vs. inlined inside the function) so the
# table is one source of truth and easy to audit at a glance.
_MANAGER_HOMEPAGES = {
    "pipx": "https://pipx.pypa.io",
    "uv":   "https://docs.astral.sh/uv/",
    "pixi": "https://pixi.sh",
}


def _fsync_path(path: Path) -> None:
    """Best-effort fsync of a file or directory. Silently no-ops on
    platforms / filesystems that can't fsync the target (Windows
    refuses fsync on directories; some networked filesystems return
    ENOSYS). Used by the pre-update snapshot writer so a power loss
    between copy + os.replace can't leave a half-written manifest.

    Mirrors the durability convention `_safe_save_json` follows for
    JSON registry writes."""
    try:
        flag = os.O_RDONLY
        # Some POSIX flavours need O_DIRECTORY for dir fsync; missing
        # on Windows so we guard with getattr.
        if path.is_dir():
            flag |= getattr(os, "O_DIRECTORY", 0)
        fd = os.open(str(path), flag)
        try:
            os.fsync(fd)
        finally:
            os.close(fd)
    except (OSError, AttributeError, ValueError):
        # fsync is durability insurance; never let it crash a backup.
        pass


def _resolve_pre_update_backup_dir(data_dir: "Path | None" = None) -> Path:
    """Where pre-update snapshots are stored. Sibling of `_DATA_DIR` by
    default so a recursive wipe of `_DATA_DIR` doesn't take the
    snapshots with it. Overridable via $SPLICECRAFT_UPDATE_BACKUP_DIR
    (also honoured by tests so they never write to the user's real
    home directory).

    Hardened: resolves both inputs to canonical absolute paths so
    relative `_DATA_DIR` values, trailing slashes, and intermediate
    symlinks don't subtly change where snapshots land. Refuses paths
    that already exist as a file (won't silently overwrite), or
    derive into a filesystem root (parent.parent == parent) which
    almost certainly indicates a misconfigured data dir.
    """
    override = os.environ.get("SPLICECRAFT_UPDATE_BACKUP_DIR", "").strip()
    if override:
        candidate = Path(override).expanduser()
        # Resolve, but tolerate the common "doesn't exist yet" case —
        # `Path.resolve()` is non-strict by default since 3.6.
        candidate = candidate.resolve()
        if candidate.exists() and not candidate.is_dir():
            raise OSError(
                f"$SPLICECRAFT_UPDATE_BACKUP_DIR points at a non-directory "
                f"({candidate}). Set it to a writable directory path."
            )
        return candidate
    base = (data_dir if data_dir is not None else _DATA_DIR).resolve()
    parent = base.parent
    # Defensive guard: refuse to write a snapshot into a filesystem
    # root or any path where the parent is the same as the path
    # itself. `parent.parent == parent` is the cross-platform "is
    # filesystem root" check (covers `/`, `C:\`, network shares).
    if parent == base or parent.parent == parent:
        raise OSError(
            f"Refusing to derive a backup location next to {base!r} — "
            "set $SPLICECRAFT_UPDATE_BACKUP_DIR to a writable directory."
        )
    candidate = parent / f"{base.name}-update-backups"
    if candidate.exists() and not candidate.is_dir():
        raise OSError(
            f"Default backup location {candidate} is not a directory. "
            "Set $SPLICECRAFT_UPDATE_BACKUP_DIR to override."
        )
    return candidate


def _data_dir_inside_install_path() -> bool:
    """True if `_DATA_DIR` is somewhere underneath the install path
    (so a pip/pipx/uv/pixi reinstall would also wipe the user's
    library). Detects the only realistic path that defeats every
    other safeguard. Returns False if either path can't be resolved
    (no false positives)."""
    try:
        data = _DATA_DIR.resolve()
        mod = Path(__file__).resolve().parent
    except (OSError, ValueError, NameError):
        return False
    if data == mod:
        return True
    return mod in data.parents


def _iter_user_data_paths() -> "list[tuple[str, str, Path, str]]":
    """Yield `(attr_name, kind, path, name)` for every user-data file
    or directory that currently exists on disk.

    `kind` is `"file"` or `"dir"`. `name` is the basename used inside
    the snapshot. Reads the live module attribute each call so the
    autouse `_protect_user_data` test fixture's monkeypatched paths
    are picked up correctly.
    """
    out: list[tuple[str, str, Path, str]] = []
    for attr in _USER_DATA_FILE_ATTRS:
        p = globals().get(attr)
        if isinstance(p, Path) and p.is_file():
            out.append((attr, "file", p, p.name))
    for attr in _USER_DATA_DIR_ATTRS:
        p = globals().get(attr)
        if isinstance(p, Path) and p.is_dir():
            out.append((attr, "dir", p, p.name))
    return out


# ── Master Delete (Settings → File → wipe all user data) ─────────────────────
#
# User-triggered nuclear option. Wipes every persistent SpliceCraft file
# the user can produce — library, collections, parts bin, primers,
# experiments, gels, custom grammars, codon tables, feature library,
# feature colours, entry vectors, settings, pre-update snapshots,
# crash-recovery autosaves, .dna sidecars, daily snapshots, lost-entries
# spillover, UI snapshots, clipboard tmpfiles, rotated logs, and the
# agent-API token. Sibling pre-update-backups dir wiped too — true clean
# slate is the user contract.
#
# SACRED — two independent blockers against accidental fire:
#
#   1. **No agent endpoint.** `_AGENT_HANDLERS` has no `master_delete`
#      / `wipe` / `nuke` entry by design. An agent that knows the
#      function name cannot reach the wipe over HTTP. Enforced by
#      `tests/test_master_delete.py::test_no_agent_endpoint_exposes_wipe`.
#
#   2. **Module-local sentinel.** `_perform_master_delete` refuses to
#      run unless the caller passes `_MASTER_DELETE_SENTINEL` — a
#      module-private `object()`. The GUI modal flow is the only path
#      that has the reference. Any direct call (e.g. from an
#      `exec`-style debugger or a future API misuse) without the
#      sentinel raises RuntimeError BEFORE any file is touched.
#      Enforced by `tests/test_master_delete.py::test_sentinel_mismatch_refused`.
#
# UI-side hardening (`MasterDeleteModal`/`MasterDeleteConfirmModal`):
#   * Stage 1 = typed-YES gate (case-sensitive, exact match — "yes"/" YES"/
#     "YESS" all refused). Cancel default-focused. Esc → cancel.
#   * Stage 2 = "are you sure?" with Yes-button GATED by a 3-second
#     cool-down. No default-focused. Esc → No. Both `_blocks_undo=True`.
#   * No keyboard binding on `action_master_delete` — menu-only.
#   * Re-entrancy guard on `PlasmidApp._master_delete_in_progress`
#     prevents stacking two modal flows.

_MASTER_DELETE_SENTINEL = object()

# Cool-down before the Stage 2 confirm button enables. 3 seconds was
# chosen as the shortest delay that forces the user to read the
# warning copy after they've already typed YES + confirmed in the
# first modal — long enough to interrupt muscle-memory click-through,
# short enough not to feel like a punishment for a user who's
# deliberately wiping their workspace.
_MASTER_DELETE_CONFIRM_COOLDOWN_S = 3.0

# Module-level cache globals that hold cleared persisted state. Every
# entry MUST exist as `_<name>_cache: ... | None = None` somewhere in
# this module — `_perform_master_delete` looks them up by name and
# resets to None so the next read re-loads from (now empty) disk.
# Adding a new cache? Append it here AND to `_protect_user_data` in
# tests/conftest.py.
_MASTER_DELETE_CACHE_ATTRS: tuple = (
    "_library_cache",
    "_collections_cache",
    "_parts_bin_cache",
    "_parts_bin_collections_cache",
    "_primers_cache",
    "_features_cache",
    "_feature_colors_cache",
    "_grammars_cache",
    "_entry_vectors_cache",
    "_codon_tables_cache",
    "_settings_cache",
    "_experiments_cache",
    "_experiment_projects_cache",
    "_gels_cache",
)


def _master_delete_file_targets() -> "list[Path]":
    """Every regular file under `_DATA_DIR` that Master Delete removes.

    Built from `_USER_DATA_FILE_ATTRS` + `_OPERATIONAL_FILE_ATTRS`
    plus each file's `.bak` / `.bak.<ts>[.N]` siblings (`_safe_save_json`
    writes both single-gen + timestamped backups; cf. invariant #31).
    Reads live module attributes so the autouse `_protect_user_data`
    fixture's monkeypatch flows through.
    """
    out: list[Path] = []
    for attr in _USER_DATA_FILE_ATTRS + _OPERATIONAL_FILE_ATTRS:
        p = globals().get(attr)
        if not isinstance(p, Path):
            continue
        out.append(p)
        # Single-generation backup.
        out.append(p.with_suffix(p.suffix + ".bak"))
        # Timestamped rotating backups + same-second collision bumps.
        parent = p.parent
        if parent.is_dir():
            try:
                for sib in parent.glob(p.name + ".bak.*"):
                    out.append(sib)
            except OSError:
                pass
    return out


def _master_delete_dir_targets() -> "list[Path]":
    """Every directory directly under `_DATA_DIR` that Master Delete
    removes.

    `_USER_DATA_DIR_ATTRS` covers crash_recovery / dna_originals /
    experiments / plugins. The four ad-hoc dirs created inline by
    other code paths (snapshots / lost_entries / clipboard /
    ui_snapshots) are appended here so the wipe is exhaustive.

    Excludes the logs directory — the active log file is held open
    by `RotatingFileHandler`; rotated backups are handled separately
    by `_master_delete_log_files`. Excludes `_DATA_DIR` itself so the
    process-held lockfile survives.
    """
    out: list[Path] = []
    seen: set[Path] = set()

    def _add(p: Path) -> None:
        try:
            key = p.resolve(strict=False)
        except OSError:
            key = p
        if key in seen:
            return
        seen.add(key)
        out.append(p)

    for attr in _USER_DATA_DIR_ATTRS:
        p = globals().get(attr)
        if isinstance(p, Path):
            _add(p)
    # Ad-hoc dirs created inline elsewhere (no module constant for
    # most). Resolve `_DATA_DIR` at call time so monkeypatched test
    # paths are honoured.
    data_root = globals().get("_DATA_DIR")
    if isinstance(data_root, Path):
        for name in ("snapshots", "lost_entries", "clipboard"):
            _add(data_root / name)
    ui = globals().get("_UI_SNAPSHOTS_DIR")
    if isinstance(ui, Path):
        _add(ui)
    return out


def _master_delete_sibling_targets() -> "list[Path]":
    """Pre-update backup directory (sibling of `_DATA_DIR`).

    Resolved via `_resolve_pre_update_backup_dir` so
    `$SPLICECRAFT_UPDATE_BACKUP_DIR` (set by tests) takes precedence.
    Returns an empty list if the resolver refuses (filesystem root
    edge case) — nothing to wipe there.
    """
    out: list[Path] = []
    try:
        cand = _resolve_pre_update_backup_dir()
    except OSError:
        return out
    if isinstance(cand, Path):
        out.append(cand)
    return out


def _master_delete_extra_root_files() -> "list[Path]":
    """Stragglers directly under `_DATA_DIR` that aren't covered by
    `_USER_DATA_FILE_ATTRS` / `_OPERATIONAL_FILE_ATTRS` but are still
    user-impacting state. As of 2026-05-20 this is just the
    `.migrated` marker from `_migrate_legacy_data`; future additions
    can be appended here so they're explicitly enumerated rather
    than relying on the residual-sweep fallback.
    """
    out: list[Path] = []
    data_root = globals().get("_DATA_DIR")
    if isinstance(data_root, Path):
        out.append(data_root / ".migrated")
    return out


def _master_delete_residual_paths() -> "tuple[list[Path], list[Path]]":
    """Return (files, dirs) under `_DATA_DIR` left over after the
    named-target wipe finished. Returns empty lists if the data dir
    no longer exists.

    `splicecraft.lock` and the `logs/` directory are excluded — the
    lockfile is held by the running process; the logs dir contains
    the active log handle that `RotatingFileHandler` writes into.
    Both are handled by other parts of `_perform_master_delete`.

    Designed to be re-runnable: a second sweep should find nothing.
    Used as the final defense-in-depth pass so any future code that
    writes a new file under `_DATA_DIR` (without registering it in
    `_USER_DATA_FILE_ATTRS` / `_OPERATIONAL_FILE_ATTRS`) still gets
    wiped on Master Delete.
    """
    files: list[Path] = []
    dirs: list[Path] = []
    data_root = globals().get("_DATA_DIR")
    if not isinstance(data_root, Path):
        return files, dirs
    if not data_root.is_dir():
        return files, dirs
    # Anchor to the active lockfile + log dir resolved values so a
    # symlink-mediated path mismatch can't bypass the skip.
    lock_path = data_root / "splicecraft.lock"
    log_dir = data_root / "logs"
    try:
        lock_resolved = lock_path.resolve(strict=False)
    except OSError:
        lock_resolved = lock_path
    try:
        log_resolved = log_dir.resolve(strict=False)
    except OSError:
        log_resolved = log_dir
    try:
        children = list(data_root.iterdir())
    except OSError:
        return files, dirs
    for child in children:
        try:
            child_resolved = child.resolve(strict=False)
        except OSError:
            child_resolved = child
        if child_resolved == lock_resolved:
            continue
        if child_resolved == log_resolved:
            continue
        try:
            if child.is_symlink():
                # Symlinks under DATA_DIR are unusual; remove them
                # via unlink (don't follow into shared filesystems).
                files.append(child)
            elif child.is_file():
                files.append(child)
            elif child.is_dir():
                dirs.append(child)
        except OSError:
            continue
    return files, dirs


def _master_delete_log_files() -> "list[Path]":
    """Rotated log backups (`splicecraft.log.1`, `.2`, …) ready for
    deletion. The currently-open `_LOG_PATH` is excluded — closing the
    file handle out from under the running `RotatingFileHandler`
    works on POSIX but raises `PermissionError` on Windows. Restart
    rolls the active log into a fresh file naturally.
    """
    out: list[Path] = []
    log_path = globals().get("_LOG_PATH")
    if not log_path:
        return out
    try:
        log_file = Path(log_path)
    except (TypeError, ValueError):
        return out
    log_dir = log_file.parent
    if not log_dir.is_dir():
        return out
    try:
        active_resolved = log_file.resolve(strict=False)
    except OSError:
        active_resolved = log_file
    try:
        children = list(log_dir.iterdir())
    except OSError:
        return out
    for child in children:
        try:
            if not child.is_file():
                continue
            if child.resolve(strict=False) == active_resolved:
                continue
            out.append(child)
        except OSError:
            continue
    return out


def _perform_master_delete(app, *, sentinel) -> "dict[str, int | bool]":
    """Wipe every persistent SpliceCraft data file the user can produce.

    IRREVERSIBLE. No built-in restore path — Master Delete is for the
    user who actually wants a clean slate. Returns a summary dict
    (file/dir counts + error count + pre-update-dir flag) the
    success modal can quote.

    CONTRACT — sentinel must be `_MASTER_DELETE_SENTINEL`. Any other
    value raises RuntimeError BEFORE any disk operation. This is one
    of two independent blockers against agent / external misuse; the
    other is the absence of an `_AGENT_HANDLERS` entry.

    Locking — holds `_cache_lock` for the file-level delete + cache
    reset so a concurrent `_save_*` (settings flush daemon, agent
    save worker) cannot interleave a write into a wiped-then-half-
    revived state.

    Settings flush — cancels the pending payload before the cache
    reset; otherwise the daemon flush worker would write a stale
    settings dict onto the now-deleted file path.

    Agent server — stopped first so any in-flight authenticated
    agent connection cannot save data back into the wiped tree.
    `_stop_agent_api` unlinks the token file too.

    Active log file — left open. Lockfile — left in place. The wipe
    deliberately stays a no-op on those two so the running process
    survives. Caller's responsibility to ask the user to restart.
    """
    if sentinel is not _MASTER_DELETE_SENTINEL:
        raise RuntimeError(
            "Master Delete refused: sentinel mismatch. This function "
            "is GUI-only and intentionally not exposed to the agent "
            "API. If you see this error you are calling the function "
            "directly — don't."
        )

    summary: dict[str, int | bool] = {
        "files_removed":      0,
        "dirs_removed":       0,
        "log_files_removed":  0,
        "pre_update_removed": False,
        "residual_files":     0,
        "residual_dirs":      0,
        "errors":             0,
    }

    _log_event(
        "masterdelete.start",
        data_dir=str(globals().get("_DATA_DIR", "")),
    )

    # 1. Stop the agent API server BEFORE wipe. Defeats the race in
    #    which an authenticated agent session keeps writing to disk
    #    after Step 4a has nuked the files.
    try:
        srv = getattr(app, "_agent_api_server", None) if app else None
        if srv is not None:
            _stop_agent_api(srv)
            try:
                app._agent_api_server = None
            except AttributeError:
                pass
    except Exception:
        _log.exception("masterdelete: stop agent api failed")

    # 2. Drain in-flight workers (best-effort, 2 s). Heavy ops
    #    (BLAST runs, pairwise aligns) are non-cancellable; we wait
    #    out the timeout and continue regardless.
    try:
        _drain_in_flight_workers(timeout_s=2.0)
    except Exception:
        _log.exception("masterdelete: drain workers failed")

    # 3. Clear the BLAST LRU. Reuses the existing cache-invalidation
    #    hook used by collection saves.
    try:
        clear_blast = globals().get("_blast_clear_cache")
        if callable(clear_blast):
            clear_blast()
    except Exception:
        _log.exception("masterdelete: blast cache clear failed")

    # 4. Cancel pending settings flush AND wait for an in-flight
    #    daemon flush to drain before acquiring the cache lock.
    #
    #    Sweep #11 (2026-05-20): pre-fix `_settings_flush_pending`
    #    was cleared under `_settings_flush_lock` BUT the daemon
    #    worker doesn't hold that lock while inside `_safe_save_json`
    #    — it only holds the lock long enough to swap out the
    #    pending payload, then releases. So when Master Delete:
    #      1. Clears `_settings_flush_pending = None`
    #      2. Holds `_cache_lock` for file unlinks
    #    a daemon worker that already grabbed the payload BEFORE
    #    step 1 (but not yet finished its `os.replace`) finishes
    #    its write to settings.json AFTER our unlink, resurrecting
    #    settings data the user explicitly asked to wipe.
    #    Fix: clear pending under the flush lock, then BUSY-WAIT
    #    until `_settings_flush_running == False` (with a sane
    #    timeout so a hung worker doesn't wedge Master Delete).
    global _settings_flush_pending
    try:
        with _settings_flush_lock:
            _settings_flush_pending = None
    except NameError:
        pass
    # Drain handshake. The daemon's exit path sets
    # `_settings_flush_running = False` inside `_settings_flush_lock`,
    # so polling under the same lock guarantees we see the flag
    # only after the worker's `_safe_save_json` has completed.
    import time as _time
    _drain_deadline = _time.time() + 2.0
    while _time.time() < _drain_deadline:
        try:
            with _settings_flush_lock:
                if not _settings_flush_running:
                    break
        except NameError:
            break
        _time.sleep(0.01)
    else:
        _log.warning(
            "masterdelete: settings flush worker did not drain in 2s; "
            "proceeding (may need to re-wipe settings.json after restart)"
        )

    # 5. Hold the cache lock across file deletion + cache reset.
    #    Every `_save_*` helper takes this same lock, so a save
    #    queued behind us waits for the wipe to finish — and then
    #    finds the cache emptied so its `_typed_clone` returns a
    #    fresh-empty payload to write back to a never-existing file.
    with _cache_lock:
        # 5a. Files: enumerated user-data + operational + extra
        #     stragglers (.migrated marker etc.).
        for path in (_master_delete_file_targets()
                     + _master_delete_extra_root_files()):
            try:
                if path.is_symlink() or path.is_file():
                    path.unlink(missing_ok=True)
                    summary["files_removed"] += 1
            except OSError as exc:
                summary["errors"] += 1
                _log.warning(
                    "masterdelete: unlink %s failed: %s", path, exc,
                )

        # 5b. Directories under _DATA_DIR.
        for path in _master_delete_dir_targets():
            try:
                if path.is_dir() and not path.is_symlink():
                    shutil.rmtree(path)
                    summary["dirs_removed"] += 1
            except OSError as exc:
                summary["errors"] += 1
                _log.warning(
                    "masterdelete: rmtree %s failed: %s", path, exc,
                )

        # 5c. Sibling pre-update-backups dir (user contract: true
        #     clean slate, no recovery path).
        for path in _master_delete_sibling_targets():
            try:
                if path.is_dir() and not path.is_symlink():
                    shutil.rmtree(path)
                    summary["pre_update_removed"] = True
            except OSError as exc:
                summary["errors"] += 1
                _log.warning(
                    "masterdelete: rmtree sibling %s failed: %s",
                    path, exc,
                )

        # 5d. Rotated log backups. Active log handle preserved.
        for path in _master_delete_log_files():
            try:
                path.unlink(missing_ok=True)
                summary["log_files_removed"] += 1
            except OSError as exc:
                summary["errors"] += 1
                _log.warning(
                    "masterdelete: unlink log %s failed: %s", path, exc,
                )

        # 5e. Defense-in-depth: residual-sweep `_DATA_DIR` for any
        #     leftover file / dir that wasn't covered by the named
        #     targets above. Catches future code that writes a new
        #     persistent file under `_DATA_DIR` without registering
        #     it in `_USER_DATA_FILE_ATTRS` — without this pass a
        #     contributor could quietly leak data past a Master
        #     Delete by adding a new persistence file and forgetting
        #     to declare it. The active log and the lockfile are
        #     excluded inside `_master_delete_residual_paths`.
        residual_files, residual_dirs = _master_delete_residual_paths()
        for path in residual_files:
            try:
                path.unlink(missing_ok=True)
                summary["residual_files"] += 1
                _log_event(
                    "masterdelete.residual.file",
                    path=str(path),
                )
            except OSError as exc:
                summary["errors"] += 1
                _log.warning(
                    "masterdelete: residual unlink %s failed: %s",
                    path, exc,
                )
        for path in residual_dirs:
            try:
                shutil.rmtree(path)
                summary["residual_dirs"] += 1
                _log_event(
                    "masterdelete.residual.dir",
                    path=str(path),
                )
            except OSError as exc:
                summary["errors"] += 1
                _log.warning(
                    "masterdelete: residual rmtree %s failed: %s",
                    path, exc,
                )

        # 5f. Reset every module-level cache. The next read sees an
        #     empty disk → returns the empty-shape payload (`[]` /
        #     `{}`) without any further side effect.
        for cache_attr in _MASTER_DELETE_CACHE_ATTRS:
            if cache_attr in globals():
                globals()[cache_attr] = None

    # 6. Soft-reset in-memory app state OUTSIDE the lock. Best-effort
    #    — the data is already gone; never let a UI race re-raise.
    if app is not None:
        try:
            _reset_app_state_after_master_delete(app)
        except Exception:
            _log.exception("masterdelete: reset_app_state failed")

    _log_event(
        "masterdelete.completed",
        files_removed=summary["files_removed"],
        dirs_removed=summary["dirs_removed"],
        log_files_removed=summary["log_files_removed"],
        pre_update_removed=summary["pre_update_removed"],
        residual_files=summary["residual_files"],
        residual_dirs=summary["residual_dirs"],
        errors=summary["errors"],
    )
    return summary


def _reset_app_state_after_master_delete(app) -> None:
    """Clear in-memory state on `PlasmidApp` so the UI reflects the
    just-wiped disk. Best-effort: every attribute access is wrapped
    so a Textual quirk on shutdown never re-raises past the wipe
    itself.

    Does NOT clear the currently-loaded record on the canvas — the
    user may want to save it to disk after restart (the only reason
    to keep editing post-wipe). The post-wipe summary modal nudges
    them to restart for a fully clean state.
    """
    # Undo / redo stacks (loaded plasmid history) — never restore
    # plasmid state across a wipe.
    for attr in ("_undo_stack", "_redo_stack",
                  "_stashed_undo_stacks", "_stashed_redo_stacks",
                  "_stash_order"):
        # Sweep #10 (2026-05-20): `except (AttributeError, Exception)`
        # collapses to just `except Exception:` because Exception
        # subsumes AttributeError — the tuple form was misleading and
        # tripped the invariant #1 "no bare except" sweep. `getattr`
        # with default already handles AttributeError; the remaining
        # surface is `.clear()` raising on read-only mappings, which
        # is genuinely defensive.
        try:
            value = getattr(app, attr, None)
            if isinstance(value, list):
                value.clear()
            elif isinstance(value, dict):
                value.clear()
        except (TypeError, AttributeError):
            pass
    try:
        app._current_undo_key = None
    except AttributeError:
        pass
    # LibraryPanel is now empty on disk; refresh table so the UI
    # reflects that without waiting for a manual click.
    try:
        lib_panel = app.query_one("#library")
        refresh = getattr(lib_panel, "_refresh_table", None)
        if callable(refresh):
            refresh()
    except Exception:
        pass


def _sha256_file(path: Path) -> str:
    """SHA-256 of a file, computed in 64 KB chunks. Used in the
    manifest so a partial / truncated copy in a snapshot can be
    detected at restore time."""
    import hashlib
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(64 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _safe_snapshot_token(s: str, max_len: int = 32) -> str:
    """Sanitise a string for use inside a snapshot directory name.
    Strips path separators, leading dots, and anything outside a
    conservative ASCII set so the resulting filename is portable
    across Linux/Mac/Windows."""
    cleaned = re.sub(r"[^A-Za-z0-9._-]", "_", s)
    cleaned = cleaned.lstrip(".") or "x"
    return cleaned[:max_len]


def _enforce_pre_update_retention(backup_dir: Path,
                                    keep: int = _PRE_UPDATE_SNAPSHOT_RETENTION
                                    ) -> None:
    """Prune oldest snapshots in `backup_dir` so at most `keep`
    remain. Best-effort: a failed delete is logged but never raised
    (the snapshot we just took is more important than reaping old
    ones).

    SAFETY: rmtree is restricted to subdirectories whose names match
    the strict regex `_PRE_UPDATE_NAME_RE`. Without that filter, a
    misconfigured (or symlinked) `backup_dir` pointing at `/` or `~`
    could match `bin`/`etc`/`home`/etc. against the previous loose
    `not name.startswith(staging-prefix)` check — and rmtree the
    user's entire system. The regex names cannot occur anywhere
    except in directories `_create_pre_update_snapshot` itself
    produced. This is enforced by
    `test_retention_only_rmtrees_snapshot_named_dirs`.

    A symlinked backup_dir is also refused outright: if the user (or
    an attacker) replaces the backup location with a symlink, we
    don't follow it for cleanup purposes.
    """
    if keep < 0:
        keep = 0
    try:
        if not backup_dir.is_dir():
            return
        # Refuse to walk into a symlinked backup_dir. `is_symlink`
        # works on POSIX + Windows (NTFS junctions read as symlinks).
        if backup_dir.is_symlink():
            _log.warning(
                "Refusing retention sweep: %s is a symlink", backup_dir
            )
            return
        # Resolve to canonical path and re-check it isn't a system
        # root. Belt + suspenders against `SPLICECRAFT_UPDATE_BACKUP_DIR=/`.
        resolved = backup_dir.resolve()
        if resolved.parent == resolved:
            _log.warning(
                "Refusing retention sweep: %s resolves to a filesystem root",
                backup_dir,
            )
            return
        snaps = []
        for p in backup_dir.iterdir():
            if not p.is_dir():
                continue
            if p.is_symlink():
                # Don't follow symlinks during cleanup either.
                continue
            if not _PRE_UPDATE_NAME_RE.match(p.name):
                # Foreign directory — not one of ours. Leave alone.
                continue
            try:
                snaps.append((p.stat().st_mtime, p))
            except OSError:
                continue
        snaps.sort(reverse=True)  # newest first
        for _, old in snaps[keep:]:
            try:
                shutil.rmtree(old, ignore_errors=False)
            except OSError as exc:
                _log.warning("Could not prune old snapshot %s: %s", old, exc)
    except OSError as exc:
        _log.warning("Pre-update retention sweep failed: %s", exc)


@_timed("op.create_pre_update_snapshot")
def _create_pre_update_snapshot(version_from: str,
                                 *,
                                 backup_dir: "Path | None" = None,
                                 retention: int = _PRE_UPDATE_SNAPSHOT_RETENTION,
                                 ) -> Path:
    """Atomically snapshot every user-data file + directory into a
    fresh subdirectory of `backup_dir`. Returns the path to the
    completed snapshot. Raises `OSError` (or a subclass) if anything
    goes wrong — callers MUST treat that as "abort the upgrade".

    Atomicity: copying happens under a hidden staging directory on
    the same filesystem. The staging directory is renamed to its
    final name (`os.replace`) only after every file copy and the
    manifest write succeed. A partially-written staging directory is
    cleaned up before re-raising. The temp-dir + atomic-rename pattern
    mirrors `_safe_save_json`.

    The snapshot lives OUTSIDE `_DATA_DIR` (default sibling) so a
    bug in a new version that recursively wipes `_DATA_DIR` cannot
    destroy the recovery copy.
    """
    import datetime as _dt
    import secrets as _secrets

    if backup_dir is None:
        backup_dir = _resolve_pre_update_backup_dir()
    backup_dir.mkdir(parents=True, exist_ok=True)
    # Hardened: refuse to write into a symlinked backup_dir. Combined
    # with the symlink-aware retention sweep, this means even a
    # malicious environment variable can't trick us into writing to —
    # or later deleting from — a system path.
    if backup_dir.is_symlink():
        raise OSError(
            f"Refusing to use {backup_dir} as backup location: "
            "the path is a symlink."
        )

    ts = _dt.datetime.now().strftime("%Y%m%d-%H%M%S")
    rand = _secrets.token_hex(4)
    safe_ver = _safe_snapshot_token(version_from)
    staging = backup_dir / f"{_PRE_UPDATE_STAGING_PREFIX}{ts}-{rand}"
    final_name = f"{ts}-{rand}__from-{safe_ver}"
    final_path = backup_dir / final_name
    # Even with random hex, defensively bump the suffix if the final
    # name already exists (would only happen on a clock-rewind + hash
    # collision, but cheap insurance).
    bump = 0
    while final_path.exists():
        bump += 1
        final_path = backup_dir / f"{final_name}.{bump}"

    try:
        staging.mkdir(parents=True, exist_ok=False)
        sources = _iter_user_data_paths()
        manifest: dict = {
            "schema_version": _PRE_UPDATE_SCHEMA_VERSION,
            "from_version": version_from,
            "timestamp": ts,
            "data_dir": str(_DATA_DIR),
            # Capture the runtime Python + platform that wrote the
            # snapshot. Restore-time consumers (and `--list-snapshots`
            # display) use this to flag cross-platform / cross-Python
            # restores that may have unexpected side-effects (e.g.
            # binary-pickle state we may add later won't survive a
            # 3.10 → 3.14 jump). Additive — older readers ignore via
            # `.get(...)` defaults so this stays back-compatible.
            #
            # `_RUNTIME_PLATFORM` is computed once at module import so
            # we don't re-call `platform.platform()` every snapshot —
            # on some OSes that helper shells out via `subprocess`,
            # which conflicts with tests that monkeypatch `subprocess.run`
            # to capture the upgrade command.
            "from_python_version": "{}.{}.{}".format(
                sys.version_info[0], sys.version_info[1], sys.version_info[2]
            ),
            "from_platform": _RUNTIME_PLATFORM,
            "files": [],
            "directories": [],
        }
        for attr, kind, src, name in sources:
            dst = staging / name
            if kind == "file":
                shutil.copy2(src, dst)
                # Durability: fsync the copy before the atomic
                # rename so a power loss between copy and replace
                # can't leave a half-written file with a manifest
                # that claims it's complete. Mirrors `_safe_save_json`.
                _fsync_path(dst)
                # Hash the destination (post-copy) so a silent corrupt
                # would be visible in the manifest.
                manifest["files"].append({
                    "attr": attr,
                    "name": name,
                    "size": dst.stat().st_size,
                    "sha256": _sha256_file(dst),
                })
            else:  # kind == "dir"
                shutil.copytree(src, dst)
                # Best-effort fsync of every file inside the copied
                # tree. We don't error out if a single file can't be
                # fsynced (read-only mounts, network FS quirks).
                try:
                    for f in dst.rglob("*"):
                        if f.is_file():
                            _fsync_path(f)
                except OSError:
                    pass
                # Counting + size for directories is informational only;
                # restoring uses the directory tree as-is.
                file_count = sum(1 for _ in dst.rglob("*") if _.is_file())
                manifest["directories"].append({
                    "attr": attr,
                    "name": name,
                    "file_count": file_count,
                })
        # Manifest goes in last so its presence is itself a "snapshot
        # is complete" marker. Restore code refuses to operate on a
        # snapshot dir without a manifest. Fsync it so the manifest's
        # existence is durable before the directory rename below.
        manifest_path = staging / _PRE_UPDATE_MANIFEST_NAME
        manifest_path.write_text(
            json.dumps(manifest, indent=2),
            encoding="utf-8",
        )
        _fsync_path(manifest_path)
        # Fsync the staging directory so the new entries (manifest +
        # copies) are durable in the directory's metadata before we
        # rename it to its final visible name. POSIX-only; the helper
        # silently no-ops on Windows.
        _fsync_path(staging)
        # Atomic rename — single filesystem op on POSIX, transactional
        # MoveFileEx on Windows. After this point the snapshot is
        # visible at its final name; before it, only `.tmp-...` exists.
        os.replace(staging, final_path)
        # Fsync the parent so the rename itself is durable.
        _fsync_path(backup_dir)
    except (OSError, shutil.Error):
        # Best-effort cleanup of the partial staging dir.
        try:
            if staging.exists():
                shutil.rmtree(staging, ignore_errors=True)
        except OSError:
            pass
        raise

    # Retention: prune oldest snapshots beyond N. Best-effort — never
    # let a retention failure invalidate the snapshot we just took.
    _enforce_pre_update_retention(backup_dir, keep=retention)
    return final_path


def _list_pre_update_snapshots(backup_dir: "Path | None" = None
                                ) -> "list[dict]":
    """Return a list of snapshot summaries, newest first. Each entry:
        {id, path, mtime, from_version, n_files, n_dirs, total_size}
    `id` is the directory's basename (what the user passes to
    --restore-pre-update). Snapshots without a manifest are skipped
    (those are partially-written or hand-corrupted)."""
    if backup_dir is None:
        try:
            backup_dir = _resolve_pre_update_backup_dir()
        except OSError:
            return []
    if not backup_dir.is_dir():
        return []
    out: list[dict] = []
    for p in backup_dir.iterdir():
        if not p.is_dir():
            continue
        if p.name.startswith(_PRE_UPDATE_STAGING_PREFIX):
            continue
        manifest = p / _PRE_UPDATE_MANIFEST_NAME
        if not manifest.is_file():
            continue
        ok_size, _reason = _safe_file_size_check(
            manifest, _PRE_UPDATE_MANIFEST_MAX_BYTES, "pre-update manifest",
        )
        if not ok_size:
            _log.warning("pre-update snapshot %s: manifest rejected (%s)",
                         p.name, _reason)
            continue
        try:
            data = json.loads(manifest.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError, UnicodeDecodeError):
            continue
        try:
            mtime = p.stat().st_mtime
        except OSError:
            continue
        total = 0
        try:
            for f in p.rglob("*"):
                if f.is_file():
                    total += f.stat().st_size
        except OSError:
            pass
        out.append({
            "id": p.name,
            "path": p,
            "mtime": mtime,
            "from_version": data.get("from_version", "?"),
            # Newer fields — older snapshots return defaults so the
            # listing stays backward-compatible.
            "from_python_version": data.get("from_python_version", "?"),
            "from_platform": data.get("from_platform", "?"),
            "schema_version": data.get("schema_version", 1),
            "n_files": len(data.get("files", [])) if isinstance(data.get("files"), list) else 0,
            "n_dirs": len(data.get("directories", [])) if isinstance(data.get("directories"), list) else 0,
            "total_size": total,
        })
    out.sort(key=lambda e: e["mtime"], reverse=True)
    return out


def _validate_snapshot_member(snap_path: Path, name: str) -> "Path | None":
    """Return the absolute path of a manifest-named snapshot member,
    or None if the name would escape the snapshot directory (path
    traversal) or contain a separator. Pure validation — never
    touches the filesystem.

    A manifest is JSON, and JSON is plaintext: anyone with write
    access to the backup directory could craft `name: "../../foo"`
    to read or overwrite arbitrary files. This guard reduces every
    `name` to a single basename and verifies the resolved path is
    still under the snapshot directory.
    """
    if not isinstance(name, str) or not name:
        return None
    # Reject anything that smells like a path component vs. a basename.
    if "/" in name or "\\" in name or name in (".", ".."):
        return None
    candidate = (snap_path / name).resolve()
    snap_resolved = snap_path.resolve()
    try:
        # Python 3.9+ has Path.is_relative_to. We're on 3.10+ per
        # pyproject; safe to use directly.
        if not candidate.is_relative_to(snap_resolved):
            return None
    except (AttributeError, ValueError):
        return None
    return candidate


@_timed("op.restore_pre_update_snapshot")
def _restore_pre_update_snapshot(snap_id_or_path: "str | Path",
                                  *,
                                  backup_dir: "Path | None" = None,
                                  ) -> dict:
    """Restore a pre-update snapshot. Each canonical JSON is replaced
    via the temp-file + os.replace pattern (same as `_safe_save_json`).
    Sub-directories are restored by atomically renaming the current
    directory aside, copying the snapshot in, then removing the
    stash. A pre-restore snapshot is taken first so the user can
    undo a bad restore.

    Hardening (sacred — do not relax without a corresponding test):
      * `schema_version` must be ≤ `_PRE_UPDATE_SCHEMA_VERSION`. A
        higher version means the snapshot was written by a newer
        SpliceCraft we don't know how to read; refuse rather than
        silently restore an unfamiliar shape.
      * Each `attr` in the manifest must be in `_USER_DATA_FILE_ATTRS`
        or `_USER_DATA_DIR_ATTRS`. A tampered manifest cannot target
        arbitrary `_*_FILE` attributes (e.g. agent token, install
        marker) for overwrite.
      * Each `name` must be basename-only and resolve under the
        snapshot directory. Blocks path-traversal reads.
      * Each file's SHA-256 (per the manifest) is recomputed on the
        copy BEFORE the atomic os.replace overwrites the user's
        current file. A bit-rotted snapshot cannot silently corrupt
        good live data.
      * Directory restore rolls back fully on partial copytree:
        delete the partial target, then rename stash back.

    Returns a summary dict:
        {pre_restore_snapshot, restored_files, restored_dirs,
         failed: [(name, reason), ...]}
    Raises FileNotFoundError if the snapshot id doesn't exist.
    Raises ValueError on unsupported schema version.
    """
    if backup_dir is None:
        backup_dir = _resolve_pre_update_backup_dir()
    if isinstance(snap_id_or_path, Path):
        snap_path = snap_id_or_path
    else:
        # Allow either a bare snapshot id (basename) or 'latest'.
        snap_id = str(snap_id_or_path).strip()
        if snap_id.lower() == "latest":
            snaps = _list_pre_update_snapshots(backup_dir)
            if not snaps:
                raise FileNotFoundError(
                    f"No pre-update snapshots in {backup_dir}"
                )
            snap_path = snaps[0]["path"]
        else:
            snap_path = backup_dir / snap_id
    if not snap_path.is_dir():
        raise FileNotFoundError(f"snapshot not found: {snap_path}")
    manifest_path = snap_path / _PRE_UPDATE_MANIFEST_NAME
    if not manifest_path.is_file():
        raise FileNotFoundError(
            f"snapshot is incomplete (no manifest): {snap_path}"
        )
    ok_size, reason = _safe_file_size_check(
        manifest_path, _PRE_UPDATE_MANIFEST_MAX_BYTES, "pre-update manifest",
    )
    if not ok_size:
        raise ValueError(f"manifest rejected: {reason}")
    manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
    if not isinstance(manifest, dict):
        raise ValueError(f"manifest is not a JSON object: {manifest_path}")

    # Schema-version negotiation: forward-compat refuses anything
    # newer than we understand (would require migration logic we
    # don't yet have). Older schemas load with `.get(...)` defaults.
    snap_schema = manifest.get("schema_version", 1)
    try:
        snap_schema_int = int(snap_schema)
    except (TypeError, ValueError):
        raise ValueError(
            f"manifest schema_version is not an int: {snap_schema!r}"
        )
    if snap_schema_int > _PRE_UPDATE_SCHEMA_VERSION:
        raise ValueError(
            f"snapshot {snap_path.name} was created by a newer SpliceCraft "
            f"(manifest schema_version={snap_schema_int}, this build supports "
            f"≤{_PRE_UPDATE_SCHEMA_VERSION}). Upgrade SpliceCraft and retry, "
            "or use the matching version to restore."
        )

    # Whitelists: the manifest CANNOT name an attribute or path
    # outside our published user-data set. Tamper-resistance.
    file_attrs = set(_USER_DATA_FILE_ATTRS)
    dir_attrs = set(_USER_DATA_DIR_ATTRS)

    # Pre-restore snapshot — gives the user one click of undo if the
    # restored data turns out to be older than what they had.
    pre_restore = _create_pre_update_snapshot(
        f"{__version__}-pre-restore",
        backup_dir=backup_dir,
    )

    summary: dict = {
        "pre_restore_snapshot": str(pre_restore),
        "restored_files": [],
        "restored_dirs": [],
        "failed": [],
    }

    files_list = manifest.get("files")
    if not isinstance(files_list, list):
        files_list = []
    for entry in files_list:
        if not isinstance(entry, dict):
            continue
        attr = entry.get("attr", "")
        name = entry.get("name", "")
        # Hardening #1: attr must be in the published user-data set.
        if attr not in file_attrs:
            summary["failed"].append(
                (name or "(no name)",
                 f"manifest attr {attr!r} is not a recognised user-data file")
            )
            continue
        # Hardening #2: name must be a safe basename inside snap_path.
        src = _validate_snapshot_member(snap_path, name)
        if src is None or not src.is_file():
            summary["failed"].append(
                (name, "snapshot member name is invalid or src absent")
            )
            continue
        target = globals().get(attr)
        if not isinstance(target, Path):
            # Production code never has this happen (attrs are module
            # constants), but defending anyway: skip the entry rather
            # than write to whatever non-Path object happens to live
            # at that name in globals().
            summary["failed"].append(
                (name, f"runtime attr {attr!r} is not a Path")
            )
            continue
        # Initialised pre-try so the except cleanup can see it even
        # if the OSError fires on mkdir before the staging path is
        # assigned (otherwise pyright flags `tmp` as possibly unbound).
        # The staging name is randomised via `mkstemp` so concurrent
        # restore attempts (UI + agent API in the same process) can't
        # collide on a deterministic `<target>.restoring` path and
        # truncate each other mid-copy.
        tmp: "Path | None" = None
        tmp_fd: "int | None" = None
        try:
            target.parent.mkdir(parents=True, exist_ok=True)
            import tempfile as _tempfile
            tmp_fd, tmp_str = _tempfile.mkstemp(
                prefix=f".{target.name}.", suffix=".restoring",
                dir=str(target.parent),
            )
            os.close(tmp_fd)
            tmp_fd = None
            tmp = Path(tmp_str)
            shutil.copy2(src, tmp)
            _fsync_path(tmp)
            # Hardening #3: verify SHA-256 against the manifest BEFORE
            # the atomic overwrite of the live file. A bit-rotted /
            # tampered snapshot cannot silently corrupt good live data.
            # The sha256 entry is MANDATORY (one of invariant #39's
            # sacred-four checks); pre-0.8.9 silently skipped verify
            # when the field was missing/empty, which a tampered manifest
            # in the user-writable backup dir could exploit. Refuse the
            # restore rather than fall through to a blind rename.
            expected = entry.get("sha256")
            if not isinstance(expected, str) or not expected:
                try:
                    tmp.unlink()
                except OSError:
                    pass
                summary["failed"].append(
                    (name,
                     "manifest entry is missing the mandatory sha256 "
                     "field — refusing restore (snapshot may be tampered "
                     "or written by an unsupported tool)")
                )
                continue
            actual = _sha256_file(tmp)
            if actual != expected:
                # Discard the staged copy and skip the rename. The
                # user's live file remains intact.
                try:
                    tmp.unlink()
                except OSError:
                    pass
                summary["failed"].append(
                    (name,
                     f"sha256 mismatch (snapshot corrupted): "
                     f"expected {expected[:16]}…, got {actual[:16]}…")
                )
                continue
            os.replace(tmp, target)
            _fsync_path(target.parent)
            summary["restored_files"].append(name)
        except (OSError, shutil.Error) as exc:
            # Best-effort: clean up any half-written staging file.
            try:
                if tmp is not None and tmp.exists():
                    tmp.unlink()
            except OSError:
                pass
            summary["failed"].append((name, str(exc)))

    dirs_list = manifest.get("directories")
    if not isinstance(dirs_list, list):
        dirs_list = []
    for entry in dirs_list:
        if not isinstance(entry, dict):
            continue
        attr = entry.get("attr", "")
        name = entry.get("name", "")
        if attr not in dir_attrs:
            summary["failed"].append(
                (name or "(no name)",
                 f"manifest attr {attr!r} is not a recognised user-data dir")
            )
            continue
        src = _validate_snapshot_member(snap_path, name)
        if src is None or not src.is_dir():
            summary["failed"].append(
                (name, "snapshot member name is invalid or src absent")
            )
            continue
        target = globals().get(attr)
        if not isinstance(target, Path):
            summary["failed"].append(
                (name, f"runtime attr {attr!r} is not a Path")
            )
            continue
        stash = target.with_name(target.name + ".restoring-old")
        try:
            target.parent.mkdir(parents=True, exist_ok=True)
            if stash.exists():
                shutil.rmtree(stash, ignore_errors=True)
            if target.exists():
                os.rename(target, stash)
            shutil.copytree(src, target)
            if stash.exists():
                shutil.rmtree(stash, ignore_errors=True)
            summary["restored_dirs"].append(name)
        except (OSError, shutil.Error) as exc:
            # Hardening #4: rollback handles the partial-copytree
            # case. Previous logic only rolled back if `not target.
            # exists()` — but copytree often creates `target` first
            # and then fails partway through, leaving a partial dir.
            # Now: always rmtree the partial target, then move stash
            # back. The `try` around `os.rename(stash, target)` is
            # belt-and-suspenders since the previous `shutil.rmtree`
            # would have raised if it couldn't clean up.
            try:
                if target.exists():
                    shutil.rmtree(target, ignore_errors=True)
                if stash.exists():
                    os.rename(stash, target)
            except OSError:
                pass
            summary["failed"].append((name, str(exc)))

    return summary


