class CustomEnzymeListModal(ModalScreen):
    """Edit the user's custom restriction-enzyme display list (GH #13).

    Single-list MVP: the user types comma- (or newline-) separated
    enzyme names into a text area, optionally toggles "Use this list",
    and clicks Save. The Save handler:

      1. Parses + validates the input against `_NEB_ENZYMES`.
      2. Writes the canonical CSV to `restr_custom_enzymes`.
      3. Writes the toggle to `restr_use_custom_list`.
      4. Re-dispatches the restriction scan so the overlay updates
         immediately.

    Unknown names are dropped silently (not rejected outright) so a
    typo or HF-variant rename doesn't strand the user — the count
    summary shows how many were accepted vs dropped. The full enzyme
    catalog is displayed in a side panel as a discovery aid.

    Dismiss payload:
      ``True``  — saved.
      ``None``  — cancelled (no setting change).
    """

    _blocks_undo: bool = True   # TextArea editing + settings save

    BINDINGS = [
        Binding("escape", "cancel",         "Cancel"),
        Binding("tab",    "app.focus_next", "Next", show=False),
    ]

    def __init__(self) -> None:
        super().__init__()
        self._initial_csv = str(_get_setting("restr_custom_enzymes", "") or "")
        self._initial_active = bool(
            _get_setting("restr_use_custom_list", False)
        )

    def compose(self) -> ComposeResult:
        with Vertical(id="enzlist-box"):
            yield Static(" Custom enzyme list ", id="enzlist-title")
            yield Label(
                "Comma- or newline-separated enzyme names "
                "(EcoRI, BamHI, BsaI, …). Unknown names are dropped.",
            )
            yield TextArea(
                self._initial_csv.replace(",", "\n"),
                id="enzlist-input",
            )
            yield Checkbox(
                "Use this list for the restriction overlay",
                value=self._initial_active,
                id="enzlist-use",
            )
            yield Static("", id="enzlist-status", markup=True)
            with Horizontal(id="enzlist-btns"):
                yield Button("Save", id="btn-enzlist-save",
                              variant="primary")
                yield Button("Cancel", id="btn-enzlist-cancel")

    def on_mount(self) -> None:
        try:
            ta = self.query_one("#enzlist-input", TextArea)
        except NoMatches:
            return
        ta.focus()
        self._refresh_status(ta.text)

    @on(TextArea.Changed, "#enzlist-input")
    def _on_input_changed(self, event: TextArea.Changed) -> None:
        self._refresh_status(event.text_area.text)

    def _refresh_status(self, raw: str) -> None:
        try:
            status = self.query_one("#enzlist-status", Static)
        except NoMatches:
            return
        names = [
            s.strip() for s in raw.replace(";", ",").replace("\n", ",").split(",")
            if s and s.strip()
        ]
        valid = sorted({n for n in names if n in _NEB_ENZYMES})
        dropped = sorted({n for n in names if n not in _NEB_ENZYMES})
        if not names:
            status.update(
                "[dim]Empty list — toggle off and Save to clear, or "
                "add names above.[/dim]"
            )
            return
        parts = [f"[green]{len(valid)} valid[/green]"]
        if dropped:
            from rich.markup import escape as _esc
            preview = ", ".join(_esc(n) for n in dropped[:5])
            more = f" …(+{len(dropped) - 5})" if len(dropped) > 5 else ""
            parts.append(
                f"[yellow]{len(dropped)} unknown[/yellow] ({preview}{more})"
            )
        status.update(" · ".join(parts))

    @on(Button.Pressed, "#btn-enzlist-save")
    def _save(self, _: Button.Pressed) -> None:
        try:
            ta = self.query_one("#enzlist-input", TextArea)
            chk = self.query_one("#enzlist-use", Checkbox)
        except NoMatches:
            self.dismiss(None)
            return
        raw = ta.text or ""
        # Same parse as `_refresh_status` so the saved CSV matches the
        # status-line count exactly.
        names = [
            s.strip() for s in raw.replace(";", ",").replace("\n", ",").split(",")
            if s and s.strip()
        ]
        valid = sorted({n for n in names if n in _NEB_ENZYMES})
        canonical = ",".join(valid)
        active = bool(chk.value) and bool(valid)
        _set_setting("restr_custom_enzymes", canonical)
        _set_setting("restr_use_custom_list", active)
        # Mirror onto the live app instance so the next scan reads the
        # post-save state without a relaunch.
        try:
            app = self.app
            app._restr_custom_enzymes = canonical  # type: ignore[attr-defined]
            app._restr_use_custom_list = active  # type: ignore[attr-defined]
            # Trigger an immediate rescan if a record is loaded. Clear
            # the stale overlay first — mirrors the `_h_replace_sequence`
            # pattern (splicecraft.py:49806-49809). Without this, on a
            # 5 Mb record the user sees old-enzyme-set overlays for the
            # full scan duration after Save.
            cur = getattr(app, "_current_record", None)
            if cur is not None and getattr(cur, "seq", None) is not None:
                app._restr_cache = []  # type: ignore[attr-defined]
                try:
                    pm = app.query_one("#plasmid-map", PlasmidMap)
                    pm._restr_feats = []
                    pm.refresh()
                except NoMatches:
                    pass
                app._dispatch_restr_scan(str(cur.seq))  # type: ignore[attr-defined]
        except (AttributeError, NoMatches):
            pass
        msg = (
            f"Saved {len(valid)} enzyme(s); custom list "
            f"{'ON' if active else 'OFF'}."
        )
        try:
            self.app.notify(msg, severity="information", markup=False)
        except Exception:
            pass
        self.dismiss(True)

    @on(Button.Pressed, "#btn-enzlist-cancel")
    def _cancel_btn(self, _: Button.Pressed) -> None:
        self.dismiss(None)

    def action_cancel(self) -> None:
        self.dismiss(None)


class ORFFinderModal(ModalScreen):
    """Find open reading frames in the loaded record.

    Six-frame scan via `_find_orfs`. Default min length is 30 aa
    (≈ 90 bp); the alt-starts checkbox enables GTG / TTG which is
    relevant for bacterial genomes but rare in plasmid CDSes.
    Selecting a row dismisses with the ORF dict so the caller can
    apply a feature-style highlight (cursor + selection range) in
    the seq panel + map.

    Dismiss payload:
      None        — cancelled / closed
      dict (ORF)  — user picked an ORF to highlight
    """

    BINDINGS = [
        Binding("escape", "cancel",         "Cancel"),
        Binding("tab",    "app.focus_next", "Next",   show=False),
    ]

    def __init__(self, sequence: str, *, circular: bool = True) -> None:
        super().__init__()
        self._seq = sequence
        self._circular = circular
        self._orfs: list[dict] = []

    def compose(self) -> ComposeResult:
        with Vertical(id="orf-box"):
            yield Static(" Find ORFs ", id="orf-title")
            yield Label(f"Sequence: {len(self._seq):,} bp · "
                        f"{'circular' if self._circular else 'linear'}")
            with Horizontal(id="orf-controls"):
                yield Label("Min aa:")
                yield Input(value="30",
                            placeholder="30",
                            id="orf-min-aa", restrict=r"[0-9]*")
                yield Checkbox("GTG / TTG starts",
                               value=False, id="orf-alt-starts")
            with Horizontal(id="orf-btns-top"):
                yield Button("Scan", id="btn-orf-scan", variant="primary")
                yield Button("Close", id="btn-orf-close")
            yield DataTable(id="orf-table", cursor_type="row",
                            zebra_stripes=True)
            yield Static("", id="orf-status", markup=True)

    def on_mount(self) -> None:
        t = self.query_one("#orf-table", DataTable)
        t.add_columns("Start", "End", "Strand", "Length (aa)", "Preview")
        # Initial scan with defaults so the user sees something
        # immediately; rescan via the Scan button after editing controls.
        self._scan()

    def _scan(self) -> None:
        try:
            min_aa = int(
                self.query_one("#orf-min-aa", Input).value or "30"
            )
        except (ValueError, NoMatches):
            min_aa = 30
        try:
            alt = bool(self.query_one("#orf-alt-starts", Checkbox).value)
        except NoMatches:
            alt = False
        self._orfs = _find_orfs(
            self._seq,
            min_aa=max(1, min_aa),
            include_alt_starts=alt,
            circular=self._circular,
        )
        try:
            t = self.query_one("#orf-table", DataTable)
        except NoMatches:
            return
        t.clear()
        for o in self._orfs:
            preview = o["aa_seq"][:24]
            if len(o["aa_seq"]) > 24:
                preview += "…"
            # 1-based bp display matches GenBank coordinates the user
            # reads in features lane / sidebar.
            t.add_row(
                f"{o['start'] + 1:,}",
                f"{o['end']:,}" if o["end"] >= o["start"]
                                else f"{o['end']:,} (wrap)",
                "+" if o["strand"] == 1 else "-",
                str(o["length_aa"]),
                preview,
            )
        try:
            self.query_one("#orf-status", Static).update(
                f"[dim]{len(self._orfs)} ORF(s) ≥ {min_aa} aa[/dim]"
            )
        except NoMatches:
            pass

    @on(Button.Pressed, "#btn-orf-scan")
    def _scan_btn(self, _) -> None:
        self._scan()

    @on(DataTable.RowSelected, "#orf-table")
    def _row_selected(self, event: DataTable.RowSelected) -> None:
        idx = event.cursor_row
        if 0 <= idx < len(self._orfs):
            self.dismiss(self._orfs[idx])

    @on(Button.Pressed, "#btn-orf-close")
    def _close_btn(self, _) -> None:
        self.dismiss(None)

    def action_cancel(self) -> None:
        self.dismiss(None)


# ── Dropdown menu modal ────────────────────────────────────────────────────────

class DropdownScreen(ModalScreen):
    """Lightweight overlay showing a positioned dropdown menu.

    Uses a near-transparent backdrop so the main app stays visible — the
    dropdown looks like a real popup anchored to the menu bar, not a
    separate "screen". Click outside the box dismisses.
    """

    BINDINGS = [Binding("escape", "cancel", "Cancel")]

    DEFAULT_CSS = """
    DropdownScreen {
        background: rgba(0, 0, 0, 0.15);
    }
    """

    def __init__(self, items: list, x: int, y: int) -> None:
        super().__init__()
        self._items = items   # (label, action_str | None)
        self._x = x
        self._y = y
        self._cursor = next(
            (i for i, (_, a) in enumerate(items) if a is not None), 0
        )

    def compose(self) -> ComposeResult:
        yield Static(
            self._build_dropdown_text(),
            id="dropdown-box",
        )

    def on_mount(self) -> None:
        inner_w = max((len(lbl) for lbl, _ in self._items), default=10) + 4
        box_h   = len(self._items) + 2
        box = self.query_one("#dropdown-box", Static)
        box.styles.offset = (self._x, self._y)
        box.styles.width  = inner_w
        box.styles.height = box_h
        box.styles.border = ("solid", "#555555")
        box.styles.background = "#1e1e1e"

    def _build_dropdown_text(self) -> Text:
        inner_w = max((len(lbl) for lbl, _ in self._items), default=10) + 4
        sep_line = "\u2500" * (inner_w - 2)
        result = Text()
        for i, (label, action) in enumerate(self._items):
            is_sep      = (label == "---")
            is_selected = (i == self._cursor and not is_sep and action is not None)
            is_disabled = (action is None and not is_sep)

            if is_sep:
                line = Text(sep_line + "\n", style="white")
            else:
                padded = f" {label:<{inner_w - 3}}"
                if is_selected:
                    line = Text(padded + "\n", style="reverse white")
                elif is_disabled:
                    line = Text(padded + "\n", style="dim white")
                else:
                    line = Text(padded + "\n", style="white")
            result.append_text(line)
        return result

    def _refresh_box(self) -> None:
        box = self.query_one("#dropdown-box", Static)
        box.update(self._build_dropdown_text())

    def on_key(self, event) -> None:
        items = self._items
        if event.key == "up":
            pos = self._cursor - 1
            while pos >= 0 and (items[pos][0] == "---" or items[pos][1] is None):
                pos -= 1
            if pos >= 0:
                self._cursor = pos
                self._refresh_box()
            event.stop()
        elif event.key == "down":
            pos = self._cursor + 1
            while pos < len(items) and (items[pos][0] == "---" or items[pos][1] is None):
                pos += 1
            if pos < len(items):
                self._cursor = pos
                self._refresh_box()
            event.stop()
        elif event.key == "enter":
            label, action = items[self._cursor]
            if action is not None:
                self.dismiss(action)
            event.stop()

    def on_click(self, event: Click) -> None:
        bx = self._x
        by = self._y
        inner_w = max((len(lbl) for lbl, _ in self._items), default=10) + 4
        bh = len(self._items) + 2
        cx, cy = event.screen_x, event.screen_y
        if bx <= cx < bx + inner_w and by <= cy < by + bh:
            row_in_box = cy - by - 1  # -1 for top border
            if 0 <= row_in_box < len(self._items):
                label, action = self._items[row_in_box]
                if label == "---" or action is None:
                    event.stop()
                    return
                self.dismiss(action)
        else:
            self.dismiss(None)
        event.stop()

    def action_cancel(self) -> None:
        self.dismiss(None)


# ── Menu bar widget ────────────────────────────────────────────────────────────

class MenuBar(Widget):
    DEFAULT_CSS = """
    MenuBar {
        height: 1;
        background: $primary-darken-3;
        layout: horizontal;
    }
    MenuBar Static {
        width: auto;
        padding: 0 2;
        color: $text;
    }
    MenuBar Static:hover {
        background: $primary;
    }
    """

    MENUS = ["File", "Settings", "Edit", "Enzymes", "Features", "Primers",
             "Mutagenize", "Synthesis", "Parts", "Constructor", "Simulator",
             "Sequencing", "Experiments", "History"]

    def compose(self) -> ComposeResult:
        for name in self.MENUS:
            yield Static(name, classes="menu-item", id=f"menu-{name.lower()}")

    def on_click(self, event: Click) -> None:
        for name in self.MENUS:
            widget_id = f"menu-{name.lower()}"
            try:
                item = self.query_one(f"#{widget_id}", Static)
            except NoMatches:
                continue
            region = item.region
            if (region.x <= event.screen_x < region.x + region.width and
                    region.y <= event.screen_y < region.y + region.height):
                # "Features", "Experiments", and "History" are direct-
                # open screens (no dropdown). Every other menu surfaces
                # items via DropdownScreen.
                if name == "Features":
                    self.app.push_screen(FeatureLibraryScreen())
                    break
                if name == "Experiments":
                    self.app.action_open_experiments()  # type: ignore[attr-defined]
                    break
                if name == "History":
                    self.app.action_show_history()  # type: ignore[attr-defined]
                    break
                x = region.x
                y = region.y + 1
                self.app.open_menu(name, x, y)  # type: ignore[attr-defined]
                break


