# Golden Braid L0 part positions — full GB 2.0 grammar.
# Each entry maps a part-type name → (position label, 5' overhang,
# 3' overhang).
#
# The full GB 2.0 fusion-site chain (Sarrion-Perdigones et al., 2013):
#
#   GGAG  TGAC  TCCC  TACT  CCAT  AATG  AGCC  TTCG  GCAG  GCTT  GGTA  CGCT
#   ┊──01──┊──02──┊──03──┊──11──┊──12──┊──13──┊──14──┊──15──┊──16──┊──17──┊──21──┊
#   ┊  5' Non-Transcribed   ┊   5'UTR  ┊LINK ┊   Translated CDS    ┊  3' UTR / TER
#
# Common workflow shapes (combined slots; spans multiple positions):
#   * `Promoter` (Pos 01-12)       — PromUTR+ATG; the default BASIC shape
#   * `Promoter-only` (Pos 01-11)  — PromUTR without LINK/+ATG
#   * `5' UTR` (Pos 12)            — LINK / +ATG context (historical name;
#                                     technically the LINK position, not
#                                     the canonical 5'UTR which is Pos
#                                     03-11. Kept under this name for
#                                     backward compat — existing user
#                                     parts classified under "5' UTR"
#                                     keep working.)
#   * `CDS` (Pos 13-16)            — full CDS with stop codon
#   * `CDS-NS` (Pos 13-14)         — legacy 2-part split (non-canonical;
#                                     splits CDS in half at TL2/TL3
#                                     boundary). The canonical no-stop
#                                     CDS is `CDS-NS (CT)` below.
#   * `C-tag` (Pos 15-16)          — legacy 2-part C-tag partner to CDS-NS
#   * `Terminator` (Pos 17-21)     — combined 3'UTR+TER
#
# Canonical GB 2.0 atomic parts (added 2026-05-10 to match the figure's
# row-B variants — SECRETED, CT-FUSION, NT-FUSION, OP-PROM-A/B):
#   * `Operator-A` (Pos 01-02)     — OP-PROM-A operator slot
#   * `Operator-B` (Pos 02)        — OP-PROM-B operator slot
#   * `Min Promoter` (Pos 03-12)   — minimal promoter, pairs with either
#                                     Operator-A or Operator-B
#   * `Distal 5' UTR` (Pos 03-11)  — canonical 5'UTR (the actual one,
#                                     before LINK)
#   * `Signal peptide` (Pos 13)    — SECRETED workflow N-terminal SP
#   * `CDS-NS (CT)` (Pos 13-15)    — CDS no-stop for CT-FUSION; canonical
#                                     no-stop ending boundary (vs legacy)
#   * `CT-tag` (Pos 16)            — canonical C-terminal tag for CT-FUSION
#   * `CDS-after-SP` (Pos 14-16)   — SECRETED workflow CDS body (after SP)
#   * `3' UTR` (Pos 17)            — 3'UTR alone (split from Terminator)
#   * `Terminator-only` (Pos 21)   — TER alone (split from Terminator)
#
# TU boundary unchanged: positions[0].oh5 = GGAG; outermost 3' OH = CGCT
# (still matches `Promoter` and `Terminator` so `_grammar_tu_overhangs`
# keeps working without a code edit).
#
# History note: pre-2026-05-10 the Promoter slot was (GGAG, TGAC) with
# `TGAC` as the Promoter→5'UTR connector — that doesn't match any
# documented GB 2.0 variant or the typical post-cloning J23100/J23114
# cassette and was replaced when the user reported MoClo mis-classification.
# The 2026-05-10 expansion adds the granular positions without removing
# the legacy combined slots so existing user parts keep classifying.
_GB_POSITIONS: dict[str, tuple[str, str, str]] = {
    # ── 5' Non-Transcribed (combined Promoter + 5'UTR + Link) ─────────
    # Combined Promoter+5'UTR+ATG (GB 2.0 PromUTR; the common BASIC form).
    # Legacy position label "Pos 1" preserved for back-compat with
    # existing user parts in `parts_bin.json` that were stored under
    # this label string.
    "Promoter":         ("Pos 1",     "GGAG", "AATG"),
    # Separate Promoter (no LINK/+ATG) — pairs with a `5' UTR` part.
    "Promoter-only":    ("Pos 1a",    "GGAG", "CCAT"),
    # ── Operator/Promoter variants (OP-PROM-A/B workflow) ─────────────
    "Operator-A":       ("Pos 01-02", "GGAG", "TCCC"),  # OP-PROM-A operator
    "Operator-B":       ("Pos 02",    "TGAC", "TCCC"),  # OP-PROM-B operator
    "Min Promoter":     ("Pos 03-12", "TCCC", "AATG"),  # pairs with either Operator
    # ── 5' UTR ────────────────────────────────────────────────────────
    # Historical "5' UTR" slot — technically the LINK position (Pos 12)
    # in canonical GB 2.0. Kept under this name for backward compat.
    "5' UTR":           ("Pos 1b",    "CCAT", "AATG"),
    # Canonical GB 2.0 5'UTR (Pos 03-11), distinct from the LINK above.
    "Distal 5' UTR":    ("Pos 03-11", "TCCC", "CCAT"),
    # ── Translated region ─────────────────────────────────────────────
    # Signal peptide (SECRETED workflow N-terminal extension; coding).
    "Signal peptide":   ("Pos 13",    "AATG", "AGCC"),
    # Full CDS with stop codon (BASIC workflow).
    "CDS":              ("Pos 3-4",   "AATG", "GCTT"),
    # Legacy 2-part CDS split (splits at TL2/TL3 boundary, non-canonical
    # but kept for backward compat with existing user parts).
    "CDS-NS":           ("Pos 3",     "AATG", "TTCG"),
    "C-tag":            ("Pos 4",     "TTCG", "GCTT"),
    # Canonical GB 2.0 CDS variants (added 2026-05-10):
    # CDS-no-stop for CT-FUSION (positions 13-15; pairs with `CT-tag`).
    "CDS-NS (CT)":      ("Pos 13-15", "AATG", "GCAG"),
    "CT-tag":           ("Pos 16",    "GCAG", "GCTT"),  # canonical C-term tag
    # CDS body for SECRETED workflow (after Signal peptide, full to stop).
    "CDS-after-SP":     ("Pos 14-16", "AGCC", "GCTT"),
    # ── 3' Non-Translated ─────────────────────────────────────────────
    # Combined 3'UTR+Terminator (BASIC workflow).
    "Terminator":       ("Pos 5",     "GCTT", "CGCT"),
    # Canonical split variants (added 2026-05-10):
    "3' UTR":           ("Pos 17",    "GCTT", "GGTA"),
    "Terminator-only":  ("Pos 21",    "GGTA", "CGCT"),
}

# Coding-DNA part types: these are the only types where silent (synonymous)
# codon substitution can be used to remove an internal Type IIS site during
# domestication. Non-coding parts (promoters, UTRs, terminators) have no
# reading frame, so internal sites must be fixed manually or by picking a
# different template region.
_GB_CODING_PART_TYPES: frozenset[str] = frozenset({
    # Legacy splits:
    "CDS", "CDS-NS", "C-tag",
    # GB 2.0 canonical translational parts (added 2026-05-10):
    "Signal peptide", "CDS-NS (CT)", "CT-tag", "CDS-after-SP",
})


def _atg_offset_for_part(part_oh5: str, part_type: str) -> int:
    """Return the number of bases the 5' boundary of a coding-part
    feature should extend upstream to include its embedded start codon.

    GB 2.0 puts the ATG start codon inside the AATG fusion overhang
    (Pos 12→13 boundary): AATG = A + ATG, where the A is the spacer
    base and ATG is the start codon. The domesticator's forward primer
    encodes AATG as the part's 5' fusion overhang and PCR-binds at
    codon 2 of the source CDS — so the L0 part's body sequence
    (`part["sequence"]`) starts at codon 2, NOT at the ATG.

    When the part is assembled into an L1 plasmid the upstream LINK
    contributes its AATG (Pos 12 oh3) which fuses with the part's
    AATG oh5; the resulting cloned sequence reads
    ``...LINK-body...A + ATG + [codon2]...`` and the ATG sits in the
    last 3 nt of the fusion overhang. A feature annotation that only
    spans [body-start, body-end) would therefore drop the user's
    start codon — visibly broken in the L1 plasmid map.

    This helper returns ``3`` when the part needs the upstream
    extension (any coding part type with ``oh5 == AATG``: Signal
    peptide, CDS, CDS-NS, CDS-NS (CT)), and ``0`` otherwise. Returning
    a numeric offset rather than a bool lets callers do
    ``feature_start -= _atg_offset_for_part(oh5, ptype)`` without
    branching on every feature loop iteration.

    Regression guard for 2026-05-10: user reported "CDS's cloned seem
    to lose the annotation of their ATG because it also occupies the
    AATG overhang."
    """
    if not isinstance(part_oh5, str) or not isinstance(part_type, str):
        return 0
    if part_oh5.upper() == "AATG" and part_type in _GB_CODING_PART_TYPES:
        return 3
    return 0

# Parts-bin TitleCase type → INSDC feature_type. Used by
# `PartsBinModal._save_as_feature` to round-trip a Golden Braid part into
# the feature library, where types follow the INSDC vocabulary.
# GB-specific shapes that don't have a 1:1 INSDC equivalent collapse to
# the closest standard type — the GB position survives in the feature's
# description string instead. Signal peptide → `sig_peptide` (a valid
# INSDC feature type for the N-terminal cleavage signal); C-tag /
# CT-tag / CDS-NS variants → CDS.
_GB_PART_TYPE_TO_INSDC: dict[str, str] = {
    # Legacy slots:
    "Promoter":         "promoter",
    "Promoter-only":    "promoter",
    "5' UTR":           "5'UTR",
    "CDS":              "CDS",
    "CDS-NS":           "CDS",
    "C-tag":            "CDS",
    "Terminator":       "terminator",
    # GB 2.0 canonical additions (2026-05-10):
    "Operator-A":       "promoter",   # operator+promoter assembled together
    "Operator-B":       "promoter",
    "Min Promoter":     "promoter",
    "Distal 5' UTR":    "5'UTR",
    "Signal peptide":   "sig_peptide",
    "CDS-NS (CT)":      "CDS",
    "CT-tag":           "CDS",
    "CDS-after-SP":     "CDS",
    "3' UTR":           "3'UTR",
    "Terminator-only":  "terminator",
}

# Type IIS recognition + tail used for all Golden Braid L0 domestication
# primers. Golden Braid splits assembly across two enzymes: **L0 parts use
# Esp3I / BsmBI (CGTCTC(1/5))**, while downstream L1+ transcriptional units
# use BsaI (GGTCTC(1/5)). The two have identical N(1)/N(5) geometry (→ 4-nt
# 5' overhangs) but different recognition sequences, so a domesticated L0
# part survives a second round of Golden Gate in L1 without re-cutting.
# Padding bases improve Type IIS digestion efficiency near DNA ends.
_GB_L0_ENZYME_NAME = "Esp3I"       # Esp3I is the isoschizomer of BsmBI
_GB_L0_ENZYME_SITE = "CGTCTC"      # recognition; rc = "GAGACG"
_GB_SPACER         = "A"           # 1 nt between recognition and the overhang
_GB_PAD            = "GCGC"        # 4 nt of extra bases for efficient end-cutting


# ── Cloning simulation (Parts Bin preview) ─────────────────────────────────────
#
# The three "Copy …" buttons in the Parts Bin let the user grab the insert,
# the full PCR amplicon (insert + primer tails), or the simulated cloned
# plasmid (insert slotted into a pUPD2-shaped backbone) as plain text.
#
# The backbone here is a **placeholder** — not a real pUPD2 sequence. It is
# a deterministic pseudo-random ACGT string, scrubbed of every Type IIS site
# SpliceCraft touches (BsaI GGTCTC/GAGACC, Esp3I/BsmBI CGTCTC/GAGACG) so the
# simulated plasmid never contains a stray recognition site that would
# re-cut during a real assembly. Once we gain a licensed / verified pUPD2
# sequence we can drop it in here without changing any callers.

def _build_pupd2_backbone_stub(seed: int = 0xBACDBAC0, length: int = 420) -> str:
    """Return a deterministic ACGT string, free of BsaI/Esp3I/BsmBI sites on
    both strands, for use as a pUPD2-shaped placeholder backbone.

    Deterministic because the same insert must produce the same cloned
    sequence across sessions (otherwise the "Copy Cloned Sequence" output
    would silently drift). Seeded with a fixed constant.
    """
    import random as _random_mod
    rng = _random_mod.Random(seed)
    bases = [rng.choice("ACGT") for _ in range(length)]
    # Scrub both strands — the linear backbone becomes part of a circular
    # product, so a top-strand CGTCTC (Esp3I/BsmBI) and a bottom-strand
    # GAGACG are biologically equivalent and both must be absent.
    forbidden = ("GGTCTC", "GAGACC", "CGTCTC", "GAGACG")
    i = 0
    while i <= length - 6:
        window = "".join(bases[i:i + 6])
        if window in forbidden:
            # Flip the middle base to something that can't re-hit any
            # forbidden site; ACGT minus the current base leaves 3 choices.
            middle = i + 3
            current = bases[middle]
            for replacement in "ACGT":
                if replacement != current:
                    bases[middle] = replacement
                    break
            # Rewind a bit to catch any new site created at the boundary.
            i = max(0, i - 5)
            continue
        i += 1
    return "".join(bases)


_PUPD2_BACKBONE_STUB: str = _build_pupd2_backbone_stub()


def _simulate_primed_amplicon(
    insert: str, oh5: str, oh3: str,
    grammar: "dict | None" = None,
) -> str:
    """PCR amplicon top strand (5'→3'), as it would run on a pre-digest gel.

    Structure:  [pad] [enzyme site] [spacer] [oh5] [insert] [oh3]
                [rc(spacer)] [rc(enzyme site)] [rc(pad)]

    Matches the primer geometry in :func:`_design_gb_primers`. Defaults to
    Golden Braid L0 (Esp3I); pass ``grammar`` to use a different cloning
    grammar's enzyme/pad/spacer (e.g., MoClo Plant uses BsaI). Used by
    both DomesticatorModal (active grammar at design time) and
    PartsBinModal "Copy Primed Sequence" (the part's stored grammar).
    """
    g = grammar if isinstance(grammar, dict) else _BUILTIN_GRAMMARS["gb_l0"]
    pad    = g.get("pad",    _GB_PAD)
    site   = g.get("site",   _GB_L0_ENZYME_SITE)
    spacer = g.get("spacer", _GB_SPACER)
    left_tail  = pad + site + spacer
    right_tail = _rc(spacer) + _rc(site) + _rc(pad)
    return left_tail + oh5 + insert + oh3 + right_tail


def _simulate_cloned_plasmid(insert: str, oh5: str, oh3: str) -> str:
    """Simulated cloned circular plasmid, linearised at the 5' overhang.

    After the cloning grammar's enzyme cuts both the amplicon and the
    backbone, the insert fragment carries `oh5…oh3` on its 4-nt sticky
    ends and ligates into the backbone in a single orientation. The
    circular product, read starting at `oh5`, is:

        [oh5] [insert] [oh3] [backbone_body]

    The backbone here is `_PUPD2_BACKBONE_STUB` — a scrubbed placeholder
    that contains no BsaI/Esp3I sites on either strand, so the simulated
    plasmid is guaranteed not to re-cut in either L0 or L1 assembly.
    """
    return oh5 + insert + oh3 + _PUPD2_BACKBONE_STUB


# ── _clone_part_into_entry_vector helpers ─────────────────────────────────


def _clone_part_bail(part: dict, reason: str):
    """Shared failure-path helper: log a structured reason at info
    level and return None. Callers fall back to the stub backbone form
    when this returns None; a `clone_sim:` log line is the breadcrumb
    that points the user at the failure cause."""
    _log.info("clone_sim: skipping real-cloning for part %r — %s",
               part.get("name"), reason)
    return None


def _clone_part_marshal_vec_features(vec_rec) -> list[dict]:
    """Marshal entry-vector SeqRecord features into the dict shape that
    `_fragments_from_cuts` expects. Wrap-aware via `_feat_bounds`
    (pre-fix `int(loc.start)` flattened wrap features to outer bounds
    and the carry-over logic dropped them as "fully inside the
    dropout"). Skips `source` rows (whole-record metadata).

    Carries ApEinfo colour qualifiers across to the fragment dict so
    backbone features (Ori / AmpR / etc.) keep their colours after
    ligation into the cloned product. Pre-2026-05-19 every vector
    feature came through as ``color: "white"`` and the cloned plasmid
    lost the visual provenance of the entry-vector's annotation."""
    vec_features: list[dict] = []
    total_vec = _seq_len(vec_rec)
    for f in (vec_rec.features or []):
        if f.type == "source":
            continue
        bounds = _feat_bounds(f, total_vec)
        if bounds is None:
            continue
        fs, fe, _fs_strand = bounds
        label = ""
        for k in ("label", "gene", "product", "note"):
            vals = f.qualifiers.get(k, [])
            if vals:
                label = str(vals[0])
                break
        color = ""
        for k in ("ApEinfo_fwdcolor", "ApEinfo_revcolor", "color"):
            vals = f.qualifiers.get(k, [])
            if vals:
                color = str(vals[0])
                break
        vec_features.append({
            "start":  fs, "end":   fe,
            "strand": f.location.strand or 1,
            "type":   f.type,
            "label":  label or f.type,
            "color":  color or "white",
        })
    return vec_features


def _clone_part_build_part_feature(
    part: dict, raw_name: str, oh5: str, oh3: str,
) -> dict:
    """Build the part_feature template that annotates the inserted
    region in the cloned plasmid. The `end` field is left at 0 because
    the caller fills it in once the synthesised top_seq length is
    known.

    Colour is sourced from the grammar's per-type palette
    (`_GB_TYPE_COLORS`) so Domesticator-saved library entries are
    visually typed (Promoter=green, CDS=yellow, Terminator=blue, etc.)
    matching what `_clone_assembly_into_entry_vector` already paints
    on TU/MOD assemblies. Falls back to white for unrecognised types
    (custom grammars without a colour table)."""
    part_type = str(part.get("type") or "")
    ftype = _GB_PART_TYPE_TO_INSDC.get(part_type, "misc_feature")
    note_bits = [f"GB part type: {part_type or '?'}"]
    if part.get("position"):
        note_bits.append(f"position {part['position']}")
    if oh5 or oh3:
        note_bits.append(f"5'OH {oh5} / 3'OH {oh3}")
    if part.get("marker"):
        note_bits.append(f"selection {part['marker']}")
    return {
        "start":  0,
        "end":    0,
        "strand": 1,
        "type":   ftype,
        "label":  raw_name,
        "note":   "; ".join(note_bits),
        "color":  _GB_TYPE_COLORS.get(part_type, "white"),
    }


def _clone_part_try_primer_path(
    part: dict, insert: str, oh5: str, oh3: str,
    enzyme: str, grammar: dict,
    all_frags: list[dict], part_feature: dict,
) -> "tuple[dict | None, int]":
    """First-try: digest the part's primed amplicon and find a vector
    fragment whose overhangs exactly match the released insert (with
    RC fallback). If both fwd + RC fail, return `(None, -1)` so the
    caller falls through to the synthetic-insert path.

    Returns `(insert_frag, dropout_idx)` on success. `insert_frag`
    carries any pre-built per-source features (multi-source assembly)
    shifted to candidate coordinates."""
    primed = part.get("primed_seq") or _simulate_primed_amplicon(
        insert, oh5, oh3, grammar=grammar,
    )
    insert_frags = _digest_with_enzymes(
        primed, [enzyme], circular=False,
        source_label=part.get("name") or "insert",
    )
    if len(insert_frags) < 3:
        return None, -1
    candidate = max(insert_frags[1:-1], key=lambda f: len(f["top_seq"]))

    def _find_dropout(insert_to_match):
        for i, f in enumerate(all_frags):
            if (_ends_compatible(f["left"],  insert_to_match["left"])
                    and _ends_compatible(f["right"], insert_to_match["right"])):
                return i
        return -1

    dropout_idx = _find_dropout(candidate)
    if dropout_idx < 0:
        rc_candidate = _rc_fragment(candidate)
        dropout_idx = _find_dropout(rc_candidate)
        if dropout_idx >= 0:
            candidate = rc_candidate
    if dropout_idx < 0:
        return None, -1
    insert_frag = dict(candidate)
    insert_frag["features"] = list(insert_frag.get("features", []))
    prebuilt = part.get("features")
    if isinstance(prebuilt, list) and prebuilt:
        # Multi-source assembly: caller chained per-source features
        # with coords relative to the body insert. Candidate top_seq
        # is roughly `oh5 + insert + oh3`, so shift each feature by
        # `len(oh5)` into candidate coords. Skip the whole-insert
        # part_feature so the MOD shows individual TU annotations
        # (Promoter / CDS / Terminator …) instead of one collapsed
        # block.
        shift = len(oh5)
        top_len = len(insert_frag["top_seq"])
        for fr in prebuilt:
            try:
                fs = int(fr.get("start", 0))
                fe = int(fr.get("end", 0))
            except (TypeError, ValueError):
                continue
            new_s = max(0, min(top_len, fs + shift))
            new_e = max(0, min(top_len, fe + shift))
            if new_e <= new_s:
                continue
            insert_frag["features"].append({
                **fr,
                "start": new_s,
                "end":   new_e,
            })
    else:
        f = dict(part_feature)
        f["end"] = len(insert_frag["top_seq"])
        insert_frag["features"].append(f)
    return insert_frag, dropout_idx


def _clone_part_synthesise_insert(
    part: dict, insert: str, oh5: str, oh3: str,
    raw_name: str, all_frags: list[dict], part_feature: dict,
) -> "tuple[dict, int]":
    """Fallback path: pick the dropout fragment via feature-aware
    selection (rep_origin / antibiotic-resistance absent → falls back
    to smallest), then synthesise the insert fragment directly. Sticky
    ends are stamped from the dropout's edges so ligation is always
    compatible.

    By the fragment-edge convention (see `_fragments_from_cuts`): the
    left overhang region's bases are the FIRST 4 nt of top_seq; the
    right overhang region lives at the START of the next fragment's
    top_seq, not at the end of this one. So the synthesised top_seq
    starts with `left_oh` and ends with the part's 3' overhang."""
    dropout = _pick_insert_fragment(all_frags) or all_frags[0]
    dropout_idx = all_frags.index(dropout)
    left_end  = dict(dropout["left"])
    right_end = dict(dropout["right"])
    left_oh   = left_end.get("overhang_seq", "")
    synth_top = left_oh + oh5 + insert + oh3
    prebuilt = part.get("features")
    if isinstance(prebuilt, list) and prebuilt:
        shift = len(left_oh) + len(oh5)
        top_len = len(synth_top)
        built_features: list[dict] = []
        for fr in prebuilt:
            try:
                fs = int(fr.get("start", 0))
                fe = int(fr.get("end", 0))
            except (TypeError, ValueError):
                continue
            new_s = max(0, min(top_len, fs + shift))
            new_e = max(0, min(top_len, fe + shift))
            if new_e <= new_s:
                continue
            built_features.append({
                **fr,
                "start": new_s,
                "end":   new_e,
            })
    else:
        f = dict(part_feature)
        # Place the part feature so that the BsaI overhangs flank it:
        # the insert annotation covers exactly the user's designed
        # sequence (between oh5 and oh3). The L1-junction overhangs
        # themselves stay untagged.
        f["start"] = len(left_oh) + len(oh5)
        f["end"]   = f["start"] + len(insert)
        built_features = [f]
    insert_frag = {
        "top_seq":      synth_top,
        "left":         left_end,
        "right":        right_end,
        "features":     built_features,
        "source_label": str(raw_name),
    }
    _log.info(
        "clone_sim: synthesised insert fragment for %r — "
        "dropout idx %d (%d bp), overhangs %s/%s",
        raw_name, dropout_idx, len(dropout["top_seq"]),
        left_oh, right_end.get("overhang_seq", ""),
    )
    return insert_frag, dropout_idx


def _clone_part_build_backbone_chain(
    all_frags: list[dict], dropout_idx: int, enzyme: str,
) -> "dict | str":
    """Ligate the surviving (non-dropout) fragments end-to-end in
    circular order, starting after the dropout. Returns the
    accumulated chain dict on success, or a human-readable error
    string on relegation failure (the caller routes this through
    `_clone_part_bail`)."""
    n = len(all_frags)
    chain_idxs = [(dropout_idx + 1 + i) % n for i in range(n - 1)]
    backbone_chain = all_frags[chain_idxs[0]]
    for ci in chain_idxs[1:]:
        backbone_chain = _ligate_fragments(backbone_chain, all_frags[ci])
        if backbone_chain is None:
            return (
                f"vector backbone fragments can't relegate after "
                f"removing dropout — extra {enzyme} sites produce "
                f"incompatible overhangs"
            )
    return backbone_chain


def _clone_part_build_seqrecord(
    closed: dict, vec_rec, raw_name: str,
):
    """Turn the closed circular `top_seq` + features dict into a
    real SeqRecord with `molecule_type=DNA` + `topology=circular`.
    Features with non-int / negative / out-of-range coords are
    dropped with a warning log (pre-fix this swallowed every
    exception including programmer bugs).

    Wrap-aware: a feature whose ``end < start`` is rendered as a
    `CompoundLocation` per the GenBank convention (head + tail).
    Pre-2026-05-19 the `if e <= s` guard silently dropped these,
    losing origin-spanning backbone features (an AmpR that straddles
    the relegated join, an Ori split across the cut point, etc.)."""
    from Bio.Seq import Seq
    from Bio.SeqRecord import SeqRecord
    from Bio.SeqFeature import (
        SeqFeature, FeatureLocation, CompoundLocation,
    )
    safe_id = re.sub(r"[^A-Za-z0-9_]", "_", str(raw_name)) or "part"
    new_seq = closed["top_seq"]
    n_seq = len(new_seq)
    desc_vec = vec_rec.name or vec_rec.id or "vector"
    new_rec = SeqRecord(
        Seq(new_seq), id=safe_id, name=safe_id,
        description=f"Cloned part: {raw_name} in {desc_vec}",
    )
    new_rec.annotations["molecule_type"] = "DNA"
    new_rec.annotations["topology"]      = "circular"
    for f in closed.get("features", []):
        try:
            s = int(f.get("start", 0))
            e = int(f.get("end",   0))
        except (TypeError, ValueError):
            continue
        if s < 0 or s >= n_seq or e < 0 or e > n_seq:
            continue
        if s == e:
            continue  # zero-length features have no biology
        strand = int(f.get("strand", 1) or 1)
        if e > s:
            loc: "FeatureLocation | CompoundLocation" = FeatureLocation(
                s, e, strand=strand,
            )
        else:
            # Wrap feature: (s, n_seq) + (0, e). Both halves carry the
            # same strand. CompoundLocation refuses empty parts, so
            # the s == n_seq / e == 0 edge cases are pre-filtered by
            # the bounds checks above.
            loc = CompoundLocation([
                FeatureLocation(s, n_seq, strand=strand),
                FeatureLocation(0, e,    strand=strand),
            ])
        quals: dict = {
            "label": [f.get("label") or f.get("type") or "feature"],
        }
        if f.get("note"):
            quals["note"] = [str(f["note"])]
        # Carry ApEinfo colours through so chained MOD / TU features
        # keep the colour the user (or the grammar's per-type palette)
        # assigned. Without this, every cloned feature renders as the
        # default white block and the visual provenance of an L0 →
        # TU → MOD chain is lost.
        color = f.get("color")
        if color and str(color).lower() != "white":
            color_str = str(color)
            quals.setdefault("ApEinfo_fwdcolor", [color_str])
            quals.setdefault("ApEinfo_revcolor", [color_str])
        try:
            new_rec.features.append(SeqFeature(
                loc,
                type=str(f.get("type", "misc_feature")),
                qualifiers=quals,
            ))
        except (TypeError, ValueError) as exc:
            _log.warning(
                "clone_sim: dropped feature %r (coords %d..%d): %s",
                f.get("label") or f.get("type"), s, e, exc,
            )
            continue
    return new_rec


def _clone_part_into_entry_vector(
    part: dict, entry_vector: dict, grammar: dict,
):
    """Simulate the actual cloning event: digest the entry vector +
    the part's primed amplicon with the grammar's Type IIS enzyme,
    ligate the insert fragment into the vector backbone, return a
    circular `SeqRecord` of the cloned plasmid.

    Mirrors what happens in real-life Golden Braid / MoClo cloning:
      1. The entry vector carries a dropout cassette flanked by two
         enzyme sites (Esp3I for L0, BsaI for L1, etc.).
      2. Cutting the vector excises the dropout and exposes
         compatible 4-nt overhangs.
      3. Cutting the part's PCR amplicon releases the insert with
         the matching overhangs (designed by the Domesticator).
      4. Ligation closes the circle: backbone + insert.

    Handles vectors with **more than 2 enzyme sites** (the common
    real-world case: a pUPD2 derivative that picked up an extra
    Esp3I site somewhere in the backbone). The helper finds ANY
    fragment whose overhangs match the part's, treats it as the
    dropout, and ligates the surviving fragments end-to-end as the
    backbone chain — same model as a real one-pot reaction with
    multiple cuts.

    Logs the specific reason on each failure path via `_log.info`
    so a user wondering "why is my part still using the pUPD2 stub"
    can grep `splicecraft.log` for `clone_sim`. Returns ``None`` on
    failure; callers fall back to the stub backbone form.

    Pre-refactor this was a 355-line monolith; per-stage logic now
    lives in `_clone_part_*` helpers. Behaviour is bit-identical;
    tested by tests/test_traditional_cloning.py + the Constructor
    integration tests in tests/test_smoke.py.
    """
    enzyme = grammar.get("enzyme") if isinstance(grammar, dict) else None
    if not isinstance(enzyme, str) or enzyme not in _NEB_ENZYMES:
        return _clone_part_bail(
            part, f"grammar enzyme {enzyme!r} not in NEB catalog"
        )
    gb_text = (entry_vector.get("gb_text") or "").strip() \
        if isinstance(entry_vector, dict) else ""
    if not gb_text:
        return _clone_part_bail(part, "entry vector has no gb_text")
    insert = (part.get("sequence") or "").upper()
    if not insert:
        return _clone_part_bail(part, "part has no sequence")
    oh5 = (part.get("oh5") or "").upper()
    oh3 = (part.get("oh3") or "").upper()

    # ── Parse the entry vector ──────────────────────────────────
    try:
        vec_rec = _gb_text_to_record(gb_text)
    except Exception as exc:
        return _clone_part_bail(
            part, f"entry-vector gb_text parse failed: {exc}"
        )
    vec_seq = str(vec_rec.seq).upper()
    if not vec_seq:
        return _clone_part_bail(part, "entry vector has empty sequence")
    vec_topology = (vec_rec.annotations.get("topology", "") or "").lower()
    vec_circular = vec_topology != "linear"
    vec_features = _clone_part_marshal_vec_features(vec_rec)

    # ── Cut the entry vector at every enzyme site ───────────────
    # `_excise_fragment_pair` insists on exactly 2 cuts; real
    # plasmids often have 3+ Esp3I sites (one extra in the backbone
    # is enough). We use the lower-level `_enzyme_cuts` +
    # `_fragments_from_cuts` so a multi-cut vector can still
    # simulate — identify the dropout fragment, ligate the rest
    # as the backbone chain.
    cuts = _enzyme_cuts(vec_seq, [enzyme], circular=vec_circular)
    if len(cuts) < 2:
        return _clone_part_bail(
            part,
            f"entry vector has {len(cuts)} {enzyme} cut(s); need ≥2 "
            f"for the IIS-cloning simulation. Configure a vector "
            f"with the dropout cassette intact."
        )
    all_frags = _fragments_from_cuts(
        vec_seq, cuts, circular=vec_circular,
        features=vec_features,
        source_label=vec_rec.name or "vector",
    )
    if not all_frags:
        return _clone_part_bail(part, "vector digest produced no fragments")

    raw_name = part.get("name") or "part"
    part_feature = _clone_part_build_part_feature(part, raw_name, oh5, oh3)

    # First try: primer-flanked overhangs that match a vector fragment
    # exactly. This is the historical well-designed-primer path —
    # honours primer-encoded silent mutations + respects deliberate
    # overhang choices.
    insert_frag, dropout_idx = _clone_part_try_primer_path(
        part, insert, oh5, oh3, enzyme, grammar, all_frags, part_feature,
    )

    # Second try (fallback): synthesise the insert fragment directly.
    # Feature-aware dropout selection protects against the "stacked-
    # TU MOD where insert > backbone" case that would have made
    # min-size pick the backbone instead of the dropout cassette.
    if insert_frag is None:
        insert_frag, dropout_idx = _clone_part_synthesise_insert(
            part, insert, oh5, oh3, raw_name, all_frags, part_feature,
        )

    # ── Build the backbone chain: surviving fragments end-to-end ──
    backbone_chain = _clone_part_build_backbone_chain(
        all_frags, dropout_idx, enzyme,
    )
    if isinstance(backbone_chain, str):
        return _clone_part_bail(part, backbone_chain)

    # ── Insert into chain + close circle ────────────────────────
    linear = _ligate_fragments(insert_frag, backbone_chain)
    if linear is None:
        return _clone_part_bail(
            part,
            "insert overhangs don't match backbone chain (ligation step)"
        )
    closed = _close_circular(linear)
    if closed is None:
        return _clone_part_bail(part, "circle won't close (right edge ≠ left edge)")
    if not closed.get("top_seq"):
        return _clone_part_bail(part, "cloned plasmid has empty sequence (unreachable)")

    new_rec = _clone_part_build_seqrecord(closed, vec_rec, raw_name)
    _log.info(
        "clone_sim: real-cloned %r into %r (%d bp → %d bp; %d cuts)",
        part.get("name"), vec_rec.name or vec_rec.id or "vector",
        len(vec_seq), _seq_len(new_rec), len(cuts),
    )
    return new_rec


def _site_for_enzyme(enzyme: str) -> str:
    """Look up the recognition site for ``enzyme`` from the NEB
    catalog. Returns "" for unknown enzymes (callers fall back to the
    grammar's primary site)."""
    info = _NEB_ENZYMES.get(enzyme)
    if isinstance(info, tuple) and info:
        return str(info[0]).upper()
    return ""


# Backbone-marker keywords used by `_pick_insert_fragment` to tell the
# bacterial / replication-machinery half of a digested plasmid apart
# from the cloned insert. Match is case-insensitive substring on
# feature labels + types — covers the common annotation styles
# (`rep_origin`, `Ori*`, `AmpR`, `KanR`, `cat`, `Spec`, etc.) without
# trying to be exhaustive: false negatives just trigger the size
# fallback, which is fine.
_BACKBONE_FEATURE_TYPES: frozenset[str] = frozenset({
    "rep_origin", "oriT",
})
_BACKBONE_LABEL_KEYWORDS: tuple[str, ...] = (
    "ori", "rep_origin",
    "ampr", "kanr", "specr", "specinomycin", "spectinomycin",
    "cmr", "chloramphenicol", "tetr", "tetracyclin",
    "carbr", "carbenicillin",
    "selection", "antibiotic",
)


def _reconstruct_l0_features_in_seq(
    insert_seq: str,
    source_parts: "list[str] | tuple[str, ...]",
    grammar_id: str,
) -> list[dict]:
    """Re-derive L0-part features inside ``insert_seq`` by string-
    searching for each named source part's body sequence.

    Used by `_assembly_fragment_from_source` to ensure every cycle
    surfaces the individual promoter / CDS / terminator annotations
    each TU was BUILT FROM, even when the saved TU plasmid only
    carries a single collapsed feature (legacy data, manually-
    annotated runs that pre-date multi-feature persist). Pure
    sequence match — no coordinate-arithmetic assumptions about
    how the alpha vector internally lays out the L0 region — so
    it works for reversed-design vectors and any custom grammar.

    Returns a list of feature dicts in the standard
    `_fragments_from_cuts` shape: ``{start, end, strand, type,
    label, color}``. Misses (L0 part deleted from bin, sequence not
    found verbatim, RC-only on linear; we try both) are silently
    skipped — better to surface fewer features than fabricated ones.
    """
    out: list[dict] = []
    if not insert_seq or not source_parts:
        return out
    insert_seq = insert_seq.upper()
    bin_index: dict[str, dict] = {}
    for p in _load_parts_bin():
        nm = p.get("name") or ""
        if (nm
                and nm not in bin_index
                and (p.get("grammar") or "gb_l0") == grammar_id
                and _part_level(p) == 0):
            bin_index[nm] = p
    for raw_name in source_parts:
        name = str(raw_name or "")
        if not name:
            continue
        p = bin_index.get(name)
        if p is None:
            continue
        body = str(p.get("sequence") or "").upper()
        if not body:
            continue
        pos = insert_seq.find(body)
        strand = 1
        if pos < 0:
            rc_body = _rc(body)
            pos = insert_seq.find(rc_body)
            if pos < 0:
                continue
            strand = -1
        ptype = str(p.get("type") or "misc_feature")
        # Extend the 5' boundary into the upstream AATG overhang so a
        # CDS-like part's annotation includes its start codon. The ATG
        # of AATG (Pos 12→13 fusion) IS the start codon — see
        # `_atg_offset_for_part`. Direction depends on strand: forward
        # parts get the extension at the lower coordinate; reverse-
        # strand parts get it at the upper coordinate. Clamps to
        # [0, insert_len] so the linear-insert case can't underflow.
        atg_off = _atg_offset_for_part(p.get("oh5", ""), ptype)
        feat_start = pos
        feat_end   = pos + len(body)
        if atg_off:
            if strand == 1:
                feat_start = max(0, pos - atg_off)
            else:
                feat_end = min(len(insert_seq), feat_end + atg_off)
        out.append({
            "start":  feat_start,
            "end":    feat_end,
            "strand": strand,
            "type":   _GB_PART_TYPE_TO_INSDC.get(
                ptype, "misc_feature",
            ),
            "label":  name,
            "color":  _GB_TYPE_COLORS.get(ptype, "white"),
        })
    return out


def _fragment_has_backbone_marker(frag: dict) -> bool:
    """Return True iff ``frag``'s features include a typical
    bacterial-backbone marker (origin of replication or antibiotic
    resistance). Case-insensitive substring match on the feature's
    label / qualifier.

    Used by `_pick_insert_fragment` to avoid the "smallest fragment
    is the dropout" heuristic — that rule breaks the moment a
    stacked-TU/MOD insert outgrows its carrier vector. Looking for
    the ORIGIN/SELECTION markers is reliable because real Golden
    Braid / MoClo entry vectors annotate them, and the L0 parts
    chained INTO an insert never do."""
    for f in (frag.get("features") or []):
        if not isinstance(f, dict):
            continue
        ftype = str(f.get("type") or "").lower()
        if ftype in _BACKBONE_FEATURE_TYPES:
            return True
        label = str(f.get("label") or "").lower()
        if not label:
            continue
        for kw in _BACKBONE_LABEL_KEYWORDS:
            if kw in label:
                return True
    return False


def _pick_insert_fragment(
    fragments: list[dict],
    expected_oh5: str = "",
    expected_oh3: str = "",
) -> "dict | None":
    """Pick the "released insert" fragment from a multi-fragment
    digest. Strategy, in priority order:

    1. **Backbone-marker exclusion** — if exactly one fragment lacks
       any origin/resistance feature, that's the insert. Reliable
       across stacked-TU/MOD plasmids where the insert can be much
       larger than the carrier backbone (the "min size" heuristic
       would otherwise mis-select once N-TUs grow past the backbone).
    2. **Overhang match** — when an expected ``(oh5, oh3)`` pair is
       supplied, prefer a fragment whose left/right overhangs match
       (in either orientation; reverse-complement of the swap is
       allowed for backbone-direction agnosticism).
    3. **Smallest fragment** — legacy fallback. Works for typical
       single-TU / first-cycle plasmids where backbone > insert.

    Returns the picked fragment dict, or ``None`` when ``fragments``
    is empty.

    Logs a warning at fallback (strategy 3) when **no** fragment
    carries a backbone marker — the pick is ambiguous in that case
    and the user's library entry may be missing rep_origin /
    resistance annotations. Callers who depend on a correct pick
    (Traditional cloning's `_build_insert_from_plasmid`) should
    surface this to the user; classifiers that scan both fragments
    (like `_classify_part_from_plasmid` since 2026-05-13) don't
    care.
    """
    if not fragments:
        return None
    # Strategy 1 — exclude backbone-marker fragments.
    insert_candidates = [
        f for f in fragments
        if not _fragment_has_backbone_marker(f)
    ]
    if len(insert_candidates) == 1:
        return insert_candidates[0]
    # Strategy 2 — overhang match (when caller knows what to expect).
    if expected_oh5 and expected_oh3:
        e5 = expected_oh5.upper()
        e3 = expected_oh3.upper()
        e5_rc = _rc(e5)
        e3_rc = _rc(e3)
        for f in fragments:
            left  = str((f.get("left")  or {}).get("overhang_seq", "")).upper()
            right = str((f.get("right") or {}).get("overhang_seq", "")).upper()
            if (left == e5 and right == e3):
                return f
            if (left == e3_rc and right == e5_rc):
                return f
    # Strategy 3 — smallest fragment (legacy, robust for ≤1-cycle).
    # Surface an ambiguity warning when NEITHER fragment carries a
    # backbone marker: the size fallback can pick the wrong half if
    # the user's insert outgrew the carrier (MAV 26 family, 2026-
    # 05-13). Traditional cloning callers should display this to the
    # user; the classifier path doesn't hit this branch anymore.
    if not any(_fragment_has_backbone_marker(f) for f in fragments):
        sizes = [len(f.get("top_seq") or "") for f in fragments]
        _log.warning(
            "_pick_insert_fragment: no backbone markers on any "
            "fragment; falling back to smallest (sizes=%r). The "
            "picked fragment may not be the biological insert — "
            "library entry likely missing rep_origin / antibiotic "
            "resistance annotations.", sizes,
        )
    return min(fragments, key=lambda f: len(f.get("top_seq") or ""))


def _pick_backbone_fragment(fragments: list[dict]) -> "dict | None":
    """Complement of `_pick_insert_fragment` — picks the bacterial
    backbone half (rep_origin + selection-marker carrier). Strategy:

    1. **Backbone-marker presence** — if exactly one fragment has
       a backbone marker, that's the backbone. Works whether or not
       the backbone is the larger fragment (matters when an insert
       outgrows its carrier in deep cycles, where max-size flips
       which fragment gets picked).
    2. **Largest fragment** — legacy fallback. Works for the
       typical entry-vector + small insert case.

    Used by traditional cloning to keep the user's intended
    backbone choice stable as inserts grow over multiple cloning
    cycles. Returns ``None`` when ``fragments`` is empty.

    Same ambiguity warning as `_pick_insert_fragment` fires when
    NEITHER fragment carries a backbone marker — fallback to size
    is a guess in that case (2026-05-13 audit).
    """
    if not fragments:
        return None
    backbone_candidates = [
        f for f in fragments
        if _fragment_has_backbone_marker(f)
    ]
    if len(backbone_candidates) == 1:
        return backbone_candidates[0]
    if not backbone_candidates:
        sizes = [len(f.get("top_seq") or "") for f in fragments]
        _log.warning(
            "_pick_backbone_fragment: no backbone markers on any "
            "fragment; falling back to largest (sizes=%r). The "
            "picked fragment may not be the biological backbone — "
            "library entry likely missing rep_origin / antibiotic "
            "resistance annotations.", sizes,
        )
    return max(fragments, key=lambda f: len(f.get("top_seq") or ""))


# LRU cache for `_assembly_fragment_from_source` digests on L1+ TUs/MODs.
# Keyed by (gb_text_hash, grammar_id, source_level, primary_enzyme,
# level_up_enzyme). Without this, `_palette_rows_for_grammar` redigests
# every saved part on every refresh — a 50-TU bin used to cost 0.25-2.5 s
# per palette rebuild (palette tab switch, source-level radio, filter
# toggle). Cap matches `_VECTOR_MATCH_CACHE` rationale: well above the
# steady-state working set for a single user, small enough that stale
# entries from a different in-memory grammar don't accumulate. Cleared
# explicitly by `_save_parts_bin` and `_save_custom_grammars` so a part
# edit / grammar enzyme change isn't masked by a stale digest.
_ASSEMBLY_FRAGMENT_CACHE: "_OD[tuple, dict | None]" = _OD()
_ASSEMBLY_FRAGMENT_CACHE_MAX = 128


def _clear_assembly_fragment_cache() -> None:
    """Drop every cached digest so the next palette refresh / save
    re-derives overhangs from the current parts bin + grammar
    state. Called from `_save_parts_bin` and `_save_custom_grammars`."""
    _ASSEMBLY_FRAGMENT_CACHE.clear()


# ── _assembly_fragment_from_source helpers ────────────────────────────────


def _assembly_fragment_l0(source: dict, source_level: int) -> "dict | None":
    """L0 short-circuit: read the part's stored sequence + overhangs
    directly. Returns None if any required field is missing — the L0
    storage contract requires sequence + oh5 + oh3 to all be present."""
    seq = (source.get("sequence") or "").upper()
    oh5 = (source.get("oh5") or "").upper()
    oh3 = (source.get("oh3") or "").upper()
    if not seq or not oh5 or not oh3:
        return None
    return {
        "name":     source.get("name") or "part",
        "sequence": seq,
        "oh5":      oh5,
        "oh3":      oh3,
        "level":    int(source_level),
    }


def _assembly_fragment_recover_gb_text(
    source: dict, source_level: int,
) -> "str | None":
    """Get the source plasmid's gb_text, falling back to library lookup.

    Back-compat: parts saved by Load Part before 2026-05-13 only carried
    `sequence` (the released insert body) without the full plasmid
    gb_text. Cross-reference the library by name (`id` or `name` match)
    to recover it so old parts-bin entries don't need to be reloaded.

    Returns ``None`` if no gb_text can be recovered."""
    gb_text = source.get("gb_text") or ""
    if gb_text:
        return gb_text
    src_name = str(source.get("name") or "").strip()
    if src_name:
        for e in _load_library():
            if not isinstance(e, dict):
                continue
            if not e.get("gb_text"):
                continue
            if (str(e.get("id") or "").strip() == src_name
                    or str(e.get("name") or "").strip() == src_name):
                _log.info(
                    "assembly_fragment: recovered gb_text for %r "
                    "from library (parts bin entry was pre-2026-05-13)",
                    src_name,
                )
                return e["gb_text"]
    _log.info(
        "assembly_fragment: %r has no gb_text and no matching "
        "library entry — can't digest at level %d. Re-Load Part "
        "from the source plasmid to refresh.",
        source.get("name"), source_level,
    )
    return None


def _assembly_fragment_cache_key(
    gb_text: str, grammar: dict, source_level: int, primary_enzyme: str,
) -> tuple:
    """Cache key for `_ASSEMBLY_FRAGMENT_CACHE`. Length + hash + grammar
    id + source_level + both enzyme candidates. We don't use the raw
    gb_text as a key because it can be hundreds of KB and Python dict
    hashing would copy the string bytes on every lookup. `len(gb_text)`
    lets the dict bucket on a cheap int while `hash(gb_text)` ties the
    slot to the actual content."""
    return (
        hash(gb_text), len(gb_text),
        grammar.get("id") or "",
        int(source_level),
        primary_enzyme,
        str(grammar.get("enzyme") or ""),
        str(grammar.get("level_up_enzyme") or ""),
    )


def _assembly_fragment_marshal_src_features(rec) -> list[dict]:
    """SeqRecord features → dict-shape list for `_excise_fragment_pair`.

    Without this, released fragments carry no features and downstream
    MOD assemblies render as one collapsed insert. Skips `source` rows
    (whole-record metadata) and tolerates whatever qualifier carried the
    label / colour."""
    out: list[dict] = []
    total_src = _seq_len(rec)
    for f in (rec.features or []):
        if f.type == "source":
            continue
        bounds = _feat_bounds(f, total_src)
        if bounds is None:
            continue
        fs, fe, fstrand = bounds
        label = ""
        for k in ("label", "gene", "product", "note"):
            vals = f.qualifiers.get(k, [])
            if vals:
                label = str(vals[0])
                break
        color = ""
        for k in ("ApEinfo_fwdcolor", "ApEinfo_revcolor", "color"):
            vals = f.qualifiers.get(k, [])
            if vals:
                color = str(vals[0])
                break
        out.append({
            "start":  fs, "end":   fe,
            "strand": fstrand,
            "type":   f.type,
            "label":  label or f.type,
            "color":  color or "white",
        })
    return out


def _assembly_fragment_enzyme_candidates(
    grammar: dict, primary_enzyme: str,
) -> list[str]:
    """Build the dedup'd enzyme-candidate list for the digest loop.

    Tries the level-up primary first, then `grammar.enzyme`, then
    `grammar.level_up_enzyme`. Reversed-design vectors lose the
    level-up enzyme's sites during the L0→TU clone, so the OTHER
    enzyme is the right cutter for that user's TU→MOD step. The
    fallback picks whichever enzyme yields a clean 2-fragment circular
    digest — properly-designed standard GB vectors hit the primary
    first and the fallback never triggers (no behaviour change)."""
    candidates: list[str] = [primary_enzyme]
    for cand in (str(grammar.get("enzyme") or ""),
                  str(grammar.get("level_up_enzyme") or "")):
        if cand and cand not in candidates:
            candidates.append(cand)
    return candidates


def _assembly_fragment_try_digests(
    plasmid_seq: str, candidates: list[str], *, circular: bool,
    src_features: list[dict], source: dict, primary_enzyme: str,
) -> "tuple[dict | None, str, object]":
    """Loop over candidate enzymes; return ``(insert_frag, chosen_enzyme, last_err)``.

    `insert_frag` is None if no candidate produced a clean 2-fragment
    digest with a pickable insert. `chosen_enzyme` is "" in that case.
    `last_err` carries the most recent `_excise_fragment_pair` error
    string so the caller can log it."""
    last_err: object = None
    for enz in candidates:
        try:
            frags, err = _excise_fragment_pair(
                plasmid_seq, [enz], circular=circular,
                features=src_features,
                source_label=source.get("name") or "src",
            )
        except Exception:
            _log.exception("assembly_fragment: digest failed for %r",
                            source.get("name"))
            continue
        if err is not None or len(frags) != 2:
            last_err = err
            continue
        # Pick the released-insert fragment via feature-aware selection
        # (rep_origin / antibiotic-resistance absent). Falls through to
        # overhang match (if the source's stored oh5/oh3 are present)
        # and finally to min-size for a robust legacy default. The
        # min-size rule alone breaks the moment a multi-TU MOD's insert
        # outgrows the carrier backbone.
        insert_frag = _pick_insert_fragment(
            frags,
            expected_oh5=str(source.get("oh5") or ""),
            expected_oh3=str(source.get("oh3") or ""),
        )
        if insert_frag is None:
            continue
        if enz != primary_enzyme:
            _log.info(
                "assembly_fragment: %r — level_up enzyme %r had no "
                "clean digest, fell back to %r",
                source.get("name"), primary_enzyme, enz,
            )
        return insert_frag, enz, last_err
    return None, "", last_err


def _assembly_fragment_strip_oh5(
    insert_frag: dict,
) -> "tuple[str, str, str, list[dict]] | None":
    """Strip the leading 4-bp 5' overhang to match the L0 storage
    convention (sequence WITHOUT the overhang; oh5/oh3 held separately).

    The right overhang lives between this fragment's cut and the next
    fragment, so it doesn't appear inside top_seq. Returns
    ``(seq_no_oh, oh5, oh3, frag_features)`` or ``None`` if any of
    top_seq / oh5 / oh3 are empty.

    Features are shifted by -len(oh5). Features whose entire span sat
    inside the stripped overhang region collapse to zero-length and are
    dropped — an oh5-only feature has no biological meaning in the
    chained sequence."""
    top_seq = (insert_frag.get("top_seq") or "").upper()
    oh5 = (insert_frag.get("left")  or {}).get("overhang_seq", "").upper()
    oh3 = (insert_frag.get("right") or {}).get("overhang_seq", "").upper()
    if not top_seq or not oh5 or not oh3:
        return None
    seq_no_oh = top_seq[len(oh5):] if top_seq.startswith(oh5) else top_seq
    frag_features: list[dict] = []
    for f in (insert_frag.get("features") or []):
        try:
            fs = int(f.get("start", 0))
            fe = int(f.get("end",   0))
        except (TypeError, ValueError):
            continue
        new_s = max(0, fs - len(oh5))
        new_e = max(0, fe - len(oh5))
        if new_e <= new_s:
            continue
        if new_s >= len(seq_no_oh):
            continue
        frag_features.append({
            **f,
            "start": new_s,
            "end":   min(new_e, len(seq_no_oh)),
        })
    return seq_no_oh, oh5, oh3, frag_features


def _assembly_fragment_augment_l0_features(
    seq_no_oh: str, source: dict, grammar: dict,
    frag_features: list[dict],
) -> list[dict]:
    """Augment the fragment's features with reconstructed L0-part
    features so every cycle propagates the full provenance (J23100,
    cscA, Lambda T0 …) even when the saved TU/MOD plasmid only carries
    a single collapsed feature for the insert region.

    Pure substring search on each `source_parts` body — works regardless
    of how the carrier vector lays out its dropout. Drops features that
    contain ≥2 reconstructed L0 sub-parts (the "ALPHA TEST 1"-style
    collapsed annotation): once individual L0 features are surfaced,
    the wrapping block is redundant clutter. Vector backbone features
    (Ori, AmpR …) sit outside the L0 region so they fail the
    containment check and stay."""
    src_parts = source.get("source_parts") or []
    if not (isinstance(src_parts, (list, tuple)) and src_parts):
        return frag_features
    try:
        recon = _reconstruct_l0_features_in_seq(
            seq_no_oh,
            src_parts,
            str(grammar.get("id") or ""),
        )
    except Exception:
        _log.exception(
            "assembly_fragment: L0 feature reconstruction "
            "raised for %r", source.get("name"),
        )
        return frag_features
    if not recon:
        return frag_features
    existing_keys = {
        (str(f.get("label") or ""),
         int(f.get("start", -1)),
         int(f.get("end",   -1)))
        for f in frag_features
    }
    kept_features: list[dict] = []
    for f in frag_features:
        try:
            fs = int(f.get("start", 0))
            fe = int(f.get("end",   0))
        except (TypeError, ValueError):
            kept_features.append(f)
            continue
        contained = sum(
            1 for r in recon
            if int(r.get("start", 0)) >= fs
            and int(r.get("end",   0)) <= fe
        )
        if contained >= 2:
            continue
        kept_features.append(f)
    for r in recon:
        key = (
            str(r.get("label") or ""),
            int(r.get("start", -1)),
            int(r.get("end",   -1)),
        )
        if key not in existing_keys:
            kept_features.append(r)
    return kept_features


def _assembly_fragment_from_source(
    source: dict, grammar: dict, source_level: int,
) -> "dict | None":
    """Extract a uniform ``{name, sequence, oh5, oh3, features}``
    fragment dict from an L0 part OR an L1+ assembled plasmid,
    suitable for chaining in a multi-part Golden Braid (or any other
    modular) assembly.

    L0 sources read fields directly. L1+ sources are digested with the
    grammar's level-up enzyme; if that yields no clean 2-fragment
    circular digest the helper falls back to grammar.enzyme (and
    grammar.level_up_enzyme), so reversed-design vectors keep
    cycling without a custom grammar. The smaller of the two released
    fragments becomes the carried "insert", with its features
    shifted into oh-stripped local coords. Returns ``None`` on any
    extraction failure so the caller can surface a clean error.

    L1+ digests are LRU-cached by (gb_text_hash, grammar_id,
    source_level, primary_enzyme, level_up_enzyme); the cache is
    cleared on parts-bin or grammar saves so a re-domesticated part
    or a level_up_enzyme tweak takes effect on the next refresh.

    Pre-refactor this was a 346-line monolith; per-stage logic now
    lives in `_assembly_fragment_*` helpers. Behaviour is bit-
    identical; tested by tests/test_domesticator.py + Constructor
    integration tests in tests/test_smoke.py.
    """
    if source_level <= 0:
        return _assembly_fragment_l0(source, source_level)

    primary_enzyme = _enzyme_for_level_up(grammar, source_level)
    if not primary_enzyme:
        return None

    gb_text = _assembly_fragment_recover_gb_text(source, source_level)
    if gb_text is None:
        return None

    cache_key = _assembly_fragment_cache_key(
        gb_text, grammar, source_level, primary_enzyme,
    )
    cached = _ASSEMBLY_FRAGMENT_CACHE.get(cache_key, _ASSEMBLY_FRAGMENT_CACHE)
    if cached is not _ASSEMBLY_FRAGMENT_CACHE:
        # LRU: bump key to most-recent so steady-state queries don't
        # evict each other. Cached value can legitimately be None (digest
        # failed once, will fail the same way again until parts/grammar
        # change). Return a typed clone so callers can mutate the dict
        # without poisoning the cache (see `_typed_clone`, invariant #17).
        _ASSEMBLY_FRAGMENT_CACHE.move_to_end(cache_key)
        if cached is None:
            return None
        return _typed_clone(cached)

    try:
        rec = _gb_text_to_record(gb_text)
    except Exception:
        _log.exception("assembly_fragment: gb_text parse failed for %r",
                        source.get("name"))
        _ASSEMBLY_FRAGMENT_CACHE[cache_key] = None
        return None
    plasmid_seq = str(rec.seq).upper()
    if not plasmid_seq:
        return None
    topology = (rec.annotations.get("topology", "") or "").lower()
    circular = topology != "linear"

    src_features = _assembly_fragment_marshal_src_features(rec)
    candidates = _assembly_fragment_enzyme_candidates(grammar, primary_enzyme)

    insert_frag, chosen_enzyme, last_err = _assembly_fragment_try_digests(
        plasmid_seq, candidates, circular=circular,
        src_features=src_features, source=source,
        primary_enzyme=primary_enzyme,
    )
    if insert_frag is None:
        _log.info(
            "assembly_fragment: %r — no clean digest under any enzyme "
            "(%s); last err: %r",
            source.get("name"), candidates, last_err,
        )
        _ASSEMBLY_FRAGMENT_CACHE[cache_key] = None
        return None

    stripped = _assembly_fragment_strip_oh5(insert_frag)
    if stripped is None:
        _ASSEMBLY_FRAGMENT_CACHE[cache_key] = None
        return None
    seq_no_oh, oh5, oh3, frag_features = stripped

    frag_features = _assembly_fragment_augment_l0_features(
        seq_no_oh, source, grammar, frag_features,
    )

    result = {
        "name":     source.get("name") or "src",
        "sequence": seq_no_oh,
        "oh5":      oh5,
        "oh3":      oh3,
        "level":    int(source_level),
        "enzyme":   chosen_enzyme,
        "features": frag_features,
    }
    # Cache result. Bound the cache via FIFO eviction (the LRU
    # semantics — `move_to_end` on hit — already keeps the working set
    # warm). Stores a typed clone so a caller mutating the returned
    # dict can't poison subsequent readers; a separate clone is
    # returned on each read so the cached version stays canonical.
    _ASSEMBLY_FRAGMENT_CACHE[cache_key] = _typed_clone(result)
    while len(_ASSEMBLY_FRAGMENT_CACHE) > _ASSEMBLY_FRAGMENT_CACHE_MAX:
        _ASSEMBLY_FRAGMENT_CACHE.popitem(last=False)
    return result


@_timed("op.clone_assembly_into_entry_vector")
def _clone_assembly_into_entry_vector(
    sources: list[dict],
    entry_vector: dict,
    grammar: dict,
    *,
    source_level: int = 0,
    name: str = "",
):
    """Multi-source Golden Braid assembly cloner.

    Concatenates ``sources`` (L0 parts when ``source_level == 0``, or
    L1+ assembled plasmids when ≥ 1) into a single chained insert,
    then ligates that insert into the cut ``entry_vector`` via the
    existing single-part cloning machinery (`_clone_part_into_entry_vector`)
    by synthesising a virtual "part" whose ``sequence`` is the chained
    inserts and whose ``oh5`` / ``oh3`` are the boundary sticky ends
    of the chain.

    The level-up enzyme is picked by `_enzyme_for_level_up(grammar,
    source_level)`, which alternates between ``grammar.enzyme`` and
    ``grammar.level_up_enzyme`` each level so the assembled product
    survives the next cycle's cut. The chosen enzyme + matching
    recognition site override `grammar.enzyme` / `grammar.site` for
    the duration of this single call so the downstream
    primed-amplicon synthesis + IIS-cut digest happen with the right
    enzyme.

    Returns ``None`` on any failure (empty source list, source
    extraction failure, junction-overhang mismatch, vector cut
    failure). Callers should surface a notify so the user knows the
    digest didn't simulate cleanly."""
    if not sources:
        return None
    fragments: list[dict] = []
    for s in sources:
        # Defensive: every source must claim the requested level.
        # Without this check, a misrouted L0 part in an L1+ lane
        # would silently fall through to the L0 extraction branch
        # (since `_assembly_fragment_from_source` only looks at the
        # `source_level` parameter, not the part's own `level`
        # field), producing a wrong-grammar assembly.
        s_lvl = _part_level(s)
        if not _level_matches_tab(s_lvl, source_level):
            _log.info(
                "clone_assembly: source %r has level %d, expected %d",
                s.get("name"), s_lvl, source_level,
            )
            return None
        frag = _assembly_fragment_from_source(s, grammar, source_level)
        if frag is None:
            _log.info(
                "clone_assembly: source %r rejected (level %d)",
                s.get("name"), source_level,
            )
            return None
        fragments.append(frag)
    # Validate chain: every junction must have matching overhangs.
    for i in range(len(fragments) - 1):
        if fragments[i]["oh3"] != fragments[i + 1]["oh5"]:
            _log.info(
                "clone_assembly: junction %d mismatch (%s vs %s)",
                i, fragments[i]["oh3"], fragments[i + 1]["oh5"],
            )
            return None
    # Concatenate top strands AND chain features so the assembled
    # MOD inherits every promoter / CDS / terminator / colour the
    # source TUs carried, instead of collapsing into a single
    # whole-insert feature named after the entry vector. Each
    # fragment contributes its 5'OH (except the first, whose oh5 is
    # the chain's terminal sticky end) + its body sequence; feature
    # coords shift by the cumulative offset of preceding fragments.
    seq_parts: list[str] = []
    chained_features: list[dict] = []
    cursor = 0
    for i, f in enumerate(fragments):
        if i > 0:
            cursor += len(f["oh5"])
            seq_parts.append(f["oh5"])
        body = f["sequence"]
        seq_parts.append(body)
        # Pull features off the fragment when `_assembly_fragment_from_source`
        # extracted them (L1+ sources). For L0 sources the helper
        # returns no features; synthesise one feature per L0 part so
        # the assembled TU shows the user's promoter / CDS /
        # terminator names instead of a single "TU1" blob. Type is
        # taken from the source's `type` field (Promoter, CDS,
        # Terminator, etc.); colour from the grammar's per-type
        # colour table when available, else falls back to "white".
        frag_feats = list(f.get("features") or [])
        # Resolve the part type once per fragment (used by both the
        # synth-feature path below and the AATG start-codon extension
        # in the per-feature loop). Hoisted out of the synth branch so
        # the start-codon fix can run for carried features too.
        ptype = ""
        for s in sources:
            if (s.get("name") or "") == f["name"]:
                ptype = str(s.get("type") or "")
                break
        if not frag_feats and body:
            color = _GB_TYPE_COLORS.get(ptype, "white")
            frag_feats = [{
                "start":  0,
                "end":    len(body),
                "strand": 1,
                "type":   _GB_PART_TYPE_TO_INSDC.get(ptype, "misc_feature"),
                "label":  f["name"],
                "color":  color,
            }]
        # Start-codon extension: when this fragment's 5' overhang is
        # AATG and the part is a coding type, a feature that lands at
        # body-start (fs == 0) needs to extend 3 nt upstream to include
        # the ATG embedded in the AATG fusion overhang. Only applies
        # to non-first fragments — the first fragment's body sits at
        # offset 0 with no AATG upstream in the chain (the AATG would
        # only appear when the entry-vector half ligates in later).
        # See `_atg_offset_for_part` for the biology rationale.
        atg_off = _atg_offset_for_part(f.get("oh5", ""), ptype) if i > 0 else 0
        for fr in frag_feats:
            try:
                fs = int(fr.get("start", 0))
                fe = int(fr.get("end",   0))
            except (TypeError, ValueError):
                continue
            if fe <= fs:
                continue
            start_in_chain = cursor + fs
            end_in_chain   = cursor + fe
            if atg_off and fs == 0:
                start_in_chain = max(0, start_in_chain - atg_off)
            chained_features.append({
                **fr,
                "start": start_in_chain,
                "end":   end_in_chain,
            })
        cursor += len(body)
    combined_seq = "".join(seq_parts)
    # Pick the enzyme + site for the level-up step. Prefer whatever
    # enzyme `_assembly_fragment_from_source` actually used to release
    # the source fragments — its auto-detect already picked the
    # enzyme that survives in the user's TU/MOD plasmids, so
    # cutting the entry vector with the SAME enzyme keeps the
    # extraction + ligation sides consistent. Falls back to the
    # grammar-level pick when no fragment carried an explicit
    # `enzyme` (legacy callers, source_level=0).
    target_enzyme = ""
    for f in fragments:
        cand = str(f.get("enzyme") or "")
        if cand:
            target_enzyme = cand
            break
    if not target_enzyme:
        target_enzyme = _enzyme_for_level_up(grammar, source_level)
    if not target_enzyme:
        return None
    target_site = _site_for_enzyme(target_enzyme)
    grammar_for_step = dict(grammar)
    grammar_for_step["enzyme"] = target_enzyme
    if target_site:
        grammar_for_step["site"] = target_site
    synthetic_name = name or "+".join(f["name"] for f in fragments)
    synthetic = {
        "name":     synthetic_name,
        "sequence": combined_seq,
        "oh5":      fragments[0]["oh5"],
        "oh3":      fragments[-1]["oh3"],
        "type":     ("TU" if source_level == 0 else "MOD"),
        "position": ("TU" if source_level == 0 else "MOD"),
        "grammar":  grammar.get("id"),
        # Pre-built features signal `_clone_part_into_entry_vector`
        # to skip the single-name part_feature and use these instead.
        # Generic across grammars: GB, MoClo, custom — anything that
        # routes through `_clone_assembly_into_entry_vector` gets the
        # multi-feature insert by virtue of this key.
        "features": chained_features,
    }
    return _clone_part_into_entry_vector(
        synthetic, entry_vector, grammar_for_step,
    )


def _splice_part_into_vector_by_overhang(
    entry_vector: dict, part: dict,
    grammar: "dict | None" = None,
):
    """Sequence-based fallback for `_part_to_cloned_seqrecord` when
    the strict IIS-digest simulation fails (extra enzyme sites,
    incompatible overhangs, missing recognition annotations, etc.).

    Finds the closest `oh5...oh3` pair in the entry vector's
    sequence (allowing both circular and reverse-complement search)
    and splices the part's insert in place of the segment between
    them — same junction structure the bench reaction would
    produce, just identified by sequence match instead of by
    enzyme cut. The user's vector sequence + features are
    preserved outside the dropout; vector features that fall
    inside the dropped region are filtered out so the saved record
    doesn't carry stale annotation.

    **Refuses when the vector has IIS sites that conflict** with
    the part's overhangs — prevents the case where the helper
    would otherwise find a coincidental ``oh5...oh3`` pattern
    elsewhere in the vector and produce a biologically wrong
    "splice" at the wrong position. Pass `grammar` so this guard
    can run; without it the splice runs unconstrained (preserving
    backward compat for callers that haven't migrated yet).

    Returns a circular `SeqRecord` on success, ``None`` when the
    overhangs aren't found in the vector OR conflict with the
    vector's IIS cuts — the absolute fallback (stub backbone)
    handles that case.
    """
    from Bio.Seq import Seq
    from Bio.SeqRecord import SeqRecord
    from Bio.SeqFeature import SeqFeature, FeatureLocation

    insert = (part.get("sequence") or "").upper()
    oh5 = (part.get("oh5") or "").upper()
    oh3 = (part.get("oh3") or "").upper()
    if not insert or len(oh5) < 4 or len(oh3) < 4:
        return None
    gb_text = (entry_vector.get("gb_text") or "").strip()
    if not gb_text:
        return None
    try:
        vec_rec = _gb_text_to_record(gb_text)
    except Exception:
        return None
    vec_seq = str(vec_rec.seq).upper()
    if not vec_seq:
        return None

    # IIS-conflict guard: if the vector has IIS sites for the
    # grammar's enzyme but NONE of the cut overhangs match the
    # part's, the user's part literally can't drop into this
    # vector. A sequence-splice would find a coincidental
    # `oh5...oh3` match somewhere else in the backbone and produce
    # a biologically meaningless "cloned" plasmid. Refuse here so
    # the orchestrator can surface a precise error explaining the
    # required overhangs.
    if isinstance(grammar, dict):
        enzyme = grammar.get("enzyme")
        if isinstance(enzyme, str) and enzyme in _NEB_ENZYMES:
            vec_circular = (
                (vec_rec.annotations.get("topology", "") or "").lower()
                != "linear"
            )
            try:
                cuts = _enzyme_cuts(
                    vec_seq, [enzyme], circular=vec_circular,
                )
            except Exception:
                cuts = []
            if cuts:
                cut_overhangs = {c["overhang_seq"] for c in cuts}
                # Allow either oh5 or oh3 to match (one end is enough
                # — the other will be evaluated by the splice's
                # internal compatibility check).
                if (oh5 not in cut_overhangs
                        and oh3 not in cut_overhangs
                        and _rc(oh5) not in cut_overhangs
                        and _rc(oh3) not in cut_overhangs):
                    _log.info(
                        "clone_sim: refusing sequence-splice for part "
                        "%r — vector has %d %s cut(s) with overhangs "
                        "%s, but part needs %s/%s",
                        part.get("name"), len(cuts), enzyme,
                        sorted(cut_overhangs), oh5, oh3,
                    )
                    return None

    # Search a doubled sequence so we can find an oh5...oh3 pair
    # that wraps the origin on a circular plasmid. The result is
    # mapped back into the canonical [0, n) coordinate space below.
    n = len(vec_seq)
    is_circular = (
        (vec_rec.annotations.get("topology", "") or "").lower()
        != "linear"
    )
    search_seq = vec_seq + (vec_seq if is_circular else "")

    # Find all (i, j) with vec[i:i+4] == oh5 and vec[j:j+4] == oh3,
    # j > i+4 (no overlap). Try both forward and reverse-complement
    # of the insert so palindromic-ish overhangs still resolve.
    def _find_pair(s5: str, s3: str) -> "tuple[int, int] | None":
        best = None
        i = search_seq.find(s5)
        while i != -1 and i < n + (n if is_circular else 0):
            j = search_seq.find(s3, i + len(s5))
            # Cap dropout span at 10 kb so a coincidental oh5/oh3
            # match at opposite poles of a big plasmid doesn't
            # produce a wildly wrong splice.
            if j != -1 and (j - i) <= 10_000:
                if best is None or (j - i) < (best[1] - best[0]):
                    best = (i, j)
            i = search_seq.find(s5, i + 1)
        return best

    pair = _find_pair(oh5, oh3)
    use_rc = False
    insert_oriented = insert
    if pair is None:
        # Try the part's overhangs swapped for an RC-oriented insert
        rc_oh5 = _rc(oh3)
        rc_oh3 = _rc(oh5)
        pair = _find_pair(rc_oh5, rc_oh3)
        if pair is not None:
            use_rc = True
            insert_oriented = _rc(insert)
    if pair is None:
        _log.info(
            "clone_sim: sequence-splice failed for part %r — "
            "neither oh5/oh3 nor their RC found within 10 kb in vector %r",
            part.get("name"), vec_rec.name,
        )
        return None

    i, j = pair
    # Build cloned sequence: [vec up to + including oh5] +
    #   insert + [vec from oh3 onwards]. For a wrap-around match
    #   (j >= n) the slicing on `search_seq` keeps the
    #   right-of-dropout segment as a single contiguous run we can
    #   re-modulus into [0, n).
    overhang5_end = i + len(oh5)
    overhang3_start = j
    if j >= n:
        # Wrap match: dropout straddles the origin. Build sequence
        # by walking the doubled `search_seq` from oh5_end up to
        # oh3_start and continuing past the doubled boundary back
        # to oh5_start to close the circle on the OTHER side.
        # Simplest mental model: cloned = vec[oh5_end:n] +
        #   vec[0:oh3_start - n] => fragments of vec NOT in dropout.
        # Then prepend oh5 + insert + oh3.
        # Equivalently: build the new sequence in doubled space and
        # slice once.
        cloned = (oh5 + insert_oriented + oh3
                  + search_seq[overhang3_start + len(oh3):
                                overhang5_end + n])
    else:
        # Normal (non-wrap) case.
        cloned = (vec_seq[:overhang5_end]
                  + insert_oriented
                  + vec_seq[overhang3_start:])
    cloned = cloned.upper()
    n_new = len(cloned)
    if n_new == 0:
        return None

    # Carry vector features through, dropping any whose footprint
    # fell entirely within the dropped region. Features outside the
    # dropped region get shifted by `delta = len(insert) -
    # len(dropout)` if they sat AFTER the dropout in linear order.
    # (Dropout bounds were tracked explicitly in an earlier revision;
    # the current shift math uses overhang5_end / overhang3_start /
    # delta directly, so the explicit bounds were dropped.)
    new_feats: list[dict] = []
    if not (j >= n):
        # Linear, non-wrap dropout: simple shift bookkeeping.
        delta = len(insert_oriented) - (j - overhang5_end)
        for f in (vec_rec.features or []):
            if f.type == "source":
                continue
            bounds = _feat_bounds(f, n)
            if bounds is None:
                continue
            fs, fe, _f_strand = bounds
            # Wrap vector features (end < start) can't be shifted by a
            # linear delta — the new plasmid has a different length and
            # the origin sits at a different offset. Pre-fix this path
            # ran `int(loc.start)` which flattened wrap features to
            # outer bounds and then dropped them as "fully inside the
            # dropout"; skipping explicitly with a log surfaces the
            # data loss in the diagnostic bundle instead.
            if fe < fs:
                _log.info(
                    "_assemble_construct: skipping wrap feature %s "
                    "(%d..%d) — linear-clone shift math can't carry it",
                    _feat_label(f), fs, fe,
                )
                continue
            # Drop features fully inside the dropout
            if fs >= overhang5_end and fe <= overhang3_start:
                continue
            # Shift features fully past the dropout
            if fs >= overhang3_start:
                new_feats.append({
                    "obj": f, "start": fs + delta, "end": fe + delta,
                })
                continue
            # Features fully before the dropout: keep as-is
            if fe <= overhang5_end:
                new_feats.append({"obj": f, "start": fs, "end": fe})
                continue
            # Features straddling the dropout boundary: skip rather
            # than try to recompute partial coords — they'd be
            # mis-leading after the splice.
        # Add the part as its own feature
        ftype = _GB_PART_TYPE_TO_INSDC.get(
            part.get("type", ""), "misc_feature",
        )
        new_feats.append({
            "obj": None,
            "start": overhang5_end,
            "end":   overhang5_end + len(insert_oriented),
            "label": part.get("name") or "part",
            "type":  ftype,
        })
    else:
        # Wrap dropout: simpler to skip the original-feature carry
        # and just annotate the insert. Origin-wrap feature math is
        # finicky; the user can re-annotate manually if needed.
        ftype = _GB_PART_TYPE_TO_INSDC.get(
            part.get("type", ""), "misc_feature",
        )
        new_feats.append({
            "obj": None,
            "start": len(oh5),
            "end":   len(oh5) + len(insert_oriented),
            "label": part.get("name") or "part",
            "type":  ftype,
        })

    raw_name = part.get("name") or "part"
    safe_id = re.sub(r"[^A-Za-z0-9_]", "_", str(raw_name)) or "part"
    desc_vec = vec_rec.name or vec_rec.id or "vector"
    new_rec = SeqRecord(
        Seq(cloned), id=safe_id, name=safe_id,
        description=f"Cloned part: {raw_name} in {desc_vec}",
    )
    new_rec.annotations["molecule_type"] = "DNA"
    new_rec.annotations["topology"]      = "circular"
    for fr in new_feats:
        try:
            s = int(fr["start"]); e = int(fr["end"])
        except (TypeError, ValueError):
            continue
        if e <= s or s < 0 or e > n_new:
            continue
        if fr.get("obj") is not None:
            f0 = fr["obj"]
            label = ""
            for k in ("label", "gene", "product", "note"):
                vals = f0.qualifiers.get(k, [])
                if vals:
                    label = str(vals[0]); break
            quals = {"label": [label or f0.type]}
            try:
                new_rec.features.append(SeqFeature(
                    FeatureLocation(
                        s, e,
                        strand=int(getattr(
                            f0.location, "strand", 1) or 1),
                    ),
                    type=str(f0.type),
                    qualifiers=quals,
                ))
            except Exception:
                continue
        else:
            try:
                new_rec.features.append(SeqFeature(
                    FeatureLocation(s, e, strand=1),
                    type=fr.get("type", "misc_feature"),
                    qualifiers={"label": [fr["label"]]},
                ))
            except Exception:
                continue
    _log.info(
        "clone_sim: sequence-spliced %r into %r at oh5=%d/oh3=%d "
        "(%d bp → %d bp, RC=%s)",
        part.get("name"), desc_vec, i, j,
        len(vec_seq), n_new, use_rc,
    )
    return new_rec


def _diagnose_part_cloning(part: dict) -> "str | None":
    """Return a short user-facing reason describing why a part
    won't simulate-clone into the configured entry vector for its
    grammar, or ``None`` when the cloning would succeed.

    Used by the parts-bin Save-to-Collection action to surface a
    notify when one or more parts fall back to the stub backbone
    instead of the user's real entry vector. The simulator now
    synthesises an insert fragment with the dropout's overhangs
    when the part's primer overhangs don't match (= the user
    designed primers for AATG/GCTT-style overhangs without knowing
    the vector exposes CTCG/TGAG via Esp3I), so an overhang
    mismatch alone is no longer a failure case. The remaining
    failure cases are:

      * No entry vector configured for the grammar (legitimate
        stub-fallback — silent, returns None)
      * Grammar's enzyme isn't recognised
      * Vector gb_text can't be parsed
      * Vector has < 2 enzyme cuts (no dropout to excise)

    L1+ parts (TU / MOD) short-circuit at the top: their `gb_text`
    IS the already-cloned plasmid, so `_part_to_cloned_seqrecord`'s
    tier 0 returns it directly without re-cloning. Surfacing
    entry-vector diagnostics for L1+ parts would be misleading —
    they don't go through tier 1 IIS digest at all. The check fires
    for every L1+ row regardless of `gb_text` presence: a degenerate
    L1+ row missing gb_text would still raise downstream in
    `_part_to_cloned_seqrecord` (empty `sequence` → ValueError), but
    surfacing "vector lacks BsaI sites" first would point the user
    at the wrong fix.
    """
    if _part_level(part) >= 1:
        return None
    grammar_id = part.get("grammar") or "gb_l0"
    try:
        grammar = _all_grammars().get(grammar_id) \
            or _BUILTIN_GRAMMARS.get("gb_l0") or {}
        entry_vector = _get_entry_vector(grammar_id)
    except Exception:
        return None
    if not isinstance(entry_vector, dict) or not entry_vector.get("gb_text"):
        return None   # legitimate stub-fallback case, no error
    enzyme = grammar.get("enzyme") if isinstance(grammar, dict) else None
    if not isinstance(enzyme, str) or enzyme not in _NEB_ENZYMES:
        return f"grammar's enzyme {enzyme!r} is not recognised"
    gb_text = entry_vector.get("gb_text") or ""
    try:
        vec_rec = _gb_text_to_record(gb_text)
    except Exception as exc:
        return f"can't parse entry vector gb_text: {exc}"
    vec_seq = str(vec_rec.seq).upper()
    vec_circular = (
        (vec_rec.annotations.get("topology", "") or "").lower()
        != "linear"
    )
    try:
        cuts = _enzyme_cuts(vec_seq, [enzyme], circular=vec_circular)
    except Exception as exc:
        return f"vector enzyme scan failed: {exc}"
    if len(cuts) < 2:
        return (f"entry vector {vec_rec.name!r} has {len(cuts)} {enzyme} "
                f"site(s) — need ≥2 to excise a dropout cassette for "
                f"IIS cloning. Pick a vector with the dropout intact.")
    return None   # cloning will succeed (digest-match or synthesis)


def _part_to_cloned_seqrecord(part: dict):
    """Build a circular SeqRecord representing a parts-bin entry's
    cloned plasmid form, ready for `LibraryPanel.add_entry`.

    Tiered cloning model:
      0. **L1+ short-circuit**. TU / MOD parts already carry the full
         assembled plasmid as `gb_text` (the parts-bin `sequence` field
         is intentionally empty for L1+ — `gb_text` is the source of
         truth, see invariant in `ConstructorModal._persist_assembly`).
         Parse and return the stored plasmid directly so a TU / MOD row
         can land in the library via Parts Bin → Save to Collection
         with all chained features intact.
      1. **IIS-digest simulation** (preferred). When the part's
         grammar has a configured entry vector,
         `_clone_part_into_entry_vector` digests the vector +
         primed amplicon at the grammar's enzyme sites and ligates
         — produces a SeqRecord equivalent to a real bench reaction.
      2. **Sequence-based splice fallback**. When tier 1 fails
         (vector lacks the IIS sites in the gb_text annotation,
         extra cuts produce no compatible dropout, etc.) we still
         search the entry vector's sequence for the part's
         `oh5...oh3` pair and splice the insert in place of the
         segment between them. The user's vector sequence is
         preserved as the backbone — the saved plasmid is the
         entry vector with the dropout cassette swapped for the
         insert.
      3. **Stub backbone** (last resort). When no entry vector is
         configured at all, or the vector doesn't contain matching
         overhangs, fall back to `_simulate_cloned_plasmid`
         (insert + overhangs + pUPD2 placeholder). Save path stays
         unbreakable.

    The record id is the part's name with non-LOCUS-safe characters
    replaced by ``_`` so Biopython's GenBank serialiser doesn't
    reject it on disk write. `clone_sim` log lines record which
    tier handled the part — grep `splicecraft.log` for diagnosis.
    """
    from Bio.Seq import Seq
    from Bio.SeqRecord import SeqRecord
    from Bio.SeqFeature import SeqFeature, FeatureLocation
    # Tier 0: L1+ short-circuit. `gb_text` IS the cloned plasmid for
    # TUs / MODs — no need to re-clone into an entry vector since the
    # Constructor already wrote the assembled plasmid into it. Linking
    # this back into the library preserves every chained TU/L0 feature.
    #
    # `_gb_text_to_record` raises ValueError on the 64 MB size cap +
    # whatever BioPython's GenBank parser surfaces on malformed input;
    # `Exception` covers both without swallowing programmer bugs
    # (TypeError / AttributeError still propagate from elsewhere in
    # the function). Matches the established pattern at
    # `_assembly_fragment_from_source` (line 23131).
    raw_gb_text = part.get("gb_text") or ""
    if raw_gb_text and _part_level(part) >= 1:
        try:
            rec = _gb_text_to_record(raw_gb_text)
        except Exception:
            _log.exception(
                "clone_sim: L1+ gb_text parse failed for %r — falling "
                "through to sequence-based tiers", part.get("name"),
            )
        else:
            # Defensive: a parsed-but-empty record is corrupt data
            # (zero-length plasmids don't biologically exist). Fall
            # through to tier 1/2/3 so the caller either gets a
            # meaningful clone or the explicit "no sequence"
            # ValueError — not a degenerate 0-bp library row.
            if _seq_len(rec) > 0:
                return rec
            _log.warning(
                "clone_sim: L1+ gb_text for %r parses to a 0-bp "
                "record — falling through to sequence-based tiers",
                part.get("name"),
            )
    insert = part.get("sequence", "") or ""
    if not insert:
        raise ValueError("Part has no sequence — cannot build SeqRecord.")

    grammar_id = part.get("grammar") or "gb_l0"
    try:
        grammar = _all_grammars().get(grammar_id) \
            or _BUILTIN_GRAMMARS.get("gb_l0") or {}
        entry_vector = _get_entry_vector(grammar_id)
    except Exception:
        grammar, entry_vector = {}, None
    if isinstance(entry_vector, dict) and entry_vector.get("gb_text"):
        # Tier 1: full IIS simulation
        cloned = _clone_part_into_entry_vector(part, entry_vector, grammar)
        if cloned is not None:
            return cloned
        # Tier 2: sequence-based overhang splice (refuses when
        # vector's IIS cuts conflict with the part's overhangs).
        cloned = _splice_part_into_vector_by_overhang(
            entry_vector, part, grammar=grammar,
        )
        if cloned is not None:
            return cloned

    # Stub backbone fallback — original behaviour pre-2026-05-07.
    oh5 = part.get("oh5", "") or ""
    oh3 = part.get("oh3", "") or ""
    seq = _simulate_cloned_plasmid(insert, oh5, oh3)

    raw_name = part.get("name") or "part"
    safe_id  = re.sub(r"[^A-Za-z0-9_]", "_", raw_name) or "part"

    rec = SeqRecord(Seq(seq), id=safe_id, name=safe_id,
                     description=f"Cloned part: {raw_name}")
    rec.annotations["molecule_type"] = "DNA"
    rec.annotations["topology"]      = "circular"

    # Insert spans `[len(oh5), len(oh5) + len(insert))` in the linearised
    # cloned plasmid (oh5 sits at the 5' end of the saved sequence).
    insert_start = len(oh5)
    insert_end   = insert_start + len(insert)
    ftype = _GB_PART_TYPE_TO_INSDC.get(part.get("type", ""), "misc_feature")
    note_bits = [f"GB part type: {part.get('type', '?')}"]
    if part.get("position"):
        note_bits.append(f"position {part['position']}")
    if oh5 or oh3:
        note_bits.append(f"5'OH {oh5} / 3'OH {oh3}")
    if part.get("backbone"):
        note_bits.append(f"backbone {part['backbone']}")
    if part.get("marker"):
        note_bits.append(f"selection {part['marker']}")
    rec.features.append(SeqFeature(
        FeatureLocation(insert_start, insert_end, strand=1),
        type=ftype,
        qualifiers={
            "label": [raw_name],
            "note":  ["; ".join(note_bits)],
        },
    ))
    return rec


def _pick_binding_region(seq: str, target_tm: float = 60.0,
                         min_len: int = 18, max_len: int = 25) -> tuple[str, float]:
    """Return the prefix of `seq` (length min_len..max_len) whose Tm is
    closest to `target_tm`. Uses primer3-py's SantaLucia Tm calculation.

    Returns (binding_sequence, tm). If primer3-py is not installed, falls
    back to a crude 2+4 rule estimate.
    """
    # Type the dispatcher as a `(str) -> float` Callable so pyright can
    # accept both primer3.calc_tm (which has a richly-typed signature
    # with extra defaulted kwargs) and the fallback approximation
    # below. Using two separate names avoids the param-name mismatch
    # pyright flags when a `def _tm(s)` re-defines the same binding.
    def _tm_fallback(s: str) -> float:
        gc = sum(1 for c in s.upper() if c in "GC")
        at = sum(1 for c in s.upper() if c in "AT")
        return float(2 * at + 4 * gc)
    _tm: "_Callable[..., float]"
    try:
        import primer3
        _tm = primer3.calc_tm
    except ImportError:
        _tm = _tm_fallback

    # Defensive init: if the caller forgot the len(seq) >= min_len guard,
    # the loop below won't execute and we'd otherwise return Tm=0 with a
    # too-short binding. Compute Tm for whatever is there so downstream
    # validation (low Tm, short primer) still trips honestly.
    best_seq = seq[:max(min_len, 1)]
    best_tm  = _tm(best_seq) if best_seq else 0.0
    best_diff = float("inf")
    for n in range(min_len, min(max_len + 1, len(seq) + 1)):
        candidate = seq[:n]
        tm = _tm(candidate)
        diff = abs(tm - target_tm)
        if diff < best_diff:
            best_seq, best_tm, best_diff = candidate, tm, diff
    return best_seq, best_tm


_GB_DOMESTICATION_FORBIDDEN: dict[str, str] = {
    # Esp3I self-cuts during L0 domestication; BsaI would re-cut during any
    # downstream L1 assembly — both must be absent from the final part.
    "BsaI":  "GGTCTC",
    "Esp3I": "CGTCTC",
}


# ── Modular cloning grammars (Golden Braid, MoClo, custom) ─────────────────────
#
# A "grammar" parameterises every Type IIS-aware tool in the app: the
# Parts Bin (which catalog + which user parts are visible), the
# Domesticator (which positions/overhangs/enzyme/forbidden-sites apply
# to primer design), and downstream constructors. Each grammar carries:
#
#   - **enzyme + site + spacer + pad** — the Type IIS recognition + the
#     primer-tail bookkeeping bytes (`pad + site + spacer + oh5 + …`).
#   - **forbidden_sites** — every Type IIS recognition that must be
#     scrubbed from a domesticated part. For Golden Braid L0 that's
#     Esp3I (current step) + BsaI (next step); for MoClo Plant it's
#     BsaI (current) + BpiI (next). The codon-fix repair pipeline
#     iterates over this dict.
#   - **positions** — ordered list of `{name, type, oh5, oh3, color}`
#     dicts. The `type` is the user-facing part-shape label (e.g.
#     "Promoter", "CDS-NS"), shared across catalog rows so a single
#     position lookup powers the Domesticator's position dropdown,
#     the parts table coloring, and the overhang-table display.
#   - **coding_types** — subset of position types that have a reading
#     frame (so the codon-fix repair pipeline can swap synonymous
#     codons to remove an internal forbidden site).
#   - **type_to_insdc** — Title-cased part type → INSDC feature_type
#     for the Save-As-Feature flow. Lossy mappings (CDS-NS → CDS) are
#     covered in the description string.
#   - **catalog** — built-in reference parts as
#     ``(name, type, position_label, oh5, oh3, backbone, marker)``
#     tuples. Empty for grammars that ship without a reference set.
#   - **editable** — built-ins are read-only; user-defined grammars
#     are loaded from `cloning_grammars.json` and can be edited in
#     `GrammarEditorModal`.
#
# The ID space is flat: built-in IDs start with their grammar family
# (``gb_l0``, ``moclo_plant``); custom-grammar IDs are slugged from
# user-supplied names (``custom_my_assembly``, etc.) at creation.

_BUILTIN_GRAMMARS: dict[str, dict] = {
    "gb_l0": {
        "id":              "gb_l0",
        "name":            "Golden Braid L0",
        "enzyme":          _GB_L0_ENZYME_NAME,
        # Iterative GB cycle: L0 → L1 cuts with Esp3I (`enzyme`); L1 →
        # L2 cuts with BsaI (`level_up_enzyme`); L2 → L3 wraps around
        # to Esp3I again (parity on source level — see
        # `_enzyme_for_level_up`). The two enzymes alternate each
        # level so the assembled product survives the next cut.
        "level_up_enzyme": "BsaI",
        "site":            _GB_L0_ENZYME_SITE,
        "spacer":          _GB_SPACER,
        "pad":             _GB_PAD,
        "forbidden_sites": dict(_GB_DOMESTICATION_FORBIDDEN),
        "positions": [
            {"name": pos, "type": ptype, "oh5": oh5, "oh3": oh3,
             "color": _GB_TYPE_COLORS.get(ptype, "white")}
            for ptype, (pos, oh5, oh3) in _GB_POSITIONS.items()
        ],
        "coding_types":    sorted(_GB_CODING_PART_TYPES),
        "type_to_insdc":   dict(_GB_PART_TYPE_TO_INSDC),
        "catalog":         list(_GB_L0_PARTS),
        "editable":        False,
    },
    # Plant MoClo (Weber et al. 2011, Engler et al. 2014). BsaI at L0,
    # BpiI/BbsI at L1 — both scrubbed during domestication. Ships
    # without a built-in catalog because Plant MoClo's reference parts
    # depend heavily on the user's host system; users seed via "New
    # Part" or by duplicating into a custom grammar.
    "moclo_plant": {
        "id":              "moclo_plant",
        "name":            "MoClo Plant (Weber 2011)",
        "enzyme":          "BsaI",
        "level_up_enzyme": "BpiI",
        "site":            "GGTCTC",
        "spacer":          "A",
        "pad":             "GCGC",
        # BsaI for the current L0 cut; BpiI (= BbsI) for the next-level
        # MoClo assembly, which uses a different Type IIS site so the
        # L0 part survives the L1 reaction without re-cutting.
        "forbidden_sites": {"BsaI": "GGTCTC", "BpiI": "GAAGAC"},
        "positions": [
            {"name": "Pos 1", "type": "Promoter",   "oh5": "GGAG", "oh3": "AATG", "color": "green"},
            {"name": "Pos 2", "type": "5' UTR",     "oh5": "AATG", "oh3": "AGGT", "color": "cyan"},
            {"name": "Pos 3", "type": "CDS",        "oh5": "AGGT", "oh3": "GCTT", "color": "yellow"},
            {"name": "Pos 4", "type": "C-tag",      "oh5": "GCTT", "oh3": "GGTA", "color": "magenta"},
            {"name": "Pos 5", "type": "Terminator", "oh5": "GGTA", "oh3": "CGCT", "color": "blue"},
        ],
        "coding_types":    ["CDS", "C-tag"],
        "type_to_insdc": {
            "Promoter":   "promoter",
            "5' UTR":     "5'UTR",
            "CDS":        "CDS",
            "C-tag":      "CDS",
            "Terminator": "terminator",
        },
        "catalog":         [],
        "editable":        False,
    },
}


# Custom grammars persist to `cloning_grammars.json` (envelope schema,
# sacred invariant #7). Schema per entry mirrors the built-in dict
# above; ``editable`` is implicitly True for everything in this file.
_GRAMMARS_FILE = _DATA_DIR / "cloning_grammars.json"
_grammars_cache: "list | None" = None


def _load_custom_grammars() -> list[dict]:
    global _grammars_cache
    if _grammars_cache is not None:
        return _typed_clone(_grammars_cache)
    entries, warning = _safe_load_json(_GRAMMARS_FILE, "Cloning grammars")
    if warning:
        _log.warning(warning)
    entries = [e for e in entries if isinstance(e, dict) and isinstance(e.get("id"), str)]
    _grammars_cache = entries
    return _typed_clone(_grammars_cache)


def _save_custom_grammars(entries: list[dict]) -> None:
    global _grammars_cache
    with _cache_lock:
        _safe_save_json(_GRAMMARS_FILE, entries, "Cloning grammars")
        _grammars_cache = _typed_clone(entries)
    # Invalidate the assembly-fragment digest cache: a grammar enzyme
    # / level_up_enzyme change shifts which fragment a TU/MOD
    # releases, so the cached overhangs from the previous grammar
    # must not survive into the next palette refresh.
    _clear_assembly_fragment_cache()


def _all_grammars() -> dict[str, dict]:
    """Return all grammars (built-in + user-defined) keyed by id.

    Built-ins come first; user-defined grammars override builtin IDs
    if they ever collide (defensive — UI prevents this on save). The
    returned dicts are independent copies, so callers may mutate them
    without poisoning the cache.
    """
    out: dict[str, dict] = {gid: deepcopy(g) for gid, g in _BUILTIN_GRAMMARS.items()}
    for g in _load_custom_grammars():
        gid = g.get("id")
        if isinstance(gid, str):
            # Custom grammars are always editable regardless of what
            # the JSON file says — stops a mis-flagged file from
            # locking the user out of their own definitions.
            g = dict(g)
            g["editable"] = True
            out[gid] = g
    return out


def _get_active_grammar() -> dict:
    """Return the currently-active grammar dict. Falls back to GB L0
    if the persisted ``active_grammar`` id no longer resolves (e.g.,
    a custom grammar was deleted while still selected)."""
    grammars = _all_grammars()
    gid = _get_setting("active_grammar", "gb_l0")
    if gid in grammars:
        return grammars[gid]
    # Recover gracefully — flip the setting back to gb_l0 so we don't
    # keep falling back forever.
    _set_setting("active_grammar", "gb_l0")
    return grammars["gb_l0"]


# ── Per-grammar entry-vector storage ────────────────────────────────
# Each cloning grammar (Golden Braid L0, MoClo, custom) has a
# canonical destination plasmid — pUPD2 for GB L0, pAGM4673 for
# MoClo L1, etc. The user picks one once per grammar via
# `GrammarEditorModal`; the choice is stored here keyed by grammar
# id and surfaced (with a Change button) at the top of the
# ConstructorModal so it's confirmed before every assembly run.
#
# Storage embeds the FULL gb_text rather than a library reference
# so the choice is resilient: renaming or deleting the source
# plasmid in the library doesn't orphan the grammar's vector.
# Schema per entry:
#   {
#     "grammar_id":  str,       # "gb_l0" / custom grammar id
#     "name":        str,       # display name (e.g. "pUPD2")
#     "size":        int,       # bp; 0 if unknown
#     "source":      str,       # "library:<lib_id>" | "file:<path>"
#     "gb_text":     str,       # GenBank text body
#   }
_ENTRY_VECTORS_FILE = _DATA_DIR / "entry_vectors.json"
_entry_vectors_cache: "list | None" = None


def _load_entry_vectors() -> list[dict]:
    global _entry_vectors_cache
    if _entry_vectors_cache is not None:
        return _typed_clone(_entry_vectors_cache)
    entries, warning = _safe_load_json(_ENTRY_VECTORS_FILE,
                                         "Entry vectors")
    if warning:
        _log.warning(warning)
    entries = [e for e in entries
                 if isinstance(e, dict)
                 and isinstance(e.get("grammar_id"), str)]
    _entry_vectors_cache = entries
    return _typed_clone(_entry_vectors_cache)


def _save_entry_vectors(entries: list[dict]) -> None:
    global _entry_vectors_cache
    with _cache_lock:
        _safe_save_json(_ENTRY_VECTORS_FILE, entries, "Entry vectors")
        _entry_vectors_cache = _typed_clone(entries)
    # Drop the digest cache built around the previous EV list — old
    # entries hanging on after a reconfigure waste cache slots and,
    # for users who rotate vectors often (testing custom grammars),
    # would push valid hits out via the FIFO eviction. The cache is
    # defined later in the file; resolve via `globals()` so this
    # cross-reference doesn't depend on declaration order.
    cache = globals().get("_VECTOR_MATCH_CACHE")
    if isinstance(cache, dict):
        cache.clear()
    # Same hygiene for the per-acceptor TU-boundary cache that backs
    # `_classify_part_from_plasmid`'s third-pass match: a reconfigured
    # EV changes which stuffer overhangs we'd hit, so the previous
    # entries must not survive the save.
    acceptor_cache = globals().get("_ACCEPTOR_TU_PAIRS_CACHE")
    if isinstance(acceptor_cache, dict):
        acceptor_cache.clear()


def _get_entry_vector(
    grammar_id: str, role: str = "",
) -> "dict | None":
    """Return the entry-vector dict for ``(grammar_id, role)``, or
    None if none has been assigned yet.

    `role` is the per-grammar slot — for Golden Braid the Constructor
    has four roles (``Alpha1``, ``Alpha2``, ``Omega1``, ``Omega2``)
    so a single grammar carries multiple L1 acceptors. The empty
    role (default) is the singleton L0 entry vector used by the
    Domesticator / `_clone_part_into_entry_vector` workflow — kept
    backward-compat with pre-2026-05-07 entry_vectors.json files
    where every entry has no `role` field.
    """
    if not isinstance(grammar_id, str) or not grammar_id:
        return None
    role = role or ""
    for e in _load_entry_vectors():
        if e.get("grammar_id") == grammar_id and (e.get("role") or "") == role:
            return e
    return None


def _set_entry_vector(
    grammar_id: str, vector: "dict | None", role: str = "",
) -> None:
    """Replace (or remove, with ``vector=None``) the entry vector
    bound to ``(grammar_id, role)``. Persists via `_safe_save_json`.

    Only the matching ``(grammar_id, role)`` entry is replaced —
    other roles for the same grammar (e.g. Alpha2 / Omega1 / Omega2
    when setting Alpha1) survive untouched.

    Sweep #10 (2026-05-20): full load-modify-save sequence runs under
    `_cache_lock` so concurrent rapid clicks across grammar tabs (or
    `_auto_bind_entry_vectors_from_entries` looping per-role) can't
    lose updates via classic RMW racing. RLock allows re-entry from
    the nested `_save_entry_vectors` lock acquisition.
    """
    if not isinstance(grammar_id, str) or not grammar_id:
        return
    role = role or ""
    with _cache_lock:
        entries = [
            e for e in _load_entry_vectors()
            if not (
                e.get("grammar_id") == grammar_id
                and (e.get("role") or "") == role
            )
        ]
        if vector is not None:
            v = dict(vector)
            v["grammar_id"] = grammar_id
            v["role"]       = role
            entries.append(v)
        _save_entry_vectors(entries)


def _set_entry_vectors_batch(
    updates: "list[tuple[str, str, dict | None]]",
) -> int:
    """Apply N entry-vector bindings under a SINGLE `_cache_lock`
    acquire + single `_save_entry_vectors` call.

    Sweep #11 (2026-05-20): the per-role auto-bind loop in
    `_auto_bind_entry_vectors_from_entries` previously called
    `_set_entry_vector` N times, each acquiring `_cache_lock`,
    re-reading the file, mutating, and writing — N round-trips
    through `_safe_save_json` (each with `.bak` + fsync). A 5-role
    × 3-grammar bulk import yielded 15 separate disk writes,
    contending against any concurrent save.

    Each update tuple is `(grammar_id, role, payload)`; passing
    ``payload=None`` removes the binding. Returns the number of
    bindings that actually changed (added / removed / replaced).
    Invalid `grammar_id` tuples are silently skipped — matches the
    no-op contract of `_set_entry_vector`.
    """
    if not updates:
        return 0
    with _cache_lock:
        entries = _load_entry_vectors()
        changed = 0
        for gid, role, vector in updates:
            if not isinstance(gid, str) or not gid:
                continue
            role = role or ""
            before = len(entries)
            entries = [
                e for e in entries
                if not (
                    e.get("grammar_id") == gid
                    and (e.get("role") or "") == role
                )
            ]
            removed_one = (len(entries) < before)
            if vector is not None:
                v = dict(vector)
                v["grammar_id"] = gid
                v["role"]       = role
                entries.append(v)
                changed += 1
            elif removed_one:
                changed += 1
        if changed:
            _save_entry_vectors(entries)
    return changed


def _clear_entry_vectors_for_grammar(grammar_id: str) -> int:
    """Drop every entry-vector binding for ``grammar_id``, regardless
    of role. Used by grammar-delete flows so a grammar with multiple
    role bindings (Constructor's Alpha1/Alpha2/Omega1/Omega2) doesn't
    leave orphan rows in entry_vectors.json that would silently come
    back to life if a future custom grammar slugs to the same id.

    Returns the number of bindings removed; 0 when nothing matched.
    No-op for empty grammar_id (defensive — callers can pass a
    user-typed value without pre-checking).

    Sweep #10 (2026-05-20): RMW under `_cache_lock`.
    """
    if not isinstance(grammar_id, str) or not grammar_id:
        return 0
    with _cache_lock:
        entries = _load_entry_vectors()
        kept = [e for e in entries if e.get("grammar_id") != grammar_id]
        n_dropped = len(entries) - len(kept)
        if n_dropped > 0:
            _save_entry_vectors(kept)
    return n_dropped


# Lowercase keyword → display name. Used by `_detect_selection_marker`
# to pull a sensible marker label out of an entry-vector's GenBank
# annotations. Order matters: longer / more specific keywords come
# first so a feature labelled `bla(AmpR)` matches "ampr" rather than
# "bla". Nothing here is a hard contract — the user can always
# overwrite the marker on a saved part if our detection picks the
# wrong one.
_SELECTION_MARKER_KEYWORDS: "tuple[tuple[str, str], ...]" = (
    ("ampicillin",     "Ampicillin"),
    ("ampr",           "Ampicillin"),
    ("kanamycin",      "Kanamycin"),
    ("kanr",           "Kanamycin"),
    ("neomycin",       "Kanamycin"),
    ("neor",           "Kanamycin"),
    ("spectinomycin",  "Spectinomycin"),
    ("specr",          "Spectinomycin"),
    ("aada",           "Spectinomycin"),
    ("smr",            "Spectinomycin"),
    ("chloramphenicol", "Chloramphenicol"),
    ("cmr",            "Chloramphenicol"),
    ("cat",            "Chloramphenicol"),
    ("tetracycline",   "Tetracycline"),
    ("tetr",           "Tetracycline"),
    ("hygromycin",     "Hygromycin"),
    ("hygr",           "Hygromycin"),
    ("zeocin",         "Zeocin"),
    ("zeor",           "Zeocin"),
    ("gentamicin",     "Gentamicin"),
    ("gmr",            "Gentamicin"),
    ("erythromycin",   "Erythromycin"),
    ("ermr",           "Erythromycin"),
    ("bla",            "Ampicillin"),   # last — matches "bla" alone
)


def _detect_selection_marker(gb_text: str) -> "str | None":
    """Scan a plasmid's GenBank text for a feature whose
    label / gene / product / note contains one of
    ``_SELECTION_MARKER_KEYWORDS`` and return the matching display
    name (e.g. ``"Kanamycin"``). Returns ``None`` when no recognised
    marker is found. Used by the Domesticator's part-save path so
    the saved `marker` field reflects the user's configured entry
    vector instead of the historical pUPD2 / Spectinomycin defaults.

    Conservative on parse failure: malformed or empty `gb_text`
    yields ``None`` so the caller can fall back to a placeholder
    rather than asserting a marker we can't actually verify.
    """
    if not isinstance(gb_text, str) or not gb_text.strip():
        return None
    try:
        rec = _gb_text_to_record(gb_text)
    except Exception:
        return None
    qual_keys = ("label", "gene", "product", "note", "standard_name")
    for feat in getattr(rec, "features", []) or []:
        bag: list[str] = []
        for k in qual_keys:
            vals = feat.qualifiers.get(k) if hasattr(feat, "qualifiers") \
                else None
            if isinstance(vals, list):
                bag.extend(str(v) for v in vals)
            elif isinstance(vals, str):
                bag.append(vals)
        # Also include the feature type so a CDS labelled just `cat`
        # surfaces — qualifiers sometimes lack the gene/product line.
        for s in bag:
            low = s.lower()
            for kw, display in _SELECTION_MARKER_KEYWORDS:
                if kw in low:
                    return display
    return None


# Per-call cache for entry-vector vector-half top_seqs, keyed by
# (gb_text, enzyme). Re-using the same `_check_vector_match` helper
# from a single classification call typically hits N entry vectors;
# without the cache, each call to the helper re-parses + re-digests
# every EV from scratch. The cache is a free-floating module-level
# dict (not a method-level @lru_cache because the EV gb_text isn't
# hashable) and is bounded by `_VECTOR_MATCH_CACHE_MAX` to absorb
# pathological cases without memory growth. `_save_entry_vectors`
# clears the cache so a reconfigure doesn't leave stale entries
# crowding the cap.
#
# Cap = 64: covers a typical 2-grammar × 4-role × 2-enzyme footprint
# (gb_l0 Alpha1/Alpha2/Omega1/Omega2 + moclo_plant Acceptor1/Acceptor2
# = 12 base entries; with custom grammars + repeated enzyme passes the
# active set is well under 32, with margin for FIFO churn). Bumped
# from 32 in 0.7.7.2 after a user with many custom grammars hit
# steady-state thrashing.
_VECTOR_MATCH_CACHE: "dict[tuple, str | None]" = {}
_VECTOR_MATCH_CACHE_MAX = 64


def _vector_half_top_seq(ev_gb: str, enzyme: str) -> "str | None":
    """Cached helper: return the entry vector's vector-half top_seq
    after digesting with ``enzyme``. Returns None on parse / digest
    failure or when the EV is non-circular (digest needs a ring).
    Cache is keyed by ``(ev_gb, enzyme)`` so a saved EV's digest is
    re-used across `_check_vector_match` calls within a classification
    run.

    Non-circular EVs are explicitly skipped (returns None) — without
    the topology check, a linearised EV file would dispatch through
    `_excise_fragment_pair(circular=True)` and produce nonsense
    fragments. Better to fail closed than report a phantom match.
    """
    key = (ev_gb, enzyme)
    if key in _VECTOR_MATCH_CACHE:
        return _VECTOR_MATCH_CACHE[key]
    result: "str | None" = None
    try:
        ev_rec = _gb_text_to_record(ev_gb)
        topology = (
            getattr(ev_rec, "annotations", {}) or {}
        ).get("topology", "")
        if str(topology).lower() != "circular":
            # Refuse linearised entry vectors — `_excise_fragment_pair`
            # with `circular=True` on a linear sequence misreports
            # cuts at the joined ends.
            _log.debug(
                "_vector_half_top_seq: skipping non-circular EV "
                "(topology=%r)", topology,
            )
        else:
            ev_seq = str(ev_rec.seq).upper()
            ev_frags, ev_err = _excise_fragment_pair(
                ev_seq, [enzyme], circular=True,
            )
            if ev_err is None and len(ev_frags) == 2:
                ev_vector_half = max(
                    ev_frags,
                    key=lambda f: len(f.get("top_seq") or ""),
                )
                result = (
                    ev_vector_half.get("top_seq") or ""
                ).upper() or None
    except Exception:
        _log.debug(
            "_vector_half_top_seq: digest failed for enzyme %r", enzyme,
        )
    # Bounded LRU-ish: drop one arbitrary entry when over cap. Insertion
    # order eviction (Python 3.7+ dict preserves insertion order) gives
    # us FIFO behaviour without an OrderedDict import.
    if len(_VECTOR_MATCH_CACHE) >= _VECTOR_MATCH_CACHE_MAX:
        try:
            _VECTOR_MATCH_CACHE.pop(next(iter(_VECTOR_MATCH_CACHE)))
        except StopIteration:
            pass
    _VECTOR_MATCH_CACHE[key] = result
    return result


def _check_vector_match(
    gid: str, enzyme: str, user_vector_frag: dict,
) -> "dict | None":
    """Compare the user's vector half (the larger digest fragment)
    against every entry vector configured for grammar ``gid``. Returns
    ``{role, name, matches: True}`` for the first vector half that's
    rotationally identical (in either orientation), or ``None`` when
    no entry vector is configured for ``gid`` / no match is found.

    The comparison uses the same ``enzyme`` that produced the user's
    digest so the two vector halves are directly comparable. Rotation-
    invariance is handled by checking whether the user's top_seq is a
    substring of the entry vector's doubled top_seq — fragments from
    rotationally equivalent rings have the same content but may start
    at different positions in the linearised representation. The same
    test is run against the EV's reverse-complement-doubled seq so an
    RC-saved user plasmid (the same biological ring written with the
    other strand on top) still matches.

    Used by `_classify_part_from_plasmid` to surface "this plasmid was
    cloned into your configured Alpha1 entry vector" so Load Part can
    confirm the user's expected destination matches before saving.
    """
    user_vec_seq = (user_vector_frag.get("top_seq") or "").upper()
    if not user_vec_seq:
        return None
    for ev in _load_entry_vectors():
        if ev.get("grammar_id") != gid:
            continue
        ev_gb = ev.get("gb_text") or ""
        if not ev_gb:
            continue
        ev_vec_seq = _vector_half_top_seq(ev_gb, enzyme)
        if not ev_vec_seq or len(user_vec_seq) != len(ev_vec_seq):
            continue
        if user_vec_seq in (ev_vec_seq + ev_vec_seq):
            return {
                "role":    ev.get("role") or "",
                "name":    ev.get("name", "?"),
                "matches": True,
            }
        # Reverse-strand orientation: the user may have saved the
        # plasmid with the other strand on top, which makes the
        # digest's top_seq the RC of the canonical vector half. Try
        # the RC-doubled form too — same rotation-invariant check.
        try:
            rc_doubled = _rc(ev_vec_seq)
            if rc_doubled and user_vec_seq in (rc_doubled + rc_doubled):
                return {
                    "role":    ev.get("role") or "",
                    "name":    ev.get("name", "?"),
                    "matches": True,
                }
        except Exception:
            _log.debug(
                "_check_vector_match: RC fallback failed for ev %r",
                ev.get("name"),
            )
            continue
    return None


# Per-(grammar_id, enzyme) cache of acceptor-stuffer overhang pairs.
# Invalidated by `_save_entry_vectors` so a reconfigured EV doesn't
# leave stale entries behind. Keyed by str → list of tuples so the
# values are independently copy-able when returned to callers (we
# return a `list(...)` so callers can mutate without poisoning).
_ACCEPTOR_TU_PAIRS_CACHE: "dict[tuple[str, str], list[tuple[str, str, str, str]]]" = {}


def _grammar_acceptor_tu_pairs(
    grammar_id: str, enzyme: str,
) -> "list[tuple[str, str, str, str]]":
    """Return ``[(role, ev_name, oh5, oh3), ...]`` — the stuffer's
    overhang pair released by digesting each configured entry vector
    for ``grammar_id`` with ``enzyme``.

    The L0 → L1 entry vector for Golden Braid has four canonical
    roles (Alpha1 / Alpha2 / Omega1 / Omega2), each receiving a TU
    in a different orientation. When BsaI digests the assembled TU
    plasmid (a TU INSIDE one of those acceptors), the released
    insert carries that acceptor's specific overhang pair — which
    is the SAME pair as the stuffer's overhangs in the empty
    acceptor itself. Pre-2026-05-13 the classifier only knew the
    canonical (Promoter.oh5, Terminator.oh3) pair via
    `_grammar_tu_overhangs`, so a TU in Alpha2 / Omega1 / Omega2
    silently failed to classify (the bug Cory hit on MAV-25 in
    alpha-2).

    Singleton entry vectors (role == "") are skipped — those are L0
    acceptors (pUPD2 et al.), not TU acceptors, and the L0 position
    table check upstream covers them.

    Result is cached per ``(grammar_id, enzyme)`` and invalidated by
    `_save_entry_vectors`. A multi-select Load Part batch that
    classifies 50 plasmids against 2 grammars × 2 enzymes was
    re-digesting every configured EV 200× without this cache.

    Failures (no gb_text, parse error, digest yields ≠ 2 fragments)
    are logged at warning level so a misconfigured EV surfaces in
    the diagnostic bundle — the user otherwise sees their TU silently
    fall through to None classification with no hint why.
    """
    cache_key = (grammar_id, enzyme)
    cached = _ACCEPTOR_TU_PAIRS_CACHE.get(cache_key)
    if cached is not None:
        return list(cached)
    out: "list[tuple[str, str, str, str]]" = []
    for ev in _load_entry_vectors():
        if ev.get("grammar_id") != grammar_id:
            continue
        role = ev.get("role") or ""
        if not role:
            continue   # singleton L0 vector — not a TU acceptor
        ev_gb = ev.get("gb_text") or ""
        ev_name = ev.get("name") or "?"
        if not ev_gb:
            _log.warning(
                "_grammar_acceptor_tu_pairs: entry vector %r "
                "(role=%r, grammar=%r) has no gb_text — skipping",
                ev_name, role, grammar_id,
            )
            continue
        try:
            record = _gb_text_to_record(ev_gb)
            ev_seq = str(getattr(record, "seq", "") or "").upper()
            if not ev_seq:
                _log.warning(
                    "_grammar_acceptor_tu_pairs: entry vector %r "
                    "parsed to empty sequence — skipping",
                    ev_name,
                )
                continue
            frags, err = _excise_fragment_pair(
                ev_seq, [enzyme], circular=True,
            )
        except Exception:
            _log.exception(
                "_grammar_acceptor_tu_pairs: digest failed for "
                "ev=%r role=%r enzyme=%r", ev_name, role, enzyme,
            )
            continue
        if err is not None or len(frags) != 2:
            _log.info(
                "_grammar_acceptor_tu_pairs: ev=%r role=%r digest "
                "with %r produced %d fragment(s) (err=%r) — skipped",
                ev_name, role, enzyme, len(frags), err,
            )
            continue
        # Stuffer = the smaller fragment (the placeholder lacZα or
        # ccdB cassette that gets replaced by the assembled TU). Its
        # 5' / 3' overhangs ARE the TU-boundary overhangs for this
        # acceptor.
        insert = min(frags, key=lambda f: len(f.get("top_seq", "")))
        oh5 = (insert.get("left")  or {}).get(
            "overhang_seq", "",
        ).upper()
        oh3 = (insert.get("right") or {}).get(
            "overhang_seq", "",
        ).upper()
        if oh5 and oh3:
            out.append((role, ev_name, oh5, oh3))
    _ACCEPTOR_TU_PAIRS_CACHE[cache_key] = list(out)
    return out


def _classify_part_from_plasmid(
    seq: str,
    *,
    circular: bool,
    features: "list[dict] | None" = None,
) -> "dict | None":
    """Identify which cloning grammar + position + level a circular
    plasmid holds, by trying each grammar's primary and secondary
    Type IIS enzymes and matching the released fragment's overhangs
    against either the grammar's L0 position table or its TU boundary
    overhangs (`_grammar_tu_overhangs`).

    SACRED INVARIANT: the (oh5, oh3) overhang pair released by the
    digest is the **only** input used to determine position type.
    The classifier never overrides this from feature labels, plasmid
    name, source filename, or any other heuristic — the user's
    biological molecule has ONE legal position per overhang pair, so
    the lookup is unambiguous and the code path must reflect that.
    Callers can re-tag manually via the Parts Bin Edit modal if they
    really need to, but the classifier itself stays mechanical.

    Detection cases (per grammar, in registry order, for each
    enzyme; **both fragments** are tried in each pass so a library
    entry without backbone-marker annotations still classifies
    correctly when the insert outgrew the backbone):

      * Either fragment's overhangs match an L0 position → ``level=0``
        (L0 part, regardless of which side of the cycle produced it).
      * Either fragment's overhangs match the canonical TU boundary
        OR a configured entry vector's stuffer pair → ``level=1`` (TU).

    Pre-2026-05-13 the classifier picked a single "insert" fragment
    via `_pick_insert_fragment` and inferred level from enzyme
    parity ("primary release ⇒ MOD"). Both heuristics broke for
    real-world plasmids:

      * `_pick_insert_fragment` falls through to "smallest fragment"
        when no `rep_origin`/`selection_marker` features are present;
        for a TU whose body is larger than its alpha backbone
        (common for any cassette ~2 kbp+) the backbone half got
        picked as the "insert" and its mirrored overhangs matched
        nothing. MAV 26 in the EDEN collection: 3250 bp body with
        the correct (GGAG, GTCA) overhangs, 1850 bp backbone with
        the mirrored (GTCA, GGAG) — the body was discarded.

      * Enzyme parity assumed the splicecraft convention
        (Esp3I = primary = L0 release, BsaI = secondary = L1
        release). The actual pDGB1 / GB 2.0 convention used by
        Sarrion-Perdigones 2013 and the user's EDEN collection has
        these REVERSED (BsaI = L0 release from pUPD2, Esp3I = L1
        release from α-vectors). Under that convention, the user's
        TUs were being mis-classified as MOD (level=2).

    Auto MOD (level=2) detection from overhangs alone is unreliable
    across both conventions — a fragment with TU-boundary overhangs
    could be a TU or a MOD depending on which enzyme cycle the lab
    uses, and we can't tell from the overhangs alone. TUs that are
    actually MODs in the user's lab can be re-tagged via the
    Parts Bin Edit modal.

    Returns ``None`` when no grammar gives a clean (exactly 2-fragment)
    digest with recognised overhangs. Otherwise returns
    ``{grammar_id, grammar_name, level, position, insert, vector,
       release_enzyme, entry_vector}``.

    Linear records skip the digest — a linear "part" can't be cleanly
    excised, and the overhangs in the .gb annotation are the source
    of truth in that case.
    """
    if not seq or not circular:
        return None
    grammars = _all_grammars()
    for gid, grammar in grammars.items():
        primary   = grammar.get("enzyme")
        secondary = (grammar.get("level_up_enzyme")
                     or grammar.get("enzyme"))
        for enzyme_role, enzyme in (
            ("primary",   primary),
            ("secondary", secondary),
        ):
            if not isinstance(enzyme, str) or not enzyme:
                continue
            # Skip the secondary pass entirely when it's the same as
            # the primary (custom grammar that omits `level_up_enzyme`)
            # — we'd just re-run the same digest with the same outcome.
            if enzyme_role == "secondary" and enzyme == primary:
                continue
            try:
                frags, err = _excise_fragment_pair(
                    seq, [enzyme], circular=True,
                    features=features,
                    source_label=grammar.get("name", gid),
                )
            except Exception:
                _log.exception(
                    "_classify_part_from_plasmid: %s digest failed for %s",
                    enzyme_role, gid,
                )
                continue
            if err is not None or len(frags) != 2:
                continue
            # Try BOTH fragments — sized assumptions about which half
            # is the "insert" break when the user's library entries
            # don't carry rep_origin/selection-marker annotations
            # AND the assembled cassette is larger than its carrier
            # backbone (MAV 26 family, 2026-05-13). For each fragment,
            # match its overhangs against the L0 position table, the
            # canonical TU boundary, and the per-acceptor stuffer
            # pairs; the FIRST match wins, with the other fragment
            # becoming the vector half by elimination.
            for insert_idx, insert in enumerate(frags):
                vector = frags[1 - insert_idx]
                oh5 = (insert.get("left")  or {}).get(
                    "overhang_seq", "",
                ).upper()
                oh3 = (insert.get("right") or {}).get(
                    "overhang_seq", "",
                ).upper()
                if not oh5 or not oh3:
                    continue
                # First check: the L0 position table. Both pre- and
                # post-cloning L0 parts land here — only the enzyme
                # differs depending on the lab's GB convention.
                for pos in (grammar.get("positions") or []):
                    pos_oh5 = str(pos.get("oh5", "")).upper()
                    pos_oh3 = str(pos.get("oh3", "")).upper()
                    if pos_oh5 == oh5 and pos_oh3 == oh3:
                        return {
                            "grammar_id":     gid,
                            "grammar_name":   grammar.get("name", gid),
                            "level":          0,
                            "position":       dict(pos),
                            "insert":         insert,
                            "vector":         vector,
                            "release_enzyme": enzyme,
                            "entry_vector":   _check_vector_match(
                                gid, enzyme, vector,
                            ),
                        }
                # Second check: canonical TU boundary overhangs
                # (Pos 1's oh5 + last position's oh3). Matches a TU
                # assembled into the canonical L1 acceptor — the
                # orientation that lines up with the grammar's L0
                # positions.
                tu_start, tu_end = _grammar_tu_overhangs(grammar)
                if (tu_start and tu_end
                        and tu_start.upper() == oh5
                        and tu_end.upper()   == oh3):
                    position = {
                        "name":  _part_level_label(1),
                        "type":  _part_level_label(1),
                        "oh5":   tu_start,
                        "oh3":   tu_end,
                        "color": "white",
                    }
                    return {
                        "grammar_id":     gid,
                        "grammar_name":   grammar.get("name", gid),
                        "level":          1,
                        "position":       position,
                        "insert":         insert,
                        "vector":         vector,
                        "release_enzyme": enzyme,
                        "entry_vector":   _check_vector_match(
                            gid, enzyme, vector,
                        ),
                    }
                # Third check: per-acceptor TU boundary overhangs.
                # Each configured entry vector's stuffer carries a
                # specific (oh5, oh3) pair; a TU assembled into
                # that acceptor will release with the same pair.
                # MAV-25 in alpha-2 hit this pass (2026-05-13).
                for role, ev_name, acc_oh5, acc_oh3 in (
                    _grammar_acceptor_tu_pairs(gid, enzyme)
                ):
                    if acc_oh5 == oh5 and acc_oh3 == oh3:
                        label = _part_level_label(1)
                        position = {
                            "name":  f"{label} ({role})",
                            "type":  label,
                            "oh5":   acc_oh5,
                            "oh3":   acc_oh3,
                            "color": "white",
                        }
                        return {
                            "grammar_id":     gid,
                            "grammar_name":   grammar.get("name", gid),
                            "level":          1,
                            "position":       position,
                            "insert":         insert,
                            "vector":         vector,
                            "release_enzyme": enzyme,
                            "entry_vector":   _check_vector_match(
                                gid, enzyme, vector,
                            ),
                        }
            # Pass 4 (2026-05-20): lenient TU detection for L1
            # acceptors that release outside the canonical (Pos 1
            # oh5, Pos N oh3) pair but use overhangs from the
            # grammar's own canonical alphabet. Caught by user
            # report on the EDEN collection MAV 25-31 (TUA1/TUA2
            # acceptors) — TUA1 releases the TU with (GGAG, GTCA);
            # TUA2 with (GTCA, CGCT). Both pairs are valid GB 2.0
            # overhangs (GTCA = RC(TGAC), a Pos 1b operator
            # overhang in the GB 2.0 expanded grammar) but neither
            # matches the strict TU boundary and neither lab has
            # entry vectors configured in `entry_vectors.json`.
            #
            # Pick the TU candidate via `_pick_insert_fragment`'s
            # backbone-marker exclusion — NEVER by fragment size.
            # Size is unreliable for L1+ TUs (an assembled cassette
            # commonly outgrows the alpha-vector backbone), and
            # the user has explicitly called out this assumption
            # as a class of bugs (2026-05-20).
            #
            # Skip pass-4 when no fragment carries a clear backbone
            # marker — pass-4 cannot safely commit to one fragment
            # being the TU without that biology signal, and a
            # wrong-tag is worse than the existing "no detectable
            # grammar" outcome.
            backbone_marked = [
                _fragment_has_backbone_marker(f) for f in frags
            ]
            if sum(backbone_marked) != 1:
                # Either both have markers (annotation noise) or
                # neither does (un-annotated entry). Either way,
                # pass-4 can't safely commit. Fall through to the
                # next grammar/enzyme.
                continue
            tu_idx = 0 if not backbone_marked[0] else 1
            tu_candidate = frags[tu_idx]
            vector_candidate = frags[1 - tu_idx]
            oh5 = (tu_candidate.get("left") or {}).get(
                "overhang_seq", "",
            ).upper()
            oh3 = (tu_candidate.get("right") or {}).get(
                "overhang_seq", "",
            ).upper()
            if not oh5 or not oh3:
                continue
            canonical = _grammar_canonical_overhangs(grammar)
            if oh5 not in canonical or oh3 not in canonical:
                continue
            position = {
                "name":  f"TU ({oh5}→{oh3})",
                "type":  _part_level_label(1),
                "oh5":   oh5,
                "oh3":   oh3,
                "color": "white",
            }
            _log_event(
                "classify.lenient_tu",
                grammar=gid, enzyme=enzyme,
                oh5=oh5, oh3=oh3,
            )
            return {
                "grammar_id":     gid,
                "grammar_name":   grammar.get("name", gid),
                "level":          1,
                "position":       position,
                "insert":         tu_candidate,
                "vector":         vector_candidate,
                "release_enzyme": enzyme,
                "entry_vector":   _check_vector_match(
                    gid, enzyme, vector_candidate,
                ),
                "lenient":        True,
            }
    return None


def _grammar_canonical_overhangs(grammar: dict) -> "set[str]":
    """Set of every 4-bp overhang the grammar's position table knows,
    plus each one's reverse complement.

    Pre-2026-05-20 the classifier hard-coded the canonical TU
    boundary as ``(positions[0].oh5, positions[-1].oh3)`` — for
    `gb_l0` that's ``(GGAG, CGCT)``. Real Golden Braid α/Ω
    acceptors release TUs with NON-canonical pairs drawn from the
    same overhang alphabet (e.g. pDGB3 α1 releases with
    ``(GGAG, GTCA)`` — the second overhang is RC of TGAC, a Pos 1b
    operator from the GB 2.0 expanded grammar). This helper
    exposes the full alphabet so the lenient pass-4 of
    `_classify_part_from_plasmid` can recognise these without
    requiring the user to pre-configure entry vectors.

    Includes reverse complements because Type IIS overhangs read
    differently depending on which strand the cut surface is being
    described from — a released fragment whose 5' overhang on the
    top strand is ``GTCA`` has ``TGAC`` on the bottom strand, and
    both are equally "this overhang".
    """
    out: "set[str]" = set()
    for pos in (grammar.get("positions") or []):
        if not isinstance(pos, dict):
            continue
        for key in ("oh5", "oh3"):
            v = str(pos.get(key, "") or "").upper()
            if v and len(v) == 4 and all(c in "ACGT" for c in v):
                out.add(v)
                out.add(_rc(v))
    return out


# ── Entry-vector role auto-detection (2026-05-20) ─────────────────────────
#
# Given a candidate plasmid + a grammar, identify which entry-vector
# role the plasmid fills:
#   * `""` (singleton) — L0 acceptor / UPD-style donor
#   * `"Alpha1"` / `"Alpha2"` — Golden Braid L1 forward / reverse acceptors
#   * `"Omega1"` / `"Omega2"` — Golden Braid L2 forward / reverse acceptors
#   * `"Acceptor1"` / `"Acceptor2"` — MoClo L1 acceptors (when mapping
#     extended)
#
# Strategy: digest with BOTH the grammar's primary and level-up enzymes.
# The stuffer (no backbone marker — identified via
# `_pick_insert_fragment`'s feature-based exclusion, NEVER size) carries
# specific overhangs depending on the acceptor's role:
#
# Golden Braid binary-assembly architecture (gb_l0 with primary=Esp3I,
# level_up=BsaI, per Sarrion-Perdigones 2013 / pDGB3):
#
#   α-vectors (L1):  BsaI = INNER (assembly), Esp3I = OUTER (release)
#                    BsaI stuffer  = (GGAG, CGCT)  (canonical TU boundary)
#                    Esp3I stuffer = (GGAG, GTCA)  → Alpha1
#                                  = (GTCA, CGCT)  → Alpha2
#
#   Ω-vectors (L2):  Esp3I = INNER, BsaI = OUTER
#                    Esp3I stuffer = (GGAG, CGCT)  (canonical TU boundary)
#                    BsaI stuffer  = (GGAG, GTCA)  → Omega1
#                                  = (GTCA, CGCT)  → Omega2
#
# The canonical TU boundary on the INNER enzyme distinguishes α from Ω
# (the OUTER enzyme is the one whose stuffer pair encodes the role).
#
# UPD detection: neither digest gives the canonical TU boundary, but
# at least one cuts cleanly into 2 fragments. Returns ("", "weak")
# meaning "looks like a singleton L0 acceptor — bind to the empty role".
#
# Sacred — backbone-marker exclusion, NEVER size, per
# `feedback_never_assume_smaller_frag_is_payload`. Two markers or zero
# markers in a single digest → that enzyme's digest is ambiguous; the
# detector tries the other enzyme but never picks by size.


def _resolve_acceptor_role(
    grammar: dict, inner_enz: str, outer_pair: "tuple[str, str]",
) -> "str | None":
    """Map (inner enzyme, outer overhang pair) to a role name.

    Golden Braid binary assembly: the level-up enzyme is the INNER
    cutter for the α (L1) family; the primary enzyme is the INNER
    cutter for the Ω (L2) family. The outer pair encodes the
    forward/reverse "1/2" suffix.

    Returns the role name (matching `_CONSTRUCTOR_BACKBONES`) or
    None for grammars whose acceptor layout we don't know.
    """
    gid = grammar.get("id", "")
    primary = grammar.get("enzyme", "") or ""
    secondary = grammar.get("level_up_enzyme", "") or ""

    # GB 2.0 binary assembly — gb_l0 only. The outer-pair encoding
    # (`GGAG → 1`, `GTCA → 2`) reflects the standard pDGB3 design.
    if gid == "gb_l0" and secondary:
        if inner_enz == secondary:
            # α-family: level-up enzyme is the inner cutter.
            if outer_pair == ("GGAG", "GTCA"):
                return "Alpha1"
            if outer_pair == ("GTCA", "CGCT"):
                return "Alpha2"
        elif inner_enz == primary:
            # Ω-family: primary enzyme is the inner cutter.
            if outer_pair == ("GGAG", "GTCA"):
                return "Omega1"
            if outer_pair == ("GTCA", "CGCT"):
                return "Omega2"
    # Other grammars (moclo_plant + custom): we don't ship a canonical
    # role mapping. The user must bind manually via the EntryVectorsModal
    # UI. Returning None tells the caller "I can't auto-tag this one".
    return None


def _detect_entry_vector_role(
    record,
    grammar: dict,
) -> "tuple[str, str] | None":
    """Identify which entry-vector role a candidate plasmid fills.

    Returns ``(role_name, confidence)`` or ``None``. ``role_name`` is
    the key into ``_CONSTRUCTOR_BACKBONES[grammar_id]`` for L1+
    acceptors, or the empty string ``""`` for an L0 / UPD-style
    singleton donor. ``confidence`` is one of:

      * ``"strict"`` — both grammar enzymes digest cleanly to 2
        fragments with the stuffer identified via backbone-marker
        exclusion, AND one digest's stuffer is the canonical TU
        boundary, AND the other digest's outer pair maps to a known
        role.
      * ``"weak"`` — at least one digest produces 2 fragments with a
        clean stuffer, but neither matches the canonical TU boundary
        and the outer pair can't be mapped. Used for UPD-style L0
        donors (singleton role).

    Returns ``None`` when:
      * The record isn't circular (linear records can't be acceptors).
      * No grammar enzyme cuts the record cleanly into 2 fragments.
      * Backbone-marker exclusion can't identify a single stuffer
        (zero or two markers per digest).
      * Detection produces a recognised α/Ω pattern in BOTH families
        simultaneously (would only happen for a synthetic chimera —
        return None to let the user disambiguate manually).

    Sacred — uses `_fragment_has_backbone_marker` to pick the stuffer
    fragment, NEVER size. See `feedback_never_assume_smaller_frag_is_payload`.
    """
    # Extract sequence + features from a SeqRecord, a plain str, or a
    # library-entry dict (gb_text). The classifier needs both.
    if hasattr(record, "seq") and hasattr(record, "features"):
        seq = str(record.seq).upper()
        circular = (
            (record.annotations or {}).get("topology") == "circular"
        )
        feats = [
            {
                "start": int(f.location.start),
                "end":   int(f.location.end),
                "type":  f.type,
                "qualifiers": dict(f.qualifiers),
            }
            for f in record.features
        ]
    elif isinstance(record, str):
        seq = record.upper()
        circular = True
        feats = []
    elif isinstance(record, dict) and isinstance(record.get("gb_text"), str):
        try:
            rec = _gb_text_to_record(record["gb_text"])
        except Exception:
            return None
        return _detect_entry_vector_role(rec, grammar)
    else:
        return None

    if not circular or not seq:
        return None

    primary = grammar.get("enzyme") or ""
    secondary = grammar.get("level_up_enzyme") or primary
    if not primary:
        return None

    # Digest with both enzymes. Skip the second pass if it's the same
    # as the primary (single-enzyme grammars don't need a second look).
    enzymes = [primary]
    if secondary and secondary != primary:
        enzymes.append(secondary)

    digests: "dict[str, tuple[str, str]]" = {}
    for enz in enzymes:
        try:
            frags, err = _excise_fragment_pair(
                seq, [enz], circular=True, features=feats,
            )
        except Exception:
            _log.exception(
                "_detect_entry_vector_role: %s digest raised", enz,
            )
            continue
        if err is not None or len(frags) != 2:
            continue
        # Stuffer = the fragment without a backbone marker. Two markers
        # or zero markers → ambiguous, skip this enzyme.
        marked = [
            _fragment_has_backbone_marker(f) for f in frags
        ]
        if sum(marked) != 1:
            continue
        stuffer = frags[0] if not marked[0] else frags[1]
        oh5 = (stuffer.get("left") or {}).get(
            "overhang_seq", "",
        ).upper()
        oh3 = (stuffer.get("right") or {}).get(
            "overhang_seq", "",
        ).upper()
        if oh5 and oh3 and len(oh5) == 4 and len(oh3) == 4:
            digests[enz] = (oh5, oh3)

    if not digests:
        return None

    tu_start, tu_end = _grammar_tu_overhangs(grammar)

    # Strict: one digest matches canonical TU boundary (inner), the
    # other gives an outer pair we can map to a role.
    if len(digests) == 2 and tu_start and tu_end:
        canonical = (tu_start.upper(), tu_end.upper())
        inner_enz = None
        outer_enz = None
        outer_pair = None
        for enz, pair in digests.items():
            if pair == canonical:
                inner_enz = enz
            else:
                outer_enz = enz
                outer_pair = pair
        if inner_enz and outer_pair:
            role = _resolve_acceptor_role(grammar, inner_enz, outer_pair)
            if role:
                return (role, "strict")

    # Weak: a 2-fragment digest fired but no role mapping. Now
    # discriminate UPD-style singletons from L0 parts / TUs / MODs
    # that ALSO digest cleanly but aren't acceptors.
    #
    # An L0 PART's stuffer overhangs match a canonical L0 position
    # (e.g. (GGAG, AATG) for a Promoter). If any digest matches an
    # L0 position table entry, the plasmid is a part — not an
    # acceptor. Reject.
    positions = grammar.get("positions") or []
    for _enz, (oh5, oh3) in digests.items():
        for pos in positions:
            p_oh5 = str(pos.get("oh5", "")).upper()
            p_oh3 = str(pos.get("oh3", "")).upper()
            if (p_oh5, p_oh3) == (oh5, oh3):
                return None
            # Mirror orientation: a part with reversed insertion still
            # exposes a recognised pair, just swapped.
            if (p_oh3, p_oh5) == (oh5, oh3):
                return None

    # A TU/MOD plasmid's stuffer overhangs come from the grammar's
    # canonical alphabet (matches `_classify_part_from_plasmid`'s
    # pass-4 lenient rule). If both overhangs of any digest are in
    # the canonical set, the plasmid is a TU/MOD — not an empty
    # acceptor. Reject.
    canonical = _grammar_canonical_overhangs(grammar)
    for _enz, (oh5, oh3) in digests.items():
        if oh5 in canonical and oh3 in canonical:
            return None

    # Everything else: NO position match, NO canonical-alphabet match,
    # but the plasmid digests cleanly. The stuffer's non-canonical
    # overhangs are the fingerprint of an L0 / UPD-style donor whose
    # internal stuffer is intentionally NOT a part-boundary pair.
    return ("", "weak")


def _auto_bind_entry_vectors_from_entries(
    entries: "list[dict]",
    *,
    grammar_ids: "list[str] | None" = None,
) -> str:
    """Run `_detect_entry_vector_role` on every library entry across
    every grammar (or `grammar_ids` if specified) and bind newly
    detected acceptors to their roles in `entry_vectors.json`.

    Sacred — existing user bindings take precedence. The auto-bind
    NEVER clobbers a role already bound by the user (or by a previous
    auto-detect). This means re-running after a partial manual
    configuration just fills in the gaps.

    Conflict resolution within the input: if two entries are detected
    as the same role, the first STRICT match wins; "weak" loses to
    "strict".

    Returns a human-readable summary string suitable for a
    `notify(...)` call, or an empty string if nothing was bound.
    Designed to slot into the post-import notification chain so the
    user gets one consolidated toast instead of one per binding.
    """
    if not entries:
        return ""
    target_grammars = grammar_ids or list(_all_grammars().keys())
    bound_by_grammar: dict[str, list[str]] = {}
    # Sweep #11 (2026-05-20): parse each gb_text ONCE up-front
    # instead of N × M (entries × grammars) times. A 100-entry,
    # 3-grammar import previously paid 300 BioPython parses on the
    # UI thread; now it pays 100. Parse failures are silently
    # skipped (same behaviour as pre-fix per-grammar loop).
    parsed_records: list[tuple[dict, object]] = []
    for entry in entries:
        if not isinstance(entry, dict):
            continue
        gb_text = entry.get("gb_text") or ""
        if not gb_text:
            continue
        try:
            rec = _gb_text_to_record(gb_text)
        except Exception:
            continue
        parsed_records.append((entry, rec))
    # Accumulate every binding into one batch and apply with ONE
    # _save_entry_vectors call at the end. Pre-fix: N × _set_entry_vector
    # → N × _safe_save_json + .bak + fsync round-trips. Now: ONE round-trip.
    pending_updates: "list[tuple[str, str, dict | None]]" = []
    for gid in target_grammars:
        grammar = _all_grammars().get(gid)
        if not isinstance(grammar, dict):
            continue
        proposals: dict[str, tuple[dict, str]] = {}
        for entry, rec in parsed_records:
            result = _detect_entry_vector_role(rec, grammar)
            if not result:
                continue
            role, conf = result
            existing = proposals.get(role)
            # Strict beats weak. Within the same confidence level,
            # first match wins (stable + deterministic given input
            # order from `_bulk_import_folder`).
            if existing is None or (
                existing[1] == "weak" and conf == "strict"
            ):
                proposals[role] = (entry, conf)
        for role_key, (entry, conf) in proposals.items():
            # Don't clobber an existing user-set binding.
            if _get_entry_vector(gid, role_key) is not None:
                continue
            payload = {
                "name":    entry.get("name") or entry.get("id", "?"),
                "size":    entry.get("size") or 0,
                "source":  "auto-detect (import)",
                "id":      entry.get("id", ""),
                "gb_text": entry.get("gb_text") or "",
            }
            pending_updates.append((gid, role_key, payload))
            _log_event(
                "entry_vector.auto_bound",
                grammar=gid, role=role_key,
                confidence=conf,
                entry_id=entry.get("id", ""),
                trigger="import",
            )
            bound_by_grammar.setdefault(gid, []).append(
                role_key or "UPD"
            )
    if pending_updates:
        try:
            _set_entry_vectors_batch(pending_updates)
        except Exception:
            _log.exception(
                "auto-bind: batch persist failed (%d updates)",
                len(pending_updates),
            )
            return ""
    if not bound_by_grammar:
        return ""
    # Compact message: "Auto-configured 5 entry vector(s) for gb_l0:
    # UPD, Alpha1, Alpha2, Omega1, Omega2".
    bits: list[str] = []
    for gid, roles in bound_by_grammar.items():
        bits.append(
            f"{gid}: {', '.join(roles)}"
        )
    total = sum(len(r) for r in bound_by_grammar.values())
    return (
        f"Auto-configured {total} entry vector role(s) "
        f"({'; '.join(bits)})."
    )


def _grammar_position_by_type(grammar: dict, ptype: str) -> "dict | None":
    """Helper: find the position spec for a given part type within a
    grammar. ``None`` if the grammar doesn't define that type — which
    e.g. means CDS-NS isn't a valid pick under MoClo Plant."""
    for pos in grammar.get("positions", []):
        if pos.get("type") == ptype:
            return pos
    return None


# ── Level helpers (Golden Braid iterative cycle) ───────────────────────
# Every part / assembled plasmid carries an integer ``level``:
#   * 0   — domesticated L0 part (single Promoter / CDS / Terminator)
#   * 1   — TU (single transcription unit, L0 parts ligated into α/Ω L1)
#   * 2+  — MOD (module of TUs, two L1 plasmids ligated into L2 — and so
#           on iteratively; level keeps incrementing each cycle)
#
# The user-facing labels collapse to L0 / TU / MOD (any level ≥2 is a
# MOD) per the parts-bin tab UX spec. Internally we keep the raw int so
# enzyme-parity arithmetic (`_enzyme_for_level_up`) keeps working as
# the user iterates further up the GB cycle.

def _part_level(part: dict) -> int:
    """Return the integer level stored on a part dict, defaulting to 0
    for legacy parts that predate the field. Coerces strings ("L0",
    "TU", "MOD") and numerics (0, 1, 2) so a hand-edited parts_bin.json
    keeps loading. Negative / non-numeric values fall back to 0."""
    raw = part.get("level", 0) if isinstance(part, dict) else 0
    if isinstance(raw, bool):
        return 0  # bool is a subclass of int — explicit guard
    if isinstance(raw, int):
        return max(0, raw)
    if isinstance(raw, str):
        s = raw.strip().upper()
        if s in ("L0", "0"):
            return 0
        if s in ("TU", "L1", "1"):
            return 1
        if s in ("MOD", "MODULE", "L2"):
            return 2
        if s.isdigit():
            return max(0, int(s))
    return 0


def _part_level_label(level: int) -> str:
    """Map an integer level to the user-facing label used in the Parts
    Bin tabs and notify strings: L0 → 'L0', 1 → 'TU', ≥2 → 'MOD'."""
    if level <= 0:
        return "L0"
    if level == 1:
        return "TU"
    return "MOD"


def _level_matches_tab(part_level: int, tab_level: int) -> bool:
    """True iff a part with ``part_level`` belongs in the ``tab_level``
    Parts Bin tab / Constructor palette filter.

    Tab L0 (0) is the only strict-match level — L0 parts are
    domesticated entities, biologically distinct from any
    assembled plasmid. Every higher-level tab absorbs its own
    level AND everything above:

      * TU tab (1) → level ≥ 1 (TUs + MODs + L3 + …)
      * MOD tab (2) → level ≥ 2 (MODs + L3 + …)

    Rationale: a MOD plasmid carries a chain that, after the
    correct level-up digest, can ligate into a "TU → MOD"
    assembly alongside a real TU — same enzyme, same overhang
    shape. Hiding the MOD from the TU palette would force users
    to re-do their library tagging just to chain plasmids the
    bench reaction handles fine. The compatibility check at
    save-time still flags overhang mismatches, so the user can
    SEE every candidate without losing the safety net.

    Used by the parts-bin row filter, the constructor's palette
    refresh, and the lane-resolver's identity match — extracted
    so the rule change in one place propagates everywhere."""
    if tab_level <= 0:
        return part_level == 0
    return part_level >= tab_level


def _enzyme_for_level_up(grammar: dict, source_level: int) -> str:
    """Pick the Type IIS enzyme that releases parts from a level-N
    source plasmid for assembly into a level-(N+1) destination.

    Golden Braid alternates enzymes each level: L0→L1 uses
    ``grammar.enzyme``, L1→L2 uses ``grammar.level_up_enzyme``, L2→L3
    wraps back to ``grammar.enzyme``. Parity on ``source_level`` picks
    the right one. Falls back to ``grammar.enzyme`` when a custom
    grammar omits ``level_up_enzyme`` (older custom grammars predate
    iterative cycle support)."""
    primary = str(grammar.get("enzyme") or "")
    secondary = str(grammar.get("level_up_enzyme") or "") or primary
    return primary if (source_level % 2) == 0 else secondary


def _grammar_dropdown_options() -> list[tuple[str, str]]:
    """Return ``[(display_name, id), …]`` for every grammar, in the
    canonical order used wherever a Select dropdown lists grammars
    (DomesticatorModal "Grammar" picker today; future menus likely):

      1. **Golden Braid L0 first** — the default reference grammar.
         Pinned at position 1 regardless of any other ordering
         shenanigans (e.g., a custom grammar id-sorted before
         ``gb_l0``).
      2. Other built-in grammars (MoClo Plant, etc.) in
         ``_BUILTIN_GRAMMARS`` insertion order.
      3. Custom grammars from ``cloning_grammars.json`` last, tagged
         ``(custom)`` for visual disambiguation.
    """
    grammars = _all_grammars()
    out: list[tuple[str, str]] = []
    if "gb_l0" in grammars:
        g = grammars["gb_l0"]
        out.append((f"{g.get('name', 'Golden Braid L0')}", "gb_l0"))
    for gid in _BUILTIN_GRAMMARS:
        if gid == "gb_l0" or gid not in grammars:
            continue
        g = grammars[gid]
        out.append((f"{g.get('name', gid)}", gid))
    for gid, g in grammars.items():
        if gid in _BUILTIN_GRAMMARS:
            continue
        out.append((f"{g.get('name', gid)}  (custom)", gid))
    return out


# ── App-wide settings (active grammar, future preferences) ─────────────────────

_SETTINGS_FILE = _DATA_DIR / "settings.json"
_settings_cache: "dict | None" = None

# Type schema for the persisted settings file. Used by
# `_validate_settings` to coerce or strip values that arrive in the
# wrong type (hand-edited JSON, partial restore from a future-version
# snapshot, etc.). Each entry maps key → (allowed_types, default)
# where `allowed_types` is a tuple suitable for `isinstance`.
# Unknown keys are PRESERVED (forward-compat: a future SpliceCraft
# might add a setting that this build doesn't know about).
#
# Adding a new persisted setting? Append the row here so a stray
# `null` / `"true"` / `[]` from a hand-edit doesn't propagate into
# the reactive UI as the wrong type. The default is what the
# validator falls back to when the value is irrecoverable.
_SETTINGS_SCHEMA: "dict[str, tuple[tuple, object]]" = {
    "show_feature_tooltips":   ((bool,),               False),
    "click_debug":             ((bool,),               False),
    "check_updates":           ((bool,),               True),
    "show_restr":              ((bool,),               False),
    "restr_unique_only":       ((bool,),               True),
    "restr_min_len":           ((int,),                6),
    "restr_custom_enzymes":    ((str,),                ""),
    "restr_use_custom_list":   ((bool,),               False),
    "min_primer_binding":      ((int,),                15),
    "show_connectors":         ((bool,),               False),
    "linear_layout":           ((bool,),               False),
    "active_collection":       ((str,),                ""),
    "active_grammar":          ((str,),                ""),
    "constructor_filter_by_grammar": ((bool,),         True),
    "last_seen_version":       ((str,),                ""),
    "last_known_latest":       ((str,),                ""),
    "last_update_check_ts":    ((int, float),          0),
    "hmm_db_path":             ((str,),                ""),
    # Persisted seq-panel height from the map/seq resize handle (PR #8
    # from Harley King). `None`-default is encoded as 0 so the schema
    # validator passes; hydrate logic treats <6 as "unset".
    "seq_panel_height":        ((int,),                0),
    # Sweep #9 (2026-05-19): keys added through 0.8.x / 0.9.x that
    # weren't registered in the schema. Without these entries a
    # hand-edited or downgrade-round-tripped settings.json could
    # carry wrong-typed values that bypass `_validate_settings`'
    # strict-bool/strict-int guard. The unknown-key forward-compat
    # passthrough catches them today, but the schema is the
    # documented contract for "what's persisted" and the new keys
    # belong there.
    "active_parts_bin":        ((str,),                ""),
    "active_project":          ((str,),                ""),
    "experiments_custom_dict": ((list,),               []),
}


def _validate_settings(raw: dict) -> "tuple[dict, list[str]]":
    """Coerce every known key in `raw` to the type declared in
    `_SETTINGS_SCHEMA`. Returns `(cleaned_dict, warnings)`. Unknown
    keys are passed through (forward-compat). Wrong-typed values
    are replaced with the schema default and a warning is appended.

    Cheap (O(n_settings)). Called from `_load_settings` so every
    consumer sees a typed view regardless of how the file got
    corrupted.
    """
    if not isinstance(raw, dict):
        return {}, [f"settings: not a dict ({type(raw).__name__}); "
                     "starting fresh"]
    out: dict = {}
    warnings: list[str] = []
    for k, v in raw.items():
        if k in _SETTINGS_SCHEMA:
            allowed, default = _SETTINGS_SCHEMA[k]
            # Strict bool/int discrimination: bool matches int
            # isinstance check, so we have to special-case.
            if isinstance(v, bool) and bool not in allowed:
                warnings.append(
                    f"settings.{k}: ignored (got bool, expected "
                    f"{[t.__name__ for t in allowed]}); using default {default!r}"
                )
                out[k] = default
                continue
            if not isinstance(v, allowed):
                warnings.append(
                    f"settings.{k}: ignored (got {type(v).__name__}, expected "
                    f"{[t.__name__ for t in allowed]}); using default {default!r}"
                )
                out[k] = default
                continue
            out[k] = v
        else:
            # Unknown key — pass through for forward-compat. A future
            # build may have added this setting and we don't want to
            # destroy it on a downgrade-then-upgrade round trip.
            out[k] = v
    return out, warnings

# Async-flush plumbing for `_set_setting`. Persistent settings are
# safety-net data (worst case: the user's last toggle doesn't survive a
# crash before the flush completes), so the disk write happens on a
# daemon thread instead of blocking the UI thread for the 5–30 ms an
# `_safe_save_json` cycle takes (read prev for shrink-detect → tempfile
# write → fsync → atomic rename → backup-pruning). Coalesced: the worker
# always flushes the most-recent payload, so a burst of 5 toggles in
# 50 ms collapses to 1–2 disk writes instead of 5.
_settings_flush_lock = threading.Lock()
_settings_flush_pending: "dict | None" = None
_settings_flush_running: bool = False


def _load_settings() -> dict:
    """Return the persistent settings dict. Stored on disk as a list of
    ``{"key": ..., "value": ...}`` envelope entries so it shares the
    schema layout (sacred invariant #7) with every other JSON file.

    Type-validates against `_SETTINGS_SCHEMA` so a hand-edited
    settings.json (or a partial restore from a future-version
    snapshot) can't propagate wrong-type values into the reactive
    UI. Unknown keys are preserved for forward-compat.
    """
    global _settings_cache
    if _settings_cache is not None:
        return _typed_clone(_settings_cache)
    entries, warning = _safe_load_json(_SETTINGS_FILE, "Settings")
    if warning:
        _log.warning(warning)
    settings: dict = {}
    for e in entries:
        if not isinstance(e, dict):
            continue
        k, v = e.get("key"), e.get("value")
        if isinstance(k, str):
            settings[k] = v
    cleaned, warns = _validate_settings(settings)
    for w in warns:
        _log.warning(w)
    _settings_cache = cleaned
    return _typed_clone(_settings_cache)


def _save_settings(settings: dict) -> None:
    """Synchronous write — kept for the few callsites (tests, migrations)
    that want the disk state visible immediately on return. UI toggles
    use `_set_setting`, which mirrors to `_settings_cache` synchronously
    and defers the disk write to a background thread."""
    global _settings_cache
    entries = [{"key": k, "value": v} for k, v in settings.items()]
    with _cache_lock:
        _safe_save_json(_SETTINGS_FILE, entries, "Settings")
        _settings_cache = _typed_clone(settings)


def _get_setting(key: str, default: "_Any" = None) -> "_Any":
    """Return the persisted value for ``key``, or ``default`` if absent.
    Typed as ``Any`` so callers like ``_active_grammar_id`` can declare
    a narrower return type (`-> str`) without a cast — pyright treats
    ``Any`` as universally assignable, sidestepping the
    ``Unknown | None`` propagation from the loose `_load_settings()`
    return."""
    return _load_settings().get(key, default)


def _settings_flush_worker() -> None:
    """Drain the pending-settings slot, write to disk, repeat until
    nothing's pending. Runs in a daemon thread spawned by
    `_set_setting`. Multiple bursts spawn at most one worker at a time
    (`_settings_flush_running` gate); subsequent `_set_setting` calls
    just overwrite the pending payload, so the worker writes the latest
    state once it gets the lock.

    `_settings_flush_running` MUST always reach False on exit, even on
    an unforeseen exception (e.g., a non-JSON-serialisable value
    sneaking in past `_validate_settings`). Pre-0.8.9 had a narrow
    `except (OSError, RuntimeError)`; an unexpected exception would
    propagate up, kill the worker thread, AND leave the flag set —
    wedging every subsequent `_set_setting` because the gate check
    silently refuses to spawn a fresh worker.
    """
    global _settings_flush_pending, _settings_flush_running
    try:
        while True:
            with _settings_flush_lock:
                payload = _settings_flush_pending
                _settings_flush_pending = None
                if payload is None:
                    return
            entries = [{"key": k, "value": v} for k, v in payload.items()]
            try:
                _safe_save_json(_SETTINGS_FILE, entries, "Settings")
            except (OSError, RuntimeError) as exc:
                # The cache was already updated synchronously, so the
                # in-process state stays consistent; only the on-disk
                # mirror is stale until the next successful flush.
                # Surface to the UI so a persistable-toggle keystroke
                # that the user thinks "took" can't silently revert
                # at next launch.
                _bg_notify_save_failure("Settings", exc)
            except Exception:
                _log.exception(
                    "settings flush: unexpected error while writing %s",
                    _SETTINGS_FILE,
                )
    finally:
        with _settings_flush_lock:
            _settings_flush_running = False


def _set_setting(key: str, value) -> None:
    """Update one setting key. Cache is updated synchronously so a
    subsequent `_load_settings()` (in this process) sees the new value
    immediately. The disk write is deferred to a daemon thread so a
    keypress that toggles a setting (e.g. `r`) doesn't block the UI on
    fsync. Coalesces bursts of toggles into fewer disk writes.

    Set ``SPLICECRAFT_SKIP_SETTINGS_FLUSH=1`` to bypass the daemon
    thread and write synchronously — used by tests so they get
    deterministic disk state without a trailing daemon thread on exit.
    Matches the `_skip_seed` / `_skip_snapshot` / `_skip_update_check`
    pattern other startup gates already follow.
    """
    global _settings_cache, _settings_flush_pending, _settings_flush_running
    settings = _load_settings()
    # Log only when the value actually changes — avoids spamming the
    # log when callers re-set the same value on settings hydration.
    # Truncate the value repr to keep log lines bounded for big lists.
    prev = settings.get(key, "<unset>")
    if prev != value:
        _log.info("setting changed: %s = %r (was %r)",
                    key, _repr_for_log(value), _repr_for_log(prev))
        # Structured counterpart so AI parsers of bug-report logs can
        # filter by setting key without regex-scraping the human-readable
        # line above. Values are run through `_repr_for_log` to truncate
        # over-long lists / cap any accidental sequence content.
        _log_event(
            "settings.changed",
            key=key, value=_repr_for_log(value),
            prev=_repr_for_log(prev),
        )
    settings[key] = value
    # Sweep #9 (2026-05-19): use `_typed_clone` instead of `dict(...)`
    # — `dict()` is a SHALLOW copy, so a nested-list value (e.g.
    # `experiments_custom_dict: ["foo", ...]`) would share the
    # caller's list reference. A subsequent caller-side mutation
    # would leak into the cache. Mirrors `_save_settings` (line
    # 24956) and the documented cache contract (invariant #17).
    _settings_cache = _typed_clone(settings)
    if os.environ.get("SPLICECRAFT_SKIP_SETTINGS_FLUSH", "").strip().lower() in (
        "1", "true", "yes"
    ):
        entries = [{"key": k, "value": v} for k, v in settings.items()]
        try:
            _safe_save_json(_SETTINGS_FILE, entries, "Settings")
        except (OSError, RuntimeError):
            _log.exception("settings sync write failed (skip-flush mode)")
        return
    with _settings_flush_lock:
        _settings_flush_pending = dict(settings)
        if _settings_flush_running:
            return
        _settings_flush_running = True
    threading.Thread(target=_settings_flush_worker,
                      name="settings-flush",
                      daemon=True).start()


def _settings_flush_sync() -> None:
    """Block until any pending settings flush has completed. Called from
    the app's atexit handler so the user's last toggle reaches disk
    before the process exits, even though the worker is a daemon
    thread (= killed on interpreter shutdown otherwise)."""
    deadline = _time.monotonic() + 2.0
    while _time.monotonic() < deadline:
        with _settings_flush_lock:
            if not _settings_flush_running and _settings_flush_pending is None:
                return
        _time.sleep(0.02)
    _log.warning("Settings flush did not complete within 2 s timeout")


def _gb_find_forbidden_hits(
    seq: str,
    sites: "dict[str, str] | None" = None,
) -> list[tuple[str, str, int]]:
    """Return ``(enzyme_name, site_found, position)`` for **every** internal
    Type IIS recognition in *seq*, on both forward and reverse strands.

    The ``sites`` map (``{enzyme_name: recognition}``) defaults to the
    Golden Braid L0 forbidden set (Esp3I + BsaI). Pass a different
    grammar's ``forbidden_sites`` to scan against MoClo (BsaI + BpiI),
    a custom grammar, or any other Type IIS combination. Returns every
    occurrence — not just the first per enzyme. Critical for accurate
    reporting when an insert contains multiple sites: the user must
    know about all of them before paying for a gBlock synthesis.
    Results are sorted by position to aid downstream reporting.
    """
    if sites is None:
        sites = _GB_DOMESTICATION_FORBIDDEN
    out: list[tuple[str, str, int]] = []
    for name, site in sites.items():
        if not isinstance(site, str) or not site:
            continue
        rc = _rc(site)
        needles = [site] if rc == site else [site, rc]
        for needle in needles:
            start = 0
            while True:
                pos = seq.find(needle, start)
                if pos == -1:
                    break
                out.append((name, needle, pos))
                start = pos + 1
    out.sort(key=lambda t: (t[2], t[0], t[1]))
    return out


_CODON_FIX_POS_RE = re.compile(r"codon (\d+)")


def _codon_fix_mutation_positions(mutations: list[str]) -> list[int]:
    """Given the string list returned by :func:`_codon_fix_sites`, return
    each mutation's 0-based codon-start nucleotide position in the insert.

    The mutation format is fixed by ``_codon_fix_sites`` — ``(codon N …)``
    where ``N`` is 1-based. A missing / malformed entry gets ``-1`` so
    callers can filter without raising.
    """
    out: list[int] = []
    for m in mutations:
        match = _CODON_FIX_POS_RE.search(m) if isinstance(m, str) else None
        if match:
            out.append((int(match.group(1)) - 1) * 3)
        else:
            out.append(-1)
    return out


def _gb_binding_region_advisory(
    mutations: list[str],
    insert_len: int,
    fwd_bind_len: int,
    rev_bind_len: int,
) -> list[dict]:
    """Return one entry per mutation that lands inside a primer binding
    window. Each entry is ``{"text", "region", "codon_start"}`` where
    ``region`` is ``"fwd"`` or ``"rev"``. Empty list when every mutation
    is safely inside the amplicon's interior.

    Why this matters: if a mutation falls inside the 5′ or 3′ binding
    window, the PCR primer won't bind perfectly to the user's original
    plasmid template — they must order the *mutated* insert as a gBlock
    and use that as the PCR template (or redesign around the site).
    """
    if not mutations or insert_len <= 0:
        return []
    positions = _codon_fix_mutation_positions(mutations)
    fwd_hi = max(0, fwd_bind_len)             # [0, fwd_hi) covers fwd binding
    rev_lo = insert_len - max(0, rev_bind_len)  # [rev_lo, insert_len) covers rev binding
    out: list[dict] = []
    for text, codon_start in zip(mutations, positions):
        if codon_start < 0:
            continue
        codon_end = codon_start + 3
        # A 3-nt codon overlaps the fwd window if any nt is in [0, fwd_hi).
        in_fwd = codon_start < fwd_hi
        # Overlaps the rev window if any nt is in [rev_lo, insert_len).
        in_rev = codon_end > rev_lo
        if in_fwd:
            out.append({"text": text, "region": "fwd",
                        "codon_start": codon_start})
        if in_rev:
            out.append({"text": text, "region": "rev",
                        "codon_start": codon_start})
    return out


@_timed("op.primer3.gb_design")
def _design_gb_primers(
    template_seq: str,
    start: int,
    end: int,
    part_type: str,
    target_tm: float = 60.0,
    codon_raw: "dict | None" = None,
    grammar: "dict | None" = None,
) -> dict:
    """Design modular cloning domestication primers for a template region.

    Defaults to Golden Braid L0 (Esp3I, GGAG/TGAC/AATG/GCTT/CGCT
    overhangs); pass ``grammar`` to use a different cloning grammar
    (MoClo Plant, custom user-defined). The amplified product, after
    digestion with the grammar's enzyme, carries the 4-nt overhangs
    associated with ``part_type`` in that grammar's position table.

    Primer structure (5'→3'):

        Forward: [pad] [enzyme site] [spacer] [5' overhang]    [binding →]
        Reverse: [pad] [enzyme site] [spacer] [RC 3' overhang] [← binding RC]

    When *codon_raw* (a ``{codon: (aa, count)}`` dict from the codon-table
    registry) is supplied and *part_type* is a coding type (CDS / CDS-NS /
    C-tag), internal BsaI or Esp3I sites are silently repaired by
    substituting synonymous codons before the primers are designed — the
    returned ``insert_seq`` is then the *mutated* sequence (which is what
    the user should order as a gBlock / synthetic fragment for PCR).
    The list of substitutions made is returned under ``mutations``.

    Returns a dict with keys: part_type, position, oh5, oh3, insert_seq,
    fwd_binding, rev_binding, fwd_full, rev_full, fwd_tm, rev_tm,
    amplicon_len, mutations, and a ``pairs`` list. ``pairs`` holds one
    dict per amplicon — each with ``fwd_full``, ``rev_full``, ``fwd_tm``,
    ``rev_tm``, ``fwd_pos``, ``rev_pos``, ``fwd_binding``, ``rev_binding``,
    ``amplicon_len``. Callers that only need the first pair can continue
    to read the legacy top-level keys; multi-pair savers should iterate
    ``pairs`` (future SOE-PCR splitting for non-repairable internal sites
    will extend this list beyond one pair).
    """
    g = grammar if isinstance(grammar, dict) else _BUILTIN_GRAMMARS["gb_l0"]
    pos_spec = _grammar_position_by_type(g, part_type)
    if pos_spec is None:
        return {
            "error": f"Part type {part_type!r} is not defined in grammar "
                     f"{g.get('name', '?')}. Available types: "
                     f"{', '.join(p.get('type', '?') for p in g.get('positions', []))}.",
            "mutations": [],
        }
    pos_label, oh5, oh3 = pos_spec.get("name", "?"), pos_spec.get("oh5", ""), pos_spec.get("oh3", "")
    forbidden_sites = g.get("forbidden_sites", _GB_DOMESTICATION_FORBIDDEN) or _GB_DOMESTICATION_FORBIDDEN
    coding_types = set(g.get("coding_types", []) or _GB_CODING_PART_TYPES)
    enzyme_pad = g.get("pad", _GB_PAD)
    enzyme_site = g.get("site", _GB_L0_ENZYME_SITE)
    enzyme_spacer = g.get("spacer", _GB_SPACER)

    total  = len(template_seq)
    insert = _slice_circular(template_seq.upper(), start, end)
    wraps  = end < start

    # Need at least 18 bp to pick a proper binding region — otherwise
    # _pick_binding_region returns the whole (too-short) insert with Tm=0.
    if len(insert) < 18:
        return {
            "error": f"Cloning region is too short ({len(insert)} bp). "
                     f"Select at least 18 bp (recommended 25+ bp for a "
                     f"robust binding region).",
            "mutations": [],
        }

    # Internal Type IIS check. The grammar's `forbidden_sites` lists
    # every recognition that must be absent from the final part — for
    # GB L0 that's Esp3I (current cut) + BsaI (next-level reuse); for
    # MoClo Plant, BsaI + BpiI. Coding parts can be repaired via
    # synonymous codon substitution; non-coding parts have no reading
    # frame so internal sites must be fixed manually.
    mutations: list[str] = []
    initial_hits = _gb_find_forbidden_hits(insert, sites=forbidden_sites)
    if initial_hits:
        hit_str = ", ".join(
            f"{name} {site} at +{pos + 1}"
            for name, site, pos in initial_hits
        )
        can_attempt_fix = (
            part_type in coding_types
            and bool(codon_raw)
            and len(insert) % 3 == 0
        )
        if can_attempt_fix and codon_raw:
            # Inline `codon_raw` narrowing for pyright: the `bool(codon_raw)`
            # inside `can_attempt_fix` is not visible across the assignment,
            # so re-asserting truthiness here lets the type checker see
            # `codon_raw` as non-None at the call site below.
            protein = _mut_translate(insert)
            if protein:
                fixed_insert, mutations = _codon_fix_sites(
                    insert, protein, codon_raw,
                    sites=forbidden_sites,
                )
                remaining = _gb_find_forbidden_hits(
                    fixed_insert, sites=forbidden_sites,
                )
                if remaining:
                    remain_str = ", ".join(
                        f"{name} {site} at +{pos + 1}"
                        for name, site, pos in remaining
                    )
                    return {
                        "error": f"Internal Type IIS site(s) remain after "
                                 f"silent-mutation attempt ({remain_str}). "
                                 f"The sites overlap codons with no "
                                 f"synonymous alternative in this codon "
                                 f"table — pick a different region or "
                                 f"redesign.",
                        "mutations": mutations,
                    }
                insert = fixed_insert
            else:
                return {
                    "error": f"Internal Type IIS site(s) found ({hit_str}) "
                             f"but the insert could not be translated for "
                             f"silent mutation — pick a different region.",
                    "mutations": [],
                }
        else:
            reasons: list[str] = []
            if part_type not in coding_types:
                reasons.append(f"{part_type} is non-coding")
            else:
                if not codon_raw:
                    reasons.append("no codon table selected")
                if len(insert) % 3 != 0:
                    reasons.append(f"insert length {len(insert)} bp is "
                                   f"not a multiple of 3")
            extra = f" ({'; '.join(reasons)})" if reasons else ""
            return {
                "error": f"Internal Type IIS site(s) found: {hit_str}. "
                         f"Silent-mutation repair unavailable{extra}. "
                         f"Pick a different region or redesign.",
                "mutations": [],
            }

    # Forward binding: first 18-25 bp of the insert
    fwd_bind, fwd_tm = _pick_binding_region(insert, target_tm)

    # Reverse binding: first 18-25 bp of the reverse-complement of the insert
    # (i.e. the last 18-25 bp of the insert, reverse-complemented)
    rev_bind, rev_tm = _pick_binding_region(_rc(insert), target_tm)

    # Assemble full primers using the grammar's enzyme/pad/spacer.
    fwd_tail = enzyme_pad + enzyme_site + enzyme_spacer + oh5
    rev_tail = enzyme_pad + enzyme_site + enzyme_spacer + _rc(oh3)

    fwd_full = fwd_tail + fwd_bind
    rev_full = rev_tail + rev_bind

    # Amplicon = pad + Esp3I + spacer + oh + insert + oh_rc + spacer_rc
    #          + Esp3I_rc + pad_rc
    amplicon_len = len(fwd_tail) + len(insert) + len(rev_tail)

    # Positions of the primer binding regions on the TEMPLATE (not the
    # full amplicon). The forward primer binds the top strand at the
    # start of the insert; the reverse primer binds the bottom strand at
    # the end of the insert (positions are reported in forward-strand
    # coordinates). Save-to-library needs these to add primer_bind
    # features to the map. For wrap regions, compute positions with
    # modular arithmetic so they land on the real plasmid coordinates.
    if wraps:
        fwd_pos = (start, (start + len(fwd_bind)) % total)
        rev_pos = ((end - len(rev_bind)) % total, end)
    else:
        fwd_pos = (start, start + len(fwd_bind))
        rev_pos = (end - len(rev_bind), end)

    pair = {
        "fwd_full":     fwd_full,
        "rev_full":     rev_full,
        "fwd_binding":  fwd_bind,
        "rev_binding":  rev_bind,
        "fwd_tm":       round(fwd_tm, 1),
        "rev_tm":       round(rev_tm, 1),
        "fwd_pos":      fwd_pos,
        "rev_pos":      rev_pos,
        "amplicon_len": amplicon_len,
    }
    # Binding-region advisory: flag any silent mutation that lands inside
    # the forward or reverse primer binding window. When non-empty, the
    # user must order the mutated insert as a gBlock and use that — not
    # the original template — as the PCR template.
    binding_region_mutations = _gb_binding_region_advisory(
        mutations, len(insert), len(fwd_bind), len(rev_bind),
    )
    return {
        "part_type":    part_type,
        "position":     pos_label,
        "oh5":          oh5,
        "oh3":          oh3,
        "insert_seq":   insert,
        "mutations":    mutations,
        "binding_region_mutations": binding_region_mutations,
        "pairs":        [pair],
        # Legacy top-level mirror of pairs[0] for callers (cloning simulator,
        # PrimerDesignScreen) that don't iterate the list yet.
        **pair,
    }


# ── Parts bin persistence ─────────────────────────────────────────────────────
# User-created parts (from the domesticator) are stored in parts_bin.json next
# to the main script. Each entry is a dict with at least the 7 canonical fields
# plus sequence, primers, and Tm values.

_PARTS_BIN_FILE = _DATA_DIR / "parts_bin.json"
_parts_bin_cache: "list | None" = None

def _load_parts_bin() -> list[dict]:
    global _parts_bin_cache
    if _parts_bin_cache is not None:
        # Deep-copy on read: parts entries carry nested dicts (qualifiers,
        # primer pairs, mutation lists). Caller mutations of those nested
        # objects would otherwise poison the in-memory cache for every
        # subsequent reader (sacred invariant #17).
        return _typed_clone(_parts_bin_cache)
    entries, warning = _safe_load_json(_PARTS_BIN_FILE, "Parts bin")
    if warning:
        _log.warning(warning)
    entries = [e for e in entries if isinstance(e, dict)]
    _parts_bin_cache = entries
    return _typed_clone(_parts_bin_cache)

def _save_parts_bin(entries: list[dict]) -> None:
    global _parts_bin_cache
    # Sweep #10 (2026-05-20): mirror moved INSIDE the lock — same fix
    # as `_save_library`. Pre-fix: Thread A wrote parts_bin.json,
    # released lock, Thread B wrote + mirrored B; Thread A then
    # mirrored A's stale snapshot. RLock allows nesting via the
    # mirror's `_save_parts_bin_collections` chain.
    with _cache_lock:
        _safe_save_json(_PARTS_BIN_FILE, entries, "Parts bin")
        # Deep-copy on save so the cache is independent of the caller's
        # reference — pre-fix `list(entries)` shared dict refs with the
        # caller, so subsequent caller mutations (e.g. modal Cancel that
        # didn't actually save) leaked back into the next `_load_parts_bin`.
        _parts_bin_cache = _typed_clone(entries)
        # Mirror into the active parts-bin collection so multi-bin users
        # don't lose state. Same contract as `_save_library` invariant #10:
        # every writeable parts-bin path goes through this helper. Silent
        # no-op if there's no active bin (first-launch race; the migration
        # in App.compose() establishes one before any UI write).
        _sync_active_parts_bin_parts(entries)
    # Invalidate the assembly-fragment digest cache: a part edit
    # (re-domestication, gb_text rewrite, deleted entry) shifts what
    # `_assembly_fragment_from_source` yields, so stale digests
    # would surface old overhangs in the constructor palette. OK to
    # run outside the lock — pure invalidation.
    _clear_assembly_fragment_cache()


# ── Parts-bin collections (multi-bin storage) ───────────────────────────────
#
# Mirrors the plasmid-collections architecture: each bin is a named
# snapshot of parts. `parts_bin.json` holds the ACTIVE bin's parts
# (back-compat with all existing readers / writers); the canonical
# multi-bin record is `parts_bin_collections.json`. Every write through
# `_save_parts_bin` mirrors into the active bin's entry — see invariant
# #10 (the plasmid-side equivalent) for the rationale.
#
# Schema (entry):
#   {"name": str, "description": str,
#    "parts": list[dict], "saved": "YYYY-MM-DD"}
#
# `name` is the user-visible identifier (unique per the picker's
# dup-name guard). Active-bin pointer lives in `settings.json` under
# `active_parts_bin` so it persists across launches.

_PARTS_BIN_COLLECTIONS_FILE = _DATA_DIR / "parts_bin_collections.json"
_parts_bin_collections_cache: "list | None" = None
_DEFAULT_PARTS_BIN_NAME = "Main Parts Bin"


def _load_parts_bin_collections() -> list[dict]:
    """Return a deepcopy of the parts-bin collections list so callers
    can mutate entries (rename, edit parts list) without poisoning the
    in-memory cache. Mirrors the `_load_collections` contract per
    invariant #17.
    """
    global _parts_bin_collections_cache
    if _parts_bin_collections_cache is None:
        entries, warning = _safe_load_json(
            _PARTS_BIN_COLLECTIONS_FILE, "Parts-bin collections",
        )
        if warning:
            _log.warning(warning)
        _parts_bin_collections_cache = [
            e for e in entries if isinstance(e, dict)
        ]
    return _typed_clone(_parts_bin_collections_cache)


def _save_parts_bin_collections(entries: list[dict]) -> None:
    """Persist the full parts-bin collections list. Deepcopies into the
    cache so caller mutations after save can't poison subsequent
    loaders (invariant #17). Clears the assembly-fragment digest cache
    because a bin add / delete / rename can shift the active bin's
    parts identity.
    """
    global _parts_bin_collections_cache
    with _cache_lock:
        _safe_save_json(
            _PARTS_BIN_COLLECTIONS_FILE, entries, "Parts-bin collections",
        )
        _parts_bin_collections_cache = _typed_clone(entries)
    # Same cache-invalidation hygiene as `_save_collections`: a bin
    # rename / delete / parts-list edit changes what
    # `_assembly_fragment_from_source` digests.
    _clear = globals().get("_clear_assembly_fragment_cache")
    if _clear is not None:
        _clear()


def _get_active_parts_bin_name() -> "str | None":
    val = _get_setting("active_parts_bin", None)
    return val if isinstance(val, str) and val else None


def _set_active_parts_bin_name(name: "str | None") -> None:
    _set_setting("active_parts_bin", name or "")


def _find_parts_bin(name: str) -> "dict | None":
    for b in _load_parts_bin_collections():
        if b.get("name") == name:
            return b
    return None


def _parts_bin_name_taken(name: str) -> bool:
    """Dup-name guard for create / rename / duplicate. Pure check,
    no side effects."""
    return _find_parts_bin(name) is not None


def _ensure_default_parts_bin() -> None:
    """Idempotent: guarantee at least one parts bin exists.

    First-run users have a (possibly empty) `parts_bin.json` but no
    `parts_bin_collections.json` — migrate by wrapping their existing
    parts in "Main Parts Bin" and marking it active. Empty parts on
    first run still produces an empty Main Parts Bin so the picker
    always has something to show.

    Like `_ensure_default_collection`, this MUST run in
    `PlasmidApp.compose()` (NOT `on_mount`) — Textual mounts
    leaves→root, so a child reading the active bin during mount sees
    stale state if the migration hasn't run.
    """
    bins = _load_parts_bin_collections()
    if bins:
        if not _get_active_parts_bin_name():
            first = bins[0].get("name")
            if first:
                _set_active_parts_bin_name(first)
        return
    existing_parts = _load_parts_bin()
    _save_parts_bin_collections([{
        "name":        _DEFAULT_PARTS_BIN_NAME,
        "description": "Default parts bin",
        "parts":       existing_parts,
        "saved":       _date.today().isoformat(),
    }])
    _set_active_parts_bin_name(_DEFAULT_PARTS_BIN_NAME)


def _sync_active_parts_bin_parts(entries: list[dict]) -> None:
    """Mirror the live `parts_bin.json` contents into the active bin's
    `parts` list inside `parts_bin_collections.json`. Silent no-op if
    no active bin (first-launch race) or if the active name has been
    deleted by the user via the picker.

    Synchronous: parts bins are typically far smaller than plasmid
    collections (a few KB to ~hundred KB), so the async coalescing
    pattern that `_sync_active_collection_plasmids` uses for 100+ MB
    libraries isn't worth the thread overhead here. Revisit if a user
    surfaces a bin with > 1000 parts.
    """
    name = _get_active_parts_bin_name()
    if not name:
        return
    # Deep-clone via `_typed_clone` — invariant #17 (see the matching
    # comment in `_sync_active_collection_plasmids`).
    snapshot = [_typed_clone(e) for e in entries if isinstance(e, dict)]
    bins = _load_parts_bin_collections()
    for b in bins:
        if b.get("name") == name:
            b["parts"] = snapshot
            try:
                _save_parts_bin_collections(bins)
            except (OSError, RuntimeError) as exc:
                _bg_notify_save_failure(
                    f"Active-parts-bin mirror ({name})", exc,
                )
            return


# ── Primer design (Primer3-backed) ─────────────────────────────────────────────
#
# Two primer types:
#   Detection — diagnostic PCR primers flanking a target region.
#               Primer3 picks the thermodynamically ideal pair.
#   Cloning   — primers with restriction-enzyme tails + GCGC padding for
#               cloning a region into a new vector.
#
# Primer library persists to primers.json (same dir as plasmid_library.json).

_PRIMERS_FILE = _DATA_DIR / "primers.json"
_primers_cache: "list | None" = None

def _load_primers() -> list[dict]:
    global _primers_cache
    if _primers_cache is not None:
        # Deep-copy on read: primer entries carry nested dicts (qualifiers,
        # binding-region info, per-pair attribute dicts). Caller mutations
        # of nested objects would poison the cache (sacred invariant #17).
        return _typed_clone(_primers_cache)
    entries, warning = _safe_load_json(_PRIMERS_FILE, "Primer library")
    if warning:
        _log.warning(warning)
    entries = [e for e in entries if isinstance(e, dict)]
    _primers_cache = entries
    return _typed_clone(_primers_cache)

def _dedupe_primers_by_sequence(entries: list[dict]) -> list[dict]:
    """Collapse primer entries whose ``sequence`` field duplicates an
    earlier entry's sequence (case-insensitive). The first entry of
    each unique sequence wins — callers that prepend MRU at index 0
    therefore keep their newest copy, while older duplicates are
    silently dropped.

    The primer-library policy across the app has always been "one entry
    per unique sequence":

      * ``PrimerDesignScreen._save_primers_btn`` rejects a designed
        primer when its sequence already exists.
      * ``_apply_record`` and ``_bulk_import_folder`` dedupe
        .dna-imported primers against the existing library before
        appending.

    Pre-2026-05-10 those dedupe paths only filtered NEW additions —
    duplicates that snuck into ``primers.json`` from earlier sessions
    (manual edits, imports before the dedupe landed, etc.) stayed
    forever. Calling this helper on every save means the next write
    of ``primers.json`` cleans up legacy duplicates without the user
    having to do anything.

    Entries lacking a usable ``sequence`` (None / empty / non-string)
    are kept verbatim — losing them silently would be worse than
    leaving the user with a one-off "unknown" row to investigate.
    """
    seen: set[str] = set()
    out: list[dict] = []
    for e in entries:
        if not isinstance(e, dict):
            out.append(e)
            continue
        raw_seq = e.get("sequence")
        if not isinstance(raw_seq, str):
            out.append(e)
            continue
        key = raw_seq.strip().upper()
        if not key:
            out.append(e)
            continue
        if key in seen:
            continue
        seen.add(key)
        out.append(e)
    return out


# App-level cache for the primer-usage index. Invalidated whenever any
# code path that could change primer_bind features writes the library
# or collections — see `_primer_usage_clear_cache()` calls in
# `_save_library` and `_save_collections`. Without the cache, every
# PrimerDesignScreen open would re-scan every plasmid (~2.5 s on a
# 600-plasmid library after regex-extract optimisation).
_primer_usage_cache: "dict[str, int] | None" = None
# Generation counter — bumped on every cache invalidation. The scan
# worker captures the generation at entry and refuses to write its
# result back if the generation moved (i.e., an invalidation fired
# mid-scan). Without this, a save firing mid-scan would let the
# worker's stale result silently overwrite the just-cleared cache
# and stick around until the next save.
_primer_usage_cache_gen: int = 0


def _primer_usage_clear_cache() -> None:
    """Invalidate `_primer_usage_cache`. Called from `_save_library`
    and `_save_collections` so the next PrimerDesignScreen open
    sees a fresh scan that reflects any plasmid edits. Also bumps
    `_primer_usage_cache_gen` so any in-flight scan worker drops
    its stale result instead of writing it back to the cache."""
    global _primer_usage_cache, _primer_usage_cache_gen
    _primer_usage_cache = None
    _primer_usage_cache_gen += 1


def _normalize_primer_seq(raw: object) -> str:
    """Whitespace-strip + uppercase a primer sequence. Robust to
    multi-line wrapped GenBank qualifier values (Biopython joins
    wrap-continued lines into a single string but may preserve
    embedded whitespace) and to non-string inputs (returns empty).

    Used by both the regex and SeqIO paths in
    `_index_primer_usage_in_collections` /
    `_find_primer_plasmid_usages` so a primer with a wrap-formatted
    `primer_seq` qualifier matches the same primer's `.upper()` form
    from the primer library — pre-fix the two paths used different
    normalisation (`.strip().upper()` vs ``re.sub(r"\\s+", "", ...)``)
    and could miss long primers wrapped at 58-col GenBank boundaries.
    """
    if not isinstance(raw, str):
        return ""
    return re.sub(r"\s+", "", raw).upper()


# Regex-extract `/primer_seq="..."` qualifier values from raw GenBank
# text. `[^"]+` matches across newlines, so wrapped multi-line
# qualifier values (Biopython folds long sequences at ~58 chars)
# capture as one match plus interior whitespace — stripped on the
# caller side. Fast path for `_index_primer_usage_in_collections`:
# the SpliceCraft `.dna`-import flow and PrimerDesignScreen save both
# stamp this qualifier, so regex catches everything without the per-
# plasmid SeqIO parse cost (~50× speed-up on 500-plasmid libraries).
_PRIMER_SEQ_QUALIFIER_RE = re.compile(r'/primer_seq="([^"]+)"')
_PRIMER_BIND_FEATURE_RE = re.compile(r'^\s+primer_bind\s', re.MULTILINE)


def _index_primer_usage_in_collections(use_cache: bool = True) -> "dict[str, int]":
    """Walk every plasmid in every collection and return
    ``{primer_sequence_upper: n_plasmids_using_it}``.

    Counts UNIQUE plasmids per primer — a plasmid with the same primer
    appearing as both forward and reverse `primer_bind` features is
    counted once. Surfaces "how popular is this primer across the
    whole library" so the user can spot core primers vs one-offs
    without manually scanning every plasmid's feature list.

    **Fast path**: regex over the raw `gb_text` for
    ``/primer_seq="..."`` qualifier values. Captures everything the
    `.dna` importer and primer designer stamp on `primer_bind`
    features (~99% of real-world entries) without paying the
    SeqIO-parse cost per plasmid.

    **Fallback**: plasmids whose `gb_text` carries `primer_bind`
    feature lines but NO `/primer_seq=` qualifiers (legacy features
    added by hand or by tools that don't stamp the qualifier) drop
    into the SeqIO path. The fallback slices each feature's location
    off the plasmid sequence — matches the binding region but not
    any cloning tail.

    Returns a shallow COPY of the cached result so caller mutations
    can't poison the cache (invariant #17). Pass ``use_cache=False``
    to force a fresh scan (test helper).
    """
    global _primer_usage_cache
    if use_cache and _primer_usage_cache is not None:
        return _primer_usage_cache.copy()
    # Capture the cache generation at scan entry so we can detect a
    # mid-scan invalidation (e.g., `_save_library` firing while we
    # iterate collections) and refuse to write our stale result back.
    entry_gen = _primer_usage_cache_gen
    counts: "dict[str, set[str]]" = {}
    try:
        collections = _load_collections()
    except Exception:
        _log.exception("primer-usage index: collection load failed")
        return {}
    for coll in collections:
        if not isinstance(coll, dict):
            continue
        coll_name = coll.get("name") or ""
        plasmids = coll.get("plasmids") or []
        for p in plasmids:
            if not isinstance(p, dict):
                continue
            # Per-plasmid identity that's unique across collections so
            # two plasmids sharing an `id` in different collections
            # still count separately. Falls back to name when id is
            # missing.
            pid = (
                f"{coll_name}:"
                f"{p.get('id') or p.get('name') or ''}"
            )
            gb_text = p.get("gb_text") or ""
            if not gb_text:
                continue
            # Fast path: regex `/primer_seq="..."` extraction.
            raw_matches = _PRIMER_SEQ_QUALIFIER_RE.findall(gb_text)
            if raw_matches:
                for raw in raw_matches:
                    seq = _normalize_primer_seq(raw)
                    if seq:
                        counts.setdefault(seq, set()).add(pid)
                continue
            # Fallback: only SeqIO-parse if there ARE `primer_bind`
            # feature lines but none have a stamped primer_seq.
            # Plasmids with no primer_bind features at all skip the
            # parse entirely.
            if not _PRIMER_BIND_FEATURE_RE.search(gb_text):
                continue
            try:
                rec = _gb_text_to_record(gb_text)
            except Exception:
                _log.debug(
                    "primer-usage index: %s failed to parse",
                    pid, exc_info=True,
                )
                continue
            n = _seq_len(rec)
            seq_str = str(rec.seq).upper() if n > 0 else ""
            for feat in rec.features:
                if feat.type != "primer_bind":
                    continue
                primer_seq = ""
                quals = getattr(feat, "qualifiers", {}) or {}
                ps_list = quals.get("primer_seq")
                if isinstance(ps_list, list) and ps_list:
                    primer_seq = _normalize_primer_seq(ps_list[0])
                if not primer_seq and n > 0:
                    bounds = _feat_bounds(feat, n)
                    if bounds is not None:
                        s, e, strand = bounds
                        # Wrap-aware slice: origin-spanning primer
                        # binding regions have end < start after
                        # `_feat_bounds` normalisation.
                        if e < s:
                            primer_seq = seq_str[s:] + seq_str[:e]
                        else:
                            primer_seq = seq_str[s:e]
                        if strand and strand < 0:
                            primer_seq = _rc(primer_seq)
                if primer_seq:
                    counts.setdefault(primer_seq, set()).add(pid)
    result = {seq: len(pids) for seq, pids in counts.items()}
    # Only write back if the cache generation didn't move while we
    # scanned — a `_save_library` mid-scan would have cleared the
    # cache and bumped the generation; writing our pre-save result
    # back would silently poison the cache with stale data until
    # the next save fires.
    if entry_gen == _primer_usage_cache_gen:
        _primer_usage_cache = result
    return result.copy()


def _find_primer_plasmid_usages(primer_seq: str) -> "list[dict]":
    """Find every plasmid carrying a `primer_bind` feature whose
    primer sequence matches ``primer_seq`` (case-insensitive, exact).
    Returns usage entries with keys:

      * ``collection``    — collection name
      * ``plasmid_id``    — library entry id (or name if id missing)
      * ``plasmid_name``  — display name
      * ``start``         — 0-based start (wrap-aware via `_feat_bounds`;
                            ``end < start`` signals origin-spanning)
      * ``end``           — 0-based end
      * ``strand``        — +1 / -1 / 0

    Used by `PrimerPlasmidsModal` to surface every plasmid that
    references a given primer. Regex pre-filters by primer-seq
    qualifier so SeqIO-parses only fire for plasmids that actually
    match — a primer present in 5 of 600 plasmids costs ~5 parses,
    not 600.

    Slower fallback (SeqIO without qualifier match) kicks in only
    when a plasmid has `primer_bind` lines but no `/primer_seq=`
    qualifiers — covers legacy features added by hand or by tools
    that don't stamp the qualifier.
    """
    target = primer_seq.strip().upper()
    if not target:
        return []
    out: list[dict] = []
    try:
        collections = _load_collections()
    except Exception:
        _log.exception("primer-usages: collection load failed")
        return []
    for coll in collections:
        if not isinstance(coll, dict):
            continue
        coll_name = coll.get("name") or ""
        plasmids = coll.get("plasmids") or []
        for p in plasmids:
            if not isinstance(p, dict):
                continue
            gb_text = p.get("gb_text") or ""
            if not gb_text:
                continue
            # Fast filter: does any `/primer_seq=` qualifier in this
            # plasmid match `target`? Uses `_normalize_primer_seq` for
            # consistency with the SeqIO path below — a wrap-formatted
            # qualifier value with embedded whitespace would otherwise
            # match in one path but not the other.
            matched_qual = False
            for raw in _PRIMER_SEQ_QUALIFIER_RE.findall(gb_text):
                if _normalize_primer_seq(raw) == target:
                    matched_qual = True
                    break
            if not matched_qual:
                # No qualifier match → primer isn't carried by this
                # plasmid (under the canonical primer_seq-stamped
                # model). Skip without parsing.
                #
                # Edge case: legacy / hand-added `primer_bind` features
                # without a `/primer_seq=` qualifier won't be matched
                # by this lookup — the binding region is only knowable
                # via a slice off `rec.seq` after a SeqIO parse, and
                # paying that parse cost on every plasmid in the 0-
                # match case (the common case when a user inspects an
                # uncommon primer) makes the modal feel broken. Users
                # whose plasmids carry such legacy features should
                # re-import the `.dna` to re-stamp qualifiers, or use
                # the BLAST modal (which doesn't rely on primer_seq)
                # for sequence-based search.
                continue
            try:
                rec = _gb_text_to_record(gb_text)
            except Exception:
                continue
            n = _seq_len(rec)
            seq_str = str(rec.seq).upper() if n > 0 else ""
            for feat in rec.features:
                if feat.type != "primer_bind":
                    continue
                this_seq = ""
                ps_list = (
                    getattr(feat, "qualifiers", {}) or {}
                ).get("primer_seq")
                if isinstance(ps_list, list) and ps_list:
                    this_seq = _normalize_primer_seq(ps_list[0])
                if not this_seq and n > 0:
                    bounds = _feat_bounds(feat, n)
                    if bounds is not None:
                        s, e, strand = bounds
                        if e < s:
                            this_seq = seq_str[s:] + seq_str[:e]
                        else:
                            this_seq = seq_str[s:e]
                        if strand and strand < 0:
                            this_seq = _rc(this_seq)
                if this_seq != target:
                    continue
                bounds = _feat_bounds(feat, n)
                if bounds is None:
                    continue
                fs, fe, fstrand = bounds
                out.append({
                    "collection":   coll_name,
                    "plasmid_id":   p.get("id") or p.get("name") or "",
                    "plasmid_name": p.get("name") or p.get("id") or "",
                    "start":        fs,
                    "end":          fe,
                    "strand":       fstrand or 0,
                })
    return out


def _dedupe_primers_by_name_longest_seq(entries: list[dict]) -> list[dict]:
    """Collapse primer entries that share a ``name`` field, keeping the
    one with the longest sequence — typically the variant carrying the
    full cloning tail rather than a truncated binding region.

    Why a separate pass from `_dedupe_primers_by_sequence`:
      * `_dedupe_primers_by_sequence` is the sacred-invariant default
        on every save: same DNA sequence ⇒ one entry, no ambiguity.
      * Name collisions are a different problem class — `.dna` imports
        often replay the same primer-name with different binding /
        tail variants (truncated annotation vs full cloned primer),
        so the on-disk schema legitimately carries N entries with the
        same name and N different sequences. Dropping them on save
        would lose data.

    This helper is therefore opt-in: it's run at startup by
    `_check_primer_duplicates` (with user confirmation via
    `PrimerDuplicatesModal`), not by `_save_primers`. The user signs
    off on the "longest wins" policy before any data leaves disk.

    Ties on length: the entry earlier in the input order wins.
    Non-dict / no-name / non-string-sequence entries are kept verbatim.
    """
    best_idx: dict[str, int] = {}
    best_len: dict[str, int] = {}
    for i, e in enumerate(entries):
        if not isinstance(e, dict):
            continue
        name = e.get("name")
        if not isinstance(name, str):
            continue
        key = name.strip()
        if not key:
            continue
        seq = e.get("sequence")
        if not isinstance(seq, str):
            continue
        this_len = len(seq.strip())
        if key not in best_idx or this_len > best_len[key]:
            best_idx[key] = i
            best_len[key] = this_len
    kept = set(best_idx.values())
    out: list[dict] = []
    for i, e in enumerate(entries):
        if not isinstance(e, dict):
            out.append(e)
            continue
        name = e.get("name")
        seq = e.get("sequence")
        # Entries without a usable name OR a string sequence aren't
        # candidates for name-collision collapse — keep them through.
        if (not isinstance(name, str) or not name.strip()
                or not isinstance(seq, str)):
            out.append(e)
            continue
        if i in kept:
            out.append(e)
    return out


def _save_primers(entries: list[dict]) -> None:
    global _primers_cache
    # Dedupe by sequence on every save (sacred policy: one entry per
    # unique sequence). See `_dedupe_primers_by_sequence`. Note that
    # NAME collisions are NOT auto-collapsed here — `.dna` imports
    # legitimately stash same-name different-sequence variants, and
    # silently dropping any would lose primer data. Name-collision
    # cleanup is opt-in via `PrimerDuplicatesModal` at startup.
    # The primer-usage cache stays valid here because adding/removing
    # primer-library entries doesn't change which plasmids carry
    # `primer_bind` features — that's `_save_library`/`_save_collections`'
    # job to invalidate.
    deduped = _dedupe_primers_by_sequence(entries)
    with _cache_lock:
        _safe_save_json(_PRIMERS_FILE, deduped, "Primer library")
        # Deep-copy on save so the cache is independent of the caller's
        # reference — pre-fix `list(entries)` shared dict refs with the
        # caller, so subsequent caller mutations (e.g. an aborted modal)
        # leaked back into the next `_load_primers`.
        _primers_cache = _typed_clone(deduped)


# ── Feature library persistence ───────────────────────────────────────────────
#
# User-created features (from the Add Feature modal or extracted from existing
# plasmids) persist to features.json. An entry is a dict:
#
#     {
#       "name":         "lacZ-alpha",           # label for the sidebar
#       "feature_type": "CDS",                  # INSDC feature-table type
#       "sequence":     "ATG...TAA",            # 5'→3' forward-strand DNA
#       "strand":       1 | -1 | 0,             # +1 forward, -1 reverse, 0 arrowless
#       "color":        "#RRGGBB" | None,       # optional per-entry override
#       "qualifiers":   {"gene": ["lacZ"], ...}, # GenBank-compatible qualifiers
#       "description":  "(free text)"           # optional
#     }
#
# The `feature_type` is validated against a curated list of INSDC-standard
# types (see `_GENBANK_FEATURE_TYPES`). Unknown types are accepted with a
# warning — some in-house projects use non-standard types and we shouldn't
# block them, but the warning flags risk of downstream tool incompatibility.
#
# Visual styling precedence when rendering a library entry:
#   1. entry["color"] if set (per-entry user override)
#   2. user-edited type default from feature_colors.json
#   3. built-in _DEFAULT_TYPE_COLORS for the feature_type
#   4. _FEATURE_PALETTE[0] as a last-resort fallback
# Use `_resolve_feature_color(entry)` rather than reading the field directly.

_FEATURES_FILE = _DATA_DIR / "features.json"
_features_cache: "list | None" = None

# Monotonic counter bumped on every change to the feature library cache
# (writes via `_save_features`, plus first-load / cache-miss reads via
# `_load_features`). Lets long-lived screens (PartsBinModal, etc.) cache
# derived indices and detect stale state without scanning the whole
# library every populate. Strict bump-on-change — never decremented.
_features_generation: int = 0

# User-edited type → default color map persisted as entries of
# {"feature_type": "<type>", "color": "#RRGGBB"}. Kept separate from the
# entry file so the defaults survive even when the library is empty.
_FEATURE_COLORS_FILE = _DATA_DIR / "feature_colors.json"
_feature_colors_cache: "dict[str, str] | None" = None

# Curated INSDC / GenBank feature-table types relevant to plasmid work.
# Full spec: https://www.insdc.org/submitting-standards/feature-table/
# Ordered by frequency so the modal dropdown puts CDS / gene / promoter at the
# top. The `source` type is excluded because each record already has exactly
# one `source` feature spanning the whole molecule — adding more would be
# invalid GenBank.
_GENBANK_FEATURE_TYPES: tuple = (
    "CDS", "gene", "mRNA", "tRNA", "rRNA", "ncRNA", "misc_RNA",
    "promoter", "terminator", "RBS", "polyA_signal", "regulatory",
    "5'UTR", "3'UTR", "intron", "exon", "operon",
    "primer_bind", "protein_bind", "misc_binding",
    "repeat_region", "LTR", "mobile_element",
    "rep_origin", "oriT",
    "sig_peptide", "mat_peptide", "transit_peptide", "propeptide",
    "misc_feature", "misc_recomb", "stem_loop", "variation",
)

# Built-in default color per feature type. Used when the user has not
# customised a default in feature_colors.json. Hex strings so they render
# identically in Rich (which accepts "#RRGGBB").
_DEFAULT_TYPE_COLORS: dict[str, str] = {
    "CDS":             "#FFA500",
    "gene":            "#FFD700",
    "mRNA":            "#FFA07A",
    "tRNA":            "#FF69B4",
    "rRNA":            "#FF1493",
    "ncRNA":           "#DA70D6",
    "misc_RNA":        "#BA55D3",
    "promoter":        "#00CED1",
    "terminator":      "#DC143C",
    "RBS":             "#00FF7F",
    "polyA_signal":    "#FF6347",
    "regulatory":      "#7FFFD4",
    "5'UTR":           "#87CEEB",
    "3'UTR":           "#4682B4",
    "intron":          "#A9A9A9",
    "exon":            "#90EE90",
    "operon":          "#DDA0DD",
    "primer_bind":     "#00BFFF",
    "protein_bind":    "#F08080",
    "misc_binding":    "#FF8C00",
    "repeat_region":   "#CD853F",
    "LTR":             "#8B4513",
    "mobile_element":  "#8B008B",
    "rep_origin":      "#9370DB",
    "oriT":            "#BA55D3",
    "sig_peptide":     "#ADFF2F",
    "mat_peptide":     "#9ACD32",
    "transit_peptide": "#7CFC00",
    "propeptide":      "#6B8E23",
    "misc_feature":    "#20B2AA",
    "misc_recomb":     "#48D1CC",
    "stem_loop":       "#FF4500",
    "variation":       "#800080",
}


def _load_features() -> list[dict]:
    """Return an independent (deep-copied) list of feature library
    entries. Callers can mutate the returned dicts freely without
    poisoning the cache — important for ``FeatureLibraryScreen``
    which buffers in-place edits (rename / color / strand / etc.) and
    then either persists or abandons. A shallow ``list(_features_cache)``
    used to share dict refs with the cache, so an abandoned mutation
    would survive in the cache and leak into the next ``_load_features``
    consumer (a freshly opened FeatureLibraryScreen, the
    DomesticatorModal feature picker, etc.) as if it had been saved.
    """
    global _features_cache, _features_generation
    if _features_cache is not None:
        return _typed_clone(_features_cache)
    entries, warning = _safe_load_json(_FEATURES_FILE, "Feature library")
    if warning:
        _log.warning(warning)
    entries = [e for e in entries if isinstance(e, dict)]
    _features_cache = entries
    # A fresh disk read is the result of either first-load or an
    # external invalidation (test harness setting `_features_cache =
    # None`, or a hand-edit of features.json). Either way the contents
    # may have changed since the last write, so bump the generation so
    # consumers know to rebuild any derived indices.
    _features_generation += 1
    return _typed_clone(_features_cache)


def _save_features(entries: list[dict]) -> None:
    """Persist `entries` and seed the in-memory cache with a deepcopy
    so subsequent caller-side mutations of `entries` (or any dict
    inside it) cannot leak into the cache after the save returns.
    Without the deepcopy, the dicts in `_features_cache` would alias
    the dicts in the caller's list — so e.g. a FeatureLibraryScreen
    that saved, then made another change, then abandoned, would leave
    the post-save mutations stuck in the cache.
    """
    global _features_cache, _features_generation
    with _cache_lock:
        _safe_save_json(_FEATURES_FILE, entries, "Feature library")
        _features_cache = _typed_clone(entries)
        _features_generation += 1


# Generation-keyed cache of the (name, feature_type) → sequence index.
# Invalidated automatically by `_save_features` bumping
# `_features_generation`, so callers don't need to manage staleness —
# `_build_feature_library_index` rebuilds transparently on the next
# call after any save / external reload.
_feature_library_index_cache: "tuple[int, dict[tuple[str, str], str]] | None" = None


def _build_feature_library_index() -> dict[tuple[str, str], str]:
    """Return ``{(name, feature_type): sequence_upper}`` for the entire
    feature library — single sweep, used for O(1) part-vs-feature
    lookups in the Parts Bin "Feat Lib" column. Doing this per row
    inside ``_populate`` would be O(parts × features); building once
    and looking up is O(parts + features) and reusable across the
    entire populate.

    Memoised by `_features_generation`: a save bumps the generation,
    so the next call reads the fresh on-disk state via
    `_load_features`. The cache value is shared (read-only) across
    callers — every consumer treats the index as a lookup table, never
    mutating it, so no deepcopy is needed.
    """
    global _feature_library_index_cache
    gen = _features_generation
    cached = _feature_library_index_cache
    if cached is not None and cached[0] == gen:
        return cached[1]
    index: dict[tuple[str, str], str] = {}
    for e in _load_features():
        name = e.get("name", "")
        ftype = e.get("feature_type", "")
        if not isinstance(name, str) or not isinstance(ftype, str):
            continue
        index[(name, ftype)] = (e.get("sequence", "") or "").upper()
    _feature_library_index_cache = (gen, index)
    return index


def _classify_feature_library_match(
    index: dict[tuple[str, str], str],
    name: str, feature_type: str, sequence: str,
) -> str:
    """Look up ``(name, feature_type)`` in a pre-built feature-library
    ``index`` and return ``"exact"`` / ``"name"`` / ``""``.

    Same semantics as :func:`_feature_library_match`, but takes a
    pre-built index so callers iterating over many parts pay the
    library-scan cost once instead of once per part. Sequences are
    compared case-insensitively (case-folded on both sides).
    """
    key = (name, feature_type)
    if key not in index:
        return ""
    existing = index[key]
    return "exact" if existing == (sequence or "").upper() else "name"


def _feature_library_match(name: str, feature_type: str,
                           sequence: str) -> str:
    """Classify whether ``(name, feature_type, sequence)`` is already in the
    feature library. Returns one of:

      - ``"exact"`` — entry with same name + type + sequence exists.
        Saving would be a no-op modulo qualifier/description tweaks.
      - ``"name"``  — entry with same name + type exists but sequence
        differs. Saving will replace the stored sequence.
      - ``""``       — no entry with this (name, type) pair.

    Convenience wrapper around :func:`_build_feature_library_index` +
    :func:`_classify_feature_library_match` for one-off lookups (e.g.
    the warning notify in ``PartsBinModal._save_as_feature``). Loops
    that scan many parts should build the index once and call
    :func:`_classify_feature_library_match` directly to avoid
    rebuilding the index on every part.
    """
    return _classify_feature_library_match(
        _build_feature_library_index(), name, feature_type, sequence,
    )


def _load_feature_colors() -> dict[str, str]:
    """Return the user's customised type → color map. Missing file / empty
    entries → empty dict. Callers should combine this with
    ``_DEFAULT_TYPE_COLORS`` — that precedence is handled by
    ``_resolve_feature_color``.

    Uses ``_typed_clone`` on read so the cache contract matches every
    other library (invariant #17). Values are ``str`` (immutable) today,
    so the practical risk is nil — but using the canonical helper keeps
    the pattern honest in case a future schema bump adds a nested
    structure to the value side.
    """
    global _feature_colors_cache
    if _feature_colors_cache is not None:
        return _typed_clone(_feature_colors_cache)
    entries, warning = _safe_load_json(_FEATURE_COLORS_FILE, "Feature colors")
    if warning:
        _log.warning(warning)
    result: dict[str, str] = {}
    for e in entries:
        if not isinstance(e, dict):
            continue
        ft  = e.get("feature_type")
        col = e.get("color")
        if isinstance(ft, str) and ft and isinstance(col, str) and col:
            result[ft] = col
    _feature_colors_cache = _typed_clone(result)
    return _typed_clone(_feature_colors_cache)


def _save_feature_colors(mapping: dict[str, str]) -> None:
    """Persist the type → color map. Written as a list of ``{"feature_type":
    ..., "color": ...}`` dicts so it shares the schema-envelope shape with
    the other libraries (sacred invariant #7).

    Re-seats the cache via ``_typed_clone`` so a caller that keeps
    mutating its mapping after the save doesn't leak post-save edits
    into the next reader (invariant #17, full deepcopy-on-save side).
    """
    global _feature_colors_cache
    entries = [{"feature_type": ft, "color": col}
               for ft, col in mapping.items()]
    with _cache_lock:
        _safe_save_json(_FEATURE_COLORS_FILE, entries, "Feature colors")
        _feature_colors_cache = _typed_clone(mapping)


def _resolve_feature_color(entry: dict) -> str:
    """Effective render color for a library entry. Never returns an empty
    string — falls back through entry override → user default → built-in
    default → palette[0]. Always produces something Rich will parse.

    Palette values that use ``color(N)`` syntax are safe inside Rich
    Style.parse but blow up Rich's markup lexer when rewrapped as
    ``[color(N)]...[/]``. Normalise them to their hex equivalent before
    returning so every downstream caller can use plain markup templating.
    """
    col = entry.get("color") if isinstance(entry, dict) else None
    if isinstance(col, str) and col:
        return _markup_safe_color(col)
    ft = entry.get("feature_type", "") if isinstance(entry, dict) else ""
    user_defaults = _load_feature_colors()
    if ft in user_defaults:
        return _markup_safe_color(user_defaults[ft])
    if ft in _DEFAULT_TYPE_COLORS:
        return _markup_safe_color(_DEFAULT_TYPE_COLORS[ft])
    return _markup_safe_color(_FEATURE_PALETTE[0])


def _markup_safe_color(col: str) -> str:
    """Return ``col`` unchanged if it's already safe for Rich markup (hex,
    named color, or ``rgb(r,g,b)``). Palette-style ``color(N)`` values
    are converted to hex via :func:`_normalise_color_input` because the
    parens collide with Rich's ``[...]`` lexer. Falls back to returning
    the raw string if normalisation fails — better to render something
    than to crash the preview."""
    if not isinstance(col, str) or not col:
        return col
    if col.startswith("color("):
        canon = _normalise_color_input(col)
        if canon:
            return canon
    return col


def _parse_qualifier_string(raw: str) -> dict[str, list[str]]:
    """Parse a user-typed qualifier line like ``gene=lacZ; product=LacZ alpha``
    into the GenBank-style ``{key: [value]}`` dict.

    - Separator between pairs is ``;`` (newlines also accepted).
    - Separator between key and value is the first ``=``.
    - Keys and values are stripped; empty keys are skipped silently.
    - Duplicate keys are merged into a single list (GenBank allows repeated
      qualifiers — e.g. multiple ``/note=`` lines).
    """
    out: dict[str, list[str]] = {}
    if not raw:
        return out
    chunks = re.split(r"[;\n]", raw)
    for chunk in chunks:
        if "=" not in chunk:
            continue
        key, _, val = chunk.partition("=")
        key = key.strip()
        val = val.strip()
        if not key:
            continue
        # Permissive: accept an empty value. GenBank flags (e.g. /pseudo)
        # are technically value-less, but splicecraft always writes a string
        # form, so keep them as empty-string qualifiers.
        out.setdefault(key, []).append(val)
    return out


def _qualifiers_to_string(quals: dict) -> str:
    """Inverse of `_parse_qualifier_string`. Used to prefill the modal when
    the user imports an existing feature. Multi-value qualifiers get one
    `key=value` pair per occurrence."""
    if not quals:
        return ""
    pieces: list[str] = []
    for key, vals in quals.items():
        if isinstance(vals, (list, tuple)):
            for v in vals:
                pieces.append(f"{key}={v}")
        else:
            pieces.append(f"{key}={vals}")
    return "; ".join(pieces)


def _extract_feature_entries_from_record(record) -> list[dict]:
    """Return one feature-library entry dict per non-source feature.

    Wrap features (origin-spanning CompoundLocations) are flattened into the
    forward-strand genomic sequence before export, so the entry's ``sequence``
    is always the 5'→3' DNA that would be re-inserted. Reverse-strand
    features store the revcomp (i.e. the 5'→3' of the feature as read), which
    matches how the Add Feature modal expects input.
    """
    try:
        from Bio.SeqFeature import CompoundLocation
    except ImportError:
        CompoundLocation = tuple()  # type: ignore[assignment]
    seq = str(getattr(record, "seq", "") or "").upper()
    total = len(seq)
    entries: list[dict] = []
    for feat in getattr(record, "features", []) or []:
        if feat.type == "source":
            continue
        loc = feat.location
        strand = getattr(loc, "strand", 1) or 1
        # Assemble the forward-strand genomic sequence under the feature,
        # respecting wrap/compound locations.
        if isinstance(loc, CompoundLocation):
            parts_seq = []
            for part in loc.parts:
                s = int(part.start) % total if total else 0
                e = int(part.end)   % (total or 1) if total else 0
                if total and e <= s:
                    parts_seq.append(seq[s:] + seq[:e])
                else:
                    parts_seq.append(seq[s:e])
            fwd = "".join(parts_seq)
        else:
            s = int(loc.start)
            e = int(loc.end)
            fwd = seq[s:e]
        # Store 5'→3' of the feature as read. For reverse-strand CDS that is
        # the revcomp of the genomic slice.
        if strand == -1 and fwd:
            feat_seq = _rc(fwd)
        else:
            feat_seq = fwd
        entries.append({
            "name":         _feat_label(feat),
            "feature_type": feat.type,
            "sequence":     feat_seq,
            "strand":       1 if strand != -1 else -1,
            "qualifiers":   {k: list(v) if isinstance(v, (list, tuple)) else [v]
                             for k, v in (feat.qualifiers or {}).items()},
            "description":  "",
        })
    return entries


# ── Codon usage registry + optimization (shared across modals) ───────────────
#
# Persistent JSON library of codon usage tables, plus pure-function optimizer
# and restriction-site fixer. Vendored from superfolder_aeblue/codon_tables.py
# and codon_optimize.py (2026-04-13) to keep the single-file convention.
#
# Storage schema (one entry per species in codon_tables.json):
#   {"name": "E. coli K12", "taxid": "83333", "source": "builtin"|"kazusa"|"user",
#    "added": "YYYY-MM-DD", "raw": {"GCT": ["A", 55], ...}}
# In-memory form uses tuples (aa, count); the "raw" JSON list is converted on
# load. Dedup key is the taxid when present, else the display name.

